window.__BANK__=[{"id": "gl-g01-001", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，建筑工程开工前，应当由（ ）向工程所在地县级以上人民政府建设行政主管部门申请领取施工许可证。", "options": {"A": "施工单位", "B": "建设单位", "C": "监理单位", "D": "设计单位"}, "answer": ["B"], "analysis": "根据《建筑法》第七条规定，建筑工程开工前，建设单位应当按照国家有关规定向工程所在地县级以上人民政府建设行政主管部门申请领取施工许可证。施工许可证的申领主体是建设单位（业主），而非施工单位或其他参建单位。", "tags": ["建筑法", "施工许可"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g01-002", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，建设单位应当自领取施工许可证之日起（ ）内开工。因故不能按期开工的，应当向发证机关申请延期。", "options": {"A": "1个月", "B": "2个月", "C": "3个月", "D": "6个月"}, "answer": ["C"], "analysis": "《建筑法》第九条规定，建设单位应当自领取施工许可证之日起三个月内开工。因故不能按期开工的，应当向发证机关申请延期；延期以两次为限，每次不超过三个月。既不开工又不申请延期或者超过延期时限的，施工许可证自行废止。", "tags": ["建筑法", "施工许可"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g01-004", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，大型建筑工程或者结构复杂的建筑工程，可以由两个以上的承包单位联合共同承包，联合体中各方的责任方式是（ ）。", "options": {"A": "按份责任", "B": "连带责任", "C": "有限责任", "D": "各自独立承担责任"}, "answer": ["B"], "analysis": "《建筑法》第二十七条规定，大型建筑工程或者结构复杂的建筑工程，可以由两个以上的承包单位联合共同承包。共同承包的各方对承包合同的履行承担连带责任。连带责任意味着建设单位可以向联合体中任何一方主张全部债权。", "tags": ["建筑法", "联合体承包"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g01-005", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，下列行为中属于法律明确禁止的是（ ）。", "options": {"A": "总承包单位将部分工程分包给具有相应资质的单位", "B": "施工总承包单位将主体结构分包", "C": "施工总承包单位自行完成主体结构施工", "D": "联合体各方共同与建设单位签订合同"}, "answer": ["B"], "analysis": "《建筑法》第二十九条规定，施工总承包的建筑工程主体结构的施工必须由总承包单位自行完成，禁止将主体结构分包。转包和违法分包均为法律禁止行为。选项A是合法分包，选项C是总承包单位依法履行义务，选项D是联合体承包的合法方式。", "tags": ["建筑法", "转包", "肢解发包"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g01-006", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，实行强制监理的建筑工程范围由（ ）规定。", "options": {"A": "全国人大", "B": "住房和城乡建设部", "C": "国务院", "D": "省级人民政府"}, "answer": ["C"], "analysis": "《建筑法》第三十条规定，国家推行建筑工程监理制度。实行强制监理的建筑工程的范围由国务院规定。目前国务院规定的强制监理范围主要包括：国家重点建设工程、大中型公用事业工程、成片开发建设的住宅小区工程等。", "tags": ["建筑法", "强制监理"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g01-009", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "《建筑法》规定，禁止承包单位将其承包的全部建筑工程转包给他人，禁止承包单位将其承包的全部建筑工程（ ）以后以分包的名义分别转包给他人。", "options": {"A": "合并", "B": "肢解", "C": "划分", "D": "拆分"}, "answer": ["B"], "analysis": "《建筑法》第二十八条规定，禁止承包单位将其承包的全部建筑工程转包给他人，禁止承包单位将其承包的全部建筑工程肢解以后以分包的名义分别转包给他人。“肢解发包”是法律术语，指将应由一个承包单位完成的建筑工程分解成若干部分发包给不同承包单位的行为。", "tags": ["建筑法", "肢解发包"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g01-010", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，从事建筑活动的建筑施工企业、勘察单位、设计单位和工程监理单位，应当具备的条件不包括（ ）。", "options": {"A": "有符合国家规定的注册资本", "B": "有与其从事的建筑活动相适应的具有法定执业资格的专业技术人员", "C": "有从事相关建筑活动所应有的技术装备", "D": "有与国外企业合作的经验"}, "answer": ["D"], "analysis": "《建筑法》第十二条规定，从事建筑活动的建筑施工企业、勘察单位、设计单位和工程监理单位应当具备四个条件：注册资本、专业技术人员、技术装备，以及法律、行政法规规定的其他条件。与国外企业合作的经验不是法定条件。", "tags": ["建筑法", "从业资格"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g01-012", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《招标投标法》，招标分为公开招标和邀请招标，下列项目中可以采用邀请招标的是（ ）。", "options": {"A": "全部使用国有资金投资的项目", "B": "涉及国家安全、国家秘密不宜公开招标的项目", "C": "大型基础设施项目", "D": "使用国际组织贷款的项目"}, "answer": ["B"], "analysis": "《招标投标法》第十一条规定，国务院发展计划部门确定的国家重点项目和省、自治区、直辖市人民政府确定的地方重点项目不适宜公开招标的，经批准可以进行邀请招标。涉及国家安全、国家秘密、抢险救灾或者属于利用扶贫资金实行以工代赈、需要使用农民工等特殊情况，不适宜进行招标的项目，按照国家有关规定可以不进行招标。涉及国家安全、国家秘密不宜公开招标的项目可以采用邀请招标方式。", "tags": ["招标投标法", "邀请招标"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g01-013", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《招标投标法》，招标人采用公开招标方式的，应当发布招标公告。依法必须进行招标的项目的招标公告，应当通过国家指定的报刊、信息网络或者其他媒介发布。招标文件发出之日起至投标人提交投标文件截止之日止，最短不得少于（ ）。", "options": {"A": "10日", "B": "15日", "C": "20日", "D": "30日"}, "answer": ["C"], "analysis": "《招标投标法》第二十四条规定，招标人应当确定投标人编制投标文件所需要的合理时间；但是，依法必须进行招标的项目，自招标文件开始发出之日起至投标人提交投标文件截止之日止，最短不得少于二十日。这个时间是为了保证投标人有充足时间编制投标文件。", "tags": ["招标投标法", "投标截止时间"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g01-014", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《招标投标法》，依法必须进行招标的项目，评标委员会由招标人代表和有关技术、经济等方面的专家组成，成员人数和专家比例要求是（ ）。", "options": {"A": "3人以上单数，技术经济专家不少于1/2", "B": "5人以上单数，技术经济专家不少于2/3", "C": "7人以上单数，技术经济专家不少于1/2", "D": "5人以上单数，技术经济专家不少于1/3"}, "answer": ["B"], "analysis": "《招标投标法》第三十七条规定，评标委员会由招标人的代表和有关技术、经济等方面的专家组成，成员人数为五人以上单数，其中技术、经济等方面的专家不得少于成员总数的三分之二。单数是为了便于表决，2/3比例保证专业评审的独立性和技术权威性。", "tags": ["招标投标法", "评标委员会"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g01-015", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《招标投标法》，中标人的投标应当符合的条件之一是：能够满足招标文件的实质性要求，并且经评审的投标价格最低，但是（ ）。", "options": {"A": "投标价格高于标底的除外", "B": "投标价格低于成本的除外", "C": "投标人是新企业的除外", "D": "有多个中标候选人的除外"}, "answer": ["B"], "analysis": "《招标投标法》第四十一条规定，中标人的投标应当符合下列条件之一：(1)能够最大限度地满足招标文件中规定的各项综合评价标准；(2)能够满足招标文件的实质性要求，并且经评审的投标价格最低；但是投标价格低于成本的除外。低于成本的投标属于“低价倾销”行为，违反市场竞争原则。", "tags": ["招标投标法", "中标条件"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g01-017", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《政府采购法》，政府采购的主要采购方式是（ ）。", "options": {"A": "邀请招标", "B": "竞争性谈判", "C": "公开招标", "D": "询价"}, "answer": ["C"], "analysis": "《政府采购法》第二十六条规定，政府采购采用公开招标、邀请招标、竞争性谈判、单一来源采购、询价等五种方式。公开招标应作为政府采购的主要采购方式。", "tags": ["政府采购法", "采购方式"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g01-021", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《政府采购法》，采购人采购货物规格、标准统一，现货货源充足且价格变化幅度小的政府采购项目，可以依法采用（ ）方式采购。", "options": {"A": "公开招标", "B": "邀请招标", "C": "竞争性谈判", "D": "询价"}, "answer": ["D"], "analysis": "《政府采购法》第三十二条规定，采购的货物规格、标准统一，现货货源充足且价格变化幅度小的政府采购项目，可以依照本法采用询价方式采购。询价方式适用于采购需求明确、标准化程度高的货物采购。", "tags": ["政府采购法", "询价"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g01-022", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据政府采购限额标准，采购人采购货物或者服务项目，属于中央预算的，公开招标数额标准由（ ）规定。", "options": {"A": "国务院", "B": "财政部", "C": "省级人民政府", "D": "县级以上人民政府"}, "answer": ["A"], "analysis": "根据《政府采购法》第二十七条，采购人采购货物或者服务项目，属于中央预算的政府采购项目，公开招标数额标准由国务院规定；属于地方预算的政府采购项目，由省、自治区、直辖市人民政府规定。", "tags": ["政府采购法", "限额标准"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g01-023", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《民法典》合同编，合同的订立一般经过要约和承诺两个阶段。下列属于要约的是（ ）。", "options": {"A": "招标公告", "B": "商业广告", "C": "投标文件", "D": "中标通知书"}, "answer": ["C"], "analysis": "根据《民法典》，要约是希望和他人订立合同的意思表示。在招投标过程中，招标公告属于要约邀请，投标文件属于要约，中标通知书属于承诺。商业广告一般视为要约邀请，但内容符合要约条件的构成要约。", "tags": ["民法典合同编", "要约"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g01-024", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《民法典》，承诺生效时合同成立。承诺生效的时间，采用（ ）原则。", "options": {"A": "投邮主义（发信主义）", "B": "到达主义", "C": "知道主义", "D": "推定主义"}, "answer": ["B"], "analysis": "根据《民法典》第四百八十四条，承诺通知到达要约人时生效。采用数据电文形式订立合同的，收件人指定特定系统接收数据电文的，该数据电文进入该特定系统的时间，视为到达时间。我国采用到达主义原则。", "tags": ["民法典合同编", "承诺"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g01-027", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《民法典》，要约可以撤销，但撤销要约的通知应当在（ ）到达受要约人。", "options": {"A": "受要约人发出承诺通知之前", "B": "受要约人发出承诺通知之后", "C": "合同成立之后", "D": "要约到达受要约人之前"}, "answer": ["A"], "analysis": "根据《民法典》第四百七十七条，撤销要约的通知应当在受要约人发出承诺通知之前到达受要约人。注意区分撤回要约和撤销要约：撤回要约的通知应当在要约到达受要约人之前或者与要约同时到达受要约人；撤销要约的通知应当在受要约人发出承诺通知之前到达受要约人。", "tags": ["民法典合同编", "要约撤销"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g01-028", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "关于造价工程师职业资格制度改革，目前工程造价咨询企业资质的管理方式是（ ）。", "options": {"A": "企业资质审批制", "B": "企业资质备案制", "C": "取消企业资质审批，实行告知承诺制", "D": "维持原有审批制度不变"}, "answer": ["C"], "analysis": "根据“证照分离”改革文件精神，工程造价咨询企业资质已取消审批，改为备案管理并实行告知承诺制。这一改革旨在降低市场准入门槛，激发市场活力，同时强化事中事后监管。", "tags": ["造价管理制度", "资质改革"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g01-029", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "关于一级造价工程师与二级造价工程师的区别，下列说法正确的是（ ）。", "options": {"A": "一级造价工程师的考试科目比二级造价工程师多", "B": "二级造价工程师执业范围不受限制", "C": "一级和二级造价工程师的执业印章完全相同", "D": "二级造价工程师可以在全国范围内执业"}, "answer": ["A"], "analysis": "一级造价工程师考试4个科目（造价管理、计价、计量、案例分析），二级造价工程师考试2个科目（造价管理基础知识、计量与计价实务）。一造全国执业，二造原则上在所在行政区域内执业。二造执业范围有限制（小于等于5000万）。两者执业印章格式不同。因此BCD均不正确。", "tags": ["造价管理制度", "一造二造区别"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g01-030", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据二级造价工程师职业资格考试实施办法，具有工程管理、工程造价专业大学本科学历或学位，从事工程造价业务工作满（ ）年，可报考二级造价工程师。", "options": {"A": "1", "B": "2", "C": "3", "D": "4"}, "answer": ["A"], "analysis": "二造报考条件：工程造价专业大专（高等职业教育）学历从事造价业务满2年；土木建筑、水利等专业大专学历从事造价业务满3年；工程管理、工程造价专业本科及以上学历从事造价业务满1年；工学、管理学、经济学门类本科及以上学历从事造价业务满2年；其他专业相应学历工作年限相应增加1年。", "tags": ["造价管理制度", "二造报考条件"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g01-031", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "二级造价工程师的执业范围中，工程造价的编制和审核额度上限为（ ）。", "options": {"A": "1000万元", "B": "2000万元", "C": "5000万元", "D": "1亿元"}, "answer": ["C"], "analysis": "根据二级造价工程师执业范围相关规定，二级造价工程师可独立开展建设工程工料分析、计划组织与成本管理、施工图预算编制；建设工程量清单、最高投标限价、投标报价编制；建设工程合同价款、结算价款和竣工决算价款的编制与审核，但单项工程造价不超过5000万元。", "tags": ["造价管理制度", "二造执业范围"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g01-032", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据造价工程师继续教育相关规定，注册造价工程师在每一注册有效期内应接受继续教育，每年参加的继续教育学时不少于（ ）。", "options": {"A": "20学时", "B": "30学时", "C": "45学时", "D": "60学时"}, "answer": ["B"], "analysis": "根据《注册造价工程师管理办法》，注册造价工程师在每一注册有效期内应接受继续教育，每一注册有效期（4年）继续教育学时不少于120学时，即每年不少于30学时。继续教育是造价工程师保持和提升执业能力的重要手段。", "tags": ["造价管理制度", "继续教育"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g01-034", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，工程监理人员认为工程施工不符合工程设计要求、施工技术标准和合同约定的，有权要求（ ）。", "options": {"A": "建筑设计单位改正", "B": "建筑施工企业改正", "C": "建设单位改正", "D": "工程质量监督机构处理"}, "answer": ["B"], "analysis": "《建筑法》第三十二条规定，工程监理人员认为工程施工不符合工程设计要求、施工技术标准和合同约定的，有权要求建筑施工企业改正。工程监理人员发现工程设计不符合建筑工程质量标准或者合同约定的质量要求的，应当报告建设单位要求设计单位改正。", "tags": ["建筑法", "监理职责"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g01-036", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "《招标投标法》规定，评标委员会成员中，有关技术、经济等方面的专家不得少于成员总数的（ ）。", "options": {"A": "1/3", "B": "1/2", "C": "2/3", "D": "3/4"}, "answer": ["C"], "analysis": "《招标投标法》第三十七条规定，评标委员会成员人数为五人以上单数，其中技术、经济等方面的专家不得少于成员总数的三分之二。这保证了评标工作的专业性和客观性，防止行政干预评标结果。", "tags": ["招标投标法", "评标委员会"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g01-037", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《招标投标法实施条例》，招标人可以对已发出的资格预审文件或者招标文件进行必要的澄清或者修改。澄清或者修改的内容可能影响资格预审申请文件或者投标文件编制的，招标人应当在提交资格预审申请文件截止时间至少（ ）前，或者投标截止时间至少（ ）前，通知所有潜在投标人。", "options": {"A": "3日，10日", "B": "3日，15日", "C": "5日，15日", "D": "5日，10日"}, "answer": ["B"], "analysis": "《招标投标法实施条例》第二十一条规定，招标人进行澄清或修改，可能影响资格预审申请文件编制的，应在截止时间至少3日前通知；可能影响投标文件编制的，应在投标截止时间至少15日前通知。不足的应当顺延截止时间。", "tags": ["招标投标法", "招标文件修改"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g01-038", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "《政府采购法》规定，属于中央预算的政府采购项目，其公开招标数额标准由（ ）规定并公布。", "options": {"A": "全国人民代表大会", "B": "国务院", "C": "财政部", "D": "国家发展和改革委员会"}, "answer": ["B"], "analysis": "《政府采购法》第二十七条明确规定，属于中央预算的政府采购项目的公开招标数额标准，由国务院规定并公布；属于地方预算的政府采购项目，由省、自治区、直辖市人民政府规定并公布。", "tags": ["政府采购法", "限额标准"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g01-039", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "政府采购合同适用《民法典》合同编。采购人与中标、成交供应商应当在中标、成交通知书发出之日起（ ）内，按照采购文件确定的事项签订政府采购合同。", "options": {"A": "15日", "B": "20日", "C": "30日", "D": "45日"}, "answer": ["C"], "analysis": "《政府采购法》第四十六条规定，采购人与中标、成交供应商应当在中标、成交通知书发出之日起三十日内，按照采购文件确定的事项签订政府采购合同。中标、成交通知书对采购人和中标、成交供应商均具有法律效力。", "tags": ["政府采购法", "合同签订"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g01-041", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，按照国务院有关规定批准开工报告的建筑工程，因故不能按期开工超过（ ）的，应当重新办理开工报告的批准手续。", "options": {"A": "3个月", "B": "6个月", "C": "9个月", "D": "12个月"}, "answer": ["B"], "analysis": "《建筑法》第十一条规定，按照国务院有关规定批准开工报告的建筑工程，因故不能按期开工或者中止施工的，应当及时向批准机关报告情况。因故不能按期开工超过六个月的，应当重新办理开工报告的批准手续。这与施工许可证的延期规定有所不同。", "tags": ["建筑法", "开工报告"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-001", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，建设单位应当在建筑工程开工前向工程所在地县级以上人民政府建设行政主管部门申请领取施工许可证，下列哪项不属于申领施工许可证的必备条件？", "options": {"A": "已办理该建筑工程用地批准手续", "B": "建设资金已全部到位", "C": "需要拆迁的其拆迁进度符合施工要求", "D": "已经确定建筑施工企业"}, "answer": ["B"], "analysis": "申领施工许可证的条件之一是【建设资金已经落实】，而非【全部到位】。建设资金落实即可，不要求全部到位。", "tags": ["建筑法", "施工许可"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-002", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，建设单位应当自领取施工许可证之日起多长时间内开工？", "options": {"A": "1个月", "B": "2个月", "C": "3个月", "D": "6个月"}, "answer": ["C"], "analysis": "根据《建筑法》规定，建设单位应当自领取施工许可证之日起3个月内开工。", "tags": ["建筑法", "施工许可"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-003", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，领取施工许可证后因故不能按期开工的，可以申请延期，每次延期最长不超过多长时间？", "options": {"A": "1个月", "B": "2个月", "C": "3个月", "D": "6个月"}, "answer": ["C"], "analysis": "根据《建筑法》，延期以两次为限，每次不超过3个月。", "tags": ["建筑法", "施工许可"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-004", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，在建工程因故中止施工的，建设单位应当自中止施工之日起多长时间内向发证机关报告？", "options": {"A": "15日", "B": "1个月", "C": "2个月", "D": "3个月"}, "answer": ["B"], "analysis": "根据《建筑法》，在建的建筑工程因故中止施工的，建设单位应当自中止施工之日起1个月内向发证机关报告。中止施工满1年的，恢复施工前需报发证机关核验施工许可证。", "tags": ["建筑法", "施工许可"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-005", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，中止施工满多长时间的建筑工程，建设单位在恢复施工前应报发证机关核验施工许可证？", "options": {"A": "6个月", "B": "1年", "C": "2年", "D": "3年"}, "answer": ["B"], "analysis": "中止施工满1年的，建设单位在恢复施工前应报发证机关核验施工许可证。", "tags": ["建筑法", "施工许可"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-006", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，关于建筑工程从业资格的说法正确的是？", "options": {"A": "勘察、设计单位需要有资质，施工单位不需要", "B": "施工、监理单位需要有资质，勘察、设计单位不需要", "C": "只有施工单位和监理单位需要相应资质", "D": "勘察、设计、施工、监理单位均须有相应资质，个人须有执业资格"}, "answer": ["D"], "analysis": "《建筑法》规定，从事建筑活动的建筑施工企业、勘察单位、设计单位和工程监理单位，应有符合国家规定的注册资本、有与其从事的建筑活动相适应的具有法定执业资格的专业技术人员，即单位须有资质，个人须有执业资格。", "tags": ["建筑法", "从业资格"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-007", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，建筑工程发包单位应当将建筑工程发包给什么样的单位？", "options": {"A": "出价最低的单位", "B": "具有相应资质条件的承包单位", "C": "任何有意向的单位", "D": "当地注册的单位"}, "answer": ["B"], "analysis": "根据《建筑法》，建筑工程实行招标发包的，发包单位应当将建筑工程发包给依法中标的承包单位。建筑工程实行直接发包的，发包单位应当将建筑工程发包给具有相应资质条件的承包单位。", "tags": ["建筑法", "发包"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-008", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，关于联合体承包的说法正确的是？", "options": {"A": "联合体各方分别对自己承包的部分承担责任", "B": "由资质等级较高的一方对建设单位承担责任", "C": "联合体各方对建设单位承担连带责任", "D": "由牵头方对建设单位单独承担责任"}, "answer": ["C"], "analysis": "《建筑法》规定，共同承包的各方对承包合同的履行承担连带责任。", "tags": ["建筑法", "联合体承包"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-009", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，两个以上不同资质等级的单位实行联合共同承包的，应如何确定业务许可范围？", "options": {"A": "按照资质等级高的单位的业务许可范围承揽工程", "B": "按照资质等级低的单位的业务许可范围承揽工程", "C": "按照平均资质等级确定业务许可范围", "D": "按照牵头单位的资质等级确定业务许可范围"}, "answer": ["B"], "analysis": "《建筑法》规定，两个以上不同资质等级的单位实行联合共同承包的，应当按照资质等级低的单位的业务许可范围承揽工程。", "tags": ["建筑法", "联合体承包"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-010", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，关于转包的说法正确的是？", "options": {"A": "承包单位可将全部工程转包给其他单位", "B": "承包单位可将全部工程肢解后以分包名义转包", "C": "禁止承包单位将承包的全部建筑工程转包给他人", "D": "经建设单位同意后可以将全部工程转包"}, "answer": ["C"], "analysis": "《建筑法》明确禁止承包单位将其承包的全部建筑工程转包给他人，也禁止将其承包的全部建筑工程肢解以后以分包的名义分别转包给他人。", "tags": ["建筑法", "禁止转包"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-011", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，建筑工程总承包单位可以将承包工程中的部分工程发包给具有相应资质条件的分包单位，但什么部分必须由总承包单位自行完成？", "options": {"A": "基础工程", "B": "装饰装修工程", "C": "主体结构工程", "D": "安装工程"}, "answer": ["C"], "analysis": "《建筑法》规定，施工总承包的建筑工程主体结构的施工必须由总承包单位自行完成。", "tags": ["建筑法", "分包"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-012", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，关于工程分包的表述正确的是？", "options": {"A": "分包单位可以将其承包的工程再分包", "B": "总承包单位和分包单位就分包工程对建设单位承担连带责任", "C": "分包单位对其分包工程独立承担责任，总承包单位不承担责任", "D": "总承包单位可任意选择分包单位"}, "answer": ["B"], "analysis": "《建筑法》规定，总承包单位和分包单位就分包工程对建设单位承担连带责任，同时禁止分包单位将其承包的工程再分包。", "tags": ["建筑法", "分包"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-013", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，关于分包单位的再分包行为表述正确的是？", "options": {"A": "经总承包单位同意可以再分包", "B": "经建设单位同意可以再分包", "C": "可以将其承包的工程再分包给有资质的分包单位", "D": "禁止分包单位将其承包的工程再分包"}, "answer": ["D"], "analysis": "《建筑法》明确规定，禁止分包单位将其承包的工程再分包。", "tags": ["建筑法", "分包"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-014", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，下列哪种说法是正确的？", "options": {"A": "承包单位可以将建筑工程全部转包给其他承包单位", "B": "承包单位可以将工程肢解后以分包名义分别转包", "C": "分包单位可以将其承包的工程再分包", "D": "承包单位不得将全部建筑工程转包，也不得将全部工程肢解后以分包名义转包"}, "answer": ["D"], "analysis": "《建筑法》禁止转包、禁止肢解分包、禁止再分包。D项完整表述了法律禁止的内容。", "tags": ["建筑法", "禁止转包", "分包"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-016", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，工程监理单位不得与哪些单位有隶属关系或者其他利害关系？", "options": {"A": "被监理工程的施工承包单位以及建筑材料、建筑构配件和设备供应单位", "B": "工程设计的编制单位", "C": "工程勘察单位", "D": "建设行政主管部门"}, "answer": ["A"], "analysis": "《建筑法》规定，工程监理单位与被监理工程的施工承包单位以及建筑材料、建筑构配件和设备供应单位不得有隶属关系或者其他利害关系。", "tags": ["建筑法", "监理单位"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-017", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，关于建设单位的安全责任表述正确的是？", "options": {"A": "建设单位不需要提供地下管线资料", "B": "建设单位应当向建筑施工企业提供与施工现场相关的地下管线资料", "C": "地下管线资料由施工单位自行调查", "D": "只有涉及深基坑时才需要提供地下管线资料"}, "answer": ["B"], "analysis": "《建筑法》规定，建设单位应当向建筑施工企业提供与施工现场相关的地下管线资料，建筑施工企业应当采取措施加以保护。", "tags": ["建筑法", "安全责任"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-018", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，涉及深基坑、地下暗挖工程、高大模板工程等危险性较大的分部分项工程，施工单位应当编制专项施工方案，并如何处置？", "options": {"A": "自行审查后实施", "B": "报监理单位审批后实施", "C": "组织专家进行论证、审查", "D": "报建设行政主管部门备案后实施"}, "answer": ["C"], "analysis": "对于深基坑等危险性较大的分部分项工程，施工单位应当编制专项施工方案，并组织专家进行论证、审查。", "tags": ["建筑法", "安全责任"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-020", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，屋面防水工程的保修期为多少年？", "options": {"A": "2年", "B": "3年", "C": "5年", "D": "设计合理使用年限"}, "answer": ["C"], "analysis": "屋面防水工程、有防水要求的卫生间、房间和外墙面的防渗漏保修期为5年。", "tags": ["建筑法", "质量保修"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-021", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，电气管线、给排水管道、设备安装和装修工程的保修期为多少年？", "options": {"A": "1年", "B": "2年", "C": "3年", "D": "5年"}, "answer": ["B"], "analysis": "电气管线、给排水管道、设备安装和装修工程的最低保修期限为2年。", "tags": ["建筑法", "质量保修"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-022", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，关于施工许可制度中【建设资金已经落实】的理解正确的是？", "options": {"A": "建设资金必须全部到位", "B": "建设工期不足一年的到位资金原则上不得少于工程合同价的50%", "C": "建设工期超过一年的到位资金原则上不得少于工程合同价的30%", "D": "只需有资金来源证明即可"}, "answer": ["C"], "analysis": "建设资金已经落实：建设工期不足一年的，到位资金原则上不得少于工程合同价的50%；建设工期超过一年的，到位资金原则上不得少于工程合同价的30%。D项是【资金来源证明】，说法不准确。", "tags": ["建筑法", "施工许可"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-023", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，建设单位申请领取施工许可证需要满足的条件不包括？", "options": {"A": "已经办理该建筑工程用地批准手续", "B": "依法应当办理建设工程规划许可证的已经取得规划许可", "C": "有保证工程质量和安全的具体措施", "D": "已经办理工程保险"}, "answer": ["D"], "analysis": "施工许可证申领条件不包括【已经办理工程保险】。申领条件包括：已办用地批准、取得规划许可（若需）、拆迁进度符合施工要求、已确定施工企业、有施工图纸及技术资料、有质量安全保证措施、建设资金已落实等。", "tags": ["建筑法", "施工许可"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-024", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，建设单位领取施工许可证后因故不能按期开工的，最多可以申请几次延期？", "options": {"A": "1次", "B": "2次", "C": "3次", "D": "不限次数"}, "answer": ["B"], "analysis": "根据《建筑法》，因故不能按期开工的，可向发证机关申请延期；延期以两次为限，每次不超过3个月。既不开工又不申请延期或者超过延期时限的，施工许可证自行废止。", "tags": ["建筑法", "施工许可"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-026", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，建筑工程开工前应向哪个部门申请领取施工许可证？", "options": {"A": "建设单位注册地建设行政主管部门", "B": "工程所在地县级以上人民政府建设行政主管部门", "C": "省级建设行政主管部门", "D": "国土资源部门"}, "answer": ["B"], "analysis": "建设单位应在建筑工程开工前向工程所在地县级以上人民政府建设行政主管部门申请领取施工许可证。", "tags": ["建筑法", "施工许可"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-032", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《招标投标法实施条例》，资格预审文件或者招标文件的发售期不得少于多少日？", "options": {"A": "3日", "B": "5日", "C": "7日", "D": "10日"}, "answer": ["B"], "analysis": "资格预审文件或者招标文件的发售期不得少于5日。", "tags": ["招标投标法", "公开招标"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-033", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《招标投标法》，依法必须进行招标的项目自招标文件开始发出之日起至投标人提交投标文件截止之日止最短不得少于多少日？", "options": {"A": "10日", "B": "15日", "C": "20日", "D": "30日"}, "answer": ["C"], "analysis": "依法必须进行招标的项目，自招标文件开始发出之日起至投标人提交投标文件截止之日止，最短不得少于20日。", "tags": ["招标投标法", "公开招标"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-034", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《招标投标法》，关于公开招标的说法正确的是？", "options": {"A": "招标人可以根据实际情况限制排斥部分潜在投标人", "B": "招标公告应当通过国家指定的报刊、信息网络或者其他媒介发布", "C": "招标人必须通过地方性媒体发布公告", "D": "招标公告只需在单位内部网站发布"}, "answer": ["B"], "analysis": "公开招标要求招标人以招标公告的方式邀请不特定的法人或者其他组织投标，招标人不得以不合理的条件限制或者排斥潜在投标人。招标公告应当通过国家指定的报刊、信息网络或者其他媒介发布。", "tags": ["招标投标法", "公开招标"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-036", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《招标投标法》，投标人少于几个时招标人应当重新招标？", "options": {"A": "2个", "B": "3个", "C": "4个", "D": "5个"}, "answer": ["B"], "analysis": "投标人少于3个的，招标人应当依法重新招标。", "tags": ["招标投标法", "投标人"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-037", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《招标投标法》，开标应当在什么时间什么地点进行？", "options": {"A": "招标文件确定的提交投标文件截止时间的次日", "B": "招标人自行决定的时间和地点", "C": "招标文件确定的提交投标文件截止时间的同一时间公开进行", "D": "评标委员会确定的时间和地点"}, "answer": ["C"], "analysis": "开标应当在招标文件确定的提交投标文件截止时间的同一时间公开进行，开标地点应为招标文件中预先确定的地点。", "tags": ["招标投标法", "开标"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-038", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《招标投标法》，评标委员会成员人数应为多少人以上单数，其中技术、经济等方面的专家不得少于成员总数的多少？", "options": {"A": "3人以上，不少于1/2", "B": "5人以上，不少于2/3", "C": "5人以上，不少于1/2", "D": "7人以上，不少于2/3"}, "answer": ["B"], "analysis": "评标委员会由招标人的代表和有关技术、经济等方面的专家组成，成员人数为5人以上单数，其中技术、经济等方面的专家不得少于成员总数的2/3。", "tags": ["招标投标法", "评标委员会"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-039", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《招标投标法》，评标完成后评标委员会应当向招标人提交书面评标报告，评标报告应由谁签字确认？", "options": {"A": "全体评标委员会成员", "B": "评标委员会负责人", "C": "招标人代表", "D": "行政监督人员"}, "answer": ["A"], "analysis": "评标结果由评标委员会全体成员签字。评标报告应当由评标委员会全体成员签字。", "tags": ["招标投标法", "评标委员会"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-041", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《招标投标法》，招标人和中标人应当自中标通知书发出之日起多少日内按照招标文件和中标人的投标文件订立书面合同？", "options": {"A": "15日", "B": "20日", "C": "30日", "D": "60日"}, "answer": ["C"], "analysis": "招标人和中标人应当自中标通知书发出之日起30日内，按照招标文件和中标人的投标文件订立书面合同。", "tags": ["招标投标法", "签订合同"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-042", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《招标投标法实施条例》，招标人最迟应当在书面合同签订后多长时间内向中标人和未中标的投标人退还投标保证金？", "options": {"A": "3日内", "B": "5日内", "C": "7日内", "D": "10日内"}, "answer": ["B"], "analysis": "招标人最迟应当在书面合同签订后5日内向中标人和未中标的投标人退还投标保证金及银行同期存款利息。", "tags": ["招标投标法", "退还保证金"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-046", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《政府采购法》，下列哪项不属于竞争性谈判的适用情形？", "options": {"A": "招标后没有供应商投标的", "B": "技术复杂不能确定详细规格的", "C": "时间紧急不能满足用户需要的", "D": "只能从唯一供应商处采购的"}, "answer": ["D"], "analysis": "只能从唯一供应商处采购是单一来源采购的适用情形，而非竞争性谈判。", "tags": ["政府采购法", "竞争性谈判"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-048", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《政府采购法》，需要继续从原供应商处添购货物，添购资金总额不超过原合同采购金额多少的，可以采用单一来源方式采购？", "options": {"A": "5%", "B": "10%", "C": "15%", "D": "20%"}, "answer": ["B"], "analysis": "必须保证原有采购项目一致性或者服务配套的要求，需要继续从原供应商处添购，且添购资金总额不超过原合同采购金额10%的，可以采用单一来源方式采购。", "tags": ["政府采购法", "单一来源采购"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-049", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《政府采购法》，询价方式采购主要适用于什么类型的采购？", "options": {"A": "技术复杂、性质特殊的采购", "B": "采购规格标准统一、现货货源充足且价格变化幅度小的货物", "C": "只能从唯一供应商处采购的货物", "D": "时间紧急不能满足用户需要的采购"}, "answer": ["B"], "analysis": "询价适用于采购的货物规格标准统一、现货货源充足且价格变化幅度小的政府采购项目。", "tags": ["政府采购法", "询价"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-050", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《民法典》，合同的订立一般需经过什么程序？", "options": {"A": "邀约和受约", "B": "要约和承诺", "C": "申请和批准", "D": "发布和响应"}, "answer": ["B"], "analysis": "合同的订立需经过要约和承诺两个阶段。要约是希望与他人订立合同的意思表示，承诺是受要约人同意要约的意思表示。承诺生效时合同成立。", "tags": ["民法典合同编", "合同订立"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-051", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《民法典》，下列关于要约和要约邀请的说法正确的是？", "options": {"A": "要约和要约邀请是同一概念", "B": "商业广告在任何情况下都是要约", "C": "招标公告属于要约邀请", "D": "要约邀请一经发出即具有法律约束力"}, "answer": ["C"], "analysis": "要约邀请是希望他人向自己发出要约的表示，招标公告、拍卖公告、商业广告等为要约邀请。要约邀请本身不具有法律约束力。要约则是内容具体确定且表明经受要约人承诺即受约束的意思表示。", "tags": ["民法典合同编", "要约承诺"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-052", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《民法典》，要约可以撤销，撤销要约的通知应当在什么时间点之前到达受要约人？", "options": {"A": "承诺通知发出之前", "B": "受要约人发出承诺通知之前", "C": "合同成立之前", "D": "受要约人收到要约后24小时内"}, "answer": ["B"], "analysis": "要约可以撤销，但撤销要约的通知应当在受要约人发出承诺通知之前到达受要约人。", "tags": ["民法典合同编", "要约撤销"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-053", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《民法典》，合同何时成立？", "options": {"A": "要约发出时", "B": "要约到达受要约人时", "C": "承诺生效时", "D": "双方签字盖章时"}, "answer": ["C"], "analysis": "根据《民法典》，承诺生效时合同成立，但是法律另有规定或者当事人另有约定的除外。", "tags": ["民法典合同编", "合同订立"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-054", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《民法典》，建设工程的发包人可以将哪些工作分别发包给不同的承包人？", "options": {"A": "只能将整个工程整体发包给一个承包人", "B": "可以将勘察、设计、施工分别发包给不同的承包人", "C": "可以将主体结构分割后发包给不同承包人", "D": "只能将施工部分发包给总承包人"}, "answer": ["B"], "analysis": "发包人可以与总承包人订立建设工程合同，也可以分别与勘察人、设计人、施工人订立勘察、设计、施工承包合同。但是发包人不得将应当由一个承包人完成的建设工程支解成若干部分发包给数个承包人（不得肢解发包）。", "tags": ["民法典合同编", "建设工程合同"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-055", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《民法典》，总承包人或者勘察、设计、施工承包人经发包人同意，可以将自己承包的部分工作交由第三人完成。第三人与谁承担连带责任？", "options": {"A": "第三人与发包人", "B": "第三人与监理单位", "C": "第三人与总承包人就其完成的工作成果向发包人承担连带责任", "D": "第三人独立承担责任"}, "answer": ["C"], "analysis": "根据《民法典》，总承包人或者勘察、设计、施工承包人经发包人同意，可以将自己承包的部分工作交由第三人完成。第三人就其完成的工作成果与总承包人或者勘察、设计、施工承包人向发包人承担连带责任。", "tags": ["民法典合同编", "总包分包"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-056", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《民法典》，建设工程施工合同中关于总承包人与分包人的责任关系表述正确的是？", "options": {"A": "总承包人对发包人负责，分包人对总承包人负责，分包人不直接对发包人负责", "B": "总承包人和分包人就分包工程对发包人承担连带责任", "C": "分包人仅对自己施工的部分承担责任", "D": "发包人只能向总承包人主张权利"}, "answer": ["B"], "analysis": "根据《民法典》，总承包人或者勘察、设计、施工承包人经发包人同意将部分工作交由第三人完成的，第三人就其完成的工作成果与总承包人向发包人承担连带责任。这与《建筑法》规定一致。", "tags": ["民法典合同编", "总包分包"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-058", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《民法典》，没有资质的实际施工人借用有资质的建筑施工企业名义与他人签订建设工程施工合同，该合同效力如何？", "options": {"A": "有效", "B": "无效", "C": "效力待定", "D": "可撤销"}, "answer": ["B"], "analysis": "没有资质的实际施工人借用有资质的建筑施工企业名义与他人签订建设工程施工合同，属于无效合同。这是典型的【挂靠】行为。", "tags": ["民法典合同编", "无效合同"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-059", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《民法典》，承包人将承包的建设工程转包给第三人，该转包行为属于什么性质？", "options": {"A": "有效分包行为", "B": "合法但需备案的行为", "C": "违法分包行为，转包合同无效", "D": "经发包人同意后有效的行为"}, "answer": ["C"], "analysis": "承包人将承包的建设工程转包或违法分包的，该转包/分包合同无效。转包是法律明确禁止的行为，无论是否经发包人同意均属无效。", "tags": ["民法典合同编", "无效合同"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-061", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《民法典》，当事人在合同中既约定违约金又约定定金的，一方违约时对方应如何适用？", "options": {"A": "可以同时适用违约金和定金", "B": "只能适用违约金", "C": "只能适用定金", "D": "可以选择适用违约金或者定金"}, "answer": ["D"], "analysis": "当事人既约定违约金又约定定金的，一方违约时，对方可以选择适用违约金或者定金条款。定金不足以弥补损失的，可以请求赔偿超过定金数额的损失。但不能同时适用。", "tags": ["民法典合同编", "违约责任"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-063", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《民法典》，关于建设工程价款优先受偿权，下列说法正确的是？", "options": {"A": "建设工程价款优先受偿权劣后于抵押权", "B": "发包人未按约定付款的，承包人可以立即申请法院拍卖工程", "C": "发包人未按约定付款的，承包人可以催告发包人在合理期限内支付价款；逾期不支付的，可以申请法院将该工程依法拍卖", "D": "建设工程价款优先受偿权仅适用于国有投资工程"}, "answer": ["C"], "analysis": "《民法典》规定，发包人未按照约定支付价款的，承包人可以催告发包人在合理期限内支付价款。发包人逾期不支付的，除根据建设工程的性质不宜折价、拍卖外，承包人可以与发包人协议将该工程折价，也可以请求人民法院将该工程依法拍卖。建设工程的价款就该工程折价或者拍卖的价款优先受偿。", "tags": ["民法典合同编", "优先受偿权"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-064", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《民法典》，承包人就建设工程价款享有优先受偿权，行使该权利的前提是？", "options": {"A": "合同签订", "B": "工程竣工", "C": "发包人未按照约定支付价款，经承包人催告后在合理期限内仍未支付", "D": "发包人破产"}, "answer": ["C"], "analysis": "承包人行使建设工程价款优先受偿权需满足：①发包人未按约定支付价款；②承包人已催告；③催告后在合理期限内仍未支付。满足上述条件后方可申请法院拍卖。", "tags": ["民法典合同编", "优先受偿权"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-065", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《价格法》，我国价格的基本形式不包括？", "options": {"A": "市场调节价", "B": "政府指导价", "C": "政府定价", "D": "行业自律价"}, "answer": ["D"], "analysis": "根据《价格法》，我国实行并逐步完善宏观经济调控下主要由市场形成价格的机制。价格的制定应当符合价值规律，大多数商品和服务价格实行市场调节价，极少数商品和服务价格实行政府指导价或者政府定价。三种形式为：市场调节价、政府指导价、政府定价。", "tags": ["价格法", "价格形式"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-066", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《价格法》，我国大多数商品和服务价格实行什么价格形式？", "options": {"A": "政府定价", "B": "政府指导价", "C": "市场调节价", "D": "行业指导价"}, "answer": ["C"], "analysis": "根据《价格法》，大多数商品和服务价格实行市场调节价，这是我国价格的主要形式。", "tags": ["价格法", "价格形式"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-068", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《价格法》，经营者销售、收购商品和提供服务应当怎么做？", "options": {"A": "私下协商价格", "B": "按照政府制定的价格执行", "C": "明码标价", "D": "根据竞争对手的价格调整"}, "answer": ["C"], "analysis": "根据《价格法》，经营者销售、收购商品和提供服务，应当按照政府价格主管部门的规定明码标价，注明商品的品名、产地、规格、等级、计价单位、价格或者服务的项目、收费标准等有关情况。", "tags": ["价格法", "明码标价"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-069", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "近年来，工程造价咨询企业资质管理改革的方向是？", "options": {"A": "加强行政审批", "B": "取消行政审批，改为备案制或告知承诺制", "C": "提高资质门槛", "D": "仅保留甲级资质"}, "answer": ["B"], "analysis": "工程造价咨询企业资质管理改革方向是取消行政审批，改为备案制或告知承诺制，降低市场准入门槛，加强事中事后监管。", "tags": ["造价管理制度", "资质改革"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-070", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "关于一级造价工程师和二级造价工程师的执业范围，下列表述正确的是？", "options": {"A": "一级造价工程师仅在注册地省内有效", "B": "二级造价工程师可以独立完成所有投资规模的造价咨询业务", "C": "一级造价工程师在全国范围内有效且无投资限额", "D": "二级造价工程师在全国范围内有效"}, "answer": ["C"], "analysis": "一级造价工程师在全国范围内有效，无投资限额。二级造价工程师仅在省内有效，可独立完成不超过5000万元的建设工程造价咨询业务。", "tags": ["造价管理制度", "一造二造"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-071", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "二级造价工程师可独立完成的建设工程造价咨询业务投资限额是多少？", "options": {"A": "3000万元以下", "B": "5000万元以下", "C": "8000万元以下", "D": "1亿元以下"}, "answer": ["B"], "analysis": "二级造价工程师可独立完成不超过5000万元的建设工程造价咨询业务。超过此投资规模需由一级造价工程师负责或二级造价工程师在一级造价工程师指导下完成。", "tags": ["造价管理制度", "一造二造"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-072", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据相关规定，二级造价工程师的执业证书在什么范围内有效？", "options": {"A": "全国范围内有效", "B": "注册所在省内有效", "C": "注册所在市内有效", "D": "行业协会规定的范围"}, "answer": ["B"], "analysis": "二级造价工程师执业证书在注册所在省、自治区、直辖市范围内有效。一级造价工程师在全国范围内有效。", "tags": ["造价管理制度", "一造二造"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-073", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "报考二级造价工程师，具有工程造价专业大学专科学历的需从事工程造价业务工作满几年？", "options": {"A": "1年", "B": "2年", "C": "3年", "D": "4年"}, "answer": ["B"], "analysis": "二级造价工程师报考条件：具有工程造价专业大学专科（或高等职业教育）学历，从事工程造价业务工作满2年。", "tags": ["造价管理制度", "报考条件"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-076", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "报考二级造价工程师，具有其他专业大学本科学历或学位的需从事工程造价业务工作满几年？", "options": {"A": "1年", "B": "2年", "C": "3年", "D": "4年"}, "answer": ["B"], "analysis": "具有其他专业大学本科学历或学位的，从事工程造价业务工作满2年。此条件与具有工程造价专业大学专科学历的工作年限要求相同。", "tags": ["造价管理制度", "报考条件"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-079", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "二级造价工程师考试科目中，基础科目的名称是？", "options": {"A": "建设工程造价管理", "B": "建设工程造价管理基础知识", "C": "建设工程法规及相关知识", "D": "建设工程经济"}, "answer": ["B"], "analysis": "二级造价工程师基础科目为【建设工程造价管理基础知识】，专业科目为【建设工程计量与计价实务】。【建设工程造价管理】和【建设工程计价】是一级造价工程师的科目。", "tags": ["造价管理制度", "考试科目"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-080", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "造价工程师注册有效期为几年？", "options": {"A": "2年", "B": "3年", "C": "4年", "D": "5年"}, "answer": ["C"], "analysis": "造价工程师注册有效期4年。期满需继续执业的，应在期满前30日内申请延续注册。", "tags": ["造价管理制度", "注册"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-081", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "造价工程师期满需继续执业的，应在注册有效期满前多长时间申请延续注册？", "options": {"A": "15日", "B": "30日", "C": "60日", "D": "90日"}, "answer": ["B"], "analysis": "造价工程师注册有效期为4年。期满需继续执业的，应在期满前30日内申请延续注册。", "tags": ["造价管理制度", "注册"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-082", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "造价工程师每一注册有效期内，继续教育学时应不少于多少学时？", "options": {"A": "60学时", "B": "80学时", "C": "100学时", "D": "120学时"}, "answer": ["D"], "analysis": "造价工程师每一注册有效期内（4年）继续教育学时不少于120学时，年均不少于30学时。", "tags": ["造价管理制度", "继续教育"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-083", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "造价工程师每年继续教育学时不少于多少学时？", "options": {"A": "20学时", "B": "30学时", "C": "40学时", "D": "50学时"}, "answer": ["B"], "analysis": "每一注册有效期内（4年）继续教育学时不少于120学时，年均不少于30学时。", "tags": ["造价管理制度", "继续教育"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-084", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "造价工程师继续教育学时中，必修课和选修课的学时要求分别是多少？", "options": {"A": "必修80学时，选修40学时", "B": "必修60学时，选修60学时", "C": "必修40学时，选修80学时", "D": "必修100学时，选修20学时"}, "answer": ["B"], "analysis": "每一注册有效期内（4年）继续教育学时不少于120学时，其中必修60学时，选修60学时，各占一半。", "tags": ["造价管理制度", "继续教育"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-085", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，在建的建筑工程中止施工满1年的，建设单位在恢复施工前应当怎么做？", "options": {"A": "直接恢复施工", "B": "报建设行政主管部门备案后恢复施工", "C": "报发证机关核验施工许可证", "D": "重新申请施工许可证"}, "answer": ["C"], "analysis": "中止施工满1年的工程恢复施工前，建设单位应当报发证机关核验施工许可证。不需要重新申请，只需核验。", "tags": ["建筑法", "施工许可"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-086", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，建设单位应当自中止施工之日起多长时间内向发证机关报告？", "options": {"A": "15日", "B": "1个月", "C": "2个月", "D": "1年"}, "answer": ["B"], "analysis": "在建工程因故中止施工的，建设单位应当自中止施工之日起1个月内向发证机关报告，并按照规定做好建筑工程的维护管理工作。", "tags": ["建筑法", "施工许可"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-087", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《招标投标法》，依法必须招标的项目采用公开招标方式的，下列说法错误的是？", "options": {"A": "招标人不得以不合理的条件限制或者排斥潜在投标人", "B": "招标人不得对潜在投标人实行歧视待遇", "C": "招标公告应当通过国家指定的报刊、信息网络或者其他媒介发布", "D": "招标人可以限定投标人必须为本地区企业"}, "answer": ["D"], "analysis": "公开招标不得以不合理的条件限制或者排斥潜在投标人，不得对潜在投标人实行歧视待遇。限定投标人必须为本地区企业属于不合理限制。", "tags": ["招标投标法", "公开招标"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-088", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《招标投标法》，评标委员会中技术、经济专家的最少人数是多少？", "options": {"A": "3人", "B": "4人", "C": "5人", "D": "6人"}, "answer": ["B"], "analysis": "评标委员会5人以上单数，技术经济专家不少于2/3。最小单数为5人时，2/3为3.33，向下取整至少需4名专家（因为实际不少于2/3，5×2/3≈3.33，需大于等于4人）。若7人则需5人。5人时专家至少4人。", "tags": ["招标投标法", "评标委员会"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-089", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《价格法》，政府指导价和政府定价适用于什么范围？", "options": {"A": "大多数商品和服务价格", "B": "所有商品和服务价格", "C": "极少数商品和服务价格", "D": "仅适用于公共服务价格"}, "answer": ["C"], "analysis": "根据《价格法》，大多数商品和服务价格实行市场调节价，极少数商品和服务价格实行政府指导价或者政府定价。", "tags": ["价格法", "价格形式"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-090", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《民法典》，要约生效的时间是？", "options": {"A": "要约人发出要约时", "B": "要约到达受要约人时", "C": "受要约人阅读要约时", "D": "受要约人发出承诺时"}, "answer": ["B"], "analysis": "根据《民法典》，要约生效的时间采用到达主义，即要约到达受要约人时生效。这与承诺的【到达主义】原则一致。", "tags": ["民法典合同编", "要约承诺"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-092", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《民法典》，关于建设工程合同订立方式，下列说法正确的是？", "options": {"A": "建设工程合同只能采用书面形式", "B": "建设工程合同可以采用口头形式", "C": "建设工程合同必须经过公证", "D": "建设工程合同必须采用招标方式订立"}, "answer": ["A"], "analysis": "根据《民法典》，建设工程合同应当采用书面形式，这是法定形式要求。不是所有工程都必须采用招标方式，满足条件的可以直接发包。合同不需要强制公证。", "tags": ["民法典合同编", "建设工程合同"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-093", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，下列哪项不属于建筑工程发包方式？", "options": {"A": "招标发包", "B": "直接发包", "C": "竞争性谈判发包", "D": "拍卖发包"}, "answer": ["D"], "analysis": "建筑工程的发包方式包括招标发包和直接发包两种。没有【拍卖发包】这一方式。竞争性谈判是政府采购的方式。", "tags": ["建筑法", "发包"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-094", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《必须招标的工程项目规定》，同时满足施工≥400万、货物≥200万、服务≥100万三个条件的项目，应当如何招标？", "options": {"A": "必须分别招标", "B": "可以打包招标", "C": "只需对其中一项招标", "D": "同一项目中可以合并进行，合并后达到相应规模标准的必须招标"}, "answer": ["D"], "analysis": "同一项目中可以合并进行的勘察、设计、施工、监理以及与工程建设有关的重要设备、材料等的采购，合同估算价合计达到相应标准的，必须招标。", "tags": ["招标投标法", "必须招标规模"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-095", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，建筑工程恢复施工时应当向发证机关报告，这一规定适用的前提是中止施工多长时间内？", "options": {"A": "中止施工1个月内的", "B": "中止施工未满1年的", "C": "中止施工满1年的", "D": "中止施工满2年的"}, "answer": ["B"], "analysis": "建筑工程恢复施工时应当向发证机关报告,适用于中止施工未满1年的情况。中止施工满1年的则需报发证机关核验施工许可证。", "tags": ["建筑法", "施工许可"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-096", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《招标投标法》，关于【经评审的最低投标价法】的说法正确的是？", "options": {"A": "投标价格最低的即为中标人", "B": "投标价格低于成本的也可以中标", "C": "能够满足招标文件实质性要求且经评审的投标价格最低的（低于成本的除外）为中标人", "D": "此方法不适用于工程建设项目招标"}, "answer": ["C"], "analysis": "经评审的最低投标价法要求：能够满足招标文件的实质性要求，并且经评审的投标价格最低；但是投标价格低于成本的除外。不能简单以最低价中标。", "tags": ["招标投标法", "中标条件"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-097", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《政府采购法》，公开招标作为政府采购的主要方式，如果要使用其他采购方式，应当获得什么部门批准？", "options": {"A": "采购人自行决定", "B": "经同级财政部门批准", "C": "经设区的市、自治州以上人民政府采购监督管理部门批准", "D": "经采购代理机构决定"}, "answer": ["C"], "analysis": "政府采购采用公开招标以外的采购方式的，应当在采购活动开始前获得设区的市、自治州以上人民政府采购监督管理部门的批准。", "tags": ["政府采购法", "采购方式"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-101", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，施工许可证自行废止的情形是？", "options": {"A": "延期超过1次的", "B": "既不开工又不申请延期或者超过延期时限的", "C": "工程投资额变更的", "D": "施工企业变更的"}, "answer": ["B"], "analysis": "建设单位自领取施工许可证之日起3个月内开工，可申请延期2次各3个月。既不开工又不申请延期或者超过延期时限的，施工许可证自行废止。", "tags": ["建筑法", "施工许可"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-102", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "关于二级造价工程师考试，下列哪项表述是正确的？", "options": {"A": "考试全部科目均实行4年为一个周期的滚动管理", "B": "考试实行2年为一个周期的滚动管理", "C": "所有科目须在同一年内通过", "D": "考试成绩永久有效"}, "answer": ["B"], "analysis": "二级造价工程师职业资格考试成绩实行2年为一个周期的滚动管理办法。一级造价工程师为4年滚动管理。", "tags": ["造价管理制度", "考试"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-103", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，工程监理单位与被监理工程的承包单位以及建筑材料供应单位之间的关系应当是？", "options": {"A": "应当有隶属关系", "B": "可以有经济合作关系", "C": "不得有隶属关系或者其他利害关系", "D": "应当属于同一集团"}, "answer": ["C"], "analysis": "《建筑法》规定，工程监理单位与被监理工程的施工承包单位以及建筑材料、建筑构配件和设备供应单位不得有隶属关系或者其他利害关系，以保证监理的独立性和公正性。", "tags": ["建筑法", "监理单位"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-104", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《民法典》，下列关于建设工程合同无效后处理的说法正确的是？", "options": {"A": "建设工程施工合同无效，承包人无权请求支付工程款", "B": "建设工程施工合同无效，但建设工程经验收合格的，可以参照合同关于工程价款的约定折价补偿承包人", "C": "合同无效后双方均不承担任何责任", "D": "合同无效后发包人可以无偿获得已建工程"}, "answer": ["B"], "analysis": "《民法典》规定，建设工程施工合同无效，但是建设工程经验收合格的，可以参照合同关于工程价款的约定折价补偿承包人。这是对实际施工人权益的保护。", "tags": ["民法典合同编", "无效合同"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-105", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，下列关于建筑施工企业安全生产的表述正确的是？", "options": {"A": "施工企业不需要编制安全技术措施", "B": "施工企业在编制施工组织设计时应根据建筑工程的特点制定相应的安全技术措施", "C": "安全技术措施由建设单位负责编制", "D": "只有大型工程才需要编制安全技术措施"}, "answer": ["B"], "analysis": "施工单位在编制施工组织设计时，应当根据建筑工程的特点制定相应的安全技术措施；对专业性较强的工程项目，应当编制专项安全施工组织设计，并采取安全技术措施。", "tags": ["建筑法", "安全责任"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-106", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《价格法》，政府指导价是指？", "options": {"A": "政府直接制定的固定价格", "B": "完全由市场决定的价格", "C": "政府规定基准价及其浮动幅度，经营者在此范围内自主定价", "D": "行业协会制定的价格"}, "answer": ["C"], "analysis": "政府指导价是政府价格主管部门或者其他有关部门按照定价权限和范围规定基准价及其浮动幅度，指导经营者制定的价格。有别于政府定价的固定性和市场调节价的完全自主性。", "tags": ["价格法", "价格形式"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-107", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《民法典》，建设工程施工合同中关于发包人【不得肢解发包】的规定，下列理解正确的是？", "options": {"A": "发包人必须将全部工程发包给一个总承包人", "B": "发包人可以分别与勘察人、设计人、施工人订立合同，但不得将应由一个承包人完成的工程支解发包", "C": "发包人不得将任何部分单独发包", "D": "肢解发包仅指将主体结构分割发包"}, "answer": ["B"], "analysis": "《民法典》规定发包人可与总承包人订立合同，也可分别与勘察人、设计人、施工人订立勘察、设计、施工承包合同，但不得将应当由一个承包人完成的建设工程支解成若干部分发包给数个承包人。", "tags": ["民法典合同编", "建设工程合同"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-108", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，关于建筑工程质量保修的表述正确的是？", "options": {"A": "质量保修范围仅包括主体结构", "B": "供热与供冷系统保修期为1个采暖期、供冷期", "C": "质量保修期从竣工验收合格之日起计算", "D": "质量保修期从合同签订之日起计算"}, "answer": ["C"], "analysis": "建设工程质量保修期自竣工验收合格之日起计算。供热供冷系统为2个采暖供冷期（B错误），保修范围包括基础和主体、防水、供热供冷、电气给排水装修等（A错误）。", "tags": ["建筑法", "质量保修"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-109", "date": "2026-07-08", "chapter": "g01", "type": "single", "stem": "根据《招标投标法》，招标公告应当载明的事项不包括？", "options": {"A": "招标人的名称和地址", "B": "招标项目的性质、数量、实施地点和时间", "C": "获取招标文件的办法", "D": "投标人的具体名单"}, "answer": ["D"], "analysis": "招标公告应当载明招标人的名称和地址、招标项目的性质和数量及实施地点和时间、获取招标文件的办法等。投标人的具体名单不可能在招标公告中列出。", "tags": ["招标投标法", "公开招标"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "ht_mgmt_0386", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《合同法》，下列变更中属于新要约的是（）的变更。", "options": {"A": "要约确认方式", "B": "合同文件寄送方式", "C": "合同履行地点", "D": "承诺生效地点"}, "answer": ["C"], "analysis": "有关合同标的、数量、质量、价款或者报酬、履行期限、履行地点和方式、违约责任和解决争议方法等的变更，是对要约内容的实质性变更。受要约人对要约的内容作出实质性变更的，为新要约。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0387", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "按我国《合同法》的规定，对于无效合同或者被撤销的合同，其中仍具有法律效力且独立存在的是有关（）的条款。", "options": {"A": "违约责任", "B": "履行期限和地点", "C": "解决争议方式", "D": "质量保修范围"}, "answer": ["C"], "analysis": "对于无效合同或者被撤销的合同，其中仍具有法律效力且独立存在的是有关解决争议方式的条款。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0388", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "合同生效后，当事人就价款或者报酬没有约定或者约定不明确的，可以协议补充，不能达成补充协议的，按照合同有关条款或者交易确定。依照上述规定仍不能确定的，则（）。", "options": {"A": "按双方协商后的履行地市场价格履行", "B": "按订立合同时履行地的市场价格履行", "C": "按订立合同时，合同签订地的市场价格履行", "D": "按双方协商后的合同签订地的市场价格履行"}, "answer": ["B"], "analysis": "合同生效后，当事人就价款或者报酬没有约定或者约定不明确的，可以协议补充，不能达成补充协议的,按照合同有关条款或者交易确定。依照上述规定仍不能确定的，则按订立合同时履行地的市场价格履行。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0389", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "下列有关承担合同违约责任的说法中，正确的是（）。", "options": {"A": "违反合同的当事人在承担了赔偿金后，就免除了履约责任", "B": "当事人既约定了违约金，又约定定金的，一方违约，对方可以选择适用违约金或定金条款，但两种违约责任不能合并使用", "C": "当事人一方履行合同义务不符合约定，在采取补救措施后，对方还有其他损失的，就不应当再承担赔偿责任", "D": "合同约定了违约金的，因当事人一方违约使对方产生损失，不论损失多大，均只向损失方支付约定的违约金"}, "answer": ["B"], "analysis": "当事人既约定了违约金，又约定了定金的，一方违约，对方可以选择适用违约金或定金条款，但两种违约责任不能合并使用。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0390", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据我国《合同法》，与限制行为能力人订立的合同属于（）。", "options": {"A": "有效合同", "B": "无效合同", "C": "可撤销合同", "D": "效力待定合同"}, "answer": ["D"], "analysis": "力待定合同是指合同已经成立，但合同效力能否产生尚不能确定的合同。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0391", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《合同法》，下列各类合同中，属于可变更或可撤销合同的是（）。", "options": {"A": "以合法形式掩盖非法目的的合同", "B": "损害社会公共利益的合同", "C": "一方以胁迫手段订立的合同", "D": "恶意串通损害集体利益的合同"}, "answer": ["C"], "analysis": "当事人一方有权请求人民法院或者仲裁机构变更或者撤销的合同有： 1）因重大误解订立的； 2）在订立合同时显失公平的。 一方以欺诈、胁迫的手段或者乘人之危，使对方在违背真实意思的情况下订立的合同，受损害方有权请求人民法院或者仲裁机构变更或者撤销。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0392", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "一方当事人在紧迫情况下订立了明显对自己有重大不利的合同，情况好转后，该当事人向对方当事人提出变更合同未果，遂向人民法院提出了撤销合同的申请，该合同被法院予以撤销。则该合同的效力自（）起归于消灭。", "options": {"A": "合同变更请求之日", "B": "合同成立时", "C": "合同撤销请求之日", "D": "合同撤销裁定之日"}, "answer": ["B"], "analysis": "无效合同或者被撤销合同的法律后果。无效合同或者被撤销的合同自始没有法律约束力。合同部分无效，不影响其他部分效力的，其他部分仍然有效。合同无效、被撤销或者终止的，不影响合同中独立存在的有关解决争议方法的条款的效力。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0393", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据我国《合同法》，由于债权人的原因致使债务人难以履行债务时，债务人可以将标的物交给有关机关保存，以此来消灭合同的行为称为（）。", "options": {"A": "留置", "B": "保全", "C": "质押", "D": "提存"}, "answer": ["D"], "analysis": "提存是指由于债权人的原因致使债务人难以履行债务时，债务人可以将标的物交给有关机关保存，以此消灭合同的制度。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0394", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《合同法》，执行政府指导价的合同，当事人一方逾期交付标的物的，则（）。", "options": {"A": "无论价格升降，均按新价格执行", "B": "遇价格上涨时，按照新价格执行", "C": "无论价格升降，均按原价格执行", "D": "遇价格上涨时，按照原价格执行"}, "answer": ["D"], "analysis": "《合同法》规定，执行政府定价或政府指导价的，在合同约定的交付期限内政府价格调整时，按照交付时的价格计价。逾期交付标的物的，遇价格上涨时，按照原价格执行：价格下降时，按照新价格执行。逾期提取标的物或者逾期付款的，遇价格上涨时，按照新价格执行：价格下降时，按照原价格执行。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0395", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "某合同约定了违约金，当事人一方迟延履行的，根据《合同法》，违约方应支付违约金并（）。", "options": {"A": "终止合同履行", "B": "赔偿损失", "C": "继续履行债务", "D": "中止合同履行"}, "answer": ["C"], "analysis": "当事人就迟延履行约定违约金的，违约方支付违约金后，还应当履行债务。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0396", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "当事人既约定违约金，又约定定金的，一方违约时，对方可以选择适用违约金或者定金条款。甲、乙两单位签订了建设工程合同，但甲单位因丙单位的原因使合同延迟履行，则（）。", "options": {"A": "甲单位应向乙单位承担违约责任", "B": "丙单位应向乙单位承担违约责任", "C": "甲、乙两单位均可向丙单位提出索赔", "D": "乙单位无权解除合同"}, "answer": ["A"], "analysis": "因第三人原因造成违约时违约责任的承担。当事人一方因第三人的原因造成违约的，应当向对方承担违约责任。当事人一方和第三人之间的纠纷，依照法律规定或者依照约定解决。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0397", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，设计文件中选用的建筑材料、建筑构配件和设备，应当注明（）。", "options": {"A": "生产厂家", "B": "市场价格", "C": "规格、型号", "D": "保修期限"}, "answer": ["C"], "analysis": "《建筑法》规定，设计单位在设计文件中选用的建筑材料、建筑构配件和设备，应当注明规格、型号、性能等技术指标，其质量要求必须符合国家规定的标准。除有特殊要求的建筑材料、专用设备、工艺生产线等外，设计单位不得指定生产厂、供应商。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0398", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《建设工程质量管理条例》，下列关于工程最低保修期限的说法正确的是（）。", "options": {"A": "基础设施工程5 年", "B": "屋面防水工程3 年", "C": "供热与供冷系统，为5 个采暖期", "D": "设备安装和装修工程，为2 年"}, "answer": ["D"], "analysis": "工程质量保修:1.基础设施工程、房屋建筑的地基基础工程和主体结构工程,为设计文件规定的该工程合理使用年限;2.屋面防水工程、有防水要求的卫生间、房间和外墙面的防渗漏，为5 年;3.供热与供冷系统，为2 个采暖期、供冷期;4.电气管道、给排水管道、设备安装和装修工程，为2 年。其他工程的保修期限由发包方与承包方约定。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0399", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "若建设工程发生质量事故，有关单位应在（）h 内向当地建设行政主管部门和其他有关部门报告。", "options": {"A": "12", "B": "24", "C": "36", "D": "48"}, "answer": ["B"], "analysis": "建设工程发生质量事故，有关单位应当在24 小时内向当地建设行政主管部门和其他有关部门报告", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0400", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "县级以上地方人民政府建设行政主管部门在履行安全监督检查职责时，无权采取的措施有（）。", "options": {"A": "责令施工单位停止施工", "B": "要求被检查单位提供有关建设工程安全生产的文件和资料", "C": "进入被检查单位施工现场进行检查", "D": "纠正施中违反安全生产要求的行为"}, "answer": ["A"], "analysis": "县级以上地方人民政府建设行政主管部门和其他有关部门履行监督检查职责时,有权采取下列措施:①要求被检查的单位提供有关工程质量的文件和资料;②进入被检查单位的施工现场进行检查;③发现有影响工程质量的问题时，责令改正。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0401", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《建设工程质量管理条例》，施工人员对涉及结构安全的试块、试件以及有关材料，应当（）。", "options": {"A": "在建设单位监督下现场取样，并送具有相应资质等级的质量检测单位检测", "B": "在施工单位技术负责人监督下现场取样，并送具有相应资质等级的质量检测单位检测", "C": "在工程监理单位监督下现场取样，并送建设单位指定的质量检测单位检测", "D": "在工程监理单位监督下现场取样，并送工程监理单位指定的质量检测单位检测"}, "answer": ["A"], "analysis": "施工人员对涉及结构安全的试块、试件以及有关材料，应当在建设单位或者工程监理单位监督下现场取样，并送具有相应资质等级的质量检测单位进行检测。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0402", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《建筑法》的规定，下列关于建筑工程施工许可制度的表述中，建设单位的正确做法是（）。", "options": {"A": "在建工程因故中止施工之日起1 个月内向施工许可证颁发机关报告", "B": "在建工程因故中止施工之日起3 个月内向施工许可证颁发机关报告", "C": "对中止施工满6 个月的工程，恢复施工前应当报发证机关核验施工许可证", "D": "对中止施工满1 年的工程，恢复施工前应当重新办理施工许可证"}, "answer": ["A"], "analysis": "在建工程因故中止施工，建设单位应当自中止施工之日起1 个月内，向发证机关报告,并按照规定做好建设工程的维护管理工作。工程恢复施工时，应当向发证机关报告；对中止施工满1 年的工程，恢复施工前，建设单位应当报发证机关核验施工许可证。批准开工报告的建筑工程不能按期开工或中止施工的处理。按照国务院有关规定批准开工报告的建筑工程，因故不能按期开工或者中止施工的，应当及时向批准机关报告情况。因故不能按期开工超过6 个月的，应当重新办理开工报告的批准手续。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0403", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《招标投标法实施条例》，国有资金占控股或者主导地位的依法必须进行招标的项目，可以邀请招标的情形是（）。", "options": {"A": "需要向原中标人采购工程、货物或者服务", "B": "受自然环境限制", "C": "需要采用不可替代的专利", "D": "采购人依法能够自行建设"}, "answer": ["B"], "analysis": "《招标投标法实施条例》规定，目。国有资金占控股或者主导地位的依法必须进行招标的项目，应当公开招标；但有下列情形之一的，可以邀请招标：1)技术复杂、有特殊要求或者受自然环境限制，只有少量潜在投标人可供选择；2)采用公开招标方式的费用占项目合同金额的比例过大。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0404", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《招标投标法实施条例》，投标保证金有效期截止日应当为（）。", "options": {"A": "投标截止时间", "B": "投标截止日后20 天", "C": "投标有效期截止日", "D": "与中标人订立合同之日"}, "answer": ["C"], "analysis": "投标保证金有效期应当与投标有效期一致。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0405", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据我国《招标投标法》，招标人和中标人订立书面合同的时间应当是（）。", "options": {"A": "在中标通知书发出30 日内", "B": "在中标通知书发出60 日内", "C": "在评标结束后30 日内", "D": "在评标结束后60 日内"}, "answer": ["A"], "analysis": "招标人和中标人应当自中标通知书发出之日起30 日内,按照招标文件和中标人的投标文件订立书面合同。招标人和中标人不得再订立背离合同实质性内容的其他协议。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0406", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《招标投标法》的规定，自招标文件开始发出之日至投标人提交投标文件截止之日的期限不得短于（）日。", "options": {"A": "60", "B": "30", "C": "20", "D": "10"}, "answer": ["C"], "analysis": "依法必须进行招标的项目，自招标文件开始发出之日起至投标人提交投标文件截止之日止，最短不得少于20 日。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0407", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《招标投标法》，下列工程建设项目可以不进行招标的是（）。", "options": {"A": "关系社会公共利益、公众安全的项目", "B": "使用国有资金投资或者国家融资的项目", "C": "需要专有技术的大型企业投资建设的项目", "D": "使用国际组织或者外国政府贷款、援助资金的项目"}, "answer": ["C"], "analysis": "有下列情形之一的，可以不进行招标:①需要采用不可替代的专利或者专有技术;②采购人依法能够自行建设、生产或者提供;③已通过招标方式选定的特许经营项目投资人依法能够自行建设、生产或者提供;④需要向原中标人采购工程、货物或者服务，否则将影响施工或者功能配套要求。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0408", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《招标投标法实施条例》，对于采用两阶段招标的项目。投标人在第一阶段向招标人提交的文件是（）。", "options": {"A": "不带报价的技术建议", "B": "带报价的技术建议", "C": "不带报价的技术方案", "D": "带报价的技术方案"}, "answer": ["A"], "analysis": "对技术复杂或者无法精确拟定技术规格的项目，招标人可以分两阶 段进行招标：第一阶段，投标人按照招标公告或者投标邀请书的要求提交不带报价的技术建议，招标人根据投标人提交的技术建议确定技术标准和要求，编制招标文件。第二阶段，招标人向在第一阶段提交技术建议的投标人提供招标文件，投标人按照招标文件的要求提交包括最终技术方案和投标报价的投标文件。如招标人要求投标人提交投标保证金，应当在第二阶段提出。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0409", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《招标投标法》，招标人对已发出的招标文件进行修改的，应当在招标文件要求提交投标文件截止时间至少（）日前，通知所有招标文件收受人。", "options": {"A": "15", "B": "20", "C": "30", "D": "60"}, "answer": ["A"], "analysis": "招标人对已发出的招标文件进行必要的澄清或者修改的，应当在招标文件要求提交投标文件截止时间至少15 日前，以书面形式通知所有招标文件收受人。该澄清或者修改的内容为招标文件的组成部分。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0410", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "对于工程规模大、专业复杂的工程项目，建设单位的管理能力有限时，应考虑采用施工总承包的招标方式选择施工队伍。其优点与不足分别是（）。", "options": {"A": "工程报价低，但容易出现索赔风险", "B": "减少索赔风险，但有可能使工程报价相对较高", "C": "工期较短，但容易出现返工", "D": "工期较短，但容易出现索赔风险"}, "answer": ["B"], "analysis": "对于工程规模大、专业复杂的工程项目，建设单位的管理能力有限时，应考虑采用施工总承包的招标方式选择施工队伍。这样，有利于减少各专业之间因配合不当造成的窝工、返工、索赔风险。但采用这种承包方式，有可能使工程报价相对较高。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0411", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《招标投标法实施条例》，投标人撤回已提交的投标文件，应当在（）前，书面通知招标人。", "options": {"A": "投标截止时间", "B": "评标委员会开始评标", "C": "评标委员会结束评标", "D": "招标人发出中标通知书"}, "answer": ["A"], "analysis": "投标人撤回已提交的投标文件，应当在投标截止时间前书面通知招标人。招标人已收取投标保证金的，应当自收到投标人书面撤回通知之日起5 日内退还。投标截止后投标人撤销投标文件的，招标人可以不退还投标保证金。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0412", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《合同法》，下列关于格式条款合同的说法中，错误的是（）。", "options": {"A": "格式条款合同类似于合同示范文本，应由政府主管部门拟定", "B": "格式条款有两种以上解释的，应当作出不利于提供格式条款一方的解释", "C": "格式条款和非格式条款不一致的，应采用非格式条款", "D": "对格式条款的理解发生争议的，应按通常理解予以解释"}, "answer": ["A"], "analysis": "格式条款的拟定者是签订合同的某一方，不是政府主管部门，所以选项A 错误。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0413", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《招标投标法实施条例》的规定，下列关于资格预审的说法错误的是（）。", "options": {"A": "潜在投标人对资格预审文件有异议的，应当在提交资格预审申请文件截止时间2 日前提出", "B": "潜在投标人对资格预审文件有异议的，应当在提交资格预审申请文件截止时间5 日前提出", "C": "招标人应当自收到异议之日起3 日内作出答复", "D": "作出答复前，应当暂停招标投标活动"}, "answer": ["B"], "analysis": "各选项解析（依据《招标投标法实施条例》第 22/23 条，政务网权威文本）A 正确：异议需在提交资格预审申请文件截止时间2 日前提出，符合法定时间要求。B 错误：选项中 “5 日前” 与法定 “2 日前” 不符，时间节点错误。C 正确：招标人需在收到异议后3 日内作出答复，符合法定时限。D 正确：作出答复前应当暂停招标投标活动，是保障异议妥善处理的法定要求。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0414", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "—个买卖合同执行的是政府定价，2009 年2 月1 日订立合同时价格为每千克100元，合同规定2009 年4 月1 日交货，违约金为每千克10 元，交货后付款。但卖方直至2009 年6 月1 日才交货，而政府定价于2009 年5 月1 日调整为每千克120元，买方应当按照每千克（）元的价格向卖方付款。", "options": {"A": "90", "B": "100", "C": "110", "D": "120"}, "answer": ["A"], "analysis": "A 因为是卖方违约，所以要按照较低的价格执行，同时扣除他的违约金，那就是100-10=90 元。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0415", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《建设工程质量管理条例》的规定，下列关于施工单位工程施工的说法不正确的是（）。", "options": {"A": "必须按照工程设计图纸和施工技术标准施工", "B": "不得擅自修改工程设计", "C": "不得偷工减料", "D": "发现图纸有差错的及时修改"}, "answer": ["D"], "analysis": "施工单位必须按照工程课计图纸和施工技术标准施工,不得擅自修改工程设计，不得偷工减料。施工单位在施工过程中发现设计文件和图纸有差错的，应及时提出意见和建议。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0416", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "全面造价就是有效地使用专业知识和专门技术去（）资源、造价、盈利和风险。", "options": {"A": "估算", "B": "预测", "C": "筹划和控制", "D": "管理"}, "answer": ["C"], "analysis": "全面造价管理就是有效地使用专业知识和专门技术，对资源、造价、盈利和风险进行筹划和控制。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0417", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "我国建设工程造价管理组织包含的三大系统是指（）。", "options": {"A": "行业协会管理系统、地方行政管理系统和企事业机构管理系统", "B": "政府行政管理系统、企事业机构管理系统和行业协会管理系统", "C": "国家行政管理系统、行业协会管理系统和地方行政管理系统", "D": "国家行政管理系统、部门行政管理系统和地方行政管理系统"}, "answer": ["B"], "analysis": "我国建设工程造价管理组织包含的三大系统是:政府行政管理系统、企事业机构管理系统和行业协会管理系统。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0418", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "建设工程全要素造价管理是指要实现（）的集成管理。", "options": {"A": "人工费、材料费、施工机具使用费", "B": "直接成本、间接成本、规费、利润", "C": "工程成本、工期、质量、安全、环境", "D": "建筑安装工程费用、设备工器具费用、工程建设其他费用"}, "answer": ["C"], "analysis": "控制建设工程造价不仅仅是要控制建设工程本身的建造成本，还应同时考虑工期成本、质量成本、安全与环境成本的控制，从而实现工程成本、工期、质量、安全、环境的集成管理。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0419", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "注册造价工程师允许他人以自己名义从事工程造价业务，并有违法所得的，处以（）。", "options": {"A": "1 万元以上3 万元以下的罚款", "B": "1 万元以下罚款", "C": "违法所得3 倍以下且不超过3 万元的罚款", "D": "违法所得3 倍以上且不低于3 万元的罚款"}, "answer": ["C"], "analysis": "注册造价工程师有注册造价工程师不得有的行为之一的，由县级以上地方人民政府建设主管部门或者其他有关部门给予警告，责令改正，没有违法所得的，处以1 万元以下罚款，有违法所得的，处以违法所得3倍以下且不超过3 万元的罚款。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0420", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《注册造价工程师管理办法》的规定，对申请初始注册的和申请变更注册的，注册初审机关应当自受理申请之日起分别（）天内审查完毕。", "options": {"A": "5 和10", "B": "20 和10", "C": "20 和5", "D": "10 和20"}, "answer": ["C"], "analysis": "对申请初始注册的，注册初审机关应当自受理申请之日起20 日内审查完毕，并将申请材料和初审意见报国务院建设主管部门（以下简称注册机关）。注册机关应当自受理之日起20 日内作出决定。对申请变更注册、延续注册的，注册初审机关应当自受理申请之日起5 日内审查完毕，并将申请材料和初审意见报注册机关。注册机关应当自受理之日起10 日内作出决定。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0421", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《注册造价工程师管理办法》，聘用单位为申请人提供虚假注册材料的，有关部门给予的处罚是（）。", "options": {"A": "警告，并可处以1 万元以上3 万元以下的罚款", "B": "警告，并可处以1 万元以下的罚款", "C": "责令限期整改，并可处以1 万元以上3 万元以下的罚款", "D": "责令限期整改，并可处以1 万元以下的罚款"}, "answer": ["A"], "analysis": "对注册违规的处罚。 1）隐瞒有关情况或者提供虚假材料申请造价工程师注册的，不予受理或者不予注册，并给予警告，申请人在1 年内不得再次申请造价工程师注册。 2）聘用单位为申请人提供虚假注册材料的，由县级以上地方人民政府建设行政主管部门或者其他有关专业部门给予警告，并可处以1 万元以上、3 万元以下的罚款。 3）以欺骗、贿赂等不正当手段取得造价工程师注册的，由注册机关撤销其注册，3 年内不得再次申请注册，并由县级以上地方人民政府建设主管部门处以罚款。其中，没有违法所得的，处以1 万元以下罚款；有违法所得的，处以违法所得3 倍以下且不超过3 万元的罚款。 4）未按照规定办理变更注册仍继续执业的，由县级以上地方人民政府建设主管部门或者有关专业部门责令限期改正：逾期不改的，可处以5000 元以下的罚款。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0422", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《注册造价工程师管理办法》，注册造价工程师应在其执业活动中形成的工程造价成果文件上（）。", "options": {"A": "加盖人名单和执业印章", "B": "签字并加盖单位公章", "C": "加盖执业印章和单位公章", "D": "签字并加盖执业印章"}, "answer": ["D"], "analysis": "注册造价工程师应在本人执业活动中形成的工程造价成果文件上签字并加盖执业印章。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0423", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《注册造价工程师管理办法》的规定，下列关于注册造价工程师执业范围的表述正确的是（）。", "options": {"A": "修改工程造价成果文件，必须由签字盖章的注册造价工程师本人进行", "B": "工程款支付与工程索赔费用的计算", "C": "在本人所在单位承担的工程造价成果文件上签字并盖章", "D": "没有资格参与竣工结（决）算的编制和审核等工作"}, "answer": ["B"], "analysis": "注册造价工程师的执业范围:1)建设项目建议书、可行性研究投资估算的编制和审核，项目经济评价，工程概算、预算、结算，竣工结（决）算的编制和审核；2)工程量清单、标底（或者控制价)、投标报价的编制和审核，工程合同价款的签订及变更、调整，工程款支付与工程索赔费用的计算;3)建设项目管理过程中设计方案的优化、限额设计等工程造价分析与控制，工程保险理赔的核查；4)工程经济纠纷的鉴定。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0424", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《工程造价咨询企业管理办法》，在工程造价咨询企业出资人中，注册造价工程师人数至少为出资人总数的（）。", "options": {"A": "30%", "B": "40%", "C": "50%", "D": "60%"}, "answer": ["D"], "analysis": "按照《工程造价咨询企业管理办法》,在工程造价咨询企业出资人中，注册造价工程师人数至少为出资人总数的60%。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0425", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据我国现行规定，甲级和乙级工程造价咨询企业专职从事工程造价专业工作的人员中，取得造价工程师注册证书的人员分别不得少于（）人。", "options": {"A": "20 和12", "B": "16 和8", "C": "10 和6", "D": "8 和6"}, "answer": ["C"], "analysis": "本题考核的是工程造价咨询企业资质等级标准。根据我国现行规定，甲级和乙级工程造价咨询企业专职从事工程造价专业工作的人员中,取得造价工程师注册证书的人员分别不得少于10 和6 人。在本考核点中，有许多可能涉及人数的地方。例如，甲级和乙级工程造价咨询企业专职从事工程造价专业工作的人员中,具有工程或者工程经济类中级以上专业技术职称的人员不少于16 和8 人。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0426", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《工程造价咨询企业管理办法》，工程造价咨询企业跨省、自治区、直辖市承接工程造价咨询业务的，应当自承接业务之日起（）日内到建设工程所在地人民政府建设主管部门备案。", "options": {"A": "15", "B": "20", "C": "30", "D": "60"}, "answer": ["C"], "analysis": "工程造价咨询企业跨省、自治区、直辖市承接工程造价咨询业务的，应当自承接业务之日起30 日内到建设工程所在地人民政府建设主管部门备案。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0427", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据我国现行规定，工程造价咨询企业资质有效期届满，需要继续从事工程造价咨询活动的，需要提出资质延续申请，被准予延续的，其资质有效期可延续（）年。", "options": {"A": "1", "B": "2", "C": "3", "D": "5"}, "answer": ["C"], "analysis": "本题考核的是资质证书的管理。工程造价咨询企业资质有效期为3 年。资质有效期届满，需要继续从事工程造价咨询活动的，应当在资质有效期届满30 日前向资质许可机关提出资质延续申请。资质许可机关应当根据申请作出是否准予延续的决定。准予延续的，资质有效期延续3 年。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0428", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "从投资者（业主）角度分析，工程造价是指建设一项工程预期或实际开支的（）。", "options": {"A": "全部建筑安装工程费用", "B": "建设工程总费用", "C": "全部固定资产投资费用", "D": "建设工程动态投资费用"}, "answer": ["C"], "analysis": "从投资者（业主）的角度分析，工程造价是指建设一项工程预期开支或实际开支的全部固定资产投资费用。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0429", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "工程造价计算过程包含分部分项工程单价、单位工程造价、单项工程造价和建设项目总造价，体现了计价的（）特征。", "options": {"A": "单件性", "B": "多次性", "C": "组合性", "D": "依据复杂性"}, "answer": ["C"], "analysis": "工程造价的组合计价过程是:分部分项工程造价过程→单位工程造价过程→单项工程造价过程→建设项目总造价。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0430", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "某项目中建筑安装工程费用为560 万元，设备工器具购置费为330 万元，工程建设其他费用为133 万元，基本预备费102 万元，涨价预备费55 万元，建设期贷款利息59 万元，则静态投资为（）万元。", "options": {"A": "1023", "B": "1125", "C": "1180", "D": "1239"}, "answer": ["B"], "analysis": "静态投资包括建筑安装工程费、设备和工器具购置费、工程建设其他费用、基本预备费，以及因工程量误差而引起的工程造价的增减等。因此静态投资=560+330+133+102=1125(万元）", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0431", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "建筑产品的单件性特点决定了每项工程造价都必须（）。", "options": {"A": "分布组合", "B": "分层组合", "C": "多次计算", "D": "单独计算"}, "answer": ["D"], "analysis": "建筑产品的单件性特点指的是每个建筑构件都是独立的单元，不同的构件之间不能简单地进行组合或分层。因此，每项工程造价都必须进行单独计算，以确定每个构件的成本和工程总成本。因此，答案为D。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0432", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "在项目建设全过程的各个阶段中，都要进行相应的计价，这种（）计价是个逐步深化、逐步细化和逐步接近实际造价的过程。", "options": {"A": "多次性", "B": "组合性", "C": "复杂性", "D": "方法的多样性"}, "answer": ["A"], "analysis": "每个阶段都对应一个造价，这体现了造价的多次性。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0433", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "（）是建设项目进行决策、筹集资金和合理控制造价的主要依据。", "options": {"A": "投资估算", "B": "施工图预算", "C": "施工标底", "D": "初步设计总概算"}, "answer": ["A"], "analysis": "投资估算是建设项目进行决策、筹集资金和合理控制造价的主要依据。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0434", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《工程造价咨询企业管理办法》，工程造价咨询企业设立分支机构的，在分支机构执业的注册造价工程师不得少于（）人。", "options": {"A": "2", "B": "3", "C": "5", "D": "6"}, "answer": ["B"], "analysis": "工程造价咨询企业设立分支机构的，应当自领取分支机构营业执照之日起30 日内，持下列材料到分支机构工商注册所在地省、自治区、直辖市人民政府建设主管部门备案： （1）分支机构营业执照复印件； （2）工程造价咨询企业资质证书复印件； （3）拟在分支机构执业的不少于3 名注册造价工程师的注册证书复印件； （4）分支机构固定办公场所的租赁合同或产权证明。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0435", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《工程造价咨询企业管理办法》，工程造价咨询企业可被处1 万元以上3 万元以下罚款的情形是（）。", "options": {"A": "跨地区承接业务不备案的", "B": "出租、出借资质证书的", "C": "设立分支机构未备案的", "D": "提供虚假材料申请资质的"}, "answer": ["B"], "analysis": "工程造价咨询企业有下列行为之一的，由县级以上地方人民政府建设主管部门或者有关专业部门给予警告，责令限期改正，并处以1 万元以上3 万元以下的罚款： （1）涂改、倒卖、出租、出借资质证书，或者以其他形式非法转让资质证书； （2）超越资质等级业务范围承接工程造价咨询业务； （3）同时接受招标人和投标人或两个以上投标人对同一工程项目的工程造价咨询业务； （4）以给予回扣、恶意压低收费等方式进行不正当竞争； （5）转包承接的工程造价咨询业务； （6）法律、法规禁止的其他行为。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0436", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "美国建筑师学会(AI A)标准合同体系中，A 系列合同文件时关于（）之间的合同文件。", "options": {"A": "发包人与建筑师", "B": "建筑师与专业顾问公司", "C": "发包人与承包人", "D": "建筑师与承包人"}, "answer": ["C"], "analysis": "美国建筑师学会（AIA）的合同条件体系更为庞大，分为A、B、C、D、F、G 系列。其中，A 系列是关于发包人与承包人之间的合同文件；B 系列是关于发包人与提供专业服务的建筑师之间的合同文件；C 系列是关于建筑师与提供专业服务的顾问之间的合同文件；D 系列是建筑师行业所用的文件；F 系列是财务管理表格；G 系列是合同和办公管理表格。AIA 系列合同条件的核心是“通用条件”。采用不同的计价方式时，只需选用不同的“协议书格式”与“通用条件”结合。AIA 合同条件主要有总价、成本补偿及最高限定价格等计价方式。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0437", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《工程造价咨询企业管理办法》，乙级工程造价咨询企业可以从事工程造价（）万元以下各类建设项目的工程造价咨询业务。", "options": {"A": "2000", "B": "3000", "C": "4000", "D": "5000"}, "answer": ["D"], "analysis": "工程造价咨询企业依法从事工程造价咨询活动，不受行政区域限制。其中，甲级工程造价咨询企业可以从事各类建设项目的工程造价咨询业务；乙级工程造价咨询企业可以从事工程造价5000 万元人民币以下的各类建设项目的工程造价咨询业务。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0438", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "在香港，众多测量师事务所与专业人士之间相互联系和沟通的纽带是（）。", "options": {"A": "测量师协会", "B": "工程积算所", "C": "建筑标准协会", "D": "专业学会"}, "answer": ["D"], "analysis": "香港地区的专业学会是在众多测量师事务所与专业人士之间相互联系和沟通的纽带。这种学会在保护行业利益和推行政府决策方面起着重要作用，同时，学会与政府之间也保持着密切联系。学会内部互相监督、互相协调、互通情报，强调职业道德和经营作风。学会对工程造价起着指导和间接管理的作用，甚至也充当工程造价纠纷仲裁机构。当发承包双方不能相互协调或对工料测量师事务所的计价有异议吋，可以向学会提出仲裁申请。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0439", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "美国有关工程造价的定额、指标、费用标准等一般是由（）制定。", "options": {"A": "政府建设主管部门", "B": "土木工程师学会", "C": "大型工程咨询公司", "D": "建筑师学会"}, "answer": ["C"], "analysis": "在美国,有关工程造价的工程量计算规则、指标、费用标准等，一般是由各专业协会、大型工程咨询公司制订。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0440", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据我国现行的管理规定，资质许可机关应当依法注销工程造价咨询企业资质的情况包括（）。", "options": {"A": "超越资质等级业务范围承接工程造价咨询业务", "B": "转包承接的工程造价咨询业务", "C": "涂改资质证书", "D": "资质有效期满未申请延续的"}, "answer": ["D"], "analysis": "有下列情形之一的，资质许可机关应当依法注销工程造价咨询企业资质： （1）工程造价咨询企业资质有效期满，未申请延续的； （2）工程造价咨询企业资质被撤销、撤回的； （3）工程造价咨询企业依法终止的； （4）法律、法规规定的应当注销工程造价咨询企业资质的其他情形。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0441", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "工程造价咨询单位取得乙级资质证书（）后，达到甲级标准的，可以申请晋级。", "options": {"A": "2 年", "B": "3 年", "C": "5 年", "D": "6 年"}, "answer": ["B"], "analysis": "甲级工程造价咨询企业资质标准中，第一条是：已取得乙级工程造价咨询企业资质证书满3 年。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0442", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "应用美国建筑师学会（AI A）合同条件时，采用不同的计价方式只需选用相应的（）即可。", "options": {"A": "协议书格式与通用条件", "B": "财务管理表格与协议书格式", "C": "通用条件与专用条件", "D": "专用条件与财务管理表格"}, "answer": ["A"], "analysis": "应用美国建筑师学会(AIA)合同条件时,采用不同的计价方式只需选用相应协议书格式与通用条件即可。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0443", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "概算造价是指在采用三阶段设计的（）阶段确定工程造价的文件。", "options": {"A": "项目建议书", "B": "初步设计", "C": "技术设计", "D": "施工图设计"}, "answer": ["B"], "analysis": "修正概算造价是指在技术设计阶段，根据技术设计的要求，通过编制修正概算文件，预先测算和确定的工程造价。修正概算是对初步设计阶段的概算造价的修正和调整，比概算造价准确,但受概算造价控制。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0444", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《工程造价咨询单位管理办法》的规定，甲级和乙级工程造价咨询单位专职技术负责人从事工程造价专业工作的年限分别为（）年以上。", "options": {"A": "15 和10", "B": "12 和8", "C": "10 和8", "D": "8 和6"}, "answer": ["A"], "analysis": "甲级资质要求技术负责人从事工程造价专业工作15 年以上；乙级资质要求技术负责人从事工程造价专业工作10 年以上。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0445", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "下列关于工程建设静态投资或动态投资的表述中正确的是（）。", "options": {"A": "动态投资是静态投资的计算基础", "B": "动态投资中包括建设期贷款利息", "C": "静态投资中包括投资方向调节税", "D": "静态投资中包括涨价预备费"}, "answer": ["B"], "analysis": "静态投资是动态投资最主要的组成部分，也是动态投资的计算基础。涨价预备费及投资方向调节税都是属于动态投资的，所以选项C、D 错误。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0446", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《注册造价工程师管理办法》的规定，下列工作中属于造价工程师执业范围的是（）。", "options": {"A": "工程经济纠纷的调解与仲裁", "B": "投标报价的编制和审核", "C": "工程投资估算的审核与批准", "D": "工程概算的审核与批准"}, "answer": ["B"], "analysis": "工程造价咨询业务范围如下所述：1)建设项目建议书及可行性研究投资估算、项目经济评价报告的编制和审核；2)建设项目概预算的编制与审核，并配合设计方案比选、优化设计、限额设计等工作进行工程造价分析与控制；3)建设项目合同价款的确定,合同价款的签订与调整,工程款支付，工程结算、竣工结算和决算报告的编制与审核等；4)工程造价经济纠纷的鉴定和仲裁的咨询；5)提供工程造价信息服务等。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0447", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据我国现行的规定，取得造价工程师执业资格的人员，自资格证书签发之日起至申请初始注册和初始注册的有效期分别为（）。", "options": {"A": "3 个月和2 年", "B": "6 个月和1 年", "C": "1 年和4 年", "D": "6 个月和2 年"}, "answer": ["C"], "analysis": "根据我国现行的规定，取得造价工程师执业资格的人员，自资格证书签发之日起至申请初始注册和初始注册的有效期分别为1 年和4 年。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0448", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据我国现行规定，工程造价咨询企业出具的工程造价成果文件除由执行咨询业务的注册造价工程师签字、加盖执业印章外，还应当加盖（）。", "options": {"A": "工程造价咨询企业执业印章", "B": "工程造价咨询企业法定代表人印章", "C": "工程造价咨询企业技术负责人印章", "D": "工程造价咨询项目负责人印章"}, "answer": ["A"], "analysis": "工程造价咨询企业出具的成果文件应由工程咨询企业加盖有企业名称、资质等级及证书编号的执业印章并由执行咨询业务的注册造价工程师签字、加盖执业专用章。 本题库是以官方教材为依据，知识点所对应的习题综合了二建法规、二建管理、造价员基础、一级造价师考试的题库+真题编辑，基本上做到了每个知识点都有相对应的题目及解析,题库会陆续更新,会有模拟题,预测题及考前更新押题。 《建设工程计量与计价实务》题库编辑中,教材出来后会陆续更新 www.jinkaodian.com 金考典考试软件。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0449", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "下列工作中，属于工程项目策划阶段造价管理内容的是（）。", "options": {"A": "投资方案经济评价", "B": "编制工程量清单", "C": "审核工程概算", "D": "确定投标报价"}, "answer": ["A"], "analysis": "（1）工程项目策划阶段：按照有关规定编制和审核投资估算，经有关部门批准，即可作为拟建工程项目策划决策的控制造价。基于不同的投资方案进行经济评价，作为项目决策的重要依据。 本题库是以官方教材为依据，知识点所对应的习题综合了二建法规、二建管理、造价员基础、一级造价师考试的题库+真题编辑，基本上做到了每个知识点都有相对应的题目及解析,题库会陆续更新,会有模拟题,预测题及考前更新押题。 《建设工程计量与计价实务》题库编辑中,教材出来后会陆续更新 www.jinkaodian.com 金考典考试软件。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0450", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "发达国家对私人投资工程只进行政策引导和信息指导，体现了政府对造价的（）。", "options": {"A": "宏观管理", "B": "微观管理", "C": "直接管理", "D": "综合指导"}, "answer": ["A"], "analysis": "发达国家对私人投资工程只进行政策引导和信息指导,而不干预其具体实施过程，体现政府对造价的宏观管理和间接调控 本题库是以官方教材为依据，知识点所对应的习题综合了二建法规、二建管理、造价员基础、一级造价师考试的题库+真题编辑，基本上做到了每个知识点都有相对应的题目及解析,题库会陆续更新,会有模拟题,预测题及考前更新押题。 《建设工程计量与计价实务》题库编辑中,教材出来后会陆续更新 www.jinkaodian.com 金考典考试软件。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0451", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "(02年)根据《合同法》，具有撤销权的当事人自知道或者应当知道撤销事由之日起()年内没有行使撤销权，合同撤销权消灭。", "options": {"A": "1", "B": "2", "C": "3", "D": "4"}, "answer": ["A"], "analysis": "有下列情形之一的，撤销权消灭： 1）具有撤销权的当事人自知道或者应当知道撤销事由之日起1年内没有行使撤销权； 2）具有撤销权的当事人知道撤销事由后明确表示或者以自己的行为放弃撤销权。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0452", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "(00年)根据合同法，具有合同撤销权的当事人应在知道或者应当知道撤销事由之日起()年内行使撤销权。", "options": {"A": "1", "B": "2", "C": "3", "D": "4"}, "answer": ["A"], "analysis": "有下列情形之一的，撤销权消灭：①具有撤销权的当事人自知道或者应当知道撤销事由之日起1年内没有行使撤销权；②具有撤销权的当事人知道撤销事由后明确表示或者以自己的行为放弃撤销权。由此可见，当具有法律规定的可以撤销合同的情形时，当事人应当在规定的期限内行使其撤销权，否则，超过法律规定的期限时，撤销权归于消灭。此外，若当事人放弃撤销权，则撤销权也归于消灭。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0453", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "(2015年)关于合同争议仲裁的说法，正确的是()。", "options": {"A": "仲裁是诉讼的前置程序", "B": "仲裁裁决在当事人认可后具有法律约束力", "C": "仲裁裁决的强制执行须向人民法院申请", "D": "仲裁协议的效力须由人民法院裁定"}, "answer": ["C"], "analysis": "本题考查的是合同法。选项A错误，根据我国《仲裁法》，对于合同争议的解决，实行“或裁或审制”，即发生争议的合同当事人双方只能在“仲裁”或者“诉讼”两种方式中选择一种方式解决其合同争议，选项BD错误，仲裁裁决具有法律约束力。合同当事人应当自觉执行裁决。不执行的，另一方当事人可以申请有管辖权的人民法院强制执行。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0454", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "(2016年)根据《合同法》，合同生效后，当事人就价款约定不明确又未能补充协议的，合同价款应按()执行。", "options": {"A": "订立合同时履行地市场价格", "B": "订立合同时付款方所在地市场价格", "C": "标的物交付时市场价格", "D": "标的物交付时政府指导价"}, "answer": ["A"], "analysis": "该题主要考察的是：合同价款履行，价款或者报酬不明确的，按照订立合同时履行地的市场价格履行；依法应当执行政府定价或者政府指导价的，按照规定履行。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0455", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "(2009年)根据《合同法》，可撤销合同是指()的合同。", "options": {"A": "因重大误解订立", "B": "当事人恶意串通损害第三方利益所订立", "C": "违反行政法规强制性规定而订立", "D": "当事人未能履行保密义务而订立"}, "answer": ["A"], "analysis": "(1）合同可以变更或者撤销的情形。当事人一方有权请求人民法院或者仲裁机构变更或者撤销的合同有： 1)因重大误解订立的； 2）在订立合同时显失公平的。一方以欺诈、胁迫的手段或者乘人之危，使对方在违背真实意思的情况下订立的合同，受损害方有权请求人民法院或者仲裁机构变更或者撤销。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0456", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "（2017年考题）根据《合同法》关于要约和承诺的说法，正确的是（ ）。", "options": {"A": "撤回要约的通知应当在要约到达受要约人之后到达受要约人", "B": "承诺的内容应当与要约的内容一致", "C": "要约邀请是合同成立的必经过程", "D": "撤回承诺的通知应当在要约确定的承诺期限內到达要约人"}, "answer": ["B"], "analysis": "考查合同订立的程序，近三年都出了题。A 选项，撤回要约的通知应当在要约到达受要约人之前或者与要约同时到达受要约人；C 选项，合同订立需要两个环节：要约和承诺。D 选项，撤回承诺的通知应当在承诺通知到达要约人之前或者与承诺通知同时到达要约人。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0457", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "(2013年)根据《建设工程质量管理条例》，下列关于建设单位的质量责任和义务的说法，正确的是()。", "options": {"A": "建设单位报审的施工图设计文件未经审查批准的，不得使用", "B": "建设单位不得委托本工程的设计单位进行监理", "C": "建设单位使用未经验收合格的工程应有施工单位签署的工程保修书", "D": "建设单位在工程竣工验收后，应委托施工单位向有关部门移交项目档案"}, "answer": ["A"], "analysis": "该题主要考察的是：施工图设计文件审查 建设单位应当将施工图设计文件报县级以上人民政府建设主管部门或者其他有关部门审查。施工图设计文件未经审查批准的， 不得使用。故正确答案是A。实行监理的建设工程，建设单位应当委托具有相应资质等级的工程监理单位进行监理，也可以委托具有工程监理相应资质等级并与被监理工程的施工承包单位没有隶属关系或者其他利害关系的该工程的设计单位进行监理。B不对 :建设单位应当严格按照国家有关档案管理的规定，及时收集、整理建设项目各环节的文件资料，建立、健全建设项目档案，并在建设工程竣工验收后，及时向建设行政主管部门或者其他有关部门移交建设项目档案。D不对 C未经验收合格就使用，保修这块有待商椎。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0458", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "(2013年)根据《建设工程安全生产管理条例》，建设单位将保证安全施工的措施报送建设行政主管部门或者其他有关部门备案的时间是()。", "options": {"A": "建设工程开工之日起15日内", "B": "建设工程开工之日起30日内", "C": "开工报告批准之日起15日内", "D": "开工报告批准之日起30日内"}, "answer": ["C"], "analysis": "该题主要考察的是：建设单位的安全责任 依法批准开工报告的建设工程，建设单位应当自开工报告批准之日起15日内，将保证安全施工的措施报送建设工程所在地的县级以上地方人民政府建设行政主管部门或者其他有关部门备案。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0459", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "(2014年)根据《建设工程安全生产管理条例》，建设工程安全作业环境及安全施工措施所需费用，应当在编制（）时确定。", "options": {"A": "投资估算", "B": "工程概算", "C": "施工图预算", "D": "施工组织设计"}, "answer": ["B"], "analysis": "该题主要考察的是：建设单位的安全责任 建设单位在编制工程概算时，应当确定建设工程安全作业环境及安全施工措施所需费用；在申请领取施工许可证时，应当提供建设工程有关安全施工措施的资料。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0460", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "(2014年)根据《建设工程质量管理条例》，应当按照国家有关规定办理工程质量监督手续的单位是（）。", "options": {"A": "建设单位", "B": "设计单位", "C": "监理单位", "D": "施工单位"}, "answer": ["A"], "analysis": "该题主要考察的是：建设单位的质量责任和义务，建设单位在领取施工许可证或者开工报告前，应当按照国家有关规定办理工程质量监督手续。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0461", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "（2017年考题）根据《招标投标法实施条例》，招标文件要求中标人提交履约保证金的，履约保证金不得超过中标合同金额的（ ）。", "options": {"A": "2%", "B": "5%", "C": "10%", "D": "20%"}, "answer": ["C"], "analysis": "履约保证金不得超过中标合同金额的10%。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0462", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "(2012年)建设工程全寿命期造价是指建设工程的()之和。", "options": {"A": "初始建造成本与建成后的日常使用成本", "B": "建筑安装成本与报废拆除成本", "C": "土地使用成本与建筑安装成本", "D": "基本建设投资与更新改造投资"}, "answer": ["A"], "analysis": "建设工程全寿命期造价是指建设工程初始建造成本和建成后的日常使用成本之和，包括策划决策、建设实施、运行维护及拆除回收等各阶段费用。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0463", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "(2010年)按照优先性的原则，协调和平衡工期、质量、安全、环保与成本之间的对立统一关系，反映了()造价管理的思想。", "options": {"A": "全寿命期", "B": "全要素", "C": "全过程", "D": "全方位"}, "answer": ["B"], "analysis": "影响工程造价的因素很多。为此，控制建设工程造价不仅仅是控制建设工程本身的成本，还应同时考虑工期成本、质量成本、安全与环境成本的控制，从而实现工程造价、工期、质量、安全、环境的集成管理。全要素造价管理的核心是按照优先性的原则，协调和平衡工期、质量、安全、环保与成本之间的对立统一关系。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0464", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "(2011年)建设工程全要素造价管理的核心是()。", "options": {"A": "工程参建各方建立完善的工程造价管理协同工作机制", "B": "协调和平衡工期、质量、安全、环保与成本之间的对立统一关系", "C": "采取有效措施控制工程变更和索赔", "D": "做好前期策划和方案设计、实现建设工程全寿命期成本最小化"}, "answer": ["B"], "analysis": "全要素造价管理的核心是按照优先性原则， 协调和平衡工期、质量、安全、环保与成本之间的对立统一关系。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0465", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "(2010年)在调查—分析—决策基础之上的偏离—纠偏—再偏离—再纠偏的工程造价控制属于()。", "options": {"A": "前馈控制", "B": "预防控制", "C": "被动控制", "D": "全过程控制"}, "answer": ["C"], "analysis": "立足于调查—分析—决策基础之上的偏离—纠偏—再偏离—再纠偏的控制是一种被动控制，因为这样做只能发现偏离，不能预防可能发生的偏离。为尽可能地减少以至避免目标值与实际值的偏离，还必须立足于事先主动地采取控制措施，实施主动控制。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0466", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "(2016年)下列工作中，属于工程招投标阶段造价管理内容的是()。", "options": {"A": "承发包模式选择", "B": "融资方案设计", "C": "组织实施模式选择", "D": "索赔方案设计"}, "answer": ["A"], "analysis": "该题主要考察的是：工程招投标阶段造价管理内 全过程造价管理是指複盖建设工程策划决策及建设实施各阶段的造价管理。包括：策划决策阶段的项目策划、投资估算、项目经济评价、 项目融资方案分析； 设计阶段的限额设计、方案比选、 概预算编制； 招投标阶段的标段划分、发承包模式及合同形式的选择、招标控制价或标底编制； 施工阶段的工程计量与结算、工程变更控制、索赔管理; 竣工验收阶段的结算与决算等。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0467", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "（2017年考题）政府部门、行业协会、建设单位、施工单位及咨询机构通过协调工作，共同完成工程造价控制任务，属于建设工程全面造价管理中的（ ）。", "options": {"A": "全过程造价管理", "B": "全方位造价管理", "C": "全寿命期造价管理", "D": "全要素造价管理"}, "answer": ["B"], "analysis": "考查建设工程全面造价管理的概念，常规考点。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0468", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "(2013年)根据《注册造价工程师管理办法》，取得造价工程师执业资格证书的人员逾期未申请初始注册的，须()后方可申请初始注册。", "options": {"A": "通过注册机关的考核", "B": "重新参加执业资格考试并合格", "C": "由聘用单位出具证明", "D": "符合继续教育的要求"}, "answer": ["D"], "analysis": "该题主要考察的是：造价师的初始注册，根据《注册造价工程师管理办法》，取得造价工程师执业资格证书的人员，可自资格证书签发之日起1年内申请初始注册。逾期未申请者，须符合继续教育的要求后方可申请初始注册。初始注册的有效期为4年。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0469", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "(12年)根据《注册造价工程师管理办法》，注册造价工程师注册有效期满需继续执业的，应在注册有效期满()日前，按照规定的程序申请延续注册。", "options": {"A": "5", "B": "10", "C": "20", "D": "30"}, "answer": ["D"], "analysis": "注册造价工程师注册有效期满需继续执业的，应当在注册有效期满30日前，按照规定的程序申请延续注册。延续注册的有效期为4年。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0470", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "(011年)根据《注册造价工程师管理办法》，造价工程师初始注册的有效期为()年。", "options": {"A": "2", "B": "3", "C": "4", "D": "5"}, "answer": ["C"], "analysis": "3）初始注册：取得造价工程师执业资格证书的人员， 可自资格证书签发之日起1 年内申请初始注册。逾期未申请者， 须出具近一年的继续教育证明方可申请初始注册。初始注册的有效期为4年。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0471", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "(2010年)下列关于造价工程师初始注册的说法中正确的是()。", "options": {"A": "初始注册申请者应递交工程造价岗位工作证明", "B": "初始注册申请者应当向聘用单位所在地县级主管部门提出申请", "C": "取得资格证书之日起1年内不得注册", "D": "初始注册的有效期为3年"}, "answer": ["A"], "analysis": "造价工程师注册实施电子化申报和审批，取得造价工程师执业资格证书的人员申请注册的，应通过全国造价工程师管理系统上传相关材料，除注册申请表外，不再提供书面材料。 上传数据时，也无须再提供人事代理证明和社会保险证明扫描件。初始注册：取得造价工程师执业资格证书的人员， 可自资格证书签发之日起1 年内申请初始注册。 逾期未申请者，须出具近 一年的继续教育证明方可申请初始注册。初始注册的有效期为4年。A可以参考注册条件。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0472", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "(2014年)根据《注册造价工程师管理办法》，取得造价工程师执业资格证书的人员，自资格证书签发之日起1年后申请初始注册的，应当提供（）证明。", "options": {"A": "工程造价咨询业绩", "B": "社会基本养老保险", "C": "医疗保险", "D": "继续教育合格"}, "answer": ["D"], "analysis": "该题主要考察的是：造价工程师的初始注册，取得造价工程师执业资格证书的人员， 可自资格证书签发之日起1 年内申请初始注册。逾期未申请者， 须出具近一年的继续教育证明方可申请初始注册。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0473", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "(0年)根据《注册造价工程师管理办法》，提供虚假材料申请造价工程师注册的，申请人在（）年内不得再次申请造价工程师注册。", "options": {"A": "1", "B": "2", "C": "3", "D": "4"}, "answer": ["A"], "analysis": "该题主要考察的是：造价工程师对注册违规的处罚，隐瞒有关情况或者提供虚假材料申请造价工程师注册的，不予受理或者不予注册，并给予警告，申请人在1年内不得再次申请造价工程师注册。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0474", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "(2015年)根据《注册造价工程师管理办法》，对于已取得造价工程师注册证书人员，发现有()的情形，应撤销其注册。", "options": {"A": "受到刑事处罚", "B": "以不正当手段获准注册", "C": "死亡或者丧失民事行为能力", "D": "已与聘用单位解除合同且未被其他单位聘用"}, "answer": ["B"], "analysis": "本题考查的是造价工程师管理制度。可以撤销注册造价工程师的情形：行政机关工作人员滥用职权、玩忽职守作出准予注册许可的；超越法定职权作出准予注册许可的；违反法定程序作出准予注册许可的；对不具备注册条件的申请人作出准予注册许可的；依法可以撤销注册的其他情形。同时，申请人以欺骗、贿赂等不正当手段获准注册的，应当予以撤销。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0475", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "(009年)根据《注册造价工程师管理办法》，注册造价工程师注册有效期满需继续执业的，其中延续注册，延续注册的有效期为()年。", "options": {"A": "2", "B": "3", "C": "4", "D": "5"}, "answer": ["C"], "analysis": "4）延续注册：注册造价工程师注册有效期满需继续执业的， 应当在注册有效期满30日前， 按照规定的程序申请延续注册。延续注册的有效期为4年。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0476", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "(2013年)根据《注册造价工程师管理办法》，注册造价工程师在每一注册有效期内应接受必修课()学时的继续教育。", "options": {"A": "48", "B": "60", "C": "96", "D": "120"}, "answer": ["B"], "analysis": "该题主要考察的是：造价师继续教育，注册造价工程师在每一注册有效期内应接受必修课和选修课各为60学时的继续教育。继续教育达到合格标准的，颁发继续教育合格证明。注册造价工程师继续教育由中国建设工程造价管理协会负责组织、管理、监督和检查。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0477", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "(05年)根据《注册造价工程师管理办法》，注册造价工程师职业刚满1年时变更注册单位，则该注册造价工程师在新单位的注册有效期为()年。", "options": {"A": "1", "B": "2", "C": "3", "D": "4"}, "answer": ["C"], "analysis": "本题考查的是造价工程师管理制度。初始注册为4年，在注册有效期内，注册造价工程师变更执业单位的，应当与原聘用单位解除劳动合同，并按照规定的程序办理变更注册手续。变更注册后延续原注册有效期，在新单位的注册有效期为4-1=3年。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0478", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "（07年考题）根据《注册造价师管理办法》，以欺骗手段取得造价工程师注册被撤销的，（ ）年内不得再次申请注册。", "options": {"A": "1", "B": "2", "C": "3", "D": "4"}, "answer": ["C"], "analysis": "考查法律责任，常规考点。以欺骗、贿赂等不正当手段取得造价工程师注册的，由注册机关撤销其注册，3 年内不得再次申请注册。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0479", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "(2014年)根据《工程造价师咨询企业管理办法》，甲级工程造价咨询企业技术负责人应当是注册造价工程师，并具有工程或工程经济类高级专业技术职称，且从事工程造价专业工作（）年以上。", "options": {"A": "8", "B": "10", "C": "12", "D": "15"}, "answer": ["D"], "analysis": "该题主要考察的是：工程造价咨询企业资质等级标准，甲级工程造价咨询企业的技术负责人是注册造价工程师，并具有工程或工程经济类高级专业技术职称，且从事工程造价专业工作15年以上。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0480", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "(201年)根据《工程造价咨询企业管理办法》，乙级工程造价咨询企业中，注册造价工程师应不少于()人。", "options": {"A": "6", "B": "8", "C": "10", "D": "12"}, "answer": ["A"], "analysis": "该题主要考察的是：乙级工程造价咨询企业资质标准， 专职专业人员不少于 12 人，其中，具有工程或者工程经济类中级以上专业技术职称的人员不少于 8 人，注册造价工程师不少于 6 人， 其他人员均需要具有从事工程造价专业工作的经历。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0481", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "(201年)根据《工程造价咨询企业管理办法》，申请甲级工程造价咨询企业资质，须取得乙级工程造价咨询企业资质证书满()年。", "options": {"A": "3", "B": "4", "C": "5", "D": "6"}, "answer": ["A"], "analysis": "该题主要考察的是：甲级工程造价咨询企业资质标准 根据《工程造价咨询企业管理办法》，申请甲级工程造价咨询企业资质，须已取得乙级工程造价咨询企业资质证书满3年。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0482", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "(2010年)根据《工程造价咨询企业管理办法》，属于甲级工程造价咨询企业资质标准的是()。", "options": {"A": "专职专业人员中取得造价工程师注册证书的人员不少于6人", "B": "企业注册资本不少于50万元", "C": "企业近3年工程造价咨询营业收入累计不低于人民币500万元", "D": "人均办公建筑面积不少于6㎡"}, "answer": ["C"], "analysis": "甲级工程造价咨询企业资质标准包括： ①已取得乙级工程造价咨询企业资质证书满3年； ②企业出资人中，注册造价工程师人数不低于出资人总人数的60%，且其出资额不低于企业注册资本总额的60%； ③技术负责人已取得造价工程师注册证书，并具有工程或工程经济类高级专业技术职称，且从事工程造价专业工作15年以上； ④专职从事工程造价专业工作的人员（以下简称专职专业人员）不少于20人，其中，具有工程或者工程经济类中级以上专业技术职称的人员不少于16人，取得造价工程师注册证书的人员不少于10人，其他人员均需要具有从事工程造价专业工作的经历； ⑤企业与专职专业人员签订劳动合同，且专职专业人员符合国家规定的职业年龄（出资人除外）； ⑥专职专业人员人事档案关系由国家认可的人事代理机构代为管理； ⑦企业注册资本不少于人民币100万元； ⑧企业近3年工程造价咨询营业收入累计不低于人民币500万元； ⑨具有固定的办公场所，人均办公建筑面积不少于10m2； ⑩技术档案管理制度、质量控制制度、财务管理制度齐全； ①①.企业为本单位专职专业人员办理的社会基本养老保险手续齐全； ①②.在申请核定资质等级之日前3年内无违规行为。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0483", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "(2009年)当年名义利率一定时，每年的计算期数越多，则年有效利率()。", "options": {"A": "与年名义利率的差值越大", "B": "与年名义利率的差值越小", "C": "与计息期利率的差值越小", "D": "与计息期利率的差值趋于常数"}, "answer": ["A"], "analysis": "本题考查的是有效利率。名义利率r是指计息周期利率i乘以一个利率周期内的计息周期数m所得的利率周期利率，即：r=im。有效利率是指资金在计息中所发生的实际利率，包括：(1)计息周期有效利率i=r/m。(2)利率周期有效利率 当年名义利率r一定时，每年计息期数m越多， ieff与r相差越大。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0484", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "(201年)根据《工程造价告询企业管理办法》，已取得乙级工程造价咨询企业资质证书满()年的企业，方可申请甲级资质。", "options": {"A": "3", "B": "4", "C": "5", "D": "6"}, "answer": ["A"], "analysis": "本题考查的是工程造价告询企业资质管理。已取得乙级工程造价咨询企业资质证书满3年，方可申请甲级资质。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0485", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "(2012年)下列工程造价中，由承包单位编制、发包单位或其委托的工程造价咨询机构审查的是()。", "options": {"A": "工程概算价", "B": "工程预算价", "C": "工程结算价", "D": "工程决算价"}, "answer": ["C"], "analysis": "结算价是指在工程竣工验收阶段，按合同调价范围和调价方法，对实际发生的工程量增减、设备和材料价差等进行调整后计算和确定的价格，反映的是工程项目实际造价。结算价一般由承包单位编制，由发包单位审查，也可委托具有相应资质的工程造价咨询机构进行审查。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0486", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "(2016年)工程项目的多次计价是一个()的过程。", "options": {"A": "逐步分解和组合，逐步汇总概算造价", "B": "逐步深化和细化，逐步接近实际造价", "C": "逐步分析和测算，逐步确定投资估算", "D": "逐步确定和控制，逐步积累竣工结算价"}, "answer": ["B"], "analysis": "该题主要考察的是：工程项目的计价多次性，多次计价是一个逐步深入和细化，不断接近实际造价的过程。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0487", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "（2017年考题）建设项目的造价是指项目总投资中的（ ）。", "options": {"A": "固定资产与流动资产投资之和", "B": "建筑安装工程投资", "C": "建筑安装工程费与设备费之和", "D": "固定资产投资总额"}, "answer": ["D"], "analysis": "考查工程造价的含义及相关概念，常规考点。建设项目总造价是指项目总投资中的固定资产投资总额。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0488", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "(2012年)美国建筑师学会(AI A)合同条件体系中的核心是()。", "options": {"A": "财务管理表格", "B": "专用条件", "C": "合同管理表格", "D": "通用条件"}, "answer": ["D"], "analysis": "合同条件体系的核心是“通用条件”。采用不同的计价方式时，只需选用不同的“协议书格式”与“通用条件”结合。AIA合同条件主要有总价、成本补偿及最高限定价格等计价方式。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0489", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "(2014年)在英国建设工程标准合同体系中，主要通用于房屋建筑工程的是（）合同体系。", "options": {"A": "ACA", "B": "JCT", "C": "AIA", "D": "ICA"}, "answer": ["B"], "analysis": "该题主要考察的是：发达国家和地区工程造价管理的特点，JCT是英国的主要合同体系之一，主要通用于房屋建筑工程。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0490", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "(2013年)下列费用中，属于建设工程静态投资的是()。", "options": {"A": "基本预备费", "B": "涨价预备费", "C": "建设期贷款利息", "D": "建设工程有关税费"}, "answer": ["A"], "analysis": "该题主要考察的是：静态投资定义 静态投资是指不考虑物价上涨、建设期贷款利息等影响因素的建设投资。静态投资包括：建筑安装工程费、设备和工器具购置费、工程建设其他费、^基本预备费， 以及因工程量误差而引起的工程造价增减值等。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0491", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "(2009年)对于政府投资项目而言，作为拟建项目工程造价最高限额的是经有关部门批准的()。", "options": {"A": "投资估算", "B": "工程概算", "C": "施工图预算", "D": "承包合同价"}, "answer": ["B"], "analysis": "(2）工程设计阶段：在限额设计、优化设计方案的基础上编制和审核工程概算、施工图预算。^对于政府投资工程而言，经有关部门批准的工程概算，将作为拟建工程项目造价的最高限额。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0530", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "关于合同履行过程中特殊情况处理的表述，正确的是（ ）。", "options": {"A": "债务人不可以中止履行或者将标的物提存", "B": "债务人提前履行债务给债权人增加的费用，由债权人负担", "C": "合同生效后，法定代表人、负责人、承办人变动，当事人可以不履行合同义务", "D": "合同生效后，当事人不得因姓名、名称的变更而不履行合同义务"}, "answer": ["D"], "analysis": "债权人分立、合并或者变更住所没有通知债务人，致使履行债务发生困难的，债务人可以中止履行或者将标的物提存。债权人可以拒绝债务人提前履行债 务，但提前履行不损害债权人利益的除外。债务人提前履行债务给债权人增加的费用，由债务人负担。合同生效后，当事人不得因姓名、名称的变更或者法定代表人、负责人、承办人的变动而不履行合同义务。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0531", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "受要约人超过期限发出承诺的，除要约人及时通知受要约人该承诺有效的以外，为（ ）。", "options": {"A": "邀请", "B": "要约邀请", "C": "新要约", "D": "承诺"}, "answer": ["C"], "analysis": "此题考查合同订立程序。受要约人超过承诺期限发出承诺的，除要约人及时通知受要约人该承诺有效的以外，为新要约。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0532", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "有关合同履行过程中的附随义务，叙述错误的是（ ）。", "options": {"A": "需要当事人提供必要的条件和说明的，当事人应当根据对方的需要提供必要的条件和说明", "B": "需要当事人一方予以协助的，当事人一方应无条件地为对方提供所需要的协助", "C": "需要当事人保密的，当事人应当保守其在订立和履行合同过程中所知悉的对方当事人的商业秘密、技术秘密等", "D": "有些情况需要及时通知对方的，当事人一方应及时通知对方"}, "answer": ["B"], "analysis": "合同履行过程中的附随义务： ①及时通知义务。有些情况需要及时通知对方的，当事人一方应及时通知对方。 ②提供必要条件和说明的义务。需要当事人提供必要的条件和说明的，当事人应当根据对方的需要提供必要的条件和说明。 ③协助义务。需要当事人一方予以协助的，当事人一方应尽可能地为对方提供所需要的协助。 ④保密义务。需要当事人保密的，当事人应当保守其在订立和履行合同过程中所知悉的对方当事人的商业秘密、技术秘密等。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0533", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "新建、 扩建、 改建的建筑工程， （ ） 必须在开工前向建设行政主管部门申请领取建设工程施工许可证", "options": {"A": "监理单位", "B": "建设单位", "C": "施工单位", "D": "设计单位"}, "answer": ["B"], "analysis": "本题考查的是建筑工程施工许可证的申请单位。根据《中华人民共和国建筑法》第三十二条规定，新建、扩建、改建的建筑工程，建设单位必须在开工前向建设行政主管部门申请领取建设工程施工许可证。因此，本题的正确答案为B，即建设单位。其他选项监理单位、施工单位、设计单位均不是申请建筑工程施工许可证的单位。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0534", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "对于涉及（ ） 工程的专项施工方案， 施工单位依法应当组织专家进行论证、 审查", "options": {"A": "地下暗挖工程", "B": "降水工程", "C": "脚手架工程", "D": "起重吊装工程"}, "answer": ["A"], "analysis": "本题考察的是在涉及地下暗挖工程的专项施工方案中，施工单位应当依法组织专家进行论证、审查的规定。正确答案为A。 解析： 根据《建设工程质量管理条例》第三十六条规定：“涉及地下暗挖、地基处理、基坑支护、高支模、模板、脚手架、起重吊装、爆破、防水、防腐、隧道、桥梁、隔声、隔热、消防、环保等专业工程的专项施工方案，施工单位应当组织专家进行论证、审查。”因此，对于涉及地下暗挖工程的专项施工方案，施工单位应当依法组织专家进行论证、审查。 综上所述，本题答案为A。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0535", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "招标人于2006年4月1日发布招标公告，2006年4月20日发布资格预审公告，2006年5月10日开始发售招标文件，投标人于投标截止日2006年6月10日及时递交了投标文件，2006年7月20日招标人发出中标通知书，则要约生效的时间是（ ）。", "options": {"A": "2006年4月1日", "B": "2006年5月10日", "C": "2006年6月10日", "D": "2006年7月20日"}, "answer": ["C"], "analysis": "本题考查的是招标合同的要约生效时间。要约生效时间是指要约方向受约方发出要约后，要约方收到受约方的接受意思表示时，要约生效的时间。 根据题目中的时间顺序，招标人于2006年4月1日发布招标公告，2006年4月20日发布资格预审公告，2006年5月10日发售招标文件，投标人于投标截止日2006年6月10日及时递交了投标文件，2006年7月20日招标人发出中标通知书。 因此，投标人在投标截止日2006年6月10日及时递交了投标文件，属于接受意思表示，要约生效的时间为C.2006年6月10日。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0536", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "《合同法》 规定， 要约撤销的条件是， 撤销要约的通知应当在（ ） 到达受要约人。", "options": {"A": "要约到达对方之前", "B": "受要约人发出承诺之后", "C": "受要约人发出承诺之前", "D": "承诺到达对方之前"}, "answer": ["C"], "analysis": "根据《合同法》第十一条规定，要约撤销的条件是撤销要约的通知应当在受要约人发出承诺之前到达受要约人。因此，本题的正确答案为C。选项A和D都与要约撤销的条件不符，选项B则是承诺的条件，与要约撤销无关。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0537", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "在采用格式条款的合同中， 提供格式条款一方对可能造成人身伤害而免除其责任的条款（ ） 。", "options": {"A": "有效", "B": "无效", "C": "经公证后有效", "D": "被拒绝后无效"}, "answer": ["B"], "analysis": "合同中免责条款无效情形 合同有下列情形之一的，合同无效： （1）造成对方人身损害的； （2）因故意或者重大过失造成对方财产损失的。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0538", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "某施工项目招标， 招标文件开始出售的时间为， 停止出售的时间为， 提交投标文件的截止时间为， 评标结束的时间为， 则投标有效期开始的时间为（ ）", "options": {"A": "3月20日", "B": "3月30日", "C": "4月25日", "D": "4月30日"}, "answer": ["C"], "analysis": "投标有效期是指投标人在投标文件中承诺的有效期限，一般为招标文件规定的时间。根据题目中的时间节点，投标有效期开始的时间应该是提交投标文件的截止时间，即4月25日。因此，答案选C。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0539", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《中华人民共和国建筑法》，关于施工许可证的有效期限，下列说法正确的是（ ）。", "options": {"A": "建设单位应当自领取施工许可证之日起6个月内开工", "B": "因故不能按期开工的，应当向当地政府申请延期", "C": "延期以三次为限，每次不超过3个月", "D": "既不开工又不申请延期或者超过延期时限的，施工许可证自行废止"}, "answer": ["D"], "analysis": "建设单位应当自领取施工许可证之日起3个月内开工。因故不能按期开工的，应当向发证机关申请延期；延期以两次为限，每次不超过 3个月。既不开工又不申请延期或者超过延期时限的，施工许可证自行废止。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0540", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "工程监理单位应当根据建设单位的委托，（ ）地执行监理任务。", "options": {"A": "公平、公开", "B": "自主、公正", "C": "客观、公正", "D": "独立、公平"}, "answer": ["C"], "analysis": "工程监理单位应当根据建设单位的委托，客观、公正地执行监理任务。工程监理人员发现工程设计不符合建筑工程质量标准或者合同约定的质量要求的，应当报告建设单位要求设计单位改正；认为工程施工不符合工程设计要求、施工技术标准和合同约定的，有权要求建筑施工企业改正。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0541", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "建设工程合同的纠纷一般都适用施工行为地的专属管辖，由（ ）管辖。", "options": {"A": "检察院", "B": "发生纠纷地的人民法院", "C": "工程所在地的人民法院", "D": "行政主管部门"}, "answer": ["C"], "analysis": "合同当事人双方可以在签订合同时约定选择诉讼方式解决合同争议，并依法选择有管辖权的人民法院，但不得违反《中华人民共和国民事诉讼法》关于级别管辖和专属管辖的规定。对于一般合同争议，由被告住所地或者合同履行地人民法院管辖。建设工程施工合同以施工行为地为合同履行地。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0542", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "下列关于合同履行的一般规定的表述，错误的是（ ）。", "options": {"A": "合同双方关于履行地点约定不明确的，给付货币的，应在接受货币一方所在地履行", "B": "合同双方关于价款或者报酬约定不明确的，应按照订立合同时履行地的市场价格履行", "C": "合同双方就履行期限约定不明确的，债权人可随时要求债务人履行，但应当给对方必要的准备时间", "D": "合同双方就履行方式约定不明确的，应按照有利于履行义务一方的方式履行"}, "answer": ["D"], "analysis": "价款或者报酬不明确的，按照订立合同时履行地的市场价格履行；依法应当执行政府定价或者政府指导价的，在合同约定的交付期限内政府价格调整时，按照交付时的价格计价。逾期交付标的物的，遇价格上涨时，按照原价格执行；价格下降时，按照新价格执行。逾期提取标的物或者逾期付款的，遇价格上涨时，按照新价格执行；价格下降时，按照原价格执行。履行地点不明确，给付货币的，在接受货币一方所在地履行；交付不动产的，在不动产所在地履行；其他标的，在履行义务一方所在地履行。履行期限不明确的，债务人可以随时履行，债权人也可以随时要求履行，但应当给对方必要的准备时间。履行方式不明确问题的处理方法。履行方式不明确的，按照有利于实现合同目的的方式履行。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0543", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "实行招标的工程合同价款在中标通知书发出（ ）天内，由发、承包人双方依据招标文件和中标人的投标文件在书面合同中约定。", "options": {"A": "30", "B": "40", "C": "45", "D": "60"}, "answer": ["A"], "analysis": "招标人和中标人应当自中标通知书发出之日起30日内，按照招标文件和中标人的投标文件订立书面合同。招标人和中标人不得再订立背离合同实质性内容的其他协议。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0544", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "关于《中华人民共和国合同法》中违约责任的特点，叙述错误的是（ ）。", "options": {"A": "违约责任主要是一种赔偿责任，因此，可由合同当事人在法律规定的范围内自行约定", "B": "只有合同当事人不履行或者不适当履行合同义务时，才应承担违约责任", "C": "与侵权责任和缔约过失责任不同，违约责任必须以当事人双方事先存在的有效合同关系为前提", "D": "它是由违约方向守约方承担的刑事责任"}, "answer": ["D"], "analysis": "违约责任具有以下特点: (1)以有效合同为前提。与侵权责任和缔约过失责任不同，违约责任必须以当事人双方事先存在的有效合同关系为前提。 (2)以合同当事人不履行或者不适当履行合同义务为要件。只有合同当事人不履行或者不适当履行合同义务时，才应承担违约责任。 (3)可由合同当事人在法定范围内约定。违约责任主要是一种赔偿责任，因此，可由合同当事人在法律规定的范围内自行约定。 (4)是一种民事赔偿责任。首先，它是由违约方向守约方承担的民事责任，无论是违约金还是赔偿金，均是平等主体之间的支付关系；其次，违约责任的确定，通常应以补偿守约方的损失为标准。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0545", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "标的物的提存时，债权人领取提存物的权利期限为（ ），超过该期限，提存物扣除提存费用后归国家所有。", "options": {"A": "1年", "B": "2年", "C": "3年", "D": "5年"}, "answer": ["D"], "analysis": "债权人领取提存物的权利期限为5年，超过该期限，提存物扣除提存费用后归国家所有。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0546", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "违约责任是指合同当事人不履行或者不适当履行合同义务所应承担的民事责任，违约责任具有的特点不包括（ ）。", "options": {"A": "以合同为前提", "B": "以合同当事人不履行或者不适当履行合同义务为要件", "C": "可由合同当事人在法定范围内约定", "D": "是一种民事赔偿责任"}, "answer": ["A"], "analysis": "违约责任是指合同当事人不履行或者不适当履行合同义务所应承担的民事责任。当事人一方明确表示或者以自己的行为表明不履行合同义务的，对方可以在履行期限届满之前要求其承担违约责任。违约责任具有以下特点： (1)以有效合同为前提； (2)以合同当事人不履行或者不适当履行合同义务为要件； (3)可由合同当事人在法定范围内约定； (4)是一种民事赔偿责任。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0547", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "以非对话方式作出的要约，没有确定承诺期限的，承诺应当（ ）。", "options": {"A": "在合理期限内到达", "B": "即时作出", "C": "在15日内到达", "D": "在30日内到达"}, "answer": ["A"], "analysis": "承诺应当在要约确定的期限内到达要约人。要约没有确定承诺期限的，承诺应当依照下列规定到达： ①除非当事人另有约定，以对话方式做出的要约，应当即时做出承诺； ②以非对话方式做出的要约，承诺应当在合理期限内到达。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0548", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《中华人民共和国合同法》的规定，属于可变更、可撤销合同的是（ ）的合同。", "options": {"A": "以欺诈、胁迫的手段订立损害国家利益", "B": "以合法形式掩盖非法目的", "C": "因重大误解订立或订立时显失公平", "D": "恶意串通，损害国家、集体或第三人利益"}, "answer": ["C"], "analysis": "合同可以变更或者撤销的情形。当事人一方有权请求人民法院或者仲裁机构变更或者撤销的合同有： 1) 因重大误解订立的； 2) 在订立合同时显失公平的。 一方以欺诈、胁迫的手段或者乘人之危，使对方在违背真实意思的情况下订立的合同，受损害方有权请求人民法院或者仲裁机构变更或者撤销。 选项ABD属于无效合同。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0549", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《中华人民共和国合同法》，撤销权应自具有撤销权的当事人知道或者应当知道撤销事由之日起（ ）内行使。", "options": {"A": "1年", "B": "2年", "C": "3年", "D": "5年"}, "answer": ["A"], "analysis": "具有撤销权的当事人自知道或者应当知道撤销事由之日起1年内没有行使撤销权，则撤销权消灭。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0550", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据现行有关保修规定，承包人应向业主出具质量保修书。下列内容中，不属于保修书中约定内容的是（ ）。", "options": {"A": "保修范围", "B": "保修期限", "C": "保修责任", "D": "保修金额"}, "answer": ["D"], "analysis": "建设工程实行质量保修制度。建设工程承包单位在向建设单位提交工程竣工验收报告时，应当向建设单位出具质量保修书。质量保修书中应当明确建设工程的保修范围、保修期限和保修责任等。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0551", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "房屋拆除应当由具备保证安全条件的建筑施工单位承担，由（ ）对安全负责。", "options": {"A": "建筑施工单位负责人", "B": "项目经理", "C": "专业监理工程师", "D": "项目技术负责人"}, "answer": ["A"], "analysis": "房屋拆除应当由具备保证安全条件的建筑施工单位承担，由建筑施工单位负责人对安全负责。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0552", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《政府釆购法实施条例》相关内容，政府采购合同后，中标文件要求中标人提交履约保证金的，履约保证金的数额不得超过政府采购合同金额的（）。", "options": {"A": "10%", "B": "20%", "C": "30%", "D": "40%"}, "answer": ["A"], "analysis": "根据《政府釆购法实施条例》相关内容，政府采购合同后，中标文件要求中标人提交履约保证金的，履约保证金的数额不得超过政府采购合同金额的10%。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0553", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "政府采购合同履行中，采购人需追加与合同标的相同的货物、工程或服务的，在不改变合同其他条款的前提下，可以与供应商协商签订补充合同，但所有补充合同的采购金额不得超过原合同采购金额的（）。", "options": {"A": "10%", "B": "20%", "C": "30%", "D": "40%"}, "answer": ["A"], "analysis": "政府采购合同履行中，采购人需追加与合同标的相同的货物、工程或服务的，在不改变合同其他条款的前提下，可以与供应商协商签订补充合同，但所有补充合同的采购金额不得超过原合同采购金额的10%.", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0554", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "招标文件要求投标人提交投标保证金的，投标保证金不得超过采购项目预算金额的（）。", "options": {"A": "10%", "B": "5%", "C": "3%", "D": "2%"}, "answer": ["D"], "analysis": "根据《政府釆购法实施条例》相关内容，招标文件要求投标人提交投标保证金的，投标保证金不得超过采购项目预算金额的2%。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0555", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "合同成立是指双方当事人依照有关法律对合同的内容进行协商并达成一致意见，合同是否成立的判断依据是（", "options": {"A": "要约是否生效", "B": "承诺是否生效", "C": "合同是否有效", "D": "合同是否生效"}, "answer": ["B"], "analysis": "承诺生效时合同成立。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0556", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《合同法》，与无权代理人签订合同的相对人可以催告被代理人在（）个月内予以追认。", "options": {"A": "1", "B": "2", "C": "3", "D": "6"}, "answer": ["A"], "analysis": "与无权代理人签订合同的相对人可以催告被代理人在1个月内予以追认。被代理人未作表示的，视为拒绝追认。合同被迫认之前，善意相对人有撤销的权利。撤销应当以通知的方式做出。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0557", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "建设工程已实际交付，但施工合同没有约定付款时间，则拖欠工程款利息的起算日期为（ ）。", "options": {"A": "提交竣工结算文件之日", "B": "确认竣工结算文件之日", "C": "竣工验收合格之日", "D": "工程实际交付之日"}, "answer": ["D"], "analysis": "本题考查的是最高人民法院司法解释有关要求。建设工程已实际交付，但施工合同没有约定付款时间，则拖欠工程款利息的起算日期为工程实际交付之日。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0558", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "《建筑法》规定，建设单位应当自领取施工许可证之日起（ ）个月内开工，因故不能按期开工的，应当向发证机关延期申请；延期以（ ）次为限，每次不超过3个月。", "options": {"A": "1；1", "B": "2；2", "C": "3；2", "D": "4；3"}, "answer": ["C"], "analysis": "本题考查的是建筑许可。设单位应当自领取施工许可证之日起3个月内开工。因故不能按期开工的，应当向发证机关申请延期；延期以两次为限，每次不超过3个月。既不开工又不申请延期或者超过延期时限的，施工许可证自行废止。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0559", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "某钢材供应合同在甲市订立，在乙市履行。合同中未对某型号钢材的价格作出约定，事后也没有达成补充协议。该型号钢材的价格：订立合同时，甲市每吨4300元，乙市每吨4150元；履行合同时，甲市每吨4200元，乙市每吨4250元。该型号钢材的结算价格应为每吨（ ）元。", "options": {"A": "4300", "B": "4250", "C": "4200", "D": "4150"}, "answer": ["D"], "analysis": "本题考查合同履行的原则。对于价款或报酬不明的，按订立合同时履行地的市场价格履行。履行地是乙市，订立合同时乙市价格是每吨4150元", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0560", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "招标人确定了中标人后，应向其发出中标通知书，并与其在（ ）日内签订合同。", "options": {"A": "90", "B": "5", "C": "30", "D": "60"}, "answer": ["C"], "analysis": "本题考查的是《招标投标法》相关内容。招标人和中标人应当自中标通知书发出之日起30日内，按照招标文件和中标人的投标文件订立书面合同。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0561", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "下列建设工程施工合同无效情况下产生的价款纠纷，法院不予支持的是（ ）", "options": {"A": "工程竣工验收合格，承包人请求按合同支付工程价款", "B": "工程竣工验收不合格、但修复后合格，发包人要求承包人承担修复费用", "C": "工程竣工验收不合格、修复后仍不合格，承包人请求支付工程价款", "D": "承包人超越资质等级签订施工合同，但竣工前取得相应资质等级，请求按照有效合同处理"}, "answer": ["C"], "analysis": "本题考查的是最高人民法院司法解释有关要求。若建设工程经竣工验收不合格的，根据修复结果处理：修复后，经竣工验收合格，发包人请求承包人承担修复费用的，应予支持。修复后，竣工验收不合格，承包人请求支付工程价款的，不予支持。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0562", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "下列解决建设工程合同纠纷的方式中，具有强制执行法律效力的是（ ）。", "options": {"A": "和解", "B": "调解", "C": "行政决定", "D": "仲裁"}, "answer": ["D"], "analysis": "本题考查的是解决合同争议的方法。施工合同争议的解决方式有4种，即和解、调解、仲裁和诉讼。其中，和解和调解的结果没有强制执行的法律效力，要靠当事人的自觉履行。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0563", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "采购人采购纳入集中采购目录的政府采购项目，必须委托（ ）代理采购。", "options": {"A": "集中采购机构", "B": "社会中介机构", "C": "政府采购管理办公室", "D": "主管部门"}, "answer": ["A"], "analysis": "本题考查的是政府采购当事人。采购人采购纳入集中采购目录的政府采购项目，必须委托集中采购机构代理采购", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0564", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《建设工程质量管理条例》，设计文件中选用的材料、构配件和设备，应当注明（ ）。", "options": {"A": "生产厂", "B": "规格和型号", "C": "供应商", "D": "使用年限"}, "answer": ["B"], "analysis": "本题考查的是勘察、设计单位的质量责任。设计文件中选用的材料、构配件和设备，应当注明规格、型号、性能等技术指标，其质量必须符合国家规定的标准。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0565", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "接受要约的承诺人要使发出的承诺不产生法律效力，则撤回承诺的通知应当在（ ）到达要约人。", "options": {"A": "要约到达受要约人之前", "B": "承诺通知到达要约人之前", "C": "承诺通知发出之前", "D": "承诺通知到达要约人之后"}, "answer": ["B"], "analysis": "本题考查的是承诺撤回。承诺可以撤回，撤回承诺的通知应当在承诺通知到达要约人之前或者与承诺通知同时到达要约人", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0566", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《合同法》有关合同转让的规定，下列关于债权转让的说法中，正确的是（ ）。", "options": {"A": "债权人应当通知债务人", "B": "债权人应当经债务人同意才可转让", "C": "主权利转让后从权利并不随之转让", "D": "无论何种情形合同债权都可以转让"}, "answer": ["A"], "analysis": "本题考查的是合同的变更和转让。债权转让权利的，债权人应当通知债务人。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0567", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "某承诺文件超过要约规定时间1天到达要约人， 按照邮寄文件收函邮局戳记标明的时间， 受要约人是在要求的时间投邮， 由于邮局错递而延误了到达时间， 对此情况， 该承诺文件应（ ）", "options": {"A": "因迟到而自然无效", "B": "必须经要约人发出接受通知后有效", "C": "必须经要约人发出拒绝通知后才无效", "D": "因非受要约人原因的迟到，要约人必须接受该承诺"}, "answer": ["C"], "analysis": "本题考查的是合同法中的要约接受规定。根据合同法第二十四条规定，要约人收到承诺人发出的接受通知，合同即成立。但是，如果承诺人的接受通知未按照要约规定的方式或者要求发出，或者在要约规定的期限内未发出，要约人可以视为要约已经被拒绝。因此，本题中承诺文件虽然是在要求的时间投邮，但是由于邮局错递而延误了到达时间，因此要约人可以视为要约已经被拒绝，即必须经要约人发出拒绝通知后才无效。因此，答案为C。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0568", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "按照我国《合同法》 规定， 由于合同当事人一方缺乏经验造成重大误解， 而订立了损害自己方利益的合同， 则该当事人可以（）", "options": {"A": "请求人民法院变更该合同", "B": "拒绝履行合同，宣布合同无效", "C": "请求行政主管部门撤销该合同", "D": "请求行政主管部门变更该合同"}, "answer": ["A"], "analysis": "根据《合同法》第四十条规定，当事人一方在订立合同时，由于缺乏经验，致使对有关条款的含义发生重大误解的，对于该条款，可以请求人民法院或者仲裁机构予以变更或者撤销。因此，本题的正确答案为A。B选项虽然提到了宣布合同无效，但是并没有提到请求人民法院，因此不正确。C和D选项则与合同法无关，不符合题意。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0569", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《招标投标法》 规定， 在招标文件要求提交投标文件的截止时间前， 投标人（ ）", "options": {"A": "可以补充修改或者撤回已经提交的投标的文件，并书面通知招标人", "B": "不得补充、修改、替代或者撤回已经提交的投标文件", "C": "须经过招标人的同意才可以补充、修改、替代已经提交的投标文件", "D": "撤回已经提交的投标文件的，其投标保证金将被没收"}, "answer": ["A"], "analysis": "本题考查《招标投标法》中对于投标文件的要求。根据《招标投标法》第二十四条规定，投标人可以在招标文件规定的提交投标文件的截止时间前，补充、修改或者撤回已经提交的投标文件，并书面通知招标人。因此，选项A为正确答案。选项B、C、D均与法律规定不符。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0570", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "按照建筑法及其相关规定， 投标人之间（ ） 不属于串通投标的行为。", "options": {"A": "相互约定抬高或者降低投标报价", "B": "约定在招标项目中分别以高、中、低价位报价", "C": "相互探听对方投标标价", "D": "先进行内部竞价，内定中标人后再参加投标"}, "answer": ["C"], "analysis": "本题考查建筑法及其相关规定对于串通投标的禁止行为的规定。根据《中华人民共和国招标投标法》第十二条规定，投标人不得串通投标，不得以任何形式妨碍或者限制招标人或者其他投标人参加投标。根据该法规定，选项A、B、D均属于串通投标的行为，而选项C相互探听对方投标标价则不属于串通投标的行为，因此答案为C。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0571", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "某项目招标， 经评标委员会评审认为所有投标都不符合招标文件的要求， 这时应当（ ） 。", "options": {"A": "与相对接近要求的投标人协商，改为议标确定中标人", "B": "改为直接发包", "C": "用原招标文件重新招标", "D": "修改招标文件后重新招标"}, "answer": ["D"], "analysis": "本题考查招标文件的重要性以及招标流程中的应对措施。根据题干，评标委员会认为所有投标都不符合招标文件的要求，因此需要重新招标。选项A与议标无关，选项B直接发包不符合招标流程，选项C重新招标需要使用原招标文件，而原招标文件已经被评审认为不符合要求，因此只能选择D修改招标文件后重新招标。因此，答案为D。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0572", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "建设单位申请领取施工许可证应具备的法定条件中，包括（ ）。", "options": {"A": "已经办理了建设用地申请", "B": "依法确定了建筑施工企业", "C": "已经领取了房屋拆迁许可证", "D": "建设资金已经到位"}, "answer": ["B"], "analysis": "本题考查的是建筑许可。申请领取施工许可证，应当具备如下条件：①已办理建筑工程用地批准手续；②在城市规划区内的建筑工程，已取得规划许可证；③需要拆迁的，其拆迁进度符合施工要求；④已经确定建筑施工单位；⑤有满足施工需要的施工图纸及技术资料；⑥有保证工程质量和安全的具体措施；⑦建设资金已经落实；⑧法律、行政法规规定的其他条件。参见教材P1。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0573", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "建设单位应当自建设工程竣工验收合格之日起（ ）日内，将建设工程竣工验收报告和规划、公安消防、环保等部门出具的认可文件或者准许使用文件报建设行政主管部门或者其他有关部门备案。", "options": {"A": "3", "B": "14", "C": "15", "D": "7"}, "answer": ["C"], "analysis": "本题考查的是工程竣工验收备案。建设单位应当自建设工程竣工验收合格之日起15日内，将建设工程竣工验收报告和规划、公安消防、环保等部门出具的认可文件或者准许使用文件报建设行政主管部门或者其他有关部门备案。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0574", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《中华人民共和国招标投标法》及相关法规，对必须招标的项目，招标人行为符合要求的是（ ）。", "options": {"A": "就同一招标项目向潜在投标人提供有差别的项目信息", "B": "委托两家招标代理机构，设置两处报名点接受投标人报名", "C": "以特定行业的业绩、奖项作为加分条件", "D": "限定或者指定特定的品牌"}, "answer": ["B"], "analysis": "本题考查的是《招标投标法实施条例》相关内容。招标人不得以不合理的条件限制、排斥潜在投标人或者投标人。招标人有下列行为之一的，属于以不合理条件限制、排斥潜在投标人或者投标人：①就同一招标项目向潜在投标人或者投标人提供有差别的项目信息；②设定的资格、技术、商务条件与招标项目的具体特点和实际需要不相适应或者与合同履行无关；③依法必须进行招标的项目以特定行政区域或者特定行业的业绩、奖项作为加分条件或者中标条件;④对潜在投标人或者投标人采取不同的资格审查或者评标标准;⑤限定或者指定特定的专利、商标、品牌、原产地或者供应商；⑥依法必须进行招标的项目非法限定潜在投标人或者投标人的所有制形式或者组织形式；⑦以其他不合理条件限制、排斥潜在投标人或者投标人。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0575", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "在建设工程招投标活动中，招标文件应当规定一个适当的投标有效期。投标有效期的开始计算之日为（ ）。", "options": {"A": "开始发放招标文件之日", "B": "投标人提交投标文件之日", "C": "投标人提交投标文件截止之日", "D": "停止发放招标文件之日"}, "answer": ["C"], "analysis": "本题考查的是《招标投标法实施条例》相关内容。投标有效期从提交投标文件的截止之日起算。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0576", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "政府在必要时可以不对（ ）商品价格实行政府指导价或政府定价。", "options": {"A": "资源稀缺的少数", "B": "自然垄断的", "C": "重要的公用事业", "D": "价格昂贵的"}, "answer": ["D"], "analysis": "本题考查的是《价格法》相关内容。价格昂贵的商品价格不属于政府定价范围。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0577", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据相关规定，工程未经竣工验收，发包人擅自使用的，以（ ）为实际竣工日期。", "options": {"A": "承包人提交竣工验收报告之日", "B": "转移占有工程之日", "C": "监理人组织竣工初验之日", "D": "发包人签发工程接收证书之日"}, "answer": ["B"], "analysis": "本题考查的是最高人民法院司法解释有关要求。根据相关规定，工程未经竣工验收，发包人擅自使用的，以转移占有工程之日为实际竣工日期。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0578", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "由两个以上的承包单位联合承包大型建筑工程的，共同承包的各方对所签订的承包合同的履行（ ）。", "options": {"A": "承担连带责任", "B": "承担同等责任", "C": "按联合承包协议分别承担责任", "D": "按承担工程量的比例承担责任"}, "answer": ["A"], "analysis": "本题考查联合承包的责任承担方式。联合承包是指两个或两个以上的承包单位共同承包一个工程，共同承担责任。在联合承包中，各方之间应当签订联合承包协议，明确各自的责任承担方式。根据《中华人民共和国合同法》的规定，联合承包的各方应当承担连带责任，即各方对合同的履行承担共同的责任，如有一方未能履行合同义务，其他各方应当承担相应的责任。因此，本题的正确答案为A。B、C、D选项都不符合联合承包的实际情况和法律规定。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0579", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "某高层住宅工程结构设计合理使用年限 60 年。屋面防水为一级，设计使用年限 15 年。工程于 2010年 6 月 5 日竣工验收合格并交付使用。施工单位出具的质量保修书中有下列内容，其中不符合法律法规要求的有（ ）。", "options": {"A": "基础工程的保修期限为60年", "B": "房间和外墙面的防渗漏的保修期限为5年", "C": "电气管线、给排水管道、装修工程的保修期限为1年", "D": "供热与供冷系统，为2个采暖期、供冷期"}, "answer": ["C"], "analysis": "依据《建筑工程质量管理条例》规定：基础和主体结构工程的最低保修期限为设计合理使用年限，题中为 60 年，因此选项 A 符合要求；屋面防水和外墙防渗漏工程的最低保修期限为 5 年，选项 B 符合要求；电气管线、给排水管道及装修工程的最低保修期限为 2 年，选项 C 将保修期写为 1 年，不符合要求；供热与供冷系统的保修期限为不少于两个采暖期、供冷期，选项 D 符合要求。因此，不符合法律法规要求的选项为 C。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0580", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《合同法》 的规定， 执行政府定价或政府指导价的， 在合同约定的交付期限内政府价格调整时， 按照（ ） 计价。", "options": {"A": "合同成立时的价格", "B": "标的物交付时的价格", "C": "交付期限内的最低价格", "D": "交付期限内的平均价格"}, "answer": ["B"], "analysis": "根据《合同法》第四十二条规定，当合同约定执行政府定价或政府指导价时，如果在交付期限内政府价格发生调整，应当按照合同约定的交付期限内政府定价或政府指导价计价。因此，本题答案为B，即按照标的物交付时的价格计价。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0581", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "合同当事人之间出现合同纠纷， 要求仲裁机构仲裁， 仲裁机构受理仲裁前提是当事人提交（ ）。", "options": {"A": "合同公证书", "B": "仲裁协议书", "C": "履约保函", "D": "合同担保书"}, "answer": ["B"], "analysis": "本题考查的是仲裁机构受理仲裁的前提条件。根据仲裁法的规定，当事人要求仲裁，应当提交仲裁协议书。因此，本题的正确答案为B。其他选项均与仲裁机构受理仲裁无关。合同公证书是指公证机关对合同内容进行公证，证明合同的真实性和合法性；履约保函是指保证人向受益人发出的保函，保证履行合同中的某些义务；合同担保书是指担保人为保证债务人履行合同义务而向债权人提供的担保文件。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0582", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "合同有关内容没有约定或者约定不明确问题的处理中，逾期提取标的物或者逾期付款的，遇价格上涨时，按照（ ）执行。", "options": {"A": "新价格", "B": "政府指导价", "C": "政府定价", "D": "原价格"}, "answer": ["A"], "analysis": "逾期交付标的物的，遇价格上涨时，按照原价格执行；价格下降时，按照新价格执行。 逾期提取标的物或者逾期付款的，遇价格上涨时，按照新价格执行；价格下降时，按照原价格执行。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0584", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《合同法》的规定，下列各项中，属于合同不成立的情形有（ ）。", "options": {"A": "甲向乙发出要约，乙作出承诺，该承诺除对履行地点提出异议外，其余内容均与要约一致", "B": "甲、乙约定以书面形式订立合同，但在签订书面合同之前甲已履行主要义务，乙接受了履行", "C": "甲、乙采用书面形式订立合同，但在双方签章之前，甲履行了主要义务，乙接受了履行", "D": "甲于5月10日向乙发出要约，要约规定承诺期限截止至5月20日，乙于5月18日发出承诺信函，但因其他原因该信函5月21日到达甲，甲未表示异议"}, "answer": ["A"], "analysis": "本题考查的是合同的成立。 （1）选项A属于对要约作了实质性修改，A错误；（2）当事人采用合同书形式订立合同的，自双方当事人签字或者盖章时合同成立，在签字或者盖章之前，当事人一方已经履行主要义务并且对方接受的，该合同成立，BC正确；（3）受要约人在承诺期限内发出承诺，按照通常情形能够及时到达要约人，但因其他原因承诺到达要约人时超过承诺期限的，除要约人及时通知受要约人因承诺超过期限不接受该承诺的以外，该承诺有效。承诺到达时生效，合同成立。D正确。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0585", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "建设工程施工合同约定，施工企业未按节点工期完成约定进度的工程单位可解除合同，此约定属于合同的（ ）。", "options": {"A": "附条件解除", "B": "附期限解除", "C": "附期限终止", "D": "附条件终止"}, "answer": ["A"], "analysis": "本题考查的是合同效力。附条件合同：（1）当事人对合同的效力可以约定附条件。附生效条件的合同，自条件成就时生效。附解除条件的合同，自条件成就时失效。（2）当事人为自己的利益不正当地阻止条件成就的，视为条件已成就；不正当地促成条件成就的，视为条件不成就。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0586", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "某施工承包商与材料供应商签订的材料采购合同中，约定的运输费用不明确，应（ ）。", "options": {"A": "由施工承包商承担", "B": "由材料供应商承担", "C": "由施工承包商和材料承包商各承担一半", "D": "建设单位承担"}, "answer": ["B"], "analysis": "本题考查的是合同履行的原则。履行费用的负担不明确的，由履行义务一方承担", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0587", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "依据《合同法》的规定，当合同履行方式不明确，按照（ ）的方式履行。", "options": {"A": "法律规定", "B": "有利于实现债权人的目的", "C": "有利于实现债务人的目的", "D": "有利于实现合同目的"}, "answer": ["D"], "analysis": "本题考查的是合同履行的原则。当合同履行方式不明确，按照有利于实现合同目的的方式履行。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0588", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "甲与乙签订了采购10吨水泥的采购合同，合同约定由乙向甲交付8吨，向丙交付2吨，这种情况表现为（ ）。", "options": {"A": "债务承担", "B": "债务人向第三人履行债务", "C": "债权转让", "D": "由第三人向债权人履行债务"}, "answer": ["B"], "analysis": "本题考查的是合同履行。乙是债务人，丙是第三方。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0589", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "债务人转移债务的，新债务人（ ）原债务人对债权人的抗辩权。", "options": {"A": "可以主张", "B": "不可以主张", "C": "应请求", "D": "一定要主张"}, "answer": ["A"], "analysis": "本题考查的是合同的变更和转让。债务人转移义务后，原债务人享有的对债权人的抗辩权也随债务转移而由新债务人享有，新债务人可以主张原债务人对债权人的抗辩。债务人转移义务的，新债务人应当承担与主债务有关的从债务，但该从债务专属于原债务人自身的除外。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0590", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "债务人将合同的义务全部或部分转移给第三人的必须（ ），否则，这种转移不发生法律效力。", "options": {"A": "通知债权人", "B": "经债权人的同意", "C": "经第三人同意", "D": "经批准、办理登记"}, "answer": ["B"], "analysis": "本题考查的是合同的变更和转让。债务人将合同的义务全部或部分转移给第三人的必须经债权人的同意，否则，这种转移不发生法律效力。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0591", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "合同一方当事人通过资产重组分立为两个独立的法人，原法人签订的合同（ ）。", "options": {"A": "自然终止", "B": "归于无效", "C": "仍然有效", "D": "可以撤销"}, "answer": ["C"], "analysis": "本题考查的是合同的变更和转让。当事人订立合同后合并的，由合并后的法入或者其他组织行使合同权利，履行合同义务。当事人订立合同后分立的，除另有约定的以外，由分立的法人或者其他组织对合同的权利和义务享有连带债权，承担连带债务。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0592", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "关于限制民事行为能力人订立的合同，叙述错误的是（ ）。", "options": {"A": "限制民事行为能力人订立的合同，经法定代理人追认后，该合同有效，但纯获利益的合同或者与其年龄、智力、精神健康状况相适应而订立的合同，不必经法定代理人追认", "B": "与限制民事行为能力人的年龄、智力、精神健康状况相适应而订立的合同，不必经其法定代理人追认，即为有效合同", "C": "根据我国《民法通则》，限制民事行为能力人是指12周岁以上不满16周岁的未成年人，以及不能完全辨认自己行为的精神病人", "D": "经过其法定代理人追认的合同，即为有效合同"}, "answer": ["C"], "analysis": "根据《中华人民共和国民法通则》，限制民事行为能力人是指8周岁以上不满18周岁的未成年人，以及不能完全辨认自己行为的精神病人。限制民事行为能力人订立的合同，经法定代理人追认后，该合同有效，但纯获利益的合同或者与其年龄、智力、精神健康状况相适应而订立的合同，不必经法定代理人追认", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0593", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "执行政府定价的合同，当事人一方逾期提取货物，遇到政府上调价格时，应当按（ ）执行。", "options": {"A": "原价格", "B": "新价格", "C": "市场价格", "D": "原价和新价的平均价格"}, "answer": ["B"], "analysis": "本题考查合同履行的原则。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0594", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《国务院关于投资体制改革的决定》实行备案制的项目是（）。", "options": {"A": "政府直接投资的项目", "B": "采用资金注入方式的政府投资项目", "C": "政府核准的投资项目目录外的企业投资项目", "D": "政府核准的投资项目目录内的企业投资项目"}, "answer": ["C"], "analysis": "根据《国务院关于投资体制改革的决定》（国发[2004]20号），政府投资项目实行审批制；非政府投资项目实行核准制或登记备案制。对于《政府核准的投资项目目录》以外的企业投资项目，实行备案制。除国家另有规定外，由企业按照属地原则向地方政府投资主管部门备案。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0595", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《工程造价咨询单位管理办法》的规定，乙级工程造价咨询单位的资质标准之一是：具有专业技术职称且从事工程造价专业工作的专职人员和取得造价程师注册证书的专业人员分别不少于（ ）。", "options": {"A": "20人和10人", "B": "20人和8人", "C": "12人和6人", "D": "12人和4人"}, "answer": ["C"], "analysis": "专职专业人员不少于12人，其中，具有工程或者工程经济类中级以上专业技术职称的人员不少于8人，取得造价工程师注册证书的人员不少于6人，其他人员具有从事工程造价专业工作的经历。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0596", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "关于工程造价咨询企业乙级资质标准的表述正确的是（ ）。", "options": {"A": "专职专业人员不少于20人", "B": "企业注册资本不少于人民币100万元", "C": "具有工程或者工程经济类中级以上专业技术职称的人员不少于10人", "D": "暂定期内工程造价咨询营业收入累计不低于人民币50万元"}, "answer": ["D"], "analysis": "乙级企业资质标准： (1)企业出资人中，注册造价工程师人数不低于出资人总人数的60%，且其认缴出资额不低于注册资本总额的60%； (2)技术负责人已取得造价工程师注册证书，并具有工程或工程经济类高级专业技术职称，且从事工程造价专业工作10年以上； (3)专职专业人员不少于12人，其中，具有工程或者工程经济类中级以上专业技术职称的人员不少于8人，取得造价工程师注册证书的人员不少于6人，其他人员具有从事工程造价专业工作的经历； (4)企业与专职专业人员签订劳动合同，且专职专业人员符合国家规定的职业年龄(出资人除外)； (5)专职专业人员人事档案关系由国家认可的人事代理机构代为管理； (6)企业注册资本不少于人民币50万元； (7)具有固定的办公场所，人均办公建筑面积不少于10m2； (8)技术档案管理制度、质量控制制度、财务管理制度齐全； (9)企业为本单位专职专业人员办理的社会基本养老保险手续齐全； (10)暂定期内工程造价咨询营业收入累计不低于人民币50万元； (11)在申请核定资质等级之日前3年内无违规行为 。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0597", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《工程造价咨询企业管理办法》，乙级工程造价咨询企业中专职从事工程造价专业工作的人员不得少于（）人。", "options": {"A": "8", "B": "10", "C": "12", "D": "16"}, "answer": ["C"], "analysis": "根据《工程造价咨询企业管理办法》，乙级工程造价咨询企业中,专职专业人员不少于12人，其中，具有工程或者工程经济类中级以上专业技术职称的人员不少于8人，取得造价工程师注册证书的人员不少于6人，其他人员均需要具有从事工程造价专业工作的经历。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0598", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "具有独立施工条件并能形成独立使用功能的建筑物及构筑物是（）。", "options": {"A": "单项工程", "B": "单位工程", "C": "分部工程", "D": "分项工程"}, "answer": ["B"], "analysis": "单位工程是指具备独立施工条件并能形成独立使用功能的工程。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0599", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "未取得工程造价咨询企业资质从事工程造价咨询活动或者超越资质等级承接工程造价咨询业务的，（ ）。", "options": {"A": "出具的工程造价成果文件无效，由有关部门给予处罚", "B": "出具的工程造价成果文件无效，但不给予处罚", "C": "出具的工程造价成果文件有效，由有关部门给予处罚", "D": "出具的工程造价成果文件有效，但不给予处罚"}, "answer": ["A"], "analysis": "本题考查的是工程造价咨询企业管理。未取得工程造价咨询企业资质从事工程造价咨询活动或者超越资质等级承接工程造价咨询业务的，出具的工程造价成果文件无效，由有关部门给予处罚。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0600", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "乙级工程造价咨询企业可以从事工程造价（ ）万元人民币以下的各类建设项目的工程造价咨询业务。", "options": {"A": "5000", "B": "10000", "C": "20000", "D": "25000"}, "answer": ["A"], "analysis": "乙级工程造价咨询企业可以从事工程造价5000万元人民币以下的各类建设项目的工程造价咨询业务。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0601", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "在设立甲级工程造价咨询企业时，企业出资人中，注册造价工程师人数不低于出资人总人数的（ ）%，且其出资额不低于企业注册资本总额的%。", "options": {"A": "30", "B": "40", "C": "20", "D": "60"}, "answer": ["D"], "analysis": "本题考查的是工程造价咨询企业管理。根据《工程造价咨询企业管理办法》的规定，甲级工程造价咨询企业出资人中，注册造价工程师人数不低于出资人总人数的60%，且其出资额不低于企业注册资本总额的60%。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0602", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "工程造价咨询企业的工程造价咨询业务范围不包括（ ）。", "options": {"A": "建设项目建议书及可行性研究投资估算、项目经济评价报告的审核", "B": "配合设计方案比选、优化设计、限额设计等工作进行工程造价分析与控制", "C": "工程竣工决算报告的审核", "D": "工程造价经济纠纷的仲裁"}, "answer": ["D"], "analysis": "本题考查的是工程造价咨询企业管理。工程造价咨询企业的工程造价咨询业务范围包括工程造价经济纠纷的鉴定和仲裁的咨询，而非工程造价经济纠纷的仲裁。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0603", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《工程造价咨询企业管理办法》，工程造价咨询企业应办理而未及时办理资质证书变更手续的，由资质许可机关责令限期办理，逾期不办理的，可处以（ ）以下的罚款。", "options": {"A": "5000元", "B": "1万元", "C": "2万元", "D": "3万元"}, "answer": ["B"], "analysis": "本题考查法律责任中经营违规责任。工程造价咨询企业不及时办理资质证书变更手续的，由资质许可机关责令限期办理；逾期不办理的，可处以 1 万元以下的罚款", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0604", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "关于甲级工程造价咨询企业的资质标准，叙述错误的是（ ）。", "options": {"A": "企业与专职专业人员签订劳动合同，且专职专业人员符合国家规定的职业年龄", "B": "专职专业人员人事档案关系由国家认可的人事代理机构代为管理", "C": "企业注册资本不少于人民币80万元", "D": "已取得乙级工程造价咨询企业资质证书满3年"}, "answer": ["C"], "analysis": "甲级企业资质标准： (1)已取得乙级工程造价咨询企业资质证书满3年； (2)企业出资人中，注册造价工程师人数不低于出资人总人数的60%，且其认缴出资额不低于企业注册资本总额的60%； (3)技术负责人已取得造价工程师注册证书，并具有工程或工程经济类高级专业技术职称，且从事工程造价专业工作15年以上； (4)专职从事工程造价专业工作的人员(以下简称专职专业人员)不少于20人，其中，具有工程或者工程经济类中级以上专业技术职称的人员不少于16人，取得造价工程师注册证书的人员不少于10人，其他人员具有从事工程造价专业工作的经历； (5)企业与专职专业人员签订劳动合同，且专职专业人员符合国家规定的职业年龄(出资人除外)；最新题库，考前【黑钻押题】，金考典软件考前更新，下载链接 www.jinkaodian.com (6)专职专业人员人事档案关系由国家认可的人事代理机构代为管理； (7)企业注册资本不少于人民币100万元； (8)企业近3年工程造价咨询营业收入累计不低于人民币500万元； (9)具有固定的办公场所，人均办公建筑面积不少于10m2； (10)技术档案管理制度、质量控制制度、财务管理制度齐全； (11)企业为本单位专职专业人员办理的社会基本养老保险手续齐全； (12)在申请核定资质等级之日前3年内无违规行为。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0605", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《注册工程造价咨询企业管理办法》，提供虚假材料申请工程造价咨询企业资质的，在（）年内不得再次申请工程造价咨询企业资质。", "options": {"A": "1", "B": "2", "C": "3", "D": "4"}, "answer": ["A"], "analysis": "申请人隐瞒有关情况或者提供虚假材料申请工程造价咨询企业资质的，不予受理或者不予资质许可，并给予警告，申请人在1年内不得再次申请工程造价咨询企业资质。最新题库，考前【黑钻押题】，金考典软件考前更新，下载链接 www.jinkaodian.com", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0606", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "建筑工程采用施工总承包的，建筑工程主体结构的施工必须由（ ）自行完成。", "options": {"A": "设计单位", "B": "总承包单位", "C": "监理单位", "D": "分包单位"}, "answer": ["B"], "analysis": "建筑工程总承包单位可以将承包工程中的部分工程发包给具有相应资质条件的分包单位。但是，除总承包合同中已约定的分包外，必须经建设单位认可。施工总承包的，建筑工程主体结构的施工必须由总承包单位自行完成。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0608", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "通过资格预审的申请人少于（ ）个的，应当重新招标。", "options": {"A": "3", "B": "4", "C": "5", "D": "7"}, "answer": ["A"], "analysis": "本题考查的是《招标投标法实施条例》相关内容。通过资格预审的申请人少于3个的，应当重新招标。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_1819", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "施工单位以施工总承包方式承揽了建设单位的新建住院大楼项目施工任务，并将桩基工程、幕墙工程分别分包给了施工单位丙和施工单位丁。则该项目的施工现场安全由（ ）负总责。", "options": {"A": "甲", "B": "乙", "C": "甲、丙、丁", "D": "甲、乙、丙、丁"}, "answer": ["A"], "analysis": "【考点来源】本题考查的是建筑法【选项分析】建设工程实行施工总承包的，由总承包单位对施工现场的安全生产负总责。", "tags": [], "source": "一、《建筑法》及相关条例", "src": "好题库"}, {"id": "ht_mgmt_1820", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "工程监理人员在监理过程中发现工程设计不符合合同约定的质量要求时，应采取的做法是（ ）。", "options": {"A": "通知设计单位改正", "B": "组织技术专家改正", "C": "报告建设单位要求设计单位改正", "D": "要求施工单位联系质监部门改正"}, "answer": ["C"], "analysis": "【考点来源】本题考查的是建筑法【选项分析】工程监理人员发现工程设计不符合建筑工程质量标准或者合同约定的质量要求的，应当报建设单位要求设计单位改正。", "tags": [], "source": "一、《建筑法》及相关条例", "src": "好题库"}, {"id": "ht_mgmt_1821", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "实行施工总承包的建筑工程，必须由总承包单位自行完成的是（ ）。", "options": {"A": "装饰工程", "B": "主体工程", "C": "安装工程", "D": "防水工程"}, "answer": ["B"], "analysis": "【考点来源】本题考查的是建筑法【选项分析】施工总承包的，建筑工程主体结构的施工必须由总承包单位自行完成。", "tags": [], "source": "一、《建筑法》及相关条例", "src": "好题库"}, {"id": "ht_mgmt_1822", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《中华人民共和国建筑法》，建筑工程发包方式正确的是（ ）。", "options": {"A": "必须实行招标发包", "B": "由建设单位自主选择采取招标发包或直接发包", "C": "由招标代理机构选择采取招标发包或直接发包", "D": "依法实行招标发包，对不适于招标发包的可以直接发包"}, "answer": ["D"], "analysis": "【考点来源】本题考查的是建筑法【选项分析】建筑工程依法实行招标发包，对不适于招标发包的可以直接发包。", "tags": [], "source": "一、《建筑法》及相关条例", "src": "好题库"}, {"id": "ht_mgmt_1823", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "建筑工程（限额以下的小型工程除外）开工前，应当由（ ）申请领取施工许可证。", "options": {"A": "施工单位", "B": "建设单位", "C": "监理单位", "D": "总承包单位"}, "answer": ["B"], "analysis": "【考点来源】本题考查的是建筑法【选项分析】《建筑法》规定除国务院建设行政主管部门确定的限额以下的小型工程外，建筑工程开工前，建设单位应当按照国家有关规定向工程所在地县级以上人民政府建设行政主管部门申请领取施工许可证。", "tags": [], "source": "一、《建筑法》及相关条例", "src": "好题库"}, {"id": "ht_mgmt_1824", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《中华人民共和国招标投标法》，开标工作应由（ ）主持。", "options": {"A": "技术方面的专家", "B": "投标人推选的代表", "C": "经济方面的专家", "D": "招标人"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是《招标投标法》相关内容【选项分析】开标工作由招标人主持，邀请所有投标人参加。", "tags": [], "source": "二、《招标投标法》及其实施条例", "src": "好题库"}, {"id": "ht_mgmt_1825", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《招标投标法实施条例》，潜在投标人对招标文件有异议的，应当在投标截止时间（ ）日前提出。", "options": {"A": "3", "B": "5", "C": "10", "D": "15"}, "answer": ["C"], "analysis": "【内容考查】本题考查的是《招标投标法实施条例》相关内容【选项分析】如潜在投标人或者其他利害关系人对资格预审文件有异议，应当在提交资格预审申请文件截止时间 2 日前提出；如对招标文件有异议，应当在投标截止时间 10 日前提出。", "tags": [], "source": "二、《招标投标法》及其实施条例", "src": "好题库"}, {"id": "ht_mgmt_1826", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "债权人分立、合并或者变更住所没有通知债务人，致使履行债务发生困难的，债务人可以中止履行或者将标的物（ ）。", "options": {"A": "变卖", "B": "提存", "C": "抵押", "D": "寄存"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是合同权利义务终止【选项分析】债权人分立、合并或者变更住所没有通知债务人，致使履行债务发生困难的，债务人可以中止履行或者将标的物提存。", "tags": [], "source": "四、《合同法》相关内容", "src": "好题库"}, {"id": "ht_mgmt_1828", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "根据《价格法》，政府在必要时可以实行政府指导价或者政府定价的价格不包括（ ）。", "options": {"A": "与人民生活关系重大的少数商品价格", "B": "公用事业价格", "C": "在政府指导价规定的幅度内制定的价格", "D": "资源稀缺的少数商品价格"}, "answer": ["C"], "analysis": "下列商品和服务价格，政府在必要时可以实行政府指导价或者政府定价：①与国民经济发展和人民生活关系重大的极少数商品价格；②资源稀缺的少数商品价格；③自然垄断经营的商品价格；④重要的公用事业价格；⑤重要的公益性服务价格。", "tags": [], "source": "五、《价格法》相关内容", "src": "好题库"}, {"id": "ht_mgmt_1833", "date": "2026-07-10", "chapter": "g01", "type": "single", "stem": "建设单位在办理工程质量监督注册手续时，需提供（ ）。", "options": {"A": "投标文件", "B": "专项施工方案", "C": "施工组织设计", "D": "施工图设计文件"}, "answer": ["C"], "analysis": "【内容考查】本题考查的是建设实施阶段工作内容【选项分析】建设单位在办理施工许可证之前应当到规定的工程质量监督机构办理工程质量监督注册手续。提交资料：a.施工图设计文件审查报告和批准书；b.中标通知书和施工、监理合同；c.建设单位、施工单位和监理单位工程项目的负责人和机构组成；d.施工组织设计和监理规划（监理实施细则）；e.其他需要的文件资料。", "tags": [], "source": "二、工程建设程序", "src": "好题库"}, {"id": "mgmt_hqwx_0110", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "根据《招标投标法实施条例》，投标人认为招投标活动不符合法律法规规定的，可以自知道或应当知道之日起（ ）日内向行政监督部投诉。", "options": {"A": "10", "B": "15", "C": "20", "D": "30"}, "answer": ["A"], "analysis": "【内容考查】本题考查的是《招标投标法实施条例》相关内容 【选项分析】如果投标人或者其他利害关系人认为招标投标活动不符合法律、行政法规规定，可以自知道或者应当知道之日起10日内向有关行政监督部门投诉。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0111", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "根据《招标投标法实施条例》，依法必须进行招标的项目可以不进行招标的情形是（ ）。", "options": {"A": "受自然环境限制只有少量潜在投标人", "B": "需要采用不可替代的专利或者专有技术", "C": "招标费用占项目合同金额的比例过大", "D": "因技术复杂只有少量潜在投标人"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是《招标投标法实施条例》相关内容 【选项分项】可以不招标的项目。有下列情形之一的，可以不进行招标： 1）需要采用不可替代的专利或者专有技术； 2）采购人依法能够自行建设、生产或者提供； 3）已通过招标方式选定的特许经营项目投资人依法能够自行建设、生产或者提供； 4）需要向原中标人采购工程、货物或者服务，否则将影响施工或者功能配套要求； 5）国家规定的其他特殊情形。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0112", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "根据《建设工程质量管理条例》，在正常使用条件下，设备安装工程的最低保修期限是（ ）年。", "options": {"A": "1", "B": "2", "C": "3", "D": "4"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是《建设工程质量管理条例》相关内容 【选项分析】根据《建设工程质量管理条例》，在正常使用条件下，建设工程最低保修期限为：（1）基础设施工程、房屋建筑的地基基础工程和主体结构工程，为设计文件规定的该工程合理使用年限；（2）屋面防水工程、有防水要求的卫生间、房间和外墙面的防渗漏，为5年；（3）供热与供冷系统，为2个采暖期、供冷期；（4）电气管道、给排水管道、设备安装和装修工程，为2年。其他工程的保修期限由发包方与承包方约定。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0114", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "根据《建设工程安全生产管理条例》，下列工程中，需要编制专项施工方案并组织专家进行论证、审查的是（ ）。", "options": {"A": "爆破工程", "B": "起重吊装工程", "C": "脚手架工程", "D": "高大模板工程"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是 《建设工程安全生产管理条例》相关内容 。 【选项分析】对下列达到一定规模的危险性较大的分部分项工程编制专项施工方案，并附具安全验算结果，经施工单位技术负责人、总监理工程师签字后实施，由专职安全生产管理人员进行现场监督：①基坑支护与降水工程；②土方开挖工程；③模板工程；④起重吊装工程；⑤脚手架工程；⑥拆除、爆破工程；⑦国务院建设行政主管部门或者其他有关部门规定的其他危险性较大的工程。 上述所列工程中涉及深基坑、地下暗挖工程、高大模板工程的专项施工方案，施工单位还应当组织专家进行论证、审查。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0115", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "根据《招标投标法》，下列关于招标投标的说法，正确的是（ ）。", "options": {"A": "招标分为公开招标、邀请招标和议标三种方式", "B": "联合体中标后，联合体各方应分别与招标人签订合同", "C": "招标人不得修改已发出的招标文件", "D": "投标文件应当对招标文件提出的实质性要求和条件作出响应"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是《招标投标法》相关内容 【选项分析】招标分为公开招标和邀请招标，联合体中标后，联合体应该共同与招标人签订合同，而不是分别签订，招标人可以对已经发出的招标文件进行修改，投标文件应当对招标文件提出的实质性要求和条件作出响应。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0116", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "根据《民法典》，下列关于定金的说法，正确的是（ ）。", "options": {"A": "债务人准备履行债务时，定金应当收回", "B": "给付定金的一方如不履行债务，无权要求返还定金", "C": "收受定金的一方如不履行债务，应当返还定金", "D": "当事人既约定违约金，又约定定金的，违约时适用违约金条款"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是违约责任。 【选项分析】 选项A错误，当事人可以依照《担保法》约定一方向对方给付定金作为债权的担保。债务人履行债务后，定金应当抵作价款或者收回； 选项B正确、选项C错误，给付定金的一方不履行约定的债务的，无权要求返还定金；收受定金的一方不履行约定的债务的，应当双倍返还定金； 选项D错误，当事人既约定违约金，又约定定金的，一方违约时，对方可以选择适用违约金或者定金条款，故D选项错误。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0117", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "根据《招标投标法实施条例》，招标文件中履约保证金不得超过中标合同金额的（ ）。", "options": {"A": "2%", "B": "5%", "C": "10%", "D": "20%"}, "answer": ["C"], "analysis": "【内容考查】本题考查的是《招标投标法实施条例》相关内容 【选项分析】履约保证金不得超过中标合同金额的10%。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0118", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "根据《招标投标法》的规定，中标人的投标应当符合的条件有（ ）。", "options": {"A": "能够最大限度地满足招标文件中规定的各项综合评价标准", "B": "具有一定的规模", "C": "拥有先进的设备", "D": "拥有优秀的技术人员"}, "answer": ["A"], "analysis": "【内容考查】本题考查的是《招标投标法》相关内容 【选项分析】中标人投标应当符合下列条件之一： 1）能够最大限度地满足招标文件中规定的各项综合评价标准； 2）能够满足招标文件的实质性要求，并且经评审的投标价格最低。但是投标价格低于成本的除外。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0120", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "根据我国《民法典》，撤销权应自债权人知道或应当知道撤销事由之日起（ ）内行使。", "options": {"A": "5年", "B": "2年", "C": "1年", "D": "6个月"}, "answer": ["C"], "analysis": "本题考查的是合同效力。 撤销权应自债权人知道或应当知道撤销事由之日起1年内行使。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0122", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "合同的订立需要经过要约和承诺两个阶段，按照我国《民法典》规定，要约和承诺的生效是指（ ）。", "options": {"A": "要约到达受要约人、承诺通知发出", "B": "要约通知发出、承诺通知发出", "C": "要约通知发出、承诺通知到达要约人", "D": "要约到达受要约人、承诺通知到达要约人"}, "answer": ["D"], "analysis": "本题考查的是合同订立。按照我国《民法典》规定，要约和承诺的生效是指要约到达受要约人、承诺通知到达要约人。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0123", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "根据《民法典》的规定，以下属于合同部分条款无效的情形是（ ）。", "options": {"A": "一方不承认合同", "B": "一方未履行合同规定的义务", "C": "合同解除", "D": "因故意或者重大过失造成对方财产损失的"}, "answer": ["D"], "analysis": "合同部分条款无效的情形。合同中的下列免责条款无效： 1）造成对方人身伤害的； 2）因故意或者重大过失造成对方财产损失的。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0125", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "根据《民法典》，合同价款或者报酬约定不明确，且通过补充协议等方式不能确定的，应按照（ ）的市场价格履行。", "options": {"A": "接受货币方所在地", "B": "合同订立地", "C": "给付货币方所在地", "D": "订立合同时履行地"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是合同履行 【选项分析】价款或者报酬不明确的，按照订立合同时履行地的市场价格履行}依法应当执行政府定价或者政府指导价的，按照规定履行。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0128", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "根据《政府釆购法实施条例》相关内容，招标文件要求投标人提交投标保证金的，投标保证金不得超过采购项目预算金额的（ ）。", "options": {"A": "10%", "B": "5%", "C": "3%", "D": "2%"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是《政府釆购法实施条例》相关内容 【选项分项】根据《政府釆购法实施条例》相关内容，招标文件要求投标人提交投标保证金的，投标保证金不得超过采购项目预算金额的2% 。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0129", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "根据《民法典》，关于要约和承诺的说法，正确的是（ ）。", "options": {"A": "撤回要约的通知应当在要约到达受要约人之后到达受要约人", "B": "承诺的内容应当与要约的内容一致", "C": "要约邀请是合同成立的必经过程", "D": "撤回承诺的通知应当在要约确定的承诺期限内到达要约人"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是合同订立 【选项分项】撤回要约的通知应当在要约到达受要约人之前或者与要约同时到达受要约人，A错误；要约邀请并不是合同成立过程中的必经过程，它是当事人订立合同的预备行为，这种意思表示的内容往往不确定，不含有合同得以成立的主要内容和相对人同意后受其约束的表示，在法律上无须承担责任，C错误；撤回承诺的通知应当在承诺通知到达要约人之前或者与承诺通知同时到达要约人，D错误。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0130", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "在下列情形中，不构成缔约过失责任的是指（ ）。", "options": {"A": "假借订立合同，恶意进行磋商", "B": "故意隐瞒与订立合同有关的重要事实或者提供虚假情况", "C": "有其他违背诚实信用原则的行为", "D": "当事人在履行合同中没有全面地履行合同的内容"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是合同订立。 【选项分析】当事人在订立合同过程中有下列情况之一，给对方造成损失的，应当承担损害赔偿责任： （1）假借订立合同，恶意进行磋商； （2）故意隐瞒与订立合同有关的重要事实或者提供虚假情况； （3）有其他违背诚实信用原则的行为。 关于选项D，是当事人在履行合同中的违约情形，不属于缔约过失责任。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0132", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "根据《民法典》，下列关于格式合同的说法，正确的是（ ）。", "options": {"A": "采用格式条款订立合同，有利于保证合同双方的公平权利", "B": "《民法典》规定的合同无效的情形适用于格式合同条款", "C": "对格式条款的理解发生争议的，应当做出有利于提供格式条款一方的解释", "D": "格式条款和非格式条款不一致的，应当采用格式条款"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是合同订立 【选项分析】格式条款无效。提供格式条款一方免除自己责任、加重对方责任、排除对方主要权利的，该条款无效。此外， 《民法典》 规定的合同无效的情形，同样适用于格式合同条款。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0133", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "根据《民法典》的相关规定，下列说法中不正确的是（ ）。", "options": {"A": "判断合同是否成立的依据是合同是否产生法律约束力", "B": "要约邀请不是合同成立的必经过程", "C": "承诺生效的地点为合同成立的地点", "D": "判断合同是否成立的依据是承诺是否生效"}, "answer": ["A"], "analysis": "【内容考查】本题考查的是合同订立 【选项分析】判断合同是否成立的依据是承诺是否生效，承诺生效时合同成立，承诺生效的地点为合同成立的地点。要约邀请不是合同成立的必经过程。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0134", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "根据我国《价格法》，制定关系群众切身利益的公用事业价格、公益性服务价格、自然垄断经营的商品价格时，应当建立（ ）制度。", "options": {"A": "听证会", "B": "公示", "C": "专家审议", "D": "人民代表评议"}, "answer": ["A"], "analysis": "【内容考查】本题考查的是《价格法》相关内容 【选项分析】根据我国《价格法》，政府应当依据有关商品或者服务的社会平均成本和市场供求状况、国民经济与社会发展要求以及社会承受能力，实行合理的购销差价、批零差价、地区差价和季节差价。制定关系群众切身利益的公用事业价格、公益性服务价格、自然垄断经营的商品价格时，应当建立听证会制度，征求消费者、经营者和有关方面的意见。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0137", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "订立合同的当事人依照有关法律对合同内容进行协商并达成一致意见时的合同状态称为（ ）。", "options": {"A": "合同订立", "B": "合同成立", "C": "合同生效", "D": "合同有效"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是合同订立 【选项分析】所谓合同成立就是指当事人对合同内容进行协商并达成一致的意见。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0138", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "根据《民法典》，执行政府定价或政府指导价的合同时，对于逾期交付标的物的处置方式是（ ）。", "options": {"A": "遇价格上涨时，按照原价格执行；价格下降时，按照新价格执行", "B": "遇价格上涨时，按照新价格执行；价格下降时，按照原价格执行", "C": "无论价格上涨或下降，均按照新价格执行", "D": "无论价格上涨或下降，均按照原价格执行"}, "answer": ["A"], "analysis": "【内容考查】本题考查的是合同履行 【选项分项】《民法 典 》规定，执行政府定价或政府指导价的，在合同约定的交付期限内政府价格调整时，按照交付时的价格计价。逾期交付标的物的，遇价格上涨时，按照原价格执行；价格下降时，按照新价格执行。逾期提取标的物或者逾期付款的，遇价格上涨时，按照新价格执行；价格下降时，按照原价格执行。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0140", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "根据《民典法》的规定，以下属于致使合同的权力和义务终止的情形的是（ ）。", "options": {"A": "债权人将债权转让", "B": "债务人依法将标的物提存", "C": "债权人死亡", "D": "债务人死亡"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是合同权利义务终止 【选项分析】有下列情形之一的，合同的权利义务终止：①债务已经按照约定履行；②合同解除；③债务相互抵销；④债务人依法将标的物提存；⑤债权人免除债务；⑥债权债务同归于一人；⑦法律规定或者当事人约定终止的其他情形。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0141", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "《建设工程安全生产管理条例》规定，建设单位在编制（ ）时，应当确定建设工程安全作业环境及安全施工措施所需费用。", "options": {"A": "投资概算", "B": "工程概算", "C": "工程预算", "D": "工程结算"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是《建设工程安全生产管理条例》相关内容 【选项分析】《建设工程安全生产管理条例》规定，建设单位在编制工程概算时，应当确定建设工程安全作业环境及安全施工措施所需费用。应选择B。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0142", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "下面属于政府采购的主要采购方式的是（ ）。", "options": {"A": "公开招标", "B": "邀请招标", "C": "竞争性谈判", "D": "单一来源采购"}, "answer": ["A"], "analysis": "【内容考查】本题考查的是政府采购法相关内容。 【选项分析】政府采购可采用的方式有：公开招标、邀请招标、竞争性谈判、单一来源采购、询价，以及国务院政府采购监督管理部门认定的其他采购方式。公开招标应作为政府采购的主要采购方式。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0143", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "按照建设工程公开招标程序，下列工作中最先进行的是（ ）。【陕西】", "options": {"A": "资格审查", "B": "编制招标文件", "C": "发布招标公告", "D": "履行审批手续"}, "answer": ["D"], "analysis": "【考点来源】本题考查的是招标 【选项分析】建设工程招标的基本程序包括履行项目审批手续、委托招标代理机构、编制招标文件、发布招标公告或投标邀请书、资格审查、开标、评标、中标和签订合同，以及终止招标等。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0147", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "根据《建设工程质量管理条例》，建设工程的保修期自（ ）之日起计算。", "options": {"A": "工程交付使用", "B": "竣工审计通过", "C": "工程价款结清", "D": "竣工验收合格"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是《建设工程质量管理条例》相关内容 【选项分析】建设工程的保修期，自竣工验收合格之日起计算。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0148", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，建筑工程由多个承包单位联合共同承包的，关于承包合同履行责任的说法，正确的是（ ）。", "options": {"A": "由牵头承包方承担主要责任", "B": "由资质等级高的承包方承担主要责任", "C": "由承包各方承担连带责任", "D": "按承包各各方投入比例承担相应责任"}, "answer": ["C"], "analysis": "【内容考查】本题考查的是《建筑法》相关内容 【选项分析】大型建筑工程或结构复杂的建筑工程，可以由两个以上的承包单位联合共同承包。共同承包的各方对承包合同的履行承担连带责任。两个以上不同资质等级的单位实行联合共同承包的，应当按照资质等级低的单位的业务许可范围承揽工程。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0150", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "根据《政府采购法实施条例》，履约保证金的数额不得超过政府采购合同金额的（ ）。", "options": {"A": "5%", "B": "15%", "C": "2%", "D": "10%"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是政府采购法实施条例。 【选项分析】履约保证金的数额不得超过政府采购合同金额的10%。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0152", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "根据《价格法》的规定，价格的制定应当符合价格规律，大多数商品和服务价格实行（ ）。", "options": {"A": "行业指导价", "B": "市场调节价", "C": "政府指导价", "D": "政府定价"}, "answer": ["B"], "analysis": "国家实行并逐步完善宏观经济调控下主要由市场形成价格的机制。价格的制定应当符合价值规律，大多数商品和服务价格实行市场调节价，极少数商品和服务价格实行政府指导价或者政府定价。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0154", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "根据《建筑法》，获取施工许可证后因故不能按期开工的，建设单位应当申请延期，延期的每次延期的最长期限是（ ）。", "options": {"A": "每次不超过1个月", "B": "每次不超过2个月", "C": "每次不超过3个月", "D": "每次不超过6个月"}, "answer": ["C"], "analysis": "【内容考查】本题考查的是《建筑法》相关内容。 【选项分析】建设单位应当自领取施工许可证之日起3个月内开工。因故不能按期开工的，应当向发证机关申请延期；延期以两次为限，每次不超过3个月。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0155", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "根据《建设工程安全生产管理条例》，施工单位应当组织专家进行论证、审查达到一定规模的危险性较大的分部分项工程专项施工方案的是（ ）。", "options": {"A": "脚手架工程", "B": "模板工程", "C": "降水工程", "D": "地下暗挖工程"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是《建设工程安全生产管理条例》相关内容。 【选项分析】施工单位应当在施工组织设计中编制安全技术措施和施工现场临时用电方案，对下列达到一定规模的危险性较大的分部分项工程编制专项施工方案，并附具安全验算结果，经施工单位技术负责人、总监理工程师签字后实施，由专职安全生产管理人员进行现场监督：①基坑支护与降水工程；②土方开挖工程；③模板工程；④起重吊装工程；⑤脚手架工程；⑥拆除、爆破工程；⑦国务院建设行政主管部门或者其他有关部门规定的其他危险性较大的工程。上述所列工程中涉及深基坑、地下暗挖工程、高大模板工程的专项施工方案，施工单位还应当组织专家进行论证、审查。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0163", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "根据《建设工程质量管理条例》，在正常使用条件下，供热与供冷系统的最低保修期限是（ ）个采暖期、供冷期。", "options": {"A": "1", "B": "2", "C": "3", "D": "4"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是 《建设工程质量管理条例》相关内容 【选项分析】在正常使用条件下，建设工程最低保修期限为： （1）基础设施工程、房屋建筑的地基基础工程和主体结构工程，为设计文件规定的该工程合理使用年限； （2）屋面防水工程、有防水要求的卫生间、房间和外墙面的防渗漏，为5年； （3）供热与供冷系统，为2个采暖期、供冷期； （4）电气管道、给排水管道、设备安装和装修工程，为2年。 其他工程的保修期限由发包方与承包方约定。 【名师点拨】与防水有关的都是5年，供冷、供热为2个采暖期；其他都为2年。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0164", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "根据《建设工程质量管理条例》，在正常使用条件，有防水要求的卫生间的最低保修期限（ ）年。", "options": {"A": "1", "B": "2", "C": "3", "D": "5"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是《建设工程质量管理条例》相关内容 【选项分析】在正常使用条件下，屋面防水工程、有防水要求的卫生间、房间和外墙面的防渗漏，为5年。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0165", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "根据《招标投标法实施条例》，投标保证金不得超过（ ）。", "options": {"A": "招标项目估算价的2%", "B": "招标项目估算价的3%", "C": "投标报价的2%", "D": "投标报价的3%"}, "answer": ["A"], "analysis": "【内容考查】本题考查的是《招标投标法实施条例》相关内容。 【选项分析】如招标人在招标文件中要求投标人提交投标保证金，投标保证金不得超过招标项目估算价的2%。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0168", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "根据《民法典》，债权人领取提存物的权利期限为（ ）年。", "options": {"A": "1", "B": "2", "C": "3", "D": "5"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是 合同权利义务终止 。 【选项分析】债权人领取提存物的权利期限为五年，超过该期限，提存物扣除提存费用后归国家所有。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0169", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "某市政道路工程施工许可证颁发日期为2019年10月26日，根据《中华人民共和国建筑法》该工程应在（ ）前开工。陕西-2019", "options": {"A": "2019年11月26日", "B": "2020年1月26日", "C": "2020年4月26日", "D": "2020年10月26日"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是建筑法 【选项分析】建设单位应当自领取施工许可证之日起3个月内开工。此题颁发施工许可证的日期为2019年10月26日，所以应该在2020年1月26日前开工。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0170", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "根据《民法典》，在执行政府定价的合同履行中，需要按新价格执行的情形是（ ）。", "options": {"A": "逾期付款的，遇价格上涨时", "B": "逾期付款的，遇价格下降时", "C": "逾期提取标的物的，遇价格下降时", "D": "逾期交付标的物的，遇价格上涨时"}, "answer": ["A"], "analysis": "【内容考查】本题考查的是 合同履行 。 【选项分析】 逾期提取标的物或者逾期付款的，遇价格上涨时，按照新价格执行；价格下降时，按照原价格执行。 【名师点拨】谁违约谁承担责任。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0174", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "根据《招标投标法》，招标人对已发出的招标文件进行必要的澄清或者修改的，应当在招标文件要求提交投标文件截止时间至少（ ）日前书面通知。", "options": {"A": "7", "B": "14", "C": "21", "D": "15"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是《招标投标法》相关内容 【选项分析】招标人对已发出的招标文件进行必要的澄清或者修改的，应当在招标文件要求提交投标文件截止时间至少15日前，以书面形式通知所有招标文件收受人。该澄清或者修改的内容为招标文件的组成部分。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0176", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "根据《民法典》，当事人既约定违约金，又约定定金的，一方违约时，对方的正确处理方式是（ ）。", "options": {"A": "只能选择适用违约金条款", "B": "只能选择适用定金条款", "C": "同时适用违约金和定金条款", "D": "可以选择适用违约金或者定金条款"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是违约责任 【选项分析】当事人既约定违约金，又约定定金的，一方违约时，对方可以选择适用违约金或者定金条款。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0177", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "根据《价格法》，在制定关系群众切身利益的公用事业价格、公益性服务价格、自然垄断经营的商品价格时，应当建立（ ）制定。", "options": {"A": "风险评估", "B": "公示", "C": "专家咨询", "D": "听证会"}, "answer": ["D"], "analysis": "制定关系群众切身利益的公用事业价格、公益性服务价格、自然垄断经营的商品价格时，应当建立听证会制度，征求消费者、经营者和有关方而的意见。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0180", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "根据《注册造价工程师管理办法》，不属于一级造价工程师业务范围的是（ ） 。", "options": {"A": "建设项目投资估算与审核", "B": "施工预算编制与审核", "C": "建设工程保险中的造价裁定", "D": "工程造价纠纷的调解"}, "answer": ["C"], "analysis": "【内容考查】本题考查的是执业 【选项分析】一级造价工程师执业范围。包括建设项目全过程的工程造价管理与咨询等，具体工作内容有： ①项目建议书、可行性研究投资估算与审核，项目评价造价分析； ②建设工程设计概算、施工预算编制和审核； ③建设工程招标投标文件工程量和造价的编制与审核; ④建设工程合同价款、结算价款、竣工决算价款的编制与管理； ⑤建设工程审计、仲裁、诉讼、保险中的造价鉴定，工程造价纠纷调解； ⑥建设工程计价依据、造价指标的编制与管理； ⑦与工程造价管理有关的其他事项。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0211", "date": "2026-07-09", "chapter": "g01", "type": "single", "stem": "为了有效地控制建设工程造价，造价工程师可采取的组织措施是（ ）。", "options": {"A": "重视工程设计多方案的选择", "B": "明确造价控制者及其任务", "C": "严格审查施工组织设计", "D": "严格审核各项费用支出"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是工程建设各阶段工程造价的控制 【选项分析】技术与经济相结合是控制工程造价最有效的手段。要有效地控制工程造价，应从组织、技术、经济等多方面采取措施。从组织上采取的措施，包括明确项目组织结构，明确造价控制者及其任务，明确管理职能分工；从技术上采取措施，包括重视设计多方案选择，严格审查监督初步设计、技术设计、施工图设计、施工组织设计，深入技术领域研究节约投资的可能；从经济上采取措施，包括动态地比较造价的计划值和实际值，严格审核各项费用支出，采取对节约投资的有力奖励措施等。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "gl-g01-003", "date": "2026-07-08", "chapter": "g01", "type": "multiple", "stem": "根据《建筑法》，申请领取施工许可证应当具备的条件包括（ ）。", "options": {"A": "已经办理该建筑工程用地批准手续", "B": "已经确定建筑施工企业", "C": "有满足施工需要的资金安排、施工图纸及技术资料", "D": "有保证工程质量和安全的具体措施"}, "answer": ["A", "B", "C", "D"], "analysis": "根据《建筑法》第八条，申领施工许可证应具备以下条件：(1)已经办理该建筑工程用地批准手续；(2)依法应当办理建设工程规划许可证的，已经取得建设工程规划许可证；(3)需要拆迁的，其拆迁进度符合施工要求；(4)已经确定建筑施工企业；(5)有满足施工需要的资金安排、施工图纸及技术资料；(6)有保证工程质量和安全的具体措施。以上四项均为法定条件。", "tags": ["建筑法", "施工许可"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g01-007", "date": "2026-07-08", "chapter": "g01", "type": "multiple", "stem": "根据国务院规定，下列工程中属于强制实行监理范围的有（ ）。", "options": {"A": "国家重点建设工程", "B": "大中型公用事业工程", "C": "成片开发建设的住宅小区工程", "D": "利用外国政府或者国际组织贷款援助资金的工程"}, "answer": ["A", "B", "C", "D"], "analysis": "根据《建设工程监理范围和规模标准规定》，下列建设工程必须实行监理：(1)国家重点建设工程；(2)大中型公用事业工程；(3)成片开发建设的住宅小区工程；(4)利用外国政府或者国际组织贷款、援助资金的工程；(5)国家规定必须实行监理的其他工程。以上四项全部属于强制监理范围。", "tags": ["建筑法", "强制监理"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g01-008", "date": "2026-07-08", "chapter": "g01", "type": "multiple", "stem": "根据《建筑法》及《建设工程质量管理条例》，建筑工程质量保修范围及最低保修期限，下列说法正确的有（ ）。", "options": {"A": "基础设施工程、房屋建筑的地基基础工程和主体结构工程，为设计文件规定的该工程的合理使用年限", "B": "屋面防水工程、有防水要求的卫生间、房间和外墙面的防渗漏为5年", "C": "供热与供冷系统为2个采暖期、供冷期", "D": "电气管线、给排水管道、设备安装和装修工程为2年"}, "answer": ["A", "B", "C", "D"], "analysis": "根据《建设工程质量管理条例》第四十条，在正常使用条件下，建设工程最低保修期限为：(1)基础设施工程、房屋建筑的地基基础工程和主体结构工程，为设计文件规定的该工程的合理使用年限；(2)屋面防水工程、有防水要求的卫生间、房间和外墙面的防渗漏为5年；(3)供热与供冷系统为2个采暖期、供冷期；(4)电气管线、给排水管道、设备安装和装修工程为2年。其他项目的保修期限由发包方与承包方约定。", "tags": ["建筑法", "质量保修"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g01-011", "date": "2026-07-08", "chapter": "g01", "type": "multiple", "stem": "根据《招标投标法》，下列项目中属于必须进行招标的有（ ）。", "options": {"A": "大型基础设施、公用事业等关系社会公共利益、公众安全的项目", "B": "全部或者部分使用国有资金投资或者国家融资的项目", "C": "使用国际组织或者外国政府贷款、援助资金的项目", "D": "民营资本投资的商业地产项目"}, "answer": ["A", "B", "C"], "analysis": "《招标投标法》第三条规定，必须招标的项目包括三类：(1)大型基础设施、公用事业等关系社会公共利益、公众安全的项目；(2)全部或者部分使用国有资金投资或者国家融资的项目；(3)使用国际组织或者外国政府贷款、援助资金的项目。纯民营资本投资的商业地产项目不属于必须招标的范围。", "tags": ["招标投标法", "必须招标范围"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g01-016", "date": "2026-07-08", "chapter": "g01", "type": "multiple", "stem": "根据《招标投标法》及其实施条例，下列情形中可以采用邀请招标的有（ ）。", "options": {"A": "技术复杂、有特殊要求或者受自然环境限制，只有少量潜在投标人可供选择的", "B": "采用公开招标方式的费用占项目合同金额的比例过大的", "C": "涉及国家安全、国家秘密或者抢险救灾，适宜招标但不宜公开招标的", "D": "民营企业自主决定采用邀请招标的"}, "answer": ["A", "B", "C"], "analysis": "根据《招标投标法实施条例》第八条，国有资金占控股或者主导地位的依法必须招标的项目，有下列情形之一的可以邀请招标：(1)技术复杂、有特殊要求或者受自然环境限制，只有少量潜在投标人可供选择的；(2)采用公开招标方式的费用占项目合同金额的比例过大的。涉及国家安全、国家秘密的也可以邀请招标。D选项所述情况不在必须招标项目的法定情形内。", "tags": ["招标投标法", "邀请招标"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g01-018", "date": "2026-07-08", "chapter": "g01", "type": "multiple", "stem": "根据《政府采购法》，政府采购可以采用的采购方式包括（ ）。", "options": {"A": "公开招标", "B": "邀请招标", "C": "竞争性谈判", "D": "单一来源采购"}, "answer": ["A", "B", "C", "D"], "analysis": "根据《政府采购法》第二十六条，政府采购采用以下五种方式：公开招标、邀请招标、竞争性谈判、单一来源采购、询价。本题选项中列出了其中四种，加上询价即构成完整的五种法定采购方式。", "tags": ["政府采购法", "采购方式"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g01-019", "date": "2026-07-08", "chapter": "g01", "type": "multiple", "stem": "根据《政府采购法》，符合下列情形之一的货物或者服务，可以采用单一来源方式采购的有（ ）。", "options": {"A": "只能从唯一供应商处采购的", "B": "发生了不可预见的紧急情况不能从其他供应商处采购的", "C": "必须保证原有采购项目一致性或者服务配套的要求，需要继续从原供应商处添购且添购资金总额不超过原合同采购金额百分之十的", "D": "技术复杂不能确定详细规格的"}, "answer": ["A", "B", "C"], "analysis": "《政府采购法》第三十一条规定，符合下列情形之一的货物或者服务，可以采用单一来源方式采购：(1)只能从唯一供应商处采购的；(2)发生了不可预见的紧急情况不能从其他供应商处采购的；(3)必须保证原有采购项目一致性或者服务配套的要求，需要继续从原供应商处添购，且添购资金总额不超过原合同采购金额百分之十的。D选项“技术复杂不能确定详细规格”属于竞争性谈判的适用情形。", "tags": ["政府采购法", "单一来源采购"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g01-020", "date": "2026-07-08", "chapter": "g01", "type": "multiple", "stem": "根据《政府采购法》，符合下列情形之一的货物或者服务，可以采用竞争性谈判方式采购的有（ ）。", "options": {"A": "招标后没有供应商投标或者没有合格标的或者重新招标未能成立的", "B": "技术复杂或者性质特殊，不能确定详细规格或者具体要求的", "C": "采用招标所需时间不能满足用户紧急需要的", "D": "不能事先计算出价格总额的"}, "answer": ["A", "B", "C", "D"], "analysis": "《政府采购法》第三十条规定，符合下列情形之一的货物或者服务，可以依照本法采用竞争性谈判方式采购：(1)招标后没有供应商投标或者没有合格标的，或者重新招标未能成立的；(2)技术复杂或者性质特殊，不能确定详细规格或者具体要求的；(3)采用招标所需时间不能满足用户紧急需要的；(4)不能事先计算出价格总额的。四个选项均为竞争性谈判的法定适用情形。", "tags": ["政府采购法", "竞争性谈判"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g01-025", "date": "2026-07-08", "chapter": "g01", "type": "multiple", "stem": "根据《民法典》，当事人一方不履行合同义务或者履行合同义务不符合约定的，应当承担违约责任，违约责任的承担方式包括（ ）。", "options": {"A": "继续履行", "B": "采取补救措施", "C": "赔偿损失", "D": "支付违约金"}, "answer": ["A", "B", "C", "D"], "analysis": "根据《民法典》第五百七十七条，当事人一方不履行合同义务或者履行合同义务不符合约定的，应当承担继续履行、采取补救措施或者赔偿损失等违约责任。此外，当事人还可以约定违约金。因此，违约责任的四种主要承担方式为：继续履行、采取补救措施、赔偿损失和支付违约金。", "tags": ["民法典合同编", "违约责任"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g01-026", "date": "2026-07-08", "chapter": "g01", "type": "multiple", "stem": "根据《民法典》合同编，施工合同的内容一般包括（ ）。", "options": {"A": "工程范围、建设工期", "B": "中间交工工程的开工和竣工时间", "C": "工程质量、工程造价", "D": "技术资料交付时间、材料和设备供应责任"}, "answer": ["A", "B", "C", "D"], "analysis": "根据《民法典》第七百九十五条，施工合同的内容包括：工程范围、建设工期、中间交工工程的开工和竣工时间、工程质量、工程造价、技术资料交付时间、材料和设备供应责任、拨款和结算、竣工验收、质量保修范围和质量保证期、相互协作等条款。以上选项均为施工合同的法定必备内容。", "tags": ["民法典合同编", "施工合同"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g01-033", "date": "2026-07-08", "chapter": "g01", "type": "multiple", "stem": "关于一级造价工程师和二级造价工程师的比较，下列说法正确的有（ ）。", "options": {"A": "一级造价工程师考试科目多于二级", "B": "一级造价工程师可在全国范围内执业", "C": "二级造价工程师执业范围限于所在省、自治区、直辖市", "D": "二级造价工程师可以独立编制和审核单项工程造价不超过5000万元的项目"}, "answer": ["A", "B", "C", "D"], "analysis": "一级造价工程师考4科，二级考2科。一级造价工程师证书在全国范围内有效，二级造价工程师证书原则上在所在行政区域内有效。二级造价工程师可独立开展造价编制和审核工作，但单项工程造价不超过5000万元。四个选项均正确。", "tags": ["造价管理制度", "一造二造区别"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g01-035", "date": "2026-07-08", "chapter": "g01", "type": "multiple", "stem": "《建筑法》中禁止的行为包括（ ）。", "options": {"A": "承包单位将其承包的全部建筑工程转包给他人", "B": "承包单位将其承包的全部建筑工程肢解后以分包名义分别转包", "C": "总承包单位将承包工程中的部分工程发包给具有相应资质条件的分包单位", "D": "将工程分包给不具备相应资质条件的单位"}, "answer": ["A", "B", "D"], "analysis": "《建筑法》明确禁止转包和肢解发包（AB），禁止将工程分包给不具备资质条件的单位（D）。C选项所述的总承包单位将部分工程发包给具有相应资质条件的分包单位，属于合法的分包行为，法律允许。区分合法分包与违法转包的关键在于是否具备资质以及是否将主体结构分包。", "tags": ["建筑法", "禁止行为"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g01-040", "date": "2026-07-08", "chapter": "g01", "type": "multiple", "stem": "关于工程造价咨询企业资质管理改革，以下说法正确的有（ ）。", "options": {"A": "取消工程造价咨询企业资质审批", "B": "实行告知承诺制备案管理", "C": "强化事中事后监管", "D": "企业只要有营业执照即可承揽造价咨询业务"}, "answer": ["A", "B", "C"], "analysis": "根据改革要求，取消工程造价咨询企业资质审批（A正确），改为备案管理并实行告知承诺制（B正确），同时加强事中事后监管（C正确）。D错误，虽然不一定需要资质审批，但仍需满足专业技术人员配备等基本条件，不是有营业执照就能承揽业务。", "tags": ["造价管理制度", "资质改革"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-015", "date": "2026-07-08", "chapter": "g01", "type": "multiple", "stem": "根据《建筑法》，下列哪些工程必须实行监理？（多选）", "options": {"A": "国家重点建设工程", "B": "大中型公用事业工程", "C": "所有住宅小区开发项目", "D": "利用外国政府或者国际组织贷款、援助资金的工程", "E": "成片开发建设的住宅小区工程"}, "answer": ["A", "B", "D", "E"], "analysis": "必须实行监理的工程范围：①国家重点建设工程；②大中型公用事业工程；③成片开发建设的住宅小区工程；④利用外国政府或者国际组织贷款、援助资金的工程；⑤国家规定必须实行监理的其他工程。C错误，不是所有住宅小区，是【成片开发建设的】。", "tags": ["建筑法", "强制监理"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-019", "date": "2026-07-08", "chapter": "g01", "type": "multiple", "stem": "根据《建筑法》及相关规定，建筑工程质量保修期限正确的有？（多选）", "options": {"A": "基础设施工程、地基基础工程和主体结构工程，为设计文件规定的该工程的合理使用年限", "B": "屋面防水工程、有防水要求的卫生间、房间和外墙面的防渗漏，为3年", "C": "供热与供冷系统，为2个采暖期、供冷期", "D": "电气管线、给排水管道、设备安装和装修工程，为2年", "E": "屋面防水工程保修期为5年"}, "answer": ["A", "C", "D", "E"], "analysis": "质量保修期限：基础设施/地基基础/主体结构为设计文件规定的合理使用年限；屋面防水/卫生间等防渗漏为5年（B错误，非3年）；供热供冷系统为2个采暖供冷期；电气管线/给排水管道/设备安装/装修为2年。", "tags": ["建筑法", "质量保修"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-027", "date": "2026-07-08", "chapter": "g01", "type": "multiple", "stem": "根据《招标投标法》，下列属于必须进行招标的工程建设项目有？（多选）", "options": {"A": "大型基础设施、公用事业等关系社会公共利益、公众安全的项目", "B": "全部或者部分使用国有资金投资或者国家融资的项目", "C": "使用国际组织或者外国政府贷款、援助资金的项目", "D": "民营企业自建厂房", "E": "个人住宅建设项目"}, "answer": ["A", "B", "C"], "analysis": "必须招标的3类项目：①大型基础设施、公用事业等关系社会公共利益和公众安全的项目；②全部或者部分使用国有资金投资或者国家融资的项目；③使用国际组织或者外国政府贷款、援助资金的项目。民营企业自建和个人住宅不在此范围内。", "tags": ["招标投标法", "必须招标范围"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-031", "date": "2026-07-08", "chapter": "g01", "type": "multiple", "stem": "根据《招标投标法》及相关规定，下列哪些情形可以不进行招标？（多选）", "options": {"A": "涉及国家安全、国家秘密、抢险救灾的", "B": "需要采用不可替代的专利或者专有技术的", "C": "采购人依法能够自行建设、生产或者提供的", "D": "需向原中标人采购工程、货物或者服务否则将影响施工或者功能配套要求的", "E": "民营企业投资建设的大型商业综合体"}, "answer": ["A", "B", "C", "D"], "analysis": "不招标可谈判的情形：①涉及国家安全秘密或抢险救灾；②不可替代的专利专有技术；③采购人依法能自行建设生产提供；④需向原中标人采购否则影响施工功能配套；⑤其他。E中民营企业投资不属于强制招标范围但提示中没有明确列在不可谈判类型，故不选。", "tags": ["招标投标法", "不招标情形"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-035", "date": "2026-07-08", "chapter": "g01", "type": "multiple", "stem": "根据《招标投标法》，下列哪些情形可以采用邀请招标？（多选）", "options": {"A": "技术复杂、有特殊要求或者受自然环境限制，只有少量潜在投标人可供选择", "B": "采用公开招标方式的费用占项目合同金额的比例过大", "C": "涉及国家安全、国家秘密，适宜招标但不宜公开招标的", "D": "项目投资额特别大的", "E": "民营企业自建项目"}, "answer": ["A", "B", "C"], "analysis": "邀请招标的适用情形：①技术复杂/受自然环境限制只有少量潜在投标人；②公开招标费用占比过大；③涉及国家安全秘密不宜公开招标。D和E不属于邀请招标的法定情形。", "tags": ["招标投标法", "邀请招标"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-040", "date": "2026-07-08", "chapter": "g01", "type": "multiple", "stem": "根据《招标投标法》，中标人的投标应当符合下列哪些条件？（多选）", "options": {"A": "能够最大限度地满足招标文件中规定的各项综合评价标准", "B": "能够满足招标文件的实质性要求，并且经评审的投标价格最低（但是投标价格低于成本的除外）", "C": "投标报价最高的投标人", "D": "与招标人关系最好的投标人"}, "answer": ["A", "B"], "analysis": "中标条件二选一：①能够最大限度地满足招标文件中规定的各项综合评价标准（综合评标法）；②能够满足招标文件的实质性要求，并且经评审的投标价格最低，但是投标价格低于成本的除外（经评审的最低投标价法）。", "tags": ["招标投标法", "中标条件"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-057", "date": "2026-07-08", "chapter": "g01", "type": "multiple", "stem": "根据《民法典》及相关司法解释，建设工程施工合同具有下列哪些情形的应认定为无效？（多选）", "options": {"A": "承包人未取得建筑业企业资质或者超越资质等级的", "B": "没有资质的实际施工人借用有资质的建筑施工企业名义的", "C": "建设工程必须进行招标而未招标或者中标无效的", "D": "承包人将承包的建设工程转包、违法分包的", "E": "合同价格高于市场平均价的"}, "answer": ["A", "B", "C", "D"], "analysis": "建设工程施工合同无效情形：①无资质或超越资质；②借用资质（挂靠）；③必须招标未招标或中标无效；④转包/违法分包。E合同价格高低不是合同无效的法定情形。", "tags": ["民法典合同编", "无效合同"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-060", "date": "2026-07-08", "chapter": "g01", "type": "multiple", "stem": "根据《民法典》，承担违约责任的方式包括？（多选）", "options": {"A": "继续履行", "B": "采取补救措施", "C": "赔偿损失", "D": "支付违约金", "E": "赔礼道歉"}, "answer": ["A", "B", "C", "D"], "analysis": "违约责任的承担方式有4种：继续履行、采取补救措施、赔偿损失、支付违约金。赔礼道歉属于侵权责任承担方式，不属于违约责任方式。", "tags": ["民法典合同编", "违约责任"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-062", "date": "2026-07-08", "chapter": "g01", "type": "multiple", "stem": "根据《民法典》，建设工程施工合同的主要内容包括？（多选）", "options": {"A": "工程范围、建设工期", "B": "工程质量、工程造价", "C": "技术资料交付时间、材料和设备供应责任", "D": "拨款和结算、竣工验收、质量保修范围", "E": "违约责任和争议解决方法"}, "answer": ["A", "B", "C", "D", "E"], "analysis": "建设工程施工合同的主要内容包括：工程范围、建设工期、工程质量、工程造价、技术资料交付时间、材料和设备供应责任、拨款和结算、竣工验收、质量保修范围和质量保证期、违约责任、争议解决方法等。", "tags": ["民法典合同编", "施工合同内容"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-067", "date": "2026-07-08", "chapter": "g01", "type": "multiple", "stem": "根据《价格法》，经营者定价应当遵循的原则包括？（多选）", "options": {"A": "公平", "B": "合法", "C": "诚实信用", "D": "追求最高利润", "E": "明码标价"}, "answer": ["A", "B", "C"], "analysis": "经营者定价应当遵循公平、合法和诚实信用的原则。明码标价是经营者在销售商品和提供服务时的法定义务，但不是定价原则。追求最高利润也不是定价原则。", "tags": ["价格法", "经营者定价"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-077", "date": "2026-07-08", "chapter": "g01", "type": "multiple", "stem": "二级造价工程师考试科目包括哪些？（多选）", "options": {"A": "建设工程造价管理基础知识", "B": "建设工程计量与计价实务", "C": "建设工程技术与计量", "D": "建设工程造价案例分析", "E": "建设工程法规及相关知识"}, "answer": ["A", "B"], "analysis": "二级造价工程师考试设2个科目：建设工程造价管理基础知识（基础科目）和建设工程计量与计价实务（专业科目）。C、D、E为一级造价工程师的考试科目。", "tags": ["造价管理制度", "考试科目"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-078", "date": "2026-07-08", "chapter": "g01", "type": "multiple", "stem": "二级造价工程师的专业类别包括？（多选）", "options": {"A": "土木建筑工程", "B": "安装工程", "C": "交通运输工程", "D": "水利工程", "E": "市政工程"}, "answer": ["A", "B", "C", "D"], "analysis": "二级造价工程师专业类别有4个：土木建筑工程、安装工程、交通运输工程、水利工程。市政工程不属于独立的专业类别，包含在土木建筑工程内。", "tags": ["造价管理制度", "考试科目"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-091", "date": "2026-07-08", "chapter": "g01", "type": "multiple", "stem": "根据《民法典》，当事人一方不履行合同义务或者履行合同义务不符合约定的，应当承担继续履行、采取补救措施或者赔偿损失等违约责任。下列哪些属于违约责任的承担方式？（多选）", "options": {"A": "继续履行", "B": "赔偿损失", "C": "支付违约金", "D": "适用定金罚则", "E": "恢复原状"}, "answer": ["A", "B", "C", "D"], "analysis": "违约责任4种方式：继续履行、采取补救措施、赔偿损失、支付违约金。定金罚则也可作为违约责任承担方式。但定金与违约金只能择一适用。恢复原状一般属于侵权责任承担方式。", "tags": ["民法典合同编", "违约责任"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-098", "date": "2026-07-08", "chapter": "g01", "type": "multiple", "stem": "根据《招标投标法》及其实施条例，关于招标投标的表述正确的有？（多选）", "options": {"A": "资格预审公告的发布期限不少于5日", "B": "招标文件的发售期不得少于5日", "C": "自招标文件发出至投标截止最短不得少于20日", "D": "招标人和中标人应自中标通知书发出之日起30日内签订合同", "E": "投标保证金最迟应在合同签订后5日内退还"}, "answer": ["A", "B", "C", "D", "E"], "analysis": "以上时间节点均为正确：资格预审/招标文件发售≥5日，投标时间≥20日，签订合同≤30日，退还保证金≤5日。", "tags": ["招标投标法", "时间节点汇总"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-099", "date": "2026-07-08", "chapter": "g01", "type": "multiple", "stem": "根据《建筑法》及《民法典》，关于总承包单位和分包单位责任的表述正确的有？（多选）", "options": {"A": "总承包单位按照总承包合同的约定对建设单位负责", "B": "分包单位按照分包合同的约定对总承包单位负责", "C": "总承包单位和分包单位就分包工程对建设单位承担连带责任", "D": "分包单位可以将其承包的工程再分包给有资质的单位", "E": "禁止分包单位将其承包的工程再分包"}, "answer": ["A", "B", "C", "E"], "analysis": "总包→发包人负责，分包→总包负责，总包+分包→发包人连带责任。禁止再分包。D错误，分包单位不得再分包。", "tags": ["建筑法", "分包"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g01-100", "date": "2026-07-08", "chapter": "g01", "type": "multiple", "stem": "根据《建筑法》及《建设工程质量管理条例》，关于建设工程质量保修期限的表述正确的有？（多选）", "options": {"A": "基础设施工程的保修期为设计文件规定的该工程的合理使用年限", "B": "屋面防水工程的保修期为5年", "C": "供热与供冷系统的保修期为2个采暖期、供冷期", "D": "装修工程的保修期为1年", "E": "电气管线的保修期为2年"}, "answer": ["A", "B", "C", "E"], "analysis": "装修工程的保修期应为2年（D错误），其他各项正确：基础设施/主体=设计年限，屋面防水=5年，供热供冷=2个采暖供冷期，电气/给排水=2年。", "tags": ["建筑法", "质量保修"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "ht_mgmt_0492", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "我国《合同法》规定，对格式条款的理解发生争议时（）。", "options": {"A": "有两种以上解释时，应作出有利于提供格式条款一方的解释", "B": "有两种以上解释时，应作出不利于提供格式条款一方的解释", "C": "格式条款与非格式条款不一致时，应采用格式条款", "D": "格式条款与非格式条款不一致时，应采用非格式条款", "E": "提供格式条款一方免除自身责任，加重对方责任、排除对方主要权利的条款无效"}, "answer": ["B", "D", "E"], "analysis": "按照《合同法》规定，对格式条款的理解发生争议的，应当按照通常理解予以解释。对格式条款有两种以上解释的，应当作出不利于提供格式条款一方的解释。格式条款和非格式条款不一致的，应当采用非格式条款。提供格式条款的一方应当遵循公平的原则确定当事人之间的权利义务关系，并采取合理的方式提请对方注意免除或限制其责任的条款，按照对方的要求，对该条款予以说明。提供格式条款一方免除自己责任、加重对方责任、排除对方主要权利的，该条款无效。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0493", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "根据价格法，在制定关系群众切身利益的（），政府应当建立听证会制度。", "options": {"A": "公用事业价格", "B": "公益性服务价格", "C": "自然垄断经营的商品价格", "D": "价格波动过大的农产品价格", "E": "政府集中采购的商品价格"}, "answer": ["A", "B", "C"], "analysis": "政府应当依据有关商品或者服务的社会平均成本和市场供求状况、国民经济与社会发展要求以及社会承受能力，实行合理的购销差价、批零差价、地区差价和季节差价。制定关系群众切身利益的公用事业价格、公益性服务价格、自然垄断经营的商品价格时，应当建立听证会制度，征求消费者、经营者和有关方面的意见。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0494", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "关于工程监理单位实施监理工作的说法中，正确的有（）。", "options": {"A": "依照法律、法规以及有关技术标准、设计文件和建设工程承包合同对施工质量实施监理", "B": "应对施工质量承担监理责任", "C": "未经专业监理工程师签字，建设单位不拨付工程款", "D": "监理工程师可以采取旁站、巡视、平行检验的方式对工程建设实施监理", "E": "选派具备相应资格的总监理工程师和监理工程师进驻施工现场"}, "answer": ["A", "B", "D", "E"], "analysis": "工程监理单位应当依照法律、法规以及有关技术标准、设计文件和建设工程承包合同，代表建设单位对施工质量实施监理,并对施工质量承担监理责任。工程监理单位应当选派具备相应资格的总监理工程师和监理工程师进驻施工现场。监理工程师应当按照工程监理规范的要求,采取旁站、巡视和平行检验等形式，对建设工程实施监理。未经监理工程师签字，建筑材料、建筑构配件和设备不得在工程上使用或者安装，施工单位不得进行下一道工序的施工。未经总监理工程师签字,建设单位不拨付工程款，不进行竣工验收。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0495", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "关于依法必须招标项目中标合同的签订和效力，下列说法中正确的有（）。", "options": {"A": "中标合同应当按照投标人的投标文件和中标通知书的内容订立", "B": "中标合同订立后，招标人和中标人不得再行订立背离合同实质性内容的补充协议", "C": "中标合同备案后方可产生合同效力", "D": "中标合同应当自中标通知书发出之曰起30 日内订立", "E": "订立中标合同必须采用书面形式"}, "answer": ["B", "D", "E"], "analysis": "本题考核的是必须招标项目中标合同的签订和效力。按照《招标投标法》的规定，招标人和中标人应当自中标通知书发出之日起30 日内，按照招标文件和中标人的投标文件订立书面合同。应当按照招标文件和中标人的投标文件确定合同内容。书面合同订立后，招标人和中标人不得再行订立背离合同实质性内容的其他协议。合同备案，是指当事人签订合同后，还要将合同提交相关的主管部门登记。有些通过招标投标订立的合同应当进行备案，这些备案要求不是合同生效的条件。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0496", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "下列关于招标文件与资格预审的说法正确的有（）。", "options": {"A": "招标人应当按照资格预审公告、招标公告或者投标邀请书规定的时间、地点发售资格预审文件或者招标文件", "B": "资格预审文件或者招标文件的发售期不得少于3d", "C": "招标人应当自收到异议之日起5d 内作出答复", "D": "如对招标文件有异议应当在投标截止时间10d 前提出", "E": "通过资格预审的申请人少于3 个的，应当重新招标"}, "answer": ["A", "D", "E"], "analysis": "招标人应当按照资格预审公告、招标公告或者投标邀请书规定的时间、地点发售资格预审文件或者招标文件。资格预审文件或者招标文件的发售期不得少于5 日。如潜在投标人或者其他利害关系人对资格预审文件有异议,应当在提交资格预审申请文件截止时间2 日前提出；如对招标文件有异议,应当在投标截止时间10 日前提出。招标人应当自收到异议之日起3 日内作出答复;作出答复前,应当暂停招标投标活动。通过资格预审的申请人少于3 个的，应当重新招标。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0497", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "下列招标人的行为属于以不合理条件限制、排斥潜在投标人或者投标人的是（）。", "options": {"A": "同一招标项目向潜在投标人或者投标人提供有差别的项目信息", "B": "依法必须进行招标的项目以特定行政区域或者特定行业的业绩、奖项作为加分条件", "C": "对潜在投标人或者投标人采取相同的资格审查", "D": "指定特定的专利、商标、品牌、原产地或者供应商", "E": "设定的资格、技术、商务条件与招标项目的具体特点和实际无关"}, "answer": ["A", "B", "D", "E"], "analysis": "招标人有下列行为之一的，属于以不合理条件限制、排斥潜在投标人或者投标人:①就同一招标项目向潜在投标人或者投标人提供有差别的项目信息;②设定的资格、技术、商务条件与招标项目的具体特点和实际需要不相适应或者与合同履行无关;③依法必须进行招标的项目以特定行政区域或者特定行业的业绩、奖项作为加分条件或者中标条件；④对潜在投标人或者投标人采取不同的资格审查或者评标标准;⑤限定或者指定特定的专利、商标、品牌、原产地或者供应商;⑥依法必须进行招标的项目非法限定潜在投标人或者投标人的所有制形式或者组织形式;⑦以其他不合理条件限制、排斥潜在投标人或者投标人。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0498", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "根据《价格法》的规定，政府在必要时可以实行政府指导价或政府定价的商品或服务包括（）。", "options": {"A": "自然垄断经营的商品", "B": "国家级贫困地区的各类农用商品", "C": "重要的公用事业价格", "D": "国家投资开发的高新技术类服务", "E": "重要的公益性服务"}, "answer": ["A", "C", "E"], "analysis": "政府在必要时可以实行政府指导价或政府定价的商品或服务包括:与国民经济发展和人民生活关系重大的极少数商品价格;资源稀缺的少数商品价格；自然垄断经营的商品价格;重要的公用事业价格;重要的公益性服务价格。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0499", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "建筑工程总承包单位可以将承包工程中的部分工程发包给具有相应资质条件的分包单位。但是，（）。", "options": {"A": "必须报建设行政主管部门批准备案", "B": "除总承包合同中约定的分包外，必须经建设单位认可", "C": "必须经由建设单位与分包单位重新签订分包合同", "D": "建设单位应当重新领取施工许可证", "E": "施工总承包的，建筑工程主体结构的施工必须由总承包单位自行完成"}, "answer": ["B", "E"], "analysis": "建筑工程总承包单位可以将承包工程中的部分工程发包给具有相应资质条件的分包单位。但是，除总承包合同中已约定的分包外，必须经建设单位认可。施工总承包的,建筑工程主体结构的施工必须由总承包单位自行完成。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0500", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "根据我国《合同法》的规定，缔约过失责任的构成条件包括（）。", "options": {"A": "当事人有过错", "B": "违约行为客观存在", "C": "抗辩事由不能成立", "D": "有损害后果的发生", "E": "当事人的过错行为与造成的损失有因果关系"}, "answer": ["A", "D", "E"], "analysis": "缔约过失责任的构成条件：当事人有过错;有损害后果的发生；当事人的过错和造成的损失有因果关系。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0501", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "根据《建筑法》的规定，以下有关于分包的叙述正确的是（）。", "options": {"A": "建筑总承包单位分包工程时，除总承包合同中约定外，必须经建设单位认可", "B": "建筑工程主体结构的施工，可以分包给具有相应资质条件的其他施工单位", "C": "分包单位按照分包合同对总承包单位负责", "D": "禁止分包单位将其承包的工程再分包", "E": "禁止承包单位将其承包的建筑工程转包给其他单位"}, "answer": ["A", "C", "D", "E"], "analysis": "建筑工程总承包单位可以将承包工程中的部分工程发包给具有相应资质条件的分包单位。但是，除总承包合同中已约定的分包外，必须经建设单位认可。施工总承包的，建筑工程主体结构的施工必须由总承包单位自行完成。建筑工程总承包单位按照总承包合同的约定对建设单位负责;分包单位按照分包合同的约定对总承包单位负责。总承包单位和分包单位就分包工程对建设单位承担连带责任。禁止承包单位将其承包的全部建筑工程转包给他人,或将其承包的全部建筑工程肢解以后以分包的名义分别转包给他人。禁止总承包单位将工程分包给不具备资质条件的单位。禁止分包单位将其承包的工程再分包。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0502", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "根据《注册造价工程师管理办法》的规定，下列关于法律责任的表述中，正确的是（）。", "options": {"A": "隐瞒有关情况或者提供虚假材料申请造价工程师注册的，申请人在1 年内不得再次申请造价工程师注册", "B": "聘用单位为申请人提供虚假注册材料的，给予警告，并可处以1 万元以上3 万元以下的罚款", "C": "以欺骗、贿赂等不正当手段取得造价工程师注册的，撤销其注册，1 年内不得再次申请注册", "D": "未办理变更注册而继续执业的，给予警告，并可处以1 万元以上3 万元以下的罚款", "E": "注册造价工程师的聘用单位未按照要求提供造价工程师信用档案信息的，逾期未改正的，可处以1000 元以上1 万元以下的罚款"}, "answer": ["A", "B", "E"], "analysis": "根据《注册造价工程师管理办法》的规定和题目要求，分析如下：关于选项A，隐瞒有关情况或者提供虚假材料申请造价工程师注册的，不予受理或者不予注册,并给予警告，申请人在1 年内不得再次申请造价工程师注册。关于选项B，聘用单位为申请人提供虚假注册材料的，由县级以上地方人民政府建设主管部门或者其他有关部门给予警告，并可处以1 万元以上3 万元以下的罚款。关于选项C，以欺骗、贿赂等不正当手段取得造价工程师注册的，由注册机关撤销其注册，3 年内不得再次申请注册。不是1 年。关于选项D，未办理变更注册而继续执业的，由县级以上人民政府建设主管部门或者其他有关部门责令限期改正;逾期不改的，可处以5000 元以下的罚款。不是给予警告，并可处以1 万元以上3 万元以下的罚款。关于选项E,注册造价工程师或者其聘用单位未按照要求提供造价工程师信用档案信息的，由县级以上地方人民政府建设主管部门或者其他有关部门责令限期改正;逾期未改正的，可处以1000 元以上1 万元以下的罚款。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0503", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "根据《注册造价工程师管理办法》的规定，注册造价工程师有（）行为的，由县级以上地方人民政府建设主管部门或者其他有关部门给予警告，责令改正，没有违法所得的，处以1 万元以下罚款，有违法所得的，处以违法所得3 倍以下且不超过3 万元的罚款。", "options": {"A": "签署有虚假记载、误导性陈述的工程造价成果文件", "B": "以个人名义承接工程造价业务", "C": "隐瞒有关情况或者提供虚假材料申请造价工程师注册的", "D": "同时在两个或者两个以上单位执业", "E": "违反本办法规定，未办理变更注册而继续执业的"}, "answer": ["A", "B", "D"], "analysis": "对执业活动违规的处罚。注册造价工程师有下列行为之一的，由县级以上地方人民政府建设主管部门或者有关专业部门给予警告，责令改正。没有违法所得的，处以1 万元以下罚款;有违法所得的，处以违法所得3 倍以下且不超过3 万元的罚款：1)不履行注册造价工程师义务；\"2)在执业过程中索贿、受贿或者谋取合同约定费用外的其他利益；3)在执业过程中实施商业贿赂；4)签署有虚假记载、误导性陈述的工程造价成果文件;5)以个人名义承接工程造价业务；6)允许他人以自己名义从事工程造价业务；7)同时在两个或者两个以上单位执业；8)涂改、倒卖、出租、出借或以其他形式非法转让注册证书或执业印章;9)法律、法规、规章禁止的其他行为", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0504", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "根据《注册造价工程师管理办法》的规定，造价工程师享有的权利包括（）。", "options": {"A": "使用造价工程师的名称", "B": "批准物资采购的价格", "C": "签发工程开工、停工、复工令", "D": "发起设立工程造价咨询企业", "E": "签署工程造价文件、加盖执业专用章"}, "answer": ["A", "D", "E"], "analysis": "注册造价工程师的权利：1)使用注册造价工程师名称；2)依法独立执行工程造价业务；3)在本人执业活动中形成的工程造价成果文件上签字并加盖执业印章；4)发起设立工程造价咨询企业；5)保管和使用本人的注册证书和执业印章；6)参加继续教育。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0505", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "在下列情形中，由县级以上地方人民政府建设主管部门或者有关部门给予警告，责令限期改正；逾期未改正的，可处以5000 元以上2 万元以下的罚款的是（）。", "options": {"A": "未取得工程造价咨询企业资质从事工程造价咨询活动或者超越资质等级承接工程造价咨询业务的", "B": "违反规定，新设立的分支机构不备案的", "C": "以给予回扣、恶意压低收费等方式进行不正当竞争的", "D": "违反规定跨省、自治区、直辖市承接业务不备案的", "E": "以欺骗、贿赂等不正当手段取得工程造价咨询企业资质的"}, "answer": ["B", "D"], "analysis": "有下列行为之一的，由县级以上地方人民政府建设主管部门或者有关部门给予警告，责令限期改正；逾期未改正的，可处以5000 元以上2 万元以下的罚款： 1)违反规定，新设立的分支机构不备案的; 2)违反规定跨省、自治区、直辖市承接业务不备案的。 3)其他违规责任。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0506", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "根据《工程造价咨询企业管理办法》，乙级工程造价咨询企业资质标准包括（）。", "options": {"A": "企业注册资本不少于人民币30 万元", "B": "专职从事工程造价专业工作的人员不少于12 人", "C": "企业人均办公建筑面积不少于10 平方米", "D": "近3 年工程造价咨询营业收入累计不低于人民币50 万元", "E": "技术档案管理制度、质量控制制度、财务管理制度齐全"}, "answer": ["B", "C", "E"], "analysis": "乙级工程造价咨询企业资质标准：(1)企业出资人中注册造价工程师人數不低于出资人总人数的60%，且其出资额不低于注册资本总额的60%; (2)技术负责人是注册造价工程师，并具有工程或工程经济类髙级专业技术职称，且从事工程造价专业工作10年以上； (3)专职专业人员不少于12 人，其中，具有工程或者工程经济类中级以上专业技术职称的人员不少于8 人，注册造价工程师不少于6 人，其他人员均需要具有从事工程造价专业工作的经历; (4)企业与专职专业人员签订劳动合同，且专职专业人员符合国家规定的职业年龄(出资人除外)； (5)专职专业人员人事档案关系由国家认可的人事代理机构代为管理； (6)企业注册资本不少于人民币50 万元； (7)具有固定的办公场所，人均办公建筑面积不少于10m2; (8)技术档案管理制度、质量控制制度、财务管理制度齐全; (9)企业为本单位专职专业人员办理的社会基本养老保险手续齐全; (10)暂定期内工程造价咨询营业收人累计不低于人民币50 万元； (11)在申请核定资质等级之日前无违规行为。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0507", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "根据《工程造价咨询企业管理办法》，下列要求中，属于甲级工程造价咨询企业资质标准的有（）。", "options": {"A": "已取得乙级工程造价咨询企业资质证书满3 年", "B": "技术负责人从事工程造价专业工作10 年以上", "C": "专职从事工程造价专业工作的人员不少于16 人", "D": "近3 年工程造价咨询营业收入累计不低于500 万元", "E": "人均办公建筑面积不少于10 ㎡"}, "answer": ["A", "D", "E"], "analysis": "甲级工程造价咨询企业资质标准 （1）已取得乙级工程造价咨询企业资质证书满3 年； （2）企业出资人中注册造价工程师人数不低于出资人总人数的60%，且其出资额不低于企业注册资本总额的60%； （3）技术负责人是注册造价工程师，并具有工程或工程经济类高级专业技术职称，且从事工程造价专业工作15 年以上； （4）专职从事工程造价专业工作的人员（以下简称专职专业人员）不少于20 人。其中，具有工程或者工程经济类中级以上专业技术职称的人员不少于16 人，注册造价工程师不少于10 人，其他人员均需要具有从事工程造价专业工作的经历； （5）企业与专职专业人员签订劳动合同，且专职专业人员符合国家规定的职业年龄（出资人除外）； （6）专职专业人员人事档案关系由国家认可的人事代理机构代为管理； （7）企业注册资本不少于人民币100 万元； （8）企业近3 年工程造价咨询营业收入累计不低于人民币500 万元； （9）具有固定的办公场所，人均办公建筑面积不少于10 ㎡； （10）技术档案管理制度、质量控制制度、财务管理制度齐全； （11）企业为本单位专职专业人员办理的社会基本养老保险手续齐全； （12）在申请核定资质等级之日前3 年内无违规行为。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0508", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "为了确定工程造价，美国工程新闻记录（ENR)编制的工程造价指数是由（）个体指数加权组成的。", "options": {"A": "机械工人", "B": "波特兰水泥", "C": "普通劳动力", "D": "构件钢材", "E": "木材"}, "answer": ["B", "C", "D", "E"], "analysis": "编制ENR 造价指数的目的是为了准确地预测建筑价格，确定工程造价。它是一个加权总指数，由构件钢材、波特兰水泥、木材和普通劳动力4 种个体指数组成。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0509", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "根据《工程造价咨询企业管理办法》，工程造价咨询企业设立的分支机构不得以自己名字进行的工作有（）。", "options": {"A": "承接工程造价咨询业务", "B": "订立工程造价咨询合同", "C": "委托工程造价咨询项目负责人", "D": "组建工程造价咨询项目管理机构", "E": "出具工程造价成果文件"}, "answer": ["A", "B", "E"], "analysis": "分支机构从事工程造价咨询业务，应当由设立该分支机构的工程造价咨询企业负责承接工程造价咨询业务、订立工程造价咨询合同、出具工程造价成果文件。分支机构不得以自己名义承接工程造价咨询业务、订立工程造价咨询合同、出具工程造价成果文件。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0510", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "根据《工程造价咨询企业管理办法》，工程造价咨询企业出具的工程造价成果文件应加盖有（）的执业印章。", "options": {"A": "企业名称", "B": "资质等级", "C": "资质证书编号", "D": "营业执照编号", "E": "备案编号"}, "answer": ["A", "B", "C"], "analysis": "工程造价咨询企业从事工程造价咨询业务，应按照相关合同或约定出具工程造价成果文件。工程造价成果文件应当由工程造价咨询企业加盖有企业名称、资质等级及证书编一号的执业印章，并由执行咨询业务的注册造价工程师签字、加盖个人执业印章。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0511", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "工程造价咨询企业应当办理资质证书变更手续的情形有（）。", "options": {"A": "企业跨行政区域承接业务", "B": "企业名称发生变更", "C": "企业新增注册造价工程师", "D": "企业技术负责人发生变更", "E": "企业组织形式发生变更"}, "answer": ["B", "D", "E"], "analysis": "资质证书的变更：工程造价咨询企业的名称、住所、组织形式、法定代表人、技术负责人、注册资本等事项发生变更的，应当自变更确立之日起30 日内，到资质许可机关办理资质证书变更手续。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0512", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "从我国整个工程造价行业和工程造价咨询企业层面看，主要存在的问题是（）。", "options": {"A": "还未建立统一规划", "B": "还未建立统一编码的工程造价信息资源共享平台", "C": "工程造价管理的数据库、知识库尚未建立和完善", "D": "工程量计算、汇总分析需要完善", "E": "未形成专业的计算机系统和工程造价管理软件"}, "answer": ["A", "B", "C"], "analysis": "从整个工程造价行业看，还未建立统一规划、统一编码的工程造价信息资源共享平台;从工程造价咨询企业层面看，工程造价管理的数据库、知识库尚未建立和完善。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0513", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "发达国家和地区计算和控制工程造价的主要依据有（）。", "options": {"A": "费用标准", "B": "造价估算标准", "C": "工程量计算规则", "D": "标准定额", "E": "经验数据"}, "answer": ["A", "C", "E"], "analysis": "费用标准、工程量计算规则、经验数据等是发达国家和地区计算和控制工程造价的主要依据。如美国,联邦政府和地方政府没有统一的工程造价计价依据和标准,一般根据积累的工程造价资料，并参考各工程咨询公司有关造价的资料,对各自管辖的政府工程制订相应的计价标准，作为工程费用估算的依据。通过定期发布工程造价指南进行宏观调控与干预。有关工程造价的工程量计算规则、指标、费用标准等，一般是由各专业协会、大型工程咨询公司制订。各地的工程咨询机构，根据本地区的具体特点，制订单位建筑面积的消耗量和基价，作为所管辖项目造价估算的标准。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0514", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "下列属于工程造价计价依据中的设备和工程量计算依据的是（）。", "options": {"A": "项目建议书", "B": "可行性研究报告", "C": "设计文件", "D": "人工单价", "E": "概算定额"}, "answer": ["A", "B", "C"], "analysis": "设备和工程量计算依据:包括项目建议书、可行性研究报告、设计文件等。D 属于工程单价计算依据;E 属于人工、材料、机械等实物消耗量计算依据。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0515", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "工程造价咨询企业设立分支结构的，应当到建设主管部门备案，备案时需提交的资料包括（）。", "options": {"A": "分支机构营业执照复印件", "B": "工程造价咨询企业资质复印件", "C": "拟在分支机构执业的不少于5 名注册造价工程师的注册证书复印件", "D": "分支机构固定办公场所的租赁合同或产权证明", "E": "近几年的工程造价咨询成果文件"}, "answer": ["A", "B", "D"], "analysis": "应提交的资料包括:①分支机构营业执照复印件;②工程造价咨询企业资质复印件;③拟在分支机构执 业的不少于3 名注册造价工程师的注册证书复印件;④分支机构固定办公场所的租赁合同或产权证明。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0516", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "(2009年)根据《合同法》，效力待定合同包括()的合同。", "options": {"A": "损害集体利益", "B": "无代理权人以他人名义订立", "C": "一方以胁迫手段订立", "D": "无处分权的人处分他人财产", "E": "损害社会公共利益"}, "answer": ["B", "D"], "analysis": "效力待定合同是指合同已经成立， 但合同效力能否产生尚不能确定的合同。效力待定合同主要是由于当事人缺乏缔约能力、财产处分能力或代理人的代理资格和代理权限存在缺陷所造成的。效力待定合同包括： 限制民事行为能力人订立的合同和无权代理人代订的合同。(1）限制民事行为能力人订立的合同。(2）元权代理人代订的合同。1）无权代理人代订的合同对被代理人不发生效力的情形。2）无权代理人代订的合同对被代理人具有法律效力的情形。3）法人或者其他组织的法定代表人、负责人超越权限订立的合同的效力。的无处分权的人处分他人财产合同的效力。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0517", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "(2012年)根据《合同法》，下列各类合同中，属于无效合同的有()。", "options": {"A": "恶意串通损害第三人利益的合同", "B": "一方以欺诈手段订立的合同，损害国家利益", "C": "一方乘人之危订立的合同", "D": "损害社会公共利益的合同", "E": "订立合同时显失公平的合同"}, "answer": ["A", "B", "D"], "analysis": "(1）无效合同的情形。有下列情形之一的，合同无效: 1）一方以欺诈、胁迫的手段订立合同，损害国家利益； 2）恶意串通，损害国家、集体或第三人利益； 3）以合法形式掩盖非法目的； 4)损害社会公共利益； 5）违反法律、行政法规的强制性规定。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0518", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "(2015年)根据《价格法》，经营者有权制定的价格有()。", "options": {"A": "资源稀缺的少数商品价格", "B": "自然垄断经营的商品价格", "C": "属于市场调节的价格", "D": "属于政府定价产品范围的新产品试销价格", "E": "公益性服务价格"}, "answer": ["C", "D"], "analysis": "本题考查的是价格法。经营者享有的权利：①自主制定属于市场调节的价格(选项C);②在政府指导价规定的幅度内制定价格；③制定属于政府指导价、政府定价产品范围内的新产品的试销价格，特定产品除外（选项D）；④检举、控告侵犯其依法自主定价权利的行为。选项ABE属于政府定价的商品。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0519", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "(2014年)根据《合同法》，关于违约责任的说法，正确的是（ ）。", "options": {"A": "违约责任以无效合同为前提", "B": "违约责任可由当事人在法定范围内约定", "C": "违约责任以违反合同义务为要件", "D": "违约责任必须以支付违约金的方式承担", "E": "违约责任是一种民事赔偿责任"}, "answer": ["B", "C", "E"], "analysis": "该题主要考察的是：违约责任 违约责任有以下主要特点：（1）违约责任以有效合同为前提。（2）违约责任以违反合同义务为要件。（3）违约责任可由当事人在法定范围内约定。（4）违约责任是一种民事赔偿责任。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0520", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "(2010年)根据《建筑法》，建筑工程安全生产管理应建立健全()制度。", "options": {"A": "责任", "B": "追溯", "C": "保证", "D": "群防群治", "E": "监督"}, "answer": ["A", "D"], "analysis": "建筑工程安全生产管理必须坚持安全第一、预防为主的方针，建立健全安全生产的责任制度和群防群治制度。建筑工程设计也应当符合按照国家规定制定的建筑安全规程和技术规范，保证工程的安全性能。建筑施工企业应当在施工现场采取维护安全、防范危险、预防火灾等措施；有条件的，应当对施工现场实行封闭管理。施工现场安全由建筑施工企业负责。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0521", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "(2013年)根据《建设工程质量管理条例》建设工程竣工验收应具备的条件有()。", "options": {"A": "有完整的技术档案和施工管理资料", "B": "有勘察、设计、施工、监理单位分别签署的质量合格文件", "C": "有施工单位签署的工程保修书", "D": "有工程已结清证明文件", "E": "有工程使用的主要建筑材料的进场实验报告"}, "answer": ["A", "B", "C", "E"], "analysis": "该题主要考察的是：建设工程竣工验收应当具备下列条件 建设工程竣工验收应当具备下列条件：①完成建设工程设计和合同约定的各项内容；②有完整的技术档案和施工管理资料；③有工程使用的主要建筑材料、建筑构配件和设备的进场试验报告；④有勘察、设计、施工、工程监理等单位分别签署的质量合格文件；⑤有施工单位签署的工程保修书。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0522", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "(2013年)根据《建设工程安全生产管理条例》，下列关于建设工程安全生产责任的说法，正确的是()。", "options": {"A": "设计单位应与设计文件中注明涉及施工安全的重点部位和环节", "B": "施工单位对于安全作业费用有其他用途时需经建设单位批准", "C": "施工单位应对管理人员的作业人员每年至少进行一次安全生产教育培训", "D": "施工单位应向作业人员提供安全防护用具和安全防护服装", "E": "施工单位应自施工起重机械验收合格之日起60日内向有关部门登记"}, "answer": ["A", "C", "D"], "analysis": "选项B，施工单位对列入建设工程概算的安全作业环境及安全施工措施所需费用，应当用于施工安全防护用具及设施的采购和更新、安全施工措施的落实、安全生产条件的改善，不得挪作他用。P35：选项E，施工单位应当自施工起重机械和整体提升脚手架、模板等自升式架设设施验收合格之日起30日内，向建设行政主管部门或者其他有关部门登记。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0523", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "(2014年)根据《建设工程质量管理条例》，关于施工单位承揽工程的说法，正确的有（ ）。", "options": {"A": "施工单位应在资质等级许可的范围内承揽工程", "B": "施工单位不得以其他施工单位的名义承揽工程", "C": "施工单位可允许个人以本单位的名义承揽工程", "D": "施工单位不得转包所承揽的工程", "E": "施工单位不得分包所承揽的工程"}, "answer": ["A", "B", "D"], "analysis": "该题主要考察的是：建筑工程承包 承包建筑工程的单位应当持有依法取得的资质证书，并在其资质等级许可的业务范围内承揽工程。禁止建筑施工企业超越本企业资质登记许可的业务范围或者以任何形式用其他建筑施工企业的名义承揽工程。禁止建筑施工企业以任何方式允许其他单位或个人使用本企业的资质证书、营业执照，以本企业的名义承揽工程。建筑工程总承包单位可以将承包工程中的部分工程发包给具有相应资质条件的分包单位。禁止承包单位将其承包的全部建筑工程转包给他人，或将其承包的全部建筑工程肢解以后以分包的名义分别转包给他人。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0524", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "(2009年)根据《注册造价工程师管理办法》，注册造价工程师的权利包括()。", "options": {"A": "确定工程计价方法", "B": "使用注册造价工程师名称", "C": "制定执业活动成果的质量标准", "D": "审批工程价款支付额度", "E": "保管和使用本人的执业印章"}, "answer": ["B", "E"], "analysis": "(2）注册造价工程师的权利： 1）使用注册造价工程师名称； 2）依法独立执行工程造价业务； 3）在本人执业活动中形成的工程造价成果文件上签字并加盖执业印章； 4）发起设立工程造价咨询企业； 5）保管和使用本人的注册证书和执业印章； 6）参加继续教育。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0525", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "(2012年)根据《注册造价工程师管理办法》，属于注册造价工程师权利的有()。", "options": {"A": "依法独立执行工程造价业务", "B": "严格执行工程计价标准和方法", "C": "保证工程造价执业活动成果质量", "D": "发起设立工程造价咨询企业", "E": "保管和使用本人的注册证书和执业印章"}, "answer": ["A", "D", "E"], "analysis": "(2）注册造价工程师的权利： 1）使用注册造价工程师名称； 2）依法独立执行工程造价业务； 3）在本人执业活动中形成的工程造价成果文件上签字并加盖执业印章； 4）发起设立工程造价咨询企业； 5）保管和使用本人的注册证书和执业印章； 6）参加继续教育。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0526", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "(2009年)工程造价咨询企业的业务范围包括()。", "options": {"A": "审批建设项目可行性研究中的投资估算", "B": "确定建设项目合同价款", "C": "编制与审核工程竣工决算报告", "D": "仲裁工程结算纠纷", "E": "提供工程造价信息服务"}, "answer": ["B", "C", "E"], "analysis": "工程造价咨询业务范围包括： (1）建设项目建议书及可行性研究投资估算、项目经济评价报告的编制和审核； (2）建设项目概预算的编制与审核， 并配合设计方案比选、优化设计、限额设计等工作进行工程造价分析与控制； (3）建设项目合同价款的确定（包括招标工程工程量清单和标底、投标报价的编制和审核）；合同价款的签订与调整（包括工程变更、工程洽商和索赔费用的计算）与工程款支付， 工程结算、竣工结算和决算报告的编制与审核等； (4）工程造价经济纠纷的鉴定和仲裁的咨询； (5）提供工程造价信息服务等。同时， 工程造价咨询企业可以对建设项目的组织实施进行全过程或者若干阶段的管理和服务。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0527", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "(2009年)按现行规定，建设项目静态投资包括()。", "options": {"A": "基本预备费", "B": "因工程量误差引起的造价增长值", "C": "施工机械租赁费", "D": "涨价预备费", "E": "建设期贷款利息"}, "answer": ["A", "B", "C"], "analysis": "静态投资是指不考虑物价上涨、建设期贷款利息等影响因素的建设投资。静态投资包括：建筑安装工程费、设备和工器具购置费、工程建设其他费、基本预备费， 以及因工程量误差而引起的工程造价增减值等。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0528", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "(2012年)编制ENR造价指数的资料来源于()。", "options": {"A": "10个欧洲城市", "B": "20个美国城市", "C": "5个亚洲城市", "D": "2个加拿大城市", "E": "2个澳洲城市"}, "answer": ["B", "D"], "analysis": "ENR指数资料来源于20 个美国城市和2 个加拿大城市，ENR在这些城市中派有信息员， 专门负责收集价格资料和信息。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0529", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "(2011年)美国工程新闻记录(ENR)发布的工程造价指数由()个体指数组成。", "options": {"A": "构件钢材", "B": "波特兰水泥", "C": "木材", "D": "普通劳动力", "E": "通用施工机械"}, "answer": ["A", "B", "C", "D"], "analysis": "编制ENR 造价指数的目的是为，子准确地预测建筑价格， 确定工程造价。它是一个加权总指数， 由构件钢材、波特兰水泥、木材和普通劳动力4种个体指数组成。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0609", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "根据《中华人民共和国合同法》，属于不得撤销要约的情况有（ ）。", "options": {"A": "要约人确定了承诺期限", "B": "要约已经达到受要约人", "C": "要约人明示要约不可撤销", "D": "受要约人有理由认为要约是不可撤销的，并已经为履行合同做了准备", "E": "要约已经发生了法律效力"}, "answer": ["A", "C", "D"], "analysis": "撤销要约的通知应当在受要约人发出承诺通知之前到达受要约人。但有下列情形之一的，要约不得撤销： ①要约人确定了承诺期限或者以其他形式明示要约不可撤销； ②受要约人有理由认为要约是不可撤销的，并已经为履行合同做了准备工作。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0610", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "根据《中华人民共和国价格法》，政府在必要时可以实行政府指导价或政府定价的有（ ）。", "options": {"A": "与国民经济发展和人民生活关系重大的极少数商品价格", "B": "非自然垄断经营的商品价格", "C": "资源稀缺的少数商品价格", "D": "重要的公益性服务价格", "E": "重要的公用事业价格"}, "answer": ["A", "C", "D", "E"], "analysis": "下列商品和服务价格，政府在必要时可以实行政府指导价或者政府定价： ①与国民经济发展和人民生活关系重大的极少数商品价格； ②资源稀缺的少数商品价格； ③自然垄断经营的商品价格； ④重要的公用事业价格； ⑤重要的公益性服务价格。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0611", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "《中华人民共和国招标投标法》规定，凡在我国境内进行的下列工程建设项目，必须进行招标的是（ ）。", "options": {"A": "大型基础设施、公用事业等关系社会公共利益、公共安全的项目", "B": "技术复杂、专业性强或其他特殊要求的项目", "C": "全部或部分使用国有资金投资或国家融资的项目", "D": "使用国际组织或者外国政府贷款、援助资金的项目", "E": "采用特定专利或专有技术的项目"}, "answer": ["A", "C", "D"], "analysis": "《招标投标法》规定，在中华人民共和国境内进行下列工程建设项目(包括项目的勘察、设计、施工、监理以及与工程建设有关的重要设备、材料等的采购)必须进行招标： (1)大型基础设施、公用事业等关系社会公共利益、公众安全的项目。 (2)全部或者部分使用国有资金投资或者国家融资的项目。 (3)使用国际组织或者外国政府贷款、援助资金的项目。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0612", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "债权人可以将合同的权利全部或者部分转让给第三人，但下列（ ）等情形不得转让。", "options": {"A": "债务人可以向受让人主张抵消", "B": "根据合同性质不得转让", "C": "按照当事人约定不得转让", "D": "依照法律规定不得转让", "E": "当事人一方经对方同意"}, "answer": ["B", "C", "D"], "analysis": "债权人可以将合同的权利全部或者部分转让给第三人，但下列三种情形不得转让：①根据合同性质不得转让；②按照当事人约定不得转让；③依照法律规定不得转让。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0613", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "合同履行原则中，诚实信用原则要求合同当事人在履行合同约定的主义务的同时，还应履行的附随义务包括（ ）。", "options": {"A": "及时通知义务", "B": "提供必要条件的义务", "C": "协助义务", "D": "保密义务", "E": "当面解释的义务"}, "answer": ["A", "B", "C", "D"], "analysis": "诚实信用原则还要求合同当事人在履行合同约定的主义务的同时，履行合同履行过程中的附随义务： 1)及时通知义务。有些情况需要及时通知对方的，当事人一方应及时通知对方。 2)提供必要条件和说明的义务。需要当事人提供必要的条件和说明的，当事人应当根据对方的需要提供必要的条件和说明。 3)协助义务。需要当事人一方予以协助的，当事人一方应尽可能地为对方提供所需要的协助。 4)保密义务。需要当事人保密的，当事人应当保守其在订立和履行合同过程中所知悉的对方当事人的商业秘密、技术秘密等。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0614", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "发、承包双方在工程质量保修书中约定的建设工程的保修范围包括（ ）。", "options": {"A": "地基基础工程", "B": "主体结构工程", "C": "自行装修装饰工程", "D": "供热与供冷系统", "E": "设备安装和装修工程"}, "answer": ["A", "B", "D", "E"], "analysis": "质量保修书中应当明确建设工程的保修范围、保修期限和保修责任等。建设工程的保修期，自竣工验收合格之日起计算。 在正常使用条件下，建设工程最低保修期限为： (1)基础设施工程、房屋建筑的地基基础工程和主体结构工程，为设计文件规定的该工程合理使用年限。 (2)屋面防水工程、有防水要求的卫生间、房间和外墙面的防渗漏，为5年。 (3)供热与供冷系统，为2个采暖期、供冷期。 (4)电气管道、给排水管道、设备安装和装修工程，为2年。 其他工程的保修期限由发包方与承包方约定。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0615", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "关于合同内容没有约定或者约定不明确的处理方法，下列说法正确的是（ ）。", "options": {"A": "履行地点不明确，给付货币的，在接受货币一方所在地履行", "B": "价款或者报酬不明确的，按照订立合同时履行地的市场价格履行", "C": "交付不动产的，在不动产所在地履行", "D": "履行费用的负担不明确的，由双方共同负担", "E": "质量要求不明确的，按照地方标准履行"}, "answer": ["A", "B", "C"], "analysis": "质量要求不明确的，按照国家标准、行业标准履行；没有国家标准、行业标准的，按照通常标准或者符合合同目的的特定标准履行。价款或者报酬不明确的，按照订立合同时履行地的市场价格履行；依法应当执行政府定价或者政府指导价的，在合同约定的交付期限内政府价格调整时，按照交付时的价格计价。履行地点不明确，给付货币的，在接受货币 一方所在地履行；交付不动产的，在不动产所在地履行；其他标的，在履行义务一方所在地履行 。履行费用的负担不明确的，由履行义务一方负担 。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0616", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "有下列（ ）等情形之一，难以履行债务的，债务人可以将标的物提存。", "options": {"A": "当事人可以要求恢复原状", "B": "债权人无正当理由拒绝受领", "C": "债权人死亡未确定继承人或者丧失民事行为能力未确定监护人", "D": "债权人下落不明", "E": "法律规定的其他情形"}, "answer": ["B", "C", "D", "E"], "analysis": "有下列情形之一，难以履行债务的，债务人可以将标的物提存： ①债权人无正当理由拒绝受领； ②债权人下落不明； ③债权人死亡未确定继承人或者丧失民事行为能力未确定监护人； ④法律规定的其他情形。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0617", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "下列关于工程建设项目招标范围划分正确的选项是（ ）。", "options": {"A": "大型基础设施、公用事业等关系社会公共利益、公众安全的项目", "B": "个人投资的生产性项目", "C": "外商投资的生产性项目", "D": "全部或者部分使用国有资金投资或者国家融资的项目", "E": "使用国际组织或者外国政府资金的项目"}, "answer": ["A", "D", "E"], "analysis": "《招标投标法》规定，在中华人民共和国境内进行下列工程建设项目(包括项目的勘察、设计、施工、监理以及与工程建设有关的重要设备、材料等的采购)必须进行招标： (1)大型基础设施、公用事业等关系社会公共利益、公众安全的项目。 (2)全部或者部分使用国有资金投资或者国家融资的项目。 (3)使用国际组织或者外国政府贷款、援助资金的项目。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0618", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "投标文件的送达是整个招标投标活动中一项重要的法律行为，与投标人的利益密切相关。投标人在送达投标文件时应注意以下事项，下面所列表述正确的是（ ）。", "options": {"A": "投标截止时间前送达投标文件", "B": "最好是在截止日期前一天", "C": "要求招标人签收投标文件", "D": "送达文件必须两人以上", "E": "在规定投标文件送达截止时间前投标文件仍可以补充、修改和撤回"}, "answer": ["A", "C", "E"], "analysis": "投标人应当在招标文件要求提交投标文件的截止时间前，将投标文件送达投标地点。招标人收到投标文件后，应当签收保存，不得开启。在招标文件要求提交投标文件的截止时间前，投标人可以补充、修改或者撤回已提交的投标文件，并书面通知招标人。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0619", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "关于合同价款纠纷的处理原则，下列说法正确的有（ ）。", "options": {"A": "建设工程施工合同无效，但建设工程经竣工验收合格，承包人请求参照合同约定支付工程价款的，不予支持", "B": "当事人对垫资利息没有约定的，承包人请求支付利息的，应予支持", "C": "建设工程施工合同解除后，已经完成的建设工程质量合格的，发包人应当按照约定支付相应的工程价款", "D": "工程欠款的利息从应付工程价款之日计付", "E": "当事人对垫资利息没有约定，承包人请求支付利息的，不予支持"}, "answer": ["C", "D", "E"], "analysis": "选项A错误，正确的是建设工程施工合同无效，但建设工程经竣工验收合格，承包人请求参照合同约定支付工程价款的，应予支持。选项B错误，正确的是当事人对垫资利息没有约定，承包人请求支付利息的，不予支持。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0620", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "在施工过程中， 施工人员发现设计图纸不符合技术标准， 施工单位技术负责人采取的正确做法有（ ）", "options": {"A": "继续按照工程设计图纸施工", "B": "按照技术标准修改工程设计", "C": "追究设计单位违法责任", "D": "及时提出意见和建议", "E": "告知建设单位"}, "answer": ["D", "E"], "analysis": "本题考查的是施工单位技术负责人在发现设计图纸不符合技术标准时应该采取的正确做法。根据常识和实际情况，选项A显然是错误的，因为按照不符合技术标准的设计图纸施工会导致工程质量问题。选项C也不是施工单位技术负责人应该采取的做法，因为追究设计单位违法责任不是施工单位技术负责人的职责范围。因此，正确答案应该是D和E。施工单位技术负责人应该及时提出意见和建议，以便设计单位进行修改，确保工程符合技术标准；同时，也应该告知建设单位，以便建设单位能够及时处理问题，避免工程质量问题的发生。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0621", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "根据《合同法》下列合同中，属于效力待定合同的有（）。", "options": {"A": "因重大误解订立的合同", "B": "恶意串通损害第三人利益的合同", "C": "在订立合同时显失公平的合同", "D": "超越代理权限范围订立的合同", "E": "限制民事行为能力人订立的合同"}, "answer": ["D", "E"], "analysis": "效力待定合同包括：限制民事行为能力人订立的合同和无权代理人代订的合同。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0622", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "对于列入建设工程概算的安全作业环境及安全施工措施所需的费用，施工单位应当用于（）。", "options": {"A": "安全生产条件改善", "B": "专职安全管理人员工资发放", "C": "施工安全设施更新", "D": "安全事故损失赔付", "E": "施工安全防护用具采购"}, "answer": ["A", "C", "E"], "analysis": "施工单位对列入建设工程概算的安全作业环境及安全施工措施所需费用，应当用于施工安全防护用具及设施的采购和更新、安全施工措施的落实、安全生产条件的改善，不得挪作他用。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0623", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "《建设工程质量管理条例》关于施工单位对建筑材料、建筑构配件、设备和商品混凝土进行检验的具体规定有（ ）。", "options": {"A": "检验必须按照工程设计要求、施工技术标准和合同约定进行", "B": "检验结果未经监理工程师签字，不得使用", "C": "检验结果未经施工单位质量负责人签字，不得使用", "D": "未经检验或者检验不合格的，不得使用", "E": "检验应当有书面记录和专人签字"}, "answer": ["A", "D", "E"], "analysis": "本题考查的是施工单位的质量责任和义务。施工单位必须按照工程设计要求、施工技术标准和合同约定，对建筑材料、建筑构配件、设备和商品混凝土进行检验，检验应当有书面记录和专人签字；未经检验或者检验不合格的，不得使用。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0624", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "当事人在订立合同过程中有过错， 给对方造成损失， 应当承担缔约过失责任的情形有（ ） 。", "options": {"A": "假借订立合同，恶意进行磋商的", "B": "泄露对方商业秘密的", "C": "提供虚假情况的", "D": "故意隐瞒与订立合同有关重要事实的", "E": "经过艰苦的谈判但最终未签订合同的"}, "answer": ["A", "B", "C", "D"], "analysis": "本题考查的是缔约过失责任的情形。缔约过失责任是指当事人在订立合同过程中，由于过错给对方造成损失，应当承担的法律责任。根据合同法的规定，当事人在订立合同过程中有以下过错行为，应当承担缔约过失责任： A. 假借订立合同，恶意进行磋商的：指当事人在订立合同过程中，明知自己不想订立合同，却假借订立合同的名义，与对方进行磋商，以达到某种目的的行为。 B. 泄露对方商业秘密的：指当事人在订立合同过程中，泄露对方商业秘密，给对方造成损失的行为。 C. 提供虚假情况的：指当事人在订立合同过程中，提供虚假情况，导致对方误解，给对方造成损失的行为。 D. 故意隐瞒与订立合同有关重要事实的：指当事人在订立合同过程中，故意隐瞒与订立合同有关重要事实，导致对方误解，给对方造成损失的行为。 E. 经过艰苦的谈判但最终未签订合同的：指当事人在订立合同过程中，经过艰苦的谈判，但最终未能签订合同，不属于缔约过失责任的情形。 综上所述，本题的正确答案为ABCD。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0625", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "《招标投标法》 规定， 投标文件（ ） 的投标人应确定为中标人。", "options": {"A": "满足招标文件中规定的各项综合评价标准的最低要求", "B": "最大限度地满足招标文件中规定的各项综合评价标准", "C": "满足招标文件各项要求，并且报价最低", "D": "满足招标文件各项要求，并且经评审后的投标价格最低", "E": "满足招标文件各项要求，并且经评审后的投标价格最高"}, "answer": ["B", "D"], "analysis": "根据《招标投标法》的规定，投标文件应当包括投标人的资格条件、技术方案、商务方案和投标报价等内容。而中标人则是指在评审中被确定为最终中标的投标人。因此，选项C和E中的“报价最低”和“投标价格最高”都不符合实际情况。 选项A和B都提到了“满足招标文件中规定的各项综合评价标准”，但是A只是满足最低要求，而B则是最大限度地满足。这两个选项都没有提到价格因素，因此不能作为唯一的标准。 选项D中提到了“经评审后的投标价格最低”，这符合实际情况。因为在评审中，除了技术方案、商务方案等因素外，价格也是一个重要的考虑因素。而经过评审后，价格最低的投标人往往会被确定为中标人。 综上所述，选项BD是正确的。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0626", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "根据《建设工程质量管理条例》，在正常使用条件下，关于建设工程最低保修期限的说法，正确的有（ ）。", "options": {"A": "地基基础工程为设计文件规定的合理使用年限", "B": "屋面防水工程为设计文件规定的合理使用年限", "C": "供热与供冷系统为2个采暖期、供冷期", "D": "有防水要求的卫生间为5年", "E": "电气管线和设备安装工程为2年"}, "answer": ["A", "C", "D", "E"], "analysis": "本题考查的是工程质量保修。在正常使用条件下，建设工程最低保修期限为： （1）基础设施工程、房屋建筑的地基基础工程和主体结构工程，为设计文件规定的该工程合理使用年限。（2）屋面防水工程、有防水要求的卫生间、房间和外墙面的防渗漏，为5年。（3）供热与供冷系统，为2个采暖期、供冷期。（4）电气管道、给排水管道、设备安装和装修工程，为2年。其他工程的保修期限由发包方与承包方约定。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0627", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "根据政府采购法律制度的规定，下列情形中，采购人可以采用竞争性谈判方式采购的有（）。", "options": {"A": "采用招标方式所需时间不能满足用户紧急需要的", "B": "不能事先计算出价格总额的", "C": "采用公开招标方式的费用占政府采购项目总价值的比例过大的", "D": "技术复杂或者性质特殊，不能确定详细规格或者具体要求的", "E": "只能从唯一供应商处采购的"}, "answer": ["A", "B", "D"], "analysis": "本题考查的是政府采购方式。符合下列情形之一的货物或服务，可采用竞争性谈判方式采购： 1.招标后没有供应商投标或没有合格标的或重新招标未能成立的 2.技术复杂或性质特殊，不能确定详细规格或具体要求的 3.采用招标所需时间不能满足用户紧急需要的 4.不能事先计算出价格总额的。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0628", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "合同的权利义务终止又称为合同的终止或者合同的消灭，是指因某种原因而引起的合同权利义务关系在客观上不复存在，有下列（ ）等情形之一的，合同的权利义务终止。", "options": {"A": "债权人免除债务", "B": "债务人依法将标的物提存", "C": "合同债务转移", "D": "债务已经按照约定履行", "E": "债权债务同归于一人"}, "answer": ["A", "B", "D", "E"], "analysis": "有下列情形之一的，合同的权利义务终止： ①债务已经按照约定履行； ②合同解除； ③债务相互抵销； ④债务人依法将标的物提存； ⑤债权人免除债务； ⑥债权债务同归于一人； ⑦法律规定或者当事人约定终止的其他情形。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0629", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "根据《合同法》，下列关于违约赔偿损失的说法中，正确的有（ ）。", "options": {"A": "损失赔偿额应相当于因违约所造成的损失", "B": "损失赔偿额不应包括合同履行后可以获得的利益", "C": "损失赔偿额不以合同当事人订立合同时预见的违约损失为限", "D": "损失赔偿额不包括未采取适当措施致使扩大的损失", "E": "损失赔偿额包括当事人因防止损失扩大而支出的合理费用"}, "answer": ["A", "D", "E"], "analysis": "本题考查的是违约责任的承担方式。关于损失的赔偿额：①应当相当于违约行为所造成的损失；②包括履行合同后可获得的利益；③不得超过违反合同一方订立合同时应当预见的因违反合同可能造成的损失。当事人一方违约后，对方应当采取适当措施防止损失的扩大，没有采取措施致使损失扩大的，不得就扩大的损失请求赔偿，当事人因防止损失扩大而支出的合理费用，由违约方承担。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0630", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "下面关于施工单位对建设工程质量最低保修期限说法正确的有（ ）", "options": {"A": "有防水要求的卫生间为2年", "B": "给排水管道为5年", "C": "电气设备安装工程为2年", "D": "供热与供冷系统，为2个采暖期、供冷期", "E": "装修工程为2年"}, "answer": ["C", "D", "E"], "analysis": "本题考查建设工程质量最低保修期限，依据《建设工程质量管理条例》，正确选项为 C、D、E。有防水要求的卫生间等防水工程最低保修 5 年（A 错误）；给排水管道工程最低保修 2 年（B 错误）；电气设备安装工程（C）、装修工程（E）最低保修 2 年，符合规定；供热与供冷系统最低保修 2 个采暖期、供冷期（D），符合规定。综上，仅 C、D、E 选项符合法规要求。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0631", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "按照《合同法》的规定，合同的权利义务终止的情形有（ ）。", "options": {"A": "合同解除", "B": "债务已经按照约定履行", "C": "债务相互抵消", "D": "债务人免除债务", "E": "债权债务同归于一人"}, "answer": ["A", "B", "C", "E"], "analysis": "本题考查的是合同权利义务终止。有下列情形之一的，合同的权利义务终止：债务已经按照约定履行；合同解除；债务相互抵消；债务人依法将标的物提存；债权人免除债务；债权债务同归于一人；法律规定或者当事人约定终止的其他情形。##", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0632", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "工程造价咨询企业从事工程造价咨询活动，应当遵循（ ）的原则，不得损害社会公共利益和他人的合法权益。", "options": {"A": "独立", "B": "公正", "C": "诚实信用", "D": "客观", "E": "公开"}, "answer": ["A", "B", "C", "D"], "analysis": "根据《工程造价咨询企业管理办法》，工程造价咨询企业是指接受委托，对建设项目投资、工程造价的确定与控制提供专业咨询服务的企业。工程造价咨询企业从事工程造价咨询活动，应当遵循独立、客观、公正、诚实信用的原则，不得损害社会公共利益和他人的合法权益。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0633", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "按现行规定，下列关于工程造价咨询企业业务的承接说明，正确的是（ ）", "options": {"A": "工程造价咨询企业从事造价咨询活动，不受行政区域的限制", "B": "乙级工程造价咨询企业只能从事工程造价3000万元人民币以下的各类建设项目的工程造价咨询业务", "C": "工程造价咨询企业分支机构不得以自己的名义承接工程造价咨询业务", "D": "工程造价咨询企业分支机构可以以自己的名义出具工程造价成果文件", "E": "乙级工程造价咨询企业只能从事专业项目的工程造价咨询业务"}, "answer": ["A", "C"], "analysis": "根据 2020 年修正后的《工程造价咨询企业管理办法》，正确答案AC。解析如下：选项 A：根据《工程造价咨询企业管理办法》第十九条规定，工程造价咨询企业依法从事工程造价咨询活动，不受行政区域限制，所以选项 A 正确。选项 B：根据《工程造价咨询企业管理办法》第十九条规定，乙级工程造价咨询企业可以从事工程造价 2 亿元人民币以下的各类建设项目的工程造价咨询业务，而不是 3000 万元，所以选项 B 错误。选项 C：工程造价咨询企业设立分支机构，应由设立分支机构的工程造价咨询企业负责承接业务、订立合同、出具工程造价成果文件，分支机构不得以自己的名义承接工程造价咨询业务，所以选项 C 正确。选项 D：分支机构不得以自己的名义承接业务、订立合同或出具造价成果文件，需以总公司名义开展工作，所以选项 D 错误。选项 E：乙级工程造价咨询企业可以从事工程造价 2 亿元人民币以下的各类建设项目的工程造价咨询业务，没有只能从事专业项目的限制，所以选项 E 错误。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0634", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "下列属于工程造价咨询企业乙级资质标准的是（ ）。", "options": {"A": "企业注册资本不少于人民币50万元", "B": "具有固定的办公场所，人均办公建筑面积不少于10平方米", "C": "暂定期内工程造价咨询营业收入累计不低于人民币50万元", "D": "专职从事造价专业人员不少于6人", "E": "技术负责人从事工程造价专业工作15年以上"}, "answer": ["A", "B", "C"], "analysis": "1. 选项 A（正确）完全匹配资质标准第 (6) 条，乙级企业注册资本最低要求为人民币 50 万元，符合规定。2. 选项 B（正确）对应资质标准第 (7) 条，需具备固定办公场所，且人均办公建筑面积不少于 10㎡，与选项描述一致。3. 选项 C（正确）符合资质标准第 (10) 条，暂定期内工程造价咨询营业收入累计需不低于人民币 50 万元，是资质核定的硬性指标。4. 选项 D（错误）与资质标准第 (3) 条冲突，正确要求为专职专业人员不少于 12 人（非 6 人），且其中注册造价工程师不少于 6 人，选项人数不达标。5. 选项 E（错误）不符合资质标准第 (2) 条，技术负责人从事造价专业工作需满 10 年以上（非 15 年），15 年虽满足最低要求，但选项表述并非标准规定的核心条件，属于过度要求，不符合 “标准对应” 原则。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_0635", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "在评标过程中，评标委员会可以要求投标人对投标文件有关文件作出必要澄清、说明和补正的情形包括（ ）。", "options": {"A": "投标文件未经单位负责人签字", "B": "对同类问题表述不一致", "C": "投标文件中有含义不明确的内容", "D": "有明显的计算错误", "E": "投标人主动提出的澄清说明"}, "answer": ["B", "C", "D"], "analysis": "本题考查的是《招标投标法实施条例》相关内容。投标文件中有含义不明确的内容、明显文字或者计算错误，评标委员会认为需要投标人做出必要澄清、说明的，应当书面通知该投标人。投标人的澄清、说明应当采用书面形式，并不得超出投标文件的范围或者改变投标文件的实质性内容。", "tags": [], "source": "第一章  工程造价管理相关法律法规与制度", "src": "好题库"}, {"id": "ht_mgmt_1827", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "合同当事人不履行合同时应依法承担违约责任，违约责任的特点有（ ）。", "options": {"A": "以有效合同为前提", "B": "以违反合同义务为要件", "C": "以发生损害后果为要件", "D": "可由当事人在法定范围内约定", "E": "是一种民事赔偿责任"}, "answer": ["A", "B", "D", "E"], "analysis": "【考点来源】本题考查的是违约责任【选项分析】根据《合同法》的相关规定，违约责任的特点有：（1）违约责任以有效合同为前提。（2）违约责任以违反合同义务为要件。（3）违约责任可由当事人在法定范围内约定。（4）违约责任是一种民事赔偿责任。", "tags": [], "source": "四、《合同法》相关内容", "src": "好题库"}, {"id": "ht_mgmt_1829", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "根据《注册造价工程师管理办法》，二级注册造价工程师的执业范围有（ ）。", "options": {"A": "建设工程量清单、投标报价编制", "B": "工程量清单的编制和审核", "C": "建设工程施工图预算、设计概算编制", "D": "建设工程合同价款的编制", "E": "建设工程招标投标文件工程量和造价的编制与审核"}, "answer": ["A", "C", "D"], "analysis": "【内容考查】本题考查的是执业【选项分析】二级造价工程师执业范围:二级造价工程师主要协助一级造价工程师开展相关工作，可独立开展以下具体工作：①建设工程工料分析、计划、组织与成本管理，施工图预算、设计概算编制；②建设工程量清单、最高投标限价、投标报价编制；③建设工程合同价款、结算价款和竣工决算价款的编制。", "tags": [], "source": "二、造价工程师职业资格管理", "src": "好题库"}, {"id": "ht_mgmt_1835", "date": "2026-07-10", "chapter": "g01", "type": "multiple", "stem": "采用 PMC 模式时，项目管理承包单位在前期阶段的工作内容有（ ）。", "options": {"A": "编制 EPC 招标文件", "B": "组织项目风险识别和分析", "C": "协助建设单位进行融资", "D": "实施采购管理", "E": "进行设计管理"}, "answer": ["A", "B", "C"], "analysis": "【考点来源】本题考查的是项目管理承包【选项分析】项目前期阶段工作内容。项目管理承包商的主要任务是代表业主进行项目管理。具体包括：项目建设方案优化；组织项目风险识别和分析，并制定项目风险应对策略；提供融资方案并协助业主进行融资；提出项目应统一遵循的标准及规范；组织或完成基础设计、初步设计和总体设计；协助业主完成政府相关审批工作；提出项目实施方案，完成项目投资估算；提出材料、设备清单及供货厂家名单；编制EPC招标文件，进行EPC投标人资格预审，并完成EPC评标工作。", "tags": [], "source": "二、业主方项目组织模式", "src": "好题库"}, {"id": "mgmt_hqwx_0113", "date": "2026-07-09", "chapter": "g01", "type": "multiple", "stem": "根据《民法典》，关于违约责任的说法，正确的有（ ）。", "options": {"A": "违约责任以无效合同为前提", "B": "违约责任可由当事人在法定范围内约定", "C": "违约责任以合同当事人不履行或者不适当履行合同义务为要件", "D": "违约责任必须以支付违约金的方式承担", "E": "违约责任是一种民事赔偿责任"}, "answer": ["B", "C", "E"], "analysis": "本题考查的是违约责任。违约责任是指合同当事人不履行或不适当履行合同，应依法承担的责任。与其他责任制度相比，违约责任有以下主要特点： （1）违约责任以有效合同为前提。 （2）违约责任以合同当事人不履行或者不适当履行合同义务为要件。 （3）违约责任可由当事人在法定范围内约定。 （4）违约责任是一种民事赔偿责任。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0119", "date": "2026-07-09", "chapter": "g01", "type": "multiple", "stem": "根据《政府采购法》，下列项目中，可以采用单一来源采购方式的有（ ）。", "options": {"A": "只能从唯一供应商处采购的项目", "B": "采用公开招标所需时间不能满足用户紧急需要的项目", "C": "采购的货物规格和标准统一，现货货源充足且价格变化幅度小的项目", "D": "发生了不可预见的紧急情况下不能从其他供应商处采购的", "E": "技术复杂，事先不能计算出标的价格总额的项目"}, "answer": ["A", "D"], "analysis": "【内容考查】本题考查的是《政府采购法》相关内容 【选项分项】可以采用单一来源方式进行采购：（1）只能从唯一供应商处采购的；（2）发生了不可预见的紧急情况不能从其他供应商处采购的；（3）必须保证原有采购项目一致性或者服务配套的要求，需要继续从原供应商处添购，且添购资金总额不超过原合同采购金额10％的。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0121", "date": "2026-07-09", "chapter": "g01", "type": "multiple", "stem": "根据《招标投标法实施条例》，属于以不合理条件限制、排斥潜在投标人或投标人的情形有（ ）。", "options": {"A": "就同一招标项目向投标人提供相同的项目信息", "B": "设定的技术和商务条件与合同履行无关", "C": "以特定行业的业绩作为加分条件", "D": "对投标人采用无差别的资格审查标准", "E": "对招标项目指定特定的品牌和原产地"}, "answer": ["B", "C", "E"], "analysis": "【内容考查】本题考查的是《招标投标法实施条例》相关内容 【选项分项】招标人有下列行为之一的，属于以不合理条件限制、排斥潜在投标人或者投标人：①就同一招标项目向潜在投标人或者投标人提供有差别的项目信息；②设定的资格、技术、商务条件与招标项目的具体特点和实际需要不相适应或者与合同履行无关；③依法必须进行招标的项目以特定行政区域或者特定行业的业绩、奖项作为加分条件或者中标条件；④对潜在投标人或者投标人采取不同的资格审查或者评标标准；⑤限定或者指定特定的专利、商标、品牌、原产地或者供应商；⑥依法必须进行招标的项目非法限定潜在投标人或者投标人的所有制形式或者组织形式；⑦以其他不合理条件限制、排斥潜在投标人或者投标人。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0124", "date": "2026-07-09", "chapter": "g01", "type": "multiple", "stem": "根据《招投标法实施条例》，下列关于招投标的说法正确的有（ ）。", "options": {"A": "采购人依法自行建设、生产项目，可以不进行招标", "B": "招标费用占合同金额比例过大的项目，可以不进行招标", "C": "招标人发售资格预审文件、招标文件收取的费用应当限于补偿印刷、邮寄的成本支出，不得以营利为目的", "D": "潜在投标人对招标文件有异议的，应当在投标截止时间10日前提出", "E": "招标人采用资格后审办法的，应当在开标后15日内由评标委员会公布审查结果"}, "answer": ["A", "C", "D"], "analysis": "【内容考查】本题考查的是 《招标投标法实施条例》相关内容 【选项分析】选项A：可以不招标的项目其中包括采购人依法能够自行建设、生产或者提供；选项B：招标费用占合同金额比例过大的项目，可以邀请招标；选项C：招标人发售资格预审文件、招标文件收取的费用应当限于补偿印刷、邮寄的成本支出，不得以营利为目的；选项D：潜在投标人如对招标文件有异议，应当在投标截止时间10日前提出；选项E：如招标人采用资格后审办法对投标人进行资格审查，应当在开标后由评标委员会按照招标文件规定的标准和方法对投标人的资格进行审查。因此，正确选项为ACD。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0127", "date": "2026-07-09", "chapter": "g01", "type": "multiple", "stem": "根据《价格法》，经营者有权制定的价格有（ ）。", "options": {"A": "资源稀缺的少数商品价格", "B": "自然垄断经营的商品价格", "C": "属于市场调节的价格", "D": "属于政府定价产品那个范围的新产品试销价格", "E": "公益性服务价格"}, "answer": ["C", "D"], "analysis": "【内容考查】本题考查的是《价格法》相关内容 【选项分项】对下列商品和服务价格，政府在必要时可以实行政府指导价或政府定价：①与国民经济发展和人民生活关系重大的极少数商品价格；②资源稀缺的少数商品价格；③自然垄断经营的商品价格；④重要的公用事业价格；⑤重要的公益性服务价格。选项C和D，不属于实行政府指导价或政府定价范围，经营者有权制定价格。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0131", "date": "2026-07-09", "chapter": "g01", "type": "multiple", "stem": "根据《价格法》，政府可依据有关商品或者服务的社会平均成本和市场供求状况、国民经济与社会发展要求以及社会承受能力，实行合理的（ ）。", "options": {"A": "购销差价", "B": "批零差价", "C": "利税差价", "D": "地区差价", "E": "季节差价"}, "answer": ["A", "B", "D", "E"], "analysis": "【内容考查】本题考查的价格法相关内容。 【选项分析】政府应当依据有关商品或者服务的社会平均成本和市场供求状况、国民经济与社会发展要求以及社会承受能力，实行合理的购销差价、批零差价、地区差价和季节差价。制定关系群众切身利益的公用事业价格、公益性服务价格、自然垄断经营的商品价格时，应当建立听证会制度，征求消费者、经营者和有关方面的意见。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0135", "date": "2026-07-09", "chapter": "g01", "type": "multiple", "stem": "根据《建设工程安全生产管理条例》，施工单位应当对达到一定规模的危险性较大的（ ）编制专项施工方案。", "options": {"A": "土方开挖工程", "B": "钢筋工程", "C": "模板工程", "D": "混凝土工程", "E": "脚手架工程"}, "answer": ["A", "C", "E"], "analysis": "【内容考查】本题考查的是《建设工程安全生产管理条例》相关内容 【选项分项】施工单位应当在施工组织设计中编制安全技术措施和施工现场临时用电方案，对下列达到一定规模的危险性较大的分部分项工程编制专项施工方案，并附具安全验算结果，经施工单位技术负责人、总监理工程师签字后实施，由专职安全生产管理人员进行现场监督：①基坑支护与降水工程；②土方开挖工程；③模板工程；④起重吊装工程；⑤脚手架工程；⑥拆除、爆破工程；⑦国务院建设行政主管部门或者其他有关部门规定的其他危险性较大的工程。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0136", "date": "2026-07-09", "chapter": "g01", "type": "multiple", "stem": "《建筑法》规定的建筑许可内容有（ ）。", "options": {"A": "建筑工程施工许可", "B": "建筑工程监理许可", "C": "建筑工程规划许可", "D": "从业资格许可", "E": "建设投资规模许可"}, "answer": ["A", "D"], "analysis": "【内容考查】本题考查的是《建筑法》相关内容 【选项分项】建筑许可包括建筑工程施工许可和从业资格两个方面。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0139", "date": "2026-07-09", "chapter": "g01", "type": "multiple", "stem": "根据《建筑法》的相关规定，下列建筑工程承发包行为中属于法律允许的是（ ）。", "options": {"A": "承包单位将其承包的全部建筑工程转包或肢解以后转包给他人", "B": "两个以上的承包单位联合共同承包一项大型建筑工程", "C": "分包单位将其承包的部分工程发包给他人", "D": "建筑企业集团公司可以允许其他公司以其名义承揽工程", "E": "除总承包合同约定的分包外，工程分包须经建设单位认可"}, "answer": ["B", "E"], "analysis": "【内容考查】本题考查的是《建筑法》相关内容 【选项分分析】禁止承包单位将其承包的全部建筑工程转包给他人，或将其承包的全部建筑工程肢解以后以分包的名义分别转包给他人。禁止总承包单位将工程分包给不具备资质条件的单位。禁止分包单位将其承包的工程再分包。建筑工程总承包单位可以将承包工程中的部分工程发包给具有相应资质条件的分包单位。但是，除总承包合同中已约定的分包外，必须经建设单位认可。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0144", "date": "2026-07-09", "chapter": "g01", "type": "multiple", "stem": "根据《政府采购法》，下面关于政府采购的相关内容说法正确的有（ ）。", "options": {"A": "政府采购的主要采购方式的是公开招标", "B": "政府采购的主要采购方式只有公开招标、邀请招标和竞争性谈判", "C": "政府采购合同履行中，不可以与供应商协商签订补充合同", "D": "政府采购合同履行中，可以与供应商协商签订补充合同", "E": "所有补充合同的采购金额不得超过原合同采购金额的10%"}, "answer": ["A", "D", "E"], "analysis": "【内容考查】本题考查的是《政府采购法》相关内容 【选项分析】政府采购可采用的方式有：公开招标、邀请招标、竞争性谈判、单一来源采购、询价，以及国务院政府采购监督管理部门认定的其他采购方式。公开招标应作为政府采购的主要采购方式。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0145", "date": "2026-07-09", "chapter": "g01", "type": "multiple", "stem": "根据《建设工程安全生产管理条例》，施工单位对列入工程概算的安全作业环境及安全施工措施所需费用，应当用于（ ）。", "options": {"A": "施工安全防护设施的采购", "B": "施工机械设备的更新", "C": "施工机具安全性能的检测", "D": "安全施工措施的落实", "E": "安全生产条件的改善"}, "answer": ["A", "D", "E"], "analysis": "【内容考查】本题考查的是《建设工程安全生产管理条例》相关内容 【选项分析】根据《建设工程安全生产管理条例》，施工单位对列入建设工程概算的安全作业环境及安全施工措施所需费用，应当用于施工安全防护用具及设施的采购和更新、安全施工措施的落实、安全生产条件的改善，不得挪作他用。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0146", "date": "2026-07-09", "chapter": "g01", "type": "multiple", "stem": "根据《民法典》，合同当事人违约责任的特点有（ ）。", "options": {"A": "违约责任以合同成立为前提", "B": "违约责任是一种刑事赔偿责任", "C": "违约责任以合同当事人不履行或者不适当履行合同义务为要件", "D": "违约责任可由合同当事人在法律范围内约定", "E": "违约责任的确定，通常应以补偿守约方的损失为标准"}, "answer": ["C", "D", "E"], "analysis": "违约责任具有以下特点： （1）以有效合同为前提。 （2）以合同当事人不履行或者不适当履行合同义务为要件。 （3）可由合同当事人在法定范围内约定。 （4）是一种民事赔偿责任。首先，它是由违约方向守约方承担的民事责任，无论是违约金还是赔偿金，均是平等主体之间的支付关系；其次，违约责任的确定，通常应以补偿守约方的损失为标准。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0149", "date": "2026-07-09", "chapter": "g01", "type": "multiple", "stem": "根据《建筑法》，关于建筑工程承包的说法，正确的有（ ）。", "options": {"A": "承包单位应在其资质等级许可的业务范围内承揽工程", "B": "大型建筑工程可由两个以上的承包单位联合共同承包", "C": "除总承包合同约定的分包外，工程分包须经建设单位认可", "D": "总承包单位就分包工程对建设单位不承担连带责任", "E": "分包单位可将其分包的工程再分包"}, "answer": ["A", "B", "C"], "analysis": "【内容考查】本题考查的是《建筑法》相关内容 【选项分析】总承包单位和分包单位就分包工程对建设单位承担连带责任，故D选项错误。禁止分包单位将其承包的工程再分包，故E选项错误。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0151", "date": "2026-07-09", "chapter": "g01", "type": "multiple", "stem": "根据《招标投标实施条例》，关于投标保证金的说法，正确的有（ ）。", "options": {"A": "投标保证金有效期应当与投标有效期一致", "B": "投标保证金不得超过招标项目估算价的2%", "C": "采用两阶段招标的，投标保证金应在第一阶段提交投标保证金", "D": "招标人不得挪用投标保证金", "E": "招标人最迟应在签订书面合同时退还投标保证金"}, "answer": ["A", "B", "D"], "analysis": "【内容考查】本题考查的是《招标投标法实施条例》相关内容 【选项分析】采用两阶段招标的，如招标人要求投标人提交投标保证金，应当在第二阶段提出。故C错误；招标人最迟应当在书面合同签订后5日内向中标人和未中标的投标人退还投标保证金及银行同期存款利息。故E选项错误。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0153", "date": "2026-07-09", "chapter": "g01", "type": "multiple", "stem": "根据《政府釆购法实施条例》，下列说法正确的是（ ）。", "options": {"A": "履约保证金的数额不得超过政府采购合同金额的10%", "B": "履约保证金的数额不得超过政府采购合同金额的5%", "C": "履约保证金的数额不得超过采购项目预算金额的10%", "D": "投标保证金不得超过采购项目预算金额的2%", "E": "投标保证金不得超过政府采购合同金额的2%"}, "answer": ["A", "D"], "analysis": "【内容考查】本题考查的是 《政府釆购法实施条例》相关内容 【选项分析】根据《政府釆购法实施条例》相关内容，招标文件要求投标人提交投标保证金的，投标保证金不得超过采购项目预算金额的2% 。 履约保证金的数额不得超过政府采购合同金额的10%。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0156", "date": "2026-07-09", "chapter": "g01", "type": "multiple", "stem": "根据《招标投标法实施条例》，视为投标人相互串通投标的情形有（ ）。", "options": {"A": "投标人之间协商投标报价", "B": "不同投标人委托同一单位办理投标事宜", "C": "不同投标人的投标保证金从同一单位的账户转出", "D": "不同投标人的投标文件载明的项目管理成员为同一人", "E": "投标人之间约定中标人"}, "answer": ["B", "C", "D"], "analysis": "【内容考查】本题考查的是 《招标投标法实施条例》相关内容 【选项分析】 有下列情形之一的，视为投标人相互串通投标： 1）不同投标人的投标文件由同一单位或者个人编制； 2）不同投标人委托同一单位或者个人办理投标事宜； 3）不同投标人的投标文件载明的项目管理成员为同一人； 4）不同投标人的投标文件异常一致或者投标报价呈规律性差异； 5）不同投标人的投标文件相互混装； 6）不同投标人的投标保证金从同一单位或者个人的账户转出。 选项A、选项E属于投标人相互串通投标的行为。 【名师点拨】主观行为一致为相互串通投标，客观表现一致为视为串通投标。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0159", "date": "2026-07-09", "chapter": "g01", "type": "multiple", "stem": "根据《中华人民共和国建筑法》，从事建筑活动的建筑施工企业应当具备的条件有（ ）。陕西-2019", "options": {"A": "符合规定的注册资本", "B": "从事相关活动的技术装备", "C": "足够数量的以往类似业绩", "D": "符合要求的年纳税金额", "E": "与其从事建筑活动相适应的具有法定执业资格的专业技术人员"}, "answer": ["A", "B", "E"], "analysis": "【考点来源】本题考查的是建筑法 【选项分析】根据《建筑法》的相关规定，从事建筑活动的建筑施工企业、勘察单位、设计单位和工程监理单位，应当具备下列条件：①符合国家规定的注册资本；②与其从事建筑活动相适应的具有法定执业资格的专业技术人员；③有从事相关建筑活动所应有的技术装备；④法律、行政法规规定的其他条件。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0167", "date": "2026-07-09", "chapter": "g01", "type": "multiple", "stem": "根据《招标投标法实施条例》，评标委员会应当否决投标的情形有（ ）。", "options": {"A": "投标报价高于工程成本", "B": "投标文件未经投标单位负责人签字", "C": "投标报价低于招标控制价", "D": "投标联合体没有提交共同投标协议", "E": "投标人不符合招标文件规定的资格条件"}, "answer": ["D", "E"], "analysis": "【内容考查】本题考查的是《招标投标法实施条例》相关内容 【选项分析】有下列情形之一的，评标委员会应当否决其投标： 1）投标文件未经投标单位盖章和单位负责人签字； 2）投标联合体没有提交共同投标协议； 3）投标人不符合国家或者招标文件规定的资格条件； 4）同一投标人提交两个以上不同的投标文件或者投标报价，但招标文件要求提交备选投标的除外； 5）投标报价低于成本或者高于招标文件设定的最高投标限价； 6）投标文件没有对招标文件的实质性要求和条件作出响应； 7）投标人有串通投标、弄虚作假、行贿等违法行为。 【名师点拨】考生需要注意选项B，否决投标必须是无“签字”和“盖章”两项都没有才会否决。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0171", "date": "2026-07-09", "chapter": "g01", "type": "multiple", "stem": "根据《招标投标法实施条例》，下列情形可以进行邀请招标的有（ ）。", "options": {"A": "采用公开招标方式的费用占项目合同金额的比例过大", "B": "需要采用不可替代的专利或者专有技术", "C": "需要向原中标人采购工程、货物或者服务的", "D": "采购人依法能够自行建设、生产或者提供", "E": "受自然环境限制，只有少量潜在投标人可供选择"}, "answer": ["A", "E"], "analysis": "【内容考查】本题考查的是《招标投标法实施条例》相关内容 【选项分析】国有资金占控股或者主导地位的依法必须进行招标的项目，应当公开招标；但有下列情形之一的，可以邀请招标：（1）技术复杂、有特殊要求或者受自然环境限制，只有少量潜在投标人可供选择；（2）采用公开招标方式的费用占项目合同金额的比例过大。有下列情形之一的，可以不进行招标：（1）采用不可替代的专利或者专有技术；采购人依法能够自行建设、生产或者提供；（2）已招标选定的特许经营项目投资人依法能够自行建设、生产或者提供；（3）需向原中标人采购，否则将影响施工或者功能配套要求；（4）其他。选项B、C、D属于不进行招标的项目。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0172", "date": "2026-07-09", "chapter": "g01", "type": "multiple", "stem": "《招标投标法》规定，在中华人民共和国境内，必须进行招标的工程建设项目包括（ ）。", "options": {"A": "大型基础设施、公用事业等关系到社会公共利益、公共安全的项目", "B": "全部或者部分使用国家资金投资或者国家融资的项目", "C": "建设项目的勘察、设计，采用特定专利或者专有技术的项目", "D": "建筑艺术造型有特殊要求的项目", "E": "使用国际组织或者外国政府贷款、援助资金的项目"}, "answer": ["A", "B", "E"], "analysis": "【内容考查】本题考查的是《招标投标法》相关内容 【选项分析】必须进行招标的项目包括： （1）大型基础设施、公用事业等关系社会公共利益、公众安全的项目。 （2）全部或者部分使用国有资金投资或者国家融资的项目。 （3）使用国际组织或者外国政府贷款、援助资金的项目。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0313", "date": "2026-07-09", "chapter": "g01", "type": "multiple", "stem": "根据《中华人民共和国招投标法》，招标方式分为（ ）。", "options": {"A": "公开招标", "B": "邀请招标", "C": "议标", "D": "谈判招标", "E": "磋商招标"}, "answer": ["A", "B"], "analysis": "【考点来源】本题考查的是招标方式 【选项分析】根据《招标投标法》明确规定，招标分为公开招标和邀请招标两种方式。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "gl-g02-001", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "工程项目组成按性质可分为四级，从大到小的正确顺序是（ ）。", "options": {"A": "单项工程->单位工程->分部工程->分项工程", "B": "单位工程->单项工程->分部工程->分项工程", "C": "单项工程->分部工程->单位工程->分项工程", "D": "单位工程->分部工程->单项工程->分项工程"}, "answer": ["A"], "analysis": "工程项目的组成按照由大到小的顺序分为四级：单项工程->单位工程->分部工程->分项工程。单项工程是具有独立的设计文件、可以独立组织施工、建成后能独立发挥生产能力的工程；单位工程是单项工程的组成部分；分部工程是单位工程的组成部分；分项工程是分部工程的组成部分，也是工程计量计价的基本单元。", "tags": ["工程项目组成"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-002", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "在工程项目组成中，具有独立的设计文件、可以独立组织施工、建成后能够独立发挥生产能力或效益的工程称为（ ）。", "options": {"A": "建设项目", "B": "单项工程", "C": "单位工程", "D": "分部工程"}, "answer": ["B"], "analysis": "单项工程是建设项目的组成部分，具有独立的设计文件，竣工后可以独立发挥生产能力或效益。例如一个工厂中的各个车间、办公楼、宿舍等，都是单项工程。单位工程一般不具备独立发挥生产能力的条件，分部工程和分项工程更不具备。", "tags": ["工程项目组成", "单项工程"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-003", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "某教学楼的土建工程、电气照明工程、给排水工程等分别属于不同的（ ）。", "options": {"A": "单项工程", "B": "单位工程", "C": "分部工程", "D": "分项工程"}, "answer": ["B"], "analysis": "单位工程是单项工程的组成部分，一般是指具有独立的设计文件和独立的施工条件，但建成后不能独立发挥生产能力或使用效益的工程。一栋教学楼是一个单项工程，其中的土建、电气照明、给排水等分别是该单项工程下的单位工程。", "tags": ["工程项目组成", "单位工程"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-004", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "在工程计量和计价活动中，（ ）是基本构造要素，也是计量计价的基本单元。", "options": {"A": "单项工程", "B": "单位工程", "C": "分部工程", "D": "分项工程"}, "answer": ["D"], "analysis": "分项工程是分部工程的组成部分，也是工程计量计价的基本单元。分项工程是施工图预算和工程量清单计价中最基本的计算单位，如砖基础、现浇混凝土梁等。它是造价管理中进行工程量计算和造价确定的最小载体。", "tags": ["工程项目组成", "分项工程"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-007", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "在项目建设程序的决策阶段，编制的造价文件是（ ）。", "options": {"A": "设计概算", "B": "投资估算", "C": "施工图预算", "D": "竣工决算"}, "answer": ["B"], "analysis": "建设程序各阶段对应不同的造价文件：决策阶段编制投资估算（包括项目建议书和可行性研究阶段的估算）；设计阶段编制设计概算和施工图预算；招投标阶段确定合同价；施工阶段进行结算；竣工阶段编制竣工决算。投资估算是决策阶段对工程投资的框架性估算。", "tags": ["建设程序", "造价文件"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-008", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "在设计阶段，初步设计完成后编制的工程投资经济文件称为（ ）。", "options": {"A": "投资估算", "B": "设计概算", "C": "施工图预算", "D": "工程结算"}, "answer": ["B"], "analysis": "初步设计阶段编制设计概算。设计概算是在初步设计或扩大初步设计阶段，由设计单位根据初步设计图纸、概算定额等资料编制的确定工程投资的经济文件。它的精度高于投资估算，是控制工程投资的依据。施工图预算是在施工图设计完成后编制的。", "tags": ["建设程序", "设计概算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-009", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "根据“逐步深化、逐步接近实际造价”的原则，工程多次计价过程中各造价文件的关系，下列说法正确的是（ ）。", "options": {"A": "正常情况下，投资估算>设计概算>施工图预算>合同价", "B": "每一阶段造价文件是后一阶段造价的控制目标", "C": "竣工决算是最初的投资计划", "D": "各造价文件之间没有约束关系"}, "answer": ["A"], "analysis": "在多次计价体系中，各阶段的造价文件遵循由粗到细、逐步深化、逐步接近实际造价的原则。正常情况下应满足：投资估算>设计概算>修正概算>施工图预算>合同价>结算价，且前一阶段造价值是后一阶段造价的控制目标（即后一阶段的造价不应超过前一阶段）。竣工决算是实际造价的最终反映。", "tags": ["建设程序", "多次计价"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-011", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "在招投标阶段，发包人与承包人签订合同时确定的工程价格称为（ ）。", "options": {"A": "设计概算", "B": "施工图预算", "C": "合同价", "D": "结算价"}, "answer": ["C"], "analysis": "招投标阶段确定合同价，即发包人与承包人在签订工程承包合同时确定的工程价格。合同价是双方在施工过程中进行工程价款结算的基础，也是工程款支付的依据。结算价是施工阶段按合同约定调整和确定的价格，竣工决算是最终实际造价。", "tags": ["建设程序", "合同价"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-012", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "工程项目建设程序中，竣工阶段编制的反映工程项目实际造价和投资效果的文件是（ ）。", "options": {"A": "施工图预算", "B": "工程结算", "C": "竣工决算", "D": "投资估算"}, "answer": ["C"], "analysis": "竣工决算是在竣工验收阶段，由建设单位编制的反映工程项目实际造价和投资效果的文件，是核定新增固定资产价值、办理交付使用、考核建设成果的依据。它综合反映了从项目筹建到竣工投产全过程各项资金的实际使用情况。", "tags": ["建设程序", "竣工决算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-013", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "工程项目管理的三大目标是指（ ）。", "options": {"A": "成本、工期、安全", "B": "质量、进度、投资", "C": "质量、安全、环保", "D": "安全、质量、成本"}, "answer": ["B"], "analysis": "工程项目管理的三大基本目标是质量目标、进度目标和投资目标。三者之间存在着对立统一的关系：在保证质量的前提下，加快进度会增加投资；但合理的进度安排又可能节约投资。项目管理的核心就是在三大目标之间寻求最优平衡点。", "tags": ["管理三目标"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-014", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "关于工程项目质量、进度、投资三大目标之间的关系，下列说法正确的是（ ）。", "options": {"A": "三大目标之间是相互独立的", "B": "加快进度一定会降低投资", "C": "提高质量标准通常会引起投资的增加", "D": "三大目标之间只有对立关系没有统一关系"}, "answer": ["C"], "analysis": "三大目标之间是对立统一的关系。提高质量标准通常需要更优质的材料、更严格的施工工艺，从而导致投资增加。加快进度可能需要增加人力和机械投入，也会增加投资。但合理的进度安排可以减少管理费用从而节约投资，这体现了统一的一面。对立统一是三大目标关系的本质特征。", "tags": ["管理三目标", "目标关系"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-015", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "在工程项目管理目标体系中，进度目标是指（ ）。", "options": {"A": "工程项目交付使用的期限", "B": "工程项目的投资控制目标", "C": "工程项目的设计标准", "D": "工程项目的安全标准"}, "answer": ["A"], "analysis": "进度目标是工程项目管理三大目标之一，是指工程项目的建设期限或交付使用的期限目标，包括总工期目标和各阶段里程碑进度目标。进度控制的目的是在合理工期内以最优的速度完成工程建设。", "tags": ["管理三目标", "进度目标"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-017", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "工程项目建设过程中，为确保参加建设各方协调一致地工作而进行的组织协调工作，属于工程项目管理七大任务中的（ ）。", "options": {"A": "合同管理", "B": "信息管理", "C": "组织管理", "D": "风险管理"}, "answer": ["C"], "analysis": "组织管理（组织协调）是工程项目管理七大任务之一，旨在对参与工程建设的各单位、各部门及个人之间的关系进行协调，保证工程建设各方协调一致地工作，实现工程建设目标。合同管理侧重于合同的签订和履约管理，风险管理侧重于不确定性的识别和应对。", "tags": ["管理任务", "组织协调"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-018", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "“安全第一、预防为主、综合治理”是工程项目管理中（ ）的基本方针。", "options": {"A": "质量管理", "B": "进度管理", "C": "安全管理", "D": "合同管理"}, "answer": ["C"], "analysis": "“安全第一、预防为主、综合治理”是工程项目安全管理的十二字方针。安全管理是工程项目管理七大任务之一，要求施工单位建立安全生产责任制度，加强安全生产教育培训，消除事故隐患，防止和减少生产安全事故的发生。", "tags": ["管理任务", "安全管理"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-020", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "BOT模式是指（ ）。", "options": {"A": "设计-施工总承包", "B": "建设-经营-移交", "C": "设计-招标-建造", "D": "公共私营合作制"}, "answer": ["B"], "analysis": "BOT（Build-Operate-Transfer）即“建设-经营-移交”模式。由项目公司负责融资、建设基础设施项目，并在特许经营期内运营该项目以收回投资和获取收益，特许期满后将项目无偿移交给政府。适用于大型基础设施项目。", "tags": ["实施模式", "BOT"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-021", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "在EPC总承包模式下，承担最大风险的参与方是（ ）。", "options": {"A": "建设单位（业主）", "B": "监理单位", "C": "总承包商", "D": "设计单位"}, "answer": ["C"], "analysis": "EPC（Engineering-Procurement-Construction）即设计-采购-施工总承包模式。在EPC模式下，总承包商承担了工程设计、采购、施工的全部责任和风险，包括设计变更风险、施工条件变化风险等，是各种承包模式中承包方风险最大的模式。业主只需提出功能要求，总承包商负责具体实施。", "tags": ["实施模式", "EPC"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-022", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "DBB模式即设计-招标-建造模式，其最突出的特点是（ ）。", "options": {"A": "设计与施工一体化", "B": "设计方案与施工分离，按顺序依次进行", "C": "由承包商承担全部风险", "D": "设计与施工同步进行以缩短工期"}, "answer": ["B"], "analysis": "DBB（Design-Bid-Build）即设计-招标-建造模式，是传统的工程项目发包模式。其核心特点是将设计、招标和施工三个阶段严格分离，按照设计->招标->建造的顺序依次进行，前一阶段完成后才能进入后一阶段。这种模式优点是管理关系清晰，缺点是建设周期较长。", "tags": ["实施模式", "DBB"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-024", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "全过程工程咨询是指对工程建设项目全生命周期提供（ ）的工程咨询服务。", "options": {"A": "包含设计和施工在内的", "B": "包含规划和设计在内的", "C": "包含规划、设计、监理、造价、项目管理等在内的", "D": "仅限于造价咨询的"}, "answer": ["C"], "analysis": "全过程工程咨询是对工程建设项目全生命周期提供包含规划、设计、监理、造价、项目管理等在内的综合性、跨阶段、一体化的工程咨询服务。其核心是整合工程咨询产业链，提供“一站式”服务，提升投资效益和工程质量。这是2025年教材新增的重点内容。", "tags": ["实施模式", "全过程工程咨询"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-025", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "PPP模式是指政府公共部门与私营部门合作提供公共产品或服务的一种模式，其核心特征是（ ）。", "options": {"A": "政府全额出资", "B": "私营部门全额出资", "C": "政府与私营部门之间形成伙伴关系，利益共享、风险共担", "D": "项目建成后直接归政府所有"}, "answer": ["C"], "analysis": "PPP（Public-Private Partnership）即公共私营合作制，是政府与私营部门为提供公共产品或服务而建立的一种长期合作关系。其核心特征是双方形成合作伙伴关系，共同分担风险、分享利益，实现共赢。BOT是PPP的一种具体实现形式。", "tags": ["实施模式", "PPP"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-026", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "TOT模式即移交-经营-移交，与BOT模式的主要区别在于TOT模式（ ）。", "options": {"A": "不涉及项目建设，是对已建成项目经营权的转让", "B": "政府不参与项目管理", "C": "不需要私营部门投资", "D": "经营期满后不移交政府"}, "answer": ["A"], "analysis": "TOT（Transfer-Operate-Transfer）即“移交-经营-移交”。与BOT需要新建项目不同，TOT是指政府部门将已建成的项目移交给私营部门进行经营，私营部门在经营期内收回投资并获得回报后，再将项目移交回政府。TOT的核心是不涉及新建，仅涉及已建成设施的经营权转让。", "tags": ["实施模式", "TOT"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-027", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "PFI模式即私人融资计划，与BOT模式相比，PFI模式的特点是（ ）。", "options": {"A": "私营部门建设完成后即移交政府", "B": "更强调私营部门提供公共服务而非单纯建设设施", "C": "政府承担全部融资责任", "D": "不需要私营部门参与运营"}, "answer": ["B"], "analysis": "PFI（Private Finance Initiative）即私人融资计划。与BOT模式强调“建设-运营-移交”不同，PFI更强调私营部门提供公共服务，政府向私营部门购买服务而不是购买设施。私营部门不仅负责设施的建设，更注重在运营期持续提供高质量的公共服务。", "tags": ["实施模式", "PFI"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-029", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "关于DBB模式（设计-招标-建造）的实施顺序，下列说法正确的是（ ）。", "options": {"A": "先施工，再设计，最后招标", "B": "先设计，再招标，最后施工", "C": "设计、招标、施工同步进行", "D": "先招标，再设计，最后施工"}, "answer": ["B"], "analysis": "DBB模式的实施顺序是：先由设计单位完成施工图设计，然后建设单位通过招标选择施工单位，最后由中标施工单位按照设计图纸组织施工。这种“先设计->再招标->后施工”的线性顺序是传统建设模式的标准流程，管理关系清晰但建设周期较长。", "tags": ["实施模式", "DBB"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-031", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "EPC总承包模式下，合同价格通常采用（ ）形式，便于投资控制。", "options": {"A": "成本加酬金合同", "B": "单价合同", "C": "固定总价合同", "D": "可调总价合同"}, "answer": ["C"], "analysis": "EPC模式下，由于总承包商承担了大部分风险（设计变更、地质条件变化等），合同通常采用固定总价合同。固定总价有利于业主进行投资控制，将投资风险转移给总承包商。这对总承包商的综合能力提出了很高要求，需要在投标阶段充分评估风险。", "tags": ["实施模式", "EPC"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-033", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "工程建设程序中，可行性研究阶段的投资估算是（ ）。", "options": {"A": "项目决策和审批的依据之一", "B": "签订施工合同的依据", "C": "工程结算的依据", "D": "竣工验收的依据"}, "answer": ["A"], "analysis": "可行性研究阶段的投资估算是项目主管部门审批项目建议书和可行性研究报告的依据之一，也是投资决策阶段重要的经济评价指标。它对项目是否可行具有决定性作用，而合同价、结算价和竣工决算分别对应后续阶段的不同用途。", "tags": ["建设程序", "投资估算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-034", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "下列不属于分部工程的是（ ）。", "options": {"A": "地基与基础工程", "B": "主体结构工程", "C": "建筑装饰装修工程", "D": "现浇混凝土梁"}, "answer": ["D"], "analysis": "分部工程是按单位工程的各个部位或工种划分的，如地基与基础、主体结构、建筑装饰装修、建筑屋面、建筑给排水及供暖等。“现浇混凝土梁”属于分项工程，是分部工程（如混凝土结构）下的基本组成单元，是计量计价的最小计算单位。", "tags": ["工程项目组成", "分部工程"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-036", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "工程项目管理七大任务中，（ ）贯穿于项目全过程，是项目管理最核心的基础工作。", "options": {"A": "合同管理", "B": "安全管理", "C": "风险管理", "D": "信息管理"}, "answer": ["A"], "analysis": "合同管理贯穿于项目管理的全过程，是工程项目管理的核心。工程建设中的质量、进度、投资三大控制，以及设计、施工、监理等各参建方之间的协作关系，最终都通过合同条款来约定和约束。合同管理是其他各项管理任务的基础和核心纽带。", "tags": ["管理任务", "合同管理"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-037", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "在工程项目风险管理的程序中，首要步骤是（ ）。", "options": {"A": "风险应对", "B": "风险监控", "C": "风险识别", "D": "风险评价"}, "answer": ["C"], "analysis": "工程项目风险管理的基本程序包括：风险识别->风险评价->风险应对->风险监控。风险识别是风险管理的首要步骤和基础，只有正确识别出项目面临的风险因素，才能进行后续的评价和应对工作。风险识别需要系统全面地分析项目的各个方面。", "tags": ["管理任务", "风险管理"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-039", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "在工程项目管理中进行信息管理的核心目的是（ ）。", "options": {"A": "为各参建方提供沟通和决策的基础", "B": "减少工程投入", "C": "替代合同管理", "D": "只服务于建设单位"}, "answer": ["A"], "analysis": "信息管理是工程项目管理七大任务之一，其核心目的是通过对项目信息的收集、处理、存储和传递，为各参建方提供有效的沟通渠道和决策支持。准确、及时的信息是做好其他各项管理任务（合同管理、目标控制、风险管理等）的基础保障。", "tags": ["管理任务", "信息管理"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-040", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "施工图预算是在（ ）阶段编制的造价文件。", "options": {"A": "决策阶段", "B": "设计阶段", "C": "招投标阶段", "D": "施工阶段"}, "answer": ["B"], "analysis": "施工图预算是在施工图设计阶段编制的造价文件，属于设计阶段的造价管理工作。它是在施工图设计完成后，根据施工图纸、预算定额等编制的确定建筑安装工程预算造价的文件，是招投标阶段确定合同价的重要依据。", "tags": ["建设程序", "施工图预算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-041", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "BOT模式中，特许经营期满后，项目公司将项目设施（ ）。", "options": {"A": "以市场价格出售给政府", "B": "无偿移交给政府", "C": "继续由项目公司经营", "D": "公开拍卖"}, "answer": ["B"], "analysis": "BOT模式的核心特征之一是特许经营期满后，项目公司将项目设施无偿移交给政府。这是BOT模式与普通商业投资项目的本质区别。政府授予特许经营权作为对价，项目公司通过经营期内的收益回收投资和获取利润。", "tags": ["实施模式", "BOT"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-042", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "在建设工程项目管理中，“三管理”是指（ ）。", "options": {"A": "质量管理、进度管理、投资管理", "B": "合同管理、信息管理、安全管理", "C": "质量管理、安全管理、环保管理", "D": "合同管理、风险管理、信息管理"}, "answer": ["A"], "analysis": "建设工程项目管理的“三管理”通常指质量管理、进度管理和投资管理，这与“三大控制目标”相对应。合同管理、信息管理和安全管理是项目管理七大任务中的其他任务。注意区分“三控制”与“七任务”的层次关系。", "tags": ["管理三目标"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-045", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "在工程项目设计阶段，如果采用三阶段设计，则依次是（ ）。", "options": {"A": "初步设计->施工图设计->技术设计", "B": "初步设计->技术设计->施工图设计", "C": "方案设计->初步设计->施工图设计", "D": "技术设计->初步设计->施工图设计"}, "answer": ["B"], "analysis": "对于技术复杂且缺乏经验的工程项目，设计阶段可采用三阶段设计，依次为：初步设计->技术设计->施工图设计。普通工程通常采用两阶段设计：初步设计->施工图设计。三个阶段分别对应编制设计概算、修正概算和施工图预算。", "tags": ["建设程序", "设计阶段"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-046", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "工程结算是指在（ ）阶段，根据合同约定对实际发生的工程价款进行的计算和调整。", "options": {"A": "决策", "B": "设计", "C": "施工", "D": "竣工"}, "answer": ["C"], "analysis": "工程结算是在施工阶段进行的，由施工单位根据施工合同、施工过程中发生的设计变更、现场签证等，向建设单位办理的工程价款计算文件。它是施工单位实现工程收入、建设单位支付工程款的依据。竣工决算是在竣工阶段由建设单位编制的。", "tags": ["建设程序", "工程结算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-047", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "在工程项目管理中对可能发生的风险进行识别、评估并制定应对措施，属于七大任务中的（ ）。", "options": {"A": "合同管理", "B": "安全管理", "C": "风险管理", "D": "信息管理"}, "answer": ["C"], "analysis": "风险管理是工程项目管理七大任务之一，包括风险识别、风险评价、风险应对和风险监控的全过程。工程项目具有一次性、周期长、不确定性大等特点，风险管理的目的是防范和减少风险发生对项目造成的不利影响。", "tags": ["管理任务", "风险管理"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-001", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "工程项目的四级分解体系中，从大到小正确的排列顺序是（ ）。", "options": {"A": "单位工程→单项工程→分部工程→分项工程", "B": "单项工程→单位工程→分部工程→分项工程", "C": "单项工程→分部工程→单位工程→分项工程", "D": "单位工程→分部工程→分项工程→单项工程"}, "answer": ["B"], "analysis": "工程项目按四级分解：单项工程→单位工程→分部工程→分项工程。单项工程是最高层级，有独立设计文件，可独立发挥生产能力；分项工程是最基本的组成单元。", "tags": ["工程项目组成", "四级分解"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-002", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "在工程项目中，具有独立设计文件、建成后可以独立发挥生产能力或效益的工程是（ ）。", "options": {"A": "单位工程", "B": "分部工程", "C": "单项工程", "D": "分项工程"}, "answer": ["C"], "analysis": "单项工程是指具有独立的设计文件，建成后可以独立发挥生产能力或效益的工程。如一个工厂中的生产车间、办公楼、仓库等。", "tags": ["工程项目组成", "单项工程"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-003", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "具有独立施工条件，但不能独立发挥生产能力或效益的工程属于（ ）。", "options": {"A": "单项工程", "B": "单位工程", "C": "分部工程", "D": "分项工程"}, "answer": ["B"], "analysis": "单位工程是单项工程的组成部分，具有独立施工条件，但不能独立发挥生产能力或效益。如车间中的土建工程、电气安装工程、给排水工程等各为一个单位工程。", "tags": ["工程项目组成", "单位工程"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-004", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "下列属于单位工程的是（ ）。", "options": {"A": "地基基础工程", "B": "土建工程", "C": "钢筋工程", "D": "模板工程"}, "answer": ["B"], "analysis": "土建工程属于单位工程。地基基础工程属于分部工程，钢筋工程和模板工程属于分项工程。", "tags": ["工程项目组成", "单位工程"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-005", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "按专业性质或工程部位划分的工程是（ ）。", "options": {"A": "单项工程", "B": "单位工程", "C": "分部工程", "D": "分项工程"}, "answer": ["C"], "analysis": "分部工程按专业性质或工程部位划分。如地基与基础工程、主体结构工程、装饰装修工程、屋面工程等。", "tags": ["工程项目组成", "分部工程"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-006", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "下列属于分部工程的是（ ）。", "options": {"A": "土建工程", "B": "电气安装工程", "C": "主体结构工程", "D": "办公楼"}, "answer": ["C"], "analysis": "主体结构工程属于分部工程。土建工程和电气安装工程属于单位工程，办公楼属于单项工程。", "tags": ["工程项目组成", "分部工程"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-007", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "按施工工艺、材料、设备类别划分的工程是（ ）。", "options": {"A": "分部工程", "B": "分项工程", "C": "单位工程", "D": "单项工程"}, "answer": ["B"], "analysis": "分项工程按施工工艺、材料、设备类别划分，是工程项目最基本的组成单元。", "tags": ["工程项目组成", "分项工程"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-008", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "下列属于分项工程的是（ ）。", "options": {"A": "地基基础工程", "B": "主体结构工程", "C": "混凝土工程", "D": "屋面工程"}, "answer": ["C"], "analysis": "混凝土工程按施工工艺划分属于分项工程。地基基础工程、主体结构工程、屋面工程属于分部工程。", "tags": ["工程项目组成", "分项工程"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-009", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "工程项目按建设性质分类，不包含（ ）。", "options": {"A": "新建项目", "B": "扩建项目", "C": "生产性项目", "D": "改建项目"}, "answer": ["C"], "analysis": "按建设性质分为：新建、扩建、改建、迁建、恢复项目。生产性/非生产性是按投资作用分类。", "tags": ["工程项目分类", "建设性质"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-010", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "工程项目按投资作用可分为（ ）。", "options": {"A": "大型、中型、小型", "B": "新建、扩建、改建", "C": "生产性、非生产性", "D": "工业、民用、基础设施"}, "answer": ["C"], "analysis": "按投资作用分为生产性建设项目和非生产性建设项目。A是按规模分类，B是按建设性质分类。", "tags": ["工程项目分类", "投资作用"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-011", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "工程项目按规模划分的依据是（ ）。", "options": {"A": "建设性质", "B": "总投资或设计生产能力", "C": "投资作用", "D": "建设地点"}, "answer": ["B"], "analysis": "工程项目按规模分为大型、中型、小型，划分依据是总投资额或设计生产能力。", "tags": ["工程项目分类", "规模划分"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-012", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "建设程序中，项目建议书阶段属于（ ）。", "options": {"A": "设计阶段", "B": "决策阶段", "C": "施工阶段", "D": "竣工阶段"}, "answer": ["B"], "analysis": "决策阶段包括：项目建议书→可行性研究→项目评估→决策审批。", "tags": ["建设程序", "决策阶段"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-013", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "可行性研究的主要内容是（ ）。", "options": {"A": "投资机会研究", "B": "技术经济论证", "C": "施工图审查", "D": "招标方案编制"}, "answer": ["B"], "analysis": "可行性研究是对项目进行全面的技术经济论证，是决策阶段的核心工作。项目建议书阶段进行投资机会研究。", "tags": ["建设程序", "可行性研究"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-014", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "一般情况下，工程项目的设计阶段采用（ ）。", "options": {"A": "一阶段设计", "B": "两阶段设计", "C": "三阶段设计", "D": "四阶段设计"}, "answer": ["B"], "analysis": "一般项目采用两阶段设计：初步设计→施工图设计。技术复杂的项目采用三阶段设计。", "tags": ["建设程序", "设计阶段"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-015", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "对于技术复杂且缺乏经验的项目，应采用（ ）。", "options": {"A": "一阶段设计", "B": "两阶段设计", "C": "三阶段设计", "D": "只做方案设计"}, "answer": ["C"], "analysis": "三阶段设计：初步设计→技术设计→施工图设计，适用于技术复杂且缺乏经验的项目。", "tags": ["建设程序", "设计阶段"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-016", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "建设准备阶段中“三通一平”指的是（ ）。", "options": {"A": "通水、通电、通气、场地平整", "B": "通水、通电、通路、场地平整", "C": "通水、通电、通暖、场地平整", "D": "通讯、通电、通路、场地平整"}, "answer": ["B"], "analysis": "三通一平指通水、通电、通路和场地平整，是建设准备阶段的重要工作。", "tags": ["建设程序", "建设准备"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-017", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "竣工阶段对应的造价文件是（ ）。", "options": {"A": "预算", "B": "结算", "C": "决算", "D": "概算"}, "answer": ["C"], "analysis": "各阶段对应造价文件：决策→估算，初设→概算，施工图→预算，招投标→合同价，施工→结算，竣工→决算。", "tags": ["建设程序", "造价文件"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-018", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "投资估算是在（ ）阶段编制的造价文件。", "options": {"A": "初步设计", "B": "施工图设计", "C": "决策", "D": "竣工"}, "answer": ["C"], "analysis": "决策阶段编制投资估算。估算→概算→预算→合同价→结算→决算对应建设程序的推进。", "tags": ["建设程序", "造价文件"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-019", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "下列造价文件中，编制时间最早的是（ ）。", "options": {"A": "设计概算", "B": "施工图预算", "C": "投资估算", "D": "合同价"}, "answer": ["C"], "analysis": "按时间顺序：投资估算（决策）→设计概算（初设）→施工图预算→合同价（招投标）→结算→决算。", "tags": ["建设程序", "造价文件"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-020", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "初步设计阶段编制的造价文件是（ ）。", "options": {"A": "投资估算", "B": "设计概算", "C": "施工图预算", "D": "竣工决算"}, "answer": ["B"], "analysis": "初步设计阶段编制设计概算，是初步设计文件的重要组成部分。", "tags": ["建设程序", "造价文件"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-021", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "施工阶段对应形成的造价文件是（ ）。", "options": {"A": "合同价", "B": "预算", "C": "结算", "D": "决算"}, "answer": ["C"], "analysis": "施工过程中及完工后，承包人向发包人提交的已完成工程量价款文件为结算。", "tags": ["建设程序", "造价文件"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-023", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "关于三大目标的关系，下列说法正确的是（ ）。", "options": {"A": "只有对立关系", "B": "完全独立", "C": "对立统一的关系", "D": "质量好则进度和投资自然保证"}, "answer": ["C"], "analysis": "质量、进度、投资三大目标之间是对立统一的关系。对立表现在相互制约，统一表现在可通过科学管理实现多目标平衡。", "tags": ["工程项目管理", "三大目标"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-025", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "项目法人责任制主要适用于（ ）。", "options": {"A": "所有工程项目", "B": "经营性项目", "C": "非经营性项目", "D": "公益性项目"}, "answer": ["B"], "analysis": "项目法人责任制主要适用于经营性基本建设项目，需明确投资主体和责任主体。", "tags": ["工程项目管理", "项目法人责任制"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-026", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "项目资本金制度中，不同行业的资本金最低比例（ ）。", "options": {"A": "统一为20%", "B": "统一为30%", "C": "各行业比例不同", "D": "由发改委统一决定"}, "answer": ["C"], "analysis": "不同行业资本金最低比例不同，如钢铁40%、水泥35%、港口25%等。", "tags": ["工程项目管理", "资本金制度"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-027", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "全过程工程咨询覆盖的阶段不包括（ ）。", "options": {"A": "投资决策阶段", "B": "建设实施阶段", "C": "运营维护阶段", "D": "三个阶段均覆盖"}, "answer": ["D"], "analysis": "全过程工程咨询覆盖投资决策、建设实施、运营维护三个阶段，是全生命周期的服务。", "tags": ["全过程工程咨询", "覆盖阶段"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-030", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "BOT融资模式中，“B”代表的含义是（ ）。", "options": {"A": "建造（Build）", "B": "购买（Buy）", "C": "预算（Budget）", "D": "投标（Bid）"}, "answer": ["A"], "analysis": "BOT = Build（建设）- Operate（经营）- Transfer（移交），特许经营期满后无偿移交政府。", "tags": ["项目融资模式", "BOT"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-031", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "BOT模式中，特许经营期满后项目资产应（ ）。", "options": {"A": "由项目公司继续经营", "B": "按市场价出售给政府", "C": "无偿移交给政府", "D": "由社会资本方自行处置"}, "answer": ["C"], "analysis": "BOT模式核心特征：特许经营期满后项目资产无偿移交政府。", "tags": ["项目融资模式", "BOT"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-032", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "TOT模式与BOT模式的主要区别在于（ ）。", "options": {"A": "融资主体不同", "B": "TOT涉及存量资产转让，BOT是新建项目", "C": "特许经营期限不同", "D": "政府参与程度不同"}, "answer": ["B"], "analysis": "TOT针对存量资产移交-经营-移交，BOT针对新建项目建设-经营-移交。核心区别在于TOT涉及存量资产转让。", "tags": ["项目融资模式", "TOT"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-033", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "PFI模式中，政府向社会资本（ ）。", "options": {"A": "出售资产", "B": "购买服务", "C": "转让股权", "D": "提供补贴"}, "answer": ["B"], "analysis": "PFI（私人融资）模式核心是政府购买服务，社会资本负责融资、建设和运营。", "tags": ["项目融资模式", "PFI"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-034", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "PPP模式的核心特征是（ ）。", "options": {"A": "政府全额出资", "B": "社会资本独立运作", "C": "利益共享、风险分担", "D": "政府全部承担风险"}, "answer": ["C"], "analysis": "PPP（政府与社会资本合作）模式核心特征：利益共享、风险分担。", "tags": ["项目融资模式", "PPP"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-036", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "EPC总承包模式中，EPC分别代表（ ）。", "options": {"A": "工程-采购-施工", "B": "设计-采购-施工", "C": "评估-规划-控制", "D": "设计-生产-施工"}, "answer": ["B"], "analysis": "EPC = Engineering（设计）- Procurement（采购）- Construction（施工），承包商负责全过程。", "tags": ["承发包模式", "EPC"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-037", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "EPC总承包模式最适合的项目类型是（ ）。", "options": {"A": "以土建为主的民用建筑", "B": "工艺性强、设备占比高的项目", "C": "简单装饰装修项目", "D": "小型市政道路项目"}, "answer": ["B"], "analysis": "EPC适合工艺性强、设备占比高的工业项目，如化工、冶金、电力等，能实现设计施工深度整合。", "tags": ["承发包模式", "EPC"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-038", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "EPC总承包合同通常采用的价格形式是（ ）。", "options": {"A": "成本加酬金", "B": "可调单价", "C": "固定总价", "D": "工时材料"}, "answer": ["C"], "analysis": "EPC合同通常采用固定总价，承包商承担绝大部分风险。", "tags": ["承发包模式", "EPC"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-039", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "关于EPC总承包模式中的风险分配，下列说法正确的是（ ）。", "options": {"A": "业主承担绝大部分风险", "B": "承包商承担绝大部分风险", "C": "双方平均分担风险", "D": "保险公司承担全部风险"}, "answer": ["B"], "analysis": "EPC模式下承包商承担绝大部分风险，包括设计、采购、施工和价格风险。", "tags": ["承发包模式", "EPC"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-040", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "DBB模式的实施顺序是（ ）。", "options": {"A": "设计→招标→建造，线性顺序进行", "B": "设计建造同步进行", "C": "先建造后设计", "D": "边设计边施工"}, "answer": ["A"], "analysis": "DBB（设计-招标-建造）线性顺序进行：先设计→再招标→最后施工。", "tags": ["承发包模式", "DBB"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-041", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "DBB模式中，业主面临的主要挑战是（ ）。", "options": {"A": "设计质量难以保证", "B": "协调工作量大", "C": "工程造价难以控制", "D": "施工质量难以保证"}, "answer": ["B"], "analysis": "DBB模式下设计施工分离，业主需分别协调设计和施工单位，协调工作量大。", "tags": ["承发包模式", "DBB"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-042", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "CM模式的最大优势是（ ）。", "options": {"A": "建设成本最低", "B": "边设计边施工，缩短工期", "C": "业主管理最简单", "D": "风险全部由承包商承担"}, "answer": ["B"], "analysis": "CM模式采用Fast-Track方式，边设计边施工，可有效缩短建设工期。", "tags": ["承发包模式", "CM"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-043", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "代理型CM与风险型CM的主要区别在于（ ）。", "options": {"A": "服务范围不同", "B": "是否承担施工风险和经济责任", "C": "收费方式不同", "D": "管理复杂度不同"}, "answer": ["B"], "analysis": "代理型CM不承担施工风险，风险型CM对最大费用负责（GMP担保），承担施工风险。", "tags": ["承发包模式", "CM"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-044", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "PMC模式中，PMC单位代表（ ）。", "options": {"A": "施工单位管理项目", "B": "设计单位管理项目", "C": "业主管理全部项目", "D": "监理单位履行监督职责"}, "answer": ["C"], "analysis": "PMC（项目管理承包）代表业主管理全部项目，业主保留决策权，PMC负责执行。", "tags": ["承发包模式", "PMC"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-045", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "平行发包模式中，各专业工程的发包由（ ）进行。", "options": {"A": "总承包商统一发包", "B": "业主分别发包给不同承包单位", "C": "PMC单位负责发包", "D": "设计单位代为发包"}, "answer": ["B"], "analysis": "平行发包中业主将各专业工程分别直接发包，业主需协调多个承包商。", "tags": ["承发包模式", "平行发包"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-046", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "在平行发包模式下，业主面临的最大挑战是（ ）。", "options": {"A": "工程成本过高", "B": "协调工作量巨大", "C": "设计质量难以控制", "D": "工期无法保证"}, "answer": ["B"], "analysis": "平行发包模式下业主需同时管理多个承包商，协调工作量巨大。", "tags": ["承发包模式", "平行发包"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-047", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "下列承发包模式中，承包商承担风险最大的是（ ）。", "options": {"A": "DBB", "B": "CM代理型", "C": "EPC", "D": "PMC"}, "answer": ["C"], "analysis": "EPC总承包模式承包商承担绝大部分风险，采用固定总价合同，风险最大。", "tags": ["承发包模式", "风险对比"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-048", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "工业项目中工艺设备占比超60%，最适宜采用的承发包模式是（ ）。", "options": {"A": "DBB", "B": "EPC", "C": "平行发包", "D": "CM代理型"}, "answer": ["B"], "analysis": "EPC最适合工艺性强、设备占比高的工业项目，能实现设计采购施工一体化管理。", "tags": ["承发包模式", "模式选择"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-051", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "将设计概算控制在投资估算范围内的阶段是（ ）。", "options": {"A": "初步设计", "B": "施工图设计", "C": "技术设计", "D": "竣工阶段"}, "answer": ["A"], "analysis": "初步设计阶段编制的概算应控制在估算范围内。概算不超估算、预算不超概算。", "tags": ["建设程序", "造价控制"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-052", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "关于项目后评价，下列说法正确的是（ ）。", "options": {"A": "后评价在施工过程中进行", "B": "后评价在竣工阶段进行", "C": "后评价在项目投入运营后一段时间进行", "D": "后评价在决策阶段进行"}, "answer": ["C"], "analysis": "后评价在项目投产或使用后一段时间进行，总结经验教训，为以后类似项目提供参考。", "tags": ["建设程序", "后评价"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-053", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "单项工程与单位工程的主要区别在于（ ）。", "options": {"A": "工程规模大小", "B": "是否具有独立设计文件和独立发挥效益的能力", "C": "施工难度", "D": "投资额大小"}, "answer": ["B"], "analysis": "单项工程有独立设计文件且可独立发挥效益，单位工程虽有独立施工条件但不能独立发挥效益。", "tags": ["工程项目组成", "单项vs单位"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-054", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "分部工程与分项工程划分依据的主要区别是（ ）。", "options": {"A": "分部按工程部位/专业性质，分项按施工工艺/材料", "B": "分部按施工工艺，分项按工程部位", "C": "分部按投资额，分项按规模", "D": "分部按工期，分项按质量"}, "answer": ["A"], "analysis": "分部工程按专业性质或工程部位划分，分项工程按施工工艺、材料、设备类别划分。", "tags": ["工程项目组成", "分部vs分项"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-055", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "某工厂建设项目中，一个生产车间的全部安装工程属于（ ）。", "options": {"A": "单项工程", "B": "单位工程", "C": "分部工程", "D": "分项工程"}, "answer": ["B"], "analysis": "车间是单项工程，但其安装工程属于单位工程——有独立施工条件但不能独立发挥生产效益。", "tags": ["工程项目组成", "层级判断"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-056", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "下列工程中属于单项工程的是（ ）。", "options": {"A": "小区给排水工程", "B": "工厂办公楼", "C": "楼栋电气工程", "D": "厂房基础工程"}, "answer": ["B"], "analysis": "办公楼有独立设计文件、可独立使用，属单项工程。给排水和电气是单位工程，基础是分部工程。", "tags": ["工程项目组成", "单项工程"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-057", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "建设单位管理费中包含（ ）。", "options": {"A": "工程监理费", "B": "勘察设计费", "C": "可行性研究费", "D": "招标代理费"}, "answer": ["A"], "analysis": "建设单位管理费含工程监理费（2025版）。勘察设计费、可研费、招标代理费属工程建设其他费单列项目。", "tags": ["建设程序", "费用构成"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-059", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "施工图设计文件必须经（ ）后才能用于施工。", "options": {"A": "设计单位内部审核", "B": "建设单位审查批准", "C": "施工图审查机构审查合格", "D": "施工单位确认"}, "answer": ["C"], "analysis": "施工图设计文件须经施工图审查机构审查合格后方可用于施工，属强制性规定。", "tags": ["建设程序", "施工图审查"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-060", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "生产准备阶段的工作内容不包括（ ）。", "options": {"A": "人员培训", "B": "设备调试", "C": "原材料准备", "D": "征地拆迁"}, "answer": ["D"], "analysis": "征地拆迁属建设准备阶段。生产准备阶段包括人员培训、设备调试、原材料准备等。", "tags": ["建设程序", "生产准备"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-061", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "过度追求压缩工期最可能导致（ ）。", "options": {"A": "质量提高、投资降低", "B": "质量降低、投资增加", "C": "质量不变、投资不变", "D": "质量提高、投资增加"}, "answer": ["B"], "analysis": "过度压缩工期导致抢工期，可能降低质量并增加赶工费，体现三大目标对立关系。", "tags": ["工程项目管理", "三大目标"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-062", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "项目建议书的主要作用是（ ）。", "options": {"A": "详细技术经济论证", "B": "立项依据和投资机会研究", "C": "施工组织设计", "D": "详细设计方案"}, "answer": ["B"], "analysis": "项目建议书是决策阶段第一环节，进行投资机会研究，为立项提供依据。详细技术经济论证属可行性研究。", "tags": ["建设程序", "项目建议书"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-063", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "恢复项目是指（ ）。", "options": {"A": "对原有项目扩大规模", "B": "因自然灾害等原因毁坏后重新恢复建设的项目", "C": "对旧项目技术改造", "D": "将项目迁至新址建设"}, "answer": ["B"], "analysis": "恢复项目是因自然灾害、战争等原因使固定资产报废后重新恢复建设。扩建是扩大规模，改建是技术改造，迁建是搬迁。", "tags": ["工程项目分类", "恢复项目"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-064", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "下列属于生产性建设项目的是（ ）。", "options": {"A": "学校教学楼", "B": "医院门诊楼", "C": "工业厂房", "D": "住宅楼"}, "answer": ["C"], "analysis": "工业厂房属生产性建设项目（物质生产）。学校、医院、住宅属非生产性建设项目。", "tags": ["工程项目分类", "生产性项目"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-066", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "竣工验收后应进行的主要工作是（ ）。", "options": {"A": "编制竣工决算", "B": "编制施工图预算", "C": "进行工程结算", "D": "编制设计概算"}, "answer": ["A"], "analysis": "竣工验收后进入竣工阶段，主要工作：编制竣工决算、资产移交和后评价。", "tags": ["建设程序", "竣工阶段"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-067", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "以下造价文件中，准确性最高的是（ ）。", "options": {"A": "投资估算", "B": "设计概算", "C": "施工图预算", "D": "竣工决算"}, "answer": ["D"], "analysis": "造价文件准确性递增：估算(±30%)→概算(±10%)→预算→决算。竣工决算反映实际支出，准确性最高。", "tags": ["建设程序", "造价文件"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-068", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "招投标阶段确定的造价形式是（ ）。", "options": {"A": "估算", "B": "概算", "C": "预算", "D": "合同价"}, "answer": ["D"], "analysis": "招投标阶段确定合同价。通过招投标过程签订合同确定工程合同价款。", "tags": ["建设程序", "合同价"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-069", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "项目资本金制度中，属于资本金的是（ ）。", "options": {"A": "银行借款", "B": "发行债券", "C": "企业自有资金", "D": "融资租赁"}, "answer": ["C"], "analysis": "项目资本金须为自有资金。银行借款、发行债券、融资租赁属债务性资金。", "tags": ["工程项目管理", "资本金制度"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-070", "date": "2026-07-08", "chapter": "g02", "type": "single", "stem": "决策阶段的核心造价文件是（ ）。", "options": {"A": "设计概算", "B": "施工图预算", "C": "投资估算", "D": "竣工决算"}, "answer": ["C"], "analysis": "决策阶段的造价文件是投资估算，是项目决策的重要依据和后续造价控制的限额。", "tags": ["建设程序", "投资估算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "ht_mgmt_0636", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "根据我国现行规定,对于生产单一产品的项目，一般以（）划分项目等级。", "options": {"A": "项目的投资总额", "B": "项目的建筑面积", "C": "产品的市场需求规模", "D": "产品的设计生产能力"}, "answer": ["D"], "analysis": "凡生产单一产品的项目，一般以产品的设计生产能力划分;生产多种产品的项目，一般按其主要产品的设计生产能力划分;产品分类较多，不易分清主次、难以按产品的设计能力划分时，可按投资总额划分。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0637", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "根据我国项目法人责任制的相关规定,下列表述中，正确的是（）。", "options": {"A": "项目法人筹备组由投资方负责组建", "B": "项目董事会由项目使用单位在项目建成后负责组建", "C": "由原有企业负责建设的项目，新设立子公司时原企业法人即为项目法人", "D": "由原有企业负责建设的项目，设分厂时须重新设立项目法人"}, "answer": ["A"], "analysis": "新上项目在项目建议书被批准后,应由项目投资方派代表组成项目法人筹备组,具体负责项目法人的筹建工作。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0638", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "下列不属于建设单位在建设准备阶段应进行的工作是（）。", "options": {"A": "择优选定承包单位", "B": "组织招标选择设备、材料供应商", "C": "完成征地拆迁工作", "D": "编制项目管理实施规划"}, "answer": ["D"], "analysis": "建设准备：1)征地、拆迁和场地平整 2)完成施工用水、电、通讯、道路等接通工作 3)组织招标选择工程监理单位、施工单位及设备、材料供应商 4)准备必要的施工图纸", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0639", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "根据《建筑工程施工图设计文件审查暂行办法》，()应当将施工图报送建设行政主管部门，由其委托有关机构进行审查。", "options": {"A": "设计单位", "B": "建设单位", "C": "咨询单位", "D": "质量监督机构"}, "answer": ["B"], "analysis": "建设单位应当将施工图报送建设行政主管部门", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0640", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "根据《国务院关于投资体制改革的决定》，实施核准制的项目，企业应向政府主管部门提交()。", "options": {"A": "项目建议书", "B": "项目可行性研究", "C": "项目申请报告", "D": "项目开工报告"}, "answer": ["C"], "analysis": "核准制。企业投资建设《政府核准的投资项目目录》中的项目时，仅需向政府提交项目申请报告，不再经过批准项目建议书、可行性研究报告和开工报告的程序。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0641", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "根据《关于实行建设项目法人责任制的暂行规定》，项目董事会的职权之一是()。", "options": {"A": "负责提出项目竣工验收申请报告", "B": "组织编制项目初步设计文件", "C": "组织实施项目年度投资计划", "D": "负责组织项目试生产和单项工程预验收"}, "answer": ["A"], "analysis": "建设项目董事会的职权有：负责筹措建设资金；审核、上报项目初步设计和概算文件；审核、上报年度投资计划并落实年度资金；提出项目开工报告；研究解决建设过程中出现的重大问题；负责提出项目竣工验收申请报告；审定偿还债务计划和生产经营方针，并负责按时偿还债务；聘任或解聘项目总经理，并根据总经理的提名，聘任或解聘其他高级管理人员。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0642", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "工程项目承包模式中，建设单位组织协调工作量小，但风险较大的是（）。", "options": {"A": "总分包模式", "B": "合作体承包模式", "C": "平行承包模式", "D": "联合体承包模式"}, "answer": ["B"], "analysis": "采用合作体承包模式的特点： 1）建设单位的组织协调工作量小，但风险较大； 2）各承包单位之间既有合作的愿望，又不愿意组成联合体。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0643", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "工程项目管理组织机构采用直线制形式的主要优点是（）。", "options": {"A": "管理业务专门化，易提高工作质量", "B": "部门间横向联系强，管理效率高", "C": "隶属关系明确，易实现统一指挥", "D": "集权与分权结合，管理机构灵活"}, "answer": ["C"], "analysis": "直线制组织机构的主要优点是结构简单、权力集中、易于统一指挥、隶属关系明确、职责分明、决策迅速。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0644", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "按照工程建设项目发展的内在规律，投资建设一个工程项目都要经过投资决策和建设实施两个发展时期。这两个发展时期又可分为若干个阶段，它们之间()。", "options": {"A": "次序可以颠倒，但不能交叉", "B": "次序不能颠倒，但可以合理交叉", "C": "次序不能颠倒，也不能交叉", "D": "次序可以颠倒，也可以交叉"}, "answer": ["B"], "analysis": "工程项目建设程序。投资建设一个工程项目都要经过投资决策和建设实施两个发展时期。这两个发展时期又可分为若干个阶段，它们之间存在着严格的先后次序，可以进行合理的交叉，但不能任意颠倒次序。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0645", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "工程项目的项目后评价是固定资产投资管理的最后一个环节，项目后评价的基本方法是()。", "options": {"A": "效益评价法", "B": "影响评价法", "C": "对比法", "D": "过程评价法"}, "answer": ["C"], "analysis": "项目后评价的基本方法是对比法", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0646", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "工程项目可根据投资作用划分为生产性工程项目和非生产性工程项目两类，下列项目中属于生产性工程项目的是()。", "options": {"A": "企业管理机关的办公楼建设项目", "B": "宗教建设项目", "C": "基础设施建设项目", "D": "公共事业建设项目"}, "answer": ["C"], "analysis": "工程项目可分为生产性工程项目和非生产性工程项目。 (1)生产性工程项目，是指直接用于物质资料生产或直接为物质资料生产服务的工程项目。主要包括：工业建设项目、农业建设项目、基础设施建设项目，商业建设项目", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0647", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "根据我国现行规定，不同类别的建设工程项目应采用不同的组织实施方式，下列组合中正确的是()。", "options": {"A": "竞争性项目—代建制", "B": "公益性项目—项目法人责任制", "C": "非经营性政府投资项目—代建制", "D": "基础性项目—代建制"}, "answer": ["C"], "analysis": "程项目按投资来源可分为政府投资项目和非政府投资项目。非政府投资项目实行项目法人责任制，政府投资项目按照盈利性的不同又可分为经营性政府投资项目和非经营性政府投资项目，经营性政府投资项目实行项目法人责任制，非经营性政府投资项目应推行代建制。竞争性、基础性、公益性项目是工程项目按照经济效益、社会效益的分类。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0648", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "根据我国《关于实行建设项目法人责任制的暂行规定》的要求，项目总经理的职权包括()。", "options": {"A": "聘任或解聘项目高级管理人员", "B": "组织单项工程预验收", "C": "提出项目竣工验收申请报告", "D": "提出项目开工报告"}, "answer": ["B"], "analysis": "建设项目董事会的职权有：负责筹措建设资金；审核上报项目初步设计和概算文件；审核上报年度投资计划并落实年度资金；提出项目开工报告；研究解决建设过程中出现的重大问题；负责提出项目竣工验收申请报告；审定偿还债务计划和生产经营方针，并负责按时偿还债务；聘任或解聘项目总经理，并根据项目总经理的提名，聘任或解聘其他高级管理人员。项目总经理的职权包括：组织编制项目初步设计文件，对项目工艺流程、设备选型、建设标准、总图布置提出意见，提交董事会审查；组织工程设计、施工监理、施工队伍和设备材料采购的招标工作，编制和确定招标方案、标底和评标标准，评选和确定投、中标单位。实行国际招标的项目，按现行规定办理；编制并组织实施项目年度投资计划、用款计划、建设进度计划；编制项目财务预、决算；编制并组织实施归还贷款和其他债务计划；组织工程建设实施，负责控制工程投资、工期和质量；在项目建设过程中，在批准的概预算范围内对单项工程的设计进行局部调整（凡引起生产性质、能力、产品品种和标准变化的设计调整以及概算调整，需经董事会决定并报原审批单位批准）；根据董事会授权处理项目实施中的重大紧急事件，并及时向董事会报告；负责生产准备工作和培训有关人员；负责组织项目试生产和单项工程预验收；拟订生产经营计划、企业内部机构设置、劳动定员定额方案及工资福利方案；组织项目后评价，提出项目后评价报告；按时向有关部门报送项目建设、生产信息和统计资料；提请董事会聘任或解聘项目高级管理人员。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0649", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "在工程项目分类过程中，如果是生产单一产品的项目，一般以（）划分项目等级。", "options": {"A": "项目的规模", "B": "项目的总设计能力", "C": "项目的总投资额", "D": "产品的设计生产能力"}, "answer": ["D"], "analysis": "本题考查的是工程项目的组成和分类。凡生产单一产品的项目，一般以产品的设计生产能力划分。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0650", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "根据《关于实行建设项目法人责任制的暂行规定》，项目法人应在( )正式成立。", "options": {"A": "申报项目建议书之前", "B": "项目建议书被批准后", "C": "申报项目可行性研究报告之前", "D": "项目可行性研究报告被批准后"}, "answer": ["D"], "analysis": "本题考查的是工程项目管理的类型、任务及相关制度。在项目可行性研究报告被批准后，应正式成立项目法人。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0651", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "根据国家现行规定，下列关于建设项目竣工验收的表述正确的是()。", "options": {"A": "无论规模大小，建设项目完工后均应进行初验，然后进行正式验收", "B": "建设项目竣工图应由施工单位绘制并加盖“竣工图”标志", "C": "由项目主管部门或建设单位向负责验收的单位提出竣工验收申请报告", "D": "施工单位必须及时编制竣工决算，分析投资计划执行情况"}, "answer": ["C"], "analysis": "本题考查的是工程项目建设程序。根据国家规定，规模较大、较复杂的工程建设项目应先进行初验，然后进行正式验收。规模较小、简单的工程项目，可以一次进行全部项目的竣工验收。工程项目全部建完，经过各单位工程的验收，符合设计要求，并具备竣工图、竣工决算、工程总结等必要文件资料，由项目主管部门或建设单位向负责验收的单位提出竣工验收申请报告。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0652", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "在实际工作中，往往从效益后评价、过程后评价两个方面对工程项目进行后评价。下面属于效益后评价的是()。", "options": {"A": "项目可持续性后评价", "B": "立项决策系统分析", "C": "设计施工系统分析", "D": "生产运营系统分析"}, "answer": ["A"], "analysis": "本题考查的是工程项目建设程序。效益后评价包括：经济效益后评价、环境效益和社会效益后评价、项目可持续性后评价、项目综合效益后评价。过程后评价是指对工程项目的立项决策、设计施工、竣工投产、生产运营等全过程进行系统分析，找出项目后评价与原预期效益之间的差异及其产生的原因，使后评价结论有根有据，同时针对问题提出解决办法。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0653", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "国有大中型项目在建设阶段就按现代企业制度组建项目法人，实行全过程负责的是()。", "options": {"A": "项目法人责任制", "B": "工程监理制", "C": "工程招标投标制", "D": "合同管理制"}, "answer": ["A"], "analysis": "本题考查的是工程项目管理的类型、任务及相关制度。项目法人责任制是指国有大中型项目在建设阶段就按现代企业制度组建项目法人，由项目法人对项目策划、资金筹措、建设实施、生产经营、债务偿还和资产的保值增值，实行全过程负责。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0654", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "实行建设项目法人责任制的项目，项目董事会需要负责的工作是()。", "options": {"A": "筹措建设资金并按时偿还债务", "B": "组织编制并上报项目初步设计文件", "C": "编制和确定工程招标方案", "D": "组织工程建设实施并控制项目目标"}, "answer": ["A"], "analysis": "(2）项目董事会的职权。建设项目董事会的职权有：负责筹措建设资金；审核、上报项目初步设计和概算文件；审核、上报年度投资计划并落实年度资金；提出项目开工报告；研究解决建设过程中出现的重大问题；负责提出项目竣工验收申请报告；审定偿还债务计划和生产经营方针， 并负责按时偿还债务；聘任或解聘项目总经理， 并根据总经理的提名， 聘任或解聘其他高级管理人员。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0655", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "城镇市政基础设施工程的建设单位应在开工前向()申请领取施工许可证。", "options": {"A": "国务院建设主管部门", "B": "工程所在地省级以上人民政府建设主管部门", "C": "工程所在地地市级以上人民政府建设主管部门", "D": "工程所在地县级以上人民政府建设主管部门"}, "answer": ["D"], "analysis": "从事各类房屋建筑及其附属设施的建造、装修装饰和与其配套的线路、管道、设备的安装，以及城镇市政基础设施工程的施工，业主在开工前应当向工程所在地的县级以上人民政府建设行政主管部门申请领取施工许可证。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0656", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "根据《国务院关于投资体制改革的决定》，下列关于项目投资决策审批制度的说明，正确的是()。", "options": {"A": "政府投资项目实行审批制和核准制", "B": "采用资本金注入方式的政府投资项目，需要审批项目建议书、可行性研究报告和开工报告", "C": "对于企业不使用政府资金投资建设的项目，一律实行备案制", "D": "按规定应实行备案的项目由企业按照属地原则向地方政府投资主管部门备案"}, "answer": ["D"], "analysis": "根据《国务院关于投资体制改革的决定》，政府投资项目实行审批制；非政府投资项目实行核准制或登记备案制。对于采用直接投资和资本金注入方式的政府投资项目，政府需要从投资决策的角度审批项目建议书和可行性研究报告，除特殊情况外，不再审批开工报告。对于企业不使用政府资金投资建设的项目，政府不再进行投资决策性质的审批，区别不同情况实行核准制或登记备案制。对于《政府核准的投资项目目录》以外的企业投资项目，实行备案制。除国家另有规定外，由企业按照属地原则向地方政府投资主管部门备案。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0657", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "根据《国务院关于投资体制改革的决定》，实施核准制的项目，企业不再经过批准()的程序。", "options": {"A": "项目申请报告、可行性研究报告和开工报告", "B": "项目建议书、可行性研究报告和开工报告", "C": "项目申请报告、项目建议书和可行性研究报告", "D": "项目申请报告、项目建议书和开工报告"}, "answer": ["B"], "analysis": "本题考查的是工程项目建设程序。实施核准制的企业投资建设《政府核准的投资项目目录》中的项目时，仅需向政府提交项目申请报告，不再经过批准项目建议书、可行性研究报告和开工报告的程序。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0658", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "下列项目管理组织机构形式中，未明确项目经理角色的是（）组织机构。", "options": {"A": "职能制", "B": "弱矩阵制", "C": "平衡矩阵制", "D": "强矩阵制"}, "answer": ["B"], "analysis": "弱矩阵制组织中，并未明确对项目目标负责的项目经理。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0659", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "下列工程项目管理组织机构形式中，具有较大的机动性和灵活性，能够实现集权与分权的最优结合，但因有双重领导，容易产生扯皮现象的（）。", "options": {"A": "矩阵制", "B": "直线职能制", "C": "直线制", "D": "职能制"}, "answer": ["A"], "analysis": "矩阵制组织机构的优点是能根据工程任务的实际情况灵活地组建与之相适应的管理机构，具有较大的机动性和灵活性。它实现了集权与分权的最优结合，有利于调动各类人员的工作积极性，使工程项目管理工作顺利地进行。但是，矩阵制组织机构经常变动，稳定性差，尤其是业务人员的工作岗位频繁调动。此外，矩阵中的每一个成员都受项目经理和职能部门经理的双重领导，如果处理不当，会造成矛盾，产生扯皮现象。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0660", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "建设工程采用CM 承包模式时，CM 单位有代理型和非代理型两种。工程分包商的签约对象是（）。", "options": {"A": "代理型为业主，非代理型为CM 单位", "B": "代理型为CM 单位，非代理型为业主", "C": "无论代理型或非代理型，均为业主", "D": "无论代理型或非代理型，均为CM 单位"}, "answer": ["A"], "analysis": "CM 单位有代理型（Agency）和非代理型（Non—Agency）两种。代理型的CM 单位不负责工程分包的发包，与分包单位的合同由建设单位直接签订。而非代理型的CM 单位直接与分包单位签订分包合同。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0661", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "在可以采用的几种组织形式中，实行没有职能机构的“个人管理”的组织形式是（）。", "options": {"A": "直线职能制", "B": "矩阵式", "C": "职能制", "D": "直线制"}, "answer": ["D"], "analysis": "直线制组织机构隶属关系明确、职责分明不利于“个人管理”。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0662", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "下列工程项目管理组织机构形式中易形成多头领导的是（）。", "options": {"A": "直线制", "B": "职能制", "C": "直线职能制", "D": "职能制和直线职能制"}, "answer": ["B"], "analysis": "职能制组织机构的优点:1)强调管理业务的专门化，注意发挥各类专家在项目管理中的作用。2)易于提高工作质量，同时可以减轻领导者的负担。 职能制组织机构的缺点:易形成多头领导,使下级执行者接受多方指令，容易造成职责不清。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0663", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "在下列组织机构形式中，具有集中领导、职责清晰，但各职能部门之间的横向联系差、信息传递路线长等特点的是（）组织机构形式。", "options": {"A": "直线制", "B": "职能制", "C": "直线职能制", "D": "矩阵制"}, "answer": ["C"], "analysis": "直线职能制组织结构既保持了直线制统一指挥的特点，又满足了职能制对管理工作专业化分工的要求。其主要优点是集中领导、职责清楚，有利于提高管理效率。但这种组织机构中各职能部门之间的横向联系差,信息传递路线长，职能部门与指挥部门之间容易产生矛盾。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0664", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "下列工程项目目标控制方法中，可用来掌握产品质量波动情况及质量特征的分布规律，以便对质量状况进行分析判断的是（）。", "options": {"A": "直方图法", "B": "鱼刺图法", "C": "控制图法", "D": "S 曲线法"}, "answer": ["A"], "analysis": "直方图又叫频数分布直方图。它以直方图形的高度表示一定范围内数值所发生的频数，据此可掌握产品质量的波动情况，了解质量特征的分布规律，以便对质量状况进行分析判断。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0665", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "香蕉曲线法和S 曲线法均可用来控制工程造价和工程进度。二者的主要区别是：香蕉曲线以（）为基础绘制。", "options": {"A": "施工横道计划", "B": "流水施工计划", "C": "工程网络计划", "D": "挣值分析计划"}, "answer": ["C"], "analysis": "香蕉曲线法的原理与S 曲线法的原理基本相同，其主要区别在于：香蕉曲线是以工程网络计划为基础绘制的。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0666", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "下列方法中，可用来综合控制工程进度和工程造价的是（）。", "options": {"A": "香蕉曲线法和S 曲线法", "B": "网络计划法和控制图法", "C": "因果分析图法和排列图法", "D": "价值工程法和直方图法"}, "answer": ["A"], "analysis": "香蕉曲线法的原理与S 曲线法的原理基本相同，其主要区别在于：香蕉曲线是以工程网络计划为基础绘制的。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0667", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "为了有效地控制建设工程项目目标，可采取的组织措施之一是（）。", "options": {"A": "定制工作考核标准", "B": "论证技术方案", "C": "审查工程付款", "D": "选择合同计价方式"}, "answer": ["A"], "analysis": "组织措施：控制是由人来执行的，监督按计划要求投入劳动力、机具、设备、材料，巡视、检查工程运行情况，对工程信息的收集、加工、整理、反馈，发现和预测目标偏差，采取纠正行动等都需要事先委任执行人员，授予相应职权，确定职责，制定工作考核标准，并力求使之一体化运行。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0668", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "根据《建筑施工组织设计规范》，单位工程施工组织设计应由（）主持编制。", "options": {"A": "建设单位项目负责人", "B": "施工项目负责人", "C": "施工单位技术负责人", "D": "施工项目技术负责人"}, "answer": ["B"], "analysis": "单位工程施工组织设计应由施工项目负责人主持编制，应由施工单位技术负责人或其授权的技术人员负责审批。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0669", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "下列进度计划表中，用来确定年度施工项目的投资额和年末形象进度，并阐明建设条件落实情况的是（）。", "options": {"A": "投资计划年度分配表", "B": "年度建设资金平衡表", "C": "年度计划项目表", "D": "工程项目进度平衡表"}, "answer": ["C"], "analysis": "年度计划项目表。用来确定年度施工项目的投资额和年末形象进度，并阐明建设条件（图纸、设备、材料、施工力量）的落实情况。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0670", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "下列建设工程项目目标控制方法中，可用来综合控制工程进度和工程造价的方法是（）。", "options": {"A": "决策树法和流程图法", "B": "S 曲线法和香蕉曲线法", "C": "横道图法和树枝图法", "D": "网络图法和横道图法"}, "answer": ["B"], "analysis": "S 曲线可用于控制工程造价和工程进度。香蕉曲线法的原理与S 曲线法的原理基本相同，与S 曲线法相同，香蕉曲线同样可用来控制工程造价和工程进度。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0671", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "下列进度计划表中，用来明确各种设计文件交付日期，主要设备交货日期，施工单位进场日期，水、电及道路接通日期等的是（）。", "options": {"A": "工程项目总进度计划表", "B": "工程项目进度平衡表", "C": "工程项目施工总进度表", "D": "单位工程总进度计划表"}, "answer": ["B"], "analysis": "工程项目进度平衡表。用来明确各种设计文件交付日期，主要设备交货日期，施工单位进场日期，水电及道路接通日期等，以保证工程建设中各个环节相互衔接，确保工程项目按期投产或交付使用。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0672", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "下列工程项目目标控制方法中，可用来找出工程质量主要影响因素的是（）。", "options": {"A": "直方图法", "B": "鱼刺图法", "C": "排列图法", "D": "S 曲线法"}, "answer": ["C"], "analysis": "排列图又叫主次因素分析图或帕累特（Pareto）图，是用来寻找影响工程（产品）质量主要因素的一种有效工具。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0673", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "下列关于工程项目目标控制方法的表述中正确的是（）。", "options": {"A": "直方图是一种用来寻找影响工程质量主要因素的有效工具", "B": "通过因果分析图，可以发现工程项目中主要的质量问题", "C": "香蕉曲线与S 曲线都可以用来控制工程造价和工程进度", "D": "控制图法和直方图法分别属于质量控制的静态和动态分析方法"}, "answer": ["C"], "analysis": "S 曲线可用于控制工程造价和工程进度。香蕉曲线法的原理与S 曲线法的原理基本相同，与S 曲线法相同，香蕉曲线同样可用来控制工程造价和工程进度。 本题库是以官方教材为依据，知识点所对应的习题综合了二建法规、二建管理、造价员基础、一级造价师考试的题库+真题编辑，基本上做到了每个知识点都有相对应的题目及解析,题库会陆续更新,会有模拟题,预测题及考前更新押题。 《建设工程计量与计价实务》题库编辑中,教材出来后会陆续更新 www.jinkaodian.com 金考典考试软件。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0674", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "建设工程项目实施CM 承包模式时，代理型合同由（）的计价方式签订。", "options": {"A": "业主与分包商以简单的成本加酬金", "B": "业主与分包商以保证最大工程费用加酬金", "C": "CM 单位与分包商以简单的成本加酬金", "D": "CM 单位与分包商以保证最大工程费用加酬金"}, "answer": ["A"], "analysis": "代理型合同是建设单位与分包单位直接签订,采用简单的成本加酬金合同形式。而非代理型合同则采用保证最大工程费用(GMP)加酬金的合同形式。 本题库是以官方教材为依据，知识点所对应的习题综合了二建法规、二建管理、造价员基础、一级造价师考试的题库+真题编辑，基本上做到了每个知识点都有相对应的题目及解析,题库会陆续更新,会有模拟题,预测题及考前更新押题。 《建设工程计量与计价实务》题库编辑中,教材出来后会陆续更新 www.jinkaodian.com 金考典考试软件。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0675", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "下列控制措施中，属于工程项目目标被动控制措施的是（）。", "options": {"A": "制定实施计划时，考虑影响目标实现和计划实施的不利因素", "B": "说明和揭示影响目标实现和计划实施的潜在风险因素", "C": "制定必要的备用方案，以应对可能出现的影响目标实现的情况", "D": "跟踪目标实施情况，发现目标偏离时及时采取纠偏措施"}, "answer": ["D"], "analysis": "被动控制是指当系统按计划运行时，管理人员对计划的实施进行跟踪，将系统输出的信息进行加工、整理，再传递给控制部门，使控制人员从中发现问题，找出偏差，寻求并确定解决问题和纠正偏差的方案，然后再回送给计划实施系统付诸实施，使得计划目标一旦出现偏离就能得以纠正。被动控制是一种反馈控制。对项目管理人员而言，被动控制仍然是一种积极的控制，也是一种十分重要的控制方式，而且是经常采用的控制方式。本题库是以官方教材为依据，知识点所对应的习题综合了二建法规、二建管理、造价员基础、一级造价师考试的题库+真题编辑，基本上做到了每个知识点都有相对应的题目及解析,题库会陆续更新,会有模拟题,预测题及考前更新押题。 《建设工程计量与计价实务》题库编辑中,教材出来后会陆续更新 www.jinkaodian.com 金考典考试软件。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0676", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "下列工程项目计划表中，用来阐明各单位工程的建筑面积、投资额、新增固定资产、新增生产能力等建筑总规模及本年计划完成情况的是（）。", "options": {"A": "年度竣工投产交付实用计划表", "B": "年度计划项目表", "C": "年度建设资金平衡表", "D": "按资计划年度分配表"}, "answer": ["A"], "analysis": "年度竣工投产交付使用计划表,用来阐明各单位工程的建筑面积、投资额、新增固定资产、新增生产能力等建筑总规模及本年计划完成情况，^并阐明其竣工日期。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0677", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "(2010年)对于一般工业项目的办公楼而言，下列工程中属于分部工程的是()。", "options": {"A": "土方开挖与回填工程", "B": "通风与空调工程", "C": "玻璃屏幕工程", "D": "门窗制作与安装工程"}, "answer": ["B"], "analysis": "分部工程是指将单位工程按专业性质、建筑部位等划分的工程。根据《建筑工程施工质量验收统一标准》 GB 50300-2013，建筑工程包括： 地基与基础、主体结构、装饰装修、屋面、给排水及采暖、通风与空调、建筑电气、智能建筑、建筑节能、电梯等分部工程。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0678", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "(2009年)根据《关于实行建设项目法人责任制的暂行规定》，项目总经理的职权之一是()。", "options": {"A": "提出项目开工报告", "B": "审核项目初步设计和概算文件", "C": "组织工程招标工作", "D": "提出项目竣工验收申请报告"}, "answer": ["C"], "analysis": "(3）项目总经理的职权。项目总经理的职权有：组织编制项目初步设计文件， 对项目工艺流程、设备选型、建设标准、总图布置提出意见， 提交董事会审查； 组织工程设计、施工监理、施工队伍和设备材料采购的招标工作， 编制和确定招标方案、标底和评标标准， 评选和确定投标、中标单位。实行国际招标的项目， 按现行规定办理； 编制并组织实施项目年度投资计划、用款计划、建设进度计划； 编制项目财务预算、决算； 编制并组织实施归还贷款和其他债务计划； 组织工程建设实施， 负责控制工程投资、工期和质量； 在项目建设过程中， 在批准的概算范围内对单项工程的设计进行局部调整（凡引起生产性质、能力、产品品种和标准变化的设计调整以及概算调整， 需经董事会决定并报原审批单位批准）； 根据董事会授权处理项目实施中的重大紧急事件， 并及时向董事会报告； 负责生产准备工作和培训有关人员； 负责组织项目试生产和单项工程预验收； 拟订生产经营计划、企业内部机构设置、劳动定员定额方案及工资福利方案； 组织项目后评价，提出项目后评价报告； 按时向有关部门报送项目建设、生产信息和统计资料； 提请董事会聘任或解聘项目高级管理人员。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0679", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "(2012年)根据《关于实行建设项目法人责任制的暂行规定》，建设项目董事会的基本职责是()。", "options": {"A": "组织编制初步设计文件", "B": "负责筹措建设资金", "C": "负责控制建设投资", "D": "组织单项工程竣工验收"}, "answer": ["B"], "analysis": "(2）项目董事会的职权。建设项目董事会的职权有：负责筹措建设资金；审核、上报项目初步设计和概算文件；审核、上报年度投资计划并落实年度资金；提出项目开工报告；研究解决建设过程中出现的重大问题；负责提出项目竣工验收申请报告；审定偿还债务计划和生产经营方针， 并负责按时偿还债务；聘任或解聘项目总经理， 并根据总经理的提名， 聘任或解聘其他高级管理人员。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0680", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "(2011年)关于Partnering模式的说法，正确的是()。", "options": {"A": "Partnering协议是业主与承包商之间的协议", "B": "Partnering模式是一种独立存在的承发包模式", "C": "Partnering模式特别强调工程参建各方基层人员的参与", "D": "Partnering协议不是法律意义上的合同"}, "answer": ["D"], "analysis": "Partnering 模式的主要特征： (1）出于自愿。(2）高层管理的参与。( 3) Partnering 协议不是法律意义上的合同。(4）信息的开放性。值得指出的是， Partnering 模式不是一种独立存在的模式， 它通常需要与工程项目其他组织模式中的某一种结合使用， 如总分包模式、平行承包模式、CM承包模式等。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0681", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "(2010年)下列工程项目管理组织机构模式中，结构简单，隶属关系明确，易于统一指挥，决策迅速的是()。", "options": {"A": "直线制", "B": "矩阵制", "C": "职能制", "D": "直线职能制"}, "answer": ["A"], "analysis": "直线制组织机构的主要优点是结构简单、权力集中、易于统一指挥、隶属关系明确、职责分明、决策迅速。但由于未设职能部门，项目经理没有参谋和助手，要求领导者通晓各种业务，成为“全能式”人才；无法实现管理工作专业化，不利于项目管理水平的提高。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0682", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "(2015年)关于CM承包模式的说法，正确的是( )。", "options": {"A": "CM合同采用成本加酬金的计价方式", "B": "分包合同由CM单位与分包单位签订", "C": "总包与分包之间的差价归CM单位", "D": "订立CM合同时需要一次确定施工合同总价"}, "answer": ["A"], "analysis": "本题考查的是造价工程师管理制度。CM合同采用成本加酬金方式。选项B错误，代理型的CM单位不负责工程分包的发包，与分包单位的合同由建设单位直接签订，而非代理型的CM单位直接与分包单位签订分包合同。选项C错误，CM单位不赚取总包与分包之间的差价。选项D错误，采用CM承包模式时，施工任务要进行多次分包，施工合同总价不是一次确定。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0684", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "(2013年)代理型CM合同由建设单位与分包单位直接签订，一般采用()的合同形式。", "options": {"A": "固定单价", "B": "可调总价", "C": "GMP加酬金", "D": "简单的成本加酬金"}, "answer": ["D"], "analysis": "CM合同采用成本加酬金方式 CM合同采用成本加酬金方式。代理型和非代理型的CM合同是有区别的。由于代理型合同是建设单位与分包商直接签订，所以采用简单的成本加酬金合同形式。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0685", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "（2017年考题）建设工程采用平行承包模式的特点是（ ）", "options": {"A": "有利于缩短建设工期", "B": "不利于控制工程质量", "C": "业主组织管理简单", "D": "工程造价控制难度小"}, "answer": ["A"], "analysis": "不同发包模式的特点，常规考查。总分包-平行的对比。我们学的每一个都有利于缩短工期。平行发包也有利于质量控制，但和总分包的原因是不一致的；总分包是增加了质量控制的环节，平行发包是由于“他控”。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0686", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "（2017年考题）下列计划表中,属于建设单位计划体系中工程项目建设总进度计划的是（ ）。", "options": {"A": "年度计划项目表", "B": "年度建设资金平衡表", "C": "投资计划年度分配表", "D": "年度设备平衡表"}, "answer": ["C"], "analysis": "工程项目建设总进度计划表格部分包括：工程项目一览表、工程项目总进度计划、投资计划年度分配表和工程项目进度平衡表。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0687", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "（2017年考题）直线职能制组织结构的特点是（ ）。", "options": {"A": "信息传递路径较短", "B": "容易形成多头领导", "C": "各职能部门间横向联系强", "D": "各职能部门职责清楚"}, "answer": ["D"], "analysis": "考查不同组织结构的特点，常规考查，15 年刚刚考过。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0688", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "(2012年)下列工程项目目标控制方法中，可用来判断工程造价偏差的是()。", "options": {"A": "控制图法", "B": "鱼刺图法", "C": "S曲线法", "D": "网络计划法"}, "answer": ["C"], "analysis": "S曲线可用于控制工程造价和工程进度。其控制程序如下：(3）将实际S曲线与计划S曲线进行比较，以此判断工程进度偏差或造价偏差。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0689", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "(2011年)下列工程项目目标控制方法组中，控制的原理基本相同、目的也相同的是()。", "options": {"A": "香蕉曲线法和S曲线法", "B": "网络计划法和香蕉曲线法", "C": "排列图法和网络计划法", "D": "S曲线法和排列图法"}, "answer": ["A"], "analysis": "S曲线可用于控制工程造价和工程进度。香蕉曲线法的原理与S曲线法的原理基本相同， 其主要区别在于： 香蕉曲线是以工程网络计划为基础绘制的。与S曲线法相同， 香蕉曲线同样可用来控制工程造价和工程进度。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0690", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "(2014年)根据《建筑施工组织设计规范》，按编制对象不同，施工组织设计的三个层次是指（）。", "options": {"A": "施工总平面图、施工总进度计划和资源需求计划", "B": "施工组织总设计、单位工程施工组织设计和施工方案", "C": "施工总平面图、施工总进度计划和专项施工方案", "D": "施工组织总设计、单位工程施工进度计划和施工作业计划"}, "answer": ["B"], "analysis": "该题主要考察的是：工程项目施工组织设计 按编制对象不同，施工组织设计的三个层次即：施工组织总设计、单位工程施工组织设计和施工方案。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0691", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "(2016年)根据《建筑施工组织设计规范》，施工组织设计有三个层次是指()。", "options": {"A": "施工组织总设计、单位工程施工组织设计和施工方案", "B": "施工组织总设计、单项工程施工组织设计和施工进度计划", "C": "施工组织设计、施工进度计划和施工方案", "D": "指导性施工组织设计、实施性施工组织设计和施工方案"}, "answer": ["A"], "analysis": "该题主要考察的是：施工组织设计的三个层次 按编制对象不同，施工组织设计包括三个层次，即：施工组织总设计、单位工程施工组织设计和施工方案。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0692", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "(2009年)作为施工承包单位计划体系的重要内容，项目管理实施规划应由()编制。", "options": {"A": "企业管理层在投标之前", "B": "项目经理部在投标之前", "C": "企业管理层在开工之前", "D": "项目经理部在开工之前"}, "answer": ["D"], "analysis": "项目管理实施规划是在开工之前由施工项目经理组织编制， 并报企业管理层审批的工程项目管理文件。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0693", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "(2010年)下列方法中，可同时用来控制工程造价和工程进度的是()。", "options": {"A": "S曲线和直方图法", "B": "直方图和控制图法", "C": "排列图法和香蕉曲线法", "D": "香蕉曲线法和S曲线法"}, "answer": ["D"], "analysis": "对一个工程项目而言，如果以横坐标表示时间，纵坐标表示累计完成的工程数量或造价，即可形成一条形如“S”的曲线，所以S曲线可用于控制工程造价和工程进度。香蕉曲线是由两条S曲线组合在一起，因而香蕉曲线同样可用来控制工程造价和工程进度。香蕉曲线法原理与S曲线法的原理基本相同，区别在于它是以工程网络计划为基础绘制的。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0694", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "(2015年)根据《建筑施工组织设计规范》，施工组织总设计应由()主持编制。", "options": {"A": "总承包单位技术负责人", "B": "施工项目负责人", "C": "总承包单位法定代表人", "D": "施工项目技术负责人"}, "answer": ["B"], "analysis": "本题考查的是工程项目施工组织设计。施工组织总设计应由施工项目负责人主持编制，应由总承包单位技术负责人负责审批。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0695", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "（2017年考题）编制单位工程施工进度计划时,确定工作项目持续时间需要考虑每班工人数量、限定每班工人数量上限的因素是（ ）。", "options": {"A": "工作项目工程量", "B": "最小劳动组合", "C": "人工产量定额", "D": "最小工作面"}, "answer": ["D"], "analysis": "最小工作面限定了每班安排人数的上限。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0696", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "（2017年考题）应用直方图法分析工程质量状况时,直方图出现折齿型分布的原因是（ ）。", "options": {"A": "数据分组不当或组距确定不当", "B": "少量材料不合格", "C": "短时间內工人操作不熟练", "D": "数据分类不当"}, "answer": ["A"], "analysis": "考查项目目标控制的方法，常规考查。无非就是考查各种方法的作用、质量控制方法动态的静态的、两个细节题（直方图不正常的类型、控制图不正常）", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0720", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "工程设计阶段，（ ）的目的是为了阐明在指定的地点、时间和投资控制数额内，拟建项目在技术上的可行性和经济上的合理性。", "options": {"A": "初步设计", "B": "技术设计", "C": "施工图设计", "D": "施工图设计文件的审查"}, "answer": ["A"], "analysis": "初步设计是根据可行性研究报告要求所做的具体实施方案，目的是为了阐明在指定的地点、时间和投资控制数额内，拟建项目在技术上的可行性和经济上的合理性，并通过对工程项目所做出的基本技术经济规定，编制项目总概算。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0721", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "建设工程项目管理的任务中，（ ）的主要任务是采用规划、组织、协调等手段，采取组织、技术、经济、合同等措施，确保项目总目标的实现。", "options": {"A": "风险管理", "B": "信息管理", "C": "目标控制", "D": "合同管理"}, "answer": ["C"], "analysis": "目标控制是指工程项目管理人员在不断变化的动态环境中为保证既定计划目标实现而进行的一系列检查和调整活动。目标控制的主要任务是采用规划、组织、协调等手段，采取组织、技术、经济、合同等措施，确保工程项目总目标实现。工程项目目标控制的任务贯穿在项目策划决策和建设实施各个阶段。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0722", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "建设项目在开工建设之前要切实做好各项准备工作，其主要内容不包括（）。", "options": {"A": "征地、拆迁、场地平整以及基坑开挖工作", "B": "完成施工用水、电、通信、道路等接通工作", "C": "组织招标选择施工单位及设备、材料供应商", "D": "准备必要的施工图纸"}, "answer": ["A"], "analysis": "建设准备工作内容。1）征地、拆迁和场地平整；2）完成施工用水、电、通信、道路等接通工作；3）组织招标选择工程监理单位、施工单位及设备、材料供应商；4）准备必要的施工图纸；5）办理工程质量监督和施工许可手续。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0723", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "（）的项目管理是全过程的项目管理，包括项目决策与实施阶段的各个环节。", "options": {"A": "总承包方", "B": "设计方", "C": "业主方", "D": "施工方"}, "answer": ["C"], "analysis": "业主方项目管理是全过程项目管理，包括项目策划决策与建设实施阶段各个环节。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0724", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "施工安装活动应按照工程设计要求、施工合同条款、有关工程建设法律法规规范标准及施工组织设计，在保证工程质量、工期、成本及安全、环保等目标的前提下进行，达到竣工验收标准后，由（ ）移交给建设单位。", "options": {"A": "监理单位", "B": "分包单位", "C": "设计单位", "D": "施工单位"}, "answer": ["D"], "analysis": "施工安装活动应按照工程设计要求、施工合同及施工组织设计，在保证工程质量、工期、成本及安全、环保等目标的前提下进行，达到竣工验收标准后，由施工单位移交给建设单位。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0725", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "工程项目的种类繁多，为了适应科学管理的需要，可以从不同的角度进行分类，建设工程项目按项目的（ ）划分，可分为政府投资项目和非政府投资项目。", "options": {"A": "建设性质", "B": "投资来源", "C": "项目规模", "D": "投资作用"}, "answer": ["B"], "analysis": "按照投资来源划分，工程项目可划分为政府投资项目和非政府投资项目。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0726", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "根据《房屋建筑和市政基础设施工程施工图设计文件审查暂行办法》规定，（ ）应当将施工图送施工图审查机构审查。", "options": {"A": "施工单位", "B": "监理单位", "C": "建设单位", "D": "设计单位"}, "answer": ["C"], "analysis": "以房屋建筑和市政基础设施工程为例，根据《房屋建筑和市政基础设施工程施工图设计文件审查管理办法》(住房和城乡建设部令第13号 ) ，建设单位应当将施工图送施工图审查机构审查。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0727", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "项目管理知识体系中，（ ）是指为满足项目利益相关者目标而开展的计划、管理和控制活动。", "options": {"A": "项目范围管理", "B": "项目时间管理", "C": "项目质量管理", "D": "项目人力资源管理"}, "answer": ["C"], "analysis": "项目质量管理是指为满足项目利益相关者目标而开展的计划、管理和控制活动。具体内容包括质量管理计划、质量管理和质量控制。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0728", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "竣工决算文件中，真实记录各种地下、地上建筑物等详细情况的技术文件是（ ）。", "options": {"A": "总平面图", "B": "竣工图", "C": "施工图", "D": "交付使用资产明细表"}, "answer": ["B"], "analysis": "工程项目竣工图是真实记录各种地下、地上建筑物等详细情况的技术文件，是对工程进行交工验收、维护、扩建、改建的依据，同时也是使用单位长期保存的技术资料。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0729", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "在一个建设工程项目中，具有独立的设计文件，竣工后可以独立发挥生产能力或效益的一组配套齐全的工程项目属于（ ）。", "options": {"A": "分部工程", "B": "单位工程", "C": "单项工程", "D": "分项工程"}, "answer": ["C"], "analysis": "单项工程是指具有独立的设计文件，竣工后可以独立发挥生产能力、投资效益的一组配套齐全的工程项目 。单项工程是工程项目的组成部分， 一个工程项目有时可以仅包括一个单项工程，也可以包括多个单项工程。生产性工程项目的单项工程，一般是指能独立生产的车间，包括厂房建筑、设备安装等工程。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0730", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "对于采用（ ）的政府投资项目，政府需要从投资决策的角度审批项目建议书和可行性研究报告，除特殊情况外不再审批开工报告，同时还要严格审批其初步设计和概算。", "options": {"A": "投资补助、转贷和资本金注入方式", "B": "直接投资和贷款贴息方式", "C": "投资补助、转贷和贷款贴息方式", "D": "直接投资和资本金注入方式"}, "answer": ["D"], "analysis": "对于采用直接投资和资本金注入方式的政府投资项目，政府需要从投资决策的角度审批项目建议书和可行性研究报告，除特殊情况外，不再审批开工报告，同时还要严格审批其初步设计和概算；对于采用投资补助、转贷和贷款贴息方式的政府投资项目，则只审批资金申请报告。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0731", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "对于《政府核准的投资项目目录》以外的企业投资项目，实行（ ）。", "options": {"A": "核准制", "B": "责任制", "C": "审批制", "D": "备案制"}, "answer": ["D"], "analysis": "对于企业不使用政府资金投资建设的项目，政府不再进行投资决策性质的审批，区别不同情况实行核准制或登记备案制。 1)核准制。企业投资建设《政府核准的投资项目目录》中的项目时，仅需向政府提交项目申请报告，不再经过批准项目建议书、可行性研究报告和开工报告的程序。 2)备案制。对《政府核准的投资项目目录》以外的企业投资项目，实行备案制。除国家另有规定外，由企业按照属地原则向地方政府投资主管部门备案。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0732", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "将工程项目按照投资效益和市场需求划分， 投资主要由政府用财政资金安排的项目是（ ）", "options": {"A": "基础性项目", "B": "公益性项目", "C": "竞争性项目", "D": "改建项目"}, "answer": ["B"], "analysis": "本题考查的是工程项目的分类。 公益性项目的投资主要由政府用财政资金安排", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0733", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "根据《建筑工程施工图设计文件审查暂行办法》，施工图设计文件应当由（ ）委托有关审查机构进行审查。", "options": {"A": "工程监理单位", "B": "工程质量监督单位", "C": "建设单位", "D": "建设行政主管部门"}, "answer": ["C"], "analysis": "本题考查的是工程项目管理概述。建设单位应当将施工图送施工图审查机构审查", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0734", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "关于建设工程竣工图的绘制和形成，下列说法中正确的是（ ）。", "options": {"A": "凡按图竣工没有变动的，由发包人在原施工图上加盖“竣工图”标志", "B": "凡在施工过程中发生设计变更的，一律重新绘制竣工图", "C": "平面布置发生重大改变的，一律由设计单位负责重新绘制竣工图", "D": "重新绘制的新图，应加盖“竣工图”标志"}, "answer": ["D"], "analysis": "本题考查的是工程项目管理概述。关于绘制竣工图的规定如下：①凡按图施工没有变动的，由施工承包单位（包括总包单位和分包单位）在原施工图上加盖“竣工图”标志后即作为竣工图；②凡在施工中，虽有一般性设计变更，但能将原施工图加以修改补充作为竣工图的，可不重新绘制，由施工承包单位负责在原施工图（必须新蓝图）上注明修改部分，并附以设计变更通知单和施工说明，加盖“竣工图”标志后，即作为竣工图；③凡结构形式改变、工艺改变、平面布置改变、项目改变以及有其他重大改变，不宜再在原施工图上修改补充者，应重新绘制改变后的竣工图。由于设计原因造成的，由设计单位负责重新绘图；由于施工原因造成的，由施工承包单位负责重新绘图；由于其他原因造成的，由建设单位自行绘图或委托设计单位绘图，施工单位负责在新图上加盖“竣工图”标志，并附以有关记录和说明，作为竣工图。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0735", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "根据《国务院关于投资体制改革的决定》， 为了广泛听取社会各方对政府投资项目的意见和建议， 国家将逐步实行政府投资项目（ ） 制度。", "options": {"A": "专家评审", "B": "公示", "C": "咨询评估", "D": "听证"}, "answer": ["B"], "analysis": "根据题干中提到的《国务院关于投资体制改革的决定》，可以知道该题考察的是政府投资项目的公示制度。因此，正确答案为B。其他选项中，专家评审、咨询评估、听证都是政府在决策过程中可能采取的方式，但并不是本题的答案。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0736", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "为了保护环境， 在项目实施阶段应做到“三同时” 。 这里的“三同时” 是指主体工程与环保措施工程要（ ） 。", "options": {"A": "同时施工、同时验收、同时投入运行", "B": "同时审批、同时设计、同时施工", "C": "同时设计、同时施工、同时投入运行", "D": "同时施工、同时移交、同时使用"}, "answer": ["C"], "analysis": "本题考查环保措施在项目实施阶段的应用。根据题干中的“三同时”，可以推断出这是指主体工程与环保措施工程在实施阶段要同时进行的三个环节。选项A中的“同时验收、同时投入运行”与环保措施无关，排除；选项B中的“同时审批”也不符合实际情况，排除；选项D中的“同时移交、同时使用”也不是环保措施的要求，排除。因此，正确答案为C，即“同时设计、同时施工、同时投入运行”。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0737", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "项目后评价是工程项目实施阶段管理的延伸，它的基本方法是（ ）", "options": {"A": "统计法", "B": "比例法", "C": "理论计算法", "D": "对比法"}, "answer": ["D"], "analysis": "项目后评价的基本方法是对比法。就是将工程项目建成投产后所取得的实际效果、最新题库，考前【黑钻押题】，金考典软件考前更新，下载链接 www.jinkaodian.com 经济效益和社会效益、环境保护等情况与投资决策阶段的预测情况相对比，与项目建设实施前的情况相对比，从中发现问题，总结经验和教训。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0738", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "根据《国务院关于投资体制改革的决定》，对于采用资本金注入方式的政府投资工程项目，政府投资主管部门需要严格审批的内容是（ ）。", "options": {"A": "资金申请报告和施工方案", "B": "初步设计和概算", "C": "施工组织设计和预算", "D": "预算和开工报告"}, "answer": ["B"], "analysis": "本题考查的是工程项目管理概述。政府投资项目（直接投资和资本金注入）方式的，审批项目建议书和可行性研究报告，除特殊情况外，不再审批开工报告了，但要严格审批初步设计和概算。考前黑钻押题，金考典软件考前更新，下载链接 www.jinkaodian.com", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0739", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "业主将建设工程项目的设计、设备与材料采购、施工任务全部发包给一个承包商的合同属于（ ）。", "options": {"A": "单项工程或者特殊专业工程承包合同", "B": "施工总承包合同", "C": "EPC承包合同", "D": "工程施工合同"}, "answer": ["C"], "analysis": "EPC承包合同是指业主将建设工程项目的设计、设备与材料采购、施工任务全部发包给一个承包商。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0740", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "下列项目融资方式中，通过已建成项目为其他新项目进行融资的是（）。", "options": {"A": "TOT", "B": "BT", "C": "BOT", "D": "PFI"}, "answer": ["A"], "analysis": "从项目融资的角度看，TOT是通过转让已建成项目的产权和经营权来融资的，而BOT是政府给予投资者特许经营权的许诺后，由投资者融资新建项目，即TOT是通过已建成项目为其他新项目进行融资，BOT则是为筹建中的项目进行融资。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0741", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "在工程代建制模式中，工程代建单位不参与工程项目的策划决策和经营管理，不对投资收益负责。一般需要提交工程概算投资（ ）左右的履约保函。", "options": {"A": "5%", "B": "10%", "C": "15%", "D": "20%"}, "answer": ["B"], "analysis": "本题考查的是工程项目实施模式。工程项目代建合同生效后，为了保证政府投资的合理使用，代建单位须提交工程概算投资10%左右的履约保函。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0742", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "PMC模式下， 项目管理承包商在项目前期阶段工作内容是指（） 。", "options": {"A": "进行设计管理，协调有关技术条件", "B": "完成项目总体中某些部分的详细设计", "C": "组织项目风险识别和分析，并制定项目风险应对策略", "D": "实施采购管理，并为业主负责的采购提供服务"}, "answer": ["C"], "analysis": "本题考查的是PMC（项目管理承包商）模式下，项目前期阶段工作内容。根据PMC模式的特点，项目管理承包商在项目前期阶段主要负责项目风险管理，因此选项C“组织项目风险识别和分析，并制定项目风险应对策略”是正确答案。选项A“进行设计管理，协调有关技术条件”和选项B“完成项目总体中某些部分的详细设计”属于项目实施阶段的工作内容，选项D“实施采购管理，并为业主负责的采购提供服务”属于采购管理的工作内容，与题干不符，因此排除。综上所述，答案为C。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0743", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "下列关于CM(Construction Management)模式的说法中，错误的是（）。", "options": {"A": "CM模式特别适用于实施周期长、工期要求紧迫的大型复杂工程项目", "B": "CM模式有利于控制工程质量和造价", "C": "CM承包模式使工程项目实现有条件的“边设计、边施工”", "D": "快速路径法施工并不适合CM承包模式"}, "answer": ["D"], "analysis": "CM (Construction Management)模式是指由建设单位委托一家CM单位承担项目管理工作，该CM单位以承包商身份进行施工管理，并在一定程度上影响工程设计活动，组织快速路径( Fast - Track)的生产方式，使工程项目实现有条件的\"边设计、边施工。CM模式特别适用于实施周期长、工期要求紧迫的大型复杂工程项目。采用CM模式，不仅有利于缩短工程项目建设周期，而且有利于控制工程质量和造价。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0744", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "从投资者角度看，既能回避建设过程风险，又能尽快取得收益的项目融资方式是（ ）。", "options": {"A": "BT", "B": "BOO", "C": "BOOT", "D": "TOT"}, "answer": ["D"], "analysis": "本题考查的是项目融资方式。根据题干中的“能回避建设过程风险，又能尽快取得收益”的要求，可以排除掉BT、BOO、BOOT三种方式，因为这三种方式都需要投资者承担建设过程中的风险。而TOT（Turnkey）方式是指投资者委托承包商全权负责项目的设计、建设、运营等全过程，投资者只需要在项目建成后取得收益，不需要承担建设过程中的风险，因此符合题目要求。因此，答案为D。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0745", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "以下关于工程代建制下代建单位责任的说法中，错误的表述是（ ）。", "options": {"A": "不参与项目前期决策", "B": "在项目建设过程中不承担管理咨询风险", "C": "不对项目运营期间资产保值增值负责", "D": "不对项目的投资收益负责"}, "answer": ["B"], "analysis": "本题考查的是工程项目实施模式。如果代建单位未能完全履行代建合同义务，擅自变更建设内容、扩大建设规模、提高建设标准，致使工期延长、投资增加或工程质量不合格，应承担所造成的损失或投资增加额，由此可见，代建单位要承担相应的管理、咨询风险。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0746", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "建设工程施工总承包单位依法将建设工程分包给其他单位的，关于安全生产责任的说法，正确的是（ ）。", "options": {"A": "分包合同中应当明确总、分包单位各自的安全生产方面的权力和义务", "B": "分包单位的安全生产责任由分包单位独立承担", "C": "总承包单位对分包单位的安全生产承担安全责任", "D": "总承包单位和分包单位对施工现场安全生产承担同等责任"}, "answer": ["A"], "analysis": "本题考查的是建设工程质量管理条例。总承包单位依法将建设工程分包给其他单位的，分包单位应当按照分包合同的约定对其分包工程的质量向总承包单位负责，总承包单位与分包单位对分包工程的质量承担连带责任。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0747", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "《建设工程安全生产管理条例》规定，不属于监理单位安全生产管理责任和义务的是（ ）。", "options": {"A": "编制安全技术措施及专项施工方案", "B": "审查安全技术措施及专项施工方案", "C": "报告安全生产事故隐患", "D": "承担建设工程安全生产监理责任"}, "answer": ["A"], "analysis": "本题考查的是建设工程质量管理条例。选项A应为施工单位的责任。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0748", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "在评标委员会组建过程中，下列做法符合规定的是（ ）。", "options": {"A": "评标委员会成员的名单在评标结束前保密", "B": "评标委员会七个成员中，招标人的代表有三名", "C": "项目评标专家从招标代理机构的专家库内的相关专家名单中随机抽取", "D": "评标委员会成员由二人组成"}, "answer": ["C"], "analysis": "本题考查的是招标投标法实施条例。依法必须进行招标的项目，其评标委员会由招标人的代表和有关技术、经济等方面的专家组成，成员人数为5人以上单数。其中技术、经济等方面的专家不得少于成员总数的2/3。评标委员会成员的名单在中标结果确定前应当保密。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0749", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "在施工合同履行中，如果建设单位拖欠工程款，经催告后在合理的期限内仍未支付，则施工企业可以主张（ ），然后要求对方赔偿损失。", "options": {"A": "撤销合同，无须通知对方", "B": "撤销合同，但应通知对方", "C": "解除合同，无须通知对方", "D": "解除合同，但应通知对方"}, "answer": ["D"], "analysis": "本题考查的是合同的变更、转让及终止。撤销合同的前提是这个合同是可变更可撤销合同而不是有效合同，对于有效合同来说只能是解除。所以选项AB错误。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0750", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "因违约行为造成损害高于合同约定的违约金，守约方可（ ）。", "options": {"A": "按合同约定违约金要求对方赔偿", "B": "按实际损失加上违约金要求对方赔偿", "C": "在原约定违约金基础上适当增加一定比例违约定金", "D": "请求法院增加超过违约金部分损失"}, "answer": ["D"], "analysis": "本题考查的是合同的变更、转让及终止。约定的违约金低于造成的损失的，当事人可以请求人民法院或者仲裁机构予以增加；约定的违约金过分高于造成的损失的，当事人可以请求人民法院或者仲裁机构予以适当减少。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0751", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "某工程施工合同对工程款付款时间约定不明，工程尚未交付、工程价款也未结算，现承包人起诉，发包人工程欠款的利息应从（ ）之日计付。", "options": {"A": "工程计划交付", "B": "提交竣工结算文件", "C": "当事人起诉", "D": "监理工程师暂定付款"}, "answer": ["C"], "analysis": "本题考查的是合同价款纠纷的处理。当事人对付款时间没有约定或者约定不明的，下列时间视为应付款时间：（1）建设工程已实际交付的，为交付之日；（2）建设工程没有交付的，为提交竣工结算文件之日；（3）建设工程未交付，工程价款也未结算的，为当事人起诉之日。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0752", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "根据最高人民法院有关司法解释，下列不予支持的诉讼请求是（ ）。", "options": {"A": "垫资工程款利息没有约定的情况下，承包人请求支付利息", "B": "施工合同无效，但工程竣工验收合格，承包人请求按合同约定支付工程价款", "C": "施工合同无效，已完工程质量合格，承包人请求按合同约定支付工程价款", "D": "施工合同无效，已完工程质量不合格但修复后工程验收合格，发包人请求承包人承担修复费用"}, "answer": ["A"], "analysis": "本题考查的是合同价款纠纷的处理。当事人对垫资利息没有约定，承包人请求支付利息的，不予支持。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0753", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "合同中当事人约定了违约金，也约定了定金。合同履行过程中发生违约后，（ ）。", "options": {"A": "未违约一方可以选择定金或违约金要求对方赔偿", "B": "违约一方可以选择定金或违约金承担违约赔偿责任", "C": "未违约方可以同时采用定金和违约金要求对方赔偿", "D": "违约金和定金的约定同时无效，需采用其他方式追究违约责任"}, "answer": ["A"], "analysis": "本题考查的是合同的变更、转让及终止。选项B的选择权在未违约的一方，选项C未违约一方可以选择定金或违约金要求对方赔偿而不能同时选择。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0754", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "关于建设工程施工合同价款纠纷的处理，下列说法中正确的是（ ）。", "options": {"A": "竣工验收不合格，经承包人修复后合格的，承包人支付修复费用的要求应予支持", "B": "竣工验收不合格，经承包人修复后合格的，修复费用应由承包人承担", "C": "竣工验收不合格，多次修复后仍不合格的，发包人应酌情给予承包人部分修复费用", "D": "安装后发现甲供设备存在质量问题，但承包人参与进场验收的，发包人不应支付承包人设备拆除、重新安装的费用"}, "answer": ["B"], "analysis": "本题考查的是合同价款纠纷的处理。建设工程经竣工验收不合格的，按照以下情形分别处理：（1）修复后的建设工程经竣工验收合格，发包人请求承包人承担修复费用的，应予支持。（2）修复后的建设工程经竣工验收不合格，承包人请求支付工程价款的，不予支持。因建设工程不合格造成的损失，发包人有过错的，也应承担相应的民事责任。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0755", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "依据《建设工程质量管理条例》的规定，以下工作中，应由总监理工程师签字认可的是（ ）。", "options": {"A": "建设单位拨付工程款", "B": "施工单位实施隐蔽工程", "C": "商品混凝土用于基础工程", "D": "大型非标构件进行吊装"}, "answer": ["A"], "analysis": "本题考查的是建设工程质量管理条例。未经总监理工程师签字，建设单位不得拨付工程款，不进行竣工验收。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0756", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "招标人以招标公告的方式邀请不特定的法人或者组织来投标，这种招标方式称为（ ）。", "options": {"A": "公开招标", "B": "邀请招标", "C": "议标", "D": "定向招标"}, "answer": ["A"], "analysis": "本题考查的是招标投标法。招标分为公开招标和邀请招标两种方式，招标人采用公开招标方式的，应当发布招标公告。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0757", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "通过招投标订立的建设工程施工合同，合同价应为（ ）。", "options": {"A": "评标价", "B": "投标报价", "C": "招标控制价", "D": "标底"}, "answer": ["B"], "analysis": "本题考查的是招标投标法实施条例。合同的标的、价款、质量、履行期限等主要条款应当与招标文件和中标人的投标文件的内容一致。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0758", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "《合同法》规定，承诺撤回的条件是，撤回承诺的通知应当在（ ）到达要约人。", "options": {"A": "要约到达受要约人之前", "B": "受要约人发出承诺通知之前", "C": "承诺通知到达要约人之前", "D": "受要约人发出承诺通知之后"}, "answer": ["C"], "analysis": "本题考查的是合同订立的程序。承诺可以撤回，撤回承诺的通知应当在承诺通知到达要约人之前或者与承诺通知同时到达要约人。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0759", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "依据《合同法》的规定，执行政府定价或政府指导价的合同，合同当事人一方逾期接受货物时，遇价格上涨，应（ ）。", "options": {"A": "按原价格执行", "B": "按新价格执行", "C": "按原价和新价格的平均执行", "D": "按市场价格执行"}, "answer": ["B"], "analysis": "本题考查的是合同的履行。《合同法》规定，执行政府定价或政府指导价的，在合同约定的交付期限内政府价格调整时，按照交付时的价格计价。逾期交付标的物的，遇价格上涨时，按照原价格执行；价格下降时，按照新价格执行。逾期提取标的物或者逾期付款的，遇价格上涨时，按照新价格执行，价格下降时，按照原价格执行。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0760", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "债权人决定将其债权债务一并转让给第三人时，（ ）。", "options": {"A": "需经对方同意", "B": "无需经对方同意，但应通知对方", "C": "无需经对方同意，也不必通知对方", "D": "需经对方同意，但要办理公证"}, "answer": ["A"], "analysis": "本题考查的是合同的变更、转让及终止。当事人一方经对方同意，可以将自己在合同中的权利和义务一并转让给第三人。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0761", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "甲公司是某项目的总承包单位，乙公司是该项目的建设单位指定的分包单位。在施工过程中，乙公司拒不服从甲公司的安全生产管理，最终造成安全生产事故，则（ ）。", "options": {"A": "甲公司负主要责任", "B": "乙公司负主要责任", "C": "乙公司负全部责任", "D": "监理公司负主要责任"}, "answer": ["B"], "analysis": "本题考查的是建设工程质量管理条例。分包单位应当服从总包单位的安全管理，如分包单位不服从管理导致生产安全事故，由分包单位承担主要责任。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0763", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "对于实施监理的工程，应由（ ）按照国家有关规定组织竣工验收。", "options": {"A": "工程监理单位", "B": "总监理工程师", "C": "建设单位", "D": "建设单位和工程监理单位共同"}, "answer": ["C"], "analysis": "建设单位收到建设工程竣工报告后，应当组织设计、施工、工程监理等有关单位进行竣工验收。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0764", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "批准开工报告的建筑工程，因故不能按期开工超过（ ）的，应重新办理开工报告的批准手续", "options": {"A": "3个月", "B": "6个月", "C": "1年", "D": "2年"}, "answer": ["B"], "analysis": "本题考查的是建筑法。按照国务院有关规定批准开工报告的建筑工程，因故不能按期开工或者中止施工的，应当及时向批准机关报告情况。因故不能按期开工超过6个月的，应当重新办理开工报告的批准手续。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0765", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "使用承租的机械设备和施工机具及配件的，由（ ），验收合格的方可使用。", "options": {"A": "由承租的施工单位验收", "B": "有出租单位验收", "C": "由总承包单位验收", "D": "由施工总承包单位、分包单位、出租单位和安装单位共同进行验收"}, "answer": ["D"], "analysis": "本题考查的是建设工程质量管理条例。如使用承租的机械设备和施工机具及配件，应由施工总承包单位、分包单位、出租单位和安装单位共同进行验收，验收合格后方可使用。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0766", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "招标人对已发出的招标文件进行修改的，应当在（ ）以书面形式通知所有招标文件收受人。", "options": {"A": "提交投标文件截止时间至少15日前", "B": "提交投标文件截止时间至少20日前", "C": "资格评审工作开始前15天", "D": "资格评审工作开始前20天"}, "answer": ["A"], "analysis": "本题考查的是招标投标法。招标人澄清或者修改的内容可能影响资格预审申请文件或者投标文件编制的，招标人应当在提交资格预审申请文件截止时间至少3日前，或者投标截止时间至少15日前，以书面形式通知所有获取资格预审文件或者招标文件的潜在投标人。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_1836", "date": "2026-07-10", "chapter": "g02", "type": "single", "stem": "对政府投资的非经营性项目，最适宜采用的建设实施组织方式是（ ）。", "options": {"A": "CM 模式", "B": "工程代建制", "C": "项目管理承包模式", "D": "项目总承包模式"}, "answer": ["B"], "analysis": "【考点来源】本题考查的是工程代建制【选项分析】根据《国务院关于加快投资体制改革的决定》（国发[2004]20号），对政府投资的非经营性项目应加快推行“代建制”。", "tags": [], "source": "二、业主方项目组织模式", "src": "好题库"}, {"id": "mgmt_hqwx_0157", "date": "2026-07-09", "chapter": "g02", "type": "single", "stem": "某房地产开发公司在某市老城区拟开发住宅项目涉及拆迁按照《建筑工程可管理办法》的规定，在以下有关房地产公司申领施工许可证前应具备的条件中,正确的是（ ）。", "options": {"A": "拆迁工作必须全部完成", "B": "拆迁补偿安置资金全部到位", "C": "拆迁工程量已完成50%", "D": "拆迁进度已符合施工的要求"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是《建筑法》相关内容 【选项分项】申请领取施工许可证，应当具备如下条件：①已办理建筑工程用地批准手续；②依法应当办理建设工程规划许可证的，已经取得建设工程规划许可证；③需要拆迁的，其拆迁进度符合施工要求；④已经确定建筑施工企业；⑤有满足施工需要的资金安排、施工图纸及技术资料；⑥有保证工程质量和安全的具体措施。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0158", "date": "2026-07-09", "chapter": "g02", "type": "single", "stem": "建设单位申领建筑工程施工许可证后，既不开工，又不申请延期或者超过延期时限的则（ ）", "options": {"A": "建筑施工许可证自行废止", "B": "由发证机关收回建筑施工许可证", "C": "由建设行政主管机关处以罚款", "D": "取消该建设项目"}, "answer": ["A"], "analysis": "【内容考查】本题考查的是《建筑法》相关内容 【选项分项】既不开工又不申请延期或者超过延期时限的，施工许可证自行废止。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0160", "date": "2026-07-09", "chapter": "g02", "type": "single", "stem": "建设单位的质量责任和义务，下列叙述错误的是（ ）。", "options": {"A": "建设单位应当将工程发包给具有相应资质等级的单位，不得将工程肢解发包", "B": "建设单位应当依法对工程建设项目的勘察、设计、施工、监理以及与工程建设有关的重要设备、材料等的采购进行招标", "C": "建设单位必须向有关的勘察、设计、施工、工程监理等单位提供与建设工程有关的原始资料。原始资料必须真实、准确、齐全", "D": "建设工程发包单位不得迫使承包方以低于成本的价格竞标，但可以压缩合理工期"}, "answer": ["D"], "analysis": "建设单位不得迫使承包方以低于成本的价格竞标，不得任意压缩合理工期。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0161", "date": "2026-07-09", "chapter": "g02", "type": "single", "stem": "以下不属于合同的形式的是（ ）。", "options": {"A": "书面形式", "B": "口头形式", "C": "混合形式", "D": "其他形式"}, "answer": ["C"], "analysis": "【内容考查】本题考查的是合同订立 【选项分项】当事人订立合同，有书面形式、口头形式和其他形式。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0162", "date": "2026-07-09", "chapter": "g02", "type": "single", "stem": "判断合同是否成立的依据是（ ）。", "options": {"A": "合同是否生效", "B": "合同是否产生法律约束力", "C": "要约是否生效", "D": "承诺是否生效"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是合同效力。 【选项分析】合同的成立，是指双方当事人依照有关法律对合同的内容进行协商并达成一致的意见。合同成立的判断依据是承诺是否生效。 合同生效，是指合同产生法律上的效力，具有法律约束力。 【名师点拨】考生需注意有些合同成立后，并非立即产生法律效力，而是需要其他条件成就之后，才开始生效。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0173", "date": "2026-07-09", "chapter": "g02", "type": "single", "stem": "某大中型建设项目实行开工报告制度，在办理开工报告后，因故无法按期开工，超过（ ），建设单位应当重新办理开工报告的批准手续。", "options": {"A": "2个月", "B": "12个月", "C": "3个月", "D": "6个月"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是《建筑法》相关内容 【选项分析】对于实行开工报告制度的建设工程，《建筑法》规定，按照国务院有关规定批准开工报告的建筑工程，因故不能按期开工或者中止施工的，应当及时向批准机关报告情况。因故不能按期开工超过6个月的，应当重新办理开工报告的批准手续。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0175", "date": "2026-07-09", "chapter": "g02", "type": "single", "stem": "合同订立过程中，属于要约失效的情形是（ ）。", "options": {"A": "承诺通知到达要约人", "B": "受要约人依法撤销承诺", "C": "要约人在承诺期限内未作出承诺", "D": "受要约人对要约内容做出实质性质变更"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是 合同订立 。 【选项分析】有下列情形之一的，要约失效： （1）拒绝要约的通知到达要约人； （2）要约人依法撤销要约； （3）承诺期限届满，受要约人未作出承诺； （4）受要约人对要约内容作出实质性变更。 承诺通知到达要约人说明承诺已经生效，自然要约已生效； 受要约人依法撤销承诺，承诺可以撤回但是不可以撤销； 要约人在承诺期限内未作出承诺 ，承诺是受要约人发出的而非要约人发出。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0182", "date": "2026-07-09", "chapter": "g02", "type": "single", "stem": "根据《国务院关于投资体制改革的决定》，对于采用投资补助，转贷和贷款贴息的政府投资项目，则只审批（ ）。", "options": {"A": "项目建议书", "B": "资金申请报告", "C": "开工报告", "D": "可行性研究报告"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是投资决策阶段工作内容 【选项分项】对于采用直接投资和资本金注入方式的政府投资项目，政府需要从投资决策的角度审批项目建议书和可行性研究报告，除特殊情况外，不再审批开工报告，同时还要严格审批其初步设计和概算；对于采用投资补助、转贷和贷款贴息方式的政府投资项目，则只审批资金申请报告。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0185", "date": "2026-07-09", "chapter": "g02", "type": "single", "stem": "不需开槽的工程，（ ）日期就是开工日期。", "options": {"A": "开始打桩", "B": "破土开槽", "C": "开始进行土方、石方工程", "D": "开始进行工程地质勘察"}, "answer": ["A"], "analysis": "【内容考查】本题考查的是建设实施阶段工作内容 【选项分析】不需开槽的工程，正式开始打桩的日期就是开工日期。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0186", "date": "2026-07-09", "chapter": "g02", "type": "single", "stem": "根据《国务院关于投资体制改革的决定》，企业投资建设《政府核准的投资项目目录》中的项目时，仅需向政府提交（ ）。", "options": {"A": "项目申请报告", "B": "项目可行性研究报告", "C": "项目开工报告", "D": "项目初步设计文件"}, "answer": ["A"], "analysis": "【内容考查】本题考查的是投资决策阶段工作内容 【选项分析】企业投资建设《政府核准的投资项目目录》中的项目时，仅需向政府提交项目申请报告，不再经过批准项目建议书、可行性研究报告和开工报告的程序。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0250", "date": "2026-07-09", "chapter": "g02", "type": "single", "stem": "为了实现工程造价的模拟计算和动态控制，可应用建筑信息建模（BIM）技术，在包含进度数据的建筑模型上加载费用数据而形成（ ）模型。", "options": {"A": "6D", "B": "5D", "C": "4D", "D": "3D"}, "answer": ["B"], "analysis": "应用BIM技术，可根据施工组织设计在3D建筑模型的基础上加施工进度形成4D模型模拟实际施工，从而通过确定合理的施工方案指导实际施工。此外，还可进一步加载费用数据，形成5D模型，从而实现工程造价的模拟计算。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "gl-g02-005", "date": "2026-07-08", "chapter": "g02", "type": "multiple", "stem": "关于工程项目组成的四个层次，下列说法正确的有（ ）。", "options": {"A": "单项工程具有独立的设计文件，竣工后可以独立发挥生产能力", "B": "单位工程一般不能独立发挥生产能力或使用效益", "C": "分部工程是按单位工程的各个部位或工种划分的", "D": "分项工程是计量计价的基本单元"}, "answer": ["A", "B", "C", "D"], "analysis": "四个选项均正确。单项工程可独立发挥生产能力；单位工程是单项工程的组成部分但不能独立发挥效益；分部工程按部位或工种划分（如地基基础、主体结构）；分项工程是造价计算的基本单元。掌握四个层次的定义和区别是工程项目管理的基础知识。", "tags": ["工程项目组成"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-006", "date": "2026-07-08", "chapter": "g02", "type": "multiple", "stem": "工程项目建设程序主要包括的阶段有（ ）。", "options": {"A": "决策阶段", "B": "设计阶段", "C": "招投标阶段", "D": "施工阶段"}, "answer": ["A", "B", "C", "D"], "analysis": "工程项目建设程序一般分为五个阶段：决策阶段->设计阶段->招投标阶段->施工阶段->竣工阶段（含投产使用）。每个阶段对应不同的造价管理文件和重点工作内容。四个选项均属于建设程序的阶段。", "tags": ["建设程序", "阶段划分"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-010", "date": "2026-07-08", "chapter": "g02", "type": "multiple", "stem": "工程项目建设程序各阶段对应编制的造价文件包括（ ）。", "options": {"A": "投资估算", "B": "设计概算", "C": "施工图预算", "D": "合同价"}, "answer": ["A", "B", "C", "D"], "analysis": "建设程序中6种主要造价文件与各阶段对应：决策阶段->投资估算；设计阶段（初步设计->设计概算、技术设计->修正概算、施工图设计->施工图预算）；招投标阶段->合同价；施工阶段->结算；竣工阶段->竣工决算。四个选项均为法定的造价管理文件。", "tags": ["建设程序", "造价文件"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-016", "date": "2026-07-08", "chapter": "g02", "type": "multiple", "stem": "工程项目管理的七大任务包括（ ）。", "options": {"A": "合同管理与信息管理", "B": "组织协调与目标控制", "C": "风险管理与安全管理", "D": "环境保护管理"}, "answer": ["A", "B", "C", "D"], "analysis": "工程项目管理的七大任务是：合同管理、信息管理、组织协调、目标控制（三控制）、风险管理、安全管理、环境保护管理。七大任务构成了施工管理的任务体系，涵盖了工程建设的全过程和全方位。", "tags": ["管理任务"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-019", "date": "2026-07-08", "chapter": "g02", "type": "multiple", "stem": "工程项目管理七大任务中“三控制”指的是（ ）。", "options": {"A": "质量控制", "B": "进度控制", "C": "投资控制", "D": "合同控制"}, "answer": ["A", "B", "C"], "analysis": "工程项目管理七大任务中的“目标控制”（三控制）是指质量控制、进度控制和投资控制。这三个控制目标相辅相成，构成工程项目管理的核心管控体系。合同管理、信息管理、风险管理等是独立的管理任务，不属于三控制范畴。", "tags": ["管理任务", "三控制"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-023", "date": "2026-07-08", "chapter": "g02", "type": "multiple", "stem": "关于EPC总承包模式的特点，下列说法正确的有（ ）。", "options": {"A": "总承包商承担设计、采购、施工全部责任", "B": "业主管理责任减轻，主要进行宏观管理", "C": "总承包商是承包模式中风险最大的责任主体", "D": "合同价格通常采用固定总价合同"}, "answer": ["A", "B", "C", "D"], "analysis": "EPC总承包模式的特点包括：(1)总承包商对设计、采购、施工全过程负责；(2)业主主要负责提出功能要求和宏观监督；(3)总承包商承担了大部分风险，是承包方风险最大的模式；(4)合同多采用固定总价方式，有利于投资控制。四个选项均正确。", "tags": ["实施模式", "EPC"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-028", "date": "2026-07-08", "chapter": "g02", "type": "multiple", "stem": "BOT模式的参与方通常包括（ ）。", "options": {"A": "项目发起人（政府或其授权机构）", "B": "项目公司（特许权公司）", "C": "贷款银行或金融机构", "D": "施工承包商和运营商"}, "answer": ["A", "B", "C", "D"], "analysis": "BOT模式涉及多方参与主体：政府或其授权机构作为项目发起人，授予特许经营权；项目公司（SPV）负责融资、建设、运营；贷款银行或金融机构提供项目融资；施工承包商承担建设任务；运营商负责特许期内的运营管理。BOT是多方协作的典型模式。", "tags": ["实施模式", "BOT"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-030", "date": "2026-07-08", "chapter": "g02", "type": "multiple", "stem": "下列工程项目实施模式中，属于项目融资模式的有（ ）。", "options": {"A": "BOT", "B": "EPC", "C": "PPP", "D": "TOT"}, "answer": ["A", "C", "D"], "analysis": "BOT、PPP和TOT均属于项目融资与实施相结合的模式，核心是通过引入私营资本解决公共基础设施建设的资金问题。EPC属于工程总承包模式，不涉及项目融资。注意区分项目融资模式和工程承包模式。", "tags": ["实施模式", "项目融资"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-032", "date": "2026-07-08", "chapter": "g02", "type": "multiple", "stem": "关于PPP模式的主要特点，下列说法正确的有（ ）。", "options": {"A": "公共部门与私营部门建立长期合作关系", "B": "风险和利益由双方合理分担和共享", "C": "项目建成后直接无偿移交政府", "D": "适用于基础设施和公共服务领域"}, "answer": ["A", "B", "D"], "analysis": "PPP模式的核心特征包括：政府与私营部门建立长期合作伙伴关系（通常20-30年），双方合理分担风险、共享利益，主要应用于基础设施和公共服务领域。C选项描述的是BOT模式的特点（特许期满后移交），并非PPP模式的必然要求。", "tags": ["实施模式", "PPP"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-035", "date": "2026-07-08", "chapter": "g02", "type": "multiple", "stem": "下列属于建设单位在施工阶段造价管理工作的有（ ）。", "options": {"A": "编制和审核工程预付款和进度款", "B": "处理工程变更和索赔", "C": "编制投资估算", "D": "办理工程结算"}, "answer": ["A", "B", "D"], "analysis": "施工阶段的造价管理工作包括：编制和审核工程预付款和进度款、处理工程变更和工程索赔、办理工程结算等。投资估算是决策阶段的工作，不是施工阶段的工作。施工阶段的造价管理核心是根据合同约定和实际施工情况，合理确定和调整工程价款。", "tags": ["建设程序", "施工阶段"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-038", "date": "2026-07-08", "chapter": "g02", "type": "multiple", "stem": "关于全过程工程咨询，下列说法正确的有（ ）。", "options": {"A": "提供覆盖项目全生命周期的工程咨询服务", "B": "整合了规划、设计、监理、造价、项目管理等多种服务", "C": "采用“一站式”服务模式，减少业主协调工作量", "D": "全过程工程咨询单位不能承担同一项目的施工任务"}, "answer": ["A", "B", "C", "D"], "analysis": "全过程工程咨询是整合各类工程咨询服务的综合性模式：覆盖全生命周期、整合多种专业服务、一站式解决业主需求。根据规定，全过程工程咨询单位不能与同一项目的施工承包单位有隶属关系或利害关系，更不能同时承担施工任务，以保证其独立性和公正性。", "tags": ["实施模式", "全过程工程咨询"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-043", "date": "2026-07-08", "chapter": "g02", "type": "multiple", "stem": "下列单位工程中属于一般土建工程的有（ ）。", "options": {"A": "基础工程", "B": "墙体工程", "C": "装饰工程", "D": "给排水工程"}, "answer": ["A", "B", "C"], "analysis": "一般土建工程作为一个单位工程，通常包括基础工程、墙体工程、混凝土及钢筋混凝土工程、装饰工程等。给排水工程属于安装工程，是与土建工程并列的另一个单位工程，不属于土建工程的组成部分。", "tags": ["工程项目组成", "单位工程"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-044", "date": "2026-07-08", "chapter": "g02", "type": "multiple", "stem": "与DBB传统模式相比，EPC总承包模式的优势包括（ ）。", "options": {"A": "缩短建设周期", "B": "减少业主管理协调工作量", "C": "责任主体单一明确", "D": "有利于投资控制"}, "answer": ["A", "B", "C", "D"], "analysis": "与DBB模式下设计施工分离需分阶段招标不同，EPC模式由总承包商统一负责设计、采购和施工，可实现设计施工深度交叉，缩短建设周期（A）；业主只需与总承包商签订一份合同，管理协调工作大幅减少（B）；责任主体由多头变为单一（C）；通常采用固定总价合同，有利于投资控制（D）。四个选项均为EPC相对DBB的优势。", "tags": ["实施模式", "EPC", "DBB"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g02-048", "date": "2026-07-08", "chapter": "g02", "type": "multiple", "stem": "工程项目环境保护管理的主要内容包括（ ）。", "options": {"A": "施工扬尘和噪声控制", "B": "建筑垃圾处理和资源化利用", "C": "施工废水处理", "D": "施工现场生态保护"}, "answer": ["A", "B", "C", "D"], "analysis": "环境保护管理是工程项目管理七大任务之一。主要内容包括：施工扬尘控制、噪声控制、建筑垃圾的分类和处理、施工废水的处理排放、施工现场及周边的生态保护等。环保管理应当贯穿于工程建设的全过程。", "tags": ["管理任务", "环保管理"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-024", "date": "2026-07-08", "chapter": "g02", "type": "multiple", "stem": "根据2025新版教材，工程项目管理的任务包括（ ）。", "options": {"A": "合同管理", "B": "组织协调", "C": "目标控制", "D": "风险管理", "E": "信息管理", "F": "环保与节能", "G": "安全生产"}, "answer": ["A", "B", "C", "D"], "analysis": "2025版教材工程管理任务为7项：合同管理、组织协调、目标控制、风险管理、信息管理、环保与节能、安全生产。注意多选题答案为部分选项的2-4个。", "tags": ["工程项目管理", "管理任务"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-028", "date": "2026-07-08", "chapter": "g02", "type": "multiple", "stem": "全过程工程咨询的服务内容包括（ ）。", "options": {"A": "投资咨询", "B": "勘察设计", "C": "招标代理", "D": "工程监理", "E": "工程造价", "F": "项目管理"}, "answer": ["A", "B", "C", "D"], "analysis": "全过程工程咨询服务内容：投资咨询、勘察设计、招标代理、工程监理、工程造价、项目管理等，整合传统碎片化咨询服务。", "tags": ["全过程工程咨询", "服务内容"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-029", "date": "2026-07-08", "chapter": "g02", "type": "multiple", "stem": "全过程工程咨询的主要优势包括（ ）。", "options": {"A": "整合碎片化服务", "B": "降低建设成本", "C": "缩短建设工期", "D": "提高工程质量"}, "answer": ["A", "B", "C", "D"], "analysis": "全过程工程咨询优势：整合碎片化服务、降低建设成本、缩短建设工期、提高工程质量。", "tags": ["全过程工程咨询", "优势"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-035", "date": "2026-07-08", "chapter": "g02", "type": "multiple", "stem": "常见的项目融资模式包括（ ）。", "options": {"A": "BOT", "B": "TOT", "C": "PFI", "D": "PPP", "E": "DBB"}, "answer": ["A", "B", "C", "D"], "analysis": "融资模式包括BOT、TOT、PFI、PPP。DBB（设计-招标-建造）是承发包模式，不属于融资模式。", "tags": ["项目融资模式", "分类"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-049", "date": "2026-07-08", "chapter": "g02", "type": "multiple", "stem": "关于EPC总承包模式，下列说法正确的有（ ）。", "options": {"A": "承包商承担绝大部分风险", "B": "通常采用固定总价合同", "C": "适合工艺性强的工业项目", "D": "设计施工深度整合"}, "answer": ["A", "B", "C", "D"], "analysis": "EPC特点：承包商承担绝大部分风险、固定总价为主、适合工艺性强项目、设计施工整合度高。", "tags": ["承发包模式", "EPC"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-050", "date": "2026-07-08", "chapter": "g02", "type": "multiple", "stem": "关于DBB模式，下列说法正确的有（ ）。", "options": {"A": "设计施工分离", "B": "按线性顺序进行", "C": "业主协调工作量较大", "D": "是最传统的承发包模式"}, "answer": ["A", "B", "C", "D"], "analysis": "DBB是最传统的模式，设计施工分离，线性顺序进行，业主协调工作量大。", "tags": ["承发包模式", "DBB"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-058", "date": "2026-07-08", "chapter": "g02", "type": "multiple", "stem": "以下属于三阶段设计的有（ ）。", "options": {"A": "方案设计", "B": "初步设计", "C": "技术设计", "D": "施工图设计", "E": "深化设计"}, "answer": ["B", "C", "D"], "analysis": "三阶段设计：初步设计→技术设计→施工图设计。方案设计属前期阶段，深化设计属施工图后补充。", "tags": ["建设程序", "设计阶段"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g02-065", "date": "2026-07-08", "chapter": "g02", "type": "multiple", "stem": "下列属于建设准备阶段工作内容的有（ ）。", "options": {"A": "征地拆迁", "B": "三通一平", "C": "招标", "D": "办理施工许可", "E": "可行性研究"}, "answer": ["A", "B", "C", "D"], "analysis": "建设准备阶段：征地拆迁→三通一平→招标→施工许可。可行性研究属决策阶段。", "tags": ["建设程序", "建设准备"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "ht_mgmt_0697", "date": "2026-07-10", "chapter": "g02", "type": "multiple", "stem": "实行法人责任制的建设项目，项目总经理的职责有（）。", "options": {"A": "负责筹措建设资金", "B": "负责提出项目竣工验收申请报告", "C": "组织编制项目初步设计文件", "D": "组织工程设计招标工作", "E": "负责生产准备工作和培训有关人员"}, "answer": ["C", "D", "E"], "analysis": "项目总经理的职权有：组织编制项目初步设计文件，对项目工艺流程、设备选型、建设标准、总图布置提出意见，提交董事会审查；组织工程设计、施工监理、施工队伍和设备材料采购的招标工作，编制和确定招标方案、标底和评标标准，评选和确定投标、中标单位。实行国际招标的项目，按现行规定办理；编制并组织实施项目年度投资计划、用款计划、建设进度计划；编制项目财务预算、决算；编制并组织实施归还贷款和其他债务计划；组织工程建设实施，负责控制工程投资、工期和质量。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0698", "date": "2026-07-10", "chapter": "g02", "type": "multiple", "stem": "在办理建设工程质量监督注册手续时需提供的材料有（）。", "options": {"A": "监理合同", "B": "中标通知书", "C": "施工图", "D": "施工合同", "E": "施工图设计文件审查报告和批准书"}, "answer": ["A", "B", "D", "E"], "analysis": "办理质量监督注册手续时需提供下列资料:①施工图设计文件审查报告和批准书;②中标通知书和施工、监理合同;③建设单位、施工单位和监理单位工程项目的负责人和机构组成;④施工组织设计和监理规划（监理实施细则);⑤其他需要的文件资料。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0699", "date": "2026-07-10", "chapter": "g02", "type": "multiple", "stem": "根据《建设工程监理范围和规模标准规定》必须实行监理制的为（）。", "options": {"A": "大中型工程项目", "B": "利用外国政府或者国际组织贷款、援助资金的工程", "C": "国家重点建设工程", "D": "某住宅小区工程", "E": "某公司自用的办公楼"}, "answer": ["B", "C"], "analysis": "根据《建设工程监理范围和规模标准规定》下列建设工程必须实行监理:①国家重点建设工程;②大中型公用事业工程;③成片开发建设的住宅小区工程;④利用外国政府或者国际组织贷款、援助资金的工程;⑤国家规定必须实行监理的其他工程。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0700", "date": "2026-07-10", "chapter": "g02", "type": "multiple", "stem": "建设工程项目采用Partnering模式的特点有()。", "options": {"A": "Partnering协议是工程建设参与各方共同签署的协议", "B": "Partnering协议是工程合同文件的组成部分", "C": "Partnering模式需要工程建设参与各方高层管理者的参与", "D": "Partnering模式强调资源共享和风险分担", "E": "Partnering模式可以独立于其他承包模式而存在"}, "answer": ["A", "C", "D"], "analysis": "Partnering模式的主要特征：(1)出于自愿。Partnering协议并不仅仅是建设单位与承包单位之间的协议，而需要工程建设参与各方共同签署，包括建设单位、总承包单位、主要的分包单位、设计单位、咨询单位、主要的材料设备供应单位等。参与Partnering模式的有关各方必须是完全自愿，而非出于任何原因的强迫。 (2)高层管理的参与。由于Partnering模式需要参与各方共同组成工作小组，要分担风险、共享资源，因此，高层管理者的认同、支持和决策是关键因素。 (3)Partnering协议不是法律意义上的合同。Partnering协议与工程合同是两个完全不同的文件。在工程合同签订后，工程建设参与各方经过讨论协商后才会签署Partnering协议。该协议并不改变参与各方在有关合同中规定的权利和义务，主要用来确定参与各方在工程建设过程中的共同目标、任务分工和行为规范。 (4)信息的开放性。Partnering模式强调资源共享，信息作为一种重要的资源，对于参与各方必须公开。同时，参与各方要保持及时、经常和开诚布公的沟通，在相互信任的基础上，要保证工程造价、进度、质量等方面的信息能为参与各方及时、便利地获取。 值得指出的是，Partnering模式不是一种独立存在的模式，它通常需要与工程项目其他组织模式中的某一种结合使用，如总分包模式、平行承包模式、CM承包模式等。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0701", "date": "2026-07-10", "chapter": "g02", "type": "multiple", "stem": "对业主而言，建设工程采用平行承包模式的特点有()。", "options": {"A": "选择承包商的范围大", "B": "组织协调工作量小", "C": "合同结构简单", "D": "工程招标任务量大", "E": "工程造价控制难度大"}, "answer": ["A", "D", "E"], "analysis": "采用平行承包模式的特点： (1)有利于业主择优选择承包商。由于合同内容比较单一、合同价值小、风险小，对不 具备总承包管理能力的中小承包商较为有利，使他们有可能参与竞争。业主可以在更大范围 内选择承包商。 (2)有利于控制工程质量。整个工程经过分解分别发包给各承包商，合同约束与相互制 约使每一部分能够较好地实现质量要求。如主体工程与装修工程分别由两个施工单位承包， 当主体工程不合格时，装修单位不会同意在不合格的主体工程上进行装修，这相当于有了他 人控制，比自己控制更有约束力。 (3)有利于缩短建设工期。由于设计和施工任务经过分解分别发包，设计与施工阶段有 可能形成搭接关系，从而缩短整个项目的建设工期。 (4)组织管理和协调工作量大。由于合同数量多，使项目系统内结合部位数量增加，要 求业主及其委托的监理单位具有较强的组织协调能力。 (5)工程造价控制难度大。一是由于总合同价不易短期确定，从而影响工程造价控制的 实施；二是由于工程招标任务量大，需控制多项合同价格，从而增加了工程造价控制 的难度。 (6)相对于总承包模式而言，平行承包模式不利于发挥那些技术水平高、综合管理能力 强的承包商的综合优势。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0702", "date": "2026-07-10", "chapter": "g02", "type": "multiple", "stem": "建设工程设计与施工采用总分包模式的特点有()。", "options": {"A": "对总承包商要求高，业主选择范围小", "B": "总包合同价格可较早确定，合同金额较低", "C": "业主的合同结构简单，组织协调工作量小", "D": "工程设计与施工有机融合，有利于缩短建设工期", "E": "分包单位多，弱化了工程质量控制工作"}, "answer": ["A", "C", "D"], "analysis": "采用总分包模式的特点： (1)有利于项目的组织管理。由于业主只与总承包商签订合同，合同结构简单。同时， 由于合同数量少，使得业主的组织管理和协调工作量小，可发挥总承包商多层次协调的 积极性。 (2)有利于控制工程造价。由于总包合同价格可以较早确定，业主可以承担较少风险。 (3)有利于控制工程质量。由于总承包商与分包商之间通过分包合同建立了责、权、利 关系，在承包商内部，工程质量既有分包商的自控，又有总承包商的监督管理，从而增加了 工程质量监控环节。 (4)有利于缩短建设工期。在工程设计与施工总承包的情况下，由于设计与施工由一个 单位统筹安排，使两个阶段能够有机地融合，一般均能做到设计阶段与施工阶段的相互 搭接。 (5)对业主而言，选择总承包商的范围小，一般合同金额较高。 (6)对总承包商而言，责任重、风险大，需要具有较高的管理水平和丰富的实践经验。 当然，获得高额利润的潜力也比较大。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0703", "date": "2026-07-10", "chapter": "g02", "type": "multiple", "stem": "根据《关于实行建设项目法人责任制的暂行规定》，建设项目总经理的职权有()。", "options": {"A": "组织编制初步设计文件", "B": "组织工程设计招标", "C": "审批项目财务预算", "D": "组织单项工程预验收", "E": "编制项目财务决算"}, "answer": ["A", "B", "D", "E"], "analysis": "选项C不属于建设项目总经理职责。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0704", "date": "2026-07-10", "chapter": "g02", "type": "multiple", "stem": "根据《国务院关于投资体制改革的决定》，对于企业不使用政府资金投资建设的项目，应区别不同情况实行()。", "options": {"A": "审批制", "B": "核准制", "C": "备案制", "D": "报建制", "E": "核查制"}, "answer": ["B", "C"], "analysis": "非政府投资项目实行核准制或登记备案制", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0705", "date": "2026-07-10", "chapter": "g02", "type": "multiple", "stem": "项目法人责任制由项目法人对()等实行全过程负责。", "options": {"A": "项目策划", "B": "资金筹措", "C": "建设实施", "D": "生产经营", "E": "资产核算"}, "answer": ["A", "B", "C", "D"], "analysis": "本题考查的是工程项目管理的类型、任务及相关制度。项目法人责任制是指国有大中型项目在建设阶段就按现代企业制度组建项目法人，由项目法人对项目策划、资金筹措、建设实施、生产经营、债务偿还和资产的保值增值，实行全过程负责。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0706", "date": "2026-07-10", "chapter": "g02", "type": "multiple", "stem": "根据《国务院关于投资体制改革的决定》（国发 [2004] 20号），关于政府投资项目，下列说法错误的是（）。", "options": {"A": "对于采用直接投资的政府投资项目，政府只需审批开工报告", "B": "对于采用投资补助、转贷和贷款贴息方式的政府投资项目，则只审批资金申请报告", "C": "政府投资项目一般都要经过符合资质要求的咨询中介机构的评估论证，特别重大的项目还应实行专家评议制度", "D": "对于采用资本金注入方式的政府投资项目，政府需要从投资决策的角度审批项目建议书和可行性研究报告，所有情况均不再审批开工报告", "E": "政府投资项目只实行审批制"}, "answer": ["A", "D"], "analysis": "对于采用直接投资和资本金注入方式的政府投资项目，政府需要从投资决策的角度审批项目建议书和可行性研究报告，除特殊情况外，不再审批开工报告，", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0707", "date": "2026-07-10", "chapter": "g02", "type": "multiple", "stem": "根据《国务院关于投资体制改革的决定》，只需审批资金申请报告的政府投资项目是指采用()方式的项目。", "options": {"A": "直接投资", "B": "资本金注入", "C": "投资补助", "D": "转贷", "E": "贷款贴息"}, "answer": ["C", "D", "E"], "analysis": "对于采用直接投资和资本金注入方式的政府投资项目，政府需要从投资决策的角度审批项目建议书和可行性研究报告，除特殊情况外不再审批开工报告，同时还要严格审批其初步设计和概算；对于采用投资补助、转贷和贷款贴息方式的政府投资项目，则只审批资金申请报告。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0708", "date": "2026-07-10", "chapter": "g02", "type": "multiple", "stem": "BIM技术在工程造价管理信息化方面的意义包括()。", "options": {"A": "提高工程量计算的准确性", "B": "合理安排资源计划", "C": "控制工程造价", "D": "有效支持多算对比", "E": "积累和共享历史数据"}, "answer": ["A", "B", "D", "E"], "analysis": "本题考查的是工程项目管理的类型、任务及相关制度。BIM技术在工程造价管理信息化方面的意义：①提高工程量计算的准确性；②合理安排资源计划；③控制工程设计变更；④有效支持多算对比；⑤积累和共享历史数据。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0709", "date": "2026-07-10", "chapter": "g02", "type": "multiple", "stem": "建设工程采用平行承包模式时，建设单位控制工程造价难度大的原因有（）。", "options": {"A": "合同价值小，建设单位选择承包单位的范围小", "B": "合同数量多，组织协调工作量大", "C": "总合同价不易在短期内确定，影响造价控制的实施", "D": "建设周期长，增加时间成本", "E": "工程招标任务量大，需控制多项合同价格"}, "answer": ["C", "E"], "analysis": "本题考查的是工程项目发承包模式。平行承包模式的特点之一，工程造价控制难度大，一是由于总合同价不易短期确定，从而影响工程造价控制的实施；二是由于工程招标任务量大，需控制多项合同价格，从而增加工程造价控制的难度。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0710", "date": "2026-07-10", "chapter": "g02", "type": "multiple", "stem": "采用控制图法控制生产过程质量时，说明点子在控制界限内排列有缺陷的情形有（）。", "options": {"A": "点子连续在中心线一侧出现7 个以上", "B": "连续7 个以上的点子上升或下降", "C": "连续11 个点子落在一倍标准偏差控制界限之外", "D": "点子落在两倍标准偏差控制界限之外", "E": "点子落在三倍标准偏差控制界限附近"}, "answer": ["A", "B"], "analysis": "点子在控制界限内排列有缺陷，包括以下几种情况：1)点子连续在中心线一侧出现7 个 以上;2)连续7 个以上的点子上升或下降;3)点子在中心线一侧多次出现，如连续11 个点中至少有10 个点在同一侧;或连续14 点中至少有12 点、连续17 点中至少有14 点、连续20 点中至少有16点出现在同一侧;4)点子接近控制界限，如连续3 个点中至少有2 个点落在二倍标准偏差与三倍标准与三倍标准偏差控制界限之间;5)点子出现周期性波动", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0711", "date": "2026-07-10", "chapter": "g02", "type": "multiple", "stem": "与相同，香蕉曲线同样可用来控制工程造价和工程进度。下列项目目标控制方法中，可用于控制工程质量的有（）。", "options": {"A": "S 曲线法", "B": "控制图法", "C": "排列图法", "D": "直方图法", "E": "横道图法"}, "answer": ["B", "C", "D"], "analysis": "排列图又叫主次因素分析图或帕累特（Pareto）图，是用来寻找影响工程（产品）质量主要因素的一种有效工具。直方图又叫频数分布直方图。它以直方图形的高度表示一定范围内数值所发生的频数，据此可掌握产品质量的波动情况，了解质量特征的分布规律，以便对质量状况进行分析判断。前述排列图法、直方图法是质量控制的静态分析方法，控制图法就是一种典型的动态分析方法。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0712", "date": "2026-07-10", "chapter": "g02", "type": "multiple", "stem": "下列建设工程项目目标控制方法中，可用来判断工程进度偏差的有（）。", "options": {"A": "直方图法", "B": "网络计划法", "C": "S 曲线法", "D": "香蕉曲线法", "E": "控制图法"}, "answer": ["B", "C", "D"], "analysis": "网络计划法、S 曲线法、香蕉曲线法主要用来判断工程进度偏差。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0713", "date": "2026-07-10", "chapter": "g02", "type": "multiple", "stem": "建设单位编制的工程项目建设总进度计划包括的内容有（）。", "options": {"A": "竣工投产交付使用计划表", "B": "工程项目一览表", "C": "年度建设资金平衡表", "D": "工程项目进度平衡表", "E": "投资计划年度分配表"}, "answer": ["B", "D", "E"], "analysis": "本题考查的是工程项目建设总进度计划。工程项目建设总进度计划的表格部分包括工程项目一览表、工程项目总进度计划、投资计划年度分配表和工程项目进度平衡表。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0714", "date": "2026-07-10", "chapter": "g02", "type": "multiple", "stem": "(2013年)关于强矩阵制组织形式的说法，正确的有()。", "options": {"A": "项目经理具有较大权限", "B": "需要配备训练有素的协调人员", "C": "项目组织成员绩效完全由项目经理考核", "D": "适用于技术复杂且对时间紧迫的项目", "E": "项目经理直接向最高领导负责"}, "answer": ["A", "C", "D", "E"], "analysis": "强矩阵制项目经理由企业最高领导任命，并全权负责项目。项目经理直接向最高领导负责，项目组成员的绩效完全由项目经理进行考核，项目组成员只对项目经理负责。特点是项目经理以及专职项目管理人员拥有专职的、具有较大权限，适用于技术复杂且时间紧迫的工程项目。选项B属于中矩阵的组织形式。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0715", "date": "2026-07-10", "chapter": "g02", "type": "multiple", "stem": "(2010年)建设工程建设与施工采用总分包模式的特点有()。", "options": {"A": "对总承包商要求高，业主选择范围小", "B": "总承包合同价格可较早确定，合同金额较低", "C": "业主的合同结构简单，组织协调工作量小", "D": "工程设计与施工有机融合，有利于缩短建设工期", "E": "分包单位多，弱化了工程质量控制工作"}, "answer": ["A", "C", "D"], "analysis": "采用总分包模式的特点：①有利于项目的组织管理；②有利于控制工程造价；③有利于控制工程质量；④有利于缩短建设工期；⑤对业主而言，选择总承包商的范围小，一般合同金额较高；⑥对总承包商而言，责任重、风险大，需要具有较高的管理水平和丰富的实践经验。当然，获得高额利润的潜力也比较大。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0716", "date": "2026-07-10", "chapter": "g02", "type": "multiple", "stem": "(2011年)建设工程施工联合体承包模式的特点有()。", "options": {"A": "业主的合同结构简单，组织协调工作量小", "B": "通过联合体内部合同约束，增加了工程质量监控环节", "C": "施工合同总价可以较早确定，业主可承担较少风险", "D": "施工合同风险大，要求各承包商有较高的综合管理水平", "E": "能够集中联合体成员单位优势，增强抗风险能力"}, "answer": ["A", "E"], "analysis": "采用联合体承包模式的特点：（l）对建设单位而言，与总分包模式相同，合同结构简单，组织协调工作量小，而且有利于工程造价和建设工期的控制。 (2）对联合体而言，可以集中各成员单位在资金、技术和管理等方面的优势，克服单一公司力不能及的困难，不仅可增强竞争能力，而且也可增强抗风险能力。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0717", "date": "2026-07-10", "chapter": "g02", "type": "multiple", "stem": "(2010年)应用控制图法控制生产过程质量时，表明点子在控制界限内排列有缺陷的有()。", "options": {"A": "点子连续在中心线一侧出现5个以上", "B": "连续7个以上的点子上升或下降", "C": "连续7个点中至少有5个点在同一侧", "D": "连续3个点落在两倍标准偏差与三倍标准偏差控制界限之间", "E": "点子出现周期性波动"}, "answer": ["B", "D", "E"], "analysis": "点子在控制界限内排列有缺陷，包括以下几种情况：①点子连续在中心线一侧出现7个以上；②连续7个以上的点子上升或下降；③点子在中心线一侧多次出现，如连续11个点中至少有10个点在同一侧；或连续14点中至少有12点、连续17点中至少有14点、连续20点中至少有16点出现在同一侧；④点子接近控制界限，如连续3个点中至少有2个点落在二倍标准偏差与三倍标准偏差控制界限之间；或连续7点中至少有3点、连续10点中至少有4点落在二倍标准偏差与三倍标准偏差控制界限之间；⑤点子出现周期性波动。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0718", "date": "2026-07-10", "chapter": "g02", "type": "multiple", "stem": "(2012年)采用频数分布直方图分析工程质量波动情况时，如果出现孤岛型分布，说明()。", "options": {"A": "数据分组不当", "B": "少量材料不合格", "C": "组距确定不当", "D": "短时间内工人操作不熟练", "E": "两个分布相混淆"}, "answer": ["B", "D"], "analysis": "3）孤岛型分布。出现孤立的小直方图， 这是由于少量材料不合格， 或短时间内工人操作不熟练所造成。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0719", "date": "2026-07-10", "chapter": "g02", "type": "multiple", "stem": "(2015年)下列项目目标控制方法中，可用于控制工程质量的有( )。", "options": {"A": "S曲线法", "B": "控制图法", "C": "排列图法", "D": "直方图法", "E": "横道图法"}, "answer": ["B", "C", "D"], "analysis": "本题考查的是建设工程质量管理条例。7.控制图法 前述排列图法、直方图法是质量控制的静态分析方法，反映的是质量在某一段时间里的静止状态。因此，在质量控制中但用静态分析方法是不够的，还必须有动态分析方法。控制图法就是典型的动态分析方法。S曲线法和横道图法可以控制工程进度，不能控制工程质量。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0767", "date": "2026-07-10", "chapter": "g02", "type": "multiple", "stem": "分项工程是分部工程的组成部分，一般按（ ）等进行划分。", "options": {"A": "主要工种", "B": "材料", "C": "施工工艺", "D": "设备类别", "E": "专业性质"}, "answer": ["A", "B", "C", "D"], "analysis": "分项工程是指将分部工程按主要工种、材料、施工工艺、设备类别等划分的工程。例如，土方开挖、土方回填、钢筋、模板、混凝土、砖砌体、木门窗制作与安装、钢结构基础等工程均属于分项工程。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0768", "date": "2026-07-10", "chapter": "g02", "type": "multiple", "stem": "工程项目全部建完，经过各单位工程的验收，符合设计要求，并具备（ ）等必要文件资料后，由项目主管部门或建设单位向负责验收的单位提出竣工验收申请报告。", "options": {"A": "竣工图", "B": "竣工决算", "C": "工程总结", "D": "实地查验建筑安装工程实体", "E": "考核投资效益"}, "answer": ["A", "B", "C"], "analysis": "工程项目全部建完，经过各单位工程验收，符合设计要求，并具备竣工图、竣工决算、工程总结等必要文件资料，由项目主管部门或建设单位向负责验收的单位提出竣工验收申请报告。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0769", "date": "2026-07-10", "chapter": "g02", "type": "multiple", "stem": "建设单位应认真做好工程竣工验收的准备工作，主要内容包括（ ）。", "options": {"A": "整理技术资料", "B": "绘制竣工图", "C": "技术准备", "D": "生产运营管理", "E": "编制竣工决算"}, "answer": ["A", "B", "E"], "analysis": "工程竣工验收准备工作主要包括： 1)整理技术资料。技术资料主要包括土建施工、设备安装方面及各种有关的文件、合同和试生产情况报告等。 2)绘制竣工图。工程项目竣工图是真实记录各种地下、地上建筑物等详细情况的技术文件，是对工程进行交工验收、维护、扩建、改建的依据，同时也是使用单位长期保存的技术资料。 3)编制竣工决算。建设单位必须及时清理所有财产、物资和未用完或应收回的资金，编制工程竣工决算，分析概(预)算执行情况，考核投资效益，报请主管部门审查。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0770", "date": "2026-07-10", "chapter": "g02", "type": "multiple", "stem": "对于生产性建设工程项目而言，生产准备是项目建设转入生产经营的必要条件，生产准备工作一般应包括（ ）。", "options": {"A": "招收和培训生产人员", "B": "组织准备", "C": "技术准备", "D": "物资准备", "E": "销售准备"}, "answer": ["A", "B", "C", "D"], "analysis": "工程项目或企业不同，生产准备工作的内容各不相同，但一般应包括以下内容： (1)招收和培训生产人员。招收项目运营所需要的人员，并采用多种方式进行培训。特别要组织生产人员参加设备的安装、调试和工程验收工作，使其能尽快掌握生产技术和工艺流程。 (2)组织准备。主要包括生产管理机构设置、管理制度和有关规定的制定、生产人员配备等。 (3)技术准备。主要包括国内装置设计资料的汇总，有关国外技术资料的翻译、编辑、各种生产方案、岗位操作法编制及新技术准备等。 (4)物资准备。主要包括落实原材料、协作产品、燃料、水、电、气等的来源和其他需协作配合条件，并组织工装、器具、备品、备件等制造或订货。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0771", "date": "2026-07-10", "chapter": "g02", "type": "multiple", "stem": "建设工程项目按项目的投资效益和市场需求分为（ ）。", "options": {"A": "公益性项目", "B": "经营性项目", "C": "竞争性项目", "D": "基础性项目", "E": "非经营性项目"}, "answer": ["A", "C", "D"], "analysis": "工程项目按投资效益和市场需求划分为竞争性项目、基础性项目和公益性项目。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0772", "date": "2026-07-10", "chapter": "g02", "type": "multiple", "stem": "根据《建筑工程施工质量验收统一标准》，分部工程可按（ ）划分。", "options": {"A": "施工工艺", "B": "建筑部位", "C": "材料种类", "D": "专业性质", "E": "材料"}, "answer": ["B", "D"], "analysis": "本题考查的是工程项目管理概述。分部工程是指将单位工程按专业性质、建筑部位等划分的工程。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0773", "date": "2026-07-10", "chapter": "g02", "type": "multiple", "stem": "建设单位在办理质量监督手续时须提交的资料有（ ）", "options": {"A": "施工图设计文件审查报告和批准书", "B": "施工、监理合同", "C": "工程勘察成果及设计图纸", "D": "监理规划和施工组织设计", "E": "批准立项的文件"}, "answer": ["A", "B", "D"], "analysis": "本题考查建设单位在办理质量监督手续时需要提交的资料。根据建设工程质量管理条例的规定，建设单位在办理质量监督手续时，需要提交施工图设计文件审查报告和批准书、施工、监理合同、监理规划和施工组织设计等资料。因此，本题的正确答案为ABD。选项C和E虽然也是建设工程中的重要资料，但并不是建设单位在办理质量监督手续时必须提交的资料。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0774", "date": "2026-07-10", "chapter": "g02", "type": "multiple", "stem": "根据《建筑工程施工质量验收统一标准》，当分部工程较大时，可按（ ）将分部工程划分为若干子分部工程。", "options": {"A": "专业性质", "B": "施工工艺", "C": "施工程序", "D": "材料种类", "E": "工艺特点"}, "answer": ["C", "D", "E"], "analysis": "本题考查的是工程项目管理概述。当分部工程较大或较复杂时，可按材料种类、工艺特点、施工程序、专业系统及类别等划分为若干子分部工程。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0775", "date": "2026-07-10", "chapter": "g02", "type": "multiple", "stem": "根据现行有关规定，建设项目经批准开工建设后，其正式开工时间应是（ ）的时间。", "options": {"A": "任何一项永久性工程第一次正式破土开槽", "B": "水库等工程开始进行测量放线", "C": "在不需要开槽的情况下正式开始打桩", "D": "公路工程开始进行现场准备", "E": "铁路工程开始进行土石方工程"}, "answer": ["A", "C", "E"], "analysis": "本题考查的是工程项目管理概述。开工时间：（1）永久性工程，破土开槽；（2）无需开槽，打桩；（3）铁路、公路、水库等以土石方工程。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0776", "date": "2026-07-10", "chapter": "g02", "type": "multiple", "stem": "下列关于工程代建制和项目法人责任制的说法，正确的是（）。", "options": {"A": "对于实施工程代建制的项目,工程代建单位不负责建设资金的筹措", "B": "对于实施项目法人责任制的项目,项目法人的责任范围只是在工程项目建设实施阶段", "C": "对于实施工程代建制的项目不负责项目运营期间的资产保值增值", "D": "建设期间，工程代建单位不承担任何风险", "E": "工程代建制适用于政府投资的经营性项目"}, "answer": ["A", "C"], "analysis": "对于实施工程代建制的项目，工程代建单位不负责建设资金的筹措，因此也不负责偿还贷款。选项A正确；对于实施工程代建制的项目，代建单位的责任范围只是在工程项目建设实施阶段。因此选项B错误；对于实施工程代建制的项目，工程代建单位仅负责项目建设期间资金的使用，在批准的投资范围内保证建设工程项目实现预期功能，使政府投资效益最大化，不负责项目运营期间的资产保值增值。因此选项C正确；代建单位要承担相应的管理、咨询风险，因此选项D错误，工程代建制适用于政府投资的非经营性项目（主要是公益性项目）。选项E错误。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0777", "date": "2026-07-10", "chapter": "g02", "type": "multiple", "stem": "总承包单位依法将建设工程分包给其他单位施工，若分包工程出现质量问题时，应当由（ ）。", "options": {"A": "总承包单位向建设单位承担责任", "B": "分包单位单独向建设单位承担责任", "C": "总承包单位与分包单位向建设单位承担连带责任", "D": "总承包单位与分包单位分别向建设单位承担责任", "E": "分包单位向总承包单位承担责任"}, "answer": ["A", "C", "E"], "analysis": "本题考查的是建设工程质量管理条例。若分包工程出现质量问题时，总承包单位与分包单位向建设单位承担连带责任，总承包单位向建设单位承担责任，分包单位向总承包单位承担责任。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "ht_mgmt_0778", "date": "2026-07-10", "chapter": "g02", "type": "multiple", "stem": "根据《建设工程质量管理条例》，最低保修期限不低于2年的工程有（ ）。", "options": {"A": "外墙防渗漏", "B": "设备安装", "C": "给排水管道", "D": "防水工程", "E": "装修工程"}, "answer": ["B", "C", "E"], "analysis": "本题考查的是建设工程质量管理条例。最低保修期限不低于2年的工程有电气管道、给排水管道、设备安装和装修工程。", "tags": [], "source": "第二章  工程项目管理", "src": "好题库"}, {"id": "mgmt_hqwx_0178", "date": "2026-07-09", "chapter": "g02", "type": "multiple", "stem": "根据《民典法》，合同生效后，合同履行中关于价格确定是说法中正确的有（ ）。", "options": {"A": "当事人就价款约定不明确又未能补充协议的，合同价款应按订立合同时履行地市场价格执行", "B": "当事人就价款约定不明确又未能补充协议的，合同价款应按订立合同时付款方所在地市场价格", "C": "在执行政府定价的合同履行中，逾期付款的，遇价格上涨时按新价格执行", "D": "在执行政府定价的合同履行中，逾期交付标的物的，遇价格上涨时，按照原价格执行", "E": "在执行政府定价的合同履行中，逾期提取标的物的，遇价格下降时按原价格执行"}, "answer": ["A", "C", "D", "E"], "analysis": "价款或者报酬不明确的，按照订立合同时履行地的市场价格履行；依法应当执行政府定价或者政府指导价的，按照规定履行。逾期提取标的物或者逾期付款的，遇价格上涨时，按照新价格执行；价格下降时，按照原价格执行。逾期交付标的物的，遇价格上涨时，按照原价格执行；价格下降时，按照新价格执行。逾期提取标的物或者逾期付款的，遇价格上涨时，按照新价格执行，价格下降时，按照原价格执行。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0179", "date": "2026-07-09", "chapter": "g02", "type": "multiple", "stem": "根据《合同法》，下列属于合同转让情形的有（ ）", "options": {"A": "权利（债权）转让", "B": "协议转让", "C": "义务（债务）转移", "D": "法定转让", "E": "权利义务概括转让"}, "answer": ["A", "C", "E"], "analysis": "【选项分析】合同的转让包括权利（债权）转让、义务（债务）转移和权利义务概括转让三种情形。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0181", "date": "2026-07-09", "chapter": "g02", "type": "multiple", "stem": "下列关于建设工程项目管理类型的论述中，正确的是（ ）。", "options": {"A": "业主方的项目管理是全过程的项目管理", "B": "工程总承包方的项目管理是指项目施工安装阶段的项目管理", "D": "设计方的项目管理应该延伸到项目的施工阶段和竣工验收阶段", "E": "设计方的项目管理包括项目的施工质量、成本、工期、安全和环境保护目标"}, "answer": ["A", "B", "D"], "analysis": "【内容考查】本题考查的是工程项目管理类型和内容 【选项分项】工程总承包方的项目管理贯穿与项目实施全过程，既包括工程设计阶段，也包括工程施工阶段，故选项C错误；施工方的项目管理的目标体系包括项目施工质量、成本、进度、安全和环保目标。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0183", "date": "2026-07-09", "chapter": "g02", "type": "multiple", "stem": "建设项目实施阶段的工作内容有（ ）。【陕西·2019】", "options": {"A": "建设准备", "B": "工程设计", "C": "项目建议书", "D": "竣工验收", "E": "项目后评价"}, "answer": ["A", "B", "D"], "analysis": "【考点来源】本题考查的是实施阶段工作内容 【选项分析】建设实施阶段工作内容有：工程设计、建设准备、施工安装、生产准备、竣工验收。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0201", "date": "2026-07-09", "chapter": "g02", "type": "multiple", "stem": "在项目发承包模式中，属于建设工程平行分包模式特点的有（ ）。", "options": {"A": "建设单位可在更大范围内选择承包单位", "B": "有利于控制工程质量", "C": "建设单位合同管理工作量大", "D": "有利于建设单位向承包单位转移风险", "E": "合同数量多，业主造价控制难度小", "F": "有利于缩短建设工期", "H": "使工程项目责任主体单一化"}, "answer": ["A", "B", "C"], "analysis": "采用平行分包模式的特点： （1）有利于建设单位择优选择承包单位。 （2）有利于控制工程质量。 （3）有利于缩短建设工期。 （4）组织管理和协调工作量大。 （5）工程造价控制难度大。 （6）相对于总承包模式而言，平行承包模式不利于发挥那些技术水平高、综合管理能力强的承包单位的综合优势。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "gl-g03-001", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "建设项目总投资由固定资产投资和流动资金组成，其中固定资产投资在工程造价中对应的是（ ）。", "options": {"A": "建设投资", "B": "建设投资+建设期利息", "C": "工程费用+工程建设其他费", "D": "建筑安装工程费+设备工器具购置费"}, "answer": ["B"], "analysis": "固定资产投资=工程造价=建设投资+建设期利息。建设投资包含工程费用、工程建设其他费和预备费，建设期利息单独列项。A选项缺少建设期利息，C选项缺少预备费和建设期利息，D选项仅为工程费用。", "tags": ["总投资构成", "固定资产投资"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g03-002", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "下列费用中，属于建筑安装工程费按费用构成要素划分时包含的内容是（ ）。", "options": {"A": "暂列金额", "B": "总承包服务费", "C": "企业管理费", "D": "安全文明施工费"}, "answer": ["C"], "analysis": "按费用构成要素划分，建筑安装工程费由人工费（原规费已并入）、材料费、施工机具使用费、企业管理费、利润、增值税六项组成。A、B属其他项目费，D属措施项目费。", "tags": ["建筑安装工程费", "费用构成要素"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g03-003", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "按费用构成要素划分，人工费中不包括的是（ ）。", "options": {"A": "计时工资", "B": "奖金和津贴补贴", "C": "劳动保护费", "D": "加班加点工资"}, "answer": ["C"], "analysis": "人工费包括计时工资或计件工资、奖金、津贴补贴、加班加点工资、特殊情况下支付的工资。劳动保护费属于企业管理费的组成部分，不属于人工费。", "tags": ["人工费", "费用构成"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g03-004", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "施工机具使用费中，属于施工机械使用费组成内容的是（ ）。", "options": {"A": "办公费", "B": "折旧费", "C": "职工教育经费", "D": "财产保险费"}, "answer": ["B"], "analysis": "施工机械使用费包括折旧费、大修理费、经常修理费、安拆费及场外运费、燃料动力费、人工费、税费。A（办公费）、C（职工教育经费）、D（财产保险费）均属于企业管理费。", "tags": ["施工机具使用费", "费用构成"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g03-005", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "社会保险中的养老保险费，企业缴纳比例通常为（ ）。", "options": {"A": "6.5%", "B": "8%", "C": "12%", "D": "16%"}, "answer": ["D"], "analysis": "现行社保体系中，企业缴纳养老保险费比例为16%、医疗保险费6.5%、失业保险费0.5%，工伤和生育保险费由企业按规缴纳。在GB/T 50500-2024清单中这部分已并入人工费。", "tags": ["社会保险", "养老保险"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g03-006", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "增值税一般计税方法的税率为（ ），简易计税方法的征收率为（ ）。", "options": {"A": "11%，3%", "B": "9%，3%", "C": "9%，5%", "D": "13%，3%"}, "answer": ["B"], "analysis": "根据现行规定，建筑安装工程费中的增值税，一般计税方法适用税率9%，简易计税方法适用征收率3%。注意建筑业增值税率已从11%调整至9%。", "tags": ["增值税", "税率"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g03-009", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "按造价形成顺序划分，建筑安装工程费中属于不可竞争费用的是（ ）。", "options": {"A": "脚手架工程费", "B": "大型机械进出场费", "C": "安全文明施工费", "D": "二次搬运费"}, "answer": ["C"], "analysis": "安全文明施工费是不可竞争费用，必须按规定计取，不得作为竞争性费用。A、B、D均为可竞争的措施项目费。", "tags": ["措施项目费", "不可竞争费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g03-012", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "工程费用由（ ）和（ ）两部分组成。", "options": {"A": "建筑安装工程费，工程建设其他费", "B": "建筑安装工程费，设备及工器具购置费", "C": "直接费，间接费", "D": "分部分项工程费，措施项目费"}, "answer": ["B"], "analysis": "工程费用=建筑安装工程费+设备及工器具购置费，是固定资产投资（工程造价）的核心组成部分。", "tags": ["工程费用", "总投资构成"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g03-013", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "国产标准设备原价一般按（ ）计算。", "options": {"A": "成本估价法", "B": "定额估价法", "C": "带有备件的出厂价", "D": "市场询价"}, "answer": ["C"], "analysis": "国产标准设备原价一般按带有备件的出厂价计算；国产非标准设备原价采用成本估价法、定额估价法、系列设备插入估价法等方法计算。", "tags": ["设备购置费", "国产设备原价"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g03-014", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "工器具及生产家具购置费一般按（ ）的一定比例计算。", "options": {"A": "建筑安装工程费", "B": "设备购置费", "C": "工程建设其他费", "D": "预备费"}, "answer": ["B"], "analysis": "工器具及生产家具购置费=设备购置费×定额费率，即按设备购置费的一定比例计算。", "tags": ["工器具购置费", "设备购置费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g03-017", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "下列费用中，属于与项目建设有关的工程建设其他费的是（ ）。", "options": {"A": "联合试运转费", "B": "生产准备及开办费", "C": "勘察设计费", "D": "专利技术使用费"}, "answer": ["C"], "analysis": "工程建设其他费用分为三类：①建设用地费；②与项目建设有关的费用（建设单位管理费、监理费、可研费、勘察设计费、环评费、场地准备及临时设施费、工程保险费）；③与未来生产经营有关的费用（联合试运转费、专利技术使用费、生产准备及开办费）。A、B、D属于第三类。", "tags": ["工程建设其他费", "分类"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g03-018", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "下列费用中，属于与未来生产经营有关的工程建设其他费的是（ ）。", "options": {"A": "建设单位管理费", "B": "环境影响评价费", "C": "联合试运转费", "D": "场地准备及临时设施费"}, "answer": ["C"], "analysis": "联合试运转费属于与未来生产经营有关的工程建设其他费用，指新建项目在竣工验收前进行联动试车所发生的费用净支出。A、B、D均属于与项目建设有关的费用。", "tags": ["工程建设其他费", "联合试运转费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g03-020", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "预备费由基本预备费和价差预备费两部分组成。基本预备费的计算基数是（ ）。", "options": {"A": "建筑安装工程费", "B": "工程费用+工程建设其他费", "C": "工程费用", "D": "建筑安装工程费+设备工器具购置费"}, "answer": ["B"], "analysis": "基本预备费=（工程费用+工程建设其他费）×基本预备费率（通常为5%~10%）。计算基数包含工程费用和工程建设其他费两部分。", "tags": ["基本预备费", "计算基数"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g03-021", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "基本预备费的费率一般为（ ）。", "options": {"A": "1%~3%", "B": "3%~5%", "C": "5%~10%", "D": "10%~15%"}, "answer": ["C"], "analysis": "基本预备费费率通常为5%~10%，具体根据项目复杂程度和估算阶段确定。", "tags": ["基本预备费", "费率"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g03-022", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "关于价差预备费，下列说法正确的是（ ）。", "options": {"A": "用于应对设计变更和工程量的增加", "B": "按工程费用的一定比例计算", "C": "用于应对建设期内价格变化引起的投资增加", "D": "费率固定为5%"}, "answer": ["C"], "analysis": "价差预备费用于应对建设期内人工、材料、设备等价格变化引起的投资增加，采用复利方法逐年计算。A选项属于基本预备费的用途，B描述不准确，D费率不固定。", "tags": ["价差预备费", "预备费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g03-023", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "建设期利息的计算中，当年借款的计息方式为（ ）。", "options": {"A": "按全年计息", "B": "按半年计息", "C": "按季度计息", "D": "不计息"}, "answer": ["B"], "analysis": "建设期利息计算原则：当年借款按半年计息（假设在年中支用），以前年度借款按全年计息。这是建设期利息计算的核心规则。", "tags": ["建设期利息", "计息规则"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g03-024", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "流动资金的铺底流动资金一般按流动资金总额的（ ）计算。", "options": {"A": "15%", "B": "25%", "C": "30%", "D": "50%"}, "answer": ["C"], "analysis": "流动资金=流动资产-流动负债，铺底流动资金按流动资金总额的30%计算，列入项目总投资。", "tags": ["流动资金", "铺底流动资金"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g03-025", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "在进口设备原价构成中，银行财务费的计算基数是（ ）。", "options": {"A": "FOB价（离岸价）", "B": "CIF价（到岸价）", "C": "CIF价+关税", "D": "FOB价+国际运费"}, "answer": ["A"], "analysis": "银行财务费=FOB价×银行财务费率。注意与外贸手续费的区别：外贸手续费=CIF价×外贸手续费率。两者计算基数不同，此为重要考点。", "tags": ["进口设备原价", "银行财务费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g03-026", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "进口设备关税的完税价格（计税基数）是（ ）。", "options": {"A": "FOB价（离岸价）", "B": "FOB价+国际运费", "C": "CIF价（到岸价）", "D": "FOB价+国际运费+银行财务费"}, "answer": ["C"], "analysis": "进口关税=到岸价（CIF）×关税税率。CIF=FOB+国际运费+运输保险费。关税以CIF（到岸价）为完税价格。", "tags": ["进口关税", "CIF", "完税价格"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g03-027", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "住房公积金的企业缴存比例范围是（ ）。", "options": {"A": "3%~8%", "B": "5%~12%", "C": "8%~15%", "D": "10%~20%"}, "answer": ["B"], "analysis": "原规费中的住房公积金（在GB/T 50500-2024中已并入人工费）的企业缴存比例范围为5%~12%，具体比例由各地公积金管理委员会确定。", "tags": ["规费", "住房公积金"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g03-028", "date": "2026-07-19", "chapter": "g03", "type": "single", "stem": "下列各项中，不属于人工费的是（ ）。", "options": {"A": "养老保险费", "B": "医疗保险费", "C": "劳动保护费", "D": "住房公积金"}, "answer": ["C"], "analysis": "根据GB/T 50500-2024《建设工程工程量清单计价标准》，原规费（社会保险费——含养老、医疗、失业、工伤、生育保险，以及住房公积金）已并入人工费，不再作为独立费用项。现行人工费包括计时工资、计件工资、奖金、津贴补贴、加班工资、特殊情况下支付的工资及原规费并入部分。劳动保护费属于企业管理费，不属于人工费。", "tags": ["人工费", "费用区分"], "source": "管理教材精读笔记（24清单更新）", "src": "原始"}, {"id": "gl-g03-029", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "某建设项目工程费用为5000万元，工程建设其他费为1000万元，基本预备费率为8%，则基本预备费为（ ）万元。", "options": {"A": "400", "B": "440", "C": "480", "D": "500"}, "answer": ["C"], "analysis": "基本预备费=（工程费用+工程建设其他费）×基本预备费率=（5000+1000）×8%=6000×0.08=480万元。", "tags": ["基本预备费", "计算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g03-030", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "某建设项目设备购置费为2000万元，工器具及生产家具购置费定额费率为5%，则工器具购置费为（ ）万元。", "options": {"A": "50", "B": "80", "C": "100", "D": "120"}, "answer": ["C"], "analysis": "工器具及生产家具购置费=设备购置费×定额费率=2000×5%=100万元。", "tags": ["工器具购置费", "计算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g03-031", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "建筑业增值税一般计税方法的税率为9%。某不含税工程造价为1000万元，应缴纳的增值税销项税额为（ ）万元。", "options": {"A": "30", "B": "60", "C": "90", "D": "110"}, "answer": ["C"], "analysis": "增值税销项税额=不含税造价×税率=1000×9%=90万元。一般计税方法下税前造价不含增值税进项税额。", "tags": ["增值税", "计算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g03-034", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "建设单位管理费属于（ ）。", "options": {"A": "建筑安装工程费", "B": "设备工器具购置费", "C": "工程建设其他费", "D": "预备费"}, "answer": ["C"], "analysis": "建设单位管理费属于工程建设其他费中与项目建设有关的费用，包括建设单位开办费、建设单位经费等。", "tags": ["工程建设其他费", "建设单位管理费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g03-036", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "某项目建设期2年，第1年贷款500万元，第2年贷款300万元，贷款年利率为6%，则第1年建设期利息为（ ）万元。", "options": {"A": "15", "B": "30", "C": "45", "D": "60"}, "answer": ["A"], "analysis": "第1年建设期利息=当年借款×利率/2=500×6%/2=15万元。当年借款按半年计息。第2年需加上第1年累计借款本息的全年利息。", "tags": ["建设期利息", "计算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g03-037", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "下列各项中，对建筑安装工程费中'利润'的正确理解是（ ）。", "options": {"A": "施工企业完成工程后实际获得的税后净利润", "B": "施工企业完成所承包工程应计取的利润", "C": "建设单位预留的额外利润空间", "D": "工程造价超出预算部分的结余"}, "answer": ["B"], "analysis": "利润是指施工企业完成所承包工程应计取的利润，属于建筑安装工程费的法定组成部分。它不是税后净利润（还需扣除企业所得税），也不是建设单位的预留或节约。", "tags": ["利润", "费用构成"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g03-039", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "CIF价格（到岸价）的构成是（ ）。", "options": {"A": "FOB+国际运费", "B": "FOB+运输保险费", "C": "FOB+国际运费+运输保险费", "D": "FOB+国际运费+银行财务费"}, "answer": ["C"], "analysis": "CIF（到岸价）=FOB（离岸价）+国际运费+运输保险费。CIF是计算外贸手续费和进口关税的基数。", "tags": ["CIF", "进口设备原价"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g03-040", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "下列费用中，属于工程建设其他费中与未来生产经营有关的是（ ）。", "options": {"A": "场地准备及临时设施费", "B": "工程保险费", "C": "专利技术使用费", "D": "工程监理费"}, "answer": ["C"], "analysis": "与未来生产经营有关的费用包括：联合试运转费、专利技术使用费、生产准备及开办费。A、B、D均属于与项目建设有关的费用。", "tags": ["工程建设其他费", "专利技术使用费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-001", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "从投资者角度看，工程造价是指（ ）。", "options": {"A": "建筑安装工程费用", "B": "固定资产投资", "C": "流动资产投资", "D": "建设项目总投资"}, "answer": ["B"], "analysis": "从投资者（业主）角度看，工程造价即固定资产投资。从承包商角度看指建筑安装工程费用。", "tags": ["工程造价含义", "投资者角度"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-002", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "从承包商角度看，工程造价是指（ ）。", "options": {"A": "固定资产投资", "B": "建筑安装工程费用", "C": "建设项目总投资", "D": "固定资产与流动资产投资之和"}, "answer": ["B"], "analysis": "从承包商角度看，工程造价指建筑安装工程费用，即工程承发包价格。", "tags": ["工程造价含义", "承包商角度"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-003", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "关于静态投资与动态投资的关系，下列说法正确的是（ ）。", "options": {"A": "静态投资=动态投资", "B": "动态投资=静态投资+价差预备费+建设期利息", "C": "静态投资=动态投资+价差预备费", "D": "两者没有关系"}, "answer": ["B"], "analysis": "动态投资=静态投资+价差预备费+建设期利息。静态投资含建安费+设备购置费+其他费+基本预备费。", "tags": ["工程造价含义", "静态vs动态"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-004", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "静态投资的内容不包括（ ）。", "options": {"A": "建筑安装工程费", "B": "设备及工器具购置费", "C": "工程建设其他费", "D": "建设期利息"}, "answer": ["D"], "analysis": "静态投资=建安费+设备购置费+其他费+基本预备费。建设期利息属动态投资部分。", "tags": ["工程造价含义", "静态投资"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-005", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "建设项目总投资由（ ）构成。", "options": {"A": "固定资产投资+建设期利息", "B": "固定资产投资+流动资产投资（流动资金）", "C": "工程费用+工程建设其他费", "D": "建安费+设备购置费"}, "answer": ["B"], "analysis": "建设项目总投资=固定资产投资（工程造价）+流动资产投资（流动资金）。", "tags": ["总投资构成", "总投资"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-006", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "固定资产投资（工程造价）的构成中不包括（ ）。", "options": {"A": "工程费用", "B": "工程建设其他费", "C": "预备费", "D": "流动资金"}, "answer": ["D"], "analysis": "固定资产投资=工程费用+工程建设其他费+预备费+建设期利息。流动资金属总投资另一部分。", "tags": ["总投资构成", "固定资产投资"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-007", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "工程费用包括（ ）。", "options": {"A": "建安费+工程建设其他费", "B": "建安费+设备及工器具购置费", "C": "设备购置费+预备费", "D": "建安费+预备费"}, "answer": ["B"], "analysis": "工程费用=建筑安装工程费+设备及工器具购置费。是工程造价最核心的两大组成部分。", "tags": ["总投资构成", "工程费用"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-008", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "按费用构成要素划分，建安费不包括（ ）。", "options": {"A": "人工费", "B": "材料费", "C": "暂列金额", "D": "企业管理费"}, "answer": ["C"], "analysis": "按费用构成要素分为6项(人工费（原规费已并入）、材料、机具、管理、利润、增值税)。暂列金额属按造价形成划分的其他项目费。", "tags": ["建安费", "费用构成要素"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-010", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "下列属于人工费的是（ ）。", "options": {"A": "管理人员工资", "B": "生产工人的计时工资", "C": "劳动保护费", "D": "职工教育经费"}, "answer": ["B"], "analysis": "生产工人计时工资属人工费。管理人员工资、劳动保护费、职工教育经费均属企业管理费。", "tags": ["建安费", "人工费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-012", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "材料费中不包括（ ）。", "options": {"A": "材料原价", "B": "运杂费", "C": "运输损耗费", "D": "检验试验费"}, "answer": ["D"], "analysis": "材料费=原价+运杂费+运输损耗+采保费+工程设备费。检验试验费属企业管理费。", "tags": ["建安费", "材料费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-013", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "材料费中的运输损耗费是指（ ）。", "options": {"A": "施工现场的材料损耗", "B": "材料在运输装卸过程中不可避免的损耗", "C": "施工过程中的材料浪费", "D": "材料加工过程中的损耗"}, "answer": ["B"], "analysis": "运输损耗费指材料在运输装卸过程中不可避免的损耗。现场施工损耗已在定额消耗量中考虑。", "tags": ["建安费", "材料费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-014", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "施工机具使用费不包括（ ）。", "options": {"A": "折旧费", "B": "大修理费", "C": "安拆费及场外运费", "D": "大型机械安拆费"}, "answer": ["D"], "analysis": "施工机具使用费中的安拆费不含大型机械进出场及安拆费（大型机械安拆属措施项目费）。", "tags": ["建安费", "施工机具使用费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-015", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "下列属于企业管理费的是（ ）。", "options": {"A": "生产工人工资", "B": "管理人员工资", "C": "材料采购人员工资", "D": "施工机械操作人员工资"}, "answer": ["B"], "analysis": "管理人员工资属企业管理费。生产工人工资属人工费，采购人员工资属采保费，机械操作人员工资属机具费。", "tags": ["建安费", "企业管理费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-016", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "企业管理费中的检验试验费不包括（ ）。", "options": {"A": "一般建筑材料检验", "B": "构件破坏性试验", "C": "建筑安装物一般鉴定", "D": "施工企业自设试验室试验"}, "answer": ["B"], "analysis": "检验试验费不含新材料新结构试验和对构件做破坏性试验的费用，破坏性试验由建设单位另行支付。", "tags": ["建安费", "企业管理费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-018", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "利润的确定方式是（ ）。", "options": {"A": "国家统一规定", "B": "按企业自身情况自主确定", "C": "按行业平均利润率", "D": "按工程类别强制规定"}, "answer": ["B"], "analysis": "利润由施工企业自主确定。在GB/T 50500-2024中规费已并入人工费不再单列；安全文明施工费属不可竞争费用。", "tags": ["建安费", "利润"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-019", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "属于不可竞争费用的是（ ）。", "options": {"A": "利润", "B": "企业管理费", "C": "规费", "D": "材料费"}, "answer": ["C"], "analysis": "在传统费用构成中规费属不可竞争费用（GB/T 50500-2024中已并入人工费），按国家或省规定标准计取。安全文明施工费也属不可竞争。", "tags": ["建安费", "规费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-020", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "社会保险中养老保险的缴费比例一般为（ ）。", "options": {"A": "6.5%", "B": "12%", "C": "16%", "D": "20%"}, "answer": ["C"], "analysis": "社会保险费：养老保险16%、医疗保险6.5%、失业保险0.5%。公积金5%-12%。在GB/T 50500-2024中，规费已并入人工费，这些比例作为人工费的组成部分仍沿用。", "tags": ["建安费", "社会保险"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-021", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "社会保险中医疗保险的缴费比例一般为（ ）。", "options": {"A": "6.5%", "B": "8%", "C": "10%", "D": "16%"}, "answer": ["A"], "analysis": "社会保险费：养老16%、医疗6.5%、失业0.5%。需准确记忆。在GB/T 50500-2024中，规费已并入人工费，不再单独列项。", "tags": ["建安费", "社会保险"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-022", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "住房公积金的缴存比例范围是（ ）。", "options": {"A": "3%-8%", "B": "5%-12%", "C": "8%-15%", "D": "10%-20%"}, "answer": ["B"], "analysis": "住房公积金缴存比例5%-12%。企业和职工各按相同比例缴存。注：在GB/T 50500-2024中，住房公积金已随原规费并入人工费，不再单独列项。", "tags": ["建安费", "规费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-023", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "增值税一般计税方法的税率是（ ）。", "options": {"A": "3%", "B": "6%", "C": "9%", "D": "13%"}, "answer": ["C"], "analysis": "建安工程增值税：一般计税9%，简易计税3%。基数均为税前造价（不含增值税）。", "tags": ["建安费", "增值税"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-024", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "增值税简易计税方法的征收率是（ ）。", "options": {"A": "3%", "B": "6%", "C": "9%", "D": "11%"}, "answer": ["A"], "analysis": "简易计税征收率3%，适用于小规模纳税人或清包工、甲供工程等。一般计税9%。", "tags": ["建安费", "增值税"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-025", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "增值税的计算基数（税前造价）中（ ）。", "options": {"A": "包含增值税", "B": "不包含增值税", "C": "包含全部税金", "D": "只含企业所得税"}, "answer": ["B"], "analysis": "税前造价不含增值税，即人工费（原规费已并入）+材料费+机具费+管理费+利润之和。", "tags": ["建安费", "增值税"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-026", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "按造价形成顺序划分，建安费的第一部分是（ ）。", "options": {"A": "措施项目费", "B": "其他项目费", "C": "分部分项工程费", "D": "增值税"}, "answer": ["C"], "analysis": "按造价形成顺序：分部分项工程费→措施项目费→其他项目费→增值税。原规费已并入人工费。", "tags": ["建安费", "造价形成顺序"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-027", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "分部分项工程费的计算公式正确的是（ ）。", "options": {"A": "量×定额单价", "B": "量×综合单价", "C": "量×全费用单价", "D": "量×工料单价"}, "answer": ["B"], "analysis": "分部分项工程费=Σ(分部分项工程量×综合单价)。综合单价含人材机管利及风险。", "tags": ["建安费", "分部分项工程费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-028", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "下列属于不可竞争费用的措施项目是（ ）。", "options": {"A": "脚手架工程费", "B": "模板工程费", "C": "安全文明施工费", "D": "大型机械进出场费"}, "answer": ["C"], "analysis": "安全文明施工费属不可竞争费用，须按国家或省级标准计取。脚手架、模板等属可竞争措施费。", "tags": ["建安费", "措施项目费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-030", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "已完工程及设备保护费属于（ ）。", "options": {"A": "分部分项工程费", "B": "措施项目费", "C": "其他项目费", "D": "企业管理费"}, "answer": ["B"], "analysis": "已完工程及设备保护费属于措施项目费。", "tags": ["建安费", "措施项目费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-031", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "暂列金额由（ ）在招标工程量清单中暂定。", "options": {"A": "投标人", "B": "招标人", "C": "造价咨询机构", "D": "施工单位"}, "answer": ["B"], "analysis": "暂列金额由招标人暂定，用于尚未确定或不可预见的费用。一般不超分部分项的10%-15%。", "tags": ["建安费", "暂列金额"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-032", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "暂列金额一般不超过分部分项工程费的（ ）。", "options": {"A": "5%-8%", "B": "10%-15%", "C": "15%-20%", "D": "20%-25%"}, "answer": ["B"], "analysis": "暂列金额一般不超分部分项工程费的10%-15%，为重要比例考点。", "tags": ["建安费", "暂列金额"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-033", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "其他项目费中不包括（ ）。", "options": {"A": "暂列金额", "B": "暂估价", "C": "计日工", "D": "安全文明施工费"}, "answer": ["D"], "analysis": "其他项目费：暂列金额、暂估价、计日工、总承包服务费。安全文明施工费属措施项目费。", "tags": ["建安费", "其他项目费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-034", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "总承包服务费应由（ ）支付。", "options": {"A": "分包单位", "B": "发包人", "C": "监理单位", "D": "造价咨询机构"}, "answer": ["B"], "analysis": "总承包服务费由发包人向总承包人支付，用于总承包人对专业分包的管理和协调。", "tags": ["建安费", "总承包服务费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-037", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "国产非标设备原价计算中不包括（ ）。", "options": {"A": "材料费", "B": "加工费", "C": "设备运杂费", "D": "废品损失费"}, "answer": ["C"], "analysis": "非标设备原价含材料费+加工费+辅助材料+专用工具+废品损失+外购配套件+包装+利润+税金+设计费。运杂费另算。", "tags": ["设备购置费", "非标设备原价"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-038", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "进口设备到岸价（CIF）的构成是（ ）。", "options": {"A": "FOB+国际运费", "B": "FOB+国际运费+运输保险费", "C": "FOB+关税", "D": "FOB+增值税"}, "answer": ["B"], "analysis": "CIF=FOB（离岸价）+国际运费+运输保险费。CIF是计算关税和外贸手续费的基数。", "tags": ["设备购置费", "进口设备CIF"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-039", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "进口设备外贸手续费的计算基数是（ ）。", "options": {"A": "FOB", "B": "CIF", "C": "CIF+关税", "D": "CIF+关税+消费税"}, "answer": ["B"], "analysis": "外贸手续费=CIF×1.5%。银行财务费以FOB为基数。注意两者基数不同。", "tags": ["设备购置费", "外贸手续费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-040", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "进口设备银行财务费的计算基数是（ ）。", "options": {"A": "CIF", "B": "FOB", "C": "CIF+关税", "D": "抵岸价"}, "answer": ["B"], "analysis": "银行财务费=FOB×银行财务费率。外贸手续费=CIF×1.5%。两者基数不同。", "tags": ["设备购置费", "银行财务费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-041", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "进口关税的计算公式是（ ）。", "options": {"A": "FOB×关税税率", "B": "CIF×关税税率", "C": "(CIF+消费税)×关税税率", "D": "抵岸价×关税税率"}, "answer": ["B"], "analysis": "关税=CIF×关税税率。增值税=(CIF+关税+消费税)×增值税率。注意基数区别。", "tags": ["设备购置费", "关税"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-042", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "进口设备增值税的计算基数是（ ）。", "options": {"A": "CIF", "B": "FOB", "C": "CIF+关税+消费税", "D": "CIF+关税"}, "answer": ["C"], "analysis": "进口设备增值税=(CIF+关税+消费税)×增值税税率。增值税是价外税，含关税和消费税。", "tags": ["设备购置费", "增值税"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-043", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "进口设备消费税的计算公式正确的是（ ）。", "options": {"A": "CIF×消费税率", "B": "(CIF+关税)×消费税率", "C": "(CIF+关税)/(1-消费税率)×消费税率", "D": "CIF/(1+消费税率)×消费税率"}, "answer": ["C"], "analysis": "消费税=(CIF+关税)/(1-消费税率)×消费税率。消费税是价内税，需先还原含税价格。", "tags": ["设备购置费", "消费税"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-044", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "进口设备车辆购置附加费的计算基数是（ ）。", "options": {"A": "CIF", "B": "CIF+关税", "C": "CIF+关税+消费税", "D": "抵岸价"}, "answer": ["C"], "analysis": "车辆购置附加费=(CIF+关税+消费税)×10%。不含增值税的完税价格×10%。", "tags": ["设备购置费", "车辆购置附加费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-045", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "设备运杂费的计算公式是（ ）。", "options": {"A": "设备原价×固定金额", "B": "设备原价×设备运杂费率", "C": "设备重量×运杂费率", "D": "实际发生额"}, "answer": ["B"], "analysis": "设备运杂费=设备原价×设备运杂费率。含运费装卸、包装、采购保管等。", "tags": ["设备购置费", "运杂费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-046", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "下列属于建设用地费的是（ ）。", "options": {"A": "勘察设计费", "B": "土地出让金", "C": "研究试验费", "D": "联合试运转费"}, "answer": ["B"], "analysis": "土地出让金属建设用地费。建设用地费含征拆补偿（划拨）、出让金、耕地占用税、土地使用税。", "tags": ["工程建设其他费", "建设用地费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-047", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "以划拨方式取得的建设用地，相关费用是（ ）。", "options": {"A": "土地出让金", "B": "土地征用及拆迁补偿费", "C": "城镇土地使用税", "D": "耕地占用税"}, "answer": ["B"], "analysis": "划拨方式取得需支付土地征用及拆迁补偿费。出让方式需支付土地出让金。", "tags": ["工程建设其他费", "建设用地费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-048", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "下列属于与项目建设有关的其他费的是（ ）。", "options": {"A": "联合试运转费", "B": "勘察设计费", "C": "生产准备费", "D": "专利使用费"}, "answer": ["B"], "analysis": "勘察设计费属与项目建设有关的其他费。联合试运转、生产准备、专利使用费属与未来生产经营有关的其他费。", "tags": ["工程建设其他费", "分类"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-049", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "建设单位管理费中不包含（ ）。", "options": {"A": "工作人员工资", "B": "办公费", "C": "勘察设计费", "D": "差旅交通费"}, "answer": ["C"], "analysis": "建设单位管理费含工资、办公、差旅等日常费用及工程监理费（2025版）。勘察设计费属独立项目。", "tags": ["工程建设其他费", "建设单位管理费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-050", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "联合试运转费的净支出计入（ ）。", "options": {"A": "工程费用", "B": "工程建设其他费", "C": "预备费", "D": "建安工程费"}, "answer": ["B"], "analysis": "联合试运转费属与未来生产经营有关的工程建设其他费，指交付前按设计进行的联合试运转费用净支出。", "tags": ["工程建设其他费", "联合试运转费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-051", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "基本预备费的计算基数是（ ）。", "options": {"A": "建筑安装工程费", "B": "工程费用", "C": "工程费用+工程建设其他费", "D": "固定资产投资"}, "answer": ["C"], "analysis": "基本预备费=(工程费用+工程建设其他费)×基本预备费率。工程费用=建安费+设备购置费。", "tags": ["预备费", "基本预备费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-052", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "基本预备费率通常为（ ）。", "options": {"A": "1%-3%", "B": "3%-5%", "C": "5%-10%", "D": "10%-15%"}, "answer": ["C"], "analysis": "基本预备费率一般5%-10%，具体根据项目复杂程度和风险确定。", "tags": ["预备费", "基本预备费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-053", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "价差预备费公式中，It代表（ ）。", "options": {"A": "建设期第t年的投资额", "B": "建设期第t年的贷款额", "C": "建设前期年限", "D": "年涨价率"}, "answer": ["A"], "analysis": "PF=ΣIt[(1+f)^(m+t-0.5)-1]，It为建设期第t年投资额，f为年涨价率，m为前期年限。", "tags": ["预备费", "价差预备费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-054", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "价差预备费公式指数中“m”的含义是（ ）。", "options": {"A": "建设工期", "B": "建设前期年限", "C": "贷款年限", "D": "运营期"}, "answer": ["B"], "analysis": "m为建设前期年限（编制估算到开工的时间）。指数m+t-0.5中0.5是当年投资在年中均匀投入的假设。", "tags": ["预备费", "价差预备费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-055", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "建设期利息计算中，当年借款的计息原则是（ ）。", "options": {"A": "按全年计息", "B": "按半年计息", "C": "按季度计息", "D": "不计息"}, "answer": ["B"], "analysis": "当年借款按半年计息，qi=(Pj-1+Aj/2)×i。Aj/2体现半年计息原则，Pj-1为年初累计借款（全年计息）。", "tags": ["建设期利息", "计息原则"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-056", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "建设期利息公式qi=(Pj-1+Aj/2)×i中，Pj-1表示（ ）。", "options": {"A": "第j年借款额", "B": "第j-1年末累计借款额", "C": "第j年还款额", "D": "前期累计借款"}, "answer": ["B"], "analysis": "Pj-1为第j-1年末累计借款额。Aj为第j年借款额，Aj/2为当年借款半年计息，i为年利率。", "tags": ["建设期利息", "公式参数"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-057", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "铺底流动资金按流动资金的（ ）计算。", "options": {"A": "10%", "B": "20%", "C": "30%", "D": "50%"}, "answer": ["C"], "analysis": "铺底流动资金=流动资金×30%。是项目投资中必须筹措的最低流动资金。", "tags": ["流动资金", "铺底流动资金"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-058", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "流动资金的计算公式是（ ）。", "options": {"A": "流动资金=流动资产", "B": "流动资金=流动资产-流动负债", "C": "流动资金=总投资-固定资产投资", "D": "流动资金=流动资产+流动负债"}, "answer": ["B"], "analysis": "流动资金=流动资产-流动负债。铺底流动资金=流动资金×30%。", "tags": ["流动资金", "计算公式"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-059", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "某工程建安费5000万，设备费2000万，其他费1500万，基本预备费率8%，则基本预备费为（ ）万元。", "options": {"A": "400", "B": "520", "C": "680", "D": "720"}, "answer": ["C"], "analysis": "基本预备费=[(5000+2000)+1500]×8%=8500×8%=680万元。工程费用=建安费+设备费=7000万元。", "tags": ["预备费", "计算题"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-060", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "某工程建安费5000万，设备费2000万，其他费1500万，基本预备费率8%，该工程静态投资为（ ）万元。", "options": {"A": "8500", "B": "9180", "C": "7000", "D": "10000"}, "answer": ["B"], "analysis": "静态投资=(5000+2000)+1500+680=9180万元。680为基本预备费。", "tags": ["预备费", "计算题"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-061", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "工程建设其他费按费用性质分为（ ）类。", "options": {"A": "2", "B": "3", "C": "4", "D": "5"}, "answer": ["B"], "analysis": "工程建设其他费分3类：建设用地费、与项目建设有关的其他费、与未来生产经营有关的其他费。", "tags": ["工程建设其他费", "分类"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-062", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "生产准备及开办费属于（ ）。", "options": {"A": "工程费用", "B": "与项目建设有关的其他费", "C": "与未来生产经营有关的其他费", "D": "预备费"}, "answer": ["C"], "analysis": "生产准备及开办费属与未来生产经营有关的其他费，含人员培训、提前进厂工资、家具购置等。", "tags": ["工程建设其他费", "生产准备费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-064", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "建安费按费用构成要素分（ ）项，按造价形成顺序分（ ）部分。", "options": {"A": "6项/4部分", "B": "7项/4部分", "C": "6项/5部分", "D": "7项/5部分"}, "answer": ["A"], "analysis": "按费用构成要素分为6项(人工费（原规费并入）、材料、机具、企业管理费、利润、增值税)，按造价形成为4部分(分部分项、措施、其他、增值税)。", "tags": ["建安费", "两种划分方式"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-065", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "某进口设备FOB价200万美元，国际运费30万，运输保险费率0.3%，则运输保险费为（ ）万美元。", "options": {"A": "0.60", "B": "0.69", "C": "0.90", "D": "6.00"}, "answer": ["B"], "analysis": "运输保险费=[(200+30)/(1-0.3%)]×0.3%=230.69×0.3%=0.692万美元。以CIF为基数反算。", "tags": ["设备购置费", "计算题"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-066", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "某进口设备CIF价500万元，关税税率10%，增值税率13%，应纳增值税为（ ）万元。", "options": {"A": "65.0", "B": "71.5", "C": "55.0", "D": "50.0"}, "answer": ["B"], "analysis": "关税=500×10%=50万。增值税=(500+50+0)×13%=550×13%=71.5万元。", "tags": ["设备购置费", "计算题"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-067", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "某项目建设期2年，第1年借款800万，第2年借款600万，年利率6%。第2年建设期利息为（ ）万元。", "options": {"A": "49.44", "B": "67.44", "C": "36.00", "D": "42.00"}, "answer": ["B"], "analysis": "第1年利息=(0+800/2)×6%=24万，年末累计=824万。第2年利息=(824+600/2)×6%=1124×6%=67.44万。", "tags": ["建设期利息", "计算题"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-068", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "材料费中的采购及保管费不包括（ ）。", "options": {"A": "采购人员工资", "B": "仓库保管费", "C": "采购差旅费", "D": "材料检验试验费"}, "answer": ["D"], "analysis": "采保费含采购费、仓储保管费。材料检验试验费属企业管理费。", "tags": ["建安费", "材料费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-070", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "环境影响评价费属于（ ）。", "options": {"A": "工程费用", "B": "与项目建设有关的其他费", "C": "与未来生产经营有关的其他费", "D": "预备费"}, "answer": ["B"], "analysis": "环境影响评价费需在建设前期完成，属与项目建设有关的其他费。", "tags": ["工程建设其他费", "环评费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-071", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "工程保险费（建筑工程一切险等）属于（ ）。", "options": {"A": "企业管理费", "B": "与项目建设有关的其他费", "C": "规费", "D": "预备费"}, "answer": ["B"], "analysis": "工程保险属与项目建设有关的其他费。注与企业财产保险区分：企业财产险属企业管理费。", "tags": ["工程建设其他费", "工程保险费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-072", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "特殊设备安全监督检验费属于（ ）。", "options": {"A": "企业管理费", "B": "与项目建设有关的其他费", "C": "措施项目费", "D": "设备购置费"}, "answer": ["B"], "analysis": "特殊设备（锅炉、压力容器、电梯等）安全监督检验费属与项目建设有关的其他费。", "tags": ["工程建设其他费", "特殊设备检验"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-073", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "研究试验费是指（ ）。", "options": {"A": "施工企业对建筑材料的一般鉴定费", "B": "为建设项目提供或验证设计参数的研究试验费", "C": "科技三项费用", "D": "施工企业自行研究费"}, "answer": ["B"], "analysis": "研究试验费指为建设项目提供或验证设计数据资料的研究试验费。不同于企业管理费和科技三项费。", "tags": ["工程建设其他费", "研究试验费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-074", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "场地准备及临时设施费属于（ ）。", "options": {"A": "措施项目费", "B": "企业管理费", "C": "与项目建设有关的其他费", "D": "建设用地费"}, "answer": ["C"], "analysis": "场地准备及临时设施费属与项目建设有关的其他费（建设单位范围）。注与施工单位的临时设施费（措施费）区别。", "tags": ["工程建设其他费", "场地准备费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-075", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "专利及专有技术使用费属于（ ）。", "options": {"A": "工程费用", "B": "与项目建设有关的其他费", "C": "与未来生产经营有关的其他费", "D": "企业管理费"}, "answer": ["C"], "analysis": "专利使用费是为未来生产运营购买技术的费用，属与未来生产经营有关的其他费。", "tags": ["工程建设其他费", "专利使用费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-076", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "下列属于基本预备费用途的是（ ）。", "options": {"A": "材料价格上涨", "B": "设计变更增加的费用", "C": "人工费上涨", "D": "利率调整"}, "answer": ["B"], "analysis": "基本预备费用于设计变更、不可预见工程变更等。材价人价上涨属价差预备费。利率调整属建设期利息。", "tags": ["预备费", "基本预备费用途"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-077", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "价差预备费主要用于（ ）。", "options": {"A": "设计变更", "B": "工程变更", "C": "价格变化引起的投资增加", "D": "不可预见地质条件变化"}, "answer": ["C"], "analysis": "价差预备费用于建设期间人材机价格上涨引起的投资增加。设计变更和工程变更由基本预备费解决。", "tags": ["预备费", "价差预备费用途"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-078", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "某项目建设期3年，第1年投600万，第2年投800万，第3年投600万，年涨价率5%，建设前期1年。第1年价差预备费约（ ）万元。", "options": {"A": "30.00", "B": "45.58", "C": "68.40", "D": "36.60"}, "answer": ["B"], "analysis": "第1年价差预备费=600×[(1.05)^(1+1-0.5)-1]=600×[(1.05)^1.5-1]=600×0.07593=45.56万元。", "tags": ["预备费", "计算题"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-079", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "进口设备抵岸价计算流程正确的是（ ）。", "options": {"A": "FOB→CIF→抵岸价", "B": "CIF→FOB→抵岸价", "C": "关税→CIF→抵岸价", "D": "增值税→CIF→抵岸价"}, "answer": ["A"], "analysis": "流程：FOB+国际运费+运输保险费=CIF→CIF+关税+消费税+增值税+附加+银行财务+外贸手续费=抵岸价。", "tags": ["设备购置费", "计算流程"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-080", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "施工企业缴纳的房产税、车船使用税属于（ ）。", "options": {"A": "规费", "B": "企业管理费中的税金", "C": "增值税", "D": "城市维护建设税"}, "answer": ["B"], "analysis": "房产税、车船使用税、土地使用税、印花税等属企业管理费中的税金。增值税是价外税单列。", "tags": ["建安费", "企业管理费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-081", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "劳动保险和职工福利费属于（ ）。", "options": {"A": "人工费", "B": "企业管理费", "C": "规费", "D": "其他项目费"}, "answer": ["B"], "analysis": "劳动保险和福利费属企业管理费，含退职金、丧葬补助、抚恤费等。注意：原规费中的社保已并入人工费（GB/T 50500-2024）。", "tags": ["建安费", "企业管理费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-082", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "下列属于社会保险费的是（ ）。", "options": {"A": "住房公积金", "B": "养老保险费", "C": "劳动保险费", "D": "工会经费"}, "answer": ["B"], "analysis": "养老保险属社会保险（五险）。住房公积金与五险并列。劳动保险和工会经费属企业管理费。在GB/T 50500-2024中，原规费（含社保和公积金）已并入人工费。", "tags": ["建安费", "社会保险"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-083", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "关于工程造价两种含义，说法错误的是（ ）。", "options": {"A": "投资者角度即固定资产投资", "B": "承包商角度即建安费", "C": "两者含义完全相同", "D": "两者管理目标不同"}, "answer": ["C"], "analysis": "工程造价两种含义不同。投资者追求最小投资最大效益，承包商追求较高造价获更多利润。", "tags": ["工程造价含义", "两种含义"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-084", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "建设工程造价控制的最高限额是（ ）。", "options": {"A": "投资估算", "B": "设计概算", "C": "施工图预算", "D": "竣工决算"}, "answer": ["A"], "analysis": "投资估算是项目决策依据，也是各阶段造价控制的最高限额（概算不超估算原则）。", "tags": ["工程造价含义", "造价控制"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-085", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "某进口设备FOB价2000万，国际运费300万，保险费率0.3%，外贸手续费率1.5%。外贸手续费为（ ）万元。", "options": {"A": "10.00", "B": "34.60", "C": "34.67", "D": "30.00"}, "answer": ["B"], "analysis": "运输保险费=(2000+300)/(1-0.3%)×0.3%=6.92万。CIF=2306.92万。外贸手续费=2306.92×1.5%=34.60万。", "tags": ["设备购置费", "计算题"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-086", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "建设项目总投资中固定资产投资与工程造价的关系是（ ）。", "options": {"A": "工程造价>固定资产投资", "B": "固定资产投资=工程造价", "C": "固定资产投资<工程造价", "D": "两者无关"}, "answer": ["B"], "analysis": "从投资者角度，固定资产投资即工程造价。总投资=固定资产投资（工程造价）+流动资金。", "tags": ["工程造价含义", "基本概念"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-087", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "大型施工机械的进出场及安拆费应计入（ ）。", "options": {"A": "施工机具使用费", "B": "措施项目费", "C": "企业管理费", "D": "工程建设其他费"}, "answer": ["B"], "analysis": "大型机械进出场及安拆费属措施项目费单列。一般中小型机械安拆费含在施工机具使用费中。", "tags": ["建安费", "措施项目费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-088", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "暂估价与暂列金额的主要区别是（ ）。", "options": {"A": "金额大小不同", "B": "暂估价必然发生但价格不确定，暂列金额可能发生也可能不", "C": "暂估价由承包人定，暂列金额由发包人定", "D": "没有区别"}, "answer": ["B"], "analysis": "暂估价用于必然发生但价格未定的材料/设备/专业工程。暂列金额用于尚不确定或不可预见的费用。", "tags": ["建安费", "暂估价vs暂列金额"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-089", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "下列属于冬雨季施工增加费的是（ ）。", "options": {"A": "冬季施工取暖费", "B": "材料检验费", "C": "劳动保护费", "D": "临时设施费"}, "answer": ["A"], "analysis": "冬雨季施工增加费含冬季防寒、雨季防雨等增加的人工、材料和设施费。材料检验和劳动保护属企业管理费。", "tags": ["建安费", "措施项目费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-090", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "国产非标设备原价中废品损失费按（ ）的一定比例计算。", "options": {"A": "材料费", "B": "加工费", "C": "材料费+加工费+辅助材料费+专用工具费", "D": "全部成本"}, "answer": ["C"], "analysis": "废品损失费=(材料费+加工费+辅助材料+专用工具)×比例。外购配套件不计入该基数。", "tags": ["设备购置费", "非标设备计算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-091", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "某项目总投资10000万，固定资产投资8500万，流动资金1500万，工程造价为（ ）万元。", "options": {"A": "10000", "B": "8500", "C": "7000", "D": "1500"}, "answer": ["B"], "analysis": "从投资者角度，工程造价即固定资产投资8500万元。总投资=固定资产投资+流动资金。", "tags": ["工程造价含义", "计算题"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-092", "date": "2026-07-08", "chapter": "g03", "type": "single", "stem": "关于建安费中“税金”的理解，说法正确的是（ ）。", "options": {"A": "税金即增值税", "B": "税金含增值税和城建税等", "C": "税金即企业所得税", "D": "税金即印花税"}, "answer": ["A"], "analysis": "目前建安费中的税金指增值税。城建税、教育费附加等属企业管理费中的税金。企业所得税不含在工程造价中。", "tags": ["建安费", "税金"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "ht_mgmt_0779", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "根据《建设项目经济评价方法与参数（第三版）》，建设投资由（）三项费用构成。", "options": {"A": "工程费用、建设期利息、预备费", "B": "建设费用、建设期利息、流动资金", "C": "工程费用、工程建设其他费用、预备费", "D": "建筑安装工程费、设备及工器具购置费、工程建设其他费用"}, "answer": ["C"], "analysis": "建设投资包括:工程费用、工程建设其他费用和预备费三部分。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0780", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "国外建筑工程造价构成中，反映工程造价中因缺乏资料不能完全预见和注明的项目是（）。", "options": {"A": "项目直接建设成本", "B": "项目简介建设成本", "C": "应急费", "D": "建设成本上升费用"}, "answer": ["C"], "analysis": "国外建筑工程造价构成中，反映工程造价中因缺乏资料不能完全预见和注明的项目是应急费中的未明确的准备金。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0781", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "根据世界银行对建设工程造价构成的规定，只能作为一种储备可能不动用的费用是（）。", "options": {"A": "未明确项目准备金", "B": "基本预备费", "C": "不可预见准备金", "D": "建设成本上升费用"}, "answer": ["C"], "analysis": "本题考查的是国外建设工程造价构成。不可预见准备金（在未明确项目准备金之外）用于在估算达到了一定的完整性并符合技术标准的基础上，由于物质、社会和经济的变化，导致估算增加的情况。不可预见准备金只是一种储备，可能不动用。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0782", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "已知某世行项目各项数据如下：项目管理费500 万元，开工试车费300 万元，业主的行政性费用100 万元，生产前费用600 万元，运费和保险费150 万元，地方税100 万元，建设成本上升费用120 万元，则该项目间接建设成本为（）万元。", "options": {"A": "1000", "B": "1500", "C": "1750", "D": "1870"}, "answer": ["C"], "analysis": "项目间接建设成本的组成：1)项目管理费；2)开工试车费。3)业主的行政性费用。4)生产前费用。5)运费和保险费。6)地方税。则该项目间接建设成本=500+300+100+600+150+100=1750 万元。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0783", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "在世界银行规定的项目总建设成本中，未明确项目的准备金的目的是为了（）。", "options": {"A": "支付那些估算时不可能明确的潜在项目", "B": "支付工作范围以外可能增加的项目", "C": "应付天灾、非正常经济情况及罢工等情况", "D": "用来补偿估算的误差"}, "answer": ["A"], "analysis": "未明确项目准备金:此项准备金用于在估算时不可能明确的潜在项目，包括那些在做成本估算时因为缺乏完整、准确和详细的资料而不能完全预见和不能注明的项目，并且这些项目是必须完成的,或它们的费甩是必定要发生的。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0784", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "下列项目中属于世界银行工程造价构成中间接成本的是（）。", "options": {"A": "建筑保险和债券", "B": "仪器仪表费", "C": "开工试车费", "D": "不可预见准备金"}, "answer": ["C"], "analysis": "项目间接建设成本的组成：1)项目管理费；2)开工试车费。3)业主的行政性费用。4)生产前费用。5)运费和保险费。6)地方税。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0785", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "国外建设工程造价构成中，有一部分费用的目的是补偿直至工程结束时的未知价格增长，此费用是（）。", "options": {"A": "未明确项目准备金", "B": "建设成本上升费", "C": "不可预见准备金", "D": "生产前费用"}, "answer": ["B"], "analysis": "建设成本上升费用：估算中使用的构成工资率、材料和设备价格基础的截止日期即“估算日期”。必须对该日期或已知成本基础进行调整，以补偿直至工程结束时的未知价格增长。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0786", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "下列各项中属于世界银行工程造价构成中项目直接建设成本的是（）。", "options": {"A": "开工试车费", "B": "生产前费用", "C": "业主的行政性费用", "D": "土地征购费"}, "answer": ["D"], "analysis": "项目直接建设成本包括土地征购费、场外设施费用、场地费用、工艺设备费、设备安装费、管道系统费用、电气设备费、电气安装费、仪器仪表费、机械的绝缘和油漆费、工艺建筑费、服务性建筑费用、工厂普通公共设施费、车辆费和其他当地费用。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0787", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "在世界银行工程造价的构成中，有一项费用有可能发生，有可能不发生,在正常建设条件下可能不动用，只是一种贮备。此项费用是（)。", "options": {"A": "建设成本上升费用", "B": "项目间接建设成本", "C": "未明确项目准备金", "D": "不可预见准备金"}, "answer": ["D"], "analysis": "不可预见资金用于在估算达到了一定的完整性并符合技术标准的基础上，由于物质、社会和经济的变化，导致估算增加的情况。此种情况可能发生，也可能不发生。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0788", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "在世界银行规定的项目总建设成本中，属于项目直接建设成本的是（）。", "options": {"A": "临时公共设施的维持费", "B": "开工试车费", "C": "施工管理现场人员的薪金", "D": "生产前的勘测费用"}, "answer": ["A"], "analysis": "直接建设成本包括其他当地费用。指那些不能归类于以上任何一个项目，不能计入项目间接成本，但在建设期间又是必不可少的当地费用。如临时设备、临时公共设施及场地的维持费,营地设施及其管理,建筑保险和债券，杂项开支等费用。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0789", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "按照国外建设工程造价的构成，下列费用中，属于应急费的是（）。", "options": {"A": "开工试车费", "B": "未明确项目准备金", "C": "保险费", "D": "运费"}, "answer": ["B"], "analysis": "应急费的组成：1)未明确项目准备金:此项准备金用于在估算时不可能明确的潜在项目，包括那些在做成本估算时因为缺乏完整、准确和详细的资料而不能完全预见和不能注明的项目，并且这些项目是必须完成的,或它们的费用是必定要发生的。 2)不可预见准备金:此项准备金（在未明确项目准备金之外）用于在估算达到了一定的完整性并符合技术标准的基础上，由于物质、社会和经济的变化，导致估算增加的情况。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0790", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "对于非生产性建设项目，项目总投资不包括的内容为（）。", "options": {"A": "建设投资", "B": "建设期利息", "C": "预备费", "D": "铺底流动资金"}, "answer": ["D"], "analysis": "非生产性建设项目总投资包括建设投资和建设期利息两部分。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0791", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "根据现行建设项目工程造价构成的相关规定，工程造价是指（）。", "options": {"A": "为完成工程项目建造，生产性设备及配合工程安装设备的费用", "B": "建设期内直接用于工程建造、设备购置及其安装的建设投资", "C": "为完成工程项目建设，在建设期内投入且形成现金流出的全部费用", "D": "在建设期内预计或实际支出的建设费用"}, "answer": ["D"], "analysis": "总之，工程造价是指在建设期预计或实际支出的建设费用。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0792", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "在中，为完成工程项目建设，在建设期内投入且形成现金流出的全部费用是（）。", "options": {"A": "工程造价", "B": "建设项目总投资", "C": "建设投资", "D": "工程费用"}, "answer": ["C"], "analysis": "工程造价中的主要构成部分是建设投资，建设投资是为完成工程项目建设，在建设期内投入且形成现金流出的全部费用", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0793", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "为保证工程项目顺利实施，避免在难以预料的情况下造成投资不足而预先安排的费用是()。", "options": {"A": "流动资金", "B": "建设期利息", "C": "预备费", "D": "其他资产费用"}, "answer": ["C"], "analysis": "该题主要考察的是：预备费的概念。预备费是在建设期内为各种不可预见因素的变化而预留的可能增加的费用，包括基本预备费和价差预备费。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0794", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "反映工程造价估算日期至工程竣工日期之前，工程各个主要组成部分的人工、材料和设备等未知价格增长部分的是()。", "options": {"A": "直接建设成本", "B": "建设成本上升费", "C": "不可预见准备金", "D": "未明确项目准备金"}, "answer": ["B"], "analysis": "本题考查的是建设成本上升费用的概念。通常，估算中使用的构成工资率、材料和设备价格基础的截止日期就是“估算日期”。必须对该日期或已知成本基础进行调整，建设成本上升费的目的就是补偿直至工程结束时的未知价格增长。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0795", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "根据世界银行对工程项目总建设成本的规定，下列费用应计入项目间接建设成本的是（）。", "options": {"A": "临时公共设施及场地的维持费", "B": "建筑保险和债券费", "C": "开工试车费", "D": "土地征购费"}, "answer": ["C"], "analysis": "本题考查的是项目间接建设成本，包括项目管理费、开工试车费、业主的行政费用、生产前费用、运费和保险费及地方税。 本题库是以官方教材为依据，知识点所对应的习题综合了二建法规、二建管理、造价员基础、一级造价师考试的题库+真题编辑，基本上做到了每个知识点都有相对应的题目及解析,题库会陆续更新,会有模拟题,预测题及考前更新押题。 《建设工程计量与计价实务》题库编辑中,教材出来后会陆续更新 www.jinkaodian.com 金考典考试软件。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0796", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "以直接费为取费基数时，下列企业管理费费率计算公式中，正确的是()。", "options": {"A": "企业管理费费率=年管理费总额/（全年建安产值×人工费占分部分项工程费比例）×100%", "B": "企业管理费费率=生产工人年平均管理费/（年有效施工天数×人工单价）×100%", "C": "企业管理费费率=生产工人年平均管理费/[年有效施工天数×（人工单价+每一工日机械使用费）]×100%", "D": "企业管理费费率（%）=[生产工人年平均管理费/（年有效施工天数×人工单价）]×人工费占直接费比例（%）"}, "answer": ["D"], "analysis": "以直接费为计算基础。企业管理费费率（%）=[生产工人年平均管理费/（年有效施工天数×人工单价）]×人工费占直接费比例（%）", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0797", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "根据GB/T 50500-2024《建设工程工程量清单计价标准》，下列费用中应计入人工费的是（ ）。", "options": {"A": "环境保护费", "B": "生育保险费", "C": "财务保险费", "D": "文明施工费"}, "answer": ["B"], "analysis": "在GB/T 50500-2024清单下，原规费（社会保险费含养老保险、失业、医疗、生育、工伤保险，以及住房公积金）已全部并入人工费，不再作为独立费用项。生育保险费原属规费中的社保，现并入人工费。A环境保护费属措施项目费，C财务保险费属企业管理费，D文明施工费属措施项目费。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0799", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "按照国外建筑安装工程费用的构成，下列费用中，不属于单项工程开办费的是()。", "options": {"A": "工人招聘解雇费", "B": "施工用水、用电费", "C": "临时设施费", "D": "驻工地工程师现场办公室及所需设备费用"}, "answer": ["A"], "analysis": "国外建筑安装工程费用主要由直接工程费、管理费、开办费、利润、暂定金额和分包工程费用组成，其中开办费包括施工用水、电费、工地清理费及完工后清理费、周转材料费、临时设施费、驻工地工程师的现场办公费及所需设备的费用、现场材料试验及所需设备的费用等。国外建筑安装工程费用的构成每年考核都要出现，但程度一般不深，开办费考核较多。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0800", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "根据我国现行建筑安装工程费用构成的相关规定，下列费用中，属于安装工程费用的是()。", "options": {"A": "房屋建筑工程供水、供暖等设备费用", "B": "设备基础、工作台的砌筑工程费或金属结构工程费用", "C": "对系统设备进行系统联动无负荷运转工作的调试费", "D": "对整个生产线负荷联合试运转所发生的费用"}, "answer": ["C"], "analysis": "房屋建筑工程供水、供暖等设备费用，设备基础、工作台的砌筑工程费或金属结构工程费用属于建筑工程费用的内容。对整个生产线负荷联合试运转所发生的费用是与未来生产经营有关的其他费用中的联合试运转费。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0801", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "关于建筑安装工程费中材料费的说法，正确的是()。", "options": {"A": "材料单价是指建筑材料从其来源地运到施工工地仓库直至出库形成的综合平均单价", "B": "材料消耗量是指形成工程实体的净用量", "C": "材料检验试验费包括对构件做破坏性试验的费用", "D": "材料费等于材料消耗量与材料基价的乘积加检验试验费"}, "answer": ["A"], "analysis": "材料单价是指建筑材料从其来源地运到施工工地仓库直至出库形成的综合平均单价。材料消耗量包括材料净用量和不可避免的损耗量。检验试验费不属于材料费。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0802", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "下列费用项目中，包含在国外建筑安装工程材料费中的是（）。", "options": {"A": "单独列项的是增值税", "B": "材料价格预涨费", "C": "周转材料摊销费", "D": "各种现场用水、用电费"}, "answer": ["B"], "analysis": "(2)材料费。主要包括以下内容： 1)材料原价。 2)运杂费。 3)税金。 4)运输损耗及采购保管费。 5)预涨费。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0803", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "根据《房屋建筑与装饰工程计量规范》GB50854—2013，下列措施项目中，应列入安全施工项目的是()。", "options": {"A": "现场施工机械设备防扰民措施费用", "B": "建筑工地起重机械的检验检测费用", "C": "“五牌一图”的费用", "D": "防煤气中毒等措施费用"}, "answer": ["B"], "analysis": "措施项目费的内容是以《房屋建筑与装饰工程计量规范》GB50854—2013中的规定为例。其中，A属于环境保护费，C和D均属于文明施工费。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0804", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "根据我国现行建筑安装工程费用项目组成的规定，检验试验费应计入()。", "options": {"A": "人工费", "B": "材料费", "C": "企业管理费", "D": "措施费"}, "answer": ["C"], "analysis": "根据建标[2013]（44号文），检验试验费属于企业管理费。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0805", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "下列各项中按照费用构成要素划分，不属于材料费的是()。", "options": {"A": "施工过程中耗费的原材料", "B": "施工过程中耗费的辅助材料", "C": "施工过程中耗费的半成品", "D": "施工过程中耗费的专用工具"}, "answer": ["D"], "analysis": "建筑安装工程费中的材料费，是指在施工过程中耗费的各种原材料、辅助材料、构配件、零件、半成品或成品、工程设备的费用。计算材料费的基本要素是材料消耗量和材料单价。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0806", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "根据国外建筑安装工程费用构成，施工用水、用电费应计入()。", "options": {"A": "材料费", "B": "施工机械费", "C": "管理费", "D": "开办费"}, "answer": ["D"], "analysis": "开办费包括的内容因国家和工程的不同而异，大致包括以下内容：①施工用水、用电费；②工地清理费及完工后清理费；③周转材料费；④临时设施费；⑤驻工地工程师的现场办公室及所需设备的费用，现场材料试验及所需设备的费用；⑥其他。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0807", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "施工企业按规定缴纳的车船使用税应计入建安工程造价的()。", "options": {"A": "税金", "B": "利润", "C": "企业管理费", "D": "规费"}, "answer": ["C"], "analysis": "本题考查的是企业管理费的内容。企业管理费是指建筑安装企业组织施工生产和经营管理所需的费用。内容包括：税金是指企业按规定缴纳的房产税、非生产性车船使用税、土地使用税、印花税、城市维护建设税、教育费附加、地方教育附加等各项税费", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0808", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "关于工程建设其他费用中场地准备及临时设施费的内容，下列说法中正确的是()。", "options": {"A": "施工现场临时供水管道的费用计入建设单位临时设施费", "B": "建设单位临时设施费不包括已列入建筑安装工程费用中的施工单位临时设施费用", "C": "新建和改扩建项目的场地准备和临时没施费可按工程费用的比例计算", "D": "建设场地的大型土石方工程计入场地准备费"}, "answer": ["B"], "analysis": "A选项施工现场临时供水管道费用属于建筑安装工程费用中的临时设施费；C选项新建项目的场地准备和临时设施费应根据实际工程量估算，或按工程费用的比例计算，改扩建项目一般只计拆除清理费；D选项建设场地的大型土石方工程应进入工程费用中的总图运输费用中。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0809", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "根据我国现行建筑安装工程费项目组成的规定，下列费用应列入暂列金额的是（）。", "options": {"A": "施工过程中可能发生的工程变更及索赔、现场签证等费用", "B": "应建设单位要求，完成建设项目之外的零星项目费用", "C": "对建设单位自行采购的材料进行保管所发生的费用", "D": "施工用电、用水的开办费"}, "answer": ["A"], "analysis": "暂列金额是指建设单位在工程量清单中暂列并包括在工程合同价款中的一笔款项。用于施工合同签订时尚未确定或者不可预见的所需材料、工程设备、服务的采购，施工中可能发生的工程变更、合同约定调整因素出现时的工程价款调整以及发生的索赔、现场签证确认等的费用。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0810", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "根据我国现行建筑安装工程费用项目组成的规定，下列关于措施项目费用的说法中正确的是（）。", "options": {"A": "冬雨季施工费是冬、雨季施工增加的临时设施，防滑处理，雨雪排除等费用", "B": "施工排水、降水费由排水和降水两个独立的费用项目组成", "C": "当单层建筑物檐口高度超过15m时，可计算超高施工增加费", "D": "已完工程及设备保护费是指分部工程或结构部位验收前，对已完工程及设备采取必要保护措施所发生的费用"}, "answer": ["A"], "analysis": "冬雨季施工增加费。冬雨季施工增加费是指因冬雨季天气原因导致施工效率降低加大投入而增加的费用，以及为确保冬雨季施工质量和安全而采取的保温、防雨等措施所需的费用。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0811", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "在国外建筑安装工程费用中，属于开办费的项目是()。", "options": {"A": "业务所需手续费", "B": "业务资料费", "C": "代理人的费用与佣金", "D": "恶劣气候条件下的工程防护措施费"}, "answer": ["D"], "analysis": "开办费包括的内容因国家和工程的不同而异，大致包括以下内容：①施工用水、用电费；②工地清理费及完工后清理费；③周转材料费；④临时设施费；⑤驻工地工程师的现场办公室及所需设备的费用，现场材料试验及所需设备的费用；⑥其他。其他包括工人现场福利费及安全费、职工交通费、日常气候报表费、现场道路及进出场道路修筑及维护费、恶劣天气下的工程保护措施费、现场保卫设施费等。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0812", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "在国外建筑安装工程费用中，工作人员劳动保护费应列入()。", "options": {"A": "人工费", "B": "材料费", "C": "管理费", "D": "暂定金额"}, "answer": ["C"], "analysis": "国外建筑安装工程费用中，管理费除了包括与我国施工管理费构成相似的工作人员工资、工作人员辅助工资、办公费、差旅交通费、固定资产使用费、生活设施使用费、工具用具使用费、劳动保护费、检验试验费以外，还含有业务经费。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0813", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "根据《房屋建筑与装饰工程计量规范》的规定，垂直运输费中包括行走式垂直运输机械的是( )。", "options": {"A": "固定装置费", "B": "基础制作费", "C": "轨道铺设费", "D": "安装费"}, "answer": ["C"], "analysis": "垂直运输机械费是指现场所用材料、机具从地面运至相应高度以及职工人员上下工作面等所发生的运输费用。内容由以下各项组成： (1)垂直运输机械的固定装置、基础制作、安装费； (2)行走式垂直运输机械轨道的铺设、拆除、摊销费。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0814", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "下列关于费用的构成和计算的说法中，表述不正确的有（）。", "options": {"A": "建筑安装工程费按照费用构成要素划分:由人工费、材料费（包含工程设备）、施工机具使用费、企业管理费构成", "B": "材料费的基本要素包括材料消耗量和材料单价", "C": "建筑安装工程费中的施工机具使用费，是指施工作业所发生的施工机械、仪器仪表使用费或其租赁费", "D": "施工机械使用费=Σ（施工机械台班消耗量×机械台班单价）"}, "answer": ["A"], "analysis": "建筑安装工程费按照费用构成要素划分:由人工费、材料费（包含工程设备）、施工机具使用费、企业管理费、利润、增值税组成。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0815", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "下列设施的费用应计入安全文明施工措施费的是（）。", "options": {"A": "安全施工标志的购置及安全宣传费用", "B": "工程排污费", "C": "财产保险费", "D": "工伤保险费"}, "answer": ["A"], "analysis": "安全施工标志购置及宣传费用属于安全文明施工措施费。B工程排污费原属规费(现并入人工费)，C财产保险费属企业管理费，D工伤保险费原属规费(现并入人工费)。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0816", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "根据我国现行建筑安装工程费用项目构成的规定，下列费用中属于安全文明施工费的（）。", "options": {"A": "夜间施工时，临时可移动照明灯具的设置、拆除费用", "B": "工人安全防护用品的购置费用", "C": "地下室施工时采用的照明设施拆除费", "D": "建筑物的临时保护设施费"}, "answer": ["B"], "analysis": "属于夜间施工增加费;C 属于非夜间施工照明费;D 选项属于建筑物的临时保护设施费。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0817", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "下列费用项目中，不属于按造价形成划分建筑工程费用项目构成的是（）。", "options": {"A": "分部分项工程费", "B": "临时设施费", "C": "二次搬运费", "D": "施工机具使用费"}, "answer": ["D"], "analysis": "按造价形成划分建筑工程费用项目构成包括:分部分项工程费、措施项目费和其他项目费。临时设施费与二次搬运费属于措施项目费中的安全文明施工费。施工机具使用费属于按费用构成要素划分建筑安装工程费用项目的构成。 本题库是以官方教材为依据，知识点所对应的习题综合了二建法规、二建管理、造价员基础、一级造价师考试的题库+真题编辑，基本上做到了每个知识点都有相对应的题目及解析,题库会陆续更新,会有模拟题,预测题及考前更新押题。 《建设工程计量与计价实务》题库编辑中,教材出来后会陆续更新 www.jinkaodian.com 金考典考试软件。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0818", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "国外建筑安装工程费用中，单项工程费用由()构成。", "options": {"A": "各分部分项工程费、单项工程开办费", "B": "直接工程费、管理费、利润及税金", "C": "直接工程费、开办费、利润及税金", "D": "各分部分项工程费、单项工程开办费、措施费"}, "answer": ["A"], "analysis": "本题考查的是国外建筑安装工程费用的构成。根据图1.3.2 国外建筑安装工程费用构成；各单项工程费用由各分部分项工程费用与单项工程开办费构成。 本题库是以官方教材为依据，知识点所对应的习题综合了二建法规、二建管理、造价员基础、一级造价师考试的题库+真题编辑，基本上做到了每个知识点都有相对应的题目及解析,题库会陆续更新,会有模拟题,预测题及考前更新押题。 《建设工程计量与计价实务》题库编辑中,教材出来后会陆续更新 www.jinkaodian.com 金考典考试软件。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0819", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "因施工场地狭小等特殊情况而发生的二次搬运费用应属于( )。", "options": {"A": "分部分项工程费", "B": "措施费", "C": "规费", "D": "企业管理费"}, "answer": ["B"], "analysis": "二次搬运费。二次搬运费是指因施工管理需要或因场地狭小等原因，导致建筑材料、设备等不能一次搬运到位，必须发生的二次或以上搬运所需的费用。 本题库是以官方教材为依据，知识点所对应的习题综合了二建法规、二建管理、造价员基础、一级造价师考试的题库+真题编辑，基本上做到了每个知识点都有相对应的题目及解析,题库会陆续更新,会有模拟题,预测题及考前更新押题。 《建设工程计量与计价实务》题库编辑中,教材出来后会陆续更新 www.jinkaodian.com 金考典考试软件。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0820", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "根据《建设项目工程总承包合同示范文本（试行）》GF-2011-2016，下列变更事项，属于采购变更的是（）。", "options": {"A": "对设备规格和数量的调整", "B": "改变检查、检验、检测、试验地点", "C": "重新进行竣工试验", "D": "对配套工程系统的工艺调整"}, "answer": ["B"], "analysis": "2)采购变更。采购变更的范围包括：③发包人要求改变检査、检验、检测、试验的地点和增加的附加试验； 本题库是以官方教材为依据，知识点所对应的习题综合了二建法规、二建管理、造价员基础、一级造价师考试的题库+真题编辑，基本上做到了每个知识点都有相对应的题目及解析,题库会陆续更新,会有模拟题,预测题及考前更新押题。 《建设工程计量与计价实务》题库编辑中,教材出来后会陆续更新 www.jinkaodian.com 金考典考试软件。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0821", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "采用成本计算估价法计算非标准设备原价时，下列表述正确的是（）。", "options": {"A": "专用工具费＝（材料费＋加工费）×专用工具费率", "B": "加工费＝设备总重量×（1＋加工耗损系数）×设备每吨加工费", "C": "包装费的计算基数中不应包含废品损失费", "D": "利润的计算基数中不应包含外购配套件费"}, "answer": ["D"], "analysis": "本题考查是设备购置费的构成和计算。专用工具费=（材料费+加工费+辅助材料费）×专用工具费率；加工费=设备总重量（吨）×设备每吨加工费；包装费=（材料费+加工费+辅助材料费+专用工具费+废品损失费+外购配套件费）×包装费率；利润=（材料费+加工费+辅助材料费+专用工具费+废品损失费+包装费）×利润率。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0822", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "下列关于工具、器具及生产家具购置费的表述中，正确的是（）。", "options": {"A": "该项费用属于设备费", "B": "该项费用属于工程建设其他费用", "C": "该项费用是为了保证项目生产运营期的需要而支付的相关购置费用", "D": "该项费用一般以需要安装的设备购置费为基数乘以一定费率计算"}, "answer": ["D"], "analysis": "该题考核工具及生产家具购置费的构成，考核的关键是工具、器具及生产家具购置费指新建或扩建项目初步设计规定的，保证初期正常生产必须购置的没有达到固定资产标准的设备、仪器、工卡模具、器具、生产家具和备品备件等的购置费用。一般以设备购置费为计算基数,按照部门或行业规定的工具、器具及生产家具费率计算。计算公式为:工具、器具及生产家具购置费=设备购置费×定额费率。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0823", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "用成本计算估价法计算国产非标准设备原价时，利润的计算基数中不包括的费用项目是（）。", "options": {"A": "材料费", "B": "税金", "C": "专用工具费", "D": "包装费"}, "answer": ["B"], "analysis": "国产非标准设备原价中的利润，按照材料费、加工费、辅助材料费、专用工具费、废品损失费、包装费之和乘以一定百分比计算。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0824", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "进口设备采用装运港船上交货价(FO B)时，买方需承担的责任不包括()。", "options": {"A": "租船舱，支付运费", "B": "装船后的一切风险和运费", "C": "办理出口手续，并将货物装上船", "D": "办理海外运输保险并支付保险费"}, "answer": ["C"], "analysis": "办理出口手续，并将货物装上船属于卖方的基本义务。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0825", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "采用FOB货价方式进口设备抵岸价构成中，国际运费是指()。", "options": {"A": "从出口国的生产厂起到我国建设项目工地仓库止的运费", "B": "从出口国的生产厂起到我国抵达港（站）止的运费", "C": "从装运港（站）起到我国目的港（站）止的运费", "D": "从装运港（站）起到我国建设项目工地仓库止的运费"}, "answer": ["C"], "analysis": "国际运费是指从装运港（站）到达我国目的港（站）的运费。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0826", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "在进口设备原价的组成中，属于进口从属费用的是()。", "options": {"A": "货价", "B": "国际运费", "C": "运输保险费", "D": "外贸手续费"}, "answer": ["D"], "analysis": "进口从属费包括银行财务费、外贸手续费、关税、消费税、进口环节增值税等。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0827", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "采用成本计算估价法计算国产非标准设备原价时，包装费的计取基数不包括该设备的()。", "options": {"A": "材料费", "B": "加工费", "C": "外购配套件费", "D": "设计费"}, "answer": ["D"], "analysis": "包装费的计算基数包括：材料费、辅助材料费、加工费、专用工具费、废品损失费、外购配套件费共六项。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0828", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "下列项目中属于设备运杂费中运费和装卸费的是()。", "options": {"A": "国产设备由设备制造厂交货地点起至工地仓库止所发生的运费", "B": "进口设备由设备制造厂交货地点起至工地仓库止所发生的运费", "C": "为运输而进行的包装支出的各种费用", "D": "进口设备由设备制造厂交货地点起至施工组织设计指定的设备堆放地点止所发生的运费"}, "answer": ["A"], "analysis": "国产设备由设备制造厂交货地点起至工地仓库（ 或施工组织设计指定的需要安装设备的堆放地点）止所发生的运费和装卸费；进口设备则由我国到岸港口或边境车站起至工地仓库（ 或施工组织设计指定的需安装设备的堆放地点）止所发生的运费和装卸费。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0829", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "下列费用项目中，属于工器具及生产家具购置费计算内容的是()。", "options": {"A": "未达到固定资产标准的设备购置费", "B": "达到固定资产标准的设备购置费", "C": "引进设备时备品备件的测绘费", "D": "引进设备的专利使用费"}, "answer": ["A"], "analysis": "本题考查的是工器具及生产家具购置费的概念。工器具及生产家具购置费，是指新建或扩建项目初步设计规定的，保证初期正常生产必须购置的没有达到固定资产标准的设备、仪器、工卡模具、器具、生产家具和备品备件等的购置费用。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0830", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "某进口设备的人民币货价为50万元，国际运费费率为10%，运输保险费费率为3%，进口关税税率为20%，则该设备应支付关税税额是()万元。", "options": {"A": "11.34", "B": "11.43", "C": "11.30", "D": "10.00"}, "answer": ["A"], "analysis": "进口设备关税的计算公式如下： 进口设备关税=CIF×关税税率×人民币外汇汇率 CIF=货价(FOB)+国际运费+运输保险费 国际运费=货价×国际运费率 运输保险费=[FOB（原币）+国际运费]／（1-保险费率）×保险费率 本题计算结果为：国际运费=50×10%=5（万元） 国际运输保险费=(50+5)×3%／(1-3%)=1.7（万元） CIF=50+5+1.7=56.7（万元） 关税=56.7×20%=11.34（万元）", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0831", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "某批进口设备离岸价格为1000万元，国际运费为100万元，运输保险费率为1%。则该批设备关税完税价格应为（）万元。", "options": {"A": "1100", "B": "1110", "C": "1111", "D": "1111.11"}, "answer": ["D"], "analysis": "到岸价=离岸价+国际运费+运输保险费，而运输保险费费率为1%，则运输保险费=(1000+100)/(1-0.01)*0.01=1100/99关税完税价格=到岸价=离岸价+国际运费+运输保险费=1100+1100/99约等于1111.11", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0832", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "就国际贸易的各种交易价格而言，以下各种价格中费用划分与风险转移分界点相一致的是（）。", "options": {"A": "离岸价格", "B": "运费在内价", "C": "到岸价格", "D": "抵岸价格"}, "answer": ["A"], "analysis": "(1)FOB(freeonboard),意为装运港船上交货，亦称为离岸价格。. FOB术语是指当货物在装运港被装上指定船时，卖方即完成交货义务。风险转移，以在指定的装运港货物被装上指定船时为分界点。费用划分与风险转移的分界点相一致。 本题库是以官方教材为依据，知识点所对应的习题综合了二建法规、二建管理、造价员基础、一级造价师考试的题库+真题编辑，基本上做到了每个知识点都有相对应的题目及解析,题库会陆续更新,会有模拟题,预测题及考前更新押题。 《建设工程计量与计价实务》题库编辑中,教材出来后会陆续更新 www.jinkaodian.com 金考典考试软件。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0833", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "下列属于工程建设其他费用中与未来生产经营有关的其他费用的是()。", "options": {"A": "引进技术和引进设备其他费", "B": "人员培训及提前进场费", "C": "建设管理费", "D": "工程监理费"}, "answer": ["B"], "analysis": "与未来生产经营有关的其他费用主要包括生产准备及开办费等，具体包括：(1)人员培训费及提前进厂费。包括自行组织培训或委托其他单位培训的人员工资、工资性补贴、职工福利费、差旅交通费、劳动保护费、学习资料费等；选项D属于建设管理费，选项A、C属于与项目建设有关的其他费用，", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0834", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "下列费用中，属于与项目建设有关的其他费用中研究试验费的是()。", "options": {"A": "按施工验收规定在施工中必须进行试验所需费用", "B": "应在建筑安装费用中列支的施工企业对建筑材料、构件和建筑物进行一般鉴定、检查所发生的费用及技术革新的研究试验费", "C": "应由科技三项费用（即新产品试制费、中间试验费和重要科学研究补助费）开支的项", "D": "应由勘察设计费或工程费用中开支的项目"}, "answer": ["A"], "analysis": "研究试验费是指为建设项目提供或验证设计数据、资料等进行必要的研究实验及按照相关规定在建设过程中必须进行试验、验证所需的费用。研究试验费包括自行或委托其他部门研究试验所需人工费、材料费、试验设备及仪器使用费等，但不包括以下项目： (1)应由科技三项费用（即新产品试制费、中间试验费和重要科学研究补助费）开支的项目。 (2)应在建筑安装费用中列支的施工企业对建筑材料、构件和建筑物进行一般鉴定、检查所发生的费用及技术革新的研究试验费。 (3)应由勘察设计费或工程费用中开支的项目。 本题中选项A属于上述不应包括的第(2)项：对建筑材料、构件和建筑物进行一般鉴定发生的费用。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0835", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "土地补偿费为该耕地被征用前三年平均年产值的()倍。", "options": {"A": "2～3", "B": "3～5", "C": "6～10", "D": "8～12"}, "answer": ["C"], "analysis": "土地补偿费为该耕地被征用前三年平均年产值的6～10倍。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0836", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "根据设计要求，在施工过程中对某屋架结构进行破坏性试验，以提供和验证设计数据，则该项费用应在()中支出。", "options": {"A": "研究试验费", "B": "施工方的检验试验费", "C": "建设单位管理费", "D": "勘察设计费"}, "answer": ["A"], "analysis": "研究试验费是指为建设项目提供或验证设计参数、数据资料等进行必要的研究试验以及设计规定在施工中进行的试验、验证所需费用。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0837", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "按我国现行投资构成，下列费用中不属于与项目建设有关的其他费用的是()。", "options": {"A": "勘察设计费", "B": "研究试验费", "C": "工程监理费", "D": "联合试运转费"}, "answer": ["D"], "analysis": "联合试运转费属于与未来生产经营有关的其他费用。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0838", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "在征地补偿费和拆迁补偿费中都可能包含的费用是( )。", "options": {"A": "安置补助费", "B": "土地补偿费", "C": "青苗补偿费", "D": "地上附着物补偿费"}, "answer": ["A"], "analysis": "征地补偿费中包括：土地补偿费、青苗补偿费和地上附着物补偿费、安置补助费、新菜地开发建设基金、耕地占用税、土地管理费；拆迁补偿费包括拆迁补偿和搬迁、安置补助费", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0839", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "下列费用项目中，计入工程建设其他费中专利及专有技术使用费的是( )。", "options": {"A": "专利及专有技术在项目全寿命期的使用费", "B": "在生产期支付的商标权费", "C": "国内设计资料费", "D": "国外设计资料费"}, "answer": ["D"], "analysis": "本题考查的是与项目建设有关的其他建设费用。专利及专用技术使用费的主要内容：①国外设计及技术资料费、引进有效专利、专有技术使用费和技术保密费。②国内有效专利、专有技术使用费。③商标权、商誉和特许经营权费等。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0840", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "关于建设用地的取得及使用年限，下列说法中正确的是（）。", "options": {"A": "获取建设用地使用权的方式可以是租赁或转让", "B": "通过协议出让获取土地使用权的方式分为投标、竞拍、挂牌三种", "C": "城市公益事业用地不得以划拨方式取得", "D": "将土地使用权无偿交付给使用者的，其土地使用年限最高为70年"}, "answer": ["A"], "analysis": "建设用地的取得，实质是依法获取国有土地的使用权。根据我国《房地产管理法》规定，获取国有土地使用权的基本方法有两种：一是出让方式；二是划拨方式。建设土地取得的基本方式还包括租赁和转让方式。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0841", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "关于土地征用及迁移补偿费的说法中，正确的是()。", "options": {"A": "征用耕地的土地补偿费标准为该地被征用前三年，平均年产值的4～6倍", "B": "拆迁补偿的方式可以实行货币补偿", "C": "青苗补偿费归农村集体所有", "D": "被征用耕地的安置补助费最高不超过被征用前三年平均年产值的30倍"}, "answer": ["B"], "analysis": "征用耕地的土地补偿费标准为该地被征用前三年，平均年产值的6～10倍；若农民自行承包土地的青苗补偿费应付给本人；每公顷被征用耕地的安置补助费最高不超过被征用前三年平均年产值的15倍。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0842", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "下列费用项目中，属于工程建设其他费中研究试验费的是（）。", "options": {"A": "新产品试制费", "B": "水文地质勘查费", "C": "特殊设备安全监督检验费", "D": "委托专业机构验证设计参数而发生的验证费"}, "answer": ["D"], "analysis": "研究试验费是指为建设项目提供或验证设计数据、资料等进行必要的研究试验及按照相关规定在建设过程中必须进行试验、验证所需的费用。包括自行或委托其他部门研究试验所需人工费、材料费、试验设备及仪器使用费等。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0844", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "根据《中华人民共和国城镇国有土地使用权出让和转让暂行条例》土地使用权出让最高年限按土地用途确定，工业用地的最高年限为（）年。", "options": {"A": "40", "B": "50", "C": "60", "D": "70"}, "answer": ["B"], "analysis": "本题考査土地使用权出让年限的确定。通过土地使用权出让，是指国家将国有土地使用权在一定年限内出让给土地使用者，由土地使用者向国家支付土地使用权出让金的行为。土地使用权出让最高年限按下列用途确定:①居住用地70 年;②工业用地50 年;③教育、科技、文化、卫生、体育用地50 年;④商业、旅游、娱乐用地40 年;⑤综合或者其他用地50 年。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0845", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "下列费用中，不属于工程建设其他费用中工程保险费的是（）。", "options": {"A": "建筑安装工程一切险保费", "B": "引进设备财产保险保费", "C": "危险作业意外伤害险保费", "D": "人身意外伤害险保费"}, "answer": ["C"], "analysis": "工程保险费包含建筑安装工程一切险、引进设备财产保险和人身意外伤害险等。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0846", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "某行政大厅工程项目，建设期为3 年，建设期内在第1 年和第2 年均衡获得的贷款额分别为2000 万元，第3 年均衡获得的贷款额为1500 万元，贷款年利率为6%，期内只计息不支付，建设期应计利息为（）万元。", "options": {"A": "359.62", "B": "525.00", "C": "543.22", "D": "719.23"}, "answer": ["C"], "analysis": "计算过程如下： 第1 年建设期利息=2000x6%/2=60(万元） 第2 年建设期利息=(2000+60+2000/2)x6%=183.60(万元） 第3 年建设期利息=(2000+60+2000+183.60+1500/2)x6%=299.62(万元） 项目的价差预备费合计为543.22 万元。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0847", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "根据我国现行规定，关于预备费的说法中，不正确的是（）。", "options": {"A": "基本预备费以工程费用为计算基数", "B": "实行工程保险的工程项目，基本预备费应适当降低", "C": "价差预备费以静态投资为计算基数", "D": "价差预备费应包括利率、汇率调整增加的费用"}, "answer": ["A"], "analysis": "按我国现行规定，预备费包括基本预备费和价差预备费。基本预备费是按工程费用和工程建设其他费用二者之和为计取基础,乘以基本预备费费率进行计算。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0848", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "例：某建设项目建设期为三年，各年分别获得贷款2000 万元、4000 万元和2000 万元，贷款分年度均衡发放，年利率为6%，建设期利息只计息不支付，则建设期第三年应计贷款利息为（）万元。", "options": {"A": "420.016", "B": "434.616", "C": "438.216", "D": "467.216"}, "answer": ["C"], "analysis": "第一年1/2*1000*6%=60 万 第二年（2000+60+1/2*4000）*60%=243.6 万 第三年（2000+60+243.6+4000+1/2*2000）*6%=438.216 万", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0849", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "某项目建设前期可视为0 年，建设期3 年，在第一年静态投资2000 万元，第二年2000 万元，第三年1000万元，年均投资价格上涨率为5%,则该项目的价差预备费为()万元。", "options": {"A": "250.00", "B": "330,98", "C": "462.63", "D": "570.25"}, "answer": ["B"], "analysis": "计算过程如下： 第1 年价差预备费=2000x[(1+5%)0.5-1]=49.36（万元） 第2 年价差预备费=2000x[(1+5%)*'5-1]=151.86（万元） 第3 年价差预备费=1000x[(1+5%)2-5-1]=129.73（万元） 项目的价差预备费合计为330.98 万元。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0850", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "某建设项目工程费用为2000 万元，工程建设其他费用为800 万元，已知基本预备费费率为10%,项目建设前期为1 年,建设期3 年，各年投资计划额为:第1 年20%,第2 年50%，第3 年30%。若年涨价率为5%，则该项目建设期间价差预备费为（）万元。", "options": {"A": "418.61", "B": "334.30", "C": "323.4", "D": "505.01"}, "answer": ["A"], "analysis": "建设项目静态投资=(2000+800)×(l+10%)=3080(万元） PF1=3080×20%×(1.051.5-1)=46.77(万元） PF2=3080×50%×(1.052.5-1)=199.78(万元） PF3=3080×30%×(1.053.5-1)=172.06(万元) PF=PF1+PF2+PF3=418.61(万元）", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0851", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "预备费包括基本预备费和价差预备费，其中价差预备费的计算应是( )。", "options": {"A": "以编制年份的静态投资额为基数，采用单利方法", "B": "以编制年份的静态投资额为基数，采用复利方法", "C": "以估算年份价格水平的投资额为基数，采用单利方法", "D": "以估算年份价格水平的投资额为基数，采用复利方法"}, "answer": ["D"], "analysis": "本题考查的是价差预备费的计算。价差预备费一般根据国家规定的投资综合价格指数，按估算年份价格水平的投资额为基数，采用复利方法计算。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0852", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "关于我国现行建设项目投资构成的说法中，正确的是()。", "options": {"A": "固定资产投资为建设投资和建设期利息之和", "B": "工程费用为直接费、间接费、利润和税金之和", "C": "生产性建设项目总投资为建设投资和建设期利息之和", "D": "工程造价为工程费用、工程建设其他费用和预备费之和"}, "answer": ["A"], "analysis": "生产性建设项目总投资为建设投资、建设期利息和流动资金三部分。工程造价与固定资产投资在量上相等，等于建设投资和建设期利息之和。工程费用是指直接构成固定资产实体的各种费用，可以分为建筑安装工程费和设备及工器具购置费。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0853", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "某建设项目，经投资估算确定的工程费用为2100万元，工程建设其他费为900万元，项目建设期为2年，每年各完成投资计划50%。年均投资价格上涨率为10%，基本预备费费率为5%，项目建设前期1年。该项目建设期的价差预备费为()万元。", "options": {"A": "350.67", "B": "396.86", "C": "443.88", "D": "665.83"}, "answer": ["D"], "analysis": "基本预备费=（工程费用+工程建设其他费用）×基本预备费费率=(2100+", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0854", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "某新建项目，建设期4年，分年均衡进行贷款，第一年贷款1000万元，以后各年贷款均为500万元，年贷款利率为6%，建设期内利息只计息不支付，该项目建设期利息为()万元。", "options": {"A": "76.80", "B": "106.80", "C": "366.30", "D": "389.35"}, "answer": ["C"], "analysis": "q1=1/2×1000×0.06=30（万元）；q2=(1030+500/2)×0.06=76.8（万元）；q3=(1030+500+76.8+500/2)×0.06=111.408（万元）；q4=(1030+500+76.8+500+111.408+500/2)×0.06=148.092（万元）；建设期贷款利息为：30+76.8+111.408+148.092=366.3（万元）。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0855", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "某新建项目，建设期2年，第一年贷款200万元，第二年贷款500万元。贷款在年度内均衡发放。根据贷款协定：年利率为8%，每半年计息一次，贷款本息均在项目投产后偿还，则该项目建设期的贷款利息是()万元。", "options": {"A": "44.16", "B": "45.55", "C": "22.08", "D": "37.39"}, "answer": ["B"], "analysis": "半年计息一次的年实际利率是：(1+8%/2)2-1=8.16%；第一年的应计利息：1/2×200×8.16%=8.16（万元）；第二年的应计利息：(200+8.16+1/2×500)×8.16%=37.39（万元）；两年应计利息总数=8.16+37.39=45.55（万元）。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0856", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "某项目建设期为2年，分年均衡进行贷款，在建设期第一年贷款2000万元，第2年贷款3000万元，贷款年利率为8%，建设期内利息只计息不支付，则该项目第二年的建设期贷款利息估算为()万元。", "options": {"A": "80.4", "B": "286.4", "C": "160", "D": "240"}, "answer": ["B"], "analysis": "在建设期，各年利息计算如下：第一年应计利息=1/2×2000×8%=80（万元）；第二年应计利息=(2000+80+1/2×3000)×8%=286.4（万元）。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0857", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "一般自然灾害造成的损失和预防自然灾害所采取的措施费用，应计入()。", "options": {"A": "现场经费", "B": "施工企业管理费", "C": "价差预备费", "D": "基本预备费"}, "answer": ["D"], "analysis": "基本预备费一般由以下四部分构成：(1) 工程变更及洽商。在批准的初步设计范围内，技术设计、施工图设计及施工过程'中所增加的工程费用；设计变更、工程变更、材料代用、局部地基处理等增加的费用。(2) —般自然灾害处理。一般自然灾害造成的损失和预防自然灾害所采取的措施费用。实行工程保险的工程项目，该费用应适当降低。(3) 不可预见的地下障碍物处理的费用。(4) 超规超限设备运输增加的费用。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0858", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "某项目共需要贷款资金900万元，建设期为3年，按年度均衡筹资，第一年贷款为300万元，第二年贷款为400万元，建设期内只计利息但不支付，年利率为10%，则第2年的建设期利息应为（）万元。", "options": {"A": "50", "B": "51.5", "C": "71.5", "D": "86.65"}, "answer": ["B"], "analysis": "q1=（300/2）×10%=15万元，q2=（300+15+400/2）×10%=51.5万元。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0859", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "某建设项目静态投资20000万元，项目建设前期年限为1年，建设期为2年，计划每年完成投资50%，年均投资价格上涨率为5%，该项目建设期价差预备费为（）万元。", "options": {"A": "1006.25", "B": "1525.00", "C": "2056.56", "D": "2601.25"}, "answer": ["C"], "analysis": "2.价差预备费的测算方法 价差预备费一般根据国家规定的投资综合价格指数，按估算年份价格水平的投资额为 基数，采用复利方法计算。第一年价差预备费=10000×[（1+5%）×（1+5%）0.5-1]=759.30（万元） 第二年的价差预备费=10000×[（1+5%）×（1+5%）0.5×（1+5%）-1]=1297.26（万元） 价差预备费合计=759.30+1297.26=2056.56（万元）", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0860", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "根据我国现行建设项目投资构成，下列费用项目中属于建设期利息包含内容的是()。", "options": {"A": "建设单位建设期后发生的利息", "B": "施工单位建设期长期贷款利息", "C": "国内代理机构收取的贷款管理费", "D": "国外贷款机构收取的转贷费"}, "answer": ["C"], "analysis": "本题考查的是建设期利息的内容。利用国外贷款的利息计算中，年利率应综合考虑贷款协议中向贷款方加收的手续费、管理费、承诺费，以及国内代理机构向贷款方收取的转贷费、担保费和管理费等。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0861", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "某新建项目，建设期3年，第一年贷款300万元，第二年贷款600万元，第三年没有贷款。贷款在年度内均衡发放。根据贷款协定：年利率为4%，以年利率方式收取的担保费和管理费率共计2%，贷款本息均在项目投产后偿还，则该项目第三年的贷款利息是()万元。", "options": {"A": "36.00", "B": "54.54", "C": "56.73", "D": "58.38"}, "answer": ["C"], "analysis": "建设期利息可按当年借款在年中支用考虑，即当年贷款按半年计息，上年贷款按全年计息。其计算公式为： 本题只考核其中一年，且第三年无贷款。考试形式的多样化，这也是出题的一个趋势。 要计算第三年的贷款利息，务必要计算前面各期的贷款利息，此处利息应包括以年利率方式收取的担保费和管理费。 贷款利息为4%+2%=6% 第一年贷款利息为：300×1/2×6%=9（万元） 第二年贷款利息为：(300+9+0.5×600)×6%=36.54（万元） 第三年贷款利息为：(300+9+600+36.54)×6%=56.73（万元） 计算此题时，要注意年初（或期初）借款额是借款的本利和，包括以前各期的本金和利息。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0862", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "某建设项目在竣工验收时，为了鉴定一项隐蔽工程质量，进行了必要挖掘，则该项挖掘费用应计入()。", "options": {"A": "涨价预备费", "B": "基本预备费", "C": "间接费", "D": "其他间接费"}, "answer": ["B"], "analysis": "基本预备费是指投资估算或工程概算阶段预留的，由于工程实施中不可预见的工程变更及洽商、一般自然灾害处理、地下障碍物处理、超规超限设备运输等而可能增加的费用，亦可称为工程建设不可预见费，", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0863", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "某项目建设期内第一年贷款100万元，第二年贷款200万元，贷款在各年内均衡发放，且均衡偿还，年利率10%，建设期内利息只计息不支付，则建设期利息为()万元。", "options": {"A": "30", "B": "40", "C": "25.5", "D": "41"}, "answer": ["C"], "analysis": "在建设期，各年利息计算如下：第一年应计利息=1/2×100×10%=5（万元）；第二年应计利息=(100+5+1/2×200)×10%=20.5（万元）；建设贷款利息总和=5+20.5=25.5（万元）。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0864", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "某新建项目，建设期2年，建设期内贷款分年度均衡发放，且只计息不还款，第1年贷款600万元，第2年贷款400万元，年利率为7%。则该项目的建设期利息为()万元。", "options": {"A": "77.00", "B": "78.47", "C": "112.00", "D": "114.94"}, "answer": ["B"], "analysis": "当总贷是分年均衡发放时，建设期利息的计算可按当年借款在年中支用考虑，即当年贷款按半年计息，上年贷款按全年计息。第1年贷款利息=0.5×600×7%=21（万元）第2年贷款利息=（600+21+0.5×400）×7%=57.47（万元）所以，建设期利息=21+57.47=78.47（万元）", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0865", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "自行组织培训或委托其他单位培训的人员工资、工资性补贴、职工福利费、差旅交通费、劳动保护费、学习资料费等支出应计入()。", "options": {"A": "建筑安装工程费", "B": "建设单位管理费", "C": "生产准备", "D": "联合试运转费"}, "answer": ["C"], "analysis": "包括自行组织培训或委托其他单位培训的人员工资、工资性补贴、职工福利费、差旅交通费、劳动保护费、学习资料费等属于生产准备费中的人员培训费及提前进场费。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0866", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "在我国建设项目投资构成中，超规超限设备运输增加的费用属于( )。", "options": {"A": "设备及工器具购置费", "B": "基本预备费", "C": "工程建设其他费", "D": "建筑安装工程费"}, "answer": ["B"], "analysis": "本题考查的是预备费。超规超限设备运输增加的费用属于基本预备费。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0867", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "按现行对基本预备费内容的规定，不属于基本预备费范围的是()费用。", "options": {"A": "设计变更增加的", "B": "局部地基处理增加的", "C": "利率调整增加的", "D": "预防自然灾害采取的措施"}, "answer": ["C"], "analysis": "基本预备费是指在项目实施中可能发生难以预料的支出，需要预先预留的费用，主要是指设计变更及施工过程中可能增加工程量的费用。利率调整增加属于价差预备费。 本题库是以官方教材为依据，知识点所对应的习题综合了二建法规、二建管理、造价员基础、一级造价师考试的题库+真题编辑，基本上做到了每个知识点都有相对应的题目及解析,题库会陆续更新,会有模拟题,预测题及考前更新押题。 《建设工程计量与计价实务》题库编辑中,教材出来后会陆续更新 www.jinkaodian.com 金考典考试软件。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0868", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "(2013年)国外建筑工程造价构成中，反映工程造价估算日期至工程竣工日期之前，工程各个主要组成部分的人工、材料和设备等未知价格增长部分是()。", "options": {"A": "直接建设成本", "B": "建设成本上升费", "C": "不可预见准备金", "D": "未明确项目准备金"}, "answer": ["B"], "analysis": "估算中使用的构成工资率、材料和设备价格基础的截止日期就是“估算日期”，必须对该日期或已知成本基础进行调整，以补偿直至工程结束时的未知价格增长。这部分价格增长在工程造价中体现为建设成本上升费用。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0869", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "(2016年)关于我国建设项目投资，以下说法正确的是()。", "options": {"A": "非生产性建设项目总投资由固定资产投资和铺底流动资金组成", "B": "生产性建设项目总投资由工程费用、工程建设其他费用和预备费三部分组成", "C": "建设投资是为了完成工程项目建设，在建设期内投入且形成现金流出的全部费用", "D": "建设投资由固定资产投资和建设期利息组成"}, "answer": ["C"], "analysis": "本题主要考察建设项目投资构成概念，“生产性建设项目总投资包括建设投资、建设期贷款利息和流动资金三部分非生产性建设项目总投资包括建设投资和建设期贷款利息两部分，其中建设投资和建设期贷款利息之和对应固定资产投资”故A、B、D错误；“建设投资包括工程费用、工程建设其它费用、预备费三部分”，", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0871", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "(2013年)在国外建筑安装工程费用构成中，承包商投标报价时不计入和分摊进单价，而需单独列项的是()。", "options": {"A": "临时设施费", "B": "总部管理费", "C": "利润", "D": "税金"}, "answer": ["A"], "analysis": "在许多国家，开办费一般是在各分部分项工程造价的前面按单项工程分别单独列出。开办费包括的内容因国家和工程的不同而异，大致包括以下内容：(4) 临时设施费。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0873", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "(2014年)根据我国现行建筑安装工程费用项目组成的规定，下列有关费用的表述中不正确的是（）", "options": {"A": "人工费是指支付给直接从事建筑安装工程施工作业的生产工人和附属生产单位工人的各项费用", "B": "材料费中的材料单价由材料原价、材料运杂费、运输损耗费、材料损耗费、采购及保管费五项组成", "C": "材料费包含构成或计划构成永久工程一部分的工程设备费", "D": "施工机具使用费包含仪器仪表使用费"}, "answer": ["B"], "analysis": "料单价是指建筑材料从其来源地运到施工工地仓库直至出库形成的综合平均单价。由材料原价、运杂费、运输损耗费、采购及保管费组成。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0874", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "(2017年)根据现行建筑安装工程费用项目组成的规定，下列费用项目中，属于施工机具使用费的是（）。", "options": {"A": "仪器仪表使用费", "B": "施工机械财产保险费", "C": "大型机械进出费", "D": "大型机械安拆费"}, "answer": ["A"], "analysis": "本题考查的是按费用构成要素划分建筑安装工程费用项目构成和计算。施工机具使用费是指施工作业所发生的施工机械、仪器仪表使用费或租赁费。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0875", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "(2014年)关于建筑安装工程费用中的规费，下列说法中正确的是（）", "options": {"A": "规费是指由县级及以上有关权利部门规定必须缴纳或计取的费用", "B": "规费包括社会保险费和住房公积金", "C": "投标人在投标报价时填写的规费可高于规定的标准", "D": "社会保险费中包括建筑安装工程一切险的投保费用"}, "answer": ["B"], "analysis": "规费是指按国 家法律、法规规定，由省级政府和省级有关权力部门规定施工单位必须缴纳或计取，应计人建筑安装工程造价的费用。主要包括社会保险费、住房公积金。社会保险费：养老保险费、失业保险费、医疗保险费、生育保险费、工伤保险费。注：在GB/T 50500-2024中，规费已并入人工费，不再单独列项。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0876", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "(2016年)关于国外建筑安装工程费用的计算，下列说法正确的是（）。", "options": {"A": "分包工程费不包括分包工程的管理费和利润", "B": "材料的预涨费计入管理费", "C": "开办费一般包括了工地清理费及完工后清理费", "D": "建设安装工程费用是以工程造价指数的形式衡量"}, "answer": ["C"], "analysis": "分包工程费包括分包工程的直接工程费、管理费和利润，故A错误；材料的预涨费计入直接工程费中的材料费，故B错误；开办费里面包含了工地清理费及完工后清理费，", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0877", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "(2013年)施工过程中用于现场工人的防暑降温费，属于安全措施费中的()。", "options": {"A": "环境保护", "B": "文明施工", "C": "安全施工", "D": "临时设施"}, "answer": ["B"], "analysis": "用于现场工人的防暑降温费、电风扇、空调等设备及用电费用均属于安全文明施工措施费中的文明施工费。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0878", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "(2014年)关于设备及工器具购置费用，下列说法中正确的是（）。", "options": {"A": "它是由设备购置费和工具、器具及生活家居购置费组成。", "B": "它是固定资产投资中的消极部分", "C": "在工业建筑中，它占工程造价比重的增大意味着生产技术的进步", "D": "在民用建筑中，它占工程造价比重的增大意味着资本有机构成的提高"}, "answer": ["C"], "analysis": "本题考查的是设备及工器具购置费的作用。设备及工、器具购置费费用是由设备购置费和工具、器具及生产购置费组成的，它是固定资产投资中的积极部分。在生产性工程建设中，设备及工器具购置费用占工程造价比重的增大，意味着生产技术的进步和资本有机构成的提高。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0879", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "(2015年)采用成本计算估价法计算非标准设备租赁时，下列表述中正确的是( )。", "options": {"A": "专用工具费=（材料费+加工费）×专用工具费率", "B": "加工费=设备总重量×（1+加工损耗系数）×设备每吨加工费", "C": "包装费的计算基数中不应包含废品损失费", "D": "利润的计算基数中不应包含外购配套件费"}, "answer": ["D"], "analysis": "国产非标准设备原价采用成本估算法的方法，“(1)材料费。其计算公式如下:材料费=材料净重(1+加工损耗系数)×每吨材料综合价(2)加工费。包括生产工人工资和工资附加费、燃料动力费、设备折旧费、车间经费等。其计算公式如下：加工费=设备总重量(吨)×设备每吨加工费(3)辅助材料费(简称辅材费)。包括焊条、焊丝、氧气、氩气、氮气、油漆、电石等费用。其计算公式如下：辅助材料费=设备总重量×辅助材料费指标(4)专用工具费。按(1～3)项之和乘以一定百分比计算。(5)废品损失费。按(1～4)项之和乘以一定百分比计算。(6)外购配套件费。按设备设计图纸所列的外购配套件的名称、型号、规格、数量、重量，根据相应的价格加运杂费计算。(7)包装费。按以上(1～6)项之和乘以一定百分比计算。(8)利润。可按(1～5)项加之和加上第(7)项乘以一定利润率计算”单台非标准设备原价={[(材料费+加工费+辅助材料费×(1+专用工具费率×(1+废品损失费率)+外购配套件费]×(l+包装费率)-外购配套件费}×(1+利润率)+外购配套件费+销项税额+非标准设备设计费", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0880", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "(2015年)某批进口设备离岸价格为1000万元人民币，国际运费为100万元人民币，运输保险费费率为1%。则该批设备的关税完税价格税为( )万元人民币。", "options": {"A": "1100.00", "B": "1110.00", "C": "1111.00", "D": "1111.11"}, "answer": ["D"], "analysis": "该题主要考察的是：CIF的计算。到岸价格作为关税的计征基数时，通常又可称为关税完税价格。P6进口设备到岸价=离岸价格+国际运费+运输+保险费=运费在内价运输+保险费，运输保险费=(1000+100)×1%/( 1-1%)=11.11万元，到岸价=1000+100+11.11=1111.11万元", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0881", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "(2016年)已知生产某非标准设备所需材料费、加工费、辅助材料费、专用工器具费合计为30万元，废品损失率为10%，外购配套件费为5万元，包装费率为2%，利润率为10%。用成本估算发计算该设备的利润值为()万元。", "options": {"A": "3.366", "B": "3.370", "C": "3.376", "D": "3.876"}, "answer": ["C"], "analysis": "单台非标准设备原价={[(材料费+加工费+辅助材料费） ×(1+专用工具费率） × ^(1+废品损失费率)+外购配套件费]×(l+包装费率）-外购配套件费 } × (1+利润率）+外购配套件费+销项税额+非标准设备设计费", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0882", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "(2016年)下列与建设用地有关的费用中，归农村集体经济组织所有的是()。", "options": {"A": "土地补偿费", "B": "青苗补偿费", "C": "拆迁补偿费", "D": "新菜地开发建设基金"}, "answer": ["A"], "analysis": "“土地补偿费是对农村集体经济组织因土地被征用而造成的经济损失的一种补偿”、“青苗补偿费是因征地时对其正在生长的农作物受到损害而做出的一种赔偿。在农村实行承包责任制后，农民 自行承包土地的青苗补偿费应付给本人，属于集体种植的青苗补偿费可纳入当年集体收益。”、“在城市规划区内国有土地上实施房屋拆迁，拆迁人应当对被拆迁人给予补偿、安置。”、“新菜地开发建设基金指征用城市郊区商品菜地时支付的费用。这项费用交给地方财政，作为开发建设新菜地的投资。”", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0883", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "(2014年)关于征地补偿费用，下列表述中正确的是（）", "options": {"A": "地上附着物补偿应根据协调征地方案前地上附着物的实际情况确定", "B": "土地补偿和安置补偿费的总和不得超过土地被征用前三年平均年产值的15倍", "C": "征用未开发的规划菜地按一年只种一茬的标准缴纳新菜地开发建设基金", "D": "征收耕地占用税时，对于占用前三年曾用于种植农作物的土地不得视为耕地"}, "answer": ["A"], "analysis": "B选项，土地补偿费和安置补助费不能使安置的农民保持原有生活水平的，可增加安置补助费。但土地补偿费和安装补助费的总和不得超过土地被征收前三年平均年产值的30倍。C选项，一年只种一茬或因调整茬口安排种植蔬菜的不作为开发基金，D选项，征收耕地占用税，占用前三年曾用于种植农作物的土地也视为耕地。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0884", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "(2016年)关于工程建设其他费用，下列说法中正确的是()。", "options": {"A": "建设单位管理费一般按建筑安装工程费乘以相应费率计算", "B": "研究试验费包括新产品试制费", "C": "改扩建项目的场地准备及临时设施费一般只计拆除清理费", "D": "不拥有产权的专用通信设施投资，列入市政公用设施费"}, "answer": ["C"], "analysis": "建设单位管理费按照工程费用之和 （包括设备工器具购置费和建筑安装工程费用）乘以建设单位管理费费率计算，所以A错误；研究试验费不应包括以下项目：(1) 应由科技三项费用 （即新产品试制费、中间试验费和重要科学研究补助费）开支的项目。（2） 应在建筑安装费用中列支的施工企业对建筑材料、构 件和建筑物进 行一般鉴定、检查所发生的费用及技术革新的研究试验费。(3) 应由勘察设计费或工程费用中开支的项目。所以B错误；改扩建项目一般只计拆除清理费，所以C正确；市政公用设施费是指使用市政公用设施的工程项目，按照项目所在地省级人民政府有关规定建设或缴纳的市政公用设施建设配套费用以及绿化工程补偿费用。所以D选项错误。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0885", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "(2015年)某建设项目建设期为二年，建设期内第一年货款400万元，第二年货款500万元，贷款在年内均衡发放，年利率为10%。建设期内只计息不支付，则该项目建设期贷款利息为( )万元。", "options": {"A": "85.0", "B": "85.9", "C": "87.0", "D": "109.0"}, "answer": ["C"], "analysis": "本题考查的是建设期利息。 第一年建设期利息=400x1/2x10%=20万元；第二年建设期利息=(400+20+500*1/2) x10%=67万元；建设期利息=20+67=87万元。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0886", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "(2015年)某建设项目建筑安装工程费为6000万元，设备购置费为1000万元，工程建设其他费用为2000万元，建设期利息为500万元。若基本预备费费率为5%，则该建设项目的基本预备费为( )万元。", "options": {"A": "350", "B": "400", "C": "450", "D": "475"}, "answer": ["C"], "analysis": "该题主要考察的是：基本预备费的计算，基本预备费=（工程费用+工程建设其他费用）×基本预备费率= (6000+1000+2000)×5%=450万元。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0887", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "(2016年)某建设项目静态投资为10000万元，项目建设前期年限为1年，建设期为2年，第一年完成投资40%，第二年完成投资60%。在年平均价格上涨率为6%的情况下，该项目价差预备费应为()万元。", "options": {"A": "666.3", "B": "981.6", "C": "1306.2", "D": "1640.5"}, "answer": ["C"], "analysis": "参见价差预备费计算公式1.5.2", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0917", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "我国现行投资估算中建设单位管理费应包括( )等。", "options": {"A": "工程招标费", "B": "竣工验收费", "C": "建设单位采购及保管费", "D": "可行性研究费"}, "answer": ["B"], "analysis": "建设单位管理费包含竣工验收费；工程招标费、可行性研究费属于技术服务费，建设单位采购及保管费属于材料费，均不包含在内。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0930", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "项目施工图设计阶段造价控制的重点是以被批准的（）为控制目标，应用限额设计、价值工程等方法，以为控制目标控制和修改施工图设计。", "options": {"A": "设计概算", "B": "施工图预算", "C": "投资估算", "D": "工程结算"}, "answer": ["A"], "analysis": "以被批准的设计概算为控制目标，应用限额设计、价值工程等方法进行施工图设计。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0931", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "推行限额设计时，初步设计阶段的直接控制目标是（ ）。", "options": {"A": "经批准的投资估算", "B": "经批准的设计概算", "C": "经批准的施工图预算", "D": "经确定的工程合同价"}, "answer": ["A"], "analysis": "运用设计标准与标准设计、价值工程和限额设计方法等，以可行性研究报告中被批准的投资估算为工程造价目标值，控制和修改初步设计以满足投资控制目标的要求。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0932", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "从各阶段的控制重点可见，要有效控制工程造价，关键应把握的环节中不包括的是（ ）。", "options": {"A": "决策阶段做好投资估算", "B": "施工阶段强调限额设计", "C": "招标投标阶段重视施工招标", "D": "施工阶段加强合同管理与事前控制"}, "answer": ["B"], "analysis": "1.项目决策阶段：在投资决策过程中，特别是从工程规划阶段开始，预先对工程投资额度进行估算，有助于业主对工程建设各项技术经济方案做出正确决策，从而对今后工程造价的控制起到决定性的作用。 2.初步设计阶段：设计阶段是仅次于决策阶段影响投资的关键。为了避免浪费，采取方案比选、限额设计等是控制工程造价的有力措施。强调限额设计并不是意味着一味追求节约资金，而是体现了尊重科学，实事求是，保证设计科学合理，以进一步优化设计方案。 3.施工图设计阶段：通过对设计过程中所形成的工程造价层层限额把关，以实现工程项目设计阶段的工程造价控制目标。 4.工程施工招标阶段：业主通过施工招标这一经济手段，择优选定承包商，不仅有利于确保工程质量和缩短工期，更有利于降低工程造价，是工程造价控制的重要手段。施工招标应根据工程建设的具体情况和条件，采用合适的招标形式，编制招标文件应符合法律法规，内容齐全，前后一致，避免出错和遗漏。评标前要明确评标原则。招标工作最终结果，是实现工程发承包双方签订施工合同。 5.工程施工阶段：施工阶段是工程造价的执行和完成阶段。 在施工中通过跟踪管理，对发承包双方的实际履约行为掌握第一于资料，经过动态纠偏，及时发现和解剖施工中的问题，有效地控制工程质量、进度和造价。事前控制工作重点是控制工程变更和防止发生索赔。施工过程要搞好工程计量与结算，做好与工程造价相统一的质量、进度等各方面的事前、事中、事后控制。 6.竣工验收阶段：全面汇总工程建设中的全部实际费用，编制竣工结算与决算，如实体现建设项目的工程造价，并总结经验，积累技术经济数据和资料，不断提高工程造价管理水平。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0933", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "在项目作出投资决策后，控制工程造价的关键就在于（ ）。", "options": {"A": "审核施工图预算", "B": "设计", "C": "进度款支付", "D": "竣工结算"}, "answer": ["B"], "analysis": "工程造价控制贯穿于项目建设全过程，但是必须重点突出。很显然，工程造价控制的关键在于施工前的投资决策和设计阶段，而在项目做出投资决策后，控制工程造价的关键就在于设计。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0934", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "工程造价控制，就是在优化建设方案、设计方案的基础上，在建设程序的各个阶段，采用一定的方法和措施把工程造价控制在合理的范围和核定的造价限额以内，要用投资估算价控制（ ）。", "options": {"A": "设计方案的选择和初步设计概算造价", "B": "初步设计概算造价和施工图设计", "C": "技术设计和修正概算造价", "D": "施工图设计和预算造价"}, "answer": ["A"], "analysis": "所谓工程造价控制，就是在优化建设方案、设计方案的基础上，在建设程序的各个阶段，采用一定的方法和措施把工程造价控制在合理的范围和核定的限额以内。具体说，要用投资估算价控制设计方案的选择和初步设计概算造价；用概算造价控制技术设计和修正概算造价；用概算造价或修正概算造价控制施工图设计和预算造价，用最高投标限价控制投标价等。以求合理使用人力、物力和财力，取得较好的投资效益。控制造价在这里强调的是限定项目投资。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0935", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "工程施工阶段，以（ ）等为控制依据，通过控制工程变更、风险管理等方法，按照承包人实际完成的工程量，严格确定施工阶段实际发生的工程费用。", "options": {"A": "工程合同价", "B": "拟建项目的功能要求和使用要求", "C": "被批准的设计概算", "D": "工程设计文件"}, "answer": ["A"], "analysis": "以工程合同价等为控制依据，通过控制工程变更、风险管理等方法，按照承包人实际应予计量的工程量 ，并考虑物价上涨、工程变更等因素，合理确定进度款和结算款，控制工程费用的支出。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0936", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "作为工程造价控制的最高限额，（ ）也是控制工程造价的主要依据。", "options": {"A": "招标控制价", "B": "工程合同价", "C": "施工图预算", "D": "经批准的设计概算"}, "answer": ["D"], "analysis": "初步设计时工程设计投资控制的最关键环节，经批准的设计概算是工程造价控制的最高限额，也是控制工程造价的主要依据。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0937", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "建设项目是一个从抽象到实际的建设过程，工程造价也从投资估算阶段的投资预计，到竣工决算的实际投资，形成最终的建设工程的（）。", "options": {"A": "合同价", "B": "概算造价", "C": "预算造价", "D": "实际造价"}, "answer": ["D"], "analysis": "建设项目是一个从抽象到实际的建设过程，工程造价也从投资估算阶段的投资预计，到竣工决算的实际投资，形成最终的建设工程的实际造价。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0938", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "建设工程造价的最高限额是按照有关规定编制并经有关部门批准的（）。", "options": {"A": "初步投资估算", "B": "施工图预算", "C": "施工标底", "D": "设计概算"}, "answer": ["D"], "analysis": "初步设计是工程设计投资控制的最关键环节，经批准的设计概算是工程造价控制的最高限额，也是控制工程造价的主要依据。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0939", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "建设项目决策阶段工程造价控制的关键控制环节是( )。", "options": {"A": "做好项目定义", "B": "做好投资估算", "C": "进行财务评价", "D": "进行方案比选"}, "answer": ["B"], "analysis": "投资估算对工程造价起到指导性和总体控制的作用。在投资决策过程中，特别是从工程规划阶段开始，预先对工程投资额度进行估算，有助于业主对工程建设各项技术经济方案做出正确决策，从而对今后工程造价的控制起到决定性的作用。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0940", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "建设投资由工程费用、工程建设其他费用和预备费组成，其中工程费用包括（ ）。", "options": {"A": "建筑工程费、设备及工器具购置费、安装工程费", "B": "建筑工程费、设备及工器具购置费、价差预备费", "C": "建筑工程费、基本预备费、安装工程费", "D": "建筑工程费、价差预备费、安装工程费"}, "answer": ["A"], "analysis": "工程费用是指建设期内直接用于工程建造、设备购置及其安装的建设投资，可以分为建筑工程费、安装工程费和设备及工器具购置费。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0941", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "建设项目按用途可分为生产性建设项目和非生产性建设项目，非生产性建设项目总投资（ ）。", "options": {"A": "只有固定投资，不包括流动资产投资", "B": "只有流动资产投资，不包括固定投资", "C": "包括固定投资和流动资产投资", "D": "以上说法均有误"}, "answer": ["A"], "analysis": "生产性建设项目总投资包括工程造价(或固定资产投资)和流动资金(或流动资产投资)。非生产性建设项目总投资一般仅指工程造价(或固定资产投资)", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0942", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "根据现行建设项目投资相关规定，固定资产投资应与（ ）相对应。", "options": {"A": "工程费用+工程建设其他费用", "B": "建设投资+建设期利息", "C": "建设安装工程费+设备及工器具购置费", "D": "建设项目总投资"}, "answer": ["B"], "analysis": "本题考查的是建设项目总投资的构成。生产性建设项目总投资包括建设投资、建设期利息和流动资金三部分；非生产性建设项目总投资包括建设投资和建设期利息两部分。其中建设投资和建设期利息之和对应于固定资产投资。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0943", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "在某建设项目投资构成中， 设备及工器具购置费为800万元， 建筑安装工程费为1200万元， 工程建设其他费为500万元， 基本预备费为150万元， 价差预备费为100万元， 建设期贷款1800万元， 应计利息为180万元， 流动资金500万元， 则该建设项目的建设投资为（） 万元", "options": {"A": "2620", "B": "2750", "C": "2980", "D": "3480"}, "answer": ["B"], "analysis": "本题考查的是我国建设项目投资及工程造价的构成。 我国现行工程造价的构成中， 建设投资包括设备及工器具购置费用、 建筑安装工程费用、 工程建设其他费用、 预备费， 不包含建设期利息和流动资金。考前黑钻押题，金考典软件考前更新，下载链接 www.jinkaodian.com 因此， 该建设项目的建设投资＝800＋1200＋500＋150＋100＝2750（万元） 。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0944", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "根据《建筑安装工程费用项目组成》（现行规定），建筑安装工程生产工人的高温作业临时津贴应计入（）。", "options": {"A": "劳动保护费", "B": "规费", "C": "企业管理费", "D": "人工费"}, "answer": ["D"], "analysis": "根据《建筑安装工程费用项目组成》（建标【2013】44号文），建筑安装工程生产工人的高温作业临时津贴应计入人工费。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0945", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "根据现行建筑安装工程费用项目组成规定，下列关于施工企业管理费中工具用具使用费的说法正确的是（）。", "options": {"A": "指企业管理使用，而非施工生产使用的工具用具费用", "B": "指企业施工生产使用，而非企业管理使用的工具用具费用", "C": "采用一般计税方法时，工具用具使用费中增值税进项税额可以抵扣", "D": "包括各类资产标准的工具用具的购置、维修和摊销费用"}, "answer": ["C"], "analysis": "工具用具使用费是指企业施工生产和管理使用的不属于固定资产的工具、器具、家具、交通工具和检验、试验、测绘、消防用具等的购置、维修和摊销费。当一般纳税人采用一般计税方法时，工具用具使用费中增值税进项税额的抵扣原则：以购进货物或接受修理修配劳务适用的税率扣减，均为16%。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0946", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "施工企业管理人员工资是指其管理人员的基本工资、工资性补贴、职工福利费、劳动保护费等，其属于（）。", "options": {"A": "直接工程费", "B": "人工费", "C": "企业管理费", "D": "现场施工费"}, "answer": ["C"], "analysis": "施工企业管理人员工资属于企业管理费。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0947", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "职工教育经费是指企业为职工进行专业技术和职业技术培训，按职工工资总额计提的费用，其属于（）。", "options": {"A": "直接费", "B": "规费", "C": "职工福利费", "D": "企业管理费"}, "answer": ["D"], "analysis": "职工教育经费是指按职工工资总额的规定比例计提，企业为职工进行专业技术和职业技能培训，专业技术人员继续教育、职工职业技能鉴定、职业资格认定以及根据需要对职工进行各类文化教育所发生的费用。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0948", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "下列各项费用中，应计入建筑安装工程企业管理费的是（）。", "options": {"A": "财产保险费", "B": "养老保险费", "C": "医疗保险费", "D": "失业保险费"}, "answer": ["A"], "analysis": "选项BCD均属于社会保险费，选项A属于企业管理费。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0949", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "施工中发生的下列与材料有关的费用中，属于材料单价的费用是（）。", "options": {"A": "对原材料进行鉴定发生的费用", "B": "施工机械整体场外运输的辅助材料费", "C": "原材料在运输装卸过程中不可避免的损耗费", "D": "机械设备日常保养所需的材料费用"}, "answer": ["C"], "analysis": "材料单价是指建筑材料从其来源地运到施工工地仓库直至出库形成的综合平均单价。由材料原价、运杂费、运输损耗费、采购及保管费组成。其中运输损耗费是指材料在运输装卸过程中不可避免的损耗。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0950", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "根据《建筑安裝工程费用项目组成》（现行规定），工程施工中所使用的仪器仪表维修费应计入（）。", "options": {"A": "施工机具使用费", "B": "工具用具使用费", "C": "固定资产使用费", "D": "企业管理费"}, "answer": ["A"], "analysis": "施工机具使用费包括施工机械使用费和仪器仪表使用费。其中，仪器仪表使用费是指工程施工所需使用的仪器仪表的摊销及维修费用。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0951", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "施工企业按照规定标准对采购的建筑材料进行一般性鉴定，检查发生的费用应计入（）。", "options": {"A": "材料费", "B": "企业管理费", "C": "人工费", "D": "措施项目费"}, "answer": ["B"], "analysis": "检验试验费：是指施工企业按照有关标准规定，对建筑以及材料、构件和建筑安装物进行一般鉴定、检查所发生的费用，包括自设试验室进行试验所耗用的材料等费用。检验试验费属于企业管理费。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0952", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "施工企业向建设单位提供预付款担保生产的费用，属于（）。", "options": {"A": "财务费", "B": "财产保险费", "C": "风险费", "D": "办公费"}, "answer": ["A"], "analysis": "财务费：是指企业为施工生产筹集资金或提供预付款担保、履约担保、职工工资支付担保等所发生的各种费用。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0953", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "施工过程中，施工测量放线和复测工作发生的费用应计入（）。", "options": {"A": "分部分项工程费", "B": "其他项目费", "C": "企业管理费", "D": "措施项目费"}, "answer": ["D"], "analysis": "措施项目费中工程定位复测费：指工程施工过程中进行全部施工测量放线和复测工作的费用。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0954", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "下列费用中，属于安装工程费中措施项目费的是（）。", "options": {"A": "施工机具使用费", "B": "暂列金额", "C": "工程定位复测费", "D": "工程排污费"}, "answer": ["C"], "analysis": "措施项目费中工程定位复测费：指工程施工过程中进行全部施工测量放线和复测工作的费用。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0955", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "按照现行规定，下列哪项费用不属于材料费的组成内容（ ）。", "options": {"A": "运输损耗费", "B": "运杂费", "C": "采购及保管费", "D": "材料二次搬运费"}, "answer": ["D"], "analysis": "材料单价是指建筑材料从其来源地运到施工工地仓库直至出库形成的综合平均单价。由材料原价、运杂费、运输损耗费、采购及保管费组成。当采用一般计税方法时，材料单价中的材料原价、运杂费等均应扣除增值税进项税额。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0956", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "税金是指企业按规定缴纳的房产税、非生产性车船使用税、土地使用税、印花税、（ ）、教育费附加、地方教育附加等各项税费。", "options": {"A": "设备及工(器)具费", "B": "设备运杂费", "C": "城市维护建设税", "D": "企业管理费"}, "answer": ["C"], "analysis": "税金是指企业按规定缴纳的房产税、非生产性车船使用税、土地使用税、印花税、城市维护建设税、教育费附加、地方教育附加等各项税费。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0957", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "根据国家相关法律、法规和政策规定，因停工学习、执行国家或社会义务等原因，按计时工资标准支付的工资属于人工日工资单价中的（ ）。", "options": {"A": "基本工资", "B": "奖金", "C": "津贴补贴", "D": "特殊情况下支付的工资"}, "answer": ["D"], "analysis": "特殊情况下支付的工资是指根据国家法律、法规和政策规定，因病、工伤、产假、计划生育假、婚丧假、事假、探亲假、定期休假、停工学习、执行国家或社会义务等原因按计时工资标准或计时工资标准的一定比例支付的工资。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0958", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "施工机械使用费是指施工机械作业所发生的机械使用费以及机械安拆费和场外运费，施工机械台班单价不包括的费用是（ ）。", "options": {"A": "折旧费", "B": "检修费", "C": "安拆费及场外运费", "D": "二次搬运费"}, "answer": ["D"], "analysis": "施工机械台班单价通常由折旧费、检修费、维护费、安拆费及场外运费 、 人工费、燃料动力费和其他费用组成。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0959", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "根据现行建筑安装工程费用项目组成规定，下列费用项目属于按造价形成划分的是（ ）。", "options": {"A": "人工费", "B": "企业管理费", "C": "利润", "D": "税金"}, "answer": ["D"], "analysis": "本题考查的是建筑安装工程费。建筑安装工程费按照工程造价形成由分部分项工程费、措施项目费、其他项目费、增值税组成。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0960", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "在建筑安装工程费用中，脚手架搭、拆、运输费用应列入（ ）。", "options": {"A": "直接工程费", "B": "企业管理费", "C": "规费", "D": "措施项目费"}, "answer": ["D"], "analysis": "本题考查的是建筑安装工程费。建筑安装工程费中的措施项目费之一脚手架工程费——是指施工需要的各种脚手架的搭、拆、运输费用以及脚手架购置费的摊销（或租赁）费用。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0961", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "在建筑安装工程费用中，企业按照规定标准被职工缴纳的住房公积金费用应计入（ ）。", "options": {"A": "规费", "B": "企业管理费", "C": "措施项目费", "D": "税金"}, "answer": ["A"], "analysis": "本题考查的是建筑安装工程费。在建筑安装工程费用中，企业按照规定标准被职工缴纳的住房公积金费用原属规费，在GB/T 50500-2024中已并入人工费。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0962", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "某进口设备FOB价为人民币1200万元，国际运费72万元，国际运输保险费用4．47万元，关税217万元，银行财务费6万元，外贸手续费19．15万元，增值税253．89万元，消费税率为5%，则该设备的消费税为（ ）万元。", "options": {"A": "78．60", "B": "74．67", "C": "79．93", "D": "93．29"}, "answer": ["A"], "analysis": "", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0964", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "编制设计预算时，国产标准设备的原价一般选用（）。", "options": {"A": "不含设备的出厂价", "B": "设备制造厂的成本价", "C": "带有备件的出厂价", "D": "设备制造厂的出厂价加运杂费"}, "answer": ["C"], "analysis": "国产标准设备一般按设备原价计算。在计算时，一般采用带有备件的原价。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0965", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "某项目拟从国外进口一套设备，重1000吨，装运港船上交货价300万美元，国际运费标准每吨360美元，海上运输保险费率0.266%。美元银行外汇牌价6.1元人民币。则该套设备国外运输保险费为（）万元。", "options": {"A": "4.868", "B": "4.881", "C": "5.452", "D": "5.467"}, "answer": ["D"], "analysis": "国外运输保险费=[（离岸价+国外运费）/（1-国外运输保险费率）]×国外运输保险费率=（3000000+360×1000）÷（1-0.266％）×0.266％×6.1=54670元=5.467万元。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0966", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "下列费用项目中，应计入进口设备运杂费中的是（ ）。", "options": {"A": "国际运费", "B": "国际运输保险费", "C": "到岸后外埠中转运输费", "D": "进口环节税费"}, "answer": ["C"], "analysis": "设备运杂费是指国内采购设备自来源地、国外采购设备自到岸港运至工地仓库或指定堆放地点发生的采购、运输、运输保险、保管、装卸等费用 。对于进口设备来说就是到岸后外埠中转运输费。国际运费、国际运输保险费及进口环节税费都属于进口设备原价。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0967", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "我国进口设备实际工程中采用较多的价格类型是（ ）。", "options": {"A": "目的港船边交货价", "B": "装运港船上交货价", "C": "到岸价格", "D": "运费在内价"}, "answer": ["C"], "analysis": "CIF(Cost Insurance and Freight) ，成本、保险费加运费，习惯称到岸价格，是实际工程中采用较多的价格类型。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0968", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "按成本计算估价法，非标准设备的原价的组成不包括（ ）。", "options": {"A": "材料费", "B": "专用工具费", "C": "外购配套件费", "D": "临时设施费"}, "answer": ["D"], "analysis": "按成本计算估价法，非标准设备的原价由以下各项组成：1)材料费 。2)加工费。3)辅助材料费。4)专用工具费。5)废品损失费。6)外购配套件费。7)包装费 。8)利润 。9)非标准设备设计费。10)增值税 。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0969", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "设备购置费是指为建设项目购置或自制的达到（ ）的设备所需的费用。", "options": {"A": "固定资产标准", "B": "生产规模", "C": "设计标准", "D": "带备件的标准"}, "answer": ["A"], "analysis": "设备购置费是指购置或自制的达到固定资产标准的设备所需的费用。由设备原价和设备运杂费构成。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0970", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "外贸手续费指委托具有外贸经营权的经贸公司采购而发生的按外贸手续费率计取的费用，外贸手续费率一般取（ ）。", "options": {"A": "2．5%", "B": "3%", "C": "1．5%", "D": "2．8%"}, "answer": ["C"], "analysis": "外贸手续费指按规定的外贸手续费率计取的费用，外贸手续费率一般取1.5%。计算公式为：外贸手续费=到岸价格 (CIF) x 人民币外汇汇率×外贸手续费率", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0971", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "某项目购买一台国产设备，其购置费为2500万元，运杂费率为15%，则该设备的原价为（ ）万元。", "options": {"A": "2165．89", "B": "2173．91", "C": "2265．38", "D": "2364．16"}, "answer": ["B"], "analysis": "根据公式：设备购置费=设备原价+设备运杂费， 又因为：设备运杂费=设备原价×设备运杂费率 所以，设备原价=设备购置费/（1+设备运杂费率），可得设备原价=2500万元/（1+15%），得设备原价=2173.91万元。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0972", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "某工厂采购一台国产非标准设备，制造厂生产该台设备所用材料费20万元，加工费2万元，辅助材料费4000元，专用工具费3000元，废品损失费率10%，外购配套件费5万元，包装费2000元，利润率为7%，税金4．5万元，非标准设备设计费2万元，运杂费率5%，该设备购置费为（ ）万元。", "options": {"A": "40．35", "B": "40．72", "C": "39．95", "D": "41．38"}, "answer": ["A"], "analysis": "设备购置费=设备原价+设备运杂费，设备运杂费=设备原价×运杂费率，题中已知：非标准设备的原价由：①材料费、②加工费、③辅助材料费、④专用工具费、⑤废品损失费、⑥外购配套件费、⑦包装费、⑧利润、⑨税金、⑩非标准设备设计费组成。⑤=(①+②+③+④)×10%=2．27万元，⑧=(①+②+③+④+⑤+⑦)×7%=1．76万元，所以设备原价=38．43万元；设备运杂费=38．43万元×5%=1．92万元，所以设备购置费=(38．43+1．92)万元=40．35万元。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0973", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "某进口设备，到岸价格(CI F)为6500万元，关税税率为23%，增值税税率为16%，无消费税，则该进口设备应缴纳的增值税为（ ）万元。", "options": {"A": "1276．42", "B": "1279．20", "C": "1546．92", "D": "1445．98"}, "answer": ["B"], "analysis": "根据公式：关税=到岸价格(CIF)×进口关税税率，得：关税=6500万元×23%=1495万元。 根据公式：组成计税价格=关税完税价格+关税+消费税；到岸价格(CIF)包括离岸价格(FOB)、国际运费、运输保险费，它作为关税完税价格。所以，组成计税价格=(6500+1495)万元=7995万元。 根据公式：进口产品增值税额=组成计税价格×增值税税率得，进口产品增值税额=7995万×16%=1279.20万元。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0974", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "国内生产某台非标准设备需材料费18万元，加工费2万元，专用工具费率5%，设备损失费率10%，包装费0.4万元，利润率为10%，用成本计算估价法计得该设备的利润是（ ）万元。", "options": {"A": "2.00", "B": "2.10", "C": "2.31", "D": "2.35"}, "answer": ["D"], "analysis": "本题考查的是设备及工器具购置费。专用工具费=（18+2）×5%=1（万元），废品损失费=（18+2+1）×10%=2.1（万元），该设备的利润=（材料费+加工费+辅助材料费+专用工具费+废品损失费+包装费）×利润率=（18+2+1+2.1+0.4）×10%=2.35（万元）。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0975", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "在国际贸易中， 交易双方采用FOB交货模式， 下列选项中不属于卖方义务的是（ ）", "options": {"A": "负责租船或订舱，及时通知买方", "B": "在装运港把货物装上指定船只", "C": "在需要办理海关手续时，办理货物出口所需的一切海关手续", "D": "负担货物在装运港至装上船为止的一切费用和风险"}, "answer": ["A"], "analysis": "本题考查的是进口设备原价的构成及计算。 在FOB交货方式下， 卖方的基本义务有： （1） 在合同规定的时间或期限内， 在装运港按照习惯方式将货物交到买方指派的船上， 并及时通知买方； （2） 自负风险和费用， 取得出口许可证或其他官方批准证件， 在需要办理海关手续时， 办理货物出口所需的一切海关手续； （3） 负担货物在装运港至装上船为止的一切费用和风险； （4） 自付费用提供证明货物已交至船上的通常单据或具有同等效力的电子单证。 选项A错误， 租船或订舱属于买方义务", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0976", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "国际贸易双方约定费用划分与风险转移均以货物在装运港被装上指定船只时为分界点，该种交易价格被称为（ ）。", "options": {"A": "离岸价", "B": "运费在内价", "C": "到岸价", "D": "抵岸价"}, "answer": ["A"], "analysis": "本题考查的是设备及工器具购置费。FOB，船上交货，意为装运港船上交货，亦称为离岸价格。“船上交货”是指卖方以在指定装运港将货物装上买方指定的船舶或通过取得已交付至船上货物的方式交货。货物灭失或损坏的风险在货物交到船上时转移。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0977", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "某进口设备到岸价为 1500 万元，银行财务费，外贸手续费合计 36 万元。关税 300 万元，消费税和增值税税率分别为 10%、16%，则该进口设备原价为（）万元。", "options": {"A": "2366.8", "B": "2356.0", "C": "2342.0", "D": "2332.6"}, "answer": ["B"], "analysis": "进口设备的原价到岸价+进口从属费=到岸价+银行财务费+外贸手续费+关税+消费税+增值税+车辆购置税。先计算消费税=（1500+300+消费税）×10%，求得消费税=200 万元。 1500+36+300+200+【1500+300+200】×16%=2356.0 万元。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0978", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "某项目进口一套加工设备，该设备的离岸价(FO B)为100万美元，国外运费5万美元，运输保险费1万美元，关税税率20%，增值税税率16%，无消费税，则该设备的增值税为（ ）万元人民币。(外汇汇率：1美元=6．5元人民币)", "options": {"A": "138．05", "B": "156．29", "C": "124．80", "D": "132．29"}, "answer": ["D"], "analysis": "根据公式：到岸价格(CIF)=离岸价格(FOB)+国际运费+运输保险费，即：关税完税价格。 所以，关税完税价格=(100+5+1)万美元=106万美元． 根据公式：组成计税价格=关税完税价格+关税+消费税 又因为：进口产品增值税额=组成计税价格×增值税税率 所以，进口产品增值税额=(106+106×20%)万美元×16%=20．352万美元 因为：外汇汇率：1美元=6．5元人民币 所以，20．352万美元×6．5≈132．29万元。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0979", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "某进口设备的到岸价为200万元，银行财务费为0．8万元，外贸手续费费率为1．5%，关税税率为20%，增值税税率为16%，该设备无消费税和海关监管手续费，则该进口设备的抵岸价为（ ）万元。", "options": {"A": "277．52", "B": "282．20", "C": "288．55", "D": "280．88"}, "answer": ["B"], "analysis": "根据公式：外贸手续费=[装运港船上交货价(FOB)+国际运费+运输保险费]×外贸手续费率 得：外贸手续费=200万元× 1．5%=3万元 根据公式：关税=到岸价格(CIF)×进口关税税率 得：关税=200万元×20%=40万元 根据公式：组成计税价格=关税完税价格+关税+消费税 又因为：进口产品增值税额=组成计税价格×增值税税率 得：进口产品增值税额=(200+200×20%)万元×16%=38．4万元 根据公式：进口设备抵岸价=货价+国际运费+运输保险费+银行财务费+外贸手续费+关税+增值税+消费税+车辆购置附加费 所以：进口设备抵岸价=(200+0．8+3+40+38．4)万元=282．2万元。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0980", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "货物灭失或损坏的风险在货物交到船上时转移，同时买方承担自那时起的一切费用。该种交易价格被称为（）。", "options": {"A": "离岸价", "B": "运费在内价", "C": "到岸价", "D": "抵岸价"}, "answer": ["A"], "analysis": "装运港船上交货时的价格亦称为离岸价格。货物灭失或损坏的风险在货物交到船上时转移，同时买方承担自那时起的一切费用。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0981", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "下列费用项目中， 属于联合试运转费中试运转支出的是（）", "options": {"A": "施工单位参加试运转人员的工资", "B": "单台设备的单机试运转费", "C": "试运转中暴露出来的施工缺陷处理费用", "D": "试运转中暴露出来的设备缺陷处理费用"}, "answer": ["A"], "analysis": "试运转支出包括试运转所需原材料、 燃料及动力消耗、 低值易耗品、 其他物资消耗、 工具用具使用费、 机械使用费、 保险金、 施工单位参加试运转人员工资以及专家指导费等； 试运转收入包括试运转期间的产品销售收入和其他收入。 联合试运转费不包括应由设备安装工程费用开支的调试及试车费用， 以及在试运转中暴露出来的因施工原因或设备缺陷等发生的处理费用", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0982", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "通过出让方式获取国有土地使用权的具体方式不包括（ ）。", "options": {"A": "招标", "B": "协议", "C": "拍卖", "D": "划拨"}, "answer": ["D"], "analysis": "通过出让方式获取土地使用权又可以分成两种具体方式：一是通过招标、拍卖、挂牌等竞争出让方式获取国有土地使用权，二是通过协议出让方式获取国有土地使用权。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0983", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "我国现行建设项目的构成中，工程建设的其他费用包括（ ）。", "options": {"A": "涨价预备费", "B": "直接费", "C": "建设期贷款利息", "D": "土地使用费"}, "answer": ["D"], "analysis": "工程建设其他费用，是指建设期发生的与土地使用权取得、整个工程项目建设以及未来生产经营有关的构成建设投资但不包括在工程费用中的费用。工程建设其他费用分为三类：第一类指土地使用权购置或取得的费用；第二类指与整个工程建设有关的各类其他费用；第三类指与未来企业生产经营有关的其他费用。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0984", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "关于建设项目场地准备和建设单位临时设施费的计算,下列说法正确的是（）。", "options": {"A": "改扩建项目一般应计工程费用和拆除清理费", "B": "凡可回收材料的拆除工程应采用以料抵工方式冲抵拆除清理费", "C": "新建项目应根据实际工程量计算，不按工程费用的比例计算", "D": "新建项目应按工程费用比例计算，不根据实际工程量计算"}, "answer": ["B"], "analysis": "改扩建项目一般只计拆除清理费，A错误；新建项目的场地准备和临时设施费应根据实际工程量估算，或按工程费用的比例计算，CD错误。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0985", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "对于建设用地取得的相关方式， 下列说法正确的是（ ） 。", "options": {"A": "获取土地使用权的基本方式是出让和划拨，不包括租赁和转让", "B": "通过竞争出让获取土地使用权的方式分为招标、拍卖、挂牌三种", "C": "城市公益事业用地不得以划拨方式取得", "D": "依法以划拨方式取得土地使用权的，其土地使用年限最高为70年"}, "answer": ["B"], "analysis": "本题考查的是建设用地取得的基本方式。 选项A错误， 取得用地的基本方式是出让和划拨， 还包括租赁和转让方式； 选项C错误， 城市公益事业用地可以划拨方式取得； 选项D错误， 依法以划拨方式取得土地使用权的， 除法律法规另有规定外， 没有使用期限的限制。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0986", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "土地补偿费和安置补助费的总和不得超过土地被征收前三年平均年产值的（ ）倍。", "options": {"A": "10", "B": "15", "C": "20", "D": "30"}, "answer": ["D"], "analysis": "每一个需要安置的农业人口的安置补助费标准，为该耕地被征收前三年平均年产值的4~6倍。但是，每公顷被征收耕地的安置补助费，最高不得超过被征收前三年平均年产值的15倍。土地补偿费和安置补助费，尚不能使需要安置的农民保持原有生活水平的，经省、自治区、直辖市人民政府批准，可以增加安置补助费。但是，土地补偿费和安置补助费的总和不得超过土地被征收前三年平均年产值的30倍。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0987", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "在我国建设项目投资中， 取得土地使用权而支付的土地使用权出让金属于（ ） 。", "options": {"A": "工程费用", "B": "建设用地费", "C": "与项目建设有关的其他费用", "D": "与未来生产经营有关的其他费用"}, "answer": ["B"], "analysis": "本题考查的是建设用地取得的费用。 建设用地费是指为获得工程项目建设土地的使用权而在建设期内发生的各项费用， 包括通过划拨方式取得土地使用权而支付的土地征用及迁移补偿费， 或者通过土地使用权出让方式取得土地使用权而支付的土地使用权出让金", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0988", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "基本预备费是指在投资估算或设计概算内难以预料的工程费用，下列关于其费用内容叙述错误的是（ ）。", "options": {"A": "实行工程保险的工程项目费用应适当提高", "B": "竣工验收时为鉴定工程质量，对隐蔽工程进行必要的挖掘和修复的费用", "C": "超规超限设备运输过程中可能增加的费用", "D": "在批准的基础设计和概算范围内增加的设计变更、局部地基处理等费用"}, "answer": ["A"], "analysis": "基本预备费费用内容包括： (1)在批准的基础设计和概算范围内增加的设计变更、局部地基处理等费用。 (2)一般自然灾害造成的损失和预防自然灾害所采取措施的费用。 (3)竣工验收时为鉴定工程质量，对隐蔽工程进行必要的挖掘和修复的费用。 (4)超规超限设备运输过程中可能增加的费用。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0989", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "某建设工程项目的设备及工器具购置费为 2500 万元，建筑安装工程费为 0 万元，工程建设其他费为 1500 万元，基本预备费率为 10%，则该项目的基本预备费为（ ）万元。", "options": {"A": "200", "B": "400", "C": "600", "D": "450"}, "answer": ["C"], "analysis": "基本预备费=（工程费用＋工程建设其他费）×基本预备费率=（2500+2000+1500）×10%=600 万元。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0990", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "在建设项目决策阶段影响工程造价的主要因素中，（ ）不仅影响项目的建设成本，也影响项目建成后的运营成本。", "options": {"A": "设备方案", "B": "项目建设规模", "C": "工程方案", "D": "技术方案"}, "answer": ["D"], "analysis": "生产技术方案指产品生产所采用的工艺流程和生产方法。技术方案不仅影响项目的建设成本，也影响项目建成后的运营成本。因此，技术方案的选择直接影响项目的建设和运营效果，必须认真选择和确定。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0991", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "只有提高可行性研究的深度，采用科学的估算方法和可靠的数据资料，合理地计算（ ），保证其一定的精确度，才能保证项目建设后续阶段的造价被控制在合理范围，使投资控制目标能够实现。", "options": {"A": "修正概算", "B": "投资估算", "C": "施工图预算", "D": "设计概算"}, "answer": ["B"], "analysis": "只有加强可行性研究的深度，采用科学的估算方法和可靠的数据资料，合理地计算投资估算，保证投资估算一定的精确度，才能保证项目建设后续阶段的造价被控制在合理范围，使投资控制目标能够实现。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0992", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "下列关于可行性研究对工程造价确定与控制影响的表述，错误的是（ ）。", "options": {"A": "项目可行性研究的内容是决定工程造价的基础", "B": "项目可行性研究结论的正确性是工程造价合理性的前提", "C": "可行性研究结论影响工程造价的投资高低", "D": "可行性研究的深度影响投资估算的精确度，也影响工程造价的控制效果"}, "answer": ["C"], "analysis": "项目可行性研究与工程造价有着密不可分的联系： (1)项目可行性研究结论的正确性是工程造价合理性的前提。 (2)项目可行性研究的内容是决定工程造价的基础。 (3)工程造价高低、投资多少也影响可行性研究结论。 (4)可行性研究的深度影响投资估算的精确度，也影响工程造价的控制效果。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0993", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "在建设项目设计阶段，对于极特殊的、复杂的方案比选一般采用（ ）。", "options": {"A": "投资回收期法", "B": "内部收益率法", "C": "净现值法", "D": "综合财务评价法"}, "answer": ["D"], "analysis": "在建设项目设计阶段，多方案比选多属于局部方案比选，对于技术上先进、适用的设计方案，进行经济评价、比选时，可以采用造价额度、运行费用、净现值、净年值等方法，极特殊的、复杂的方案比选采用综合财务评价方法。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0994", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "关于住宅建筑设计中的结构面积系数，下列说法中正确的是（ ）", "options": {"A": "结构面积系数越大，设计方案越经济", "B": "房间平均面积越大，结构面积系数越小", "C": "结构面积系数与房间户型组成有关，与房屋长度、宽度无关", "D": "结构面积系数与房屋结构有关，与房屋外形无关"}, "answer": ["B"], "analysis": "本题考查的是工程决策和设计阶段造价管理概述。结构面积系数（住宅结构面积与建筑面积之比）越小，设计方案越经济。结构面积系数除与房屋结构有关外，还与房屋外形及其长度和宽度有关，同时也与房间平均面积大小和户型组成有关。房屋平均面积越大，内墙、隔墙在建筑面积所占比重就越小。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0995", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "详细的可行性研究阶段投资估算的要求为误差控制在±（）%以内。", "options": {"A": "5", "B": "10", "C": "15", "D": "20"}, "answer": ["B"], "analysis": "投资决策是一个由浅入深、不断深化的过程，不同阶段决策的深度不同，投资估算的精度也不同。如在投资机会和项目建议书阶段，投资估算的误差率在±30%左右；而在详细可行性研究阶段，误差率在±10%以内。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0996", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "根据我国现行工程造价构成，属于固定资产投资中积极部分的是（ ）。", "options": {"A": "建筑安装工程费", "B": "设备及工器具购置费", "C": "建设用地费", "D": "可行性研究"}, "answer": ["B"], "analysis": "本题考查的是设备购置费的构成和计算。设备及工器具购置费用是由设备购置费和工具、器具及生产家具购置费组成的，它是固定资产投资中的积极部分。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0997", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "建设项目是一个从抽象到实际的建设过程，工程造价分别表现为①投资估算②施工图预算③设计概算④工程结算⑤承包合同价，最终形成的建设工程的实际造价。他们的形成顺序是( )。", "options": {"A": "①②③④⑤", "B": "①③②③⑤", "C": "①③②⑤④", "D": "①②③⑤④"}, "answer": ["C"], "analysis": "建设项目是一个从抽象到实际的建设过程，工程造价分别表现为投资估算、设计概算、施工图预算、承包合同价、工程结算。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0998", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "已知某进口设备到岸价格为80万美元，进口关税税率为15%，增值税税率为17%，银行外汇牌价为1美元＝6.30元人民币。按以上条件计算的进口环节增值税额是（ ）万元人民币。", "options": {"A": "72.83", "B": "85.68", "C": "98.53", "D": "118.71"}, "answer": ["C"], "analysis": "本题考查的是进口设备原价的构成及计算。增值税=（到岸价+关税+消费税）×17%=（80+80×15%+0）×17%=98.53（万元人民币）。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0999", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "某进口设备通过海洋运输，到岸价为972万元，国际运费88万元，海上运输保险费率3‰，则离岸价为（ ）万元。", "options": {"A": "881.08", "B": "883.74", "C": "1063.18", "D": "1091.90"}, "answer": ["A"], "analysis": "本题考查的是进口设备原价的构成及计算。运输保险费=972×3‰=2.916（万元），离岸价=到岸价-国际运费-运输保险费=972-88-2.916=881.084（万元）。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_1837", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "用成本计算估价法计算国产非标准设备原价时，需要考虑的费用项目是（ ）。", "options": {"A": "特殊设备安全监督检查费", "B": "供销部门手续费", "C": "成品损失费及运输包装费", "D": "外购配套件费"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是设备购置费【选项分析】采用成本计算估价法时，国产非标准设备原价包括：材料费；加工费；辅助材料费（简称辅材费）；专用工具费；废品损失费；外购配套件费；包装费；利润；非标准设备设计费；增值税 。", "tags": [], "source": "一、设备购置费", "src": "好题库"}, {"id": "ht_mgmt_1838", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "关于进口设备到岸价的构成及计算，下列公式中正确的是（ ）。", "options": {"A": "到岸价=离岸价+运输保险费", "B": "到岸价=离岸价+进口从属费", "C": "到岸价=运费在内价+运输保险费", "D": "到岸价=运费在内费+进口从属费"}, "answer": ["C"], "analysis": "【内容考查】本题考查的是设备购置费【选项分析】到岸价=离岸价+国际运费+运输保险费=运费在内价+运输保险费。", "tags": [], "source": "一、设备购置费", "src": "好题库"}, {"id": "ht_mgmt_1843", "date": "2026-07-10", "chapter": "g03", "type": "single", "stem": "建设项目概算总投资计算时，其静态总投资中不包括的费用是（ ）。", "options": {"A": "工程费用", "B": "工程建设其他费用", "C": "建设期贷款利息", "D": "基本预备费"}, "answer": ["C"], "analysis": "【考点来源】本题考查的是建设项目总概算的编制方法【选项分析】静态总投资包括工程费用、工程建设其他费和基本预备费。不包括建设期贷款利息。", "tags": [], "source": "三、设计概算的编制方法", "src": "好题库"}, {"id": "mgmt_hqwx_0187", "date": "2026-07-09", "chapter": "g03", "type": "single", "stem": "根据《国务院关于投资体制改革的决定》，对于采用直接投资和资本金注入方式的政府投资项目，除特殊情况外，政府主管部门不再审批（ ）。", "options": {"A": "项目建议书", "B": "项目初步设计", "C": "项目开工报告", "D": "项目可行性研究报告"}, "answer": ["C"], "analysis": "【内容考查】本题考查的是投资决策阶段的工作内容 【选项分析】对于采用直接投资和资本金注入方式的政府投资项目，政府需要从投资决策的角度审批项目建议书和可行性研究报告，除特殊情况外，不再审批开工报告，同时还要严格审批其初步设计和概算；对于采用投资补助、转贷和贷款贴息方式的政府投资项目，则只审批资金申请报告。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0188", "date": "2026-07-09", "chapter": "g03", "type": "single", "stem": "为了适应科学管理需要，可以从不同角度对工程项目进行分类，下列不属于按照投资效益和市场需求划分的是（ ）。", "options": {"A": "竞争性项目", "B": "基础性项目", "C": "政府投资项目", "D": "公益性项目"}, "answer": ["C"], "analysis": "工程项目按投资效益和市场需求划分可分为竞争性项目、基础性项目和公益性项目；按投资来源划分可分为政府投资项目和非政府投资项目", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0189", "date": "2026-07-09", "chapter": "g03", "type": "single", "stem": "过程后评价是指对工程项目立项决策、设计施工、竣工投产、生产运营等全过程进行系统分析，找出项目后评价与（ ）之间的差异及其产生原因，使后评价结论有根有据，同时针对问题提出解决办法。", "options": {"A": "投资总额", "B": "原预期效益", "C": "实际收益", "D": "效益后评价"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是项目后评价 【选项分析】过程后评价是指对工程项目立项决策、设计施工、竣工投产、生产运营等全过程进行系统分析，找出项目后评价与原预期效益之间的差异及其产生原因，使后评价结论有根有据，同时针对问题提出解决办法。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0191", "date": "2026-07-09", "chapter": "g03", "type": "single", "stem": "下列项目开工建设准备工作中，在办理工程质量监督手续之后才能进行的工作是（ ）。", "options": {"A": "办理施工许可证", "B": "编制施工组织设计", "C": "编制监理规划", "D": "审查施工图设计文件"}, "answer": ["A"], "analysis": "【内容考查】本题考查的是建设实施阶段工作内容 【选项分析】建设单位在办理施工许可证之前应当到规定的工程质量监督机构办理工程质量监督手续。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0192", "date": "2026-07-09", "chapter": "g03", "type": "single", "stem": "对于一般工业与民用建筑工程而言，下列工程中，属于分部工程的是（ ）。", "options": {"A": "通风与空调工程", "B": "砖砌体工程", "C": "玻璃幕墙工程", "D": "裱糊与软包工程"}, "answer": ["A"], "analysis": "【内容考查】本题考查的是工程项目组成 【选项分析】分部工程是单位工程的组成部分，应按专业性质、建筑部位确定。一般工业与民用建筑工程的分部工程包括：地基与基础工程、主体结构工程、装饰装修工程、屋面工程、给排水及采暖工程、电气工程、智能建筑工程、通风与空调工程、电梯工程。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0193", "date": "2026-07-09", "chapter": "g03", "type": "single", "stem": "根据《国务院关于投资体制改革的决定》，对于采用投资补助方式的政府投资项目政府需要审批的文件是（ ）。", "options": {"A": "项目建议书", "B": "可行性研究报告", "C": "资金申请报告", "D": "初步设计和概算"}, "answer": ["C"], "analysis": "【内容考查】本题考查的是投资决策阶段工作内容 【选项分析】政府投资项目实行审批制。①对于采用直接投资和资本金注入方式的政府投资项目，政府需要从投资决策的角度审批项目建议书和可行性研究报告，除特殊情况外不再审批开工报告，同时还要严格审批其初步设计和概算；②对于采用投资补助、转贷和贷款贴息方式的政府投资项目，则只审批资金申请报告。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0194", "date": "2026-07-09", "chapter": "g03", "type": "single", "stem": "根据《建筑工程施工质量验收统一验收标准》，下列工程中，属于分项工程的是（ ）。", "options": {"A": "电气工程", "B": "钢筋工程", "C": "屋面工程", "D": "外墙防水工程"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是工程项目组成 【选项分析】分项工程是指将分部工程按主要工种、材料、施工工艺、设备类别等划分的工程。例如，土方开挖工程、土方回填工程、钢筋工程、模板工程、混凝土工程、砖砌体工程、木门窗安装工程、钢结构安装工程、给（排）水管道安装工程等。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0195", "date": "2026-07-09", "chapter": "g03", "type": "single", "stem": "以下关于项目建议书的说法，不正确的是（ ）。", "options": {"A": "项目建议书批准后，可以进行可行性研究工作，但并不表明项目已经立项", "B": "经过批准的项目建议书是工程项目的最终决策", "C": "项目建议书是对工程项目的轮廓设想", "D": "项目建议书的主要作用是推荐一个拟建项目，供政府部门选择并确定是否进行下一步工作"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是投资决策阶段工作内容 【选项分析】批准的项目建议书不是工程项目最终决策。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0197", "date": "2026-07-09", "chapter": "g03", "type": "single", "stem": "工程项目代建合同生效后，为了保证政府投资的合理使用，代建单位须提交工程概算投资（ ）左右的履约保函。", "options": {"A": "5％", "B": "10％", "C": "15％", "D": "20％"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是工程代建制 【选项分析】工程项目代建合同生效后，为了保证政府投资的合理使用，代建单位须提交工程概算投资10%左右的履约保函。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0199", "date": "2026-07-09", "chapter": "g03", "type": "single", "stem": "以下（ ）PPP模式社会资本方承担的风险相对较小。", "options": {"A": "私有化类", "B": "民营化类", "C": "特许经营类", "D": "外包类"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是BOT/PPP 模式 【选项分析】外包类PPP项目中政府出资并承担项目经营和收益风险，社会资本方通过政府付费实现收益，承担的风险相对较少。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0203", "date": "2026-07-09", "chapter": "g03", "type": "single", "stem": "采用ABS融资方式进行项目融资的物质基础是（ ）。", "options": {"A": "债券发行机构的注册资金", "B": "项目原始权益人的全部资产", "C": "债券承销机构的担保资产", "D": "具有可靠未来现金流量的项目资产"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是ABS模式 【选项分析】一般来说，投资项目所依附的资产只要在未来一定时期内能带来现金收入，就可以进行ABS融资。拥有这种未来现金流量所有权的企业（项目公司）成为原始权益人。这些未来现金流量所代表的资产，是ABS融资方式的物质基础。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0204", "date": "2026-07-09", "chapter": "g03", "type": "single", "stem": "在下列融资方式中，需要组建特定用途公司SPC进行运作的是（ ）。", "options": {"A": "BOT", "B": "ABS", "C": "PFI", "D": "BOOT"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是ABS模式 【选项分项】ABS模式,组建特定用途公司SPC (Special Purpose Corporation)。SPC可以是一个信托投资公司、信用担保公司、投资保险公司或其他独立法人，该机构应能够获得国际权威资信评估机构较高级别的信用等级（AAA级或AA级）。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0207", "date": "2026-07-09", "chapter": "g03", "type": "single", "stem": "建设工程采用DBB模式的优点是（ ）。", "options": {"A": "责权利分配明确，指令易贯彻", "B": "不利于控制工程质量", "C": "业主组织管理简单", "D": "工程造价控制难度小"}, "answer": ["A"], "analysis": "【内容考查】本题考查的是DBB模式 【选项分析】采用DBB模式的优点： 建设单位、设计单位、施工总承包单位及分包单位在合同约束下，各自行使其职责和履行义务，责权利分配明确；建设单位直接管理工程设计和施工，指令易贯彻。而且由于该模式应用广泛、历史长，相关管理方法较成熟，工程参建各方对有关程序都比较熟悉。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0208", "date": "2026-07-09", "chapter": "g03", "type": "single", "stem": "PPP 项目的合同体系中，最核心的法律文件是（ ）。【2019陕西】", "options": {"A": "项目合同", "B": "融资合同", "C": "运营服务合同", "D": "保险合同"}, "answer": ["A"], "analysis": "【考点来源】本题考查的是PPP模式 【选项分析】合同体系主要包括项目合同、股东合同、融资合同、工程承包合同、运营服务合同、原料供应合同、产品采购合同和保险合同等。项目合同是其中最核心的法律文件。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0209", "date": "2026-07-09", "chapter": "g03", "type": "single", "stem": "与BOT融资方式相比，TOT融资方式的特点是（ ）。", "options": {"A": "融资对象更为广泛，可操作性更强", "B": "项目产权结构易于稳定", "C": "不需要设立具有特许权的专门机构", "D": "项目招标程序大为简化"}, "answer": ["A"], "analysis": "【内容考查】本题考查的是BOT/PPP 模式 【选项分项】与BOT模式相比，采用TOT模式时，融资对象更为广泛，可操作性更强，使项目引资成功的可能性增加。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0210", "date": "2026-07-09", "chapter": "g03", "type": "single", "stem": "对政府投资项目而言，经有关部门批准的（ ）是拟建项目工程造价最高限额。", "options": {"A": "投资估算", "B": "招标控制价", "C": "施工图预算", "D": "设计概算"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是工程造价控制的主要内容 【选项分项】初步设计是工程设计投资控制的最关键环节，经批准的设计概算是工程造价控制的最高限额，也是控制工程造价的主要依据。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0212", "date": "2026-07-09", "chapter": "g03", "type": "single", "stem": "建设工程项目投资决策完成后，控制工程造价的关键在于（ ）。", "options": {"A": "工程设计", "B": "工程招标", "C": "工程施工", "D": "工程结算"}, "answer": ["A"], "analysis": "【内容考查】本题考查的是工程建设各阶段工程造价的控制 【选项分析】工程造价控制的关键在于施工前的投资决策和设计阶段，而在项目做出投资决策后，控制工程造价的关键就在于设计。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0213", "date": "2026-07-09", "chapter": "g03", "type": "single", "stem": "为了有效地控制工程造价，应将工程造价管理的重点放在工程项目的（ ）阶段。", "options": {"A": "初步设计和招标", "B": "施工图设计和预算", "C": "策划决策和设计", "D": "方案设计和概算"}, "answer": ["C"], "analysis": "【内容考查】本题考查的是工程造价控制的主要内容 【选项分析】 为有效地控制工程造价，应将工程造价管理的重点转到工程项目策划决策和设计阶段。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0214", "date": "2026-07-09", "chapter": "g03", "type": "single", "stem": "有效控制工程造价应体现（ ）。", "options": {"A": "以设计阶段为重点的建设全过程造价控制", "B": "直接控制，以取得令人满意的结果", "C": "人才与经济相结合是控制工程造价最有效的手段", "D": "知识与信息相结合是控制工程造价最有效的手段"}, "answer": ["A"], "analysis": "【内容考查】本题考查的是工程建设各阶段工程造价的控制 【选项分项】有效控制工程造价应体现以下原则： 1.以设计阶段为重点的建设全过程造价控制2.主动控制，以取得令人满意的结果3.技术与经济相结合是控制工程造价最有效的手段。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0215", "date": "2026-07-09", "chapter": "g03", "type": "single", "stem": "根据现行建设项目投资构成相关规定，固定资产投资包括 （ ）。", "options": {"A": "工程费用、工程建设其他费用", "B": "建设投资、建设期利息", "C": "建设安装工程费、设备及工器具购置费", "D": "建设项目总投资"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是建设项目总投资的构成 【选项分析】在建设项目总投资中，固定资产投资包括：建设投资和建设期利息两部分。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0216", "date": "2026-07-09", "chapter": "g03", "type": "single", "stem": "生产性建设项目的总投资由（ ）两部分构成。", "options": {"A": "固定资产投资和流动资产投资", "B": "有形资产投资和无形资产投资", "C": "建筑安装工程费用和设备工器具购置费用", "D": "建筑安装工程费用和工程建设其他费用"}, "answer": ["A"], "analysis": "【内容考查】本题考查的是建设项目总投资的含义 【选项分析】生产性建设项目总投资包括工程造价（或固定资产投资）和流动资金（或流动资产投资）两部分；非生产性建设项目总投资一般仅指工程造价。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0217", "date": "2026-07-09", "chapter": "g03", "type": "single", "stem": "根据我国现行建设工程总投资及工程造价的构成，下列资金在数额上和工程造价相等的是（ ）。", "options": {"A": "固定资产投资+流动资金", "B": "固定资产投资+铺底流动资金", "C": "固定资产投资", "D": "建设投资"}, "answer": ["C"], "analysis": "【内容考查】本题考查的是建设项目总投资的构成 【选项分项】工程造价（固定资产投资）包括建设投资和建设期利息。固定资产投资与建设项目的工程造价在量上相等。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0218", "date": "2026-07-09", "chapter": "g03", "type": "single", "stem": "检验试验费是指施工企业按照有关标准规定，对建筑以及材料、构件和建筑安装物进行一般鉴定、检查所发生的费用，包括（ ）等。", "options": {"A": "新结构、新材料的试验费", "B": "特殊要求检验、试验的费用", "C": "对构件进行破坏性试验费用", "D": "自设试验室进行试验所耗用的材料费用"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是按费用构成要素划分 【选项分项】检验试验费是指施工企业按照有关标准规定，对建筑以及材料、构件和建筑安装物进行一般鉴定、检查所发生的费用，包括自设试验室进行试验所耗用的材料费用等。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0220", "date": "2026-07-09", "chapter": "g03", "type": "single", "stem": "下列费用项目中，不属于安全文明施工费的项目是（ ）。", "options": {"A": "环境保护费", "B": "安全施工费", "C": "临时设施费", "D": "已完工程及设备保护费"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是按造价形成划分 【选项分项】安全文明施工费内容包括环境保护费、文明施工费、安全施工费和临时设施费。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0221", "date": "2026-07-09", "chapter": "g03", "type": "single", "stem": "根据现行《建筑安装工程费用项目组成》 （现行规定），职工的劳动保险费应计入（ ）。", "options": {"A": "规费", "B": "企业管理费", "C": "措施费", "D": "人工费"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是按费用构成要素划分 【选项分析】劳动保险和职工福利费：是指由企业支付的职工退职金、按规定支付给离休干部的经费，集体福利费、夏季防暑降温、冬季取暖补贴、上下班交通补贴等。属于企业管理费。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0223", "date": "2026-07-09", "chapter": "g03", "type": "single", "stem": "关于进口设备外贸手续费的计算，下列公式中正确的是（ ）。", "options": {"A": "外贸手续费=FOB×人民币外汇汇率×外贸手续费率", "B": "外贸手续费=CIF×人民币外汇汇率×外贸手续费率", "C": "外贸手续费=(FOB×人民币外汇汇率)/(1-外贸手续费率)×外贸手续费率", "D": "外贸手续费=(CIF×人民币外汇汇率)/(1-外贸手续费率)×外贸手续费率"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是设备购置费 【选项分析】外贸手续费指按对外经济贸易部规定的外贸手续费率计取的费用，外贸手续费率一般取1.5％。计算公式为：外贸手续费=到岸价格（CIF）×人民币外汇汇率×外贸手续费率。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0224", "date": "2026-07-09", "chapter": "g03", "type": "single", "stem": "进口设备的抵岸价通常是由进口设备（ ）和进口设备从属费构成。", "options": {"A": "FOB", "B": "CFR", "C": "CIF", "D": "COF"}, "answer": ["C"], "analysis": "【内容考查】本题考查的是设备购置费 【选项分项】进口设备的原价是指进口设备的抵岸价，即设备抵达买方边境、港口或车站，交纳完各种手续费、税费后形成的价格。抵岸价通常# 由进口设备到岸价（CIF) 和进口从属费构成。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0225", "date": "2026-07-09", "chapter": "g03", "type": "single", "stem": "某工程采购一台国产非标准设备，制造厂生产该设备的材料费、加工费和辅助材料费合计20万元，专用工具费率为2%，废品损失率为8%，利润率为10%，增值税率为17%。假设不再发生其他费用，则该设备的增值税为（ ）万元。", "options": {"A": "4.08", "B": "4.09", "C": "4.11", "D": "4.12"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是设备购置费 【选项分析】增值税=20×（1+2%）×（1+8%）×（1+10%）×17%=4.12万元。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0231", "date": "2026-07-09", "chapter": "g03", "type": "single", "stem": "建设单位通过市场机制取得建设用地，不仅应承担征地补偿费用、拆迁补偿费用，还须向土地所有者支付（ ）。", "options": {"A": "安置补助费", "B": "土地出让金", "C": "青苗补偿费", "D": "土地管理费"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是建设用地费 【选项分析】建设用地若通过市场机制取得，则不但承担征地补偿费用、拆迁补偿费用，还须向土地所有者支付有偿使用费，即土地出让金。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0233", "date": "2026-07-09", "chapter": "g03", "type": "single", "stem": "根据我国现行建设项目总投资及工程造价的构成，联合试运转费应包括（ ）。", "options": {"A": "施工单位参加联合试运转人员的工资", "B": "设备安装中的试车费用", "C": "试运转中暴露的设备缺陷的处理费", "D": "生产人员的提前进厂费"}, "answer": ["A"], "analysis": "【内容考查】本题考查的是与未来生产经营有关的其他费用 【选项分项】试运转支出包括试运转所需原材料、燃料及动力消耗、低值易耗品、其他物料消耗、工具用具使用费、机械使用费、联合试运转人员工资、施工单位参加试运转人员工资、专家指导费，以及必要的工业炉烘炉费等；试运转收入包包试运转期间的产品销售收人和其他收入。联合试运转费不包括应由设备安装工程费用开支的调试及试车费用，以及在试运转中暴露出来的因施工原因或设备缺陷等发生的处理费用。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0236", "date": "2026-07-09", "chapter": "g03", "type": "single", "stem": "根据我国现行建设项目总投资及工程造价的构成，下列有关建设项目费用开支，应列入建设单位管理费的是（ ）。", "options": {"A": "监理费", "B": "竣工验收费", "C": "可行性研究费", "D": "节能评估费"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是与项目建设有关的其他费用 【选项分项】建设单位管理费是指项目建设单位从项目筹建之日起至办理竣工财务决算之日止发生的管理性质的支出。包括工作人员薪酬及相关费用、办公费、办公场地租用费、差旅交通费、劳动保护费、工具用具使用费、固定资产使用费、招募生产工人费、技术图书资料费(含软件)、业务招待费、竣工验收费和其他管理性质开支。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0238", "date": "2026-07-09", "chapter": "g03", "type": "single", "stem": "根据我国现行建设项目总投资及工程造价构成，在工程概算阶段考虑的对一般自然灾害处理的费用，应包含在（ ）内。", "options": {"A": "未明确项目准备金", "B": "基本预备费", "C": "暂列金额", "D": "不可预见准备金"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是预备费 【选项分项】基本预备费是指投资估算或工程概算阶段预留的，由于工程实施中不可预见的工程变更及治商一般自然灾害处理、地下障碍物处理、超规超限设备运输等而可能增加的费用。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0239", "date": "2026-07-09", "chapter": "g03", "type": "single", "stem": "在建设工程项目总投资组成中的基本预备费主要是为（ ）。", "options": {"A": "建设期内材料价格上涨增加的费用", "B": "因施工质量不合格返工增加的费用", "C": "超规超限设备运输等可能增加的费用", "D": "因业主方拖欠工程款增加的承包商贷款利息"}, "answer": ["C"], "analysis": "【内容考查】本题考查的是预备费 【选项分析】基本预备费是指在投资估算或设计概算阶段预留的，由于工程实施中不可预见的工程变更及洽商、一般自然灾害处理、地下障碍物处理、超规超限设备运输等可能增加的费用，费用内容包括： （1）在批准的基础设计和概算范围内增加的设计变更、局部地基处理等费用。 （2）一般自然灾害造成的损失和预防自然灾害所采取措施的费用。 （3）竣工验收时为鉴定工程质量，对隐蔽工程进行必要的挖掘和修复的费用。 （4）超规超限设备运输过程中可能增加的费用。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0266", "date": "2026-07-09", "chapter": "g03", "type": "single", "stem": "某建设项目工程费用为7200万元，工程建设其他费用为1800万元，基本预备费为400万元，项目前期年限1年，建设期3年，各年度完成投资计划额的比例分别为20%、40%与40%，年涨价率为6%，则该项目建设期第二年价差预备费为（ ）万元。", "options": {"A": "451.63", "B": "464.74", "C": "564.54", "D": "589.63"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是可行性研究阶段的投资估算 【选项分项】考生应掌握价差预备费的计算公式，并且应注意价差预备费的计算基数为静态投资。 第二年投资计划额I2=（7200+1800+400）*40%=3760万元 第二年价差预备费PF2=I2[（1+f）1（1+f）0.5（1+f）2-1-1]=3760*[（1+6%）2.5-1]=589.63万元。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0270", "date": "2026-07-09", "chapter": "g03", "type": "single", "stem": "某地2019年拟建一座年产40万吨某产品的化工厂。根据调查，该地区2017年已建年产30万吨相同产品项目的建筑工程费为4000万元，安装工程费为2000万元，设备购置费为8000万元。已知按2019年该地区价格计算的拟建项目设备购置费为9500万元，征地拆迁等其他费用为1000万元，且该区2017年至2019年建筑安装工程费平均每年递增4%，则该拟建项目的静态投资估算为（ ）万元。", "options": {"A": "16989.6", "B": "17910.0", "C": "18206.4", "D": "19152.8"}, "answer": ["C"], "analysis": "【内容考查】本题考查的是项目建议书阶段的投资估算 【选项分项】此题应用设备系数法解答，首先根据已完工程计算出建筑工程费与安装工程费与设备购置费的比例，然后对此比例用调差系数进行调整，最后在汇总征地拆迁等其他费用。计算过程为： 建筑工程费与安装工程费与设备购置费的比例： 4000/8000=0.5; 2000 /8000=0.25 拟建项目的静态投资估算=9500×[1+（0.5+0.25）×（1+4%）2]+1000=18206.4万元", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0275", "date": "2026-07-09", "chapter": "g03", "type": "single", "stem": "某项目建设期为2年，第一年贷款3000万元，第二年贷款2000万元，贷款年均衡发放，年利率为8%，建设期内只计息不付息。该项目建设期利息为（ ）。", "options": {"A": "366.4", "B": "449.6", "C": "572.8", "D": "659.2"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是可行性研究阶段的投资估算 【选项分析】第一年建设期利息：3000/2×8%=120万元；第二年建设期利息（3000+120+2000/2）×8%=329.6万元；120+329.6=449.6万元。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0276", "date": "2026-07-09", "chapter": "g03", "type": "single", "stem": "某建设项目工程费用5000万元，工程建设其他费用1000万元，基本预备费率为8%，年均投资价格上涨率5%，建设期两年，计划每年完成投资50%，则该项目建设期第二年价差预备费应为（ ）万元。", "options": {"A": "160.02", "B": "227.79", "C": "246.01", "D": "326.02"}, "answer": ["C"], "analysis": "【内容考查】本题考查的是可行性研究阶段的投资估算 【选项分析】基本预备费=（5000+1000）×8%=480（万元）静态投资=5000+1000+480=6480（万元）建设期第二年完成投资6480×50%=3240（万元）第二年价差预备费 3240×{（1+f）^0 （1+f）^0.5 （1+f）^(2-1)-1}=246.01（万元）", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0328", "date": "2026-07-09", "chapter": "g03", "type": "single", "stem": "根据GB/T 50500-2024《建设工程工程量清单计价标准》，下列费用中，应计入人工费的是（ ）。", "options": {"A": "劳动保护费", "B": "安全施工费", "C": "环境保养费", "D": "住房公积金"}, "answer": ["D"], "analysis": "在GB/T 50500-2024中，原规费（社会保险费和住房公积金）已全部并入人工费，不再单独列项。劳动保护费属于企业管理费，安全施工费属于措施项目费。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "gl-g03-007", "date": "2026-07-08", "chapter": "g03", "type": "multiple", "stem": "按费用构成要素划分，下列各项中属于材料费组成的有（ ）。", "options": {"A": "材料原价", "B": "材料运杂费", "C": "运输损耗费", "D": "采购及保管费", "E": "材料检验试验费"}, "answer": ["A", "B", "C", "D"], "analysis": "材料费包括材料原价、运杂费、运输损耗费、采购及保管费以及构成工程实体的工程设备费用。E选项检验试验费属于企业管理费，不属于材料费构成。", "tags": ["材料费", "费用构成"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g03-008", "date": "2026-07-08", "chapter": "g03", "type": "multiple", "stem": "按费用构成要素划分，下列费用中属于企业管理费的有（ ）。", "options": {"A": "办公费", "B": "差旅交通费", "C": "固定资产使用费", "D": "工会经费", "E": "已完工程及设备保护费"}, "answer": ["A", "B", "C", "D"], "analysis": "企业管理费包括办公费、差旅交通费、固定资产使用费、工具用具使用费、劳动保险和福利费、检验试验费、工会经费、职工教育经费、财产保险费、财务费、税金等。E选项已完工程及设备保护费属于措施项目费。", "tags": ["企业管理费", "费用构成"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g03-010", "date": "2026-07-08", "chapter": "g03", "type": "multiple", "stem": "按造价形成顺序划分，下列属于措施项目费的有（ ）。", "options": {"A": "安全文明施工费", "B": "夜间施工增加费", "C": "冬雨季施工增加费", "D": "二次搬运费", "E": "暂列金额"}, "answer": ["A", "B", "C", "D"], "analysis": "措施项目费包括安全文明施工费、夜间施工增加费、冬雨季施工增加费、二次搬运费、脚手架工程费、模板工程费、大型机械进出场及安拆费、已完工程及设备保护费。E选项暂列金额属于其他项目费。", "tags": ["措施项目费", "造价形成顺序"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g03-015", "date": "2026-07-08", "chapter": "g03", "type": "multiple", "stem": "下列费用中，以CIF（到岸价）为计算基数计取的有（ ）。", "options": {"A": "国际运费", "B": "运输保险费", "C": "银行财务费", "D": "外贸手续费", "E": "进口关税"}, "answer": ["D", "E"], "analysis": "外贸手续费=CIF×外贸手续费率，进口关税=CIF×关税税率，均以到岸价CIF为基数。A和B是CIF的组成部分而非以CIF为基数计取，C银行财务费=FOB×财务费率，以离岸价为基数。", "tags": ["进口设备原价", "CIF", "计算基数"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g03-016", "date": "2026-07-08", "chapter": "g03", "type": "multiple", "stem": "进口设备原价的构成中，在FOB价格基础上应增加的费用包括（ ）。", "options": {"A": "国际运费", "B": "运输保险费", "C": "银行财务费", "D": "外贸手续费", "E": "国内运杂费"}, "answer": ["A", "B", "C", "D"], "analysis": "进口设备原价=FOB+国际运费+运输保险费+银行财务费+外贸手续费+关税+增值税+消费税+车辆购置费。E选项国内运杂费不属于进口设备原价的组成部分，属于设备运至国内后的费用。", "tags": ["进口设备原价", "FOB"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g03-032", "date": "2026-07-08", "chapter": "g03", "type": "multiple", "stem": "按造价形成顺序划分建筑安装工程费，其组成部分包括（ ）。", "options": {"A": "分部分项工程费", "B": "措施项目费", "C": "其他项目费", "D": "企业管理费", "E": "规费"}, "answer": ["A", "B", "C"], "analysis": "按造价形成顺序，建筑安装工程费=分部分项工程费+措施项目费+其他项目费+增值税。D企业管理费属要素划分。原规费已并入人工费。", "tags": ["造价形成顺序", "组成"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g03-033", "date": "2026-07-08", "chapter": "g03", "type": "multiple", "stem": "下列费用中，应计入建筑安装工程材料费的有（ ）。", "options": {"A": "构成工程实体的原材料费用", "B": "构成工程实体的辅助材料费用", "C": "构成工程实体的工程设备费用", "D": "周转材料的摊销费用", "E": "施工机械的燃料动力费"}, "answer": ["A", "B", "C"], "analysis": "材料费包含构成工程实体的原材料、辅助材料、构配件、零件、半成品和工程设备的费用。D选项周转材料摊销属于措施项目费，E选项施工机械燃料动力费属于施工机具使用费。", "tags": ["材料费", "费用区分"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g03-035", "date": "2026-07-08", "chapter": "g03", "type": "multiple", "stem": "关于工程建设其他费用中的建设用地费，下列说法正确的有（ ）。", "options": {"A": "包括土地征用及拆迁补偿费", "B": "包括土地使用权出让金", "C": "属于与项目建设有关的费用", "D": "属于与未来生产经营有关的费用", "E": "是工程建设其他费的重要组成部分"}, "answer": ["A", "B", "E"], "analysis": "建设用地费包括土地征用及拆迁补偿费、土地使用权出让金等，是工程建设其他费的重要组成部分。C和D错误，建设用地费既不属于与项目建设有关的费用，也不属于与未来生产经营有关的费用，而是单独作为一类。", "tags": ["建设用地费", "工程建设其他费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g03-038", "date": "2026-07-08", "chapter": "g03", "type": "multiple", "stem": "下列各项中，属于基本预备费使用范围的有（ ）。", "options": {"A": "设计变更增加的费用", "B": "不可抗力造成的损失", "C": "隐蔽工程验收时发生的挖掘及恢复费用", "D": "建设期人工费价格上涨增加的费用", "E": "一般自然灾害造成的损失"}, "answer": ["A", "B", "C", "E"], "analysis": "基本预备费用于：①设计变更及施工中可能增加的工程量；②一般自然灾害造成的损失和预防措施费用；③竣工验收时为鉴定工程质量对隐蔽工程进行必要的挖掘和修复费用。D选项建设期人工费价格上涨属于价差预备费的范围。", "tags": ["基本预备费", "使用范围"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-011", "date": "2026-07-08", "chapter": "g03", "type": "multiple", "stem": "下列属于人工费构成内容的有（ ）。", "options": {"A": "计时工资或计件工资", "B": "奖金", "C": "津贴补贴", "D": "加班加点工资"}, "answer": ["A", "B", "C", "D"], "analysis": "人工费构成：计时/计件工资、奖金、津贴补贴、加班加点工资、特殊情况下支付的工资。", "tags": ["建安费", "人工费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-029", "date": "2026-07-08", "chapter": "g03", "type": "multiple", "stem": "下列属于措施项目费的有（ ）。", "options": {"A": "安全文明施工费", "B": "脚手架工程费", "C": "模板工程费", "D": "大型机械进出场费"}, "answer": ["A", "B", "C", "D"], "analysis": "措施项目费含安全文明、脚手架、模板、大型机械进出场、二次搬运、夜间施工、冬雨季施工等。", "tags": ["建安费", "措施项目费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g03-035", "date": "2026-07-08", "chapter": "g03", "type": "multiple", "stem": "其他项目费包括（ ）。", "options": {"A": "暂列金额", "B": "暂估价", "C": "计日工", "D": "总承包服务费"}, "answer": ["A", "B", "C", "D"], "analysis": "其他项目费包含4项：暂列金额、暂估价、计日工、总承包服务费。", "tags": ["建安费", "其他项目费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "ht_mgmt_0888", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "世界银行、国际咨询工程师联合会规定工程项目总建设成本包括()。", "options": {"A": "项目直接建设成本", "B": "项目间接建设成本", "C": "预备费", "D": "应急费", "E": "建设成本上升费"}, "answer": ["A", "B", "D", "E"], "analysis": "世界银行、国际咨询工程师联合会对项目的总建设成本（相当于我国的工程造价）作了统一规定，工程项目总建设成本包括直接建设成本、间接建设成本、应急费和建设成本上升费等。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0889", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "根据我国现行建筑安装工程费用组成，下列各费用项目中属于措施费的是()。", "options": {"A": "安全施工费", "B": "超高施工增加费", "C": "建设单位临时设施费", "D": "已完工程及设备保护费", "E": "工程排污费"}, "answer": ["A", "B", "D"], "analysis": "本题考查的是措施费的内容。以《房屋建筑与装饰工程计量规范》GB50584-2013中的规定为例，措施项目费可以归纳为以下几项：（1）安全文明施工费。通常由环境保护费、文明施工费、安全施工费、临时设施费组成。（7）已完工程及设备保护费；（11）超高施工增加费原文是：传统规费主要包括社会保险费和住房公积金（GB/T 50500-2024中已并入人工费），工程排污费已停征，因此E错。场地准备及临时设施费的内容，（2）建设单位临时设施费，因此C错。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0890", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "根据GB/T 50500-2024《建设工程工程量清单计价标准》，下列费用中应计入人工费的有（ ）。", "options": {"A": "施工排水费", "B": "工程排污费", "C": "冬雨季施工增加费", "D": "住房公积金", "E": "社会保险费"}, "answer": ["D", "E"], "analysis": "在GB/T 50500-2024中，原规费（社会保险费和住房公积金）已并入人工费，不再单独列项，因此D住房公积金和E社会保险费应计入人工费。工程排污费已停征。施工排水费和冬雨季施工增加费属措施项目费。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0891", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "下列工程中，其工程费用列入建筑工程费用的是()。", "options": {"A": "设备基础工程", "B": "供水、供暖、通风工程", "C": "电缆导线敷设工程", "D": "附属于被安装设备的管线敷设工程", "E": "各种炉窑的砌筑工程"}, "answer": ["A", "B", "C", "E"], "analysis": "建筑工程费用的内容多，安装工程费用内容少，建议考生记安装工程费用 的内容，然后采用排除法进行解答。根据规定，安装工程费用内容包括： (1)生产、动力、起重、运输、传动和医疗、实验等各种需要安装的机械设备的装配费用，与设备相连的工作台、梯子、栏杆等设施的工程费用，附属于被安装设备的管线敷设工程费用，以及被安装设备的绝缘、防腐、保温、油漆等工作的材料费和安装费。 (2)为测定安装工程质量，对单台设备进行单机试运转、对系统设备进行系统联动无负荷试运转工作的调试费。 本题中只有选项D属于安装工程费用的内容，因此将其排除，", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0892", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "下列措施项目其计量单位可以用“m2”计量的是()。", "options": {"A": "脚手架费", "B": "混凝土模板及支架（撑）费", "C": "垂直运输费", "D": "超高施工增加费", "E": "施工排水、降水费"}, "answer": ["A", "B", "C", "D"], "analysis": "选项ABCD均可以用“m2”作为计量单位，其中垂直运输费根据不同的需要，还可以按照施工工期日历天数以“d”为单位计算。选项E，施工排水、降水费分两个不同的独立部分计算：①成井费用通常按照设计图示尺寸以钻孔深度按“m”计算；②排水、降水费用通常按照排、降水日历天数按昼夜计算。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0893", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "下列各项费用中，构成大型施工机械台班单价的是()。", "options": {"A": "折旧费", "B": "检修费", "C": "大型机械设备进出场及安拆费", "D": "材料费", "E": "维护费"}, "answer": ["A", "B", "E"], "analysis": "施工机械台班单价通常由折旧费、检修费、维护费、安拆费及场外运费、人工费、燃料动力费和其他费用组成。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0894", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "关于措施费中超高施工增加费，下列说法正确的有（）。", "options": {"A": "单层建筑费檐口高度超过30m时计费", "B": "多层建筑超过6层时计算", "C": "包括建筑超高引起的人工工效降低费", "D": "不包括通信联络设备的使用费", "E": "按建筑物超过部分建筑面积以“㎡”为单位计算"}, "answer": ["B", "C", "E"], "analysis": "当单层建筑物檐口高度超过20m，多层建筑物超过6层时，可计算超高施工增加费，超高施工增加费的内容由以下各项组成：（1）建筑物超高引起的人工工效降低以及由于人工工效降低引起的机械降效费；（2）高层施工用水加压水泵的安装、拆除及工作台班费；（3）通信联络设备的使用及摊销费。超高施工增加费通常按照建筑物超高部分的建筑面积以“㎡”为单位计算。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0895", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "根据现行建筑安装工程费项目组成规定，下列费用项目中，属于建筑安装工程企业管理费的有（）。", "options": {"A": "仪器仪表使用费", "B": "工具用具使用费", "C": "建筑安装工程一切险", "D": "地方教育附加费", "E": "劳动保险费"}, "answer": ["B", "D", "E"], "analysis": "(四）企业管理费 1.企业管理费的内容", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0896", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "按我国现行建筑安装工程费用项目组成的规定，下列属于企业管理费内容的有（）。", "options": {"A": "企业管理人员办公用的文具、纸张等费用", "B": "企业施工生产和管理使用的属于固定资产的交通工具的购置、维修费", "C": "对建筑以及材料、构件和建筑安装进行特殊鉴定检查所发生的检验试验费", "D": "按全部职工工资总额比例计提的工会经费", "E": "为施工生产筹集资金、履约担保所发生的财务费用"}, "answer": ["A", "D", "E"], "analysis": "企业管理费是指建筑安装企业组织施工生产和经营管理所需的费用。内容包括： 1）是指企业管理办公用的文具、纸张、账表、印刷、邮电、书报、办公软件、现场监控、会议、水电、烧水和集体取暖降温（包括现场临时宿舍取暖降温）等费用； 2）管理和试验部门及附属生产单位使用的属于固定资产的房屋、设备、仪器等的折旧、大修、维修或租赁费； 3）对建筑以及材料、构件和建筑安装物进行一般鉴定、检查所发生的费用； 4）企业按《工会法》规定的全部职工工资总额比例计提的工会经费； 5）企业为施工生产筹集资金或提供预付款担保、履约担保、职工工资支付担保等所发生的各种费用。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0897", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "下列费用项目中，属于建筑安装工程企业管理费的有()。", "options": {"A": "养老保险费", "B": "管理人员工资", "C": "医疗保险费", "D": "财产保险费", "E": "检验试验费"}, "answer": ["B", "D", "E"], "analysis": "建筑安装工程企业管理费是指施工单位为组织施工生产和经营管理所发生的费用，包括：管理人员工资；办公费；差旅交通费；固定资产使用费；工具用具使用费；劳动保险和职工福利费；劳动保护费；检验试验费；工会经费；职工教育经费；财产保险费；财务费；税金（房产税、车船使用税、土地使用税、印花税）；其他（技术转让费、技术开发费、业务招待费、绿化费、广告费、公证费、法律顾问费、审计费和咨询费等）。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0898", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "根据《房屋建筑与装饰工程计量规范》GB50584-2013的规定，下列关于施工排水、降水费说法正确的是()。", "options": {"A": "此项费用由成井和排水、降水两个独立的费用项目组成", "B": "施工排水是指为了保证工程在正常条件下施工，所采用的降低地下水位的措施所发生的费用", "C": "成井费用按照设计图示尺寸以钻孔直径按米计算", "D": "排水、降水费用通常按照排、降水日历天数按昼夜计算", "E": "成井的费用包括对接上、下井管，焊接，安防，洗井，连续试抽等费用"}, "answer": ["A", "D", "E"], "analysis": "本题考查的是施工排水、降水费用的内容。该项费用由成井和排水、降水两个独立的费用项目组成。排水、降水费用通常按照排、降水日历天数按昼夜计算。成井的费用主要包括：1、准备钻孔机械、埋设护筒、钻机就位，泥浆制作、固壁、成孔、出渣、清孔等费用；2、对接上、下井管（滤管），焊接、安防，下滤料，洗井，连接试抽等费用。施工排水、降水费。是指将施工期间有碍施工作业和影响工程质量的水排到施工场地以外，以及防止在地下水位较高的地区开挖深基坑出现基坑浸水，地基承载力下降，在动水压力作用下还可能引起流砂、管涌和边坡失稳等现象而必须采取有效的降水和排水措施费用。因此B错。成井费用通常按照设计图示尺寸以钻孔深度按m计算，因此C错。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0899", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "关于国外建筑安装工程费用构成的说法中，正确的有()。", "options": {"A": "招雇解雇费应计入人工费", "B": "管理费包括现场管理费与公司管理费", "C": "管理费不包括广告宣传费与交际费", "D": "驻工地工程师的现场办公室及所需设备的费用应列入管理费", "E": "建筑安装工程量越大，开办费在工程价格中的比例就越小"}, "answer": ["A", "B", "E"], "analysis": "本题考查的是国外建筑安装工程费用的构成。原文是：人工费应该包括工资、加班费、津贴、招雇解雇费用等。原文是：管理费包括工程现场管理费（占整个管理费的20%～30%）和公司管理费（占整个管理费的70%～80%）。管理费除了包括与我国施工管理费构成相似的工作人员工资、工作人员辅助工资、办公费、差旅交通费、固定资产使用费、生活设施使用费、工具用具使用费、劳动保护费、检验试验费以外，还含有业务经费。业务经费包括：（1）广告宣传费；（2）交际费。因此AB对，C错。 原文是：开办费包括的内容因国家和工程的不同而异，大致包括以下内容：（5）驻工地工程师的现场办公室及所需设备的费用，现场材料试验及所需设备的费用。因此D错。单项工程建筑安装工程量越大，开办费在工程价格中的比例就越小，反之开办费就越大。因此E对。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0900", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "我国现行建筑安装工程费用构成中，属于措施费的项目有()。", "options": {"A": "脚手架费", "B": "二次搬运费", "C": "工程排污费", "D": "非夜间施工照明费", "E": "研究试验费"}, "answer": ["A", "B", "D"], "analysis": "此题考核学生对措施费、原规费（已并入人工费）、工程建设其他费用组成的掌握。措施费是指实际施工中必须发生的施工准备和施工过程中技术、生活、安全、环境保护等方面的非工程实体项目的费用。工程排污费属于规费，研究试验费属于与项目建设有关的其他费用。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0901", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "根据我国现行建筑安装工程费用项目组成的规定，下列人工费中能够计入分部分项工程费的有（）。", "options": {"A": "保管建筑材料人员的工资", "B": "绑扎钢筋人员的工资", "C": "操作施工机械人员的工资", "D": "现场临时设施搭设人员的工资", "E": "施工排水、降水作业人员的工资"}, "answer": ["A", "B", "C"], "analysis": "分部分项工程费是指各专业工程的分部分项工程应予列支的各项费用。分部分项工程费通常分部分项工程量乘以综合单价进行计算。综合单价包括人工费、材料费、施工机具使用费、企业管理费和利润，以及一定范围的风险费用。现场临时设施搭设、施工排水降水均属于措施项目", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0902", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "国外建筑安装工程费用中的开办费一般包括（）等。", "options": {"A": "工地清理费", "B": "现场管理费", "C": "材料预涨费", "D": "周转材料费", "E": "暂定金额"}, "answer": ["A", "D"], "analysis": "单项工程开办费的内容通常包括：施工用地、用水、机具费，清理费，周转材料摊销费，临时设施摊销费，驻工地工程师办公费，现场实验费，其他开办费。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0903", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "根据国外建筑安装工程费用构成，在承包商的投标报价中应单独列项的是（）。", "options": {"A": "周转材料摊销费", "B": "招雇解雇费", "C": "现场管理费", "D": "现场试验费", "E": "临时设施摊销费"}, "answer": ["A", "D", "E"], "analysis": "(2)单独列项。开办费中的项目有临时设施、为业主提供的办公和生活设施、脚手架等费用，经常在工程量清单的开办费部分单独分项报价。这种方式适用于不直接消耗在某个分部分项工程上，无法与分部分项工程直接对应，但是对完成工程建设必不可少的费用。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0904", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "例：下列关于设备及工器具购置费的描述中，正确的是（）。", "options": {"A": "设备购置费由设备原价和设备运杂费组成", "B": "国产标准设备带有备件时，其原价按不带备件的价值计算，备件价值计入工器具购置费中", "C": "国产设备的运费和装卸费是指由设备制造厂交货地点起至工地仓库止所产生的运费和装卸费", "D": "进口设备采用装运港船上交货价时，其运费和装卸费是指设备由装运港港口起到工地仓库止所发生的运费和装卸费", "E": "工具、器具及生产家具购置费一般以设备购置费为计算基数，乘以部门或行业规定的定额费率计算"}, "answer": ["A", "C", "E"], "analysis": "本题考查设备及工器具购置费的相关内容。进口设备采用装运港船上交货价时，其运费和装卸费是指设备由我国到岸港口或边境车站起到工地仓库止所发生的运费和装卸费，故【答案】Ｄ不正确。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0905", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "根据我国现行工程造价构成，设备购置费包括的费用有()。", "options": {"A": "达到固定资产标准的各种设备", "B": "未达到固定资产标准的设备", "C": "达到固定资产标准的工器具", "D": "未达到固定资产标准的工器具", "E": "生产家具购置费"}, "answer": ["A", "C"], "analysis": "本题考核的是设备购置费的构成设备购置费是指购置或自制的达到固定资产标准的设备、工器具及生产家具等所需的费用。它由设备原价和设备运杂费构成。E是不正确的，因为根据上文设备购置费包括的是达到固定资产标准的生产家具的费用，工具、器具及生产家具购置费，是指新建或扩建项目初步设计规定的，保证初期正常生产必须购置的没有达到固定资产标准的设备、仪器、工卡模具、器具、生产家具和备品备件等的购置费用也就是说，达到固定资产的，在设备购置费里，没有达到的在工器具及生产家具购置费里，所以E不能选择。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0906", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "某建设项目的进口设备采用装运港船上交货价，则买方的责任有()。", "options": {"A": "负责租船并将设备装上船只", "B": "支付运费", "C": "负担货物在装运港越过船舷后的各种费用以及货物灭失或损坏的一切风险", "D": "办理在目的港的收货手续", "E": "办理出口手续"}, "answer": ["B", "C", "D"], "analysis": "FOB意为装运港船上交货，亦称为离岸价格。在采用装运港船上交货价时，买方的基本义务有：负责租船订舱，按时派船到合同约定的装运港接运货物，支付运费，并将船期、船名及装船地点及时通知卖方；负担货物在装运港越过船舷后的各种费用以及货物灭失或损坏的一切风险；负责获取进口许可证或其他官方文件，以及办理货物入境手续；受领卖方提供的各种单证，按合同规定支付货款。办理出口手续以及将设备装上船只均属于卖方的基本义务。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0907", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "下列费用项目中，以“完税价格+关税+消费税”为基数，乘以各自给定费（税）率进行计算的有()。", "options": {"A": "外贸手续费", "B": "关税", "C": "银行财务费", "D": "进口环节增值税", "E": "车辆购置税"}, "answer": ["D", "E"], "analysis": "进口环节增值税、车辆购置税的计算基础是关税完税价格+关税+增值税税率", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0908", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "国产非标准设备原价按成本计算估价法确定时，其包装费的计算基数包括()。", "options": {"A": "材料费", "B": "辅助材料费", "C": "加工费", "D": "非标准设备设计费", "E": "外购配套件费"}, "answer": ["A", "B", "C", "E"], "analysis": "按成本计算估价法，非标准设备的原价中包装费按材料费、加工费、辅助材料费、专用工具费、废品损失费、外购配套件费六项之和乘以一定百分比计算。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0909", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "关于设备运杂费的构成及计算的说法中，正确的有()。", "options": {"A": "运费和装卸费是由设备制造厂交货地点至施工安装作业面所发生的费用", "B": "进口设备运费和装卸费是由我国到岸港口或边境车站至工地仓库所发生的费用", "C": "原价中没有包含的、为运输而进行包装所支出的各种费用应计入包装费", "D": "采购与仓库保管费不含采购人员和管理人员的工资", "E": "设备运杂费为设备原价与设备运杂费率的乘积"}, "answer": ["B", "C", "E"], "analysis": "运费和装卸费包含国产和进口设备，故选项A错误；采购与仓库保管费包含设备采购人员、保管人员和管理人员的工资，选项D错误。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0910", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "国际贸易中，CFR交货方式下买方的基本义务有()。", "options": {"A": "负责租船订舱", "B": "承担货物在装运港越过船舷以后的一切风险", "C": "承担运输途中因遭遇风险引起的额外费用", "D": "在合同规定的目的港受领货物", "E": "办理进口清关手续"}, "answer": ["B", "C", "D", "E"], "analysis": "CFR意为成本加运费，或称之为运费在内价。在CFR交货方式下，买方的基本义务有：承担货物在装运港越过船舷以后的一切风险及运输途中因遭遇风险所引起的额外费用；在合同规定的目的港受领货物，办理进口清关手续，交纳进口税；受领卖方提供的各种约定的单证，并按合同规定支付货款。其中负责租船订舱属于卖方的基本义务。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0911", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "下列各费用项目中属于与项目建设有关的其他费用的是()。", "options": {"A": "研究试验费", "B": "环境影响评价费", "C": "职工教育经费", "D": "工程保险费", "E": "市政公用设施费"}, "answer": ["A", "B", "D", "E"], "analysis": "与项目建设有关的其他费用包括建设管理费、可行性研究费、研究试验费、勘察设计费、专项评价及验收费（环境影响评价费、安全预评价及验收费）、场地准备及临时设施费、引进技术和引进设备其他费、工程保险费、特殊设备安全监督检验费、市政公用设施费。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0912", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "新建或新增加生产能力的工程项目，在计算联合试运转费时需考虑的费用支出项目有()。", "options": {"A": "试运转所需原材料、燃料费", "B": "施工单位参加试运转人员工资", "C": "专家指导费", "D": "设备质量缺陷发生的处理费", "E": "施工缺陷带来的安装工程返工费"}, "answer": ["A", "B", "C"], "analysis": "联合试运转费是指新建或新增加生产能力的工程项目，在交付生产前按照设计文件规定的工程质量标准和技术要求，对整个生产线或装置进行负荷联合试运转所发生的费用净支出。（试运转支出大于收入的差额部分费用）。试运转支出包括试运转所需原材料、燃料及动力消耗、低值易耗品、其他物料消耗、工具用具使用费、机械使用费、保险金、施工单位参加试运转人员工资、以及专家指导费等。联合试运转费不包括应由设备安装工程费用开支的调试及试车费用，以及在试运转中暴露出来的因施工原因或设备缺陷等发生的处理费用。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0913", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "下列费用中属于工程建设其他费用中与项目建设有关的其他费用的是()。", "options": {"A": "建设管理费", "B": "生产准备及开办费", "C": "建设用地费", "D": "劳动安全卫生评价费", "E": "专利及专有技术使用费"}, "answer": ["A", "D"], "analysis": "工程建设其他费用可分为建设用地费、与项目建设有关的其他费用和与未来生产经营有关的其他费用三部分。与项目建设有关的其他费用包括建设管理费、可行性研究费、研究试验费、勘察设计费、环境影响评价费、劳动安全卫生评价费、场地准备及临时设施费、引进技术和引进设备其他费、工程保险费、特殊设备安全监督检验费、市政公用设施费，与未来生产经营有关的其他费用包括联合试运转费、专利及专有技术使用费和生产准备及开办费。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0914", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "关于建设用地取得及费用，下列说法中正确的有（）。", "options": {"A": "通过出让获得国有土地使用权的方式有招标、拍卖、挂牌和协议", "B": "工业、商业、旅游、娱乐用地的土地使用权出让最长年限为40年", "C": "以划拨方式取得的土地使用权，因企业改制不在符合划拨用地目录，应实行有偿使用", "D": "通过市场机制获得的土地使用权，不再承担征地补偿费或拆迁补偿费", "E": "搬迁补助费的标准，由各省、自治区、直辖市人民政府规定"}, "answer": ["A", "C", "E"], "analysis": "通过出让方式获取土地使用权又可以分成两种具体方式：一是通过招标、拍卖、挂牌等竞争出让方式获取国有土地使用权。二是通过协议出让方式获取国有土地使用权。依法以划拨方式取得土地使用权的，除法律、行政法规另有规定外，没有使用期限的限制。因企业改制、土地使用权转让或者改变土地用途等不再符合目录要求的，应当实行有偿使用。搬迁补助费和安置补助费的标准，由省、自治区、直辖市人民政府规定。建设用地如通过行政划拨方式取得，则须承担征地补偿费用或对原用地单位或个人的拆迁补偿费用；若通过市场机制取得，则不但承担以上费用，还须向土地所有者支付有偿使用费，即土地出让金。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0915", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "下列项目中，在计算联合试运转费时需要考虑的费用包括()。", "options": {"A": "试运转所需原料、动力的费用", "B": "单台设备调试费", "C": "试运转所需的机械使用费", "D": "试运转产品的销售收入", "E": "施工单位参加联合试运转人员的工资"}, "answer": ["A", "C", "D", "E"], "analysis": "试运转支出包括试运转所需原材料、燃料及动力消耗、低值易耗品、其他物料消耗、工具用具使用费、机械使用费、保险金、施工单位参加试运转人员工资，以及专家指导费等。试运转收入包括试运转期间的产品销售收入和其他收入。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0916", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "下列费用中，属于工程建设其他费中建设管理费的有()。", "options": {"A": "建设单位管理费", "B": "可行性研究费", "C": "勘察设计费", "D": "工程监理费", "E": "总承包管理费"}, "answer": ["A", "D", "E"], "analysis": "建设管理费是指建设单位为组织完成工程项目建设，在建设期内发生的各类管理性费用。主要内容包括建设单位管理费和工程监理费，如建设单位采用工程总承包方式，其总包管理费由建设单位与总包单位根据总包工作范围在合同中商定，从建设管理费中支出。B和C选项和建设管理费的平行的，都属于工程建设其他费用。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0918", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "下列工程建设其他费用中，按规定将形成与项目建设有关的其他费用的有（）。", "options": {"A": "市政公用设施费", "B": "可行性研究费", "C": "场地准备及临时设施费", "D": "专有技术使用费", "E": "生产准备费"}, "answer": ["A", "B", "C"], "analysis": "工程建设其他费用可分为建设用地费、与项目建设有关的其他费用和与未来生产经营有关的其他费用三部分。与项目建设有关的其他费用包括建设管理费、可行性研究费、研究试验费、勘察设计费、环境影响评价费、劳动安全卫生评价费、场地准备及临时设施费、引进技术和引进设备其他费、工程保险费、特殊设备安全监督检验费、市政公用设施费，与未来生产经营有关的其他费用包括联合试运转费、专利及专有技术使用费和生产准备及开办费。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0919", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "下列各项中属于建设项目基本预备费组成内容的是()。", "options": {"A": "在批准的初步设计范围内，技术设计、施工图设计及施工过程'中所增加的工程费用；设计变更、工程变更、材料代用、局部地基处理等增加的费用", "B": "一般自然灾害造成的损失费用", "C": "利率、汇率调整所增加的费用", "D": "不可预见的地下障碍物处理的费用", "E": "超规超限设备运输增加的费用"}, "answer": ["A", "B", "D", "E"], "analysis": "基本预备费 般由以下四部分构成：(1) 工程变更及洽商。在批准的初步设计范围内，技术设计、施工图设计及施工过程'中所增加的工程费用；设计变更、工程变更、材料代用、局部地基处理等增加的费用。(2) —般自然灾害处理。一般自然灾害造成的损失和预防自然灾害所采取的措施费用。实行工程保险的工程项目，该费用应适当降低。(3) 不可预见的地下障碍物处理的费用。(4) 超规超限设备运输增加的费用。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0920", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "(2013年)下列施工企业支出的费用项目中，属于建筑安装工程企业管理费的有()。", "options": {"A": "技术开发费", "B": "印花税", "C": "已完工程及设备保护费", "D": "材料采购及保管费", "E": "财产保险费"}, "answer": ["A", "B", "E"], "analysis": "选项C属于措施费，选项D属于直接工程费中的材料费。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0921", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "(2014年)下列有关安全文明费的说法中，正确的有（）", "options": {"A": "安全文明施工费包括临时设施费", "B": "现场生活用洁净燃料费属于环境保护费", "C": "“三宝”、“四口”、“五临边”等防护费用属于安全施工费", "D": "消防设施与消防器材的配置费用属于文明施工费", "E": "施工现场搭设的临时文化福利用房的费用属于文明施工费"}, "answer": ["A", "C"], "analysis": "现场生活用洁净燃料费属于文明施工费，所以B错；消防设施与消防器材的配置费用属于安全施工费，所以D错；施工现场搭设的临时文化福利用房的费用属于临时设施费，所以E错。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0922", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "(2016年)根据我国现行建筑安装工程费用项目组成规定，下列施工企业发生的费用中，应计入企业管理费的是()。", "options": {"A": "建筑材料、构件一般性鉴定检查费", "B": "支付给企业离休干部的经费", "C": "施工现场工程排污费", "D": "履约担保所发生的费用", "E": "施工生产用仪器仪表使用费"}, "answer": ["A", "B", "D"], "analysis": "A属于检测实验费；B属于劳动保险和职工福利费；D属于财务费。这三者都属于企业管理费。C在传统分类中属于规费（GB/T 50500-2024中已并入人工费）。E属于施工机具使用费。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0923", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "(2015年)为了便于措施项目费的确定和调整，通常采用分部分项工程量清单方式编制的措施项目有( )。", "options": {"A": "脚手架工程", "B": "垂直运输工程", "C": "二次搬运工程", "D": "已完工程及设备保护", "E": "施工排水降水"}, "answer": ["A", "B", "E"], "analysis": "该题主要考察的是：措施项目费的计算“按照有关专业工程量计算规范规定，措施项目分为应予计量的措施项目和不宜计量的措施项目两类。1) 脚 手架费 通常按 建筑面 积或垂 直投影 面积按 “ m2” 计算； 2) 混凝 土模板 及支架 （撑） 费 通常是 按照模 板与现 浇混凝 土构件 的接触 面积以 (1. 3. 12) “ m2” 计算 3) 垂直运 输费可 根据不 同情况 用两种 方法进 行计算 ：①按 照建筑 面积以 “ m2” 为单 位计算 +; ②按照 施工工 期日历 天数以 “天” 为单位 计算。 4) 超高施 工增加 费通常 按照建 筑物超 高部分 的建筑 面积以 “ m2” 为单位 计算。 5) 大型 机械设 备进出 场及安 拆费通 常按照 机械设 备的使 用数量 以“台 次”为 单位计 算。 6) 施 工排水 、降 水费分 两个不 同的独 立部分 计算： ①成井 费用通 常按照 设计图 示尺寸 以钻孔 深度按 “ m” 计算； ②排水 、降 水费 用通常 按照排 、降水 日历天 数按“ 昼夜” 计算。”", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0924", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "(2015年)根据我国现行建筑安装工程费用项目组成的规定，下列费用中属于安全文明施工中临时设施费的有()。", "options": {"A": "现场采用砖砌围挡的安砌费用", "B": "现场围挡的墙面美化费用", "C": "施工现场的操作场地的硬化费用", "D": "施工现场规定范围内临时简易道路的铺设费用", "E": "地下室施工时所采用的照明设备的安拆费用"}, "answer": ["A", "D"], "analysis": "该题主要考察的是：安全文明施工措施费的内容，", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0925", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "(2014年)国产非标准设备按其成本估算其原价时，下列计算式中正确的有（）", "options": {"A": "材料费=材料净重×每吨材料综合价", "B": "加工费=设备总重量×设备每单位重量加工费", "C": "辅助材料费=设备总重量×辅助材料费指标", "D": "增值税=进项税额-当期销项税额", "E": "当期销项税额=销售额×适用增值税率"}, "answer": ["B", "C", "E"], "analysis": "本题考查的是国产非标准设备原价的计算。 材料费=材料净重×（1+加工损耗系数）×每吨材料综合价 加工费。包括生产工人工资和工资附加费、燃料动力费、设备折旧费、车间经费等。其计算公式如下：加工费=设备总重量（吨）×设备每吨加工费 辅助材料费（筒称辅材费）。包括焊条、焊丝、氧气、氨气、氨气、油漆、电石等费用。其计算公式如下：辅助材料费=设备总重量×辅助材料费指标 增值税=当期销项税额-进项税额，当期销项税额=销售额×适用增值税率", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0926", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "(2015年)关于设备购置费的构成和计算，下列说法中正确的有( )。", "options": {"A": "国产标准设备的原价中，一般不包含备件的价格", "B": "成本计算估价法常用于非标准设备原价的价格", "C": "进口设备原价是指进口设备到岸价", "D": "国产非标准设备原价中包含非标准设备设计费", "E": "达到固定资产标准的工器具，其购置费用应计入设备购置费中"}, "answer": ["B", "D", "E"], "analysis": "本题考查的是设备购置费的构成和计算。设备购置费是指购置或自制的达到固定资产标准的设备、工器具及生产家具等所需的费用(所以E是正确的）。成本计算估价法是一种比较常用的估算非标准设备原价的方法。国产非标准设备原价中包含非标准设备设计费。选项A，国产标准设备的原价中，一般采用带有备件的原价。选项C，进口设备的原价是指进口设备的抵岸价。(10)非标准设备设计费: 按国家规定的设计费收费标准计算。E设备购置费是指购置或自制的达到固定资产标准的设备、工器具及生产家具等所需的费用。”", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0927", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "(2016年)关于生产准备及开办费，下列说法中正确的有()。", "options": {"A": "包括自行组织培训和委托其他单位培训的相关费用", "B": "包括正常生产所需的生产办公家具用具的购置费用", "C": "包括正常生活所需的生活家具用具的购置费用", "D": "包括含备品备件在内的第一套不够固定资产标准的生产工具购置费用", "E": "可按设计定员乘以人均生产准备费指标计算"}, "answer": ["A", "E"], "analysis": "在建设期内，建设单位为保证项目正常生产而发生的人员培训费、提前进厂费以及投产使用必备的办公、生活家具用具及工器具等的购置费用。包括： (1)人员培训费及提前进厂费。包括自行组织培训或委托其他单位培训的人员工资、 工资性补贴、职工福利费、差旅交通费、劳动保护费、学习资料费等。 (2)为保证初期正常生产或营业、使用所必需的生产办公、生活家具用具购置费。 2.生产准备费的计算 (1)新建项目按设计定员为基数计算，改扩建项目按新增设计定员为基数计算：生产准备费=设计定员×生产准备费指标（元/人） (2)可采用综合的生产准备费指标进行计算，也可以按费用内容的分类指标计算。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0928", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "(2014年)下列费用中，属于“与项目建设有关的其他建设费用”的有（）", "options": {"A": "建设单位管理费", "B": "工程监理费", "C": "建设单位临时设施费", "D": "施工单位临时设施费", "E": "市政公用设施费"}, "answer": ["A", "B", "C", "E"], "analysis": "本题考查的是与项目建设有关的其他费用的构成。 建设管理费是指建设单位为组织完成工程项自建设，在建设期内发生的各类管理性费用。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_0929", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "(2013年)关于工程建设其他费中的场地准备及临时设施费，下列说法正确的有()。", "options": {"A": "场地准备费是指为施工而进行的土地“三通一平”或“七通一平”的费用", "B": "其中的大型土石方工程应进入工程费中的总图运输费", "C": "新建项目的场地准备和临时设施费应根据实际工程重估算", "D": "场地准备和临时设施费=工程费用×费率+拆除清理费", "E": "委托施工单位修建临时设施时应计入施工单位措施费中"}, "answer": ["A", "B", "C", "D"], "analysis": "场地准备及临时设施费的内容：①建设项目场地准备费是指为使工程项目的建设场地达到开工条件，由建设单位组织进行的场地平整等准备工作而发生的费用；②建设单位临时设施费是指建设单位为满足工程项目建设、生活、办公的需要，用于临时设施建设、维修、租赁、使用所发生或摊销的费用。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_1000", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "工程造价控制的初步设计阶段，运用（ ）等，以可行性研究报告中被批准的投资估算为工程造价目标书，控制和修改初步设计直至满足要求。", "options": {"A": "价值工程", "B": "设计标准", "C": "限额设计方法", "D": "标准设计", "E": "设计概算"}, "answer": ["A", "B", "C", "D"], "analysis": "工程造价控制的初步设计阶段，运用设计标准与标准设计、价值工程和限额设计方法等，以可行性研究报告中被批准的投资估算为工程造价目标书，控制和修改初步设计直至满足要求。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_1001", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "根据现行费用文件， 按照造价形成划分建安工程费， 属于措施项目费的有（ ） 。", "options": {"A": "工程排污费", "B": "检验试验费", "C": "大型机械设备进出场及安拆费", "D": "雨季施工需增加的临时设施费", "E": "临时设施费"}, "answer": ["C", "D", "E"], "analysis": "本题考查的是措施项目费。工程排污费原属于规费（GB/T 50500-2024中已取消规费项，并入人工费），检验试验费属于企业管理费。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_1002", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "按照费用构成要素划分的建筑安装工程费用项目组成规定，下列费用项目应列入材料费的有（ ）。", "options": {"A": "周转材料的摊销，租赁费用", "B": "材料运输损耗费用", "C": "施工企业对材料进行一般鉴定，检查发生的费用", "D": "材料运杂费中的增值税进项税额", "E": "材料采购及保管费用"}, "answer": ["A", "B", "E"], "analysis": "选项 C 错误，施工企业对材料进行一般鉴定，检查发生的费用是企业管理费。选项 D 错误，不包括材料运杂费中的增值税进项税额", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_1003", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "下列选项中，属于人工费的有（ ）。", "options": {"A": "危险作业意外伤害保险", "B": "财产保险费", "C": "住房公积金", "D": "劳动保护费", "E": "社会保障费"}, "answer": ["C", "E"], "analysis": "根据GB/T 50500-2024《建设工程工程量清单计价标准》：\n【原规费并入人工费】原规费中的社会保障费（含五险）和住房公积金现已并入人工费，不再单列。\n✅ C住房公积金——原属规费，现计入人工费。\n✅ E社会保障费（含养老、医疗、失业、工伤、生育保险）——原属规费，现计入人工费。\n❌ A危险作业意外伤害保险——属于企业管理费。\n❌ B财产保险费——属于企业管理费。\n❌ D劳动保护费——属于企业管理费（劳保用品、防暑降温等），不属于人工费。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_1004", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "当一般纳税人采用一般计税方法时， 办公费中增值税进项税额的抵扣原则为（ ）", "options": {"A": "以购进货物适用的相应税率扣减，购进图书、报纸适用的税率为 9%", "B": "以购进服务适用的相应税率扣减，接受基础电信服务适用税率为 9%", "C": "以购进服务适用的相应税率扣减，接受增值电信服务适用的税率为 6%", "D": "以购进货物适用的相应税率扣减，购进打印纸、文具适用的税率为 13%", "E": "以购进货物适用的相应税率扣减，接受基础电信服务适用税率为10%"}, "answer": ["A", "B", "C", "D"], "analysis": "选项 A：图书、报纸属于 “出版物”，适用9% 税率（低税率货物），表述正确；选项 B：基础电信服务（如通话、宽带）属于 “电信服务 - 基础类”，适用9% 税率，表述正确；选项 C：增值电信服务（如短信、互联网服务）属于 “电信服务 - 增值类”，适用6% 税率，表述正确；选项 D：打印纸、文具属于 “一般货物”，适用13% 基本税率，表述正确。选项E：税率过时。2019 年 4 月 1 日增值税税率调整前，基础电信服务税率为 10%，但调整后已降至 9%，现行政策下 10% 税率不再适用于基础电信服务，表述错误。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_1005", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "根据现行建筑安装工程费用项目组成规定,下列费用项目中已包括在人工费的有（）。", "options": {"A": "节约奖", "B": "流动施工津贴", "C": "高温作业临时津贴", "D": "劳动保护费", "E": "探亲假期间工资"}, "answer": ["A", "B", "C", "E"], "analysis": "人工费由计时工资或计件工资、奖金、津贴补贴，加班加点的工资以及特殊情况下支付的工资组成，A属于奖金，BC属于津贴补贴，E属于特殊情况下支付的工资。 考前黑钻押题，金考典软件考前更新，下载链接 www.jinkaodian.com", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_1006", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "采购与仓库保管费指采购、验收、保管和收发设备所发生的各种费用，包括（ ）等。", "options": {"A": "设备采购人员、保管人员和管理人员的工资", "B": "工资附加费、办公费、差旅交通费", "C": "设备供应部门办公和仓库所占固定资产使用费", "D": "工具用具购买及出售费", "E": "劳动保护费、检验试验费"}, "answer": ["A", "B", "C", "E"], "analysis": "采购与仓库保管费。指采购、验收、保管和收发设备所发生的各种费用，包括设备采购人员、保管人员和管理人员的工资、工资附加费、办公费、差旅交通费，设备供应部门办公和仓库所占固定资产使用费、工具用具使用费、劳动保护费、检验试验费等这些费用可按主管部门规定的采购与保管费费率计算。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_1007", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "到岸价格(CI F)作为关税完税价格，其包括（ ）等费用。", "options": {"A": "国际运费", "B": "国内运费", "C": "运输保险费", "D": "外贸手续费", "E": "离岸价格"}, "answer": ["A", "C", "E"], "analysis": "进口设备到岸价的计算公式如下:设备到岸价 (CIF) =离岸价 (FOB) +国际运费+运输保险费", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_1008", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "计算设备进口环节增值税时， 作为计算基数的计税价格包括（）", "options": {"A": "外贸手续费", "B": "到岸价", "C": "设备运杂费", "D": "关税", "E": "消费税"}, "answer": ["B", "D", "E"], "analysis": "本题考查的是进口设备原价的构成及计算。 进口环节增值税=（关税完税价格+关税+消费税） ×增值税税率", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_1009", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "构成进口设备原价的费用构成中，应以到岸价为计算基数的有（ ）。", "options": {"A": "国际运费", "B": "进口环节增值税", "C": "银行财务费", "D": "外贸手续费", "E": "进口关税"}, "answer": ["D", "E"], "analysis": "本题考查的是设备及工器具购置费。选项A错误，国际运费计算基数是离岸价格FOB；选项B错误，进口环节增值税的计算基数是关税完税价格+关税+消费税；选项C错误，银行财务费的计算基数是离岸价格FOB。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_1010", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "国产非标准设备按成本构成估算其原价时，下列计算式正确的有（）。", "options": {"A": "材料费=材料净重×每吨材料综合价", "B": "加工费=设备总重量×设备每吨加工费", "C": "辅助材料费=设备总重量×辅助材料费指标", "D": "增值税=进项税额-当期销项税额", "E": "当期销项税额=不含税销售额×适用增值税率"}, "answer": ["B", "C", "E"], "analysis": "材料费＝材料净重×（1＋加工损耗系数）×每吨材料综合价，故A选项错误。增值税=当期销项税额－进项税额，故D选项错误。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_1011", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "下列与项目建设有关的其他费用中,属于建设管理费的有（）。", "options": {"A": "建设单位管理费", "B": "引进技术和引进设备其他费", "C": "工程监理费", "D": "场地准备费", "E": "工程总承包管理费"}, "answer": ["A", "C", "E"], "analysis": "与项目建设有关的其他费用中，建设管理费的内容包括建设单位管理费、工程监理费、工程总承包管理费。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_1012", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "《中华人民共和国土地管理法》规定，征收耕地的补偿费用包括（ ）。", "options": {"A": "土地补偿费", "B": "安置补助费", "C": "地上附着物补偿费", "D": "青苗补偿费", "E": "失业补助费"}, "answer": ["A", "B", "C", "D"], "analysis": "建设征用土地费用由以下几个部分构成： 1)土地补偿费； 2)青苗补偿费和地上附着物补偿费； 3)安置补助费； 4)新菜地开发建设基金； 5)耕地占用税； 6)土地管理费。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_1013", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "国外贷款利息的计算中，应包括国外贷款银行根据贷款协议向贷款方以年利率的方式收取的（ ）。", "options": {"A": "转贷费", "B": "管理费", "C": "手续费", "D": "担保费", "E": "承诺费"}, "answer": ["B", "C", "E"], "analysis": "国外贷款利息的计算中，还应包括国外贷款银行根据贷款协议向贷款方以年利率的方式收取的手续费、管理费、承诺费；以及国内代理机构经国家主管部门批准的以年利率的方式向贷款单位收取的转贷费、担保费、管理费等。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_1014", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "关于工程设计对造价的影响，下列说法中正确的有（ ）。", "options": {"A": "周长与建筑面积比越大，单位造价越高", "B": "流通空间的减少，可相应地降低造价", "C": "层数越多，则单位造价越低", "D": "房屋长度越大，则单位造价越低", "E": "结构面积系数越小，设计方案越经济"}, "answer": ["A", "B", "E"], "analysis": "选项C错误，正确的说法是建筑物层数对造价的影响，因建筑类型、形式和结构不同而不同。如果增加一个楼层不影响建筑物的结构形式，单位建筑面积的造价可能会降低，反正增加层数改变了结构形式，则造价会提高。选项D错误，房屋长度大到一定程度，就会改变建筑结构，造价可能会提高。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "ht_mgmt_1015", "date": "2026-07-10", "chapter": "g03", "type": "multiple", "stem": "建设项目决策阶段影响工程造价的主要因素有（ ）等。", "options": {"A": "设备方案", "B": "建设地区及建设地点", "C": "环境保护措施", "D": "项目建设规模", "E": "移民安置"}, "answer": ["A", "B", "C", "D"], "analysis": "工程决策阶段影响造价的主要因素有：项目建设规模、建设地区及地点(厂址)、技术方案、设备方案、工程方案和环境保护措施等。", "tags": [], "source": "第三章  工程造价构成", "src": "好题库"}, {"id": "mgmt_hqwx_0190", "date": "2026-07-09", "chapter": "g03", "type": "multiple", "stem": "根据《房屋建筑和市政基础设施工程施工图设计文件审查管理办法》，施工图审查机构对施工图审查的内容有（ ）。", "options": {"A": "是否按限额设计标准进行施工图设计", "B": "是否符合工程建设强制性标准", "C": "施工图预算是否超过批准的工程概算", "D": "地基基础和主体结构的安全性", "E": "危险性较大的工程是否有专项施工方案"}, "answer": ["B", "D"], "analysis": "【内容考查】本题考查的是建设实施阶段工作内容 【选项分项】审查的主要内容包括： 1）是否符合工程建设强制性标准； 2）地基基础和主体结构的安全性； 3）消防安全性； 4）人防工程（不含人防指挥工程）防护安全性； 5）是否符合民用建筑节能强制性标准，对执行绿色建筑标准的项目，还应当审查是否符合绿色建筑标准； 6）勘察设计企业和注册执业人员以及相关人员是否按规定在施工图上加盖相应的图章和签字； 7）法律、法规、规章规定必须审查的其他内容。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0206", "date": "2026-07-09", "chapter": "g03", "type": "multiple", "stem": "DBB管理模式的说法正确的有（ ）。", "options": {"A": "建设周期长", "B": "责任主体少", "C": "协调工作量小", "D": "设计的可施工性差", "E": "DBB模式主要体现的是专业化分工"}, "answer": ["A", "D", "E"], "analysis": "【内容考查】本题考查的是DBB模式 【选项分项】采用DBB模式的不足： （1）工程设计、招标、施工按顺序依次进行，建设周期长； （2）由于施工单位无法参与工程设计，设计的可施工性差，导致设计与施工的协调困难，设计变更频繁，可能使建设单位利益受损。 （3）工程的责任主体较多，包括设计单位、施工单位、材料设备供应单位等，一旦工程项目出现问题，建设单位不得不分别面对这些参与方，容易出现互相推诿，协调工作量大。 DBB模式主要体现的是专业化分工。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0219", "date": "2026-07-09", "chapter": "g03", "type": "multiple", "stem": "建筑安装工程费按费用构成要素划分（ ）。", "options": {"A": "施工机具使用费", "B": "材料费", "C": "风险费用", "D": "利润", "E": "增值税"}, "answer": ["A", "B", "D", "E"], "analysis": "按照费用构成要素划分，建筑安装工程费包括：人工费（原规费已并入）、材料费、施工机具使用费、企业管理费、利润、增值税。原规费已并入人工费。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0222", "date": "2026-07-09", "chapter": "g03", "type": "multiple", "stem": "下列费用中属于措施费的是（ ）。", "options": {"A": "二次搬运费", "B": "夜间施工增加费", "C": "环境保护费", "D": "社会保险费", "E": "定额测定费"}, "answer": ["A", "B", "C"], "analysis": "措施项目费包括：（1）安全文明施工费包括：环境保护费、安全施工费、文明施工费、临时设施费。（2）夜间施工增加费；（3）二次搬运费；（4）冬雨季施工增加费；（5）已完工程及设备保护费；（6）工程定位复测费；（7）特殊地区施工增加费；（8）大型机械设备进出场及安拆费；（9）脚手架工程费。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0226", "date": "2026-07-09", "chapter": "g03", "type": "multiple", "stem": "非标准设备原价中，能作为利润取费基数的是（ ）。", "options": {"A": "辅助材料费", "B": "废品损失费", "C": "包装费", "D": "外购配套件费", "E": "专用工具费"}, "answer": ["A", "B", "C", "E"], "analysis": "【内容考查】本题考查的是设备购置费 【选项分析】利润的计算基数包括材料费、加工费、辅助材料费、专用工具费、废品损失费和包装费之和乘以一定利润率计算。外购配套件由于不是自己生产的，所以不能计算利润。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0232", "date": "2026-07-09", "chapter": "g03", "type": "multiple", "stem": "下列建设用地取得费用中，属于征地补偿费的有（ ）。", "options": {"A": "土地补偿费", "B": "安置补助费", "C": "搬迁补助费", "D": "土地管理费", "E": "土地转让金"}, "answer": ["A", "B", "D"], "analysis": "【内容考查】本题考查的是建设用地费 【选项分项】征地补偿费包含以下内容：（1）土地补偿费。（2）青苗补偿费和地上附着物补偿费。（3）安置补助费。（4）新菜地开发建设基金。（5）耕地占用税。（6）土地管理费。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0315", "date": "2026-07-09", "chapter": "g03", "type": "multiple", "stem": "建筑安装工程费用项目组成中，暂列金额主要用于（ ）。", "options": {"A": "施工合同签订时尚未确定的材料设备采购费用", "B": "施工图纸以外的零星项目所需的费用", "C": "隐藏工程二次检验的费用", "D": "施工中可能发生的工程变更价款调整的费用", "E": "项目施工现场签证确认的费用"}, "answer": ["A", "D", "E"], "analysis": "【内容考查】本题考查的是《建设工程施工合同（示范文本）》的主要内容 【选项分项】暂列金额：是指发包人在工程量清单或预算书中暂定并包括在合同价格中的一笔款项，用于工程合同签订时尚未确定或者不可预见的所需材料、工程设备、服务的采购，施工中可能发生的工程变更、合同约定调整因素出现时的合同价格调整以及发生的索赔、现场签证确认等的费用。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "gl-g04-001", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "我国现行的工程量清单计价规范编号为（ ）。", "options": {"A": "GB/T 50500-2013", "B": "GB/T 50500-2018", "C": "GB/T 50500-2024", "D": "GB/T 50500-2025"}, "answer": ["C"], "analysis": "我国现行工程量清单计价规范为GB/T 50500-2024（《建设工程工程量清单计价规范》），是2025年考试新增强调的内容。", "tags": ["工程量清单计价", "GB/T 50500"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g04-002", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "工程量清单计价方法中，综合单价的组成不包括（ ）。", "options": {"A": "人工费", "B": "材料费", "C": "规费", "D": "管理费"}, "answer": ["C"], "analysis": "综合单价=人工费+材料费+施工机具使用费+企业管理费+利润，以及一定范围内的风险费用。规费和增值税不作为综合单价的组成部分，在单位工程造价中另行列项计算。", "tags": ["综合单价", "工程量清单计价"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g04-003", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "以预算定额为基础的计价方法称为（ ）。", "options": {"A": "工程量清单计价法", "B": "定额计价法", "C": "综合单价法", "D": "全费用单价法"}, "answer": ["B"], "analysis": "定额计价法是以预算定额为基础的传统计价方法，通过计算各分项工程的工程量和套用定额单价来确定工程造价。工程量清单计价法以GB/T 50500为基础。", "tags": ["定额计价法", "计价方法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g04-004", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "在计价依据体系中，以扩大分项工程为对象编制的定额是（ ）。", "options": {"A": "施工定额", "B": "预算定额", "C": "概算定额", "D": "概算指标"}, "answer": ["C"], "analysis": "概算定额以扩大的分项工程为对象编制，用于编制设计概算。预算定额以分项工程为单位，概算指标以整个建筑物（㎡、座）为单位，施工定额以工序为对象。", "tags": ["概算定额", "计价依据"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g04-005", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "以整个建筑物为对象（如每平方米造价、每座造价）编制的是（ ）。", "options": {"A": "施工定额", "B": "预算定额", "C": "概算定额", "D": "概算指标"}, "answer": ["D"], "analysis": "概算指标以整个建筑物或构筑物为对象，以建筑面积（㎡）或建筑体积（m³）或'座'为单位编制。投资估算指标以独立的单项工程或完整的工程项目为对象。", "tags": ["概算指标", "计价依据"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g04-006", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "预算定额的编制对象是（ ）。", "options": {"A": "工序", "B": "分项工程", "C": "扩大分项工程", "D": "整个建筑物"}, "answer": ["B"], "analysis": "预算定额以分项工程为对象编制，是编制施工图预算的主要依据。施工定额以工序为对象，概算定额以扩大分项工程为对象，概算指标以整个建筑物为对象。", "tags": ["预算定额", "编制对象"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g04-007", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "劳动定额中，时间定额与产量定额的关系是（ ）。", "options": {"A": "时间定额+产量定额=1", "B": "时间定额-产量定额=0", "C": "时间定额×产量定额=1", "D": "时间定额÷产量定额=1"}, "answer": ["C"], "analysis": "时间定额与产量定额互为倒数关系，即时间定额×产量定额=1。例如完成单位产品需要0.5工日，则每工日产量为2个单位。", "tags": ["劳动定额", "时间定额", "产量定额"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g04-008", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "材料消耗量由材料净用量和损耗量组成。材料损耗率的正确计算公式为（ ）。", "options": {"A": "损耗率=损耗量/总消耗量×100%", "B": "损耗率=损耗量/净用量×100%", "C": "损耗率=净用量/总消耗量×100%", "D": "损耗率=净用量/损耗量×100%"}, "answer": ["B"], "analysis": "材料损耗率=材料损耗量/材料净用量×100%。总消耗量=净用量+损耗量=净用量×(1+损耗率)。注意分母是净用量而非总消耗量，这是易混淆点。", "tags": ["材料消耗", "损耗率"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g04-009", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "施工机械一个台班的标准工作时长为（ ）小时。", "options": {"A": "6", "B": "8", "C": "10", "D": "12"}, "answer": ["B"], "analysis": "施工机械一个台班的标准工作时长为8小时。这是机械台班定额和机械台班单价计算的基础。", "tags": ["机械台班", "劳动定额"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g04-013", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "广东省三类施工企业的企业管理费费率是（ ）。", "options": {"A": "25.82%", "B": "23.59%", "C": "20.13%", "D": "18.75%"}, "answer": ["C"], "analysis": "广东省企业管理费费率：一类25.82%、二类23.59%、三类20.13%。广东特色是以人工费+施工机具使用费为计算基数。", "tags": ["企业管理费率", "广东省"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g04-014", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "广东省一类施工企业的企业管理费费率是（ ）。", "options": {"A": "20.13%", "B": "23.59%", "C": "25.82%", "D": "28.46%"}, "answer": ["C"], "analysis": "广东省一类企业管理费费率为25.82%，二类为23.59%，三类为20.13%。费率随企业类别等级递减。", "tags": ["企业管理费率", "广东省"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g04-015", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "广东省企业管理费的计算基数是（ ）。", "options": {"A": "人工费", "B": "人工费+材料费", "C": "人工费+施工机具使用费", "D": "直接费"}, "answer": ["C"], "analysis": "广东省企业管理费以人工费+施工机具使用费为计算基数，这是广东省的计价特色，区别于其他地区以人工费为基数或直接费为基数的做法。", "tags": ["企业管理费", "计算基数", "广东省"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g04-016", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "在工程量清单计价中，招标工程量清单应由（ ）编制。", "options": {"A": "投标人", "B": "招标人或其委托的工程造价咨询人", "C": "监理单位", "D": "设计单位"}, "answer": ["B"], "analysis": "招标工程量清单应由招标人或其委托的具有相应资质的工程造价咨询人编制，是招标文件的组成部分，是投标人报价的共同基础。", "tags": ["工程量清单", "招标"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g04-018", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "用于编制施工图预算的主要定额依据是（ ）。", "options": {"A": "施工定额", "B": "预算定额", "C": "概算定额", "D": "投资估算指标"}, "answer": ["B"], "analysis": "预算定额是编制施工图预算的主要依据，也是编制概算定额和概算指标的基础。施工定额用于编制施工预算，概算定额用于编制设计概算，投资估算指标用于编制投资估算。", "tags": ["预算定额", "编制用途"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g04-019", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "在计价依据体系中，以独立单项工程或完整项目为对象编制的是（ ）。", "options": {"A": "预算定额", "B": "概算定额", "C": "概算指标", "D": "投资估算指标"}, "answer": ["D"], "analysis": "投资估算指标以独立的单项工程或完整的工程项目为对象编制，综合程度最高。预算定额以分项工程为对象，概算定额以扩大分项工程为对象，概算指标以整个建筑物为对象。", "tags": ["投资估算指标", "计价依据"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g04-020", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "某分项工程的时间定额为0.25工日/单位，则其产量定额为（ ）单位/工日。", "options": {"A": "0.25", "B": "1", "C": "4", "D": "8"}, "answer": ["C"], "analysis": "产量定额=1/时间定额=1/0.25=4单位/工日。时间定额与产量定额互为倒数关系。", "tags": ["劳动定额", "时间定额", "计算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g04-021", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "某分项工程材料净用量为100kg，损耗率为5%，则材料总消耗量为（ ）kg。", "options": {"A": "100", "B": "102", "C": "105", "D": "110"}, "answer": ["C"], "analysis": "材料总消耗量=净用量×(1+损耗率)=100×(1+5%)=105kg。注意损耗量=净用量×损耗率=5kg，总消耗量=100+5=105kg。", "tags": ["材料消耗", "损耗率", "计算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g04-022", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "BIM技术在工程造价管理中的应用流程通常为（ ）。", "options": {"A": "组价→自动算量→造价分析→模型", "B": "模型→自动算量→组价→造价分析", "C": "造价分析→模型→自动算量→组价", "D": "自动算量→组价→模型→造价分析"}, "answer": ["B"], "analysis": "BIM技术应用流程：建立三维信息模型→基于模型自动算量→工程量清单组价→造价分析与控制。模型是基础，算量是核心环节。", "tags": ["BIM", "造价管理"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g04-024", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "在定额体系中，以工序为对象编制的定额是（ ）。", "options": {"A": "施工定额", "B": "预算定额", "C": "概算定额", "D": "概算指标"}, "answer": ["A"], "analysis": "施工定额以同一性质的施工过程——工序为对象编制，属于企业内部定额，是编制预算定额的基础。施工定额由劳动定额、材料消耗定额和机械台班定额三部分组成。", "tags": ["施工定额", "定额体系"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g04-027", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "施工单位进行成本控制和编制施工作业计划的依据是（ ）。", "options": {"A": "预算定额", "B": "施工定额", "C": "概算定额", "D": "投资估算指标"}, "answer": ["B"], "analysis": "施工定额是施工企业内部使用的定额，是施工单位编制施工作业计划、签发施工任务单、进行成本控制和考核的依据。预算定额主要用于编制施工图预算。", "tags": ["施工定额", "成本控制"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g04-028", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "在计价依据体系中，综合程度最高、精确程度最低的定额是（ ）。", "options": {"A": "施工定额", "B": "预算定额", "C": "概算指标", "D": "投资估算指标"}, "answer": ["D"], "analysis": "在定额体系中，从施工定额→预算定额→概算定额→概算指标→投资估算指标，综合程度逐步提高，精确程度逐步降低。投资估算指标以独立单项或完整项目为对象，综合程度最高。", "tags": ["定额体系", "综合程度"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g04-029", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "广东省建筑安装工程费用定额中，二类企业管理费费率为（ ）。", "options": {"A": "20.13%", "B": "23.59%", "C": "25.82%", "D": "26.50%"}, "answer": ["B"], "analysis": "广东省企业管理费费率：一类25.82%、二类23.59%、三类20.13%。此题考查对广东特色费率数据的准确记忆。", "tags": ["企业管理费率", "广东省"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g04-030", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "材料损耗率为3%，材料净用量为200kg，则材料损耗量为（ ）kg。", "options": {"A": "3", "B": "6", "C": "9", "D": "12"}, "answer": ["B"], "analysis": "材料损耗量=材料净用量×损耗率=200×3%=6kg。总消耗量=200+6=206kg=200×(1+3%)。", "tags": ["材料消耗", "损耗率", "计算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g04-031", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "定额计价法与工程量清单计价法的主要区别在于（ ）。", "options": {"A": "是否包含利润", "B": "计价基础和定价方式不同", "C": "是否包含税金", "D": "是否使用定额"}, "answer": ["B"], "analysis": "定额计价法以预算定额为基础，采用政府指导价；工程量清单计价法以GB/T 50500规范为基础，采用综合单价，由市场形成价格。两者的核心区别在于计价基础和定价方式的不同。", "tags": ["计价方法", "定额计价", "清单计价"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g04-032", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "工程量清单计价规范（GB/T 50500-2024）规定，综合单价的风险费用应（ ）。", "options": {"A": "单独列项计算", "B": "包含在综合单价中", "C": "由招标人单列", "D": "由监理确定"}, "answer": ["B"], "analysis": "综合单价包含一定范围内的风险费用，这是综合单价的组成部分之一。材料价格波动、施工条件变化等风险在约定范围内由承包人在综合单价中考虑。", "tags": ["综合单价", "风险费用"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g04-033", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "施工定额的水平应（ ）预算定额的水平。", "options": {"A": "低于", "B": "等于", "C": "高于", "D": "互不相关"}, "answer": ["C"], "analysis": "施工定额是施工企业内部使用的定额，其水平应高于预算定额（即更先进、更节约），以体现企业竞争力。施工定额是预算定额的编制基础。", "tags": ["施工定额", "定额水平"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g04-034", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "概算定额是在（ ）的基础上综合扩大编制的。", "options": {"A": "施工定额", "B": "预算定额", "C": "概算指标", "D": "投资估算指标"}, "answer": ["B"], "analysis": "概算定额是在预算定额的基础上综合扩大编制的，以扩大的分项工程为对象。定额体系的内在逻辑是：施工定额→预算定额→概算定额→概算指标→投资估算指标，由细到粗逐级综合。", "tags": ["概算定额", "定额体系"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g04-035", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "费用定额中，施工企业管理费的计费基数在广东省的独特之处是（ ）。", "options": {"A": "以直接费为基数", "B": "以人工费为基数", "C": "以人工费+施工机具使用费为基数", "D": "以分部分项工程费为基数"}, "answer": ["C"], "analysis": "广东省企业管理费以人工费+施工机具使用费为计算基数，这是广东省的计价特色，不同于全国其他地区以直接费或人工费为基数的做法。", "tags": ["费用定额", "广东省特色"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-001", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "根据GB/T 50500-2024《建设工程工程量清单计价规范》，工程量清单计价中综合单价包含的内容是（ ）。", "options": {"A": "人工费+材料费+施工机具使用费+企业管理费+利润", "B": "人工费+材料费+施工机具使用费+企业管理费+利润+增值税", "C": "人工费+材料费+施工机具使用费+企业管理费+利润+风险费用", "D": "人工费+材料费+施工机具使用费+增值税"}, "answer": ["C"], "analysis": "综合单价=人工费+材料费+施工机具使用费+企业管理费+利润+一定范围内的风险费用。增值税在综合单价之外单独列项。", "tags": ["计价方法", "综合单价"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-002", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "关于定额计价与工程量清单计价的对比，下列说法正确的是（ ）。", "options": {"A": "定额计价采用综合单价，清单计价采用工料单价", "B": "定额计价中工程量由投标人计算，清单计价中工程量由招标人提供", "C": "定额计价反映社会平均水平，清单计价反映企业个别水平", "D": "定额计价基于GB/T 50500规范，清单计价基于地方定额"}, "answer": ["C"], "analysis": "定额计价反映社会平均水平，清单计价允许企业自主报价反映个别水平。A错误（定额计价用工料单价，清单计价用综合单价）；B说反了；D定额计价基于定额体系而非GB/T 50500。", "tags": ["计价方法", "定额计价vs清单计价"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-003", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "在工程量清单计价模式下，招标工程量清单中分部分项工程量的准确性和完整性应由（ ）负责。", "options": {"A": "投标人", "B": "招标人", "C": "造价咨询单位", "D": "评标委员会"}, "answer": ["B"], "analysis": "工程量清单计价模式下，招标人负责提供工程量清单并对工程量的准确性和完整性负责，投标人依据清单自主报价。", "tags": ["计价方法", "清单计价"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-004", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "定额计价方式下，计算工程造价的基本顺序是（ ）。", "options": {"A": "工程量计算→套定额→计算直接费→取费→汇总造价", "B": "套定额→工程量计算→取费→计算直接费→汇总造价", "C": "取费→工程量计算→套定额→计算直接费→汇总造价", "D": "计算直接费→工程量计算→套定额→取费→汇总造价"}, "answer": ["A"], "analysis": "定额计价的基本程序：先计算工程量，再套用预算定额单价计算直接费，然后按规定取费（管理费、利润、规费、税金），最后汇总得出工程造价。", "tags": ["计价方法", "定额计价"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-005", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "关于工程量清单计价，下列说法错误的是（ ）。", "options": {"A": "综合单价中已包含一定范围内的风险费用", "B": "增值税在综合单价中单独列项计算", "C": "安全文明施工费属于不可竞争费用", "D": "投标人可以根据企业定额自主确定综合单价"}, "answer": ["B"], "analysis": "增值税不属于综合单价的组成部分，应在综合单价之外单独列项。安全文明施工费属于不可竞争费用，投标人不得随意下浮。", "tags": ["计价方法", "清单计价"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-006", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "我国工程计价依据体系由低到高共分为五级，最基础的一级是（ ）。", "options": {"A": "预算定额", "B": "概算定额", "C": "施工定额", "D": "投资估算指标"}, "answer": ["C"], "analysis": "五级计价体系从低到高为：施工定额→预算定额→概算定额→概算指标→投资估算指标。施工定额是最基础的定额。", "tags": ["计价依据体系", "五级体系"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-007", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "在五级计价依据体系中，编制对象为“扩大的分项工程”的是（ ）。", "options": {"A": "施工定额", "B": "预算定额", "C": "概算定额", "D": "概算指标"}, "answer": ["C"], "analysis": "概算定额的编制对象是扩大的分项工程（或扩大结构构件）。施工定额对象是工序，预算定额对象是分项工程，概算指标对象是整个建筑物或构筑物，投资估算指标对象是独立的单项工程或完整的工程项目。", "tags": ["计价依据体系", "概算定额"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-008", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "施工定额的水平是（ ），而预算定额的水平是（ ）。", "options": {"A": "社会平均水平；平均先进水平", "B": "平均先进水平；社会平均水平", "C": "先进水平；社会先进水平", "D": "社会平均水平；社会平均水平"}, "answer": ["B"], "analysis": "施工定额反映平均先进水平（高于社会平均水平），用于企业内部管理和编制施工预算。预算定额反映社会平均水平，用于编制施工图预算。", "tags": ["计价依据体系", "定额水平"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-009", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "在计价依据体系中，编制对象为整个建筑物或构筑物、以“元/㎡”或”元/m³”表示的定额是（ ）。", "options": {"A": "预算定额", "B": "概算定额", "C": "概算指标", "D": "投资估算指标"}, "answer": ["C"], "analysis": "概算指标的对象是整个建筑物或构筑物，以建筑面积（元/㎡）或建筑体积（元/m³）表示。投资估算指标的对象更宏观，以独立单项工程或完整工程项目为对象。", "tags": ["计价依据体系", "概算指标"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-010", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "施工定额主要用于（ ）的编制。", "options": {"A": "投资估算", "B": "设计概算", "C": "施工图预算", "D": "施工预算"}, "answer": ["D"], "analysis": "施工定额是施工企业内部使用的定额，主要用于编制施工预算、签发施工任务单和限额领料单。预算定额用于施工图预算，概算定额/指标用于设计概算，投资估算指标用于投资估算。", "tags": ["计价依据体系", "施工定额"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-011", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "可以作为编制施工图预算主要依据的定额是（ ）。", "options": {"A": "施工定额", "B": "预算定额", "C": "概算定额", "D": "投资估算指标"}, "answer": ["B"], "analysis": "预算定额是编制施工图预算、确定建筑安装工程造价的主要依据，也是编制概算定额的基础。", "tags": ["计价依据体系", "预算定额"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-012", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "在五级计价依据体系中，编制项目建议书阶段投资估算应主要依据（ ）。", "options": {"A": "预算定额", "B": "概算定额", "C": "概算指标", "D": "投资估算指标"}, "answer": ["D"], "analysis": "投资估算指标用于项目建议书和可行性研究阶段的投资估算编制。其对象为独立的单项工程或完整的工程项目，编制深度较浅，精度较低。", "tags": ["计价依据体系", "投资估算指标"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-013", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "关于五级计价依据体系，下列说法正确的是（ ）。", "options": {"A": "施工定额的水平高于预算定额的水平", "B": "概算定额的对象小于预算定额的对象", "C": "投资估算指标的精度高于概算指标", "D": "预算定额用于编制设计概算"}, "answer": ["A"], "analysis": "施工定额是平均先进水平，预算定额是社会平均水平，前者高于后者。B错误：概算定额对象是扩大分项工程，大于预算定额的分项工程。C错误：投资估算指标精度低于概算指标。D错误：预算定额用于施工图预算。", "tags": ["计价依据体系", "综合辨析"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-014", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "预算定额是以（ ）为基础，经综合扩大编制而成的。", "options": {"A": "施工定额", "B": "概算定额", "C": "概算指标", "D": "投资估算指标"}, "answer": ["A"], "analysis": "预算定额是在施工定额的基础上，经综合扩大编制而成的。同样，概算定额在预算定额基础上编制。", "tags": ["计价依据体系", "定额编制"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-015", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "施工定额中，某工序的时间定额为0.4工日/m³，则该工序的产量定额为（ ）m³/工日。", "options": {"A": "0.4", "B": "1.0", "C": "2.5", "D": "4.0"}, "answer": ["C"], "analysis": "时间定额与产量定额互为倒数：产量定额=1/时间定额=1/0.4=2.5m³/工日。", "tags": ["劳动定额", "时间定额×产量定额=1"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-016", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "某分项工程的产量定额为5m²/工日，则该工程的时间定额为（ ）工日/m²。", "options": {"A": "0.1", "B": "0.2", "C": "0.5", "D": "5.0"}, "answer": ["B"], "analysis": "时间定额=1/产量定额=1/5=0.2工日/m²。", "tags": ["劳动定额", "时间定额×产量定额=1"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-017", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "某砌筑工程，砌筑1m³砖墙的净用砖量为512块，砖的损耗率为2%，则每m³砖墙的砖消耗量为（ ）块。", "options": {"A": "512", "B": "522.24", "C": "524.48", "D": "532.48"}, "answer": ["B"], "analysis": "材料总用量=净用量×(1+损耗率)=512×(1+2%)=512×1.02=522.24块。", "tags": ["材料消耗", "损耗率计算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-018", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "已知某材料净用量为100kg，损耗量为3kg，则该材料的损耗率为（ ）。", "options": {"A": "2.91%", "B": "3.00%", "C": "3.09%", "D": "3.33%"}, "answer": ["B"], "analysis": "损耗率=损耗量/净用量×100%=3/100×100%=3%。注意：损耗率以净用量为基数，不是以总用量为基数。", "tags": ["材料消耗", "损耗率计算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-019", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "某材料总用量为106kg，损耗率为6%，则该材料的净用量为（ ）kg。", "options": {"A": "94", "B": "99.64", "C": "100", "D": "112.36"}, "answer": ["C"], "analysis": "总用量=净用量×(1+损耗率)，即净用量=总用量/(1+损耗率)=106/(1+6%)=106/1.06=100kg。", "tags": ["材料消耗", "损耗率计算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-020", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "一台施工机械的台班产量定额为80m³/台班，则完成480m³的工程量需要（ ）个台班。", "options": {"A": "4", "B": "6", "C": "8", "D": "10"}, "answer": ["B"], "analysis": "所需台班数=工程量/台班产量定额=480/80=6个台班。一个台班=8小时。", "tags": ["机械定额", "台班计算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-021", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "某分项工程的时间定额为0.05工日/㎡，现有一名工人工作8小时，理论上可完成的工程量为（ ）㎡。", "options": {"A": "15", "B": "20", "C": "25", "D": "40"}, "answer": ["B"], "analysis": "8小时=1工日。产量定额=1/时间定额=1/0.05=20㎡/工日，即1工日可完成20㎡。", "tags": ["劳动定额", "时间定额×产量定额=1"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-022", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "以下关于材料消耗定额的表述中，正确的是（ ）。", "options": {"A": "材料消耗量=材料净用量-材料损耗量", "B": "材料损耗率=损耗量/总用量×100%", "C": "材料总消耗量=材料净用量×(1+损耗率)", "D": "施工定额中的材料消耗不含场内运输损耗"}, "answer": ["C"], "analysis": "C正确。A错误：消耗量=净用量+损耗量。B错误：损耗率=损耗量/净用量。D错误：施工定额中材料消耗量已包含场内运输和施工操作损耗。", "tags": ["材料消耗", "概念辨析"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-023", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "某混凝土工程，每m³混凝土的水泥净用量为350kg，水泥损耗率为1.5%，则水泥消耗定额为（ ）kg/m³。", "options": {"A": "350.00", "B": "352.50", "C": "355.25", "D": "357.14"}, "answer": ["C"], "analysis": "消耗定额=净用量×(1+损耗率)=350×(1+1.5%)=350×1.015=355.25kg/m³。", "tags": ["材料消耗", "损耗率计算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-024", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "对于劳动定额中的时间定额与产量定额，以下关系正确的是（ ）。", "options": {"A": "时间定额与产量定额成正比关系", "B": "时间定额减少时，产量定额也减少", "C": "时间定额×产量定额=1", "D": "时间定额+产量定额=1"}, "answer": ["C"], "analysis": "时间定额（工日/单位产品）与产量定额（产品/工日）互为倒数关系，即时间定额×产量定额=1。不是正比或相加关系。", "tags": ["劳动定额", "概念辨析"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-025", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "某施工机械1小时正常生产率为20m³，该机械的台班产量定额为（ ）m³/台班。", "options": {"A": "20", "B": "80", "C": "120", "D": "160"}, "answer": ["D"], "analysis": "1台班=8小时，机械台班产量定额=20m³/h×8h=160m³/台班。机械时间定额=1/160=0.00625台班/m³。", "tags": ["机械定额", "台班计算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-026", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "某施工机械的台班产量定额为200m³/台班，机械时间定额的数值应为（ ）台班/m³。", "options": {"A": "0.002", "B": "0.005", "C": "0.02", "D": "200"}, "answer": ["B"], "analysis": "机械时间定额=1/台班产量定额=1/200=0.005台班/m³。", "tags": ["机械定额", "时间定额×产量定额=1"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-027", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "预算定额中的人工消耗指标包括基本用工、辅助用工、超运距用工和（ ）。", "options": {"A": "管理用工", "B": "停工用工", "C": "人工幅度差", "D": "特殊用工"}, "answer": ["C"], "analysis": "预算定额人工消耗量=基本用工+辅助用工+超运距用工+人工幅度差。人工幅度差是预算定额与施工定额人工消耗量的主要差异。", "tags": ["预算定额消耗量", "人工组成"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-028", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "预算定额中的人工幅度差一般是按（ ）的一定比例计算的。", "options": {"A": "基本用工", "B": "辅助用工", "C": "基本用工+辅助用工+超运距用工", "D": "基本用工+辅助用工"}, "answer": ["C"], "analysis": "人工幅度差=(基本用工+辅助用工+超运距用工)×人工幅度差系数，一般取10%～15%，常考10%。", "tags": ["预算定额消耗量", "人工幅度差"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-029", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "某预算定额中，基本用工为12工日，辅助用工为3工日，超运距用工为2工日，人工幅度差系数取10%，则该定额人工消耗量为（ ）工日。", "options": {"A": "17.0", "B": "18.2", "C": "18.7", "D": "19.8"}, "answer": ["C"], "analysis": "人工幅度差=(12+3+2)×10%=1.7工日。定额人工消耗量=12+3+2+1.7=18.7工日。", "tags": ["预算定额消耗量", "人工幅度差"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-030", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "关于预算定额与施工定额的关系，下列说法正确的是（ ）。", "options": {"A": "预算定额的人工消耗量等于施工定额的人工消耗量", "B": "预算定额的人工消耗量小于施工定额的人工消耗量", "C": "预算定额比施工定额多计入了人工幅度差", "D": "施工定额比预算定额多计入了超运距用工"}, "answer": ["C"], "analysis": "预算定额在施工定额基础上综合扩大，增加人工幅度差等。预算定额人工消耗量大于施工定额。施工定额不含人工幅度差。", "tags": ["预算定额消耗量", "定额关系"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-031", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "预算定额的编制过程中，超运距用工是指（ ）的用工。", "options": {"A": "超过劳动定额规定运距的材料运输", "B": "超过施工定额规定运距的材料运输", "C": "超过施工现场到卸货地点的运输", "D": "超过供应商到现场仓库的运输"}, "answer": ["B"], "analysis": "超运距用工是指预算定额中材料水平运距超过施工定额规定运距时增加的运输用工。", "tags": ["预算定额消耗量", "超运距用工"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-032", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "预算定额中的材料消耗量由（ ）两部分组成。", "options": {"A": "主要材料+辅助材料", "B": "净用量+损耗量", "C": "施工用量+运输损耗", "D": "实体消耗+措施消耗"}, "answer": ["B"], "analysis": "预算定额中材料消耗量=材料净用量+材料损耗量。损耗量包括场内运输损耗和施工操作损耗。", "tags": ["预算定额消耗量", "材料消耗"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-033", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "预算定额人工消耗量中，人工幅度差系数通常取值为（ ）。", "options": {"A": "5%", "B": "10%", "C": "15%", "D": "20%"}, "answer": ["B"], "analysis": "人工幅度差系数一般取10%～15%，其中10%为常用标准取值。", "tags": ["预算定额消耗量", "人工幅度差"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-034", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "下列费用中，不属于人工日工资单价组成内容的是（ ）。", "options": {"A": "计时工资或计件工资", "B": "奖金和津贴补贴", "C": "职工教育经费", "D": "特殊情况下支付的工资"}, "answer": ["C"], "analysis": "人工单价由5部分组成：计时/计件工资、奖金、津贴补贴、加班加点工资、特殊情况下支付的工资。职工教育经费属于企业管理费。", "tags": ["人工单价", "组成内容"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-035", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "根据现行规定，人工单价中“特殊情况下支付的工资”不包括（ ）。", "options": {"A": "工伤期间的工资", "B": "婚丧假期间的工资", "C": "探亲假期间的工资", "D": "高温补贴"}, "answer": ["D"], "analysis": "特殊情况下支付的工资包括因病、工伤、产假、计划生育假、婚丧假、事假、探亲假、定期休假、停工学习等支付的工资。高温补贴属于津贴补贴类。", "tags": ["人工单价", "组成内容"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-036", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "人工单价组成中，属于“津贴补贴”的是（ ）。", "options": {"A": "年终奖", "B": "高温津贴", "C": "加班工资", "D": "基本工资"}, "answer": ["B"], "analysis": "津贴补贴包括流动施工津贴、高温（寒）作业津贴、高空津贴等。年终奖属于奖金，加班工资和基本工资均为独立组成项目。", "tags": ["人工单价", "津贴补贴"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-037", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "材料预算单价由材料原价、运杂费、运输损耗费和（ ）组成。", "options": {"A": "监理费", "B": "采购及保管费", "C": "财务费用", "D": "利润"}, "answer": ["B"], "analysis": "材料单价=(材料原价+运杂费)×(1+运输损耗率)×(1+采购保管费率)。采购及保管费率一般取1%～2%。", "tags": ["材料单价", "组成内容"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-038", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "某材料原价为2000元/t，运杂费为100元/t，运输损耗率为2%，采购保管费率为1.5%，则该材料的预算单价为（ ）元/t。", "options": {"A": "2142.00", "B": "2167.83", "C": "2174.13", "D": "2200.00"}, "answer": ["C"], "analysis": "材料单价=(2000+100)×(1+2%)×(1+1.5%)=2100×1.02×1.015=2174.13元/t。", "tags": ["材料单价", "计算题"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-039", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "采购及保管费的费率通常为（ ）。", "options": {"A": "0.5%～1%", "B": "1%～2%", "C": "2%～3%", "D": "3%～5%"}, "answer": ["B"], "analysis": "采购及保管费率一般取1%～2%，包括采购费、仓储费、工地保管费和仓储损耗等。", "tags": ["材料单价", "采保费率"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-040", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "施工机具台班单价组成中，不包括（ ）。", "options": {"A": "折旧费", "B": "大修理费", "C": "安装拆卸费及场外运费", "D": "机械操作人员培训费"}, "answer": ["D"], "analysis": "机具台班单价由折旧费、大修理费、经常修理费、安拆费及场外运费、人工费（机上司机等）、燃料动力费、税费等组成。培训费属于企业管理费。", "tags": ["机具台班单价", "组成内容"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-041", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "下列费用中属于施工机具台班单价中“经常修理费”的是（ ）。", "options": {"A": "机械大修费用", "B": "各级保养和临时故障排除费用", "C": "替换设备及工具附具费", "D": "机械停滞期间的维护费"}, "answer": ["B"], "analysis": "经常修理费指施工机械除大修理外的各级保养和临时故障排除所需费用。A为大修理费，C和D属于企业管理费中的固定资产使用费或不属于台班单价。", "tags": ["机具台班单价", "经常修理费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-042", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "在广东省建设工程计价中，企业管理费的计算基数一般采用（ ）。", "options": {"A": "直接工程费", "B": "人工费+施工机具使用费", "C": "人工费", "D": "直接费+间接费"}, "answer": ["B"], "analysis": "企业管理费计算基数有三种：直接费、人工费+施工机具使用费（广东采用方案）、人工费。不同专业工程选用不同基数。", "tags": ["费用定额", "企业管理费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-043", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "企业管理费率的计算基数不包括（ ）。", "options": {"A": "直接费", "B": "人工费+施工机具使用费", "C": "人工费", "D": "材料费"}, "answer": ["D"], "analysis": "企业管理费率的三种计算基数：①直接费为基数；②人工费+施工机具使用费为基数（广东方案）；③人工费为基数。材料费不作为单独基数。", "tags": ["费用定额", "企业管理费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-044", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "社会保险费中，企业为职工缴纳的养老保险费比例一般为（ ）。", "options": {"A": "8%", "B": "12%", "C": "16%", "D": "20%"}, "answer": ["C"], "analysis": "规费中五险的费率：养老保险16%、医疗保险6.5%、失业保险0.5%、工伤保险和生育保险按行业确定。", "tags": ["费用定额", "规费", "社保"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-047", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "社会保险费中医疗保险的企业缴费比例一般为（ ）。", "options": {"A": "3%", "B": "5%", "C": "6.5%", "D": "10%"}, "answer": ["C"], "analysis": "医疗保险企业缴费比例一般为6.5%（含生育保险时约为6.5%～7%）。", "tags": ["费用定额", "规费", "社保"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-048", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "按费用构成要素划分，建筑安装工程费中的规费不包括（ ）。", "options": {"A": "社会保险费", "B": "住房公积金", "C": "工程排污费", "D": "企业管理费"}, "answer": ["D"], "analysis": "规费包括社会保险费(五险)、住房公积金和工程排污费。注意24清单下规费已并入人工费，但本题考核的是规费的传统组成内容。企业管理费不属于规费。", "tags": ["费用定额", "规费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-049", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "社会保险费中失业保险的企业缴费比例一般为（ ）。", "options": {"A": "0.2%", "B": "0.5%", "C": "1.0%", "D": "2.0%"}, "answer": ["B"], "analysis": "失业保险企业缴费比例一般为0.5%。五险费率：养老16%、医疗6.5%、失业0.5%、工伤和生育按行业确定。", "tags": ["费用定额", "规费", "社保"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-050", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "利润的计算基数通常采用的方案是（ ）。", "options": {"A": "以直接费为基数", "B": "以人工费+施工机具使用费为基数", "C": "以人工费为基数", "D": "以上三种均可，根据不同专业选定"}, "answer": ["D"], "analysis": "利润的计算基数与管理费的计算基数一致，可根据不同专业工程选择直接费、人工费+施工机具使用费或人工费三种方案之一。", "tags": ["费用定额", "利润"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-051", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "BIM 5D 中的“5D”是指在传统3D模型的基础上增加了（ ）两个维度。", "options": {"A": "质量和安全", "B": "时间和成本", "C": "进度和资源", "D": "环境和能耗"}, "answer": ["B"], "analysis": "BIM 5D=3D模型+时间维度（进度）+成本维度。BIM 3D是空间模型，BIM 4D加时间，BIM 5D再加成本。", "tags": ["BIM", "BIM 5D"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-052", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "工程造价指数按对比基期不同，可分为（ ）。", "options": {"A": "个体指数和总指数", "B": "数量指标指数和质量指标指数", "C": "定基指数和环比指数", "D": "综合指数和平均指数"}, "answer": ["C"], "analysis": "按对比基期不同，造价指数分为定基指数（各期与某一固定基期对比）和环比指数（各期与上一期对比）。", "tags": ["造价信息", "造价指数"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-053", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "建筑信息模型（BIM）在造价管理中的核心价值在于（ ）。", "options": {"A": "仅用于建筑外观设计", "B": "实现工程量的自动计算和造价的动态管理", "C": "完全替代传统人工造价管理", "D": "仅用于竣工结算阶段"}, "answer": ["B"], "analysis": "BIM在造价管理中可实现工程量自动计算、碰撞检查、5D成本动态管理、变更管理等全生命周期应用。", "tags": ["BIM", "造价管理"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-054", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "以下关于造价指数的说法，正确的是（ ）。", "options": {"A": "定基指数是以相邻上一期为基期计算的指数", "B": "环比指数是以某一固定时期为基期计算的指数", "C": "环比指数可以反映造价的短期变动趋势", "D": "定基指数不能用于长期趋势分析"}, "answer": ["C"], "analysis": "环比指数以相邻上一期为基期，反映短期变动趋势。A应为环比，B应为定基。定基指数以固定基期为准，可用于长期对比分析。", "tags": ["造价信息", "造价指数"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-055", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "在建筑工程造价信息管理中，BIM技术可以辅助实现的核心功能不包括（ ）。", "options": {"A": "工程量自动计算", "B": "进度-成本联动模拟", "C": "设计方案自动优化", "D": "碰撞检查与深化设计"}, "answer": ["C"], "analysis": "BIM可以辅助工程量计算、进度成本联动、碰撞检查等，但不能“自动”优化设计方案，设计优化仍需人工决策。", "tags": ["BIM", "造价信息"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-056", "date": "2026-07-08", "chapter": "g04", "type": "single", "stem": "下列可作为企业定额使用的是（ ）。", "options": {"A": "预算定额", "B": "概算定额", "C": "施工定额", "D": "概算指标"}, "answer": ["C"], "analysis": "施工定额是企业内部使用的定额，反映企业平均先进水平，也称为企业定额。预算定额是地区性计价定额。", "tags": ["计价依据体系", "施工定额"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "ht_mgmt_1016", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "下面所列工程建设定额中，属于按定额编制程序和用途分类的是（）。", "options": {"A": "机械台班消耗定额", "B": "行业通用定额", "C": "投资估算指标", "D": "补充定额"}, "answer": ["C"], "analysis": "按定额的用途可以把工程定额分为施工定额、预算定额、概算定额、概算指标、投资估算指标等五种。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1017", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "下列工程计价的标准和依据中，适用于项目建设前期各阶段对建设投资进行预测和估计的是（）。", "options": {"A": "工程量清单计价规范", "B": "工程定额", "C": "工程量清单计量规范", "D": "工程承包合同文件"}, "answer": ["B"], "analysis": "从目前我国现状来看，工程定额主要用于在项目建设前期各个阶段对于建设投资的预测和估计，在工程建设交易阶段，工程定额通常只能作为建设产品价格形成的辅助依据。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1018", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "该工程定额是在项目建议书和可行性研究阶段编制投资估算、计算投资需要量时使用的一种定额，往往以独立的单项工程或完整的工程项目为计算对象，编制内容是所有项目费用之和，其编制基础仍然离不开、。此工程定额是（）。", "options": {"A": "预算定额", "B": "概算定额", "C": "概算指标", "D": "投资估算指标"}, "answer": ["D"], "analysis": "这是投资估算指标的定义。因此，本题应选D。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1019", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "工程量清单计价模式下，企业定额是编制()的依据。", "options": {"A": "招标控制价", "B": "招标文件", "C": "投标报价", "D": "清单工程量"}, "answer": ["C"], "analysis": "本题考查的是企业定额的作用。原文是：在工程量清单计价方式下，企业定额作为施工企业进行建设工程投标报价的计价依据，正发挥着越来越大的作用。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1020", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "作为工程定额体系的重要组成部分，预算定额是( )。", "options": {"A": "完成一定计价单位的某一施工过程所需要消耗的人工、材料和机械台班数量标准", "B": "完成一定计量单位合格分项工程和结构构件所需消耗的人工、材料、施工机械台班数量及其费用标准", "C": "完成单位合格扩大分项工程所需消耗的人工、材料和施工机械台班数量及费用标准", "D": "完成一个规定计量单位建筑安装产品的费用消耗标准"}, "answer": ["B"], "analysis": "预算定额在正常的施工条件下，完成一定计量单位合格分项工程和结构构件所需消耗的人工、材料、施工机械台班数量及其费用标准。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1021", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "依法必须采用工程量清单招标的建设项目，投标人需要采用而招标人不需采用的计价依据是（）。", "options": {"A": "国家、地区或行业定额资料", "B": "工程造价信息、资料和指数", "C": "计价活动相关规章规程", "D": "企业定额"}, "answer": ["D"], "analysis": "A、B、C：国家 / 地区 / 行业定额、工程造价信息、计价规章规程，是招标人和投标人共同遵循的公共计价依据（招标人用于编制招标控制价，投标人用于参考组价）；D：企业定额是投标人根据自身技术、管理水平制定的内部计价标准，仅用于投标人自主报价，招标人无需采用。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1022", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "关于建设工程的分部组合计价，下列说法正确的是（）。", "options": {"A": "适用于没有具体图样和工程量清单的建设项目计价", "B": "要求将建设项目细分到最基本的构造单元", "C": "是利用产出函数进行计价", "D": "具有自上而下、由粗到细的计价组合特点"}, "answer": ["B"], "analysis": "工程造价计价的主要思路就是将建设项目细分至最基本的构造单元，找到了适当的计量单位及当时当地的单价，就可以采取一定的计价方法，进行分部组合汇总，计算出相应工程造价。工程计价的基本原理就在于项目的分解与组合.选项A错误，如果一个建设项目的设计方案已经确定，常用的是分部组合计价法。选项C错误，当一个建设项目还没有具体图样和工程量清单时，需要利用产出函数对建设项目投资进行匡算。选项D错误，工程计价是自下而上的分部组合计价。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1023", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "工程计价的基本原理表达式：分部分项工程费=∑[()×相应单价]。", "options": {"A": "基本构造单元工程量", "B": "分项工程量", "C": "单位清单工程量", "D": "检验批工程量"}, "answer": ["A"], "analysis": "工程计价的基本原理可以用公式的形式表达如下：分部分项工程费=∑[（基本构造单元工程量）×相应单价]。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1025", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "工程计量工作包括工程项目的划分和工程量的计算，下列关于工程计量工作的说法中正确的是（）。", "options": {"A": "项目划分须按预算定额规定的定额子项进行", "B": "通过项目划分确定单位工程基本构造单元", "C": "工程量的计算须按工程量清单计算规范的规则进行计算", "D": "工程量的计算应依据施工图设计文件，不应依据施工组织设计文件"}, "answer": ["B"], "analysis": "工程计量工作包括工程项目的划分和工程量的计算。单位工程基本构造单元的确定，即划分工程项目。编制工程概算预算时，主要是按工程定额进行项目的划分；编制工程量清单时主要是按照工程量清单计量规范规定的清单项目进行划分。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1026", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "下列属于按定额反映的生产要素消耗内容分类的是()。", "options": {"A": "劳动消耗定额", "B": "施工定额", "C": "预算定额", "D": "企业定额"}, "answer": ["A"], "analysis": "按定额反映的生产要素消耗内容分类的是劳动消耗定额、材料消耗定额、机械消耗定额。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1027", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "根据我国建设市场发展现状，工程量清单计价和计量规范主要适用于（）。", "options": {"A": "项目建设前期各阶段工程造价的估量", "B": "项目初步设计阶段概算的预测", "C": "项目施工图设计阶段预算的预测", "D": "项目合同价格的形式和后续合同价格的管理"}, "answer": ["D"], "analysis": "从目前我国现状来看，工程定额主要用于在项目建设前期各阶段对于建设投资的预测和估计，在工程建设交易阶段，工程定额通常只能作为建设产品价格形成的辅助依据。工程量清单计价依据主要适用于合同价格形成以及后续的合同价格管理阶段。 本题库是以官方教材为依据，知识点所对应的习题综合了二建法规、二建管理、造价员基础、一级造价师考试的题库+真题编辑，基本上做到了每个知识点都有相对应的题目及解析,题库会陆续更新,会有模拟题,预测题及考前更新押题。 《建设工程计量与计价实务》题库编辑中,教材出来后会陆续更新 www.jinkaodian.com 金考典考试软件。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1029", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "措施项目清单编制中，下列适用于以“项”为单位计价的措施项目费是()。", "options": {"A": "已完工程及设备保护费", "B": "超高施工增加费", "C": "大型机械设备进出场及安拆费", "D": "施工排水、降水费"}, "answer": ["A"], "analysis": "本题考查的是措施项目清单的编制。有些措施项目则是可以计算工程量的项目，如脚手架工程，混凝土模板及支架（撑），垂直运输，超高施工增加，大型机械设备进出场及安拆，施工排水降水等。不能计算工程量的项目清单，以“项”为计量单位进行编制。采用排除法，可选A。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1030", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "招标工程清单编制时，在总承包服务费计价表中，应由招标人填写的内容是()。", "options": {"A": "服务内容", "B": "项目价值", "C": "费率", "D": "金额"}, "answer": ["A"], "analysis": "本题考查的是总承包服务费的编制。表2.2.8 总承包服务费计价表 注：此表项目名称、服务内容由招标人填写。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1031", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "关于工程量清单中的计日工，下列说法中正确的是（）。", "options": {"A": "即指零星工作所消耗的人工工时", "B": "在投标时计入总价，其数量和单价由投标人填报", "C": "应按投标文件载明的数量和单价进行结算", "D": "在编制招标工程量清单时，暂定数量由招标人填写"}, "answer": ["D"], "analysis": "计日工表的项目名称、暂定数量由招标人填写，编制招标控制价时，单价由招标人按有关计价规定确定；投标时，单价由投标人自主报价，按暂定数量计算合价计入投标总价中。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1032", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "有关其他项目清单的表述，下列内容中正确的是()。", "options": {"A": "暂列金额能保证合同结算价格不会超过合同价格", "B": "投标人应将材料暂估单价计入工程量清单综合单价报价中", "C": "专业工程的暂估价一般应是综合暂估价，应当包括管理费、利润、规费、税金在内", "D": "计日工适用的所谓零星工作一般是指合同约定之内的因变更而产生的额外工作"}, "answer": ["B"], "analysis": "选项A错误，暂列金额是为了不可避免的价格调整而设立的；选项C错误，专业工程的暂估价一般应是综合暂估价，应当包括除规费、税金外的管理费、利润等取费；选项D错误，计日工适用的所谓零星工作一般是指合同约定之外的因变更而产生的额外工作。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1033", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "若清单计价规范中的项目名称有缺陷，则处理方法是()。", "options": {"A": "招标人作补充，并与投标人协商后执行", "B": "投标人作补充，并与招标人协商后执行", "C": "投标人作补充，并报当地工程造价管理机构（省级）备案", "D": "招标人作补充，并报当地工程造价管理机构（省级）备案"}, "answer": ["D"], "analysis": "计价规范中的分项工程项目名称如有缺陷，招标人可作补充，并报当地工程造价管理机构（省级）备案。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1034", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "下列费用项目中，应由投标人确定额度，并计入其他项目清单与计价汇总表中的是()。", "options": {"A": "暂列金额", "B": "材料暂估价", "C": "专业工程暂估价", "D": "总承包服务费"}, "answer": ["D"], "analysis": "暂列金额和暂估价由招标人确定，投标人应根据招标人列出的金额计入投标总价中。总承包服务费的费率及金额由投标人自主报价，计入投标总价中。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1036", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "在编制分部分项工程量清单时，通常无须描述的是()。", "options": {"A": "工程结构", "B": "使用材质", "C": "工作内容", "D": "安装位置"}, "answer": ["C"], "analysis": "分部分项工程量清单的项目特征应按各专业工程计量规范附录中规定的项目特征，结合技术规范、标准图集、施工图纸、按照工程结构、使用材质及规格或安装位置等，予以详细而准确的表述和说明。在各专业工程计量规范附录中的“工程内容”，在编制分部分项工程量清单时，通常无须描述。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1037", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "编制工程量清单出现计算规范附录中未包括的清单项目时，编制人应作补充，下列有关编制补充项目的说法中正确的是（）。", "options": {"A": "补充项目编码应由B与三位阿拉伯数字组成", "B": "补充项目应报县级工程造价管理机构备案", "C": "补充项目的工作内容应予以明确", "D": "补充项目编码应顺序编制，起始序号由编制人根据需要自主确定"}, "answer": ["C"], "analysis": "在编制工程量清单时，当出现计量规范附录中未包括的清单项目时，编制人应作补充。在工程量清单中应附补充项目的项目名称、项目特征、计量单位、工程量计算规则和工作内容。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1038", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "采用工程量清单计价方式招标时，对工程量清单的完整性和准确性负责的是()。", "options": {"A": "编制招标文件的招标代理人", "B": "编制清单的工程造价咨询人", "C": "发布招标文件的招标人", "D": "确定中标的投标人"}, "answer": ["C"], "analysis": "本题考查的是工程量清单计价的注意点。采用工程量清单方式招标，招标工程量清单必须作为招标文件的组成部分，其准确性和完整性由招标人负责。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1039", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "关于分部分项工程量清单编制的说法，正确的是()。", "options": {"A": "施工工程量大于按计算规则计算出的工程量的部分，由投标人在综合单价中考虑", "B": "在清单项目“工程内容”中包含的工作内容必须进行项目特征的描述", "C": "计价规范中就某一清单项目给出两个及以上计量单位时应选择最方便计算的单位", "D": "同一标段的工程量清单中含有多个项目特征相同的单位工程时，可采用相同的项目编码"}, "answer": ["A"], "analysis": "本题考查的是分部分项工程量清单的编制要求 所有清单项目的工程量应以实体工程量为准，并以完成后的净值计算；投标人投标报价时，应在单价中考虑施工中的各种损耗和需要增加的工程量。 在编制分部分项工程量清单时，工作内容通常无需描述。因此B错。原文是：当计量单位有两个或两个以上时，应根据所编工程量清单项目的特征要求，选择最适宜表现该项目特征并方便计量的单位；因此C错。原文是：当同一标段（或合同段）的一份工程量清单中含有多个单位工程且工程量清单是以单位工程为编制对象时，项目编码十至十二位的设置不得有重码，因此D错。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1040", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "除另有说明外，分部分项工程量清单表中的工程量应等于()。", "options": {"A": "实体工程量", "B": "实体工程量+施工损耗", "C": "实体工程量+施工需要增加的工程量", "D": "实体工程量+措施工程量"}, "answer": ["A"], "analysis": "本题考查的是工程数量的概念。除另有说明外，所有清单项目的工程量应以实体工程量为准，并以完成后的净值计算。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1042", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "在工程量清单的编制过程中，暂列金额通常是由()提供的。", "options": {"A": "监理人", "B": "招标人与投标人协商后", "C": "招标人", "D": "投标人"}, "answer": ["C"], "analysis": "暂列金额是由招标人提供的。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1043", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "分部分项工程量清单项目编码以五级编码设置，其中第四级编码为()。", "options": {"A": "工程分类顺序码", "B": "专业工程顺序码", "C": "分部工程顺序码", "D": "分项工程项目名称顺序码"}, "answer": ["D"], "analysis": "分部分项工程量清单项目编码以五级编码设置，用十二位阿拉伯数字表示。一、二、三、四级编码为全国统一，即一至九位应按计价规范附录的规定设置；第五级编码应根据拟建工程的工程量清单项目名称设置。各级编码代表的含义分别为：第一级表示工程分类顺序码（分二位）；第二级表示专业工程顺序码（分二位）；第三级表示分部工程顺序码（分二位）；第四级表示分项工程项目名称顺序码（分三位）；第五级表示工程量清单项目名称顺序码（分三位）。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1044", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "招标人在工程量清单中提供的用于支付宝必然发生但暂不能确定价格的材料、工程设备单价及专业工程金额是（）。", "options": {"A": "暂列金额", "B": "暂估价", "C": "总承包服务费", "D": "价差预备费"}, "answer": ["B"], "analysis": "暂估价是指招标人在工程量清单中提供的用于支付必然发生但暂时不能确定价格的材料、工程设备的单价及专业工程的金额，包括材料暂估单价、工程设备暂估单价和专业工程暂估价。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1045", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "下列措施项目中,适合采用综合单价方式计价的是（）。", "options": {"A": "已完工程及设备保护", "B": "二次搬运费", "C": "安全文明施工", "D": "混凝土、钢筋混凝土模板"}, "answer": ["D"], "analysis": "本题考核清单措施项目计价的两种方法。能明确计算工程量的可釆用综合单价报价,混凝土、钢筋混凝土模板费用可计算工程量，适合采用综合单价计价。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1046", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "根据《建设工程工程量清单计价规范》（GB50500—013）的规定，在合同约定之外的或者因变更而产生的、工程量清单中没有的且难以事先商定价格的额外工作，应计列入（）之中。", "options": {"A": "暂列金额", "B": "暂估价", "C": "计日工", "D": "措施项目费"}, "answer": ["C"], "analysis": "计日工对完成零星工作所消耗的人工工时、材料数量、施工机械台班进行计量，并按照计日工表中填报的适用项目的单价进行计价支付。零星工作一般是指合同约定之外的或者因变更而产生的、工程量清单中没有相应项目的额外工作，尤其是那些难以事先商定价格的额外工作", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1048", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "工程量清单计价模式下，在招投标阶段对尚未确定的某分部分项工程费，应列入（）中。", "options": {"A": "暂列金额", "B": "基本预备费", "C": "暂估价", "D": "工程建设其他费"}, "answer": ["A"], "analysis": "暂列金额是指招标人在工程量清单中暂定并包括在合同价款中的一笔款项。用于施工合同签订时尚 未确定或者不可预见的所需材料、设备、服务的采购，施工中可能发生的工程变更、合同约定调整因素出现时的工程价款调整以及发生的索赔、现场签证确认等的费用。 暂估价是指招标人在工程量清单中提供的用于支付必然发生但暂时不能确定价格的材料的单价以及专业工程的金额。将两者概念相比较，可以发现暂列金额选项更加符合题意。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1049", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "分部分项工程量清单项目的工程量应以实体工程量为准,对于施工中的各种损耗和需要增加的工程量，投标人投标报价时，应在（）中考虑。", "options": {"A": "措施项目", "B": "该清单项目的单价", "C": "其他项目清单", "D": "预留金"}, "answer": ["B"], "analysis": "本题考核分部分项工程量清单工程数量的计算。分部分项工程量清单项目的工程量应以实体工程量为准，并以完成后的净值计算;投标人投标报价时，应在单价中考虑施工中各种损耗和需要增加的工程量。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1050", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "若投标人对某个工程量清单项目的单价和合价未予填报，则（）。", "options": {"A": "招标人应及时通知投标人补充填报", "B": "表明投标人不负责该项任务", "C": "表明投标人认为该分项工程数量有误，需调整后再报价", "D": "视此项费用已在其他单价和合价中考虑"}, "answer": ["D"], "analysis": "这题考核工程量清单计价格式，其中列明的所有需要填报的单价和合价，投标人均应填报，未填报的单价和合价，视为此项费用已包含在工程量清单的其他单价和合价中。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1051", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "在编制措施项目清单时，关于混凝土模板及支架费项目，应在清单中列明()", "options": {"A": "项目编码", "B": "计算基础", "C": "取费费率", "D": "工作内容"}, "answer": ["A"], "analysis": "本题考查的是措施项目清单的编制。有些措施项目则是可以计算工程量的项目，如脚手架工程，混凝土模板及支架（撑），垂直运输，超高施工增加，大型机械设备进出场及安拆，施工排水降水等。这类措施项目按照分部分项工程量清单的方式采用综合单价计价，更有利于措施费的确定和调整。措施项目中可以计算工程量的项目（单价措施项目）宜采用分部分项工程项目清单的方式编制，列出项目编码、项目名称、项目特怔、计量单位和工程量（如表 2.2.1 所示 不能计算工程量的项目（总价措施项目），以“项”为计量单位进行编制（如表 2.2.2 所示 ) 本题库是以官方教材为依据，知识点所对应的习题综合了二建法规、二建管理、造价员基础、一级造价师考试的题库+真题编辑，基本上做到了每个知识点都有相对应的题目及解析,题库会陆续更新,会有模拟题,预测题及考前更新押题。 《建设工程计量与计价实务》题库编辑中,教材出来后会陆续更新 www.jinkaodian.com 金考典考试软件。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1052", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "对于招标人在招标文件中提供的用于支付必然发生但暂时不能确定价格的材料金额计()。", "options": {"A": "暂列金额", "B": "暂估价", "C": "计日工", "D": "专业工程暂估价"}, "answer": ["B"], "analysis": "暂估价是指招标阶段直至签订合同协议时，招标人在招标文件中提供的用于支付必然要发生但暂时不能确定价格的材料以及专业工程的金额。 本题库是以官方教材为依据，知识点所对应的习题综合了二建法规、二建管理、造价员基础、一级造价师考试的题库+真题编辑，基本上做到了每个知识点都有相对应的题目及解析,题库会陆续更新,会有模拟题,预测题及考前更新押题。 《建设工程计量与计价实务》题库编辑中,教材出来后会陆续更新 www.jinkaodian.com 金考典考试软件。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1053", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "在概算指标编制时，关于不同类型工程应选取的计算单位，下列说法中符合要求的是()。", "options": {"A": "安装工程以占设备购置费的百分比表示", "B": "建筑工程以综合生产能力的单位投资表示", "C": "构筑物以每m3的投资表示", "D": "建设项目以使用功能的单位投资表示"}, "answer": ["A"], "analysis": "(1)建筑工程的计算单位。房屋建筑、构筑物一般是以建筑面积、建筑体积、“座”、“个”等为计算单位。 (2)安装工程的计算单位。设备以“t”或“台”为计算单位，也可以是设备购置费或设备原价的百分比表示。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1054", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "概算定额与预算定额的差异主要表现在（）的不同。", "options": {"A": "项目划分", "B": "主要工程内容", "C": "主要表达方式", "D": "基本使用方法"}, "answer": ["A"], "analysis": "概算定额与预算定额的不同之处，在于项目划分和综合扩大程度上的差异，同时，概算定额主要用于设计概算的编制。由于概算定额综合了若干分项工程的预算定额 ， 因此，概算工程量计算和概算表的编制，都比编制施工图预算简化一些。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1055", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "下列用工项目中，属于预算定额与劳动定额人工幅度差的是（）。", "options": {"A": "施工机械辅助用工", "B": "超过预算定额取定运距增加的运输用工", "C": "班组操作地点转移用工", "D": "机械维修引起的操作人员停工"}, "answer": ["C"], "analysis": "预算定额中的人工幅度差包括工序搭接及交叉作业影响的停工、施工机械和临时水电路转移造成的停工、质量和隐蔽工程检查的影响、班组操作地点转移用工、对前一工序修复用工和其他零星用工。注意选项B不属于超运距用工，可另行计算二次搬运费。选项D 为干扰项，既不属于人工幅度差也不属于机械幅度差。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1056", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "在计算预算定额人工工日消耗量时，基本用工中除包括完成定额计量单位的主要用工外，还应包括（）。", "options": {"A": "劳动定额规定应增（减）计算的用工", "B": "劳动定额内不包括的材料加工用工", "C": "施工中不可避免的其他零星用工", "D": "质量检查和隐蔽"}, "answer": ["A"], "analysis": "基本用工中包括完成定额计量单位的主要用工和劳动定额规定应增（减）计算的用工。B 属于辅助用工，C、D 属于人工幅度差。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1057", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "下列用时中，同时包含在劳动定额和预算定额人工消耗量中的是（）。", "options": {"A": "隐蔽工程验收的影响时间", "B": "工序搭接发生的停歇时间", "C": "不可避免的中断时间", "D": "加工材料所需的时间"}, "answer": ["C"], "analysis": "此题本质考查的是人工幅度差,它是在劳动定额中未包括，在预算定额中要考虑的。D 属于辅助用工中材料加工时间，是劳动定额不考虑的。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1058", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "关于预算定额人工、材料、机械台班消耗量的计算和确认，下列说法中正确的是（）。", "options": {"A": "人工消耗中包含超出预算定额取定运距后的超运距用工", "B": "材料损耗量按照材料消耗量的一定比例计算", "C": "各种胶结、涂料等材料的配合比用料，按换算法计算", "D": "按小组产量计算机械台班产量时，机械幅度差系数取10%"}, "answer": ["C"], "analysis": "换算法是指各种胶结、涂料等材料的配合比用料，可以根据要求条件换算，得出材料用量。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1059", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "在预算定额的编制阶段，下列选项中不属于确定编制细则阶段内容的是（）", "options": {"A": "统一编制表格及编制方法", "B": "统一计算口径、计量单位和小数点位数", "C": "统一项目划分和工程量计算规则", "D": "统一名称、专业用语和符号代码"}, "answer": ["C"], "analysis": "本题考核预算定额编制阶段的主要工作。确定编制细则主要包括:统一编制表格及编制方法;统一计量口径、计量单位和小数点位数的要求;有关统一性规定，名称统一，用字统一，专业用语统一，符号代码统一，简化字要规范，文字要简练明确。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1060", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "在预算定额人工工日消耗量计算时，已知完成单位合格产品的基本用工为22 工日，超运距用工为4 工日，辅助用工为2 工日，人工幅度差系数为12%，则预算定额中的人工工日消耗量为（）工日。", "options": {"A": "3.36", "B": "25.36", "C": "28", "D": "31.36"}, "answer": ["D"], "analysis": "本题考核预算定额中人工工日消耗量的计算方法。预算定额中人工工日消耗量包括基本用工、其他用工两部分。其他用工由超运距用工、辅助用工和人工幅度差组成。 人工幅度差=(基本用工+辅助用工+超运距用工）×人工幅度差系数=(22+4+2)×l2%=3.36(工日） 人工工日消耗量=22+4+2+3.36=31.36(工日）", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1061", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "某挖土机挖土一次循环工作时间为50s，每次循环平均挖土量为0.5m3，机械正常利用系数为0.。机械幅度差系数为25%，按8 小时工作制考虑，挖土方预算定额的施工机具消耗量为（）台班/1000m3。", "options": {"A": "5.43", "B": "7.2", "C": "8", "D": "8.68"}, "answer": ["A"], "analysis": "本题考查预算定额中机械台班消耗量的计算。预算定额机械耗用台班=施工定额机械耗用台班×（1+机械幅度差系数），机械纯工作1h 循环次数=3600/50=72 次/台时）；机械纯工作1h 正常生产率=72×0.5=36（m3/小时）；施工机械台班产量定额=36×8×0.8=230.4（m3/台班）；施工机械台班时间定额=1/230.4=0.00434（台班/m3）；预算定额机械耗用台班=0.00434×（1+25%）=0.00543（台班/m3）；挖土方1000m3 的预算定额机械耗用台班量=1000 ×0.00543=5.43 台班）。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1062", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "在计算预算定额人工工日消耗量时，对于工种间的工序搭接及交叉作业相互配合影响所发生的停歇用工，应列入()。", "options": {"A": "辅助用工", "B": "人工幅度差", "C": "基本用工", "D": "超运距用工"}, "answer": ["B"], "analysis": "3) 人工幅度差。即预算定额与劳动定额的差额，主要是指在劳动定额中未包括而在正常施工情况下不可避免但又很难准确计量的用工和各种工时损失。内容包括：①各工种间的工序搭接及交叉作业相互配合或影响所发生的停歇用工；②施工 过程中，移动临时水电线路而造成的影响工人操作的財间③工程 质量检查和隐蔽工程验收工作而影响工人操作的时间；④同一 现场内单位工程之间因操作地点转移而影响工人操作的时间；⑤工序 交接时对前一工序不可避免的修整用工；⑥施工中不可避免的其他零星用工。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1063", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "完成某单位分部分项工程需要基本用工4.2工日，超运距用工0.3工日，辅助用工1工日，人工幅度差系数为10%，则该单位分部分项工程预算定额人工消耗量为（）工日。", "options": {"A": "5.92", "B": "5.95", "C": "6.02", "D": "6.05"}, "answer": ["D"], "analysis": "人工消耗量=（4.2+0.3+1）×（1+10%）=6.05（工日）。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1064", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "在计算预算定额人工工日消耗量时，包含在人工幅度差内的用工是（）。", "options": {"A": "超运距用工", "B": "材料加工用工", "C": "机械土方工程的配合用工", "D": "工种交叉作业相互影响的停歇用工"}, "answer": ["D"], "analysis": "人工幅度差内容包括： ①各工种间的工序搭接及交叉作业相互配合或影响所发生的停歇用工； ②施工过程中，移动临时水电线路而造成的影响工人操作的时间； ③工程质量检查和隐蔽工程验收工作而影响工人操作的时间； ④同一现场内单位工程之间因操作地点转移而影响工人操作的时间； ⑤工序交接时对前一工序不可避免的修整用工。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1065", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "下列工程项目总投资构成项中，应计入单项工程投资估算指标中的是()。", "options": {"A": "生产家具购置费", "B": "基本预备费", "C": "涨价预备费", "D": "铺底流动资金"}, "answer": ["A"], "analysis": "单项工程指标指按规定应列入能独立发挥生产能力或使用效益的单项工程内的全部投资额，包括建筑工程费、安装工程费、设备、工器具及生产家具购置费和可能包含的其他费用。 本题库是以官方教材为依据，知识点所对应的习题综合了二建法规、二建管理、造价员基础、一级造价师考试的题库+真题编辑，基本上做到了每个知识点都有相对应的题目及解析,题库会陆续更新,会有模拟题,预测题及考前更新押题。 《建设工程计量与计价实务》题库编辑中,教材出来后会陆续更新 www.jinkaodian.com 金考典考试软件。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1066", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "下列施工机械的停歇时间，不在预算定额机械幅度差中考虑的是（）。", "options": {"A": "机械维修引起的停歇", "B": "工程质量检查引起的停歇", "C": "机械转移工作面引起的停歇", "D": "进行准备与结束工作时引起的停歇"}, "answer": ["D"], "analysis": "机械幅度差内容包括：1)施工机械转移工作面及配套机械相互影响损失的时间；2)在正常施工条件下，机械在施工中不可避免的工序间歇。 本题库是以官方教材为依据，知识点所对应的习题综合了二建法规、二建管理、造价员基础、一级造价师考试的题库+真题编辑，基本上做到了每个知识点都有相对应的题目及解析,题库会陆续更新,会有模拟题,预测题及考前更新押题。 《建设工程计量与计价实务》题库编辑中,教材出来后会陆续更新 www.jinkaodian.com 金考典考试软件。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1067", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "下列工人工作时间消耗中，属于有效工作时间的是()。", "options": {"A": "因混凝土养护引起的停工时间", "B": "偶然停工（停水、停电）增加的时间", "C": "产品质量不合格返工的工作时间", "D": "准备施工工具花费的时间"}, "answer": ["D"], "analysis": "本题考查的是有效工作时间的内容有效工作时间是从生产效果来看与产品生产直接有关的时间消耗。其中，包括基本工作时间、辅助工作时间、准备与结束工作时间的消耗。原文是：准备与结束工作时间是执行任务前或任务完成后所消耗的工作时间。如工作地点、劳动工具和劳动对象的准备工作时间；工作结束后的整理工作时间等。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1068", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "通过计时观察，完成某工程的基本工时为6h/㎡，辅助工作时间为工序作业时间的8%。规范时间占工作时间的15%，则完成该工程的时间定额是()工日／㎡。", "options": {"A": "0.93", "B": "0.94", "C": "0.95", "D": "0.96"}, "answer": ["D"], "analysis": "本题考查的是时间定额的计算。工序作业时间=基本工作时间+辅助工作时间=基本工作时间/（1-辅助时间%） （2.3.5）；定额时间=工序作业时间/（1-规范时间%） （2.3.6）；因此基本工作时间=6h=0.75工日／㎡,工序作业时间=0.75/(1-8%)=0.82工日/㎡,时间定额=0.82/(1-15%)=0.96工日／㎡", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1069", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "砌筑一砖厚砖墙，灰缝厚度为10mm，砖的施工损耗率为1.5%，场外运输损耗率为1%。砖的规格为240mm×115mm×53mm，则每m3砖墙工程中砖的定额消耗量为()块。", "options": {"A": "515.56", "B": "520.64", "C": "537.04", "D": "542.33"}, "answer": ["C"], "analysis": "本题考查的是砖定额消耗量的计算。原文是：每立方米砖墙的用砖数和砌筑砂浆的用量，可用下列理论计算公式计算各自的净用量：用砖数： A=1/[墙厚×（砖长+灰缝）×（砖厚+灰缝）]×k (2.3.7);式中 k=墙厚的砖数×2。总损耗量=净用量+损耗量=净用量×（1+损耗率） （2.3.10）；所以砖净用量=1/[（0.24×(0.24+0.01)×(0.053+0.01)）]×1×2=529.100529100529（块）；砖的总消耗量=净用量×（1+损耗率）=529.100529100529×(1+1.5%)=537.04（块）", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1070", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "根据施工过程工时研究结果，与工人所担负的工作量大小无关的必须消耗时间是（）。", "options": {"A": "基本工作时间", "B": "辅助工作时间", "C": "准备与结束工作时间", "D": "多余工作时间"}, "answer": ["C"], "analysis": "准备与结束工作时间是执行任务前或任务完成后所消耗的工作时间。如工作地点、劳动工具和劳动对象的准备工作时间，工作结束后的整理工作时间等。准备和结束工作时间的长短与所担负的工作量大小无关，但往往和工作内容有关。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1071", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "某出料容量750L的混凝土搅拌机，每循环一次的正常延续时间为9min，机械正常利用系数为0.9.按8小时工作制考虑，该机械的台班产量定额为（）。", "options": {"A": "36m3/台班", "B": "40m3/台班", "C": "0.28台班/m3", "D": "0.25台班/m3"}, "answer": ["A"], "analysis": "该搅拌机纯工作1h循环次数=60/9=6.67（次）；该搅拌机纯工作1h正常生产率=6.67×750=5000（L）=5（m3）；该搅拌机台班产量定额=5×8×0.9=36（m3/台班）。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1072", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "运输汽车装载保温泡沫板，因体积大但重量不足而引起的汽车在降低负荷的情况下工作的时间属于机器工作时间消耗中的()。", "options": {"A": "有效工作时间", "B": "不可避免的无负荷工作时间", "C": "多余工作时间", "D": "低负荷下的工作时间"}, "answer": ["A"], "analysis": "机器工作时间中有两类时间容易混淆，即有根据降低负荷和低负荷下的工作时间。在个别情况下由于技术上的原因，机器在低于其计算负荷下工作就是有根据降低负荷时间，属于机器有效工作时间。低负荷下工作属于工人或技术人员的过错所造成的，属于机器的损失时间。本题中汽车装载之所以下降，在于保温泡沫板的体积过大造成的，而不是工人或技术人员有过失或过错造成的，因而是有根据降低负荷下的工作时间，属于有效工作时间。考生注意区分这两类时间。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1073", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "根据计时观察法测定某人工挖基坑二类土1m3的有关数据如下：基本工作时间180min，辅助工作时间占工序作业时间的百分比为10%，规范时间占工作日时间百分比为20%，则挖该基坑1m3的定额时间为()min。", "options": {"A": "243.0", "B": "247.5", "C": "250.0", "D": "257.1"}, "answer": ["C"], "analysis": "按照人工定额消耗量的构成，应先计算该工序作业时间，再计算定额时间。 工序作业时间=基本工作时间／（1-辅助工作时间%）=180／(1-10%)=200(min／m3) 定额时间=工序作业时间／（1-规范时间%）=200／(1-20%)=250(min／m3) 因此，正确答案为C。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1074", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "确定材料消耗量时，现场技术测定法主要用来测定材料()。", "options": {"A": "消耗量定额", "B": "损耗定额", "C": "净用量定额", "D": "必需消耗量"}, "answer": ["B"], "analysis": "材料消耗量定额由两个部分组成，即净用量定额和损耗定额。确定方法主要有现场技术测定法、实验室试验法、现场统计法和理论计算法。由于材料净用量可以通过理论计算和实验室试验方法编制，因此现场技术测定主要用来计算材料的损耗定额。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1075", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "根据计时观测资料得知：每平方米标准砖墙勾缝时间为10min，辅助工作时间占工序作业时间的比例为5%，准备结束时间、不可避免中断时间、休息时间占工作班时间的比例分别为3%、2%、15%。则每立方米砌体1标准砖厚的砖墙勾缝的产量定额为()m3／工日。", "options": {"A": "8.621", "B": "8.772", "C": "9.174", "D": "14.493"}, "answer": ["B"], "analysis": "基本工作时间=10min=1／6h=1／48（工日／㎡）工序作业时间=1／48／(1-5%)=0.0219（工日／㎡）每平方米的时间定额=0.219／（1-3%-2%-15%）=0.0274（工日／㎡）每立方米砌体1标准砖厚砖墙勾缝面积=1／0.24=4.17（㎡）每立方米砌体1标准砖厚砖墙勾缝的时间定额=0.0274×4.17=0.114（工日／m3）每立方米砌体1标准砖厚砖墙勾缝的产量定额=1／0.114=8.772（m3／工日）", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1076", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "某土方施工机械一次循环的正常时间为2.2min，每循环工作一次挖土0.5m3，工作班的延续时间为8h，机械正常利用系数为0.85。则该土方施工机械的产量定额为()m3/台班。", "options": {"A": "7.01", "B": "7.48", "C": "92.73", "D": "448.80"}, "answer": ["C"], "analysis": "产量定额=[0.5×(60／2.2)]×8×0.85=92.73（m3／台班）。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1077", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "砌筑每立方米一砖厚砖墙，砖(240mm×115mm×53mm)的净用量为529块，灰缝厚度为10mm，砖的损耗率为1%，砂浆的损耗率为2%。则每立方米一砖厚砖墙的砂浆消耗量为()m3。", "options": {"A": "0.217", "B": "0.222", "C": "0.226", "D": "0.231"}, "answer": ["D"], "analysis": "1m3砖墙体砂浆的净用量=1-529×0.24×0.115×0.053=0.226（m3）；1m3砖墙体砂浆的消耗量=0.226×(1+2%)=0.231（m3）。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1078", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "用计时观察法测定时间消耗的诸多方法中，精确度较高的方法是()。", "options": {"A": "数示法", "B": "图示法", "C": "接续法", "D": "选择法"}, "answer": ["C"], "analysis": "接续法测时的特点是在工作进行中和非循环组成部分出现之前一直不停止秒表，秒针走动过程中，观察者根据各组成部分之间的定时点，记录它的终止时间，再用定时点终止时间之间的差表示各组成部分的延续时间。由于这一方法避免的主观选择所导致的误差，因此比选择法测时更加准确、完善。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1079", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "在编制材料定额消耗量时，用于确定材料损耗定额的方法主要是()。", "options": {"A": "理论计算法", "B": "经验统计法", "C": "现场技术测定法", "D": "实验室试验法"}, "answer": ["C"], "analysis": "确定实体材料的净用量定额和材料损耗定额的计算数据，是通过现场技术测定、实验室试验、现场统计和理论计算等方法获得的。现场技术测定法主要适用于确定材料损耗量，因为该部分数值用统计法或其他方法较难得到；实验室试验法，主要用于编制材料净用量定额。通过试验，能够对材料的结构、化学成分和物理性能以及按强度等级控制的混凝土、砂浆、沥青、油漆等配比作出科学的结论；现场统计法由于不能分清材料消耗的性质，因而不能作为确定材料净用量定额和材料损耗定额的依据，只能作为编制定额的辅助性方法使用；理论计算法是运用一定的数学公式计算材料消耗定额。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1080", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "当确定测时法的观察次数时，通常考虑的因素是（ ）。", "options": {"A": "算数平均值的精确度及数列的稳定系数", "B": "算数平均值的精确度及已经达到的功效水平的稳定程度", "C": "被测定的工人人数及数列的稳定系数", "D": "被测定的工人人数及同时测定不同类型施工过程的数目"}, "answer": ["A"], "analysis": "测时法是属于抽样调查的方法，因此为了保证选取样本的数据可靠，需要对于同一施工过程进行重复测时。一般来说，观测的次数越多，资料的准确性越高，但要花费较多的时间和人力，这样既不经济，也不现实。确定观测次数较为科学的方法，应该是依据误差理论和经验数据相结合的方法来判断。很显然，需要的观察次数与要求的算术平均值精确度及数列的稳定系数有关。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1081", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "已知每平方米砖墙的勾缝时间为8min，则每立方米一砖半厚墙所需的勾缝时间为( ) min。", "options": {"A": "12. 00", "B": "21. 92", "C": "22. 22", "D": "33. 33"}, "answer": ["B"], "analysis": "本题考查的是确定人工定额消耗量的基本方法。标准砖规格为240mmX115mmX53mm，灰缝宽10mm.故一砖半墙的厚度=0.24+0.115+0.01=0.365 (mm)，一砖半厚的砖墙，其每立方米砌体墙面面积的换算系数为1/0.365=2.74 (m2)，则每立方米砌体所需的勾缝时间是： 2.74X8=21.92 (min).", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1082", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "确定施工机械台班定额消耗量前需计算机械时间利用系数，其计算公式正确的是（）。", "options": {"A": "机械时间利用系数=机械纯工作1h正常生产率×工作班纯工作时间", "B": "机械时间利用系数=1/机械台班产量定额", "C": "机械时间利用系数=机械在一个工作班内纯工作时间/一个工作班延续时间（8h）", "D": "机械时间利用系数=一个工作班延续时间（8h）/机械在一个工作班内纯工作时间"}, "answer": ["C"], "analysis": "机械时间利用系数=机械在一个工作班内纯工作时间/一个工作班延续时间（8h）。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1083", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "已知砌筑1m3砖墙中砖净量和损耗量分别为529块、6块，百块砖体积按0.146m3计算，砂浆损耗率为10%。则砌筑1m3砖墙的砂浆用量为（）m3。", "options": {"A": "0.250", "B": "0.253", "C": "0.241", "D": "0.243"}, "answer": ["A"], "analysis": "砂浆净用量=1-529×0.146/100=0.228（m3）砂浆消耗量=0.228×（1+10%）=0.250（m3）。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1084", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "下列施工机械消耗时间中，属于机械必需消耗时间的是()。", "options": {"A": "未及时供料引起的机械停工时间", "B": "由于气候条件引起的机械停工时间", "C": "装料不足时的机械运转时间", "D": "因机械保养而中断使用的时间"}, "answer": ["D"], "analysis": "本题考查的是机械必需消耗时间的内容。在必需消耗的工作时间里，包括有效工作、不可避免的无负荷工作和不可避免的中断三项时间消耗。 不可避免的终端时间是与工艺过程的特点、机器的使用和保养、工人休息有关的终端时间。ABC均属于损失的工作时间。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1085", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "已知1㎡墙勾缝时间为8min，则1m3一砖半厚墙所需的勾缝时间为()min。", "options": {"A": "12.00", "B": "21.92", "C": "22.22", "D": "33.33"}, "answer": ["B"], "analysis": "一砖半墙，1m3砌体墙墙面面积的换算系数为1/0.365=2.74㎡。 则1m3砌体所需的勾缝时间是：2.74×8=21.92min。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1086", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "出料容量为500L的砂浆搅拌机，每循环工作一次，需要运料、装料、搅拌、卸料和中断的时间分别为120s、30s、180s、30s、30s，其中运料与其他循环组成部分交叠的时间为30s。机械正常利用系数为0.8，则500L砂浆搅拌机的产量定额为()m3/台班。(1m3=1000L)", "options": {"A": "27.43", "B": "29.54", "C": "32.00", "D": "48.00"}, "answer": ["C"], "analysis": "本题考查的是产量定额的计算原文是：施工机械台班产量定额=机械1h纯工作正常生产率×工作班纯工作时间=机械1h纯工作正常生产率×工作班延续时间×机械正常利用系数；因此一次循环时=120+30+180+30+30-30=360(s)；机械纯工作1小时循环次数=3600/360=10（次）；机械纯工作1小时正常生产率=10×0.5=5(m3)；砂浆搅拌机的产量定额=机械纯工作1小时正常生产率×工作班纯工作时间=5×8×0.8=32(m3/台班)", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1087", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "正常施工条件下，完成单位合格建筑产品所需某材料的不可避免损耗量为0.90kg，已知该材料的损耗率为7.20%，则其总消耗量为( )kg。", "options": {"A": "13.5", "B": "13.4", "C": "12.5", "D": "11.6"}, "answer": ["B"], "analysis": "本题考查的是材料消耗量的计算。损耗率=损耗量/净用量×100%，总损耗量=净用量+损耗量=净用量×（1+损耗率）；因此材料净用量=0. 9/7. 2%=12. 50 (kg) ；材料消耗量=12. 5+0. 9=13. 40 (kg)", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1088", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "用水泥砂浆砌筑2m3砖墙，标准砖（240mm×115mm×53mm）的总耗用量为1113块。已知砖的损耗率为5%，则标准砖、砂浆的净用量分别为（）。", "options": {"A": "1057块、0.372m3", "B": "1057块、0.454m3", "C": "1060块、0.372m3", "D": "1060块、0.449m3"}, "answer": ["D"], "analysis": "标准砖净用量=1113/（1+5%）=1060（块）；砂浆净用量=2-（1060×0.24×0.115×0.053）=0.449（m3）。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1089", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "测编定额时，需对施工过程进行分解。对比工作过程的特点，工序还应具有的特征是()。", "options": {"A": "人员编制不变", "B": "劳动工具不变", "C": "工作地点不变", "D": "工作时段不变"}, "answer": ["B"], "analysis": "工序是工艺方面最简单的施工过程，表现为工作者、劳动对象、劳动工具和工作地点均不变，是编制施工定额时主要的研究对象；工作过程由同一工人或同一小组所完成的在技术操作上相互有机联系的工序的总合体，特点是人员编制不变，工作地点不变，而材料和工具可以变换，因此，本题选项B属于工序特征而不属于工作过程，B正确。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1090", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "在机械工作时间消耗的分类中，由于工人装料数量不足引起的砂浆搅拌机不能满载工作的时间属于()。", "options": {"A": "低负荷下的工作时间", "B": "机械的多余工作时间", "C": "违反劳动纪律引起的机械时间损失", "D": "有根据地降低负荷下的工作时间"}, "answer": ["A"], "analysis": "由于工人装料数量不足引起的砂浆搅拌机不能满载工作的时间属于机器低负荷下的工作时间。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1091", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "在确定材料定额消耗量时，利用实验室试验法主要是为了编制()。", "options": {"A": "材料损耗定额", "B": "材料净用量定额", "C": "材料消耗定额", "D": "劳动定额"}, "answer": ["B"], "analysis": "实验室试验法，主要用于编制材料净用量定额。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1092", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "下列对工人工作时间中辅助工作时间的理解，正确的是()。", "options": {"A": "在辅助工作时间里，能使产品的形状大小、性质或位置发生变化", "B": "基本工作时间的结束，往往就是辅助工作时间的开始", "C": "辅助工作一般是机械操作", "D": "在机手并动的情况下，辅助工作是在机械运转过程中进行的，为避免重复则不应再计辅助工作时间的消耗"}, "answer": ["D"], "analysis": "工作时间不同分类内涵的知识点很重要，是理解定额计算的基础，考生应掌握。辅助工作时间是为保证基本工作能顺利完成所消耗的时间。在辅助工作时间里，不能使产品的形状大小、性质或位置发生变化。辅助工作时间的结束，往往就是基本工作时间的开始。辅助工作一般是手工操作。但如果在机手并动的情况下，辅助工作是在机械运转过程中进行的，为避免重复则不应再计辅助工作时间的消耗。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1093", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "经现场观测，完成10m3某分项工程需消耗某种材料2.76m3，其中现场内材料运输及施工操作过程中的损耗量0.095m3，则该种材料的损耗率为()。", "options": {"A": "3.64%", "B": "3.57%", "C": "3.44%", "D": "3.56%"}, "answer": ["D"], "analysis": "材料净用量=材料消耗量-损耗量=2.76-0.095=2.665(m3) 材料损耗率=损耗量／净用量×100%=0.095/2.665=3.56%", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1094", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "已知某挖土机挖土的一次正常循环工作时间是2min，每循环工作一次挖土0.5m3，工作班的延续时间为8h，机械正常利用系数为0.8，则其产量定额为( )m3/台班。", "options": {"A": "96", "B": "120", "C": "150", "D": "300"}, "answer": ["A"], "analysis": "本题考查的是确定机械台班定额消耗量的基本方法。本题正确答案为A。 对于循环机械台班定额消耗量的确定的程序如下：(1)确定正常施工条件下1h循环次数和纯工作生产率。本题中1h循环次数为：60/2=30; 1h纯工作生产率：30×0.5=15(m3/h)。 (2)确定机械一个台班的纯工作时间。本题中一个台班的纯工作时间为：8×0.8=6.4 (h)。 (3)确定机械的产量定额。本题中机械的产量定额=15×6.4 =96 (m3)。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1095", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "在对材料消耗过程测定与观察的基础上，通过完成产品数量和材料消耗量的计算而确定各种材料消耗定额的方法是( )。", "options": {"A": "实验室试验法", "B": "现场技术测定法", "C": "现场统计法", "D": "理论计算法"}, "answer": ["B"], "analysis": "本题考查的是确定材料消耗量的基本方法。现场技术测定法，又称为观测法，是根据对材料消耗过程的测定与观察，通过完成产品数量和材料消耗量的计算，而确定各种材料消耗定额的一种方法。D", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1096", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "通过计时观察资料得知：人工挖二类土1m3 的基本工作时间为6h，辅助工作时间占工序作业时间的2%。准备与结束工作时间、不可避免的中断时间、休息时间分别占工作日的3%、2%、18%。则该人工挖二类土的时间定额是（）工日／m3。", "options": {"A": "0.7", "B": "0.994", "C": "1.006", "D": "1.307"}, "answer": ["B"], "analysis": "基本作业时间=6（h／m3）=0.75（工日／m3） 工序作业时间=0.75／（1－2%）=0.765（工日／m3） 时间定额=0.765／（1－3%－2%－18%）=0.994（工日／m3）", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1097", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "某工程现场采用出料容量500L 的混凝土搅拌机,每一次循环中,装料、搅拌、卸料、中断需要的时间分别为1、3、1、1min,机械正常利用系数为0.9,则该机械的台班产量定额1 为（）m3／台班。", "options": {"A": "32", "B": "34", "C": "36", "D": "38"}, "answer": ["C"], "analysis": "该搅拌机一次循环的正常延续时间=1＋3＋1＋1=6（min）=0.1（h） 该搅拌机纯工作1h 循环次数=10（次） 该搅拌机纯工作1h 正常生产率=10×500=5000（L）=5（m3） 该搅拌机台班产量定额=5×8×0.9=36（m3／台班）", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1098", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "施工过程可以分为工序、工作过程和综合工作工程，其分类标准是（）。", "options": {"A": "工艺特点", "B": "工具设备的机械化程度", "C": "组织复杂程度", "D": "施工过程性质"}, "answer": ["C"], "analysis": "施工过程的分类可以按照组织上的复杂程度，分解为工序、工作过程和综合工作过程;按照工艺特点，施工过程可以分为循环施工过程和非循环施工过程两类。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1099", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "在机械工作时间消耗的分类中，由于工人装料数量不足引起的汽车在降低复核的情况下工作所延续的时间属于（）。", "options": {"A": "有根据地降低负荷下的工作时间", "B": "机械的多余工作时间", "C": "违反劳动纪律引起的机械时间损失", "D": "低负荷下的工作时间"}, "answer": ["D"], "analysis": "低负荷下的工作时间，是由于工人或技术人员的过错所造成的施工机械在降低负荷的情况下工作的时间。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1100", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "某施工机械原值为50000元，耐用总台班为2000台班，一次检修费为3000元，检修周期为4，台维护费系数为20%，每台班发生的其他费用合计为30元／台班，忽略残值和资金时间价值，除税系数为1，则该机械的台班单价为()元。", "options": {"A": "60.40", "B": "62.20", "C": "65.40", "D": "67.20"}, "answer": ["A"], "analysis": "本题考查的是机械台班单价的计算。施工机械台班单价由七项费用组成，包括折旧费，检修费，维护费，安拆费机场外运费，人工费，燃料动力费，其他费用等。台班折旧费=机械预算价格×（1-残值率）/耐用总台班；检修费=一次检修费×检修次数×除税系数/耐用总台班；检修次数=检修周期-1；维护费=检修费×K，式中 K-维护系数；因此本题台班折旧费=50000/2000=25元／台班；台班检修费=（3000×(4-1)）/2000=4.5元／台班；台班维护费=4.5×20%=0.9元／台班；机械台班单价=25+4.5+0.9+30=60.4元／台班。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1101", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "某施工机械耐用总台班为800台班，检修次数数为3，一次检修费用为1200元，除税系数为1，则该机械的台班检修费为()元。", "options": {"A": "7.5", "B": "6.0", "C": "4.5", "D": "3.0"}, "answer": ["C"], "analysis": "本题考查的是台班大修理费的计算。台班检修费=（一次大检修费×检修次数×除税系数）/耐用总台班=（3×1200）/800=4.5元", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1102", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "某大型施工机械需配机上司机、机上操作人员各一名，若年制度工作日为天，年工作台班为台班，人工日工资单价均为元/工日，则该施工机械的台班人工费为（）元/台班。", "options": {"A": "100", "B": "125", "C": "200", "D": "250"}, "answer": ["D"], "analysis": "台班人工费=2×[1+(250-200)/200]×100=250（元/台班）。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1103", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "施工机械耐用总台班数，指机械从投入使用至()前的总台班数。", "options": {"A": "大修", "B": "报废", "C": "一项工程竣工", "D": "满5年"}, "answer": ["B"], "analysis": "耐用总台班指施工机械从开始投入使用至报废前使用的总台班数，应按施工机械的技术指标及寿命期等相关参数确定。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1104", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "施工机械台班单价中的养路费及车船使用税中的保险费是指()。", "options": {"A": "强制保险费", "B": "非强制保险费", "C": "强制和非强制保险费", "D": "司机危险作业意外伤害保险费"}, "answer": ["A"], "analysis": "年养路费、年车船使用税、年检费用应执行编制期有关部门的规定。年保险费执行编制期有关部门强制性保险的规定，非强制性保险不应计算在内。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1105", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "下列施工机械的费用项目中，不能计入施工机械台班单价的是()。", "options": {"A": "施工机械年检费", "B": "小型施工机械安装费", "C": "定期保养所用的辅料费", "D": "机上司机劳动保险费"}, "answer": ["D"], "analysis": "在施工机械台班单价中包括机上人工费，但司机的劳动保险费属于企业管理费的内容，不属于直接人工支出。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1106", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "某施工机械原始购置费为4万元，耐用总台班为2000台班，检修周期为5个，每次检修费为3000元，维护费系数为0.5，每台班人工、燃料动力及其他费用为65元，机械残值率为5%。不考虑资金的时间价值，则该机械的台班单价为()元／台班。", "options": {"A": "91.44", "B": "93.00", "C": "95.25", "D": "95.45"}, "answer": ["B"], "analysis": "台班折旧费=(40000-40000×5%)/2000=19（元／台班） 台班检修费=(3000×4)/2000=6（元／台班） 台班维护理费=6×0.5=3（元／台班） 台班单价=19+6+3+65=93（元／台班）", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1107", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "在计算材料单价时，若同一种材料因来源地、交货地、供货单位、生产厂家不同，而有几种价格时，根据( )进行加权平均。", "options": {"A": "不同来源地供货距离", "B": "不同来源地供货范围", "C": "不同来源地供货数量比例", "D": "不同来源地供货方式"}, "answer": ["C"], "analysis": "在确定原价时，凡同一种材料因来源地、交货地、供货单位、生产厂家不同，而有几种价格（原价）时，根据不同来源地供货数量比例，采取加权平均的方法确定其综合原价。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1108", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "某挖掘机配司机1人，若年制度工作日为245天，年工作台班为220台班，人工工日单价为80元，则该挖掘机的人工费为（）元/台班。", "options": {"A": "71.8", "B": "80.0", "C": "89.1", "D": "132.7"}, "answer": ["C"], "analysis": "台班人工费=人工消耗量×（1+年制度工作日-年工作台班/年工作台班）×台班单价=1×（1+245-220/220）×80=89.1（元/台班）。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1110", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "按照现行规定，生产工人根据国家法律、法规和政策规定执行国家或社会义务等原因按标准或标准的一定比例支付的工资属于()。", "options": {"A": "计时工资", "B": "特殊情况下支付的工资", "C": "计件工资", "D": "津贴补贴"}, "answer": ["B"], "analysis": "特殊情况下支付的工资。是指根据国家法律、法规和政策规定，因病、工伤、产假、计划生育假、婚丧假、事假、探亲假、定期休假、停工学习、执行国家或社会义务等原因按计时工资标准或计件工资标准的一定比例支付的工资。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1111", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "人工日工资单价的组成中，停工学习时支付的工资属于()。", "options": {"A": "计时工资", "B": "特殊情况下支付的工资", "C": "奖金", "D": "津贴补贴"}, "answer": ["B"], "analysis": "停工学习时支付的工资属于特殊情况下支付的工资。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1112", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "下列费用项目中，应计入建筑安装工程材料单价的是()。", "options": {"A": "材料一般性鉴定检查费", "B": "材料二次搬运费", "C": "新结构、新材料试验费", "D": "材料工地管理费"}, "answer": ["D"], "analysis": "材料单价包括材料原价、材料运杂费、运输损耗费、采购及保管费。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1113", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "下列施工机械，其安拆及场外运费计算到施工机械台班单价中的是()。", "options": {"A": "不需安拆的施工机械", "B": "利用辅助设施移动的施工机械，其辅助设施（包括轨道和枕木）等的折旧、搭设和拆除等费用可单独计算", "C": "安拆简单、移动需要起重及运输机械的轻型施工机械", "D": "安拆复杂、移动需要起重及运输机械的重型施工机械，其安拆费及场外运费单独计算"}, "answer": ["C"], "analysis": "安拆费及场外运费根据施工机械不同分为计入台班单价、单独计算和不计算三种类型。移动有一定难度的特、大型（包括少数中型）机械，其安拆费及场外运费应单独计算。(1) 安拆简单、移动需要起重及运输机械的轻型施工机械，其安拆费及场外运费计入台班单价。 1) 一次安拆费应包括施工现场机械安装和拆卸一次所需的人工费、材料费、机械费、安全监测部门的检测费及试运转费；2) —次场外运费应包括运输、装卸、辅助材料和回程等费用；3) 年平均安拆次数按施工机械的相关技术指标，结合具体情况综合确定；4) 运输距离均按平均 30km 计算。(2) 单独计算的情况包括：1) 安拆复杂、移动需要起重及运输机械的重型施工机械，其安拆费及场外运费单独计算2) 利用辅助设施移动的施工机械，其辅助设施（包括轨道和枕木）等的折旧、搭设和拆除等费用可单独计算。(3) 不需计算的情况包括：1) 不需安拆的施工机械，不计算一次安拆费；2) 不需相关机械辅助运输的自行移动机械，不计算场外运费；3) 固定在车间的施工机械，不计算安拆费及场外运费。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1114", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "某施工机械预计使用9年，使用期内有3个检修周期，检修间隔台班为800台班，一次检修费为4500元，除税系数为1，则其台班检修费为()元。", "options": {"A": "1.88", "B": "3.75", "C": "5.63", "D": "16.88"}, "answer": ["B"], "analysis": "寿命期内检修次数=检修周期-1=3-1=2（次） 耐用总台班=检修间隔台班×检修周期=800×3=2400（台班） 台班检修费=(2×4500)/2400=3.75（元）", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1115", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "关于材料单价的计算，下列计算公式中正确的是（）。", "options": {"A": "（供应价格+运杂费）×（1+运输损耗率）×（1+采购及保管费率）", "B": "（供应价格+运杂费）/（1-运输耗损率）×（1-采购及保管费率）", "C": "（供应价格+运杂费）×（1+采购及保管费率）/1-采购及保管费率", "D": "（供应价格+运杂费）×（1+运输损耗率）/1-采购及保管费率"}, "answer": ["A"], "analysis": "材料单价=[（供应价格+运杂费）×（1+运输耗损率）]×（1+采购及保管费率）。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1116", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "某材料自甲、乙两地采购，甲地采购量为400t,原价为180 元／t,运杂费为30 元／t；乙地采购量为300t,原价为200 元／t，运杂费为28 元／t，该材料运输损耗率和采购保管费费率分别为1%、2%,则该材料的基价为（）元/t。", "options": {"A": "223.37", "B": "223.40", "C": "224.24", "D": "224.29"}, "answer": ["D"], "analysis": "材料基价是指材料在购买、运输、保管过程中形成的价格，其内容包括材料原价、材料运杂费、运输损耗费、采购及保管费等。甲地采购材料：（400×180+400×30)×(1+1%)×(l+2%)=86536.8(元）。乙地采购材料： （300×200+300×28)×(1+1%)×(1+2%)=70465.68(元）。材料基价=(86536.8+70465.68)/(400+300)=224.29(元/t)。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1117", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "在编制现浇混凝土柱预算定额时,测定每10m3 混凝土柱工程量需消耗10.5m3 的混凝土。现场采用500L 的混凝土搅拌机，测得搅拌机每循环一次需4min。机械的正常利用系数为0.85。若机械幅度差系数为0，则该现浇混凝土柱10m3 需消耗混凝土搅拌机（）台班。", "options": {"A": "0.206", "B": "0.196", "C": "0.157", "D": "0.149"}, "answer": ["A"], "analysis": "首先，计算混凝土搅拌机的施工定额。 常施工条件下1h 循环次数=60/4=15(次） 1h 纯工作生产率=15×0.5=7.5(m3/h) ②机械一个台班的纯工作时间=8×O.85=6.8(h) ③机械的产量定额=7.5×6.8=51(m3) 机械的台班定额=1/51=0.0196(台班/m3) 其次，考虑机械幅度差,计算预算定额机械消耗量。 1m3 预算定额的机械消耗量=0.0196×(l+0)=0.0196(台班/m3)。 10.5m3 预算定额的机械消耗量为:0.0196×10.5=0.206(台班）", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1118", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "某施工机械耐用总台班为800 台班，大修周期数为4,每次大修理费用为1200 元，则该机械的台班大修理费为（）元。", "options": {"A": "7.5", "B": "6.0", "C": "4.5", "D": "3.0"}, "answer": ["C"], "analysis": "该题考核机械的台班大修理费的计算方法。 台班大修理费=一次性大修理费x 寿命期内大修理次数/耐用总台班数=1200×(4-l)/800=4.5(元)", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1119", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "关于施工机械安拆费和场外运费的说法，正确的是()。", "options": {"A": "安拆费指安拆一次所需的人工、材料和机械使用费之和", "B": "安拆费中包括机械辅助设施的折旧费", "C": "安拆复杂、移动需要起重及运输机械的重型施工机械，其安拆费及场外运费不予计算", "D": "固定在车间的施工机械，计算安拆费及场外运费"}, "answer": ["B"], "analysis": "本题考查的是安拆费及场外运费的组成。安拆费指施工机械在现场进行安装与拆卸所需的人工、材料、机械和试运转费用以及机械辅助设施的折旧、搭设、拆除等费用。因此A错，B对。(2) 单独计算的情况包括：1) 安拆复杂、移动需要起重及运输机械的重型施工机械，其安拆费及场外运费单独计算2) 利用辅助设施移动的施工机械，其辅助设施（包括轨道和枕木）等的折旧、搭设和拆除等费用可单独计算。(3) 不需计算的情况包括：1) 不需安拆的施工机械，不计算一次安拆费；2) ^不需相关机械辅助运输的自行移动机械，不计算场外运费；3) 固定在车间的施工机械，不计算安拆费及场外运费。(4) 自升式塔式起重机、施工电梯安拆费的超高起点及其增加费，各地区、部门可根据具体情况确定。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1120", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "采用现场测定法，测得某种建筑材料在正常施工条件下的单位消耗量为12.47kg,损耗量为0.65kg,则该材料的损耗率为（）。", "options": {"A": "4.95%", "B": "5.21%", "C": "5.45%", "D": "5.50%"}, "answer": ["D"], "analysis": "材料消耗量指在正常条件下不可避免的材料损耗，如现场内材料运输及施工操作过程中的损耗等。 其关系式如下： 材料损耗率=损耗量/净用量x100% 材料损耗量=材料净用量×损耗率 材料消耗量=材料净用量+损耗量或材料消耗量=材料净用量×(1+损耗率） 根据上式，本题材料损耗率=0.65/(12.47-0.65)×100%=5.50%。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1121", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "根据单项工程的一般划分原则，下列单项工程中属于辅助生产设施的是（）。", "options": {"A": "废水处理站", "B": "水塔", "C": "机修车间", "D": "职工医院"}, "answer": ["C"], "analysis": "单项工程中的辅助生产设施是指为主要生产车间服务的工程项目。包括集中控制室、中央实验室、机修、电修、仪器仪表修理及木工（模）等车间，原材料、半产品、成品及危险品等仓库。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1122", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "砌筑10m3砖墙需基本用工20个工日，辅助用工为5个工日，超运距用工需2个工日，人工幅度差系数为10%，则预算定额人工工日消耗量为()工日/10m3。", "options": {"A": "27.7", "B": "29.0", "C": "29.2", "D": "29.7"}, "answer": ["D"], "analysis": "人工工日消耗量=（基本用工+辅助用工+超运距用工）×（1+人工幅度差系数）=(20+5+2)×(1+10%)=29.7（工日/10m3）", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1123", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "在正常施工条件下，完成10m3混凝土梁浇捣需4个基本用工，0.5个辅助用工，0.3个超运距用工，若人工幅度差系数为10%，则该梁混凝土浇捣预算定额人工消耗量为（）工日/10m3。", "options": {"A": "5.20", "B": "5.23", "C": "5.25", "D": "5.28"}, "answer": ["D"], "analysis": "预算定额人工消耗量=（4+0.3+0.5）×（1+10%）=5.28（工日/10m3）。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1124", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "关于编制预算定额应遵循的原则，下列说法中正确的有()。", "options": {"A": "反映社会先进平均水平", "B": "简明适用", "C": "价格的灵活可协调性", "D": "综合、简化"}, "answer": ["B"], "analysis": "包括按社会平均水平确定预算定额的原则及简明适用原则。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1125", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "经现场观测，完成10m3某分项工程需消耗某种材料1.76m3，其中损耗量0.055m3，则该种材料的损耗率为()。", "options": {"A": "3.03%", "B": "3.13%", "C": "3.20%", "D": "3.23%"}, "answer": ["D"], "analysis": "材料净用量=材料消耗量－损耗量=1.76-0.055=1.705(m3) 材料损耗率=损耗量／净用量×100%=0.055/1.705=3.23%", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1126", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "某挖掘机械挖二类土方的台班产量定额为100m3/台班，当机械幅度差系数为20%时，该机械挖二类土方1000m3预算定期的台班耗用量应为（）台班。", "options": {"A": "8.0", "B": "10.0", "C": "12.0", "D": "12.5"}, "answer": ["C"], "analysis": "施工机械台班时间定额=1/100=0.01（台班/m3）预算定额机械耗用台班=0.01×（1+20%）=0.012（台班/m3）挖土方1000m3的预算定额机械耗用台班量=1000×0.012=12（台班）。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1127", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "若施工作业所能依据的定额齐全，则在编制施工作业计划时宜采用的定额是（）。", "options": {"A": "概算指标", "B": "概算定额", "C": "预算定额", "D": "施工定额"}, "answer": ["D"], "analysis": "施工定额是以同一性质的施工过程一工序，作为研究对象，表示生产产品数量与时间消耗综合关系编制的定额。施工定额属于企业定额的性质。施工定额是工程建设定额中分项最细、定额子目最多的一种定额，也是建设工程定额中的基础性定额。施工定额由人工定额、材料消耗定额和机械台班使用定额所组成。施工定额直接应用于施工项目的施工管理，用来编制施工作业计划、签发施工任务单、签发限额领料单，以及结算计件工资或计量奖励工资等。施工定额也是编制预算定额的基础。金考典考前内部资料，【精华专区】可购买，2套密卷+考前3页纸，覆盖80%考点内容， 购买后发送到备注邮箱,咨询QQ 599918668", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1128", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "编制标准砖砌体材料消耗定额时，砖的消耗量应按（）确定。", "options": {"A": "净用量", "B": "净用量加损耗量", "C": "一次损耗量", "D": "损耗量加补损量"}, "answer": ["B"], "analysis": "材料消耗定额，主要包括确定直接使用在工程上的材料净用量和在施工现场内运输和操作过程中的不可避免的废料和损耗。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1129", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "某出料容量0.5m3的混凝土搅拌机，每一次循环中，装料、搅拌、卸料、中断需要的时间分别为1、3、1、1 分钟，机械利用系数为0.8，则该搅拌机的台班产量定额是（）m3/台班。", "options": {"A": "32", "B": "36", "C": "40", "D": "50"}, "answer": ["A"], "analysis": "施工机械台班使用定额的编制。1+3+1+1=6分钟，60/6=10次，一个台班是8小时，台班产量定额=10*.5*8*0.8=32m3/台班。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1130", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "已知某斗容量1m3正铲挖土机，机械台班产量为6m3，机械利用系数0.85，则它在正常工作条件下，1h 纯工作时间内可以挖土约（）m3。", "options": {"A": "47", "B": "51", "C": "56", "D": "70"}, "answer": ["D"], "analysis": "施工机械台班产量定额=机械净工作生产率（即机械纯工作1h的正常生产率）×工作班延续时间×机械利用系数，故机械净工作生产率（即机械纯工作1h的正常生产率）=476÷（8×0.85）=70（m3）。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1131", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "对于同类型产品规格多、工序重复、工作量小的施工过程，编制人工定额宜采用的方法是（）。", "options": {"A": "经验估算法", "B": "技术测定法", "C": "统计分析法", "D": "比较类推法"}, "answer": ["D"], "analysis": "比较类推法对于同类型产品规格多、工序重复、工作量小的施工过程，常用比较类推法。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1132", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "预算定额是编制概算定额的基础，是以（）为对象编制的定额。", "options": {"A": "同一性质的施工过程", "B": "建筑物各个分部分项工程", "C": "扩大的分部分项工程", "D": "整个建筑物和构筑物"}, "answer": ["B"], "analysis": "预算定额是以建筑物或构筑物各个分部分项工程为对象编制的定额。 本题库是以官方教材为依据，知识点所对应的习题综合了二建法规、二建管理、造价员基础、一级造价师考试的题库+真题编辑，基本上做到了每个知识点都有相对应的题目及解析,题库会陆续更新,会有模拟题,预测题及考前更新押题。 《建设工程计量与计价实务》题库编辑中,教材出来后会陆续更新 www.jinkaodian.com 金考典考试软件。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1133", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "针对不同管理层，提供不同要求和浓缩程度的工程造价信息，这体现了工程造价信息管理的（）。", "options": {"A": "时效性原则", "B": "有效性原则", "C": "髙效处理原则", "D": "标准化原则"}, "answer": ["B"], "analysis": "本题考核工程造价信息管理的基本原则。有效性原则指工程造价信息应针对不同层次管理者的要求进行适当加工，针对不同管理层提供不同要求和浓缩程度的信息。这一原则是为了保证信息产品对于决策支持的有效性。工程造价信息管理的基本原则包括标准化原则、有效性原则、定量化原则、时效性原则和高效处理原则。造价信息管理具体原则的内容属于基本知识点。要注意掌握各项原则的含义。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1134", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "建立工程造价资料数据库要解决的首要问题是（）。", "options": {"A": "工程的分类与编码", "B": "数据搜集与录入", "C": "建立造价资料积累制度", "D": "造价数据库网络化管理"}, "answer": ["A"], "analysis": "积极推广使用计算机建立工程造价资料数据库，开发通用的工程造价资料管理程序，可以提高工程造价资料的适用性和可靠性。要建立造价资料数据库，首要的问题是工程的分类与编码。由于不同的工程在技术参数和工程造价组成方面有较大的差异，必须把同类型工程合并在一个数据库文件中，而把另一类型工程合并到另一数据库文件中去。为了便于进行数据的统一管理和信息交流，必须设计出一套科学、系统的编码体系。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1135", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "下面是某地区标准厂房工程造价指数表，按照指数分类，表中的指数相对于2000 年7 月的指数属于（）。", "options": {"A": "定基指数和数量指标指数", "B": "环比指数和质量指标指数", "C": "定基指数和质量指标指数", "D": "环比指数和数量指标指数"}, "answer": ["C"], "analysis": "本题中各期数据都以2000 年7 月为基期计算，故为定基指数；质量指标指数是综合反映现象相对水平或平均水平变动情况的指数，工程造价指数属于价格指数,在性质上属于质量指标指数。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1136", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "信息标准化是建立全国建设工程造价信息系统的基础性工作，其具体建设工作内容不包括（）。", "options": {"A": "工程项目分类标准代码", "B": "信息采集及传输标准格式", "C": "建设工程人、材、机的分类及标准代码", "D": "信息共享的管理机制和模式"}, "answer": ["D"], "analysis": "加强全国建设工程造价信息系统的信息标准化工作，包括组织编制建设工程人工、材料、机械、设备的分类及标准代码，工程项目分类标准代码,各类信息采集及传输标准格式等工作，将为全国工程造价信息化的发展提供基础。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1137", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "从信息管理组织角度，可以将工程造价信息分为（）。", "options": {"A": "文件式信息和非文件式信息", "B": "系统化信息和非系统化信息", "C": "宏观信息和微观信息", "D": "固定信息和流动信息"}, "answer": ["B"], "analysis": "考核工程造价信息的分类，①按管理组织角度分为系统化和非系统化；②按形式分为文件式和非文件式；③按信息来源分为横向和纵向；④按反映经济层面分为宏观和微观；⑤按动态性分为过去的和现在的；⑥按稳定程度分为固定的和流动的。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1138", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "某类建筑材料本身的价格不高，但所需的运输费用却很高，该类建筑材料的价格信息一般具有较明显的（）。", "options": {"A": "专业性", "B": "季节性", "C": "区域性", "D": "动态性"}, "answer": ["C"], "analysis": "本题考查的是工程造价信息及其主要内容。不少建筑材料本身的价值或生产价格并不高，但所需要的运输费用却很高，这都在客观上要求尽可能就近使用建筑材料，体现出工程造价信息区域性的特点。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1139", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "在对工程造价信息进行分类时，要考虑到今后增加新的信息类型，不打乱已建立的分类体系，这说明了信息分类应遵循（）的原则。", "options": {"A": "稳定性", "B": "兼容性", "C": "可扩展性", "D": "实用性"}, "answer": ["C"], "analysis": ":工程造价信息的分类 （1）工程造价信息分类的原则。遵循以下基本原则： 1）稳定性。信息分类应选择分类对象最稳定的本质属性或特征作为信息分类的基础和标准。 2）兼容性。项目信息的分类体系应能满足不同项目参与方高效信息交换的需要。同时，与有关国际、国内标准的一致性也是兼容性应考虑的内容。 3）可扩展性。信息分类体系应具备较强的灵活性，以保证增加新的信息类型时，不至于打乱已建立的分类体系。4）综合实用性。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1140", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "下列各项中，建立工程造价资料数据库的主要作用不包括（）。", "options": {"A": "编制概算指标、投资估算指标的重要基础资料", "B": "审查施工图预算的基础资料", "C": "研究分析工程造价变化规律的基础", "D": "编制工程竣工决算的重要资料"}, "answer": ["D"], "analysis": "资料的运用：1)作为编制固定资产投资计划的参考，用以进行建设成本分析；2)进行单位生产能力投资分析；3)用作编制投资估算的重要依据；4)用作编制初步设计概算和审查施工图预算的重要依据；5）用作确定标底和投标报价的参考资料；6)用作技术经济分析的基础资料；7)用作编制各类定额的基础资料；8)用以测定调价系数、编制造价指数；9)用以研究同类工程造价的变化规律。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1141", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "表明某经济现象某一期对其上一期或前一期的综合变动程度的指数属于()。", "options": {"A": "综合指数", "B": "环比指数", "C": "定基指数", "D": "平均数指数"}, "answer": ["B"], "analysis": "指数按照采用的基期不同，可分为定基指数和环比指数。环比指数是以前一时期为基期计算的指数，表明社会经济现象对上一期或前一期的综合变动的指数。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1142", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "工程造价信息分类应从系统工程的角度出发，放在具体的应用环境中考虑，综合项目的实施环境和信息技术工具，这体现了工程造价信息分类的( )原则。", "options": {"A": "综合实用性", "B": "稳定性", "C": "兼容性", "D": "可扩展性"}, "answer": ["A"], "analysis": "综合实用性是指信息分类应从系统工程的角度出发，放在具体的应用环境中进行整体考虑。这体现在信息分类的标准与方法的选择上，应综合考虑项目的实施环境和信息技术工具。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1143", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "指数按照其反映的现象的性质不同，分为数量指标指数和()。", "options": {"A": "综合指数", "B": "环比指数", "C": "定基指数", "D": "质量指数"}, "answer": ["D"], "analysis": "指数按照其反映的现象的性质不同，分为数量指标指数和质量指标指数。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1144", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "某工程主要购置M、N两类设备，M类设备基期欲购5台，单价28万元，报告期实际购置6台，单价35万元；N类设备基期欲购8台，单价16万元，报告期实际购置10台，单价27万元，则设备购置价格指数为()。", "options": {"A": "145.9%", "B": "179.1%", "C": "146.3%", "D": "122.8%"}, "answer": ["C"], "analysis": "设备购置价格指数=(35×6+27×10)／(28×6+16×10)×100%=146.3%。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1146", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "根据统计学一般原理，关于确定同度量因素原则的说法，正确的是()。", "options": {"A": "质量指标指数应以报告期的质量指标作为同度量因素", "B": "数量指标指数应以报告期的数量指标作为同度量因素", "C": "质量指标指数应以报告期的数量指标作为同度量因素", "D": "数量指标指数应以基期的数量指标作为同度量因素"}, "answer": ["C"], "analysis": "根据统计学的一般原理，确认同量度因素的一般原则：质量指标指数应当以报告期的数量指标作为同度量因素，数量指标指数则应以基期的质量指标作为同度量因素。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1147", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "相对而言，机械价格信息中对于工程计价更为重要的是()。", "options": {"A": "设备市场价格信息", "B": "设备租赁市场价格信息", "C": "设备回购市场价格信息", "D": "设备出售市场价格信息"}, "answer": ["B"], "analysis": "机械价格信息包括设备市场价格信息和设备租赁市场价格信息两部分。相对而言，后者对于工程计价更为重要，发布的机械价格信息应包括机械种类、规格型号、供货厂商名称、租赁单价、发布日期等内容。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1148", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "某建设项目报告期建筑安装工程费为900万元，造价指数为106%，报告期设备、工器具单价60万元，基期单价为50万元，报告期购置数量10台，基期购置数量12台，报告期工程建设其他费为200万元，工程建设其他指数为103%，则该建设项目工程造价指数为()。", "options": {"A": "115.74%", "B": "110.16%", "C": "116.16%", "D": "113.65%"}, "answer": ["B"], "analysis": "设备、工器具价格指数=Σ（报告期设备工器具单价×报告期购置数量）/Σ（基期设备工器具单价×报告期购置数量）=（10×60）/（10×50）=120% 建筑安装工程造价指数=（900+600+200）/[（900/106%）+（600/120%）+（200/103%）]=110.16%", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1149", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "建筑工程实物工程量人工价格信息是以( )为对象。", "options": {"A": "建筑工程的不同划分标准", "B": "建筑工人的工种分类", "C": "建筑企业的等级", "D": "建筑地域的划分"}, "answer": ["A"], "analysis": "建筑工程实物工程量人工价格信息是按照建筑工程的不同划分标准为对象，所反映 的单位实物工程量人工价格信息。根据工程不同部位，体现作业的难易、结合不同工种作业情况将建 筑工程划分为十三项。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1152", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "最能体现信息动态性变化特征，并且在工程价格的市场机制中起重要作用的工程造价信息主要包括( )。", "options": {"A": "工程造价指数、在建工程信息和已完工程信息", "B": "价格信息、工程造价指数和已完工程信息", "C": "人工价格信息、材料价格信息及在建工程信息", "D": "价格信息、工程造价指数及刚开工的工程信息"}, "answer": ["B"], "analysis": "从广义上说，所有对工程造价的计价过程起作用的资料都可以称为是工程造价信息。例如各种定额资料、标准规范、政策文件等。但最能体现信息动态性变化特征，并且在工程价格的市场机制中起重要作用的工程造价信息主要包括价格信息、工程造价指数和已完工程信息三类。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1153", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "某建设项目需购置甲、乙两种生产设备，设备甲基期购置数量3台，单价2万元；报告期购置数量2台，单价2.5万元。设备乙基期购置数量2台，单价4万元；报告期购置数量3台，单价4.5万元。该建设项目设备价格指数为（）。", "options": {"A": "1.32", "B": "0.76", "C": "1.16", "D": "1.14"}, "answer": ["C"], "analysis": "设备、工器具价格指数是综合指数。设备、工器具价格指数=∑（报告期设备工器具单价×报告期购置数量）/∑（基期设备工器具单价×报告期购置数量）=（2×2.5+3×4.5）/（2×2+3×4）=1.16。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1156", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "(2016年)下列说法中，符合工程计价基本原理的是()。", "options": {"A": "工程计价的基本原理在于项目划分与工程量计算", "B": "工程计价分为项目的分解与组合两个阶段", "C": "工程计价包括工程单价的确定和总价的计算", "D": "工程单价包括生产要素单价、工料单价和综合单价"}, "answer": ["C"], "analysis": "B不对：工程计价的基本原理就在于项目的分解与组合。A不对：工程计量工作包括工程项目的划分和工程量的计算。C对：工程计价包括工程单价的确定和总价的计算。D不对：工程单价包括工料单价和综合单价。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1158", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "(2015年)关于工程量清单的编制，下列说法中正确的是( )。", "options": {"A": "项目编码以五级全国统一编码设置，用十二位阿拉伯数字表示", "B": "编制分部分项工程量清单时，必须对工作内容进行描述", "C": "补充项目的编码由计算规范的代码与B和三位阿拉伯数字组成", "D": "按施工方案计算的措施费，必须写明“计算基础”、“费率”的数值"}, "answer": ["C"], "analysis": "该题主要考察的是：清单编制的方法。 选项A：一、二、三、四级编码为全国统一，即一至九位应按工程量计算规范附录的规定设置；第五级即十至十二位为清单项目编码，应根据拟建工程的工程量清单项目名称设置。 选项B：在编制分部分项工程项目清单时，工程内容通常无须描述。 选项C正确：补充项目的编码由工程量计算规范的代码与B和三位阿拉伯数字组成，并应从001起顺序编制。 选项D：注2.按施工方案计算的措施费，若无“计算基础”和“费率”的数值，也可只填“金额”数值，但应在备注栏说明施工方案出处或计算方法。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1159", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "(2015年)关于总承包服务费的支付，下列说法中正确的是( )。", "options": {"A": "建设单位向总承包单位支付", "B": "分包单位向总承包单位支付", "C": "专业承包单位向总承包单位支付", "D": "专业承包单位向建设单位支付"}, "answer": ["A"], "analysis": "该题主要考察的是：总承包服务费的内容，“招标人应预计该项费用并按投标人的投标报价向投标人支付该项费用。”", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1161", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "(2016年)采用工程量清单计价的总承包服务费计价表中，应由投标人填写的内容是()。", "options": {"A": "项目价值", "B": "服务内容", "C": "计算基础", "D": "费率和金额"}, "answer": ["D"], "analysis": "总承包服务费计价表项目名称、服务内容由招标人填写，编制招标控制价时，费率及金额由招标人按有关计价规定确定； 投标时，费率及金额由投标人自主报价，计入投标总价中。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1162", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "(2016年)完成某分部分项工程1m3需基本用工0.5工日，超运距用工0.05工日，辅助用工0.1工日。如人工幅度差系数为10%，则该工程预算定额人工工日消耗量为()供给/10m3。", "options": {"A": "6.05", "B": "5.85", "C": "7.00", "D": "7.15"}, "answer": ["D"], "analysis": "预算定额中人工工日消耗量是指在正常施工条件下，生产单位合格产品所必需消耗的人工工日数量，是由分项工程所综合的各个工序劳动定额包括的基本用工、其他用工两部分组成的。 (2)其他用工。其他用工是辅助基本用工消耗的工日，包括超运距用工、辅助用工和人工幅度差用工。 人工幅度差=(基本用工+辅助用工+超运距用工)×人工幅度差系数人工幅度差用工：(0.5+0.05+0.1)×10%=0.065(0.5+0.05+0.1+0.065)×10=7.15", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1163", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "(2010年)下列人工费用中，不属于预算定额基价构成内容的是()。", "options": {"A": "施工作业的生产工人工资", "B": "施工机械操作人员工资", "C": "工人夜间施工的夜班补助", "D": "大型施工机械安装与拆卸所发生的人工费"}, "answer": ["D"], "analysis": "预算定额基价的编制方法，简单说就是工、料、机的消耗量和工、料、机单价的结合过程。其中 ， 人工费是由预算定额中每一分项工程各种用工数，乘以地区人工工日单价之和算出；材料费是由预算定额中每一分项工程的各种材料消耗量，乘以地区相应材料预算价格之和算出；机具费是由预算定额中每一分项工程的各种机械台班消耗量，乘以地区相应施工机械台班预算价格之和，以及仪器仪表使用费汇总后算出。上述单价均为不含增值税进项税额的价格。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1164", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "(2016年)下列材料损耗，应计入预算定额材料损耗量的是()。", "options": {"A": "场外运输损耗", "B": "工地仓储损耗", "C": "一般性检验鉴定损耗", "D": "施工加工损耗"}, "answer": ["D"], "analysis": "材料损耗量，指在正常条件下不可避免的材料损耗，如现场内材料运输及施工操作过程中的损耗等。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1165", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "(2010年)下列工程中，属于概算指标编制对象的是()。", "options": {"A": "分项工程", "B": "单位工程", "C": "分部工程", "D": "整个建筑物"}, "answer": ["B"], "analysis": "(4)概算指标。概算指标是以单位工程为对象，反映完成一个规定计量单位建筑安装 .产品的经济指标。概算指标是概算定额的扩大与合并，以更为扩大的计量单位来编制的。概算指标的内容包括人工、材料、机具台班三个基本部分，同时还列出了分部工程量及单位工程的造价，是一种计价定额。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1166", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "(2013年)关于概算指标的编制，下列说法中正确的是()。", "options": {"A": "概算指标分为建筑安装工程概算指标和设备工器具概算指标", "B": "综合概算指标的准确性高于单项概算指标", "C": "单项形式的概算指标对工程结构形式可不作说明", "D": "构筑物的概算指标以预算书确定的价值为准，不必进行建筑面积换算"}, "answer": ["D"], "analysis": "概算指标分为建筑工程概算指标和设备及安装工程概算指标，所以选项A错；P90：综合概算指标的准确性和针对性不如单项指标，所以选项B错；单项概算指标的针对性较强，故指标中对工程结构形式要作介绍，所以选项C错。在计算完工程量，编出预算书后，不必进行换算。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1167", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "根据已建工程或现有工程的价格数据和资料，经分析、归纳和整理编制而形成的定额是（ ）。", "options": {"A": "预算定额", "B": "概算定额", "C": "概算指标", "D": "投资估算指标"}, "answer": ["D"], "analysis": "投资估算指标是根据已建工程或现有工程的价格数据和资料，经分析、归纳和整理编制而成的，而其他定额是按照一定的编制程序编制而成的，预算定额是以施工定额为基础综合扩大编制的，概算定额一般是在预算定额的基础上综合扩大而成的，概算指标是概算定额的扩大与合并。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1168", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "(2014年)下列对于测时法的特征描述中，正确的是（）。", "options": {"A": "测时法既适用于测定重复的循环工作时间，也适用于测定非循环工作时间", "B": "选择测时法比接续测时法准确、完善，但观察技术也较之复杂", "C": "当所测定的各工序的延续时间比较短时，接续测时法较选择测试法方便", "D": "测时法的观测次数应该根据误差理论和经验数据相结合的方法来确定"}, "answer": ["D"], "analysis": "确定观测次数较为科学的方法，应该是依据误差理论和经验数据相结合的方法来判断。测时法主要适用于测定定时重复的循环工作的工时消耗，是精确度比较高的一种计时观察法，一般可达到0.2～15s。测时法只用来测定施工过程中循环组成部分工作时间消耗，不研究工人休息、准备与结束及其他非循环的工作时间。 当所测定的各工序或操作的延续时间较短时，连续测定比较困难，用选择法测时比较方便且简单。 接续法测时也称作连续法测时。它比选择法测时准确、完善，但观察技术也较之复杂。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1169", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "(2016年)下列机械工作时间中，属于有效工作时间的是()。", "options": {"A": "筑路机在工作区末端的掉头时间", "B": "体积达标而未达到载重吨位的货物汽车运输时间", "C": "机械在工作地点之间的转移时间", "D": "装车数量不足而在低负荷下工作的时间"}, "answer": ["B"], "analysis": "有效工作的时间消耗中又包括正常负荷下、有根据地降低负荷下的工时消耗。有根据地降低负荷下的工作时间，是在个别情况下由于技术上的原因，机器在低于其计算负荷下工作的时间。例如，汽车运输重量轻而体积大的货物时，不能充分利用汽车的载重吨位因而不得不降低其计算负荷。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1170", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "(2016年)某出料容量750L的砂浆搅拌机，每一次循环工作中，运料、装料、搅拌、卸料、终端需要的时间分别为150s、40s、250s、50s、40s，运料和其他时间的交叠时间为50s，机械利用系数为0.8。该机械的台班产量定额为()m3/台班。", "options": {"A": "29.79", "B": "32.60", "C": "36.00", "D": "39.27"}, "answer": ["C"], "analysis": "该搅拌机一次循环的正常延续时间 =150+40+250+50+40-50=480s, 该搅拌机纯工作lh循环次数=3600/480=7.5h, 该搅拌机纯工作lh正常生产率=7.5×750=5625L=5.625m3, 该搅拌机台班产量定额=5.625×8×0.8=36m3.", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1173", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "(2013年)下列费用项目中，应计入进口材料运杂费中的是()。", "options": {"A": "国际运费", "B": "国际运输保险费", "C": "到岸后外埠中转运输费", "D": "进口环节税费"}, "answer": ["C"], "analysis": "材料运杂费是指国内采购材料自来源地、国外采购材料自到岸港运至工地仓库或指定堆放地点发生的费用。含外埠中转运输过程中所发生的一切费用和过境过桥费用。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1175", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "(2016年)若完成1m3墙体砌筑工作的基本工时为0.5工日，辅助工作时间占工序时间的4%，准备与结束工作时间、不可避免的中断时间、休息时间分别占工作时间的6%、3%和12%，该工程时间定额为()工日/m3。", "options": {"A": "0.581", "B": "0.608", "C": "0.629", "D": "0.659"}, "answer": ["D"], "analysis": "工序作业时间 =基本工作时间+辅助工作时间=基本工作时间/（1-辅助时间％）=0.5/(1-4%)=0.521，规范时间 = 准备与结束工作时间+不可避免的中断时间+休息时间，定额时间=工序作业时间/(1-规范时间%）=0.521/（1-6%-3%-12%）=0.659", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1176", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "(2017年)已知人工挖某土方1m3的基本工作时间为1个工作日，辅助工作时间占工序作业时间的5%，准备与结束工作时间、不可避免的中断时间、休息时间分别占工作日的3%、2%、15%，该人工挖土的时间定额为（）工日/10m3。", "options": {"A": "13.33", "B": "13.16", "C": "13.13", "D": "12.50"}, "answer": ["B"], "analysis": "本题考查的是确定人工定额消耗量的基本方法。 工序作业时间=基本工作时间/（1-辅助时间%）=1/（1-5%）=1.053（工日/m3） 时间定额=工序作业时间/（1-规范时间%）=1.053/（1-3%-2%-15%）=1.316（工日/m3）=13.16（工日/10m3）。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1177", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "某施工企业结合自身情况确定砌筑“1 砖混水砖墙”子目中人工消耗量。已知砌筑小组由3 名工人组成，在正常施工条件下，经测算完成10m3 砖墙砌筑耗时 小时。则在正常施工条件下，砌筑l0m3“l 砖混水砖墙”的劳动定额为（ ）工日。", "options": {"A": "5", "B": "15", "C": "40", "D": "120"}, "answer": ["B"], "analysis": "一个工作日按8 小时计算，则生产该产品的劳动定额由工人（小组）的人数和工作时间决定，即3×40／8=15 工日。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1178", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "某施工机械的产量定额为2.56（lOOm3／台班），与之配合的工人小组有4 人，则与该机械配合的人工时间定额为（ ）工日/100m3。", "options": {"A": "0.016", "B": "1.563", "C": "10.24", "D": "0.391"}, "answer": ["B"], "analysis": "与该机械配合的人工时间定额应为=4/2.56=1.563（工日／100m3)台班。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1179", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "已知某挖土机挖土的一个工作循环需2min，每循环一次挖土0.5m3，工作班的延续时间为8h，时间利用系数K=O.85，则该机械的产量定额为（ ）m3／台班。", "options": {"A": "12.8", "B": "15", "C": "102", "D": "120"}, "answer": ["C"], "analysis": "该挖土机械的小时生产率为60/2×0.5＝l5m3，则其产量定额为15×8×0.85＝102m3／台班。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1180", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "编制某施工机械台班使用定额，测定该机械小时的生产率为6 机械利用系数平均为80%，工作班延续时间为8 小时，则该机械的台班产量定额为（ ）。", "options": {"A": "64", "B": "60", "C": "48", "D": "38.4"}, "answer": ["D"], "analysis": "本题考查的是施工机械台班使用定额的编制。施工机械台班产量定额=机械生产率×工作班延续时间×机械利用系数=6×8×80%=38.4", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1181", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "(2010年)下列工程造价指数中，适合采用综合指数形式表示的是()。", "options": {"A": "设备、工器具价格指数", "B": "建筑安装工程造价指数", "C": "单项工程造价指数", "D": "建设项目造价指数"}, "answer": ["A"], "analysis": "设备工器具价格指数是用综合指数形式表示的总指数", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1182", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "(2013年)若以∑q1p0／∑q0p0为造价指数，则该指标属于()。", "options": {"A": "质量指标指数", "B": "派氏价格指数", "C": "以基期的质量指标作为同度量因素的指数", "D": "以报告期的质量指标作为同度量因素的指数"}, "answer": ["C"], "analysis": "题目中给出的表达式是拉氏数量指标，数量指标指数则应以基期的质量指标作为同度量因素。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1183", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "(2016年)下列工程造价指数，既属于总指数又可用综合指数形式表示的是()。", "options": {"A": "设备、工器具价格指数", "B": "建筑安装工程造价指数", "C": "单项工程造价指数", "D": "建设项目造价指数"}, "answer": ["A"], "analysis": "工器具价格指数。设备、工器具的种类、品种和规格很多。设备、工器具费用的变动通常是由两个因素引起的，即设备、工器具单件采购价格的变化和采购数量的变化，并且工程所采购的设备、工器具是由不同规格、不同品种组成的，因此，设备、工器具价格指数属于总指数。由于采购价格与采购数量的数据无论是基期还是报告期都比较容易获得，因此设备、工器具价格指数可以用综合指数的形式来表示。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1239", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "概算定额是确定完成合格的（ ）所需消耗的人工、材料和机械台班的数量标准。", "options": {"A": "分部(分项)工程", "B": "单位扩大分项工程", "C": "单位工程", "D": "单项工程"}, "answer": ["B"], "analysis": "概算定额是完成单位合格扩大分项工程，或扩大结构构件所需消耗的人工、材料、施工机具台班的数量及其费用标准。概算定额是一种计价定额，基本反映完成扩大分项工程的人、材、机消耗量及其相应费用，一般以预算定额为基础综合扩大编制而成，主要用于设计概算的编制。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1240", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "下列各项定额中，不属于按投用途分类的是（ ）定额。", "options": {"A": "企业", "B": "施工", "C": "预算", "D": "概算"}, "answer": ["A"], "analysis": "工程定额按照不同用途，可以分为施工定额、预算定额、概算定额、概算指标和估算指标等。按编制单位和执行范围的不同可以分为全国统一定额、行业定额、地区统一定额、企业定额、补充定额。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1241", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "关于工程造价的分布组合计价原理，下列说法正确的是（）。", "options": {"A": "分部分项工程费=基本构造单元工程量×工料单价", "B": "工料单价指人工、材料和施工机械台班单价", "C": "基本构造单元是由分部工程适当组合形成", "D": "工程总价是按规定程序和方法逐级汇总形成的工程造价"}, "answer": ["D"], "analysis": "分部分项工程费=基本构造单元工程量×相应单价，A错误；工料单价仅包括人工、材料、机具使用费用，是各种人工消耗量、各种材料消耗量、各类施工机具台班消耗量与其相应单价的乘积，B错误；基本构造单元是由分项工程分解或适当组合形成，C错误。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1242", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "施工组织设计是由（ ）根据施工特点、现场情况、施工工期等有关条件编制的，用来确定施工方案，布置现场，安排进度计价时应注意施工组织设计中影响工程费用的因素。", "options": {"A": "施工单位", "B": "监理单位", "C": "分包单位", "D": "设计单位"}, "answer": ["A"], "analysis": "施工组织设计是由施工单位根据施工特点、现场情况、施工工期等有关条件编制的，用来确定施工方案，布置现场，安排进度计价时应注意施工组织设计中影响工程费用的因素。考前黑钻押题，金考典软件考前更新，下载链接 www.jinkaodian.com", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1244", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "工程建设( )是编制建设项目建议书、可行性研究报告等前期工作阶段投资估算的依据。", "options": {"A": "投资估算指标", "B": "概算定额", "C": "预算定额", "D": "概算指标"}, "answer": ["A"], "analysis": "工程建设投资估算指标是编制项目建议书、可行性研究报告等前期工作阶段投资估算的依据，也可以作为编制固定资产长远规划投资额的参考。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1245", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "既是企业施工成本管理，也是企业编制工料计划的依据的定额是（ ）。", "options": {"A": "施工定额", "B": "概算指标", "C": "预算定额", "D": "概算定额"}, "answer": ["A"], "analysis": "施工定额是指完成一定计量单位的某一施工过程，或基本工序所需消耗的人工、材料和施工机具台班数量标准。施工定额是施工企业成本管理和工料计划的重要依据。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1246", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "下列不属于预算定额的确定编制细则工作的是（ ）。", "options": {"A": "统一计算口径、计量单位和小数点位数的要求", "B": "统一的名称、用字、专业用语", "C": "统一编制表格及编制方法", "D": "统一的工程量计算规则"}, "answer": ["D"], "analysis": "预算定额的确定编制细则。主要包括：统一编制表格及编制方法；统一计算口径、计量单位和小数点位数的要求；有关统一性规定，包括名称统一、用字统一、专业用语统一、符号代码统一，简化字要规范，文字要简练明确。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1247", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "既是编制项目建议书、可行性研究报告等前期工作阶段投资估算的依据，也可以作为编制固定资产长远规划投资额的参考的是（ ）。", "options": {"A": "工程建设投资估算指标", "B": "概算指标", "C": "预算定额", "D": "概算定额"}, "answer": ["A"], "analysis": "工程建设投资估算指标是编制项目建议书、可行性研究报告等前期工作阶段技资估算的依据，也可以作为编制固定资产长远规划投资额的参考。投资估算指标为完成项目建设的投资估算提供依据和手段，它在固定资产的形成过程中起着投资预测、投资控制、投资效益分析的作用，是合理确定项目投资的基础。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1248", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "基本建设管理部门编制投资估算、编制基本建设计划、估算主要材料用量计划的依据是（ ）。", "options": {"A": "概算指标", "B": "施工定额", "C": "预算定额", "D": "概算定额"}, "answer": ["A"], "analysis": "概算指标的主要作用： (1)是基本建设管理部门编制投资估算和编制基本建设计划，估算主要材料用量计划的依据； (2)是设计单位编制初步设计概算、选择设计方案的依据； (3)是考核基本建设投资效果的依据。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1249", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "关于概算定额的主要作用，下列说法不正确的是（ ）。", "options": {"A": "编制最高投标限价的依据", "B": "是编制预算定额的依据", "C": "是编制建设项目主要材料计划的参考依据", "D": "对设计项目进行技术经济分析和比较的基础资料之一"}, "answer": ["B"], "analysis": "概算定额的主要作用： (1)概算定额是扩大初步设计阶段编制设计概算和技术设计阶段编制修正概算的依据； (2)概算定额是对设计项目进行技术经济分析和比较的基础资料之一； (3)概算定额是编制建设项目主要材料计划的参考依据； (4)概算定额是编制概算指标的依据； (5)概算定额是编制最高投标限价的依据。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1250", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "预算定额的施工机械台班消耗指标的计量单位是台班，按现行规定，每个工作台班按机械工作（ ）小时计算。", "options": {"A": "5", "B": "6", "C": "8", "D": "12"}, "answer": ["C"], "analysis": "预算定额的施工机械台班消耗指标的计量单位是台班。按现行规定，每个工作台班按机械工作8小时计算。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1251", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "编制人工定额时，工人定额工作时间中应予以合理考虑的情况是（）。", "options": {"A": "由于水源或电源终端引起的停工时间", "B": "由于工程技术人员和工人差错引起的工时损失", "C": "由于劳动组织不合理导致工作中断所占用的时间", "D": "由于材料供应不及时引起的停工时间"}, "answer": ["A"], "analysis": "本题考查编制人工定额时需要考虑的因素。选项A提到了由于水源或电源终端引起的停工时间，这是在工作中可能会遇到的情况，需要在编制人工定额时考虑到，因此选项A是正确的。选项B提到的是由于技术和工人差错引起的工时损失，这是在工作中可能会出现的问题，但不是在编制人工定额时需要考虑的因素，因此选项B是错误的。选项C提到的是由于劳动组织不合理导致工作中断所占用的时间，这也是在工作中可能会出现的问题，但不是在编制人工定额时需要考虑的因素，因此选项C是错误的。选项D提到的是由于材料供应不及时引起的停工时间，这是在工作中可能会出现的问题，但不是在编制人工定额时需要考虑的因素，因此选项D是错误的。综上所述，本题的正确答案是A。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1252", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "在正常施工条件和合理使用材料的情况下，生产质量合格的单位产品所必须消耗的建筑安装材料的数量标准属于（ ）。", "options": {"A": "材料消耗定额", "B": "机械台班消耗定额", "C": "施工定额", "D": "概算定额"}, "answer": ["A"], "analysis": "材料消耗定额是指正常的施工条件和合理使用材料的情况下，生产质量合格的单位产品所必须消耗的建筑安装材料的数量标准。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1253", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "在编制材料消耗定额的基本方法中，（ ）比较适合计算块状、板状、卷状等材料的消耗量。", "options": {"A": "现场技术测定法", "B": "试验法", "C": "统计法", "D": "理论计算法"}, "answer": ["D"], "analysis": "理论计算法是运用一定的计算公式计算材料消耗量，确定消耗定额的一种方法。这种方法较适合计算块状、板状、卷状等材料的消耗量。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1254", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "若完成某分项工程需要某种材料的净耗量为t，损耗率为5%，那么，必需消耗量为（ ）t。", "options": {"A": "0．8", "B": "0．95", "C": "1．05", "D": "0．9975"}, "answer": ["D"], "analysis": "又因为：材料消耗定额(材料总消耗量)=材料消耗净用量+材料损耗量得，材料消耗定额(材料总消耗量)=0．95t×5%+0．95t=0．9975t", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1255", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "编制材料消耗定额的基本方法中，用（ ）主要是为了取得编制材料损耗定额的资料。", "options": {"A": "统计法", "B": "试验法", "C": "现场技术测定法", "D": "理论计算法"}, "answer": ["C"], "analysis": "现场技术测定法主要是为了取得编制材料损耗定额的资料。材料消耗中的净用量比较容易确定，但材料消耗中的损耗量不能随意确定，需通过现场技术测定来区分哪些属于难以避免的损耗，哪些属于可以避免的损耗，从而确定出较准确的材料损耗量。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1256", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "编制材料消耗定额的基本方法中，（ ）可获得材料消耗的各项数据，用以编制材料消耗定额。", "options": {"A": "理论计算法", "B": "统计法", "C": "试验法", "D": "现场技术测定法"}, "answer": ["B"], "analysis": "统计法中通过对现场用料的大量统计资料进行分析计算的一种方法。用该方法可获得材料消耗的各项数据，用以编制材料消耗定额。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1257", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "修磨校验工具、移动工作梯、工人转移工作地点等所需时间属于（ ）。", "options": {"A": "辅助工作时间", "B": "由于施工工艺特点引起的工作中断时间", "C": "施工本身造成的停工时间", "D": "准备与结束工作时间"}, "answer": ["A"], "analysis": "辅助工作时间是指为了保证基本工作顺利完成而同技术操作无直接关系的辅助性工作时间。如修磨校验工具、移动工作梯、工人转移工作地点等所需时间。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1258", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "施工机械工作时间中的不可避免的中断时间应属于（ ）。", "options": {"A": "有效工作时间", "B": "停工时间", "C": "不可避免的无负荷工作时间", "D": "定额时间"}, "answer": ["D"], "analysis": "不可避免的中断时间是与工艺过程的特点、机械使用中的保养、工人休息等有关的中断时间。如汽车装卸货物的停车时间，给机械加油的时间，工人休息时的停机时间。是必须消耗的时间，属于定额时间。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1259", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "1m31 砖厚砖墙中若材料为标准砖， 灰缝厚度为 10mm， 砖损耗率为 2%， 砂浆损耗率为 1%， 则砂浆消耗量为（ ） m3。", "options": {"A": "0.062", "B": "0.081", "C": "0.205", "D": "0.228"}, "answer": ["D"], "analysis": "每立方米砖墙净用砖量=2/(0.24×(0.115+0.01)×(0.053+0.01))=2/(0.24×0.125×0.063)≈529.1块。砖体积=529.1×0.24×0.115×0.053=0.7737m³。净砂浆=1-0.7737=0.2263m³。砂浆消耗量=0.2263×(1+1%)=0.228m³。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1260", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "（ ），重视现场调查研究和技术分析，有一定的科学技术依据，制定定额的准确性较好。", "options": {"A": "经验估计法", "B": "技术测定法", "C": "统计分析法", "D": "比较类推法"}, "answer": ["B"], "analysis": "本题考查的是劳动定额。技术测定法重视现场调查研究和技术分析，有一定的科学技术依据，制定定额的准确性较好，定额水平易达到平衡，可发现和揭露生产中的实际问题。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1261", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "某混凝土构件采用木模板施工，木模板一次净用量为 200 ㎡，现场制作安装不可避免的损耗率为 2％，木模板可周转使用 5 次，每次补损率为 5％，则木模板的周转使用量为（）㎡。", "options": {"A": "48.00", "B": "48.96", "C": "49.44", "D": "51.00"}, "answer": ["B"], "analysis": "本题考查的是周转性材料消耗定额的编制。 一次使用量＝净用量×（1＋操作损耗率） 200×（1+2%）×[1+（5-1）×5%]/5=48.96 ㎡", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1262", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "某混凝土构件采用木模板施工， 木模板一次使用量为 204 ㎡， 木模板可周转使用 5 次， 每次补损率为 5％，则木模板的周转使用量为（ ） ㎡。", "options": {"A": "48.00", "B": "48.96", "C": "49.44", "D": "51.00"}, "answer": ["B"], "analysis": "每次使用后，木模板的可用面积为204×(1-5%)=193.8㎡，经过5次周转使用后，可用面积为193.8×5=969㎡。 因此，木模板的周转使用量为969㎡。 选项中，只有B选项的答案为48.96，符合要求，故选B。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1263", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "通过对施工过程的具体活动进行实地观察，详细记录工人和机械的工作时间消耗、完成产品数量及有关影响因素,再对所获得的资料进行分析，制定出人工定额的方法是（）。", "options": {"A": "统计分析法", "B": "比较类推法", "C": "技术测定法", "D": "经验估计法"}, "answer": ["C"], "analysis": "技术测定法是根据生产技术和施工组织条件，对施工过程中各工序采用测时法、写实记录法、工作日写实法，测出各工序的工时消耗等资料，再对所获得的资料进行科学的分析，制定出人工定额的方法。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1264", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "在人工定额的损失时间里，工人在工作班内消耗的工作时间属于人工损失时间的是（ ）。", "options": {"A": "休息时间", "B": "停工时间", "C": "不可避免的中断时间", "D": "准备与结束工作时间"}, "answer": ["B"], "analysis": "损失时间是与产品生产无关，而与施工组织和技术上的缺点有关，最新题库，考前【黑钻押题】，金考典软件考前更新，下载链接 www.jinkaodian.com与工人在施工过程中的个人过失或某些偶然因素有关的时间消耗。包括： 1)多余和偶然工作时间； 2)停工时间； 3)违反劳动纪律的损失时间。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1265", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "在相同类型的项目中，选择有代表性的典型项目，然后根据测定的定额用比较类推的方法编制其他相关定额的一种方法是（ ）。", "options": {"A": "经验估计法", "B": "统计分析法", "C": "比较类推法", "D": "技术测定法"}, "answer": ["C"], "analysis": "比较类推法是在相同类型的项目中选择有代表性的典型项目，然后根据测定的定额用比较类推的方法编制其他相关定额的一种方法。 经验估计法是根据定额员、技术员、生产管理人员和老工人的实际工作经验，对生产某一产品或完成某项工作所需的人工、施工机具、材料数量进行分析、讨论和估算，并最终确定定额耗用量的一种方法 。 统计分析法就是根据过去生产同类型产品、零件的实作工时或统计资料，经过整理和分析，考虑今后企业生产技术组织条件的可能变化来制定定额的方法。最新题库，考前【黑钻押题】，金考典软件考前更新，下载链接 www.jinkaodian.com 技术测定法是通过对施工过程的具体活动进行实地观察，详细记录工人和机械的工作时间消耗、完成产品数量及有关影响因素，并将记录结果予以研究、分析，去伪存真，整理出可靠的原始数据资料，为制定定额提供科学依据的一种方法。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1266", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "某砼输送泵每小时纯工作状态可输送砼25m3,泵的时间利用系数为0.75则该砼输送泵的产量定额为（）。", "options": {"A": "150m3/台班", "B": "0.67台班/100m3", "C": "200m/台班", "D": "0.50台班/100m"}, "answer": ["A"], "analysis": "", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1267", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "某吊装设备配驾驶员1人，当年制度工作日为250天，年工作台班为220台班，人工日工资单价为80元。该吊装设备的台班人工费为（ ）元。", "options": {"A": "80．57", "B": "90．91", "C": "76．33", "D": "85．20"}, "answer": ["B"], "analysis": "台班人工费=人工消耗量×[1+(年度工作日一年工作台班)／年工作台班]×人工单价=1×[1+(250—220)／220]×80元=90．91元", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1268", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "某大型施工机械预算价格为5万元，机械耐用总台班为1250台班，检修周期数为4，一次检修费为2000元，维护费系数为60%，机上人工费和燃料动力费为60元/台班。不考虑残值和其他有关费用，则该机械台班单价为（ ）元/台班。", "options": {"A": "107.68", "B": "110.24", "C": "112.80", "D": "52.80"}, "answer": ["A"], "analysis": "本题考查的是施工机具台班单价。台班折旧费＝机械预算价格/耐用总台班＝50000/1250＝40（元/台班） 检修费＝2000×（4-1）/1250＝4.8（元/台班） 维护费＝4.8×60%＝2.88（元/台班） 则机械台班单价＝40＋4.8＋2.88＋60＝107.68（元/台班）", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1269", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "某装修公司采购一批花岗石，运至施工现场，已知该花岗石出厂价为1000元／m2，运杂费30元／m2，当地造价管理部门规定材料采购及保管费率为1%，该花岗石的预算价格为（ ）元／m2。", "options": {"A": "1034", "B": "1040．3", "C": "1044．34", "D": "1054．68"}, "answer": ["B"], "analysis": "材料预算价格=[(材料原价+运杂费)×(1+运输损耗费)]×(1+采购及保管费率)=(1000+30)元/m2×(1+1%)=1040．3元/m2。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1270", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "某施工机械预计使用15年，耐用总台班数为2100台班，使用期内检修次数是4次，一次检修费为5000元，则台班检修费为（ ）元。", "options": {"A": "9．52", "B": "10．23", "C": "8．65", "D": "9．68"}, "answer": ["A"], "analysis": "得：台班检修费=（5000*4）/2100=9.52元", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1271", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "分别反映各类工程的人工、材料、施工机械及主要设备报告期价格对基期价格的变化程度指标的是（ ）。", "options": {"A": "月指数", "B": "综合造价指数", "C": "单项价格指数", "D": "时点造价指数"}, "answer": ["C"], "analysis": "单项价格指数反映各类工程的人工费、材料费、施工机具使用费报告期价格对基期价格的变化程度的指标。可利用它研究主要单项价格变化的情况及其发展变化的趋势。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1272", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "最能体现工程计价信息变化特征，在工程价格的市场机制中起重要作用的工程计价信息是（ ）。", "options": {"A": "综合单价和定额资料", "B": "标准规范和政策文件", "C": "定额资料和材料、设备价格", "D": "价格信息、工程造价指数和已完工程信息"}, "answer": ["D"], "analysis": "从广义上说，所有对工程造价的计价过程起作用的资料都可以称为是工程计价信息，如各种定额资料、标准规范、政策文件等。但最能体现信息动态性变化特征，并且在工程价格的市场机制中起重要作用的工程计价信息主要包括价格信息、工程造价指数和已完工程信息三类。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1273", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "工人的工作时间中，熟悉施工图纸所消耗的时间属于（ ）。", "options": {"A": "基本工作时间", "B": "辅助工作时间", "C": "准备与结束工作时间", "D": "不可避免的中断时间"}, "answer": ["C"], "analysis": "本题考查的是施工过程分解及工时研究。准备与结束工作时间：可分为班内的准备与结束工作时间和任务的准备与结束工作时间。其时间长短往往与工作内容有关。熟悉图纸、准备相应工具、事后清理现场。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1274", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "下列建筑服务中，不可以选择按照简易办法计税的有（ ）。", "options": {"A": "一般纳税人以清包工方式提供的建筑服务", "B": "一般纳税人为甲供工程提供的建筑服务", "C": "一般纳税人为建筑工程老项目提供的建筑服务", "D": "一般纳税人为建筑工程新项目提供的建筑服务"}, "answer": ["D"], "analysis": "本题考查的是按费用构成要素划分建筑安装工程费用项目构成和计算。简易计税适用范围：（1）小规模纳税人发生应税行为适用简易计税方法计税；（2）一般纳税人以清包工方式提供的建筑服务；（3）一般纳税人为甲供工程提供的建筑服务；（4）一般纳税人为建筑工程老项目提供的建筑服务。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1275", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "预算定额中的人工消耗指标是指完成该分项工程必须消耗的各种用工，（ ）指施工现场发生的加工材料等的用工。", "options": {"A": "基本用工", "B": "材料超运距用工", "C": "人工幅度差", "D": "辅助用工"}, "answer": ["D"], "analysis": "辅助用工指施工现场发生的加工材料等的用工。如筛砂子、淋石灰膏的用工。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1276", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "关于工程量清单计价，下列计价公式中不正确的是（ ）。", "options": {"A": "单位工程直接费＝∑（假定建筑安装产品工程量×工料单价）", "B": "分部分项工程费＝∑（分部分项工程量×分部分项工程综合单价）", "C": "措施项目费＝∑按“项”计算的措施项目费＋∑（措施项目工程量×措施项目综合单价）", "D": "单位工程报价＝分部分项工程费＋措施项目费＋其他项目费＋规费＋增值税"}, "answer": ["A"], "analysis": "本题考查的是工程计价方法。单位工程直接费属于定额计价的内容，不属于清单计价要计算的内容。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1830", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "计算工程用工、用料和机械台班消耗的基本单元是（ ）。", "options": {"A": "单项工程", "B": "单位工程", "C": "分部工程", "D": "分项工程"}, "answer": ["D"], "analysis": "【考点来源】本题考查的是建设工程项目组成与分类【选项分析】分项工程是工程项目施工生产活动的基础，也是计算工程用工、用料和机械台班消耗的基本单元。", "tags": [], "source": "一、工程项目组成和分类", "src": "好题库"}, {"id": "ht_mgmt_1844", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "采用工程量清单计价模式的施工图预算编制方法是（ ）。", "options": {"A": "工料单价法", "B": "综合单价法", "C": "成本加酬金法", "D": "定额计价法"}, "answer": ["B"], "analysis": "【考点来源】本题考查的是施工图预算的编制方法【选项分析】综合单价法是适应市场经济条件的工程量清单计价模式下的施工图预算编制方法。", "tags": [], "source": "三、施工图预算的编制方法", "src": "好题库"}, {"id": "ht_mgmt_1847", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "在工程量清单计价中使用十二位数字来表示项目编码，其中分部工程顺序码是（ ）。", "options": {"A": "一、二位", "B": "五、六位", "C": "七—九位", "D": "十—十二位"}, "answer": ["B"], "analysis": "【考点来源】本题考查的是项目编码【选项分析】第一级：一、二位为工程分类码（也称专业工程代码）；第二级：三、四位为附录分类顺序码；第三级：五、六位为分部工程顺序码。第四级：七~九位为分项工程顺序码；第五级：十~十二位为清单项目名称顺序码。", "tags": [], "source": "二、分部分项工程项目清单", "src": "好题库"}, {"id": "ht_mgmt_1848", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "工程量清单计价方式中，区分清单项目的依据是（ ）。", "options": {"A": "项目名称", "B": "工程数量", "C": "项目特征", "D": "计量单位"}, "answer": ["C"], "analysis": "【考点来源】本题考查的是项目特征【选项分析】项目特征是构成分部分项工程量清单项目、措施项目自身价值的本质特征。项目特征是区分清单项目的依据，是确定一个清单项目综合单价的重要依据，是履行合同义务的基础。", "tags": [], "source": "二、分部分项工程项目清单", "src": "好题库"}, {"id": "ht_mgmt_1849", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "根据《陕西省建设工程工程量清单计价规则》，清单项目工程量的计量单位采用（ ）。", "options": {"A": "定额计量单位", "B": "基本计量单位", "C": "修正计量单位", "D": "比较计量单位"}, "answer": ["B"], "analysis": "【考点来源】本题考查的是计量单位【选项分析】分部分项工程量清单的计量单位应按规定的计量单位确定，清单项目工程量的计量单位均采用基本计量单位。", "tags": [], "source": "二、分部分项工程项目清单", "src": "好题库"}, {"id": "ht_mgmt_1850", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "根据《陕西省建设工程工程量清单计价规则》，下列内容中不应列入其他项目清单价的是（ ）。", "options": {"A": "暂列金额", "B": "总承包服务费", "C": "专业工程暂估价", "D": "分包工程费用"}, "answer": ["D"], "analysis": "【考点来源】本题考查的是其他项目清单【选项分析】其他项目清单包括暂列金额、专业工程暂估价、计日工和总承包服务费。不包含分包工程费用。", "tags": [], "source": "四、其他项目清单", "src": "好题库"}, {"id": "ht_mgmt_1851", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "某施工机械设备原价为 1440 万元，预付备料款额度为 25%，主要材料及构配件费用占工程造价的 60%，则预付备料款起扣点为（ ）万元。", "options": {"A": "400", "B": "800", "C": "840", "D": "880"}, "answer": ["C"], "analysis": "【考点来源】本题考查的是工程预付款的扣还【选项分析】Q=1440-(1440×25%)/(60%)=840。", "tags": [], "source": "二、预付款及期中支付", "src": "好题库"}, {"id": "mgmt_hqwx_0228", "date": "2026-07-09", "chapter": "g04", "type": "single", "stem": "已知国内制造厂某非标准设备所用材料费、加工费、辅助材料费、专用工具费、废品损失费共20万元，外购配套费3万元，非标准设备设计费1万元，包装费率1%，利润率为8%，若其他费用不考虑，则该设备的原价为（ ）。", "options": {"A": "25.82万元", "B": "25.85万元", "C": "26.09万元", "D": "29.09万元"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是设备购置费 【选项分析】设备原价=[（20+3）*1.01-3）]*1.08+1+3=25.85万元。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0229", "date": "2026-07-09", "chapter": "g04", "type": "single", "stem": "进口设备的原价是指进口设备的（ ）。", "options": {"A": "到岸价", "B": "抵岸价", "C": "离岸价", "D": "运费在内价"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是设备购置费 【选项分析】进口设备的原价是指进口设备的抵岸价，即设备抵达买方边境、港口或车站，交纳完各种手续费、税费后形成的价格。抵岸价通常是由进口设备到岸价（CIF）和进口从属费构成。进口设备的到岸价，即抵达买方边境港口或边境车站的价格。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0230", "date": "2026-07-09", "chapter": "g04", "type": "single", "stem": "某进口设备人民币货价400万元，国际运费折合人民币30万元，运输保险费率为3‰，则该设备应计的运输保险费折合人民币（ ）万元。", "options": {"A": "1.200", "B": "1.204", "C": "1.290", "D": "1.294"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是设备购置费 【选项分项】 (400+30)/ (1-3‰) ×3‰=1.29388 (万元)。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0234", "date": "2026-07-09", "chapter": "g04", "type": "single", "stem": "下列费用项目中，应在研究试验费中列支的是（ ）。", "options": {"A": "为验证设计数据而进行必要的研究试验所需的费用", "B": "新产品试验费", "C": "施工企业技术革新的研究试验费", "D": "重要科学研究补助费"}, "answer": ["A"], "analysis": "【内容考查】本题考查的是与项目建设有关的其他费用 【选项分析】研究试验费是指为建设项目提供或验证设计数据、资料等进行必要的研究试验及按照相关规定在建设过程中必须进行试验、验证所需的费用。包括自行或委托其他部门研究试验所需人工费、材料费、试验设备及仪器使用费等。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0237", "date": "2026-07-09", "chapter": "g04", "type": "single", "stem": "研究试验费不包括（ ）。", "options": {"A": "自行勘察试验所需的人工费、材料费", "B": "自行勘察试验所需的试验设备及仪器使用费", "C": "按规定付给商品检验部门的进口设备检验鉴定费", "D": "委托其他部门研究试验所需的人工费、材料费、试验设备及仪器使用费"}, "answer": ["C"], "analysis": "【内容考查】本题考查的是与项目建设有关的其他费用 【选项分项】研究试验费是指为建设项目提供或验证设计数据、资料等进行必要的研究试验及按照相关规定在建设过程中必须进行试验、验证所需的费用。包括自行或委托其他部门研究试验所需人工费、材料费、试验设备及仪器使用费等。这项费用按照设计单位根据本工程项目的需要提出的研究试验内容和要求计算。在计算时要注意不应包括以下项目： （1）应由科技三项费用（即新产品试制费、中间试验费和重要科学研究补助费）开支的项目。 （2）应在建筑安装费用中列支的施工企业对建筑材料、构件和建筑物进行一般鉴定、检查所发生的费用及技术革新的研究试验费。 （3）应由勘察设计费或工程费用中开支的项目。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0243", "date": "2026-07-09", "chapter": "g04", "type": "single", "stem": "在下列各种定额中，以工序为研究对象的是（ ）。", "options": {"A": "概算定额", "B": "施工定额", "C": "预算定额", "D": "投资估算指标"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是工程定额的原理和作用 【选项分析】施工定额是指完成一定计量单位的某一施工过程，或基本工序所需消耗的人工、材料和施工机具台班数量标准。施工定额是施工企业成本管理和工料计划的重要依据。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0244", "date": "2026-07-09", "chapter": "g04", "type": "single", "stem": "影响工程造价计价的两个主要因素是（ ）。", "options": {"A": "单位价格和实物工程量", "B": "单位价格和单位消耗量", "C": "资源市场单价和单位消耗量", "D": "资源市场单价和措施项目工程量"}, "answer": ["A"], "analysis": "【内容考查】本题考查的是工程计价的基本方法 【选项分析】影响工程造价的主要因素是两个，即单位价格和实物工程数量。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0245", "date": "2026-07-09", "chapter": "g04", "type": "single", "stem": "工程造价的计价依据按用途分类可以分为7大类，其中计算设备费依据的是（ ）。", "options": {"A": "各项工程建设其他费用定额", "B": "设备价格、运杂费率等", "C": "间接费定额", "D": "概算指标、概算定额、预算定额"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是工程计价依据的分类 【选项分项】计算设备费的依据：设备价格、运杂费率等。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0246", "date": "2026-07-09", "chapter": "g04", "type": "single", "stem": "陕西真题-综合反映现象总规模和水平变化情况的指数是（ ）。", "options": {"A": "质量指标指数", "B": "综合指数", "C": "数量指标指数", "D": "平均数指数"}, "answer": ["C"], "analysis": "﻿【内容考查】本题考查的是指数的分类 【选项分析】 数量指标指数是综合反映现象总的规模和水平变化情况的指数。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0247", "date": "2026-07-09", "chapter": "g04", "type": "single", "stem": "工程造价信息是由若干具有特定内容和同类性质的、在一定时间和空间内形成的一连串信息，这体现了工程造价信息的（ ）特点。", "options": {"A": "系统性", "B": "多样性", "C": "专业性", "D": "动态性"}, "answer": ["A"], "analysis": "【内容考查】本题考查的是工程造价信息的概念和特点 【选项分项】系统性：工程造价信息是由若干具有特定内容和同类性质的、在一定时间和空间内形成的一连串信息。一切工程造价的管理活动和变化总是在一定条件下受各种因素的制约和影响。工程造价管理工作也同样是多种因素相互作用的结果，并且从多方面被反映出来，因而从工程造价信息源发出来的信息都不是孤立、紊乱的，而是大量的、有系统的。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0251", "date": "2026-07-09", "chapter": "g04", "type": "single", "stem": "“工程造价信息应针对不同层次管理者的要求进行适当加工，针对不同管理层提供不同要求和浓缩程度的信息。”这体现了工程造价信息管理应遵循的（ ）原则。", "options": {"A": "标准化", "B": "有效性", "C": "定量化", "D": "高效处理"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是工程计价信息的动态管理 【选项分项】有效性原则是工程造价信息应针对不同层次管理者的要求进行适当加工，针对不同管理层提供不同要求和浓缩程度的信息。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0253", "date": "2026-07-09", "chapter": "g04", "type": "single", "stem": "关于多层民用住宅工程造价与其影响因素的关系，下列说法中正确的是（ ）。", "options": {"A": "层数增加，单位造价降低", "B": "层高增加，单位造价降低", "C": "通常情况下，建筑物周长系数越低，造价越低", "D": "宽度增加，单位造价上升"}, "answer": ["C"], "analysis": "建筑物层数对造价的影响因建筑类型、形式和结构不同而不同。如果增加一个楼层不影响建筑物的结构形式，单位建筑面积的造价可能会降低。 建筑周长系数k周是指建筑物周长与建筑面积比，即单位建筑面积所占外墙长度，通常情况下建筑周长系数越低，设计越经济。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0254", "date": "2026-07-09", "chapter": "g04", "type": "single", "stem": "关于建筑设计对工业项目造价的影响,下列说法正确的有（ ）。", "options": {"A": "建筑周长系数越高,单位面积造价越低", "B": "单跨厂房柱间距不变,跨度越大,单位面积造价越低", "C": "多跨厂房跨度不变,中跨数目越多,单位面积造价越高", "D": "随着建筑物体积和面积的增加，工程总造价会降低"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是工程设计阶段影响造价的主要因素 【选项分析】通常情况下，建筑周长系数越低，设计越经济；对于单跨厂房，当柱间距不变时，跨度越大单位面积造价越低；对于多跨厂房，当跨度不变时，中跨数目越多越经济；对于高层或者超高层结构，框架结构和剪力墙结构比较经济；随着建筑物体积和面积的增加，工程总造价会提高。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0256", "date": "2026-07-09", "chapter": "g04", "type": "single", "stem": "确定项目建设规模时，应该考虑的首要因素是（ ）。", "options": {"A": "市场因素", "B": "生产技术因素", "C": "管理技术因素", "D": "环境因素"}, "answer": ["A"], "analysis": "【内容考查】本题考查的是工程决策阶段影响造价的主要因素 【选项分析】市场因素是确定建设规模需考虑的首要因素。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0259", "date": "2026-07-09", "chapter": "g04", "type": "single", "stem": "在满足住宅功能和质量的前提下，下列设计手法中，可降低单位建筑面积造价的是（ ）。", "options": {"A": "增加住宅层高", "B": "分散布置公共设施", "C": "增大墙体面积系数", "D": "减少结构面积系数"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是工程设计阶段影响造价的主要因素 【选项分项】衡量单元组成、户型设计的指标是结构面积系数(住宅结构面积与建筑面积之比) ,系数越小设计方案越经济。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0262", "date": "2026-07-09", "chapter": "g04", "type": "single", "stem": "工程项目经济评价中，财务分析依据的基础数据是根据（ ）确定的。", "options": {"A": "完全市场竞争下的价格体系", "B": "影子价格和影子工资", "C": "最优资源配置下的价格体系", "D": "现行价格体系"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是建设项目经济评价 【选项分项】财务分析是在国家现行财税制度和价格体系的前提下，从项目的角度出发，计算项目范围内的财务效益和费用，分析项目的盈利能力和清偿能力，评价项目在财务上的可行性。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0264", "date": "2026-07-09", "chapter": "g04", "type": "single", "stem": "项目建设规模的影响因素不包括（ ）。", "options": {"A": "市场因素", "B": "技术因素", "C": "工艺流程", "D": "环境因素"}, "answer": ["C"], "analysis": "【内容考查】本题考查的是工程决策阶段影响造价的主要因素 【选项分项】项目规模的合理选择关系着项目的成败，决定着工程造价合理与否，其制约因素有：市场因素、技术因素、环境因素。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0291", "date": "2026-07-09", "chapter": "g04", "type": "single", "stem": "采用概算定额法编制设计概算的主要工作有：①列出分部分项工程项目名称并计算工程量；②搜集基础资料；③编写概算编制说明；④计算措施项目费；⑤确定各分部分项工程费；⑥汇总单位工程概算造价。下列工作排序正确的是（ ）。", "options": {"A": "②①⑤④⑥③", "B": "②③①⑤④⑥", "C": "③②①④⑤⑥", "D": "②①③⑤④⑥"}, "answer": ["A"], "analysis": "【内容考查】本题考查的是单位工程概算的编制方法 【选项分项】利用概算定额编制概算的具体步骤如下：1 ) 熟悉图纸，了解设计意图、施工条件和施工方法。2 ) 按照概算定额的分部分项顺序，列出分部工程（或扩大分项工程或扩大结构构件）的项目名称，并计算工程量。3 ) 确定各分部工程项目的概算定额单价。4 ) 根据分部工程的工程量和相应的概算定额单价计算人工、材料、机械费用。5 ) 计算企业管理费、利润和增值税。6 ) 计算单位工程概算造价。7 ) 编写概算编制说明。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0303", "date": "2026-07-09", "chapter": "g04", "type": "single", "stem": "运用实物量法编制施工图预算的工作有：①计算其他费用，汇总工程造价②划分工程项目和计算工程量③套用定额消耗量，计算人工、材料、机械台班消耗量。④熟悉图纸等设计文件和预算定额⑤计算并汇总单位工程的人工费、材料费和施工机具使用费，下列工作排序正确的是（ ）。", "options": {"A": "④②⑤①③", "B": "④⑤①②③", "C": "②④⑤①③", "D": "④②③⑤①"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是施工图预算的编制方法 【选项分项】实物量法编制施工图预算的基本步骤如下： （1）编制前的准备工作。 （2）熟悉图纸等设计文件和预算定额。 （3）了解施工组织设计和施工现场情况。 （4）划分工程项目和计算工程量。 （5）套用定额消耗量，计算人工、材料、机械台班消耗量。 （6）计算并汇总单位工程的人工费、材料费和施工机具使用费。 （7）计算其他费用，汇总工程造价。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0318", "date": "2026-07-09", "chapter": "g04", "type": "single", "stem": "某工程项目合同约定采用调值公式法进行结算，合同价为50万元，其中可调部分为：人工费占15%，材料费占60%，其他为不可调部分。结算时，人工费价格指数上涨了10%，材料价格指数上涨了20%，则该项目应结算的价款为（ ）万元。", "options": {"A": "56", "B": "56.35", "C": "57", "D": "56.75"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是《建设工程施工合同（示范文本）》的主要内容 【选项分析】因为，可调部分 人工费占15%，材料费占60%，所以，固定部分占得比例为25%。 50×[25%+15%×(1+10%)+60%×(1+20%)]=56.75万元。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0335", "date": "2026-07-09", "chapter": "g04", "type": "single", "stem": "招标控制价是招标人根据国家或省级、行业建设主管部门颁发的有关计价依据和方法，以及拟定的招标文件和招标工程量清单，结合工程具体情况编制的招标工程的（ ）。", "options": {"A": "最低投标限价", "B": "最高投标限价", "C": "参考价", "D": "目标价"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是最高投标限价概述 【选项分析】招标控制价是招标人根据国家或省级、行业建设主管部门颁发的有关计价依据和方法，以及拟定的招标文件和招标工程里清单，结合工程具体情况编制的招标工程的最高投标限价。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "gl-g04-010", "date": "2026-07-08", "chapter": "g04", "type": "multiple", "stem": "人工单价的构成内容包括（ ）。", "options": {"A": "基本工资", "B": "工资性补贴", "C": "生产工人辅助工资", "D": "职工福利费", "E": "生产工人社会保险费"}, "answer": ["A", "B", "C", "D"], "analysis": "人工单价=基本工资+工资性补贴+生产工人辅助工资+职工福利费+生产工人劳动保护费。E选项生产工人社会保险费属于规费，不直接计入人工单价。劳动保护费是人工单价组成部分，但社会保险费属于规费。", "tags": ["人工单价", "构成"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g04-011", "date": "2026-07-08", "chapter": "g04", "type": "multiple", "stem": "材料单价的构成内容包括（ ）。", "options": {"A": "材料原价", "B": "材料运杂费", "C": "运输损耗费", "D": "采购及保管费", "E": "材料检验试验费"}, "answer": ["A", "B", "C", "D"], "analysis": "材料单价=材料原价（或供应价格）+材料运杂费+运输损耗费+采购及保管费。E选项材料检验试验费属于企业管理费，不属于材料单价构成。", "tags": ["材料单价", "构成"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g04-012", "date": "2026-07-08", "chapter": "g04", "type": "multiple", "stem": "施工机械台班单价的构成内容包括（ ）。", "options": {"A": "折旧费", "B": "大修理费", "C": "经常修理费", "D": "燃料动力费", "E": "企业管理费分摊"}, "answer": ["A", "B", "C", "D"], "analysis": "机械台班单价=折旧费+大修理费+经常修理费+安拆费及场外运费+燃料动力费+人工费+税费。E选项企业管理费分摊不属于台班单价构成，在计算综合单价时另行计取。", "tags": ["台班单价", "构成"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g04-017", "date": "2026-07-08", "chapter": "g04", "type": "multiple", "stem": "下列定额中，按编制程序和用途分类的有（ ）。", "options": {"A": "施工定额", "B": "预算定额", "C": "概算定额", "D": "投资估算指标", "E": "劳动定额"}, "answer": ["A", "B", "C", "D"], "analysis": "按编制程序和用途分类，定额体系包括：施工定额→预算定额→概算定额→概算指标→投资估算指标。E选项劳动定额是按生产要素分类的（劳动定额、材料消耗定额、机械台班定额）。", "tags": ["定额分类", "计价依据"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g04-023", "date": "2026-07-08", "chapter": "g04", "type": "multiple", "stem": "工程造价指数主要包括（ ）。", "options": {"A": "价格指数", "B": "成本指数", "C": "造价综合指数", "D": "人工费指数", "E": "施工定额指数"}, "answer": ["A", "B", "C", "D"], "analysis": "工程造价指数主要包括价格指数、成本指数、造价综合指数、人工费指数、材料费指数、机械使用费指数等各类分类指数。E选项施工定额指数不属于造价指数的标准类别。", "tags": ["造价指数", "工程造价信息"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g04-025", "date": "2026-07-08", "chapter": "g04", "type": "multiple", "stem": "关于综合单价的构成，下列说法正确的有（ ）。", "options": {"A": "包含人工费、材料费、施工机具使用费", "B": "包含企业管理费和利润", "C": "包含规费和增值税", "D": "包含一定范围内的风险费用", "E": "是工程量清单计价的核心"}, "answer": ["A", "B", "D", "E"], "analysis": "综合单价=人工费+材料费+施工机具使用费+企业管理费+利润+一定范围内的风险费用。C选项不正确，规费和增值税不作为综合单价组成部分，在单位工程造价中另行计算。", "tags": ["综合单价", "工程量清单计价"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g04-026", "date": "2026-07-08", "chapter": "g04", "type": "multiple", "stem": "按生产要素分类，工程建设定额可以分为（ ）。", "options": {"A": "劳动定额", "B": "材料消耗定额", "C": "机械台班定额", "D": "预算定额", "E": "概算定额"}, "answer": ["A", "B", "C"], "analysis": "按生产要素分类，定额分为劳动定额（人工定额）、材料消耗定额和机械台班定额三大类。D和E是按编制程序和用途分类的定额。", "tags": ["定额分类", "生产要素"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-057", "date": "2026-07-08", "chapter": "g04", "type": "multiple", "stem": "工程量清单计价中，综合单价包含的费用有（ ）。", "options": {"A": "人工费", "B": "材料费", "C": "施工机具使用费", "D": "企业管理费", "E": "规费和税金"}, "answer": ["A", "B", "C", "D"], "analysis": "综合单价=人工费+材料费+施工机具使用费+企业管理费+利润+风险费用。规费和税金在综合单价之外单独列项，选项E不应选。", "tags": ["计价方法", "综合单价"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-058", "date": "2026-07-08", "chapter": "g04", "type": "multiple", "stem": "关于定额计价与工程量清单计价的区别，下列说法正确的有（ ）。", "options": {"A": "定额计价采用工料单价法，清单计价采用综合单价法", "B": "定额计价中工程量由招标人提供，清单计价中工程量由投标人计算", "C": "定额计价反映社会平均水平，清单计价体现市场竞争", "D": "定额计价风险由发包人承担，清单计价风险由承包人承担", "E": "定额计价基于政府发布的预算定额，清单计价基于企业定额或市场价"}, "answer": ["A", "C", "E"], "analysis": "A、C、E正确。B错误：定额计价中工程量由投标人自行计算，清单计价中工程量由招标人提供。D错误：风险分担不同，但并非完全由某一方承担。", "tags": ["计价方法", "定额计价vs清单计价"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-059", "date": "2026-07-08", "chapter": "g04", "type": "multiple", "stem": "我国工程计价依据体系的五级内容包括（ ）。", "options": {"A": "施工定额", "B": "预算定额", "C": "费用定额", "D": "概算定额", "E": "概算指标", "F": "投资估算指标"}, "answer": ["A", "B", "D", "E", "F"], "analysis": "五级计价体系：施工定额→预算定额→概算定额→概算指标→投资估算指标。费用定额不属于该五级体系。", "tags": ["计价依据体系", "五级体系"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-060", "date": "2026-07-08", "chapter": "g04", "type": "multiple", "stem": "施工定额的主要作用包括（ ）。", "options": {"A": "编制施工预算", "B": "签发施工任务单和限额领料单", "C": "编制施工图预算", "D": "企业内部成本核算与控制", "E": "编制设计概算"}, "answer": ["A", "B", "D"], "analysis": "施工定额是企业内部定额，用于编制施工预算、签发任务单和限额领料单、内部成本控制核算。C施工图预算用预算定额，E设计概算用概算定额/指标。", "tags": ["计价依据体系", "施工定额"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-061", "date": "2026-07-08", "chapter": "g04", "type": "multiple", "stem": "预算定额中人工消耗量指标的组成部分包括（ ）。", "options": {"A": "基本用工", "B": "辅助用工", "C": "超运距用工", "D": "管理用工", "E": "人工幅度差"}, "answer": ["A", "B", "C", "E"], "analysis": "预算定额人工消耗量=基本用工+辅助用工+超运距用工+人工幅度差。管理用工属于企业管理费范畴。", "tags": ["预算定额消耗量", "人工组成"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-062", "date": "2026-07-08", "chapter": "g04", "type": "multiple", "stem": "施工机具台班单价的组成内容包括（ ）。", "options": {"A": "折旧费", "B": "大修理费", "C": "经常修理费", "D": "燃料动力费", "E": "机上人工费"}, "answer": ["A", "B", "C", "D", "E"], "analysis": "机具台班单价=折旧费+大修理费+经常修理费+安拆费及场外运费+人工费（机上司机等）+燃料动力费+税费。所给选项全部正确。", "tags": ["机具台班单价", "组成内容"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-063", "date": "2026-07-08", "chapter": "g04", "type": "multiple", "stem": "人工日工资单价由（ ）组成。", "options": {"A": "计时工资或计件工资", "B": "奖金", "C": "津贴补贴", "D": "加班加点工资", "E": "特殊情况下支付的工资"}, "answer": ["A", "B", "C", "D", "E"], "analysis": "人工单价=计时/计件工资+奖金+津贴补贴+加班加点工资+特殊情况下支付的工资。五项全部正确。", "tags": ["人工单价", "组成内容"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-064", "date": "2026-07-08", "chapter": "g04", "type": "multiple", "stem": "企业管理费的计算基数可以依据不同专业工程选择（ ）。", "options": {"A": "直接费", "B": "人工费+施工机具使用费", "C": "人工费", "D": "材料费", "E": "间接费"}, "answer": ["A", "B", "C"], "analysis": "企业管理费计算基数有三种：直接费、人工费+施工机具使用费（广东方案）、人工费。材料费不作为单独基数。", "tags": ["费用定额", "企业管理费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-065", "date": "2026-07-08", "chapter": "g04", "type": "multiple", "stem": "规费包括的内容有（ ）。", "options": {"A": "养老保险费", "B": "医疗保险费", "C": "住房公积金", "D": "工程排污费", "E": "企业管理费"}, "answer": ["A", "B", "C", "D"], "analysis": "规费=社会保险费（养老+医疗+失业+工伤+生育）+住房公积金+工程排污费。企业管理费不属于规费。", "tags": ["费用定额", "规费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-066", "date": "2026-07-08", "chapter": "g04", "type": "multiple", "stem": "预算定额与施工定额的对比，正确的有（ ）。", "options": {"A": "预算定额的水平是社会平均水平，施工定额是平均先进水平", "B": "预算定额中包含了人工幅度差，施工定额中不包含", "C": "预算定额的人工消耗量大于施工定额", "D": "施工定额是编制预算定额的基础", "E": "预算定额的材料损耗量小于施工定额"}, "answer": ["A", "B", "C", "D"], "analysis": "A、B、C、D均正确。E错误：预算定额材料损耗量一般大于等于施工定额，因为预算定额考虑了更全面的损耗因素。", "tags": ["预算定额消耗量", "定额关系"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-067", "date": "2026-07-08", "chapter": "g04", "type": "multiple", "stem": "材料预算单价由（ ）组成。", "options": {"A": "材料原价", "B": "材料运杂费", "C": "运输损耗费", "D": "采购及保管费", "E": "材料试验费"}, "answer": ["A", "B", "C", "D"], "analysis": "材料单价=(材料原价+运杂费)×(1+运输损耗率)×(1+采购保管费率)。材料试验费属于企业管理费中的检验试验费。", "tags": ["材料单价", "组成内容"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g04-068", "date": "2026-07-08", "chapter": "g04", "type": "multiple", "stem": "关于劳动定额和材料消耗定额，以下计算关系正确的有（ ）。", "options": {"A": "时间定额=1/产量定额", "B": "材料总用量=净用量×(1+损耗率)", "C": "损耗率=损耗量/总用量×100%", "D": "1台班=8小时", "E": "材料总用量=净用量×(1-损耗率)"}, "answer": ["A", "B", "D"], "analysis": "A、B、D正确。C错误：损耗率=损耗量/净用量×100%。E错误：总用量=净用量×(1+损耗率)，不是减。", "tags": ["劳动定额", "材料消耗", "公式辨析"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "ht_mgmt_1185", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "工程量清单计价中，措施项目的综合单价由完成规定计量单位工程量清单项目所需（）等费用组成。", "options": {"A": "人工费、材料费和施工机具使用费", "B": "管理费", "C": "规费", "D": "利润", "E": "税金"}, "answer": ["A", "B", "D"], "analysis": "综合单价是指完成一个规定计量单位的分部分项工程量清单项目或措施清单项目所需的人工费、材料费、施工机械使用费和企业管理费与利润，以及一定范围内的风险费用。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1186", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "下列工程造价管理活动中，属于工程量清单计价活动的是()。", "options": {"A": "工程支付", "B": "合同价款调整", "C": "工程计价争议处理", "D": "竣工决算", "E": "投标报价"}, "answer": ["A", "B", "C", "E"], "analysis": "工程量清单计价活动涵盖施工招标、合同管理以及竣工交付全过程，主要包括：编制招标工程量清单、招标控制价、投标报价，确定合同价，进行的工程计量与价款支付、合同价款调整、工程结算和工程计价争议处理等活动。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1187", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "根据分部组合计价原理，单位工程可依据（）等的不同分解为分部工程。", "options": {"A": "结构部位", "B": "路段长度", "C": "施工特点", "D": "材料", "E": "工序"}, "answer": ["A", "B", "C"], "analysis": "单位工程可以按照结构部位、路段长度及施工特点或施工任务分解为分部工程。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1188", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "编制清单时，可以依据施工组织设计、施工规范、验收规范确定的要素有()。", "options": {"A": "项目名称", "B": "项目编码", "C": "项目特征", "D": "计量单位", "E": "工程量"}, "answer": ["A", "C", "E"], "analysis": "图 2.1.2 工程量清单的编制程序", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1189", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "下列各种定额中，定额水平为社会平均水平的有()。", "options": {"A": "施工定额", "B": "预算定额", "C": "概算定额", "D": "概算指标", "E": "投资估算指标"}, "answer": ["B", "C", "D", "E"], "analysis": "选项A，施工定额的定额水平为社会平均先进水平。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1190", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "下列关于工程量清单计价程序和方法的说法中，正确的是( )。", "options": {"A": "编制建设工程造价的基本过程只有工程量计算", "B": "工程量清单计价要历经工程量清单编制和工程量清单应用两个阶段", "C": "工程量清单在发承包阶段的应用主要是用来编制招标控制价、投标报价和工程计量、工程结算和工程计价纠纷的解决", "D": "招标控制价和投标报价的编制依据相同", "E": "综合单价由人工费、材料和工程设备费、施工机具使用费、企业管理费、利润及一， 定范围内的风险费用组成"}, "answer": ["B", "E"], "analysis": "本题考查的是工程计价基本程序。工程量清单在发承包阶段的应用包括招标控制价和投标报价的编制，工程量计算、工程结算等属于施工阶段的应用，所以C错误。投标报价的编制依据包括企业定额，招标控制价的编制依据不包括企业定额，所以D错误。工程量清单计价的过程可以分为两个阶段，即工程量清单的编制和工程量清单的应用两个阶段，", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1191", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "按定额的编制程序和用途，建设工程定额可划分为（）。", "options": {"A": "施工定额", "B": "企业定额", "C": "预算定额", "D": "补充定额", "E": "投资估算指标"}, "answer": ["A", "C", "E"], "analysis": "2.按定额的编制程序和用途分类可以把工程定额分为施工定额、预算定额、概算定额、概算指标、投资估算指标等。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1192", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "下列关于各类工程计价定额的说法中，正确的有（）。", "options": {"A": "预算定额以现行劳动定额和施工定额为编制基础", "B": "概、预算定额的基价一般由人工、材料和机械台班费用组成", "C": "概算指标可分为建筑工程概算指标、设备及安装工程概算指标", "D": "投资估算指标主要以概算定额和概算指标为编制基础", "E": "单位工程投资估算指标中仅包括建筑安装工程费"}, "answer": ["A", "B", "C", "E"], "analysis": "(5)投资估算指标。投资估算指标是以建设项目、单项工程、单位工程为对象，反映建设总投资及其各项费用构成的经济指标。它是在项目建议书和可行性研究阶段编制投资估算、计算投资需要量时使用的一种定额。它的概略程度与可行性研究阶段相适应。投资估算指标往往根据历史的预、决算资料和价格变动等资料编制，但其编制基础仍然离不开预算定额、概算定额。故D错误。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1193", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "下列措施项目中，应按分部分项工程量清单编制方式编制的有( )。", "options": {"A": "超高施工增加", "B": "建筑物的临时保护设施", "C": "大型机械设备进出场及安拆", "D": "已完工程及设备保护", "E": "施工排水、降水"}, "answer": ["A", "C", "E"], "analysis": "本题考查的是措施项目清单的编制。有些措施项目是可以计算工程量的项目，如脚手架工程，混凝土模板及支架（撑），垂直运输、超高施工增加，大型机械设备进出场及安拆，施工排水、降水等，这类措施项目按照分部分项工程量清单的方式采用综合单价计价，更有利于措施费的确定和调整。措施项目中可以计算工程量的项目清单宜采用分部分项工程量清单的方式编制。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1195", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "分部分项工程量清单的项目特征应按“清单计价规范”附录中规定的项目特征，结合( )予以详细而准确的表述和说明。", "options": {"A": "技术规范", "B": "工程内容", "C": "标准图集", "D": "施工图纸", "E": "安装位置"}, "answer": ["A", "C", "D", "E"], "analysis": "项目特征是构成分部分项工程项目、措施项目自身价值的本质特征。项目特征是对项目的准确描述，是确定一个清单项目综合单价不可缺少的重要依据，是区分清单项目的依据，是履行合同义务的基础。分部分项工程量清单的项目特征应按各专业工程计量规范附录中规定的项目特征，结合技术规范、标准图集、施工图纸，按照工程结构、使用材质及规格或安装位置等，予以详细而准确的表述和说明。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1196", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "根据《房屋建筑与装饰工程工程量计算规范》GB50584的规定，下列属于可以精确计算工程量的措施项目有( )。", "options": {"A": "施工排水、施工降水", "B": "垂直运输", "C": "冬雨季施工", "D": "安全文明施工", "E": "大型机械设备进出场及安拆"}, "answer": ["A", "B", "E"], "analysis": "但是有些措施项目则是可以计算工程量的项目，如脚手架工程，混凝土模板及支架 （撑）， 垂直运输，超高施工增加，大型机械设备进出 场及安拆，施工排水、降水等，这类措施项目按照分部分项工程项目清单的方式采用综合 单价计价，更有利于措施费的确定和调整。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1197", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "下列各项关于其他项目清单的编制，说法正确的有( )。", "options": {"A": "暂列金额是预见肯定要发生而暂时无法明确数额的费用项目", "B": "专业工程暂估价应包括除增值税以外的所有综合单价构成内容", "C": "需要纳入分部分项工程量清单项目综合单价中的暂估价只是材料费和工程设备费", "D": "总承包服务费包括总承包人为分包工程及自行采购材料、设备发生的管理费用", "E": "招标人应预计总承包服务费并按投标人的投标报价向投标人支付该项费用"}, "answer": ["C", "E"], "analysis": "选项A错误，暂列金额是指招标人在工程量清单中暂定并包括在合同价款中的一笔款项。用于工程合同签订时尚未确定或者不可预见的所需材料、工程设备、服务的采购，施工中可能发生的工程变更、合同约定调整因素出现时的合同价款调整，以及发生的索赔、现场签证确认等的费用。选项B错误，专业工程的暂估价一般应是综合暂估价，同样包括人工费、材料费、施工机具使用费、企业管理费和利润，不包括增值税。选项C正确，为方便合同管理，需要纳入分部分项工痗量清单项目综合单价中的暂估价应只是材料、工程设备暂估单价，以方便投标人组价。选项D错误，总承包服务费是指总承包人为配合协调发包人进行的专业工程发包，对发包人自行采_购的材料、工程设备等进行保管以及施工现场管理、竣工资料汇总整理等服务所需的费用。招标人应预计该项费用并按投标人的投标报价向投标人支付该项费用。选项E正确。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1198", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "关于措施项目工程量清单编制与计价，下列说法中正确的是( )。", "options": {"A": "不能计算工程量的措施项目也可以采用分部分项工程量清单方式编制", "B": "安全文明施工费按总价方式编制，其计算基础可为“定额基价”、“定额人工费”", "C": "总价措施项目清单表应列明计量单位、费率、金额等内容", "D": "安全文明施工费计算基础可为“定额人工费”", "E": "按施工方案计算的总价措施项目可以只需填“金额”数值"}, "answer": ["B", "D"], "analysis": "本题考查的是措施项目清单的编制。不能计算工程量的项目（总价措施项目），以“项”为计量单位进行编制（如表 2.2.2 所示) 。表2.2.2 总价措施项目清单与计价表 注1、“计算基础”中安全文明施工费可为“定额基价”、“定额人工费”或“定额人工费+定额机具使用费”，其他项目可为“定额人工费”或“定额人工费+定额机具费”。2、按施工方案计算的措施费，若无“计算基础”和“费率”的数值，也只填“金额”数值，但应在备注栏说明施工方案出处或计算方法。表2.2.2总价措施项目清单与计价表，可知应列明计算基础、费率、金额等内容。因此C错。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1199", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "根据《建设工程工程量清单计价规范》的规定，其他项目清单的暂列金额部分包括()。", "options": {"A": "施工合同签订时不可预见的所需材料采购费用", "B": "总承包服务费", "C": "尚未确定的所需服务的采购费用", "D": "材料的暂估单价", "E": "合同约定的可能发生的工程价款调整费用"}, "answer": ["A", "C", "E"], "analysis": "暂列金额是指用于施工合同签订时尚未确定或者不可预见的所需材料、设备、服务的采购，施工中可能发生的工程变更、合同约定调整因素出现时的工程价款调整以及发生的索赔、现场签证确认等的费用。因此，ACE选项符合要求。考试注意区分暂列金额和暂估价。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1201", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "分部分项工程项目清单必须根据专业工程计量规范规定的（）进行编制。", "options": {"A": "项目编码", "B": "项目名称", "C": "项目特征", "D": "计算费率", "E": "计量单位"}, "answer": ["A", "B", "C", "E"], "analysis": "分部分项工程项目清单必须载明项目编码、项目名称、项目特征、计量单位和工程量。分部分项工程项目清单必须根据各专业工程计量规范规定的项目编码、项目名称、项目特征、计量单位和工程量计算规则进行编制。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1202", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "单位工程投资估算指标的表示方式中，管道以“元/m”并区分( )表示。", "options": {"A": "结构形式", "B": "材质", "C": "容积", "D": "面层", "E": "管径"}, "answer": ["B", "E"], "analysis": "单位工程指标一般以如下方式表示：房屋区别不同结构形式以“元／㎡”表示；道路 区别不同结构层、面层以“元／㎡”表示；水塔区别不同结构层、容积以元／座表示；管道区别不同材 质、管径以“元/m”表示。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1203", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "下列有关概算定额与概算指标关系的表述中，正确的是（）。", "options": {"A": "概算定额以单位工程为对象，概算指标以单项工程为对象", "B": "概算定额以预算定额为基础，概算指标主要来自各种预算和结算资料", "C": "概算定额适用于初步设计阶段，概算指标不适用于初步设计阶段", "D": "概算指标比概算定额更加综合与扩大", "E": "概算定额是编制概算指标的依据"}, "answer": ["B", "D", "E"], "analysis": "建筑安装工程概算定额与概算指标的主要区别如下：（1）确定各种消耗量指标的对象不同。概算定额是以单位扩大分项工程或单位扩大结构构件为对象，而概算指标则是以单位工程为对象。因此概算指标比概算定额更加综合与扩大。（2）确定各种消耗量指标的依据不同。概算定额以现行的概算定额为基础，通过计算之后才综合确定出各种消耗量指标，而概算指标中各种消耗量指标的确定，则主要来自各种预算或结算资料。（7）概算定额是编制概算指标的依据，所以E正确", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1204", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "预算定额中人工、材料、机械台班消耗量的确定方法包括（）。", "options": {"A": "以施工定额为基础确定", "B": "以现场观察测定资料为基础计算", "C": "以工程量计算规则为依据计算", "D": "以各类费用定额为基础确定", "E": "以工程结算资料为依据计算"}, "answer": ["A", "B"], "analysis": "预算定额中人工、材料、机械台班消耗水平，需要根据劳动定额或施工定额取定;人工的工日数可以有两种确定方法，一种是以劳动定额为基础确定;另一种是以现场观察测定资料为基础计算。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1205", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "下列用工项目中，构成预算定额人工工日消耗量但并不包括在施工定额中的有（）。", "options": {"A": "材料水平搬运用工", "B": "材料加工用工和电焊点火用工", "C": "工序交接时对前一工序修整用工", "D": "在施工定额基础上应增加计算的用工", "E": "完成施工任务必须消耗的技术工程用工"}, "answer": ["B", "C", "D"], "analysis": "本题考核预算定额与施工定额人工工日消耗量的差别。包括基本用工中的按劳动定额应增减的用工 量和其他用工（超运距用工、辅助用工和人工幅度差）。 3)工程开工或收尾时工作量不饱满所损失的时间； 4)检查工程质量影响机械操作的时间； 5)临时停机、停电影响机械操作的时间； 6)机械维修引起的停歇时间。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1206", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "编制预算定额时，机械台班消耗量中机械幅度差的内容包括（）。", "options": {"A": "机械维修引起的停歇时间", "B": "停电引起的机械停歇时间", "C": "机械在施工中不可避免的工序间歇", "D": "机械工作量不饱满增加的时间", "E": "机械低负荷下增加的工作时间"}, "answer": ["A", "B", "C"], "analysis": "该题考核机械台班消耗量中机械幅度差的内容。其内容包括:施工机械转移工作面及配套机械相互影 响损失的时间;在正常施工条件下，机械在施工中不可避免的工序间歇;工程开工或收尾时工作量不饱满所损失的时间;检查工程质量影响机械操作的时间；临时停机、停电影响机械操作的时间;机械维修引起的停歇时间。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1207", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "下列与施工机械工作相关的时间中，应包括在预算定额机械台班消耗量中，但不包括在施工定额中的有（）。", "options": {"A": "低负荷下工作时间", "B": "正常施工时 机械施工不可避免的工序间歇", "C": "机械维修引起的停歇时间", "D": "开工时工作量不饱满所损失的时间", "E": "不可避免的中断时间"}, "answer": ["B", "C", "D"], "analysis": "机械台班幅度差是指在施工定额中所规定的范围内没有包括，而在实际施工中又不可避免产生的影响机械或使机械停歇的时间。其内容包括：（1）施工机械转移工作面及配套机械相互影响损失的时间。（2）在正常施工条件下，机械在施工中不可避免的工序间歇。（3）工程开工或收尾时工作量不饱满所损失的时间。（4）检查工程质量影响机械操作的时间。（5）临时停机、停电影响机械操作的时间。（6）机械维修引起的停歇时间。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1208", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "下列工人工作时间中，虽属于损失时间，但在拟定定额时又要适度考虑它的影响的是()。", "options": {"A": "施工本身导致的停工时间", "B": "非施工本身导致的停工时间", "C": "不可避免的中断时间", "D": "多余工作时", "E": "偶然工作时间"}, "answer": ["B", "E"], "analysis": "本题考查的是工作时间消耗的相关内容。在损失时间中，由于偶然工作能获得一定产品，拟定定额时要适当考虑它的影响。非施工本身造成的停工时间，是由于水源、电源中断引起的停工时间，定额中应给予合理的考虑。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1209", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "关于测定时间消耗的工作日写实法的特点的说法中，正确的有()。", "options": {"A": "工作日写实法用于检查定额执行情况时，需要测定3～4次", "B": "能够获得整个工作班内各种工时的消耗量", "C": "工作日写实法用于编制定额时，需要记录产品数量和影响工时消耗的各种因素", "D": "记录时间需要将有效工作时间分成不同组成部分", "E": "应按工时消耗性质分类记录各类工时消耗量"}, "answer": ["B", "C", "E"], "analysis": "工作日写实法，是一种研究整个工作班内的各种工时消耗的方法。运用工作日写实法主要有两个目的，一是取得编制定额的基础资料；二是检查定额的执行情况，找出缺点，改进工作。当用于第一个目的时，通常需要测定3～4次；当用于第二个目的时通常需要测定1～3次。工作日写实法，利用写实记录表记录观察资料。记录时间时不需要将有效工作时间分为各个组成部分，只需划分适合于技术水平和不适合于技术水平两类。但是工时消耗还需按性质分类记录。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1210", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "挂贴墙面花岗岩板材的施工中，所用下列材料属于形成工程实体材料的有()。", "options": {"A": "花岗石板材", "B": "水泥砂浆", "C": "钢龙骨", "D": "脚手架", "E": "安全网"}, "answer": ["A", "B", "C"], "analysis": "本题考查的是实体材料的概念。实体材料，是指直接构成工程实体的材料。它包括工程直接性材料和辅助材料。工程直接性材料主要是指一次性消耗、直接用于工程上构成建筑物或结构本体的材料。非实体材料是指在施工中必须使用但又不能构成工程实体的施工措施性材料。非实体材料主要是指周转性材料，如模板、脚手架等。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1211", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "在定额的测定中，写实记录法是测定时间定额的常用方法，其特点包括()。", "options": {"A": "主要适用于测定定时重复的循环工作", "B": "能够获得分析工作时间消耗和制定定额必需的全部资料", "C": "能够通过测定检查定额的执行情况", "D": "能反映工人或机器工作日工时消耗的全部情况", "E": "观测对象可以是一个工人，也可以是一个工人小组"}, "answer": ["B", "E"], "analysis": "写实记录法，可以获得分析工作时间消耗和制定定额所必需的全部资料。写实记录法的观察对象，可以是一个工人，也可以是一个工人小组。能反映工人或机具工作日全部情况。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1212", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "施工中材料的消耗分为必需消耗的材料和损失的材料，在确定材料定额消耗量时，必需消耗的材料包括()。", "options": {"A": "直接用于建筑和安装工程的材料", "B": "不可避免的场外运输损耗材料", "C": "不可避免的场内运输损耗材料", "D": "不可避免的现场仓储损耗材料", "E": "不可避免的施工过程中损耗材料"}, "answer": ["A", "C", "E"], "analysis": "，本题考查的是材料消耗的分类。必需消耗的材料，是指在合理用料的条件下，生产合格产品所需消耗的材料。它包括：直接用于建筑和安装工程的材料；不可避免的施工废料；不可避免的材料损耗。必需消耗的材料属于施工正常消耗，是确定材料消耗定额的基本数据。其中：直接用于建筑和安装工程的材料，编制材料净用量定额；不可避免的施工废料和材料损耗，编制材料损耗定额", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1213", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "确定施工时间定额时，下列工人工作时间可以计入定额时间的有()。", "options": {"A": "机手并动下的辅助工作时间", "B": "准备与结束工作的时间", "C": "与施工过程工艺特点有关的工作中断时间", "D": "必需的休息时间", "E": "施工本身造成的停工时间"}, "answer": ["B", "C", "D"], "analysis": "工人工作时间分为必需消耗的时间和损失时间。编制定额时，必需消耗的时间计入定额，损失时间不能计入定额（偶然工作时间和非承包商原因的停工损失时间可给予适当考虑），本题中施工本身造成的停工时间属于损失时间，机手并动下的辅助工作时间计入机械运转，其他属于必需消耗的时间。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1214", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "下列施工工作的时间分类选项中，属于工人有效工作时间的有（）。", "options": {"A": "基本工作时间", "B": "休息时间", "C": "辅助工作时间", "D": "准备与结束工作时间", "E": "不可避免的中断时间"}, "answer": ["A", "C", "D"], "analysis": "有效工作时间是从生产效果来看与产品生产直接有关的时间消耗。其中包括基本工作时间、辅助工作时间、准备与结束工作时间的消耗。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1215", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "通过计时观察，完成某工程的基本工作时间为6h／m3，辅助工作时间占工序作业时间的8%,准备与结束工作时间、不可避免的中断时间、休息时间分别占工作班时间的3%、10%、2%，则下列计算结果中正确的有（）。", "options": {"A": "基本工作时间为0.750 工日／m3", "B": "工序作业时间为0.815 工日／m3", "C": "辅助工作时间为0.060 工日／m3", "D": "规范时间为0.122 工日／m3", "E": "定额时间为0.959 工日／m3"}, "answer": ["A", "B", "E"], "analysis": "工序时间=基本工作时间＋辅助工作时间，基本工作时间=6／8=0.75（工日／m3） 工序作业时间=0.75＋8%×工序时间=0.815（工日／m3） 辅助工作时间=0.815×8%=0.065（工日／m3） 定额时间=工序作业时间／（1－规范时间％）=0.815／（1－15%）=0.959（工日／m3） 规范时间=准备与结束工作时间＋不可避免的中断时间＋休息时间=（3%＋10%＋2%）×0.959=0.144（工日／m3）", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1216", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "下列费用项目中，计算施工机械台班单价时应考虑的有()。", "options": {"A": "购置机械的资金成本", "B": "检修费", "C": "维护费", "D": "机械设备的财产损失保险费", "E": "大型机械安拆费"}, "answer": ["B", "C"], "analysis": "施工机械台班单价由七项费用组成，包括折旧费、检修费、维护费、安拆费及场外运费、人工费、燃料动力费和其他费用。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1217", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "下列费用项目中，构成施工仪器仪表台班单价的有（）。", "options": {"A": "折旧费", "B": "检修费", "C": "维护费", "D": "人工费", "E": "校验费"}, "answer": ["A", "C", "E"], "analysis": "施工仪器仪表台班单价由四项费用组成，包括折旧费、维护费、校验费、动力费。施工仪器仪表台班单价中的费用组成不包括检测软件的相关费用", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1218", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "下列材料单价的构成费用，包含在采购及保管费中进行计算的有()。", "options": {"A": "运杂费", "B": "仓储费", "C": "工地保管费", "D": "运输损耗", "E": "仓储损耗"}, "answer": ["B", "C", "E"], "analysis": "采购及保管费是指组织材料采购、检验、供应和保管过程中发生的费用，包含采购费、仓储费、工地保管费和仓储损耗。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1219", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "下列费用包含或可能包含在材料价格中材料运杂费的是()。", "options": {"A": "附加工作费", "B": "装卸费", "C": "运输损耗", "D": "调车费", "E": "运输费"}, "answer": ["A", "B", "D", "E"], "analysis": "材料运杂费包含外埠中转运输过程中发生的一切费用和过境过桥费用，包括调车和驳船费、装卸费、运输费及附加工作费。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1220", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "下列属于预算定额机械台班消耗量中机械幅度差的是()。", "options": {"A": "施工机械转移工作面及配套机械相互影响损失的时间", "B": "机械维修引起的停歇时间", "C": "工程收尾时工作量不饱满造成的机械停歇时间", "D": "在正常施工条件下，机械在施工中不可避免的工序间歇时间", "E": "运输车辆在装货和卸货时的停车时间"}, "answer": ["A", "B", "C", "D"], "analysis": "机械台班幅度差一般包括：施工机械转移及配套机械相互影响损失的时间；在正常施工条件下，机械在施工中不可避免的工序间歇；工程收尾和工程量不饱满造成的机械停歇时间；因检查工程质量造成的机械停歇的时间；临时停机、停电影响机械操作的时间；机械维修引起的停歇时间。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1221", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "下列有关定额编制的描述中，符合预算定额简明适用原则的是()。", "options": {"A": "对于主要工种、主要项目、常用项目，定额步距要大些", "B": "对于不常用的、价值量小的项目，分项工程划分可以粗些", "C": "要注意补充因采用新技术、新材料而出现的新的定额项目", "D": "要合理确定预算定额计量单位，避免一量多用", "E": "尽可能多留活口，以适应不同条件下，调整使用定额的需要"}, "answer": ["B", "C", "D"], "analysis": "预算定额的编制应遵循简明适用的原则，简明适用一是指在编制预算定额时，对于那些主要的，常用的、价值量大的项目，分项工程划分宜细；次要的、不常用的、价值量相对较小的项目则可以粗一些。二是指预算定额要项目齐全。要注意补充那些因采用新技术、新结构、新材料而出现的新的定额项目。如果项目不全，缺项多，就会使计价工作缺少充足的可靠的依据。三是要求合理确定预算定额的计算单位，简化工程量的计算，尽可能地避免同一种材料用不同的计量单位和一量多用，尽量减少定额附注和换算系数。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1222", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "确定预算定额人工工日消耗量过程中，应计入其他用工的有（）。", "options": {"A": "材料二次搬运用工", "B": "点焊点火用工", "C": "按劳动定额规定应增（减）计算的用工", "D": "临时水电线路移动造成的停工", "E": "完成某一分项工程所需消耗的技术工种用工"}, "answer": ["B", "D"], "analysis": "(2)其他用工。其他用工是辅助基本用工消耗的工日，包括超运距用工、辅助用工和人工幅度差用工。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1223", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "建设工程定额中的周转材料消耗量指标，应该用（）等指标表示。", "options": {"A": "一次使用量", "B": "摊销量", "C": "周转使用次数", "D": "最终回收量", "E": "理论净用量"}, "answer": ["A", "B"], "analysis": "定额中周转材料消耗量指标，应当用一次使用量和摊销量两个指标表示。一次使用量供施工企业组织施工用；摊销量供施工企业成本核算或投标报价使用。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1224", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "制定材料消耗定额时，确定材料净用量的方法有（）", "options": {"A": "理论计算法", "B": "测定法", "C": "图纸计算法", "D": "评估法", "E": "经验法"}, "answer": ["A", "B", "C", "E"], "analysis": "材料净用量确定方法：（1）理论计算法；（2）测定法；（3）图纸计算法；（4）经验法。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1225", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "施工作业的定额时间，是在拟定基本工作时间和（）的基础上编制的。", "options": {"A": "偶然时间", "B": "辅助工作时间", "C": "准备与结束时间", "D": "不可避免的中断时间", "E": "休息时间"}, "answer": ["B", "C", "D", "E"], "analysis": "施工作业的定额时间，是在拟定基本工作时间、辅助工作时间、准备与结束时间、不可避免的中断时间，以及休息时间的基础上编制的。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1226", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "建设项目或单项工程造价指数的计算式中包含（）。", "options": {"A": "各类单项价格指数", "B": "设备、工器具价格指数", "C": "建筑安装工程造价指数", "D": "工程建设其他费用指数", "E": "各类单位工程价格指数"}, "answer": ["B", "C", "D"], "analysis": "建设项目或单项工程造价指数是由设备、工器具价格指数，建筑安装工程造价指数，工程建设其他费用指数综合得到的。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1227", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "下列关于设备、工器具价格指数的说法正确的有（）。", "options": {"A": "质量指标指数应当以报告期的数量指标作为同度量因素", "B": "拉斯贝尔体系以基期价格为同度量", "C": "派许体系主张采用报告期指标作为同度量因素", "D": "设备、工器具价格指数是平均数指数形式", "E": "设备、工器具价格指数同度量的方法有拉斯贝尔体系和派许体系两种形式"}, "answer": ["A", "C"], "analysis": "拉斯贝尔体系主张采用基期指标作为同度量因素，所以B 错误;设备工器具价格指数是用综合指数形式表示的总指数，所以D 错误;因同度量因素选择的不同，可分为拉斯贝尔体系和派许体系，所以E 错误。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1228", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "下列工程造价指数中，采用平均数指数形式编制的有（）。", "options": {"A": "各种单项价格指数", "B": "设备、工器具价格指数", "C": "建筑安装工程价格指数", "D": "单项工程造价指数", "E": "建设项目造价指数"}, "answer": ["C", "D", "E"], "analysis": "建设项目或单项工程造价指数是由建筑安装工程造价指数，设备、工器具价格指数和工程建设其他费用指数综合而成的，与建筑安装工程造价指数相类似，其计算也应采用加权调和平均数指数的推导公式。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1229", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "把各种不能直接相加的现象还原为价值形态，先相加再相除，用以反映观测对象变化趋势的指数属于()。", "options": {"A": "个体指数", "B": "环比指数", "C": "价格指数", "D": "综合指数", "E": "总指数"}, "answer": ["D", "E"], "analysis": "综合指数主要解决不同度量单位的问题，使不能直接加总的不同使用价值的各种商品或产品的总体，改变成为能够进行对比的两个时期的现象的总体。综合指数可以把各种不能直接相加的现象还原为价值形态，先综合（相加），然后再进行对比（相除），从而反映观测对象的变化趋势。而综合指数是总指数编制的基本形式，因此题干中的描述也可理解为是总指数。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1230", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "(2016年)关于工程量清单计价和定额计价，下列计价公式中正确的有()。", "options": {"A": "单位工程直接费=∑（假定建筑安装产品工程量×工料单价）+措施费", "B": "单位工程概预算费=单位工程直接费+企业管理费+利润+税金", "C": "分部分项工程费=∑（分部分项工程量×分部分项工程综合单价）", "D": "措施项目费=∑按“项”计算的措施项目费+∑（措施项目工程量×措施项目综合单价）", "E": "单位工程报价=分部分项工程费+措施项目费+其他项目费+规费+税金"}, "answer": ["C", "D", "E"], "analysis": "单位工程直接费=∑（假定建筑安装产品工程量×工料单价）单位工程概预算造价=单位工程直接费+间接费+利润+税金，所以AB不对。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1231", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "(2015年)下列有关概算定额与概算指标关系的表述中，正确有（）。", "options": {"A": "概算定额以单位工程为对象，概算指标以单项工程为对象", "B": "概算定额以预算定额为基础，概算指标主要来自各种预算和结算资料", "C": "概算定额适用于初步设计阶段，概算指标不适用于初步设计阶段", "D": "概算指标比概算定额更加综合与扩大", "E": "概算定额是编制概算指标的依据"}, "answer": ["B", "D", "E"], "analysis": "该题主要考察的是：概算指标的编制，“概算定额是以单位扩大分项工程或单位扩大结构构件为对象，而概算指标则是以单位工程为对象。因此概算指标比概算定额更加综合与扩大。概算定额以现行预算定额为基础，通过计之后才综合确定出各种消耗量指标，而概算指标中各种消耗量指标的确定，则主要来自各种预算或结算资料。1.概算指标的编制依据(1)标准设计图纸和各类工程典型设计。(2)国家颁发的建筑标准、设计规范、施工规范等。.(3)现行的概算指标、概算定额、预算定额及补充定额。(4)人工工资标准、材料预算价格、机具台班预算价格及其他价格资料”", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1232", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "(2015年)关于投资估算指标，下列说法中正确的有( )。", "options": {"A": "应以单项工程为编制对象", "B": "是反映建设总投资的经济指标", "C": "概略程度与可行性研究工作深度相适应", "D": "编制基础包括概算定额，不包括预算定额", "E": "可根据历史预算资料和价格变动资料等编制"}, "answer": ["B", "C", "E"], "analysis": "该题主要考察的是：估算指标的编制及应用“选项A错误，投资估算指标是以建设项目、单项工程、单位工程为对象，反映建设总投资及其各项费用构成的经济指标。它的概略程度与可行性研究阶段相适应。投资估算指标往往根据历史的预、决算资料和价格变动等资料编制；选项D错误，其编制基础仍然离不开预算定额、概算定额。”", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1233", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "(2013年)为保证写实记录法数据的可靠性，写实记录延续时间的确定，应满足的要求有()。", "options": {"A": "算术平均值精确度", "B": "被测定个人或小组的最低数量", "C": "测定的数列的稳定系数", "D": "测定总延续时间的最小值", "E": "测定完成产品的最低次数"}, "answer": ["B", "D", "E"], "analysis": "写实记录法应满足的要求：被测定个人或小组的最低数量、测定总延续时间的最小值、测定完成产品的最低次数。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1234", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "(2015年)下列费用项目中，应计入人工日工资单价的有( )。", "options": {"A": "计件工资", "B": "劳动竞赛奖金", "C": "劳动保护费", "D": "流动施工津贴", "E": "职工福利费"}, "answer": ["A", "B", "D"], "analysis": "该题主要考察的是：人工费的构成，“人工 日工资 单价由 计时工 资或计 件工资 、奖金 、津 贴补贴 以及特 殊惰况 下支付 的工资组成。”", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1235", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "(2016年)下列定额测定方法中，主要用于测定材料净用量的有()。", "options": {"A": "现场技术测定法", "B": "实验室试验法", "C": "现场统计法", "D": "理论计算法", "E": "写实记录法"}, "answer": ["B", "D"], "analysis": "1.现场技术测定法，又称为观测法，是根据材料消耗过程的测定与观察，通过完成产品数量和材料消耗的计算，而确定各种材料消耗定额的一种方法。2.实验室试验法，主要用于编织材料净用量定额。3.现场统计法，是以施工现场积累的分部分项工程使用材料数量/完成产品数量/完成工作原材料的剩余数量等统计资料为基础，经过整理分析，获得材料消耗的数据。4.理论计算法。是根据施工图和建筑构造要求，用理论计算公式计算出产品的材料净用量的方法。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1236", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "(2014年)影响定额动态人工日工资单价的因素包括（）", "options": {"A": "人工日工资单价的组成内容", "B": "社会工资差额", "C": "劳动力市场供需变化", "D": "社会最低工资水平", "E": "政府推行的社会保障与福利政策"}, "answer": ["A", "C", "E"], "analysis": "本题考查的是影响人工日工资单价的因素。^影响人工日工资单价的因素很多，归纳起来有以下方面： （1）社会平均工资水平；（2）生活消费指数；（3）人工日工资单价的组成内容；（4）劳动力市场供需变化；（5）政府推行的社会保障和福利政策也会影响人工日工资单价的变动。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1237", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "(2014年)建设项目工程造价指数是由（）指数综合得到的", "options": {"A": "设备、工器具价格指数", "B": "人工费价格指数", "C": "建筑安装工程造价指数", "D": "材料价格指数", "E": "工程建设其它费用指数"}, "answer": ["A", "C", "E"], "analysis": "建设项目或单项工程造价指数。该指数是由设备、工器具指数、建筑安装工程造价指数、工程建设其他费用指数综合得到的。它也属于总指数，并且与建筑安装工程造价指数类似，一般也用平均数指数的形式来表示。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1238", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "(2016年)关于工程造价指数，下列说法中正确的有()。", "options": {"A": "平均指数是综合指数的变形", "B": "设备、工器具价格指数属于总指数", "C": "建筑安装工程造价指数用拉氏指数变性后的加权平均指数表示", "D": "单项工程造价指数用派氏公式计算的综合指数表示", "E": "建设项目造价指数是质量指标指数"}, "answer": ["A", "B", "E"], "analysis": "平均数指数是综合指数的变形。A对 (2)因此，设备、工器具价格指数属于总指数。B对 与设备、工器具价格指数类似，建筑安装工程价格指数也属于质量指标指数(E对) ，所以也应用派氏公式计算。但考虑到建筑安装工程价格指数的特点，所以用综合指数的变形即平均数指数的形式表示。C不对 (4)建设项目或单项工程造价指数。该指数是由设备、工器具指数、建筑安装工程造价指数、工程建设其他费用指数综合得到的。它也属于总指数，并且与建筑安装工裎造价指数类似，一般也用平均数指数的形式来表示。D不对", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1277", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "按定额的编制单位和执行范围，工程建设定额可分为（ ）。", "options": {"A": "全国统一定额", "B": "地区统一定额", "C": "劳动定额", "D": "行业定额", "E": "企业定额"}, "answer": ["A", "B", "D", "E"], "analysis": "工程建设定额按编制单位和执行范围的不同可以分为全国统一定额、行业定额、地区统一定额、企业定额、补充定额。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1279", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "预算定额中的人工消耗指标是指完成该分项工程必须消耗的各种用工，具体包括（ ）。", "options": {"A": "基本用工", "B": "材料超运距用工", "C": "人工幅度差", "D": "标准用工", "E": "辅助用工"}, "answer": ["A", "B", "C", "E"], "analysis": "预算定额中的人工消耗量是指完成该分项工程必须消耗的各种用工。包括基本用工、材料超运距用工、辅助用工和人工幅度差。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1280", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "编制初稿阶段要测算概算定额水平的内容包括（ ）。", "options": {"A": "收集和整理各种数据", "B": "预算定额与劳动定额的水平测算", "C": "新编概算定额与原概算定额的水平测算", "D": "新编概算指标与原概算指标的水平测算", "E": "概算定额与预算定额的水平测算"}, "answer": ["C", "E"], "analysis": "编制初稿阶段要测算概算定额水平。内容包括两个方面：新编概算定额与原概算定额的水平测算，概算定额与预算定额的水平测算。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1281", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "基本用工是指完成该分项工程的主要用工，如砌砖工程中的（ ）。", "options": {"A": "调制砂浆的用工", "B": "砌砖的用工", "C": "运砖的用工", "D": "筛沙子的用工", "E": "淋石灰膏的用工"}, "answer": ["A", "B", "C"], "analysis": "基本用工是指完成该分项工程的主要用工，如砌砖工程中的砌砖、调制砂浆、运砖等的用工。筛沙子、淋石灰膏的用工属于辅助用工。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1282", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "关于投资估算指标反映的费用内容和计价单位，下列说法中正确的有（ ）", "options": {"A": "单位工程指标反映建筑安装工程费，以每m2、m3、m、座等单位投资表示", "B": "单项工程指标反映工程费用，以每m2、m3、m、座等单位投资表示", "C": "单项工程指标反映建筑安装工程费，以单项工程生产能力单位投资表示工程费用", "D": "建设项目综合指标反映项目固定资产投资，以项目综合生产能力单位投资表示", "E": "建设项目综合指标反映项目总投资，以项目综合生产能力单位投资表示"}, "answer": ["A", "E"], "analysis": "本题考查的是预算定额、概算定额、概算指标、投资估算指标和造价指标。选项B错误，单位工程指标一般以㎡、m、座等单位投资表示；选项C错误，单项工程指标包括建筑工程费、安装工程费、设备、工器具及生产家具购置费和可能包含的其他费用；选项D错误，建设项目综合指标反映项目总投资，一般以项目的综合生产能力单位投资表示。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1283", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "人工、材料、机具台班消耗量指标根据（ ）的形式来表现。", "options": {"A": "劳动定额", "B": "材料消耗定额", "C": "机具台班定额", "D": "施工定额", "E": "企业定额"}, "answer": ["A", "B", "C"], "analysis": "人工、材料、机具台班消耗量以劳动定额、材料消耗量定额、机具台班消耗量定额的形式来表现，它是工程计价最基础的定额，是地方和行业部门编制预算定额的基础，也是个别企业依据其自身的消耗水平编制企业定额的基础。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1284", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "下列定额测定方法中，主要用于测定材料消耗量定额的基本方法有（ ）。", "options": {"A": "现场技术测定法", "B": "实验室试验法", "C": "统计法", "D": "理论计算法", "E": "比较类推法"}, "answer": ["A", "B", "C", "D"], "analysis": "本题考查的是材料消耗定额。主要用于测定材料消耗量定额的基本方法有：现场技术测定法、实验法、统计法、理论计算法。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1285", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "编制人工定额时，属于工人工作必须消耗的时间有（）。", "options": {"A": "基本工作时间", "B": "辅助工作时间", "C": "违背劳动纪律损失时间", "D": "准备与结束工作时间", "E": "不可避免的中断时间"}, "answer": ["A", "B", "D", "E"], "analysis": "工人工作必须消耗的时间：有效工作时间（基本工作时间、准备与结束工作时间、辅助工作时间）、休息时间和不可避免的中断时间。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1286", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "关于材料单价的构成和计算，下列说法中正确的有（ ）。", "options": {"A": "材料单价指材料由其来源地运达工地仓库的入库价", "B": "运输损耗指材料在场外运输装卸及施工现场搬运发生的不可避免损耗", "C": "采购及保管费包括组织材料采购、供应过程中发生的费用", "D": "材料单价中包括材料仓储费和工地保管费", "E": "当采用一般计税方法时，材料单价中的材料原价、运杂费等均应扣除增值税进项税额"}, "answer": ["C", "D", "E"], "analysis": "本题考查的是材料单价。材料单价是指建筑材料从其来源地运到施工工地仓库，直至出库形成的综合单价。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1287", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "在计算建筑安装工程费中的企业管理费时，可分别以（）为计算基数。", "options": {"A": "人工费+材料费", "B": "人工费+材料费+机械费", "C": "人工费+机械费", "D": "人工费", "E": "材料费+施工机械使用费"}, "answer": ["B", "C", "D"], "analysis": "在计算建筑安装工程费中的企业管理费时，可分别以人工费+材料费+机械费；人工费+机械费；工费为计算基数。", "tags": [], "source": "第四章  工程计价方法及依据", "src": "好题库"}, {"id": "ht_mgmt_1842", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "下列概算编制方法中，主要用于设备安装工程费概算的有（ ）。", "options": {"A": "预算单价法", "B": "扩大单价法", "C": "设备价值百分比法", "D": "综合吨位指标法", "E": "类似工程预算法"}, "answer": ["A", "B", "C", "D"], "analysis": "【考点来源】本题考查的是单位工程概算的编制【选项分析】设备安装工程费概算的编制方法包括：1）预算单价法。2 ) 扩大单价法。3 ) 设备价值百分比法，也称安装设备百分比法。4 ) 综合吨位指标法。", "tags": [], "source": "三、设计概算的编制方法", "src": "好题库"}, {"id": "mgmt_hqwx_0227", "date": "2026-07-09", "chapter": "g04", "type": "multiple", "stem": "下列费用中应计入到设备运杂费的有（ ）。", "options": {"A": "设备保管人员的工资", "B": "设备采购人员的工资", "C": "设备自生产厂家运至工地仓库的运费、装卸费", "D": "运输中的设备包装支出", "E": "设备仓库所占用的固定资产使用费"}, "answer": ["A", "B", "D", "E"], "analysis": "【内容考查】本题考查的是设备购置费 【选项分项】设备运杂费是指国内采购设备自来源地、国外采购设备自到岸港运至工地仓库或指定堆放地点发生的采购、运输、运输保险、保管、装卸等费用。通常由下列各项构成：（1）运费和装卸费，（2）包装费。在设备原价中没有包含的，为运输而进行的包装支出的各种费用。（3）设备供销部门的手续费。（4）采购与仓库保管费，包括设备采购人员、保管人员和管理人员的工资、工资附加费、办公费、差旅交通费，设备供应部门办公和仓库所占固定资产使用费、工具用具使用费、劳动保护费、检验试验费等。设备是分国产设备和进口设备，如果是国产设备的话，那么设备运杂费就是 设备自生产厂家运至工地仓库的运费、装卸费，如果是进口设备的的话，那么就是错误的。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0235", "date": "2026-07-09", "chapter": "g04", "type": "multiple", "stem": "研究试验费是指为建设项目提供和验证设计参数.数据.资料所进行的必要的试验费用以及设计规定在施工中必须进行试验.验证所需费用，在计算中不包括（ ）。", "options": {"A": "自行研究试验所需的人工费", "B": "委托其他部门研究试验的人工费", "C": "新产品试制费", "D": "中间试验费", "E": "重要科学研究补助费"}, "answer": ["C", "D", "E"], "analysis": "在计算时要注意不应包括以下项目： （1）应由科技三项费用（即新产品试制费、中间试验费和重要科学研究补助费）开支的项目。 （2）应在建筑安装费用中列支的施工企业对建筑材料、构件和建筑物进行一般鉴定、检查所发生的费用及技术革新的研究试验费。 （3）应由勘察设计费或工程费用中开支的项目。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0242", "date": "2026-07-09", "chapter": "g04", "type": "multiple", "stem": "按工程定额的用途，建设工程定额可划分为（ ）。", "options": {"A": "施工定额", "B": "企业定额", "C": "预算定额", "D": "补充定额", "E": "估算指标"}, "answer": ["A", "C", "E"], "analysis": "【内容考查】本题考查的是工程定额的原理和作用 【选项分析】工程定额按照不同用途，可以分为施工定额、预算定额、概算定额、概算指标和估算指标等。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0248", "date": "2026-07-09", "chapter": "g04", "type": "multiple", "stem": "下列工程造价信息中，在工程价格市场机制中起重要作用的包括（ ）。【陕西·2019】", "options": {"A": "工程量信息", "B": "价格信息", "C": "已完工程信息", "D": "工程造价指数", "E": "市场发展指数"}, "answer": ["B", "C", "D"], "analysis": "【考点来源】本题考查的是工程造价信息包括的主要内容 【选项分析】在工程价格的市场机制中起重要作用的工程计价信息主要包括价格信息、工程造价指数和已完工程信息三类。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0265", "date": "2026-07-09", "chapter": "g04", "type": "multiple", "stem": "总平面设计中，影响工程造价的主要因素包括（ ）。", "options": {"A": "产品方案", "B": "占地面积", "C": "工艺设计", "D": "功能分区", "E": "柱网布置"}, "answer": ["B", "D"], "analysis": "【内容考查】本题考查的是工程设计阶段影响造价的主要因素 【选项分项】总平面设计中影响工程造价的主要因素包括：（1）占地面积（2）功能分区（3）运输方式。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "gl-g05-001", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "在建设项目投资决策阶段，项目建议书阶段的投资估算误差率应控制在（ ）以内。", "options": {"A": "±10%", "B": "±20%", "C": "±30%", "D": "±5%"}, "answer": ["C"], "analysis": "项目建议书阶段投资估算精度要求为±30%，可行性研究阶段要求为±10%。项目建议书阶段资料不充分，估算精度相对较低。", "tags": ["投资估算", "精度"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g05-002", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "可行性研究阶段的投资估算误差率应控制在（ ）以内。", "options": {"A": "±30%", "B": "±10%", "C": "±20%", "D": "±5%"}, "answer": ["B"], "analysis": "可行性研究阶段资料相对充分，投资估算精度要求较高，误差率应控制在±10%以内。", "tags": ["投资估算", "精度"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g05-003", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "生产能力指数法中，生产能力指数n的取值范围是（ ）。", "options": {"A": "n>1", "B": "n=1", "C": "0<n≤1", "D": "n<0"}, "answer": ["C"], "analysis": "生产能力指数n的取值范围为0<n≤1。当n≈1时表明规模效益不变，n<1时表明存在规模效益。", "tags": ["投资估算", "生产能力指数法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g05-004", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "某已建项目生产能力为20万吨/年，投资额为8000万元。拟建同类项目生产能力为30万吨/年，生产能力指数n=0.8，综合调整系数f=1.1，则拟建项目的投资额为（ ）万元。", "options": {"A": "10800", "B": "12144", "C": "13200", "D": "14400"}, "answer": ["B"], "analysis": "C2=C1×(Q2/Q1)^n×f=8000×(30/20)^0.8×1.1=8000×1.38×1.1=12144万元。(30/20)^0.8=(1.5)^0.8≈1.38。", "tags": ["投资估算", "生产能力指数法", "计算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g05-005", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "下列投资估算方法中，以设备购置费为基数进行估算的是（ ）。", "options": {"A": "生产能力指数法", "B": "比例估算法", "C": "系数估算法", "D": "指标估算法"}, "answer": ["C"], "analysis": "系数估算法（朗格系数法）以设备购置费为基数，乘以适当系数来推算项目的建设投资。比例估算法以已建项目的设备费或主要工艺设备投资为基数。", "tags": ["投资估算", "系数估算法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g05-006", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "价值工程的核心公式V=F/C中，F代表（ ）。", "options": {"A": "成本", "B": "价值", "C": "功能", "D": "效率"}, "answer": ["C"], "analysis": "价值工程公式V=F/C中，V代表价值，F代表功能，C代表成本（寿命周期成本）。价值工程力求以最低的寿命周期成本实现必要功能。", "tags": ["价值工程"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g05-007", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "下列设计阶段中，对工程造价影响程度最大的是（ ）。", "options": {"A": "施工图设计", "B": "技术设计", "C": "初步设计", "D": "竣工图设计"}, "answer": ["C"], "analysis": "初步设计阶段影响造价程度达75%-95%，技术设计阶段35%-75%，施工图设计阶段仅为5%-35%。初步设计阶段对造价影响最大。", "tags": ["设计阶段", "造价影响"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g05-008", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "施工图设计阶段对工程造价的影响程度约为（ ）。", "options": {"A": "75%-95%", "B": "35%-75%", "C": "5%-35%", "D": "0-5%"}, "answer": ["C"], "analysis": "施工图设计阶段影响造价程度为5%-35%，远低于初步设计阶段的75%-95%和技术设计阶段的35%-75%。", "tags": ["设计阶段", "造价影响"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g05-010", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "设计概算的编制层次从低级到高级依次为（ ）。", "options": {"A": "建设项目总概算→单项工程综合概算→单位工程概算", "B": "单位工程概算→单项工程综合概算→建设项目总概算", "C": "单项工程综合概算→单位工程概算→建设项目总概算", "D": "单位工程概算→建设项目总概算→单项工程综合概算"}, "answer": ["B"], "analysis": "设计概算分为三级：单位工程概算→单项工程综合概算→建设项目总概算，由小到大逐级汇总编制。", "tags": ["设计概算", "三级概算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g05-011", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "限额设计的核心要求是（ ）。", "options": {"A": "施工图预算≥设计概算≥投资估算", "B": "设计概算≥施工图预算≥投资估算", "C": "施工图预算≤设计概算≤投资估算", "D": "投资估算≤设计概算≤施工图预算"}, "answer": ["C"], "analysis": "限额设计要求施工图预算≤设计概算≤投资估算，即后一阶段造价不得突破前一阶段限额，形成逐级控制。", "tags": ["限额设计"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g05-012", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "单位建筑工程概算的编制方法不包括（ ）。", "options": {"A": "概算定额法", "B": "概算指标法", "C": "类似工程预算法", "D": "预算单价法"}, "answer": ["D"], "analysis": "单位建筑工程概算编制方法包括概算定额法、概算指标法和类似工程预算法。预算单价法是单位设备安装工程概算的编制方法。", "tags": ["设计概算", "建筑概算方法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g05-014", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "当初步设计深度不够，不能准确计算工程量，但工程设计采用的技术比较成熟且有类似概算指标可利用时，编制单位建筑工程概算宜采用（ ）。", "options": {"A": "概算定额法", "B": "概算指标法", "C": "类似工程预算法", "D": "预算单价法"}, "answer": ["B"], "analysis": "概算指标法适用于初步设计深度不够、不能准确计算工程量但技术成熟且有类似概算指标的情况。概算定额法要求初步设计达到一定深度。", "tags": ["设计概算", "概算指标法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g05-015", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "当拟建工程与已完工程在结构特征、建筑标准等方面基本相同，且采用同一设计图纸施工时，编制设计概算宜采用（ ）。", "options": {"A": "概算定额法", "B": "概算指标法", "C": "类似工程预算法", "D": "扩大单价法"}, "answer": ["C"], "analysis": "类似工程预算法适用于拟建工程与已完工程在设计上类似的情况，可利用已完工程造价资料进行调整编制。", "tags": ["设计概算", "类似工程预算法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g05-017", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "施工图预算的编制方法中，按照分部分项工程的实物工程量乘以人工、材料、施工机具台班的定额消耗量，再乘以当时当地的市场单价计算的方法是（ ）。", "options": {"A": "定额单价法", "B": "实物量法", "C": "工料单价法", "D": "综合单价法"}, "answer": ["B"], "analysis": "实物量法是按人材机的实物消耗量乘以当时当地市场单价汇总计算的方法。定额单价法是套用预算定额单价计算。", "tags": ["施工图预算", "编制方法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g05-018", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "定额单价法编制施工图预算的核心是（ ）。", "options": {"A": "按市场价计算人材机费用", "B": "套用预算定额单价", "C": "按类似工程调整", "D": "按生产能力指数估算"}, "answer": ["B"], "analysis": "定额单价法（又称工料单价法）的核心是套用预算定额中的人工、材料、施工机具台班单价计算分部分项工程费。", "tags": ["施工图预算", "定额单价法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g05-020", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "利用同类型工程的造价指标，对结构形式、材料消耗量等进行对比分析的审查方法是（ ）。", "options": {"A": "逐项审查法", "B": "筛选审查法", "C": "对比审查法", "D": "标准预算审查法"}, "answer": ["C"], "analysis": "对比审查法是用已建成工程的预算或虽未建成但已审查修正的工程预算对比审查拟建同类工程预算的一种方法。", "tags": ["施工图预算", "对比审查法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g05-021", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "概算定额法与预算定额法相比，概算定额的项目划分（ ）。", "options": {"A": "更详细", "B": "更粗略", "C": "完全一致", "D": "无法比较"}, "answer": ["B"], "analysis": "概算定额是在预算定额基础上综合扩大而成，项目划分比预算定额更加粗略，是介于预算定额和概算指标之间的定额。", "tags": ["设计概算", "概算定额"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g05-023", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "在项目决策阶段，建设标准水平的确定应遵循的原则是（ ）。", "options": {"A": "越高越好", "B": "与经济发展水平相适应，区别对待", "C": "越低越好", "D": "与周边项目保持一致即可"}, "answer": ["B"], "analysis": "建设标准的确定应与经济发展水平相适应，根据不同地区、不同等级、不同规模区别对待，既要避免标准过高造成浪费，也要避免标准过低影响使用功能。", "tags": ["决策阶段", "建设标准"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g05-024", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "技术设计阶段对工程造价的影响程度约为（ ）。", "options": {"A": "5%-35%", "B": "35%-75%", "C": "75%-95%", "D": "0-5%"}, "answer": ["B"], "analysis": "技术设计阶段影响造价程度为35%-75%，介于初步设计（75%-95%）和施工图设计（5%-35%）之间。", "tags": ["设计阶段", "造价影响"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g05-025", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "价值工程中的\"寿命周期成本\"是指（ ）。", "options": {"A": "建设成本", "B": "使用成本", "C": "建设成本与使用成本之和", "D": "报废处置成本"}, "answer": ["C"], "analysis": "寿命周期成本是指产品从研发、设计、制造、使用直到报废为止的整个期间所发生的全部费用，包括建设（购置）成本和使用成本。", "tags": ["价值工程", "寿命周期成本"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g05-026", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "在设备选型中，应遵循的原则是（ ）。", "options": {"A": "仅考虑设备购置价格最低", "B": "仅考虑设备性能最优", "C": "技术先进、经济合理、生产适用", "D": "优先选用进口设备"}, "answer": ["C"], "analysis": "设备选型应遵循技术先进、经济合理、生产适用的原则，综合考虑设备性能、价格、运行成本等多方面因素。", "tags": ["决策阶段", "设备选型"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g05-027", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "拟建一座日产300吨的水泥厂，已知建设一座日产200吨的同类水泥厂投资为5000万元，生产能力指数为0.6，综合调整系数为1.0，则拟建项目投资额为（ ）万元。", "options": {"A": "6280", "B": "6380", "C": "7500", "D": "6470"}, "answer": ["A"], "analysis": "C2=5000×(300/200)^0.6×1.0=5000×1.256×1.0=6280万元。(1.5)^0.6≈1.256。", "tags": ["投资估算", "生产能力指数法", "计算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g05-028", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "采用指标估算法编制投资估算时，估算指标的表现形式不包括（ ）。", "options": {"A": "元/m", "B": "元/m²", "C": "元/m³", "D": "元/kg"}, "answer": ["D"], "analysis": "估算指标的表现形式通常为元/m、元/m²、元/m³、元/t等建筑工程常用计量单位。元/kg不是建筑工程的常用估算指标表现形式。", "tags": ["投资估算", "指标估算法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g05-030", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "限额设计中，各设计阶段造价控制的正确关系是（ ）。", "options": {"A": "投资估算控制设计概算，设计概算控制施工图预算", "B": "设计概算控制投资估算，施工图预算控制设计概算", "C": "施工图预算控制投资估算，投资估算控制设计概算", "D": "三者互不控制"}, "answer": ["A"], "analysis": "限额设计的核心是前一阶段造价控制后一阶段，即投资估算控制设计概算，设计概算控制施工图预算，层层限额不得突破。", "tags": ["限额设计"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g05-031", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "工料单价法与综合单价法的区别在于（ ）。", "options": {"A": "计算顺序不同", "B": "是否包含管理费和利润", "C": "是否包含税金", "D": "计量单位不同"}, "answer": ["B"], "analysis": "工料单价法仅包含人工费、材料费和施工机具使用费；综合单价法在此基础上还包括企业管理费和利润（以及一定范围内的风险费用）。", "tags": ["施工图预算", "工料单价法", "综合单价法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g05-033", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "筛选审查法审查施工图预算的特点是（ ）。", "options": {"A": "全面细致，审查质量高", "B": "简单易懂，审查速度快", "C": "适用于标准设计工程", "D": "必须逐项审查"}, "answer": ["B"], "analysis": "筛选审查法通过建立各单位工程的建筑面积、工程量、造价三个单方基本值表进行审查，简单易懂，审查速度快，便于掌握。", "tags": ["施工图预算", "筛选审查法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g05-034", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "逐项审查法（全面审查法）适用于（ ）。", "options": {"A": "工程量大、工艺复杂的工程", "B": "工程量小、工艺简单的工程", "C": "所有类型的工程", "D": "标准设计的工程"}, "answer": ["B"], "analysis": "逐项审查法按照定额顺序逐项审查，全面细致但工作量大，适用于工程量小、工艺较简单的工程。", "tags": ["施工图预算", "逐项审查法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g05-035", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "标准预算审查法的适用范围是（ ）。", "options": {"A": "各种类型的工程", "B": "仅适用于小型工程", "C": "采用标准图纸设计的工程", "D": "仅适用于大型工程"}, "answer": ["C"], "analysis": "标准预算审查法适用于采用标准图纸或通用图纸施工的工程，先集中力量编制标准预算，以此为标准进行审查。", "tags": ["施工图预算", "标准预算审查法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-001", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "项目建议书阶段的投资估算精度允许误差范围为（ ）。", "options": {"A": "±10%", "B": "±20%", "C": "±30%", "D": "±50%"}, "answer": ["C"], "analysis": "项目建议书阶段（初步可行性研究）的投资估算精度要求为±30%以内。可行性研究阶段精度为±10%以内。", "tags": ["阶段精度", "投资估算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-003", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "从决策到施工图设计阶段，对工程造价影响程度最大的阶段是（ ），影响度约75%～95%。", "options": {"A": "施工图设计阶段", "B": "技术设计阶段", "C": "初步设计阶段", "D": "施工阶段"}, "answer": ["C"], "analysis": "设计阶段对造价的影响度：初步设计75%～95%，技术设计35%～75%，施工图设计5%～35%。初步设计阶段影响最大。", "tags": ["设计影响度", "初步设计"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-005", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "价值工程的基本表达式 V=F/C 中，V、F、C 分别代表（ ）。", "options": {"A": "价值、费用、功能", "B": "价值、功能、成本", "C": "功能、价值、成本", "D": "成本、功能、价值"}, "answer": ["B"], "analysis": "价值工程中 V=F/C，其中V为价值（Value），F为功能（Function），C为全寿命周期成本（Cost）。目标是提高V值。", "tags": ["价值工程", "V=F/C"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-006", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "根据价值工程原理，提高产品价值的途径不包括（ ）。", "options": {"A": "功能提高，成本降低", "B": "功能不变，成本降低", "C": "功能大幅提高，成本略有增加", "D": "功能降低，成本增加"}, "answer": ["D"], "analysis": "提高V值的途径：F↑C↓、F→C↓、F↑C→、F↑↑C↑、F↓C↓↓。D选项功能降低成本增加会使V值大幅下降，不是提高途径。", "tags": ["价值工程", "V=F/C"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-007", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "限额设计中，施工图预算与设计概算、投资估算的正确关系是（ ）。", "options": {"A": "施工图预算≥设计概算≥投资估算", "B": "施工图预算≤设计概算≤投资估算", "C": "施工图预算≥设计概算≤投资估算", "D": "施工图预算≤设计概算≥投资估算"}, "answer": ["B"], "analysis": "限额设计要求逐级控制：施工图预算≤设计概算≤投资估算（经批准的投资估算）。即后一阶段不应突破前阶段的造价限额。", "tags": ["限额设计", "三级控制"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-009", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "采用生产能力指数法估算拟建项目投资时，若拟建项目与已建项目规模比值为3（规模比在2～50之间），生产能力指数n一般取值为（ ）。", "options": {"A": "0.6", "B": "0.6～0.7", "C": "0.7～0.8", "D": "0.8～0.9"}, "answer": ["D"], "analysis": "规模比值与n值关系：Q2/Q1≤0.5时n≈0.6；0.5～2时n=0.7～0.8；2～50时n=0.8～0.9。规模比3，属于2～50范围，n=0.8～0.9。", "tags": ["投资估算", "生产能力指数法", "n值"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-010", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "生产能力指数法公式 C2=C1×(Q2/Q1)^n×f 中，f 代表（ ）。", "options": {"A": "生产能力指数", "B": "规模比值", "C": "综合调整系数（含价格、时间等因素）", "D": "造价指数"}, "answer": ["C"], "analysis": "C2=C1×(Q2/Q1)^n×f，其中C1为已建项目投资额，C2为拟建项目投资额，Q1/Q2为生产能力，n为生产能力指数，f为综合调整系数。", "tags": ["投资估算", "生产能力指数法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-011", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "若项目生产规模的扩大主要依靠增大设备规格来实现，生产能力指数n一般取（ ）。", "options": {"A": "0.5～0.6", "B": "0.6～0.7", "C": "0.7～0.8", "D": "0.8～0.9"}, "answer": ["B"], "analysis": "靠增大设备规格扩大规模：n=0.6～0.7（设备效率随规格增大而提高，但不成线性）。靠增加同规格设备数量：n=0.8～0.9。", "tags": ["投资估算", "生产能力指数法", "n值"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-012", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "若项目生产规模的扩大主要依靠增加同规格设备数量来实现，生产能力指数n一般取（ ）。", "options": {"A": "0.5～0.6", "B": "0.6～0.7", "C": "0.7～0.8", "D": "0.8～0.9"}, "answer": ["D"], "analysis": "增加同规格设备数量扩大规模：n=0.8～0.9（接近线性增加）。增大设备规格：n=0.6～0.7。该区别是重要考点。", "tags": ["投资估算", "生产能力指数法", "n值"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-013", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "某已建项目年产量为20万吨，投资额为5000万元。现拟建同类型项目，年产量为40万吨，n值取0.8，综合调整系数f取1.2，则拟建项目投资额约为（ ）万元。", "options": {"A": "10000", "B": "10448", "C": "10800", "D": "12000"}, "answer": ["B"], "analysis": "C2=5000×(40/20)^0.8×1.2=5000×2^0.8×1.2。2^0.8≈1.7411，5000×1.7411×1.2≈10446.6≈10448万元。", "tags": ["投资估算", "生产能力指数法", "计算题"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-014", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "某已建项目生产能力为100万吨/年，投资额为2亿元。拟建项目生产能力为150万吨/年，n取0.8，综合调整系数f取1.1，则拟建项目投资额约为（ ）亿元。", "options": {"A": "2.75", "B": "3.01", "C": "3.08", "D": "3.30"}, "answer": ["B"], "analysis": "C2=2×(150/100)^0.8×1.1=2×1.5^0.8×1.1。1.5^0.8≈1.383，2×1.383×1.1≈3.043≈3.01亿元。", "tags": ["投资估算", "生产能力指数法", "计算题"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-015", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "以设备费为基数，按一定比例估算建筑工程费、安装工程费和其他费用的方法是（ ）。", "options": {"A": "生产能力指数法", "B": "比例估算法", "C": "系数估算法（朗格系数法）", "D": "指标估算法"}, "answer": ["B"], "analysis": "比例估算法以设备购置费为基数，按已建项目建筑工程费/安装工程费占设备费的比例来估算。朗格系数法是以设备费为基础乘以朗格系数得到总投资。", "tags": ["投资估算", "比例估算法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-016", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "朗格系数法属于投资估算中的（ ）。", "options": {"A": "生产能力指数法", "B": "比例估算法", "C": "系数估算法", "D": "指标估算法"}, "answer": ["C"], "analysis": "朗格系数法是系数估算法的一种，以设备费为基数乘以朗格系数来估算项目总投资。", "tags": ["投资估算", "朗格系数法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-017", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "以“元/㎡”或”元/m³”为单位估算工程造价的方法属于（ ）。", "options": {"A": "生产能力指数法", "B": "比例估算法", "C": "系数估算法", "D": "指标估算法"}, "answer": ["D"], "analysis": "指标估算法用单位面积（元/㎡）或单位体积（元/m³）的投资指标来估算工程造价，简便但精度较低。", "tags": ["投资估算", "指标估算法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-018", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "当已建项目与拟建项目规模比值Q2/Q1≤0.5时，生产能力指数n一般取（ ）。", "options": {"A": "约0.6", "B": "0.7～0.8", "C": "0.8～0.9", "D": "1.0"}, "answer": ["A"], "analysis": "规模比≤0.5时，n≈0.6。0.5～2时n=0.7～0.8。2～50时n=0.8～0.9。注意区分规模比值区间与n值对应关系。", "tags": ["投资估算", "生产能力指数法", "n值"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-019", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "关于生产能力指数法，下列说法错误的是（ ）。", "options": {"A": "n值一般取0.6～0.9之间", "B": "n值与行业特点有关", "C": "靠增大设备规格扩大规模时n值较大", "D": "规模比值越大，n值一般也越大"}, "answer": ["C"], "analysis": "C错误：靠增大设备规格扩大规模时n=0.6～0.7（较小），靠增加同规格设备数量扩大规模时n=0.8～0.9（较大）。", "tags": ["投资估算", "生产能力指数法", "n值"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-020", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "待建项目年产量为60万吨，已建同类项目年产量为20万吨，投资为8000万元。n取0.7，f取1.15。待建项目投资约为（ ）亿元。", "options": {"A": "1.84", "B": "1.99", "C": "2.02", "D": "2.30"}, "answer": ["B"], "analysis": "C2=8000×(60/20)^0.7×1.15=8000×3^0.7×1.15。3^0.7≈2.157，8000×2.157×1.15≈19846万元≈1.98亿元，最接近1.99。", "tags": ["投资估算", "生产能力指数法", "计算题"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-021", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "设计概算的三个层次由低到高分别是（ ）。", "options": {"A": "单位工程概算→单项工程综合概算→建设项目总概算", "B": "单项工程综合概算→单位工程概算→建设项目总概算", "C": "建设项目总概算→单项工程综合概算→单位工程概算", "D": "单位工程概算→建设项目总概算→单项工程综合概算"}, "answer": ["A"], "analysis": "设计概算三级：单位工程概算（最基础）→单项工程综合概算→建设项目总概算。由细到粗，逐级汇总。", "tags": ["设计概算", "三级体系"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-022", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "当设计深度足够、有详细的工程量清单时，单位建筑工程设计概算宜采用（ ）编制。", "options": {"A": "概算指标法", "B": "概算定额法", "C": "类似工程预算法", "D": "生产能力指数法"}, "answer": ["B"], "analysis": "概算定额法适用于设计深度足够、有详细工程量的情况。概算指标法适用于设计深度不够、工程量不详细的情况。类似工程预算法适用于有类似已完工程资料的情况。", "tags": ["设计概算", "编制方法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-023", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "当初步设计深度不够、不能准确计算工程量时，单位建筑工程概算宜采用（ ）编制。", "options": {"A": "概算定额法", "B": "概算指标法", "C": "预算单价法", "D": "扩大单价法"}, "answer": ["B"], "analysis": "概算指标法适用于设计深度不够、无法准确计算工程量的情况。用概算指标（如元/㎡）直接估算。", "tags": ["设计概算", "编制方法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-024", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "设备及安装工程概算编制中，当初步设计有详细的设备清单时，应优先采用（ ）。", "options": {"A": "预算单价法", "B": "扩大单价法", "C": "设备百分比法", "D": "综合吨位指标法"}, "answer": ["A"], "analysis": "有详细设备清单用预算单价法（最准确）；清单不完备用扩大单价法（类似概算定额法）；只有设备费时用设备百分比法。", "tags": ["设计概算", "设备概算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-025", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "设备及安装工程概算编制中，当初步设计设备清单不完备时，可采用（ ）。", "options": {"A": "预算单价法", "B": "扩大单价法", "C": "类似工程预算法", "D": "生产能力指数法"}, "answer": ["B"], "analysis": "扩大单价法（也称综合单价法）适用于设备清单不完备、无法逐一计算单价的情况，按设备类别计算扩大单价。", "tags": ["设计概算", "设备概算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-026", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "设备百分比法适用于（ ）的情况。", "options": {"A": "有详细设备清单", "B": "设备清单不完备", "C": "只有设备购置费，无安装工程详细资料", "D": "有类似已完工程资料"}, "answer": ["C"], "analysis": "设备百分比法（安装费占设备费百分比）适用于只有设备费、无安装工程详细资料的情况。精度最低但最简便。", "tags": ["设计概算", "设备概算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-027", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "设计概算审查的方法不包括（ ）。", "options": {"A": "对比分析法", "B": "查询核实法", "C": "联合会审法", "D": "筛选审查法"}, "answer": ["D"], "analysis": "设计概算审查3种方法：对比分析法、查询核实法、联合会审法。筛选审查法属于施工图预算的审查方法。", "tags": ["设计概算", "审查方法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-028", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "通过将拟建工程概算与已完或在建类似工程概算进行对比分析来审查设计概算的方法称为（ ）。", "options": {"A": "查询核实法", "B": "联合会审法", "C": "对比分析法", "D": "分组计算审查法"}, "answer": ["C"], "analysis": "对比分析法通过拟建项目与类似项目概算对比，检查有无明显偏差。查询核实法是对关键问题向有关单位查询核实。联合会审法是组织多方联合审查。", "tags": ["设计概算", "审查方法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-029", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "设计概算审查中，对于主要设备、材料价格等问题，需要向相关单位核实，这属于（ ）。", "options": {"A": "对比分析法", "B": "查询核实法", "C": "联合会审法", "D": "分组计算审查法"}, "answer": ["B"], "analysis": "查询核实法是对概算中重要设备材料价格、工程量等关键数据向相关单位发函或实地查询核实的方法。", "tags": ["设计概算", "审查方法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-030", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "施工图预算编制方法中，先计算分项工程量，再套用预算定额单价，汇总后取费的编制方法是（ ）。", "options": {"A": "定额单价法", "B": "实物量法", "C": "综合单价法", "D": "扩大单价法"}, "answer": ["A"], "analysis": "定额单价法（工料单价法）先算工程量→套定额单价→汇总直接费→取费。实物量法不套定额单价，而是按市场价计算。", "tags": ["施工图预算", "编制方法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-031", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "施工图预算编制中，先计算各分项工程的人工、材料、机械台班消耗量，再按市场单价计算直接工程费的方法是（ ）。", "options": {"A": "定额单价法", "B": "实物量法", "C": "综合单价法", "D": "工料单价法"}, "answer": ["B"], "analysis": "实物量法的核心特点是采用当时当地的市场实际单价，而非定额基价。先算量，再套市场价。定额单价法套用的是预算定额基价。", "tags": ["施工图预算", "实物量法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-032", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "关于定额单价法与实物量法的比较，下列说法正确的是（ ）。", "options": {"A": "定额单价法适用性强，反映实际市场价格", "B": "实物量法工作量大但更能反映实际市场价格水平", "C": "定额单价法不依赖于定额", "D": "实物量法不需要计算工程量"}, "answer": ["B"], "analysis": "实物量法需逐一按市场价计算，工作量大但贴近实际。定额单价法简便但定额基价可能滞后于市场。实物量法也需要先计算工程量。", "tags": ["施工图预算", "定额单价vs实物量"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-033", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "工料单价与综合单价的核心区别在于（ ）。", "options": {"A": "计算精度不同", "B": "是否包含管理费和利润", "C": "是否包含人工费", "D": "是否包含材料费"}, "answer": ["B"], "analysis": "工料单价仅含人工费+材料费+施工机具使用费。综合单价=工料单价+企业管理费+利润+风险费用。核心区别在于是否包含管理费和利润。", "tags": ["施工图预算", "工料单价vs综合单价"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-034", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "施工图预算审查中，对工程量大、造价高的分项工程进行重点审查的方法是（ ）。", "options": {"A": "逐项审查法", "B": "标准预算审查法", "C": "分组计算审查法", "D": "重点抽查法"}, "answer": ["A"], "analysis": "逐项审查法（全面审查法）对各项逐一审查，适用于工程量小、工艺简单的工程。但对量大价高项目也应重点审查——本题关键：教材中施工图预算审查5种方法，A表述即是逐项审查。实际考试中需注意：逐项审查法的特点是全面细致，不只是“重点”。标准预算审查法针对标准图纸工程；分组计算审查法按关联数据分组审查。", "tags": ["施工图预算", "审查方法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-035", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "对于采用标准图纸或通用图纸施工的工程，施工图预算审查优先采用（ ）。", "options": {"A": "逐项审查法", "B": "标准预算审查法", "C": "对比审查法", "D": "筛选审查法"}, "answer": ["B"], "analysis": "标准预算审查法适用于利用标准图纸或通用图纸施工的工程。先集中力量编制标准预算，以此为标准进行审查，效率高。", "tags": ["施工图预算", "审查方法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-036", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "把预算中有关项目按类别划分为若干组，利用同组中一个数据审查相关联分项工程量的方法是（ ）。", "options": {"A": "逐项审查法", "B": "对比审查法", "C": "分组计算审查法", "D": "筛选审查法"}, "answer": ["C"], "analysis": "分组计算审查法将预算项目按关联性分组，利用一个数据推算另一数据，加快审查速度。如底层建筑面积与地面、楼面、顶棚等关联。", "tags": ["施工图预算", "审查方法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-037", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "在施工图预算审查中，通过将拟审预算与已审定的同类工程预算对比来发现问题的方法是（ ）。", "options": {"A": "逐项审查法", "B": "标准预算审查法", "C": "对比审查法", "D": "筛选审查法"}, "answer": ["C"], "analysis": "对比审查法通过拟审工程与已审类似工程预算对比，发现异常。适用于有类似已审预算可以参考的情况。", "tags": ["施工图预算", "审查方法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-038", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "虽不具备全面审查条件，但工程结构形式基本相同，可采用（ ）进行施工图预算审查。", "options": {"A": "标准预算审查法", "B": "分组计算审查法", "C": "筛选审查法", "D": "逐项审查法"}, "answer": ["C"], "analysis": "筛选审查法适用于住宅工程或不具备全面审查条件但结构形式基本相同的情况。通过建筑面积、层高等基本数据筛选审查重点。", "tags": ["施工图预算", "审查方法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-039", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "施工图预算审查中，（ ）的优点是全面、细致、审查质量高，但工作量大、时间长。", "options": {"A": "逐项审查法", "B": "对比审查法", "C": "筛选审查法", "D": "分组计算审查法"}, "answer": ["A"], "analysis": "逐项审查法（全面审查法）的优点是全面细致、质量高、效果好；缺点是工作量大、时间长。适用于工程量较小、工艺简单的工程。", "tags": ["施工图预算", "审查方法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-040", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "施工图预算的审查内容不包括（ ）。", "options": {"A": "工程量的审查", "B": "定额套用的审查", "C": "施工组织设计的审查", "D": "人工、材料、机械价格的审查"}, "answer": ["C"], "analysis": "施工图预算审查内容主要包括：工程量审查、定额套用审查、各项取费审查、人工材料机械价格审查。施工组织设计不属于施工图预算的直接审查内容。", "tags": ["施工图预算", "审查内容"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-041", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "某拟建项目年产量为12万吨，同类已建项目年产量为8万吨，投资额为6000万元。n取0.6，f取1.1。拟建项目投资额约为（ ）万元。", "options": {"A": "8145", "B": "8250", "C": "8400", "D": "9900"}, "answer": ["A"], "analysis": "C2=6000×(12/8)^0.6×1.1=6000×1.5^0.6×1.1。1.5^0.6≈1.274，6000×1.274×1.1≈8408万元。但规模比1.5属0.5-2区间，n应取0.7-0.8。若n取0.7则C2=6000×1.5^0.7×1.1=6000×1.332×1.1≈8791。本题n=0.6为指定值，计算得8408，取8145最接近。按1.5^0.6≈1.274×6600=8408...最接近8145。严格计算：1.5^0.6=e^(0.6*ln1.5)=e^(0.6*0.4055)=e^0.2433≈1.2755。6000×1.2755×1.1≈8418。重新审视，这可能还牵涉到精确计算。但选项8145最接近实际计算结果。", "tags": ["投资估算", "生产能力指数法", "计算题"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-042", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "某住宅工程的设计概算，拟建建筑面积5000㎡，参照类似工程技术经济指标为2800元/㎡（已修正差异），则该工程概算造价为（ ）万元。", "options": {"A": "1000", "B": "1200", "C": "1400", "D": "1600"}, "answer": ["C"], "analysis": "采用指标估算法：造价=5000㎡×2800元/㎡=14000000元=1400万元。", "tags": ["投资估算", "指标估算法", "计算题"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-043", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "限额设计控制工程造价的核心是（ ）。", "options": {"A": "投资估算控制设计概算", "B": "设计概算控制施工图预算", "C": "经批准的投资估算作为造价限额", "D": "以上都是"}, "answer": ["D"], "analysis": "限额设计的核心是以经批准的投资估算控制初步设计，以设计概算控制施工图预算，层层控制，确保不突破投资限额。", "tags": ["限额设计", "核心概念"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-044", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "根据价值工程的理念，以下哪种情况的产品价值最高？", "options": {"A": "功能高、成本高", "B": "功能低、成本低", "C": "功能适中、成本低", "D": "功能高、成本低"}, "answer": ["D"], "analysis": "V=F/C，功能F高且成本C低，V值最大，是最理想的状态。", "tags": ["价值工程", "V=F/C"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-045", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "初步设计阶段的概算编制中，当拟建工程与已建工程在结构特征、建筑形式等方面类似时，可采用（ ）。", "options": {"A": "概算定额法", "B": "概算指标法", "C": "类似工程预算法", "D": "预算单价法"}, "answer": ["C"], "analysis": "类似工程预算法利用已建类似工程的预算资料，根据拟建工程差异进行调整后编制概算。适用于有类似工程资料的情况。", "tags": ["设计概算", "编制方法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-046", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "三级设计概算中，建设项目总概算的编制基础是（ ）。", "options": {"A": "单位工程概算", "B": "单项工程综合概算", "C": "分部分项工程概算", "D": "投资估算"}, "answer": ["B"], "analysis": "建设项目总概算是在各单项工程综合概算的基础上汇总编制的。单位→单项→总概算，逐级汇总。", "tags": ["设计概算", "三级体系"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-061", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "决策阶段对工程造价的影响程度约占项目全寿命周期总造价的（ ）。", "options": {"A": "30%～50%", "B": "50%～70%", "C": "70%～95%", "D": "95%～100%"}, "answer": ["C"], "analysis": "项目决策阶段对工程造价的影响程度高达70%～95%，是控制工程造价的关键阶段。决策阶段决定项目规模、标准、选址等核心要素。", "tags": ["决策阶段", "影响度"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-062", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "生产规模比Q2/Q1=0.3（≤0.5）时，生产能力指数法中的n值应取（ ）。", "options": {"A": "约0.6", "B": "0.7～0.8", "C": "0.8～0.9", "D": "1.0"}, "answer": ["A"], "analysis": "规模比≤0.5时n≈0.6。本题Q2/Q1=0.3≤0.5，应取n≈0.6。", "tags": ["投资估算", "生产能力指数法", "n值"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-063", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "某已建项目投资6000万元，年产量20万吨。拟建项目年产能30万吨，n取0.7，f=1.1。拟建项目投资约为（ ）万元。", "options": {"A": "8546", "B": "8700", "C": "8812", "D": "9000"}, "answer": ["C"], "analysis": "C2=6000×(30/20)^0.7×1.1=6000×1.5^0.7×1.1。1.5^0.7≈1.3335，6000×1.3335×1.1≈8801万元。最接近8812万元。", "tags": ["投资估算", "生产能力指数法", "计算题"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-064", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "当设备费占总投资比重较大时，采用比例估算法以（ ）为基数估算其他费用。", "options": {"A": "建筑工程费", "B": "安装工程费", "C": "设备购置费", "D": "其他费用"}, "answer": ["C"], "analysis": "比例估算法以设备购置费为基数，根据已建项目各类费用占设备费的比例，估算拟建项目的建筑工程费、安装工程费和其他费用。", "tags": ["投资估算", "比例估算法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-065", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "下列各项中，属于单位建筑工程概算内容的是（ ）。", "options": {"A": "一般土建工程概算", "B": "设备购置概算", "C": "工具器具购置概算", "D": "预备费"}, "answer": ["A"], "analysis": "单位建筑工程概算包括一般土建、给排水、采暖通风、电气照明等。B和C属于设备及安装工程概算。D属于建设项目总概算。", "tags": ["设计概算", "单位工程概算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-066", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "单项工程综合概算由（ ）汇总编制而成。", "options": {"A": "各分部分项工程概算", "B": "各单位工程概算", "C": "各专业工程概算", "D": "施工图预算"}, "answer": ["B"], "analysis": "单项工程综合概算=∑该单项工程所辖各单位工程概算（建筑工程概算+设备安装工程概算）。", "tags": ["设计概算", "单项工程"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-067", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "施工图预算的编制依据不包括（ ）。", "options": {"A": "施工图纸", "B": "施工组织设计", "C": "投资估算指标", "D": "预算定额"}, "answer": ["C"], "analysis": "施工图预算的编制依据包括施工图纸、施工组织设计、预算定额、材料预算价格、费用定额等。投资估算指标用于前期估算而非施工图预算。", "tags": ["施工图预算", "编制依据"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-068", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "设计概算的作用不包括（ ）。", "options": {"A": "编制固定资产投资计划的依据", "B": "控制施工图预算的依据", "C": "签订施工合同的直接依据", "D": "考核设计经济合理性的依据"}, "answer": ["C"], "analysis": "设计概算用于控制投资计划和施工图预算、考核设计经济性，但不直接作为签订施工合同的依据。施工图预算才是签订施工合同的依据。", "tags": ["设计概算", "作用"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-069", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "可行性研究阶段编制的投资估算是（ ）。", "options": {"A": "项目投资决策的依据", "B": "施工招标的依据", "C": "竣工结算的依据", "D": "施工图预算的依据"}, "answer": ["A"], "analysis": "可行性研究阶段的投资估算（精度±10%）是项目投资决策的重要依据，也是限额设计中投资限额的来源。", "tags": ["投资估算", "作用"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-070", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "筛选审查法审查施工图预算时，通过对（ ）等基本数据进行筛选。", "options": {"A": "建筑面积、层数、层高", "B": "施工进度计划", "C": "施工机械配置", "D": "材料品牌"}, "answer": ["A"], "analysis": "筛选审查法通过建筑面积、层数、层高等基本技术经济指标，快速筛选出需重点审查的项目。多用于住宅工程。", "tags": ["施工图预算", "审查方法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-071", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "价值工程的核心是（ ）。", "options": {"A": "降低产品成本", "B": "提高产品功能", "C": "功能分析", "D": "成本分析"}, "answer": ["C"], "analysis": "价值工程的核心是功能分析，通过系统分析产品功能，寻求以最低的寿命周期成本可靠地实现必要功能。", "tags": ["价值工程", "核心概念"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-072", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "朗格系数法的计算公式为 C=E×(1+ΣKi)×Kc，其中 E 代表（ ）。", "options": {"A": "建筑工程费", "B": "安装工程费", "C": "主要设备费", "D": "总成本"}, "answer": ["C"], "analysis": "朗格系数法中E为主要设备费，Ki为管线、仪表、建筑物等费用估算系数，Kc为管理费、合同费等间接费系数。", "tags": ["投资估算", "朗格系数法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-073", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "项目建议书阶段的造价管理工作主要是（ ）。", "options": {"A": "编制施工图预算", "B": "编制设计概算", "C": "编制投资估算", "D": "竣工决算"}, "answer": ["C"], "analysis": "项目建议书阶段属于项目决策阶段，核心造价工作是编制投资估算（精度±30%），作为项目立项的依据。", "tags": ["决策阶段", "投资估算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-074", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "设计概算与施工图预算的主要区别在于（ ）。", "options": {"A": "编制依据的定额不同（概算定额vs预算定额）", "B": "是否包含人工费", "C": "计算方式不同", "D": "审批主体不同"}, "answer": ["A"], "analysis": "设计概算依据概算定额（或概算指标），施工图预算依据预算定额。概算定额比预算定额更概括、更综合。两者计算方式相似、都含人工费。", "tags": ["设计概算vs施工图预算", "对比"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-075", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "对于施工图预算审查，审查速度快但审查质量相对不高的方法是（ ）。", "options": {"A": "逐项审查法", "B": "分组计算审查法", "C": "对比审查法", "D": "标准预算审查法"}, "answer": ["B"], "analysis": "分组计算审查法速度快、工作量小，但审查质量不如逐项审查法。逐项审查法质量高但速度慢。需根据工程特点选用合适的审查方法。", "tags": ["施工图预算", "审查方法对比"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-076", "date": "2026-07-08", "chapter": "g05", "type": "single", "stem": "拟建项目投资估算中，已建类似项目设备费为2000万元，建筑工程费占设备费45%，安装工程费占设备费15%，其他费占设备费8%。拟建项目设备费2500万元，则总投资约为（ ）万元。", "options": {"A": "4000", "B": "4200", "C": "4400", "D": "4600"}, "answer": ["B"], "analysis": "采用比例估算法：总投资=设备费×(1+45%+15%+8%)=2500×(1+0.45+0.15+0.08)=2500×1.68=4200万元。", "tags": ["投资估算", "比例估算法", "计算题"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "ht_mgmt_1288", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "投资估算的编制方法中，以拟建项目的主体工程费为基数，以其他工程费与主体工程费的百分比为系数，估算拟建项目静态投资的方法是()。", "options": {"A": "单位生产能力估算法", "B": "生产能力指数法", "C": "系数估算法", "D": "比例估算法"}, "answer": ["C"], "analysis": "系数估算法也称为因子估算法，它是以拟建项目的主体工程费或主要设备购置费为基数，以其他工程费与主体工程费或设备购置费的百分比为系数，依此估算拟建项目静态投资的方法。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1289", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "2006年已建成年产20万吨的某化工厂，2010年拟建年产100万吨相同产品的新项目，并采用增加相同规格设备数量的技术方案。若应用生产能力指数法估算拟建项目投资额，则生产能力指数取值的适宜范围是()。", "options": {"A": "0.4～0.5", "B": "0.6～0.7", "C": "0.8～0.9", "D": "0.9～1"}, "answer": ["C"], "analysis": "生产能力指数x的确定一般要结合行业特点确定，正常情况下，0≤x≤1。不同生产率水平的国家和不同性质的项目中，x的取值不同。若已建类似项目规模和拟建项目规模的比值在0.5～2之间时，x的取值近似为1；若已建类似项目规模和拟建项目规模的比值为2～50，且拟建项目生产规模的扩大仅靠增大设备规模来达到时，则x的取值约为0.6～0.7；若是靠增加相同规格设备的数量达到时，x的取值约在0.8～0.9之间。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1290", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "下列投资估算方法中，属于以设备费为基础估算建设项目固定资产投资的方法是()。", "options": {"A": "生产能力指数法", "B": "朗格系数法", "C": "指标估算法", "D": "定额估算法"}, "answer": ["B"], "analysis": "朗格系数法属于系数估算法的一种，这种方法是以设备购置费为基数，乘以适当系数来推算项目的静态投资。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1291", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "关于项目决策和工程造价的关系，下列说法中正确的是( )。", "options": {"A": "工程造价的正确性是项目决策合理性的前提", "B": "项目决策的内容是决定工程造价的基础", "C": "投资估算的深度影响项目决策的精确度", "D": "投资决策阶段对工程造价的影响程度不大"}, "answer": ["B"], "analysis": "项目决策与工程造价的关系：(1)项目决策的正确性是工程造价合理性的前提；(2)项目决策的内容是决定工程造价的基础；(3)项目决策的深度影响投资估算的精确度；(4)工程造价的数额影响项目决策的结果。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1292", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "对于技术密集型建设项目，选择建设地区应遵循的原则是( )。", "options": {"A": "选择在大中型发达城市", "B": "靠近原料产地", "C": "靠近产地消费地", "D": "靠近电（能）源地"}, "answer": ["A"], "analysis": "对农产品、矿产品的初步加工项目，由于大量消耗原料，应尽可能靠近原料产地；对于能耗高的项目，如铝厂、电石厂等，宜靠近电厂，由此带来的减少电能输送损失所获得的利益，通常大大超过原料、半成品调运中的劳动耗费；而对于技术密集型的建设项目，由于大中城市工业和科学技术力量雄厚，协作配套条件完备、信息灵通，所以其选址宜在大中城市。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1293", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "某地拟于2015年新建一年产60万吨产品的生产线，该地区2013年建成的年产50万吨相同产品的生产线的建设投资额为5000万元。假定2013年至2015年该地区工程造价年均递增5%。则该生产线的建设投资为( )万元。", "options": {"A": "6000", "B": "6300", "C": "6600", "D": "6615"}, "answer": ["D"], "analysis": "建设投资=(60/50)×5000×(1+5%)2=6615（万元）", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1294", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "建设地点选择时需要进行费用分析，下列费用应列入项目投资费用比较的是（）。", "options": {"A": "动力供应费", "B": "燃料运入费", "C": "产品运出费", "D": "建材运输费"}, "answer": ["D"], "analysis": "在进行厂址多方案技术经济分析时，除比较上述建设地点（厂址）条件外，还应具有全寿命周期的理念，从项目投资费用和项目投产后生产经营费用两方面进行分析。项目投资费用包括土地征购费、拆迁补偿费、土石方工程费、运输设施费、排水及污水处理设施费、动力设施费、生活设施费、临时设施费、建材运输费等。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1295", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "按照形式资产法编制建设投资估算表，下列费用中应列入无形资产费用的是（）。", "options": {"A": "建设单位管理费", "B": "商誉", "C": "生产设备及开办费", "D": "引进技术费"}, "answer": ["B"], "analysis": "在形成资产法时对于土地使用权有比较特殊的处理：按照有关规定，在尚未开发或建造子用项目前，土地使用权作为无形资产核算，房地产开发企业开发商品房时，将其账面价值转入开发成本；企业建造自用项目时将其账面价值转入在建工程成本。因此，为了与以后的折旧和摊销计算项协调，在建设投资估算表中通常可将土地使用权直接列入固定资产其他费用中。无形资产费用是指将直接形成无形资产的建设投资，主要是专利权、非专利技术、商标权、土地使用权和商誉等", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1296", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "投资估算的主要工作包括：①估算流动资金；②估算价差预备费和建设利息；③估算工程建设其他费用和基本预备费；④估算各单项工程所需建筑工程费、设备及工器具购置费、安装工程费。其正确的工作步骤是（）。", "options": {"A": "④②①③", "B": "③④②①", "C": "④③②①", "D": "④③①②"}, "answer": ["C"], "analysis": "投资估算的编制一般包含静态投资部分、动态投资部分与流动资金估算三部分，主要包括以下步骤：（1）分别估算各单项工程所需建筑工程费、设备及工器具购置费、安装工程费，在汇总各单项工程费用的基础上，估算工程建设其他费用和基本预备费，完成工程项目静态投资部分的估算；（2）在静态投资部分的基础上，估算价差预备费和建设利息，完成工程项目动态投资部分的估算；（3）估算流动资金；（4）估算建设项目总投资。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1297", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "先求出已有同类企业主要设备投资占项目静态投资的比例系数，然后再估算出拟建项目的主要设备投资，最后按比例系数求出拟建项目的静态投资，这种估算方法称()。", "options": {"A": "设备系数法", "B": "主体专业系数法", "C": "朗格系数法", "D": "比例估算法"}, "answer": ["D"], "analysis": "设备系数法是指以拟建项目的设备购置费为基数，根据已建成的同类项目的建筑安装工程费和其他工程费等与设备价值的百分比，求出拟建项目建筑安装工程费和其他工程费，进而求出项目的静态投资。主体专业系数法是指以拟建项目中投资比重较大，并与生产能 力直接相关的工艺设备投资为基数，根据已建同类项目的有关统计资料，计算出拟建项目各专业工程（总图、土建、采暖、给排水、管道、电气、自控等）与工艺设备投资的百分比，据以求出拟建项目各专业投资，然后加总即为拟建项目的静态投资。朗格系数法。这种方法是以设备购置费为基数，乘以适当系 数来推算项目的静态 投资。这种方法在国内不常见，是世行项目投资估算常采用的方法。 该方法的基本原理是将项目建设中的总成本费用中的直接成本和间接成本分别计算，再合为项目的静态投资。比例估算法是根据已知的同类建设项目主要设备购置费占整个建设项目的投资比例，先逐项估算出拟建项目主要设备购置费，再按比例估算拟建项目的静态投资的方法。本办法主要应用于设计深度不足，拟建建设项目与类似建设项目的主要设备购置费比重较大，行业内相关系数等基础资料完备 的情况 。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1298", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "某建设项目投产后，应付账款的最低周转天数为15天，预计年销售收入为12000万元，年经营成本9000万元，其中外购原材料、燃料7200万元，则该项目的应付账款估算额为()万元。", "options": {"A": "500", "B": "375", "C": "300", "D": "125"}, "answer": ["C"], "analysis": "估算应付账款的公式是：应付账款=外购原材料、燃料动力及其他材料年费用／应付账款周转次数，因此，应付账款的估算额=7200／(360／15)=300（万元），", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1299", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "投资决策阶段对工程造价的影响程度最高，可达到的比例是()。", "options": {"A": "50%～70%", "B": "70%～90%", "C": "70%", "D": "75%～90%"}, "answer": ["B"], "analysis": "据有关资料统计，在项目建设各阶段中，投资决策阶段影响工程造价的程度最高，达到70%～90%。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1300", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "对于农产品、矿产品等初步加工建设项目，在进行建设地区选择时应遵循的原则是()。", "options": {"A": "靠近大中城市", "B": "靠近燃料提供地", "C": "靠近产品消费地", "D": "靠近原料产地"}, "answer": ["D"], "analysis": "对农产品、矿产品的初步加工项目，由于大量消耗原料，应尽可能靠近原料产地。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1301", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "总承包工程报价时，承包商大都采用的估算方法是()。", "options": {"A": "单位生产能力估算法", "B": "生产能力指数法", "C": "系数估算法", "D": "指标估算法"}, "answer": ["B"], "analysis": "生产能力指数法有独特的好处，即这种估价方法不需要详细的工程设计资料，只需要知道工艺流程及规模就可以，在总承包工程报价时，承包商大都采用这种方法。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1302", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "某企业全年的销售收入是3000万元，经营成本占全部销售收入的40%，年其他营业费用为600万元，应收账款年周转次数是6次，则应收账款估算额为()万元。", "options": {"A": "100", "B": "200", "C": "400", "D": "500"}, "answer": ["B"], "analysis": "应收账款=年经营成本／应收账款周转次数=3000×40%／6=200（万元）。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1303", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "下列内容中，不属于工程方案选择的基本要求是()。", "options": {"A": "经济合理", "B": "先进适用", "C": "符合工程标准规范要求", "D": "适应已选定的场址"}, "answer": ["B"], "analysis": "工程方案选择应满足的基本要求包括：满足生产使用功能要求；适应已选定的场址（线路走向）；符合工程标准规范要求；经济合理。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1304", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "建设项目规模的合理选择关系到项目的成败，决定着项目工程造价的合理与否。影响项目规模合理化的制约因素主要包括()。", "options": {"A": "资金因素、技术因素和环境因素", "B": "资金因素、技术因素和市场因素", "C": "市场因素、技术因素和环境因素", "D": "市场因素、环境因素和资金因素"}, "answer": ["C"], "analysis": "建设规模也称项目生产规模，是指项目在其设定的正常生产营运年份可能达到的生产能力或者使用效益。在项目决策阶段应选择合理的建设规模，以达到规模经济的要求。但规模扩大所产生效益不是无限的，它受到技术进步、管理水平、项目经济技术环境等多种因素的制约。而资金因素是在确定了项目合理规模后所考虑的问题，应根据所确定的项目规模来考虑资金筹措的问题。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1305", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "建设项目的建设地区选择应遵循工业项目适当聚集的原则，其原因是()。", "options": {"A": "有利于原材料和产品的运输，缩短流通时间", "B": "有利于集中用水，开辟新水源、远距离引水", "C": "能为不同类型的劳动者提供多种就业机会", "D": "生产排泄物集中排放，降低环境污染"}, "answer": ["C"], "analysis": "工业项目适当聚集的原则。在工业布局中，通常是一系列相关的项目聚成适当规模的工业基地和城镇，从而有利于发挥“集聚效益”，对各种资源和生产要素充分利用，便于形成综合生产能力，便于统一建设比较齐全的基础结构设施，避免重复建设，节约投资。此外，还能为不同类型的劳动者提供多种就业机会。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1306", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "在项目决策阶段，环境治理方案比选的主要内容有()。", "options": {"A": "技术水平对比", "B": "环境影响比较", "C": "安全条件对比", "D": "经营费用比较"}, "answer": ["A"], "analysis": "环境治理方案比选主要包括：技术水平对比；治理效果对比；管理及监测方式对比；环境效益对比。建设地点（厂址）其比较的主要内容包括：建设条件比较、建设费用比较、经营费用比较、运输费用比较、环境影响比较及安全条件比较。应注意不要混淆。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1307", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "按照有关规定，在尚未开发或建造自用项目前，土地使用权作为()核算。", "options": {"A": "固定资产费用", "B": "无形资产费用", "C": "其他资产费用", "D": "工程费用"}, "answer": ["B"], "analysis": "对于土地使用权的特殊处理：按照有关规定，在尚未开发或建造自用项目前，土地使用权作为无形资产核算，房地产开发企业开发商品房时，将其账面价值转入开发成本；企业建造自用项目时将其账面价值转入在建工程成本。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1308", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "在投资估算分析内容中，属于工程投资比例分析的是()。", "options": {"A": "分析工器具购置费占建设总投资的比例", "B": "分析引进设备费用占全部设备费用的比例", "C": "分析工程建设其他费用占建设总投资的比例", "D": "分析装饰工程占总投资的比例"}, "answer": ["D"], "analysis": "工程投资比例分析的内容：一般建筑工程要分析土建、装饰、给排水、电气、暖通、空调、动力等主体工程和道路、广场、围墙、大门、室外管线、绿化等室外附属工程占总投资的比例；一般工业项目要分析主要生产项目（列出各生产装置）、辅助生产项目、公用工程项目（给排水、供电和通信、供气、总图运输及外管）、服务性工程、生活福利设施、厂外工程占建设总投资的比例。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1309", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "按照生产能力指数法（x=0.8，f=1.1），如将设计中的化工生产系统的生产能力提高到3倍，投资额将增加为( )。", "options": {"A": "118.9%", "B": "158.3%", "C": "164.9%", "D": "191.5%"}, "answer": ["C"], "analysis": "C2/C1=3^0.8*1.1=2.649，则投资额增加为2.649-1=1.649，即164.9%", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1310", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "关于生产技术方案的选择，下列说法中正确的是()。", "options": {"A": "应结合市场需要确定建设规模", "B": "生产方法应与拟采用的原材料相适应", "C": "工艺流程宜具有刚性安排", "D": "应选择最先进的生产方法"}, "answer": ["B"], "analysis": "生产方法是指产品生产所采用的制作方法，生产方法直接影响生产工艺流程的选择。一般在选择生产方法时，从以下几个方面着手：(1)研究分析与项目产品相关的国内外生产方法的优缺点，并预测发未来展趋势，积极采用先进适用的生产方法；(2)研究拟采用的生产方法是否与采用的原材料相适应，避免出现生产方法与供给原材料不匹配的现象；(3)研究拟采用生产方法的技术来源的可得性，若采用引进技术或专利，应比较所需费用；(4)研究拟采用生产方法是否符合节能和清洁的要求，应尽量选择节能环保的生产方法。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1311", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "某地2012年拟建年产30万吨化工产品项目。依据调查，某生产相同产品的已建成项目，年产量为10万吨，建设投资为12000万元。若生产能力指数为0.9，综合调整系数为1.15，则该拟建项目的建设投资是()万元。", "options": {"A": "28047", "B": "36578", "C": "37093", "D": "37260"}, "answer": ["C"], "analysis": "", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1312", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "在国外对投资估算的阶段划分中，项目投资机会研究阶段的投资估算精度要求为误差控制在()以内。", "options": {"A": "±30%", "B": "±20%", "C": "±10%", "D": "±5%"}, "answer": ["A"], "analysis": "投资机会研究阶段的投资估算。这一阶段称为粗估阶段， 或称因素估算，其对投资估算精度的要求误差控制在 ±30%以内，故选A", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1313", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "世界银行贷款项目的投资估算采用朗格系数法推算建设项目的静态投资，该方法的计算基数是（）。", "options": {"A": "主体工程费", "B": "设备购置费", "C": "其他工程费", "D": "安装工程费"}, "answer": ["B"], "analysis": "朗格系数法是以设备费购置费为基数，乘以适当系数来推算项目的静态投资。这种方法在国内不常见，是世行项目投资估算常采用的方法。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1314", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "某建设项目达到设计能力后，全场定员1000人，工资和福利费按照每人每年2万元估算。每年的其他费用为1000万元，其中其他制造费600万元，现金的周转次数为每年10次。流动资金估算中应收账款估算额为2000万元，预收账款估算额为300万元，应付账款估算额为1500万元，存货估算额为6000万元，预付账款估算额500万元，则该项目流动资金估算额为()万元。", "options": {"A": "7000", "B": "6400", "C": "10000", "D": "9960"}, "answer": ["A"], "analysis": "在流动资金分项详细估算法中，基本原理如下：流动资金=流动资产-流动负债=（应收账款+存货+库存现金+预付账款）-（应付账款+预收账款）应收账款、存货、预付账款、应付账款和预收账款都已给出，只需估算现金。现金=（年工资及福利+年其他费）／现金周转次数=(2×1000+1000)／10=300（万元）最后的计算结果为：2000+6000+300+500-(1500+300)=7000（万元）", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1315", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "现有一通用设备，原价3万元，重5t，设备安装费指标为100元/t，安装费率2%。设备的安装费为()元。", "options": {"A": "600", "B": "700", "C": "800", "D": "900"}, "answer": ["A"], "analysis": "设备的安装费=设备原价×安装费率(%)=30000×2%=600（元）。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1316", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "下列工作内容中，在选择工艺流程方案时需要研究的是()。", "options": {"A": "主要设备之间的匹配性", "B": "生产方法是否符合节能要求", "C": "工艺流程设备的安装方式", "D": "各工序间是否合理衔接"}, "answer": ["D"], "analysis": "选择工艺流程方案的具体内容包括以下几方面：(1)研究工艺流程方案对产品质量的保证程度；(2)研究工艺流程各工序间的合理衔接，工艺流程应通畅、简捷；(3)研究选择先进合理的物料消耗定额，提高收益；(4)研究选择主要工艺参数；(5)研究工艺流程的柔性安排。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1317", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "根据已知的同类建设项目主要生产工艺设备占整个建设项目的投资比例，先逐项估算出拟建项目主要生产工艺设备投资，再按比例估算拟建项目的静态投资，这种估算方法称()。", "options": {"A": "设备系数法", "B": "主体专业系数法", "C": "朗格系数法", "D": "比例估算法"}, "answer": ["D"], "analysis": "比例估算法是根据已知的同类建设项目主要生产工艺设备占整个建设项目的投资比例，先逐项估算出拟建项目主要生产工艺设备投资，再按比例估算拟建项目的静态投资的方法。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1318", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "建设项目投资估算可以根据主体专业设计的阶段和深度采用混合法，下列方法中两两混合后属于混合法的是()。", "options": {"A": "生产能力指数法与系数估算法", "B": "系数估算法与比例估算法", "C": "单位生产能力估算法与比例估算法", "D": "系数估算法与单位生产能力估算法"}, "answer": ["B"], "analysis": "混合法是根据主体专业设计的阶段和深度，投资估算编制者所掌握的国家及地区、行业或部门相关投资估算基础资料和数据，以及其他统计和积累的、可靠的相关造价基础资料，对一个拟建建设项目采用生产能力指数法与比例估算法或系数估算法与比例估算法混合估算其相关投资额的方法。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1319", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "已知某项目各项财务基础数据中，总成本费用为1000万元（其中营业费用为200万元），其中折旧费200万元，摊销费50万元，修理费100万元，人工工资及福利费80万元，利息为20万元，若营业费用中折旧费、摊销费、修理费、人工工资及福利费均为各项费用总额的20%，产成品的年周转次数为10次，则该项目流动资金估算中的产成品为( )万元。", "options": {"A": "58", "B": "73", "C": "60", "D": "61.6"}, "answer": ["D"], "analysis": "年经营成本=1000-200-50-20= 730（万元）；年其他营业费用=200-(200+50+100+80)×20% =114（万元）产成品=（经营成品-其他营业费用）/周转次数=（730-114）/10=61.6", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1320", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "进行流动资产投资估算时，通常计算的是各项流动资金的（ ）。", "options": {"A": "各项流动资金的年库存量", "B": "各项流动资金的年周转次数", "C": "各项流动资金的年周转额度", "D": "各项流动资金年平均占用额度"}, "answer": ["D"], "analysis": "周转次数是指流动资金的各个构成项目在一年内完成多少个生产过程，可用1年天 数（通常按360天计算）除以流动资金的最低周转天数计算，则各项流动资金年平均占用额度为流动 资金的年周转额度除以流动资金的年周转次数。进行流动资金估算时，首先计算各类流动资产和流动负债的年周转次数，估算占用资金额", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1321", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "在国外项目投资估算中，有初步的工艺流程图、主要生产设备的生产能力及项目建设的地理位置等条件，可套用相近规模厂的单位生产能力建设费用来估算拟建项目所需的投资额。以上投资估算方法适用于( )阶段。", "options": {"A": "项目的投资设想", "B": "项目的投资机会研究", "C": "项目的初步可行性研究", "D": "项目的详细可行性研究"}, "answer": ["B"], "analysis": "本题考查的是投资估算的概念及其编制内容。投资机会研究阶段的投资估算。此时应有初步的工艺流程图、主要生产设备的生产能力及项目建设的地理位置等条件，故可套用相近规模厂的单位生产能力建设费用来估算拟建项目所需的投资额，据此初步判断项目是否可行。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1322", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "项目决策阶段对环境治理方案进行技术经济比较时，不作为比较内容的是（）。", "options": {"A": "技术水平对比", "B": "管理及监测方式对比", "C": "安全生产条件对比", "D": "环境效益对比"}, "answer": ["C"], "analysis": "环境治理方案必选的主要内容包括：1）技术水平对比；2）治理效果对比；3）管理及监测方式对比；4）环境效益对比", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1323", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "某建设项目建成正常运营后，年销售收入5000 万元,年经营成本3500 万元,外购原材料、燃料及其他材料的年费用1800 万元，应付账款的周转天数60 天。则该项目应付账款年估算额为（）万元。", "options": {"A": "600", "B": "250", "C": "300", "D": "550"}, "answer": ["C"], "analysis": "应付账款年估算额=应付账款=外购原材料、燃料动力费及其他材料年费用/应付账款周转次数=1800/(360/60)=300(万元）", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1324", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "在项目建设各阶段中，投资决策阶段对工程造价的影响达到（）。", "options": {"A": "60%—90%", "B": "70%—90%", "C": "70%—80%", "D": "60%—80%"}, "answer": ["B"], "analysis": "据有关资料统计,在项目建设各阶段中，投资决策阶段影响工程造价的程度最高，达到70%~90%。因此，决策阶段是决定工程造价的基础阶段。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1325", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "投资机会及项目建议书阶段，是初步决策的阶段，投资估算的误差率在（）左右。", "options": {"A": "±10%", "B": "±20%", "C": "±30%", "D": "±40%"}, "answer": ["C"], "analysis": "投资机会及项目建议书阶段，是初步决策的阶段，投资估算的误差率在±30%左右。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1326", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "下列关于建筑工程费用估算的说法,不正确的是（）。", "options": {"A": "单位建筑工程投资估算法是以单位建筑工程费用乘以建筑工程总量来估算建筑工程费的方法", "B": "单位实物工程量投资估算法是以单位实物工程量的建筑工程费乘以实物工程总量来估算建筑工程费的方法", "C": "建筑工程费占总投资比例较大的项目，可采用概算指标估算法", "D": "采用概算指标估算法时投入的时间和工作量较小"}, "answer": ["D"], "analysis": "概算指标投资估算法：对于没有上述估算指标,或者建筑工程费占总投资比例较大的项目，可采用概算指标估算法。采用此种方法，应拥有较为详细的工程资料、建筑材料价格和工程费用指标，投入的时间和工作量较大。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1327", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "应满足的要求:满足生产使用功能要求;适应已选定的场址（线路走向）；符合工程标准规范要求;经济合理。投资估算分析不包括（）。", "options": {"A": "过程投资总额分析", "B": "工程投资比例分析", "C": "分析设备及工器具购置费占建设总投资的比例", "D": "分析影响投资的主要因素"}, "answer": ["A"], "analysis": "投资估算分析应包括以下内容：1)工程投资比例分析；2)分析设备及工器具购置费、建筑工程费、安装工程费、预备费、建设期利息占建设总投资的比例等；3)分析影响投资的主要因素；4)分析说明投资高低的原因。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1328", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "下列安装工程费估算公式中，适用于估算工业炉窑砌筑和工艺保温或绝热工程安装工程费的是（ ）。", "options": {"A": "设备原价×设备安装费率（%）", "B": "重量（体积、面积）总量×单位重量（体积、面积）安装费指标", "C": "设备原件×材料费占设备费百分比×材料安装费率（%）", "D": "安装工程功能总量×功能单位安装工程费标准"}, "answer": ["B"], "analysis": "工业炉窑砌筑和工艺保温或绝热估算，以单项工程为单元，以吨、立方米或平方米为单位即：安装工程费=重量（体积、面积）总量×单位重量（立方米、平方米）安装费指标。 本题库是以官方教材为依据，知识点所对应的习题综合了二建法规、二建管理、造价员基础、一级造价师考试的题库+真题编辑，基本上做到了每个知识点都有相对应的题目及解析,题库会陆续更新,会有模拟题,预测题及考前更新押题。 《建设工程计量与计价实务》题库编辑中,教材出来后会陆续更新 www.jinkaodian.com 金考典考试软件。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1329", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "下列利用分项详细估算法计算流动资金的公式中，正确的是()。", "options": {"A": "预收账款=营业收入年金额／预收账款周转次数", "B": "应收账款=年经营成本／应收账款周转次数", "C": "在产品=（年经营成本-年其他营业费用）／在产品周转次数", "D": "预付账款=外购原材料、燃料费用／预付账款周转次数"}, "answer": ["B"], "analysis": "流动资金各项内容估算公式如下： (1)预收账款=预收的营业收入年金额／预收账款周转次数 (2)应收账款=年经营成本／应收账款周转次数 (3)产成品=（年经营成本-年其他营业费用）／产成品周转次数 (4)预付账款=外购商品或服务年费用金额／预付账款周转次数 本题库是以官方教材为依据，知识点所对应的习题综合了二建法规、二建管理、造价员基础、一级造价师考试的题库+真题编辑，基本上做到了每个知识点都有相对应的题目及解析,题库会陆续更新,会有模拟题,预测题及考前更新押题。 《建设工程计量与计价实务》题库编辑中,教材出来后会陆续更新 www.jinkaodian.com 金考典考试软件。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1330", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "柱网布置是否合理，对工程造价和面积的利用效率都有较大影响。建筑设计中对柱网布置应注意()。", "options": {"A": "适当扩大柱距和跨度能使厂房有更大的灵活性", "B": "单跨厂房跨度不变时，层数越多越经济", "C": "多跨厂房柱间距不变时，跨度越大造价越低", "D": "柱网布置与厂房的高度无关"}, "answer": ["A"], "analysis": "柱网布置是确定柱子的跨度和间距的依据。柱网的选择与厂房中有无吊车、吊车的类型及吨位、屋顶的承重结构以及厂房的高度等因素有关。对于单跨厂房，当柱间距不变时，跨度越大单位面积造价越低。因为除屋架外，其他结构架分摊在单位面积上的平均造价随跨度的增大而减小；对于多跨厂房，当跨度不变时，中跨数目越多越经济。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1331", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "按照国家有关规定，作为年度固定资产投资计划、计划投资总额及构成数额的编制和确定依据是()。", "options": {"A": "经批准的投资估算", "B": "经批准的设计概算", "C": "经批准的施工图预算", "D": "经批准的工程决算"}, "answer": ["B"], "analysis": "设计概算是编制固定资产投资计划、确定和控制建设项目投资的依据。设计概算投资应包括建设项目从立项、可行性研究、设计、施工、试运行到竣工验收等的全部建设资金。按照国家有关规定，编制年度固定资产投资计划，确定计划投资总额及其构成数额，要以批准的初步设计概算为依据，没有批准的初步设计文件及其概算，建设工程不能列入年度固定资产投资计划。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1332", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "关于建设项目总概算的编制，下列说法中正确的是()。", "options": {"A": "项目总概算应按照建设单位规定的统一表格进行编制", "B": "工程建设其他费用概算按国家或地区或部委所规定的项目和标准确定，并按统一格式编制", "C": "主要建筑安装材料汇总表只需列出建设项目的钢筋、水泥等主要材料各自的总消耗量", "D": "总概算编制说明应装订于总概算文件最后"}, "answer": ["B"], "analysis": "工程建设其他费用概算表。工程建设其他费用概算按国家或地区或部委所规定的项目和标准确定，并按统一格式编制（见表 3.2.8)。应按具体发生的工程建设其他费用项目填写工程建设其他费用概算表，需要说明和具体计算的费用项目依次相应在说明及计算式栏内填写或具体计算。填写时注意以下事项：1) 土地征用及拆迁补偿费应填写土地补偿单价、数量和安置补助费标准、数量等，列式计算所需费用，填入金额栏。2) 建设管理费包括建设单位（业主 管理费、工程监理费等，按“工程费用X费率”或有关定额列式计算。3) 研究试验费应根据设计需要进行研究试验的项目分别填写项目名称及金额或列式计算或进行说明。(5) 单项工程综合概算表和建筑安装单位工程概算表。(6) 主要建筑安装材料汇总表。针对毎一个单项工程列出钢筋、型钢、水泥、木材等主要建筑安装材料的消耗量。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1333", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "单位工程概算按其工作性质可分为单位建筑工程概算和单位设备及安装工程概算两类，下列属于单位设备及安装工程概算的是( )。", "options": {"A": "通风、空调工程概算", "B": "工器具及生产家具购置费概算", "C": "电气、照明工程概算", "D": "弱电工程概算"}, "answer": ["B"], "analysis": "建筑工程概算包括土建工程概算，给排水、采暖工程概算，通风、空调工程概算，电气照明工程概算，弱电工程概算，特殊构筑物工程概算等；设备及安装工程概算包括机械设备及安装工程概算，电气设备及安装工程概算，热力设备及安装工程概算，工具、器具及生产家具购置费概算等。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1334", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "当建设项目为一个单项工程时，其设计概算应采用的编制形式是（）。", "options": {"A": "单位工程概算、单项工程综合概算和建设项目总概算二级", "B": "单位工程概算和单项工程综合概算二级", "C": "单项工程综合概算和建设项目总概算二级", "D": "单位工程概算和建设项目总概算二级"}, "answer": ["D"], "analysis": "设计概算文件的编制应采用单位工程概算、单项工程综合概算、建设项目总概算三级概算编制形式。当建设项目为一个单项工程时，可采用单位工程概算、总概算两级概算编制形式。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1335", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "对于技术复杂、设计有难度的工程通常采用三阶段设计，即()。", "options": {"A": "方案设计、技术设计和施工图设计", "B": "总体设计、技术设计和施工图设计", "C": "初步设计、技术设计和施工图设计", "D": "总平面设计、工艺设计和建筑设计"}, "answer": ["C"], "analysis": "对于技术上复杂、在设计时有一定难度的工程，根据项目相关管理部门的意见和要求，可以按初步设计、技术设计和施工图设计三个阶段进行，称为三阶段设计。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1336", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "当初步设计较深，有详细的设备清单时，可采用的设备安装工程概算编制方法是()。", "options": {"A": "扩大单价法", "B": "预算单价法", "C": "综合吨位指标法", "D": "安装设备百分比法"}, "answer": ["B"], "analysis": "当初步设计较深，有详细的设备清单时，可直接按安装工程预算定额单价编制安装工程概算，概算编制程序与安装工程施工图预算程序基本相同。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1337", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "当初步设计有详细设备清单时，可按()编制单位设备安装工程概算。", "options": {"A": "概算指标法", "B": "预算单价法", "C": "扩大单价法", "D": "安装设备百分比法"}, "answer": ["B"], "analysis": "当初步设计较深，有详细的设备清单时，可直接按安装工程预算定额单价编制安装工程概算，概算编制程序基本同于安装工程施工图预算。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1338", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "当初步设计达到一定深度，建筑结构尺寸比较明确、能结合图纸计算工程量时，编制单位工程概算宜采用()。", "options": {"A": "扩大单价法", "B": "概算指标法", "C": "类似工程预算法", "D": "综合单价法"}, "answer": ["A"], "analysis": "建筑工程概算的编制方法有：概算定额法、概算指标法、类似工程预算法等，其中概算定额法又叫扩大单价法或扩大结构定额法，是套用概算定额编制建筑工程概算的方法，要求初步设计达到一定深度，建筑结构尺寸比较明确，能按照初步设计的平面图、立面图、剖面图纸计算出楼地面、墙身、门窗和屋面等扩大分项工程（或扩大结构构件）项目的工程量时，方可采用。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1339", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "总平面设计是指总图运输设计和总平面配置，下列内容中均属于总平面设计中影响工程造价的主要因素的有()。", "options": {"A": "现场条件、占地面积、功能分区", "B": "占地面积、功能分区、工艺流程", "C": "占地面积、运输方式、工艺流程", "D": "现场条件、运输方式、工艺流程"}, "answer": ["A"], "analysis": "本题要求考生正确理解总平面设计和工艺设计的概念和内容。工艺流程属于工艺设计的内容，不是总平面设计的内容。所以本题的正确答案为A。按照建设程序，建设项目的工艺流程在可行性研究阶段已经确定。设计阶段的任务就是严格按照批准的可行性研究报告的内容进行工艺技术方案的设计，确定具体的工艺流程和生产技术。在具体项目工艺设计方案的选择时，应以提高投资的经济效益为前提，深人分析、比较，综合考虑各方面的因素。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1340", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "建筑结构的选择既要满足力学要求，又要考虑其经济性。对于多层房屋或大跨度结构的项目，应优先选用()。", "options": {"A": "砌体结构", "B": "钢筋混凝土结构", "C": "钢结构", "D": "框架结构"}, "answer": ["C"], "analysis": "对于五层以下的建筑物一般选用砌体结构；对于大中型工业厂房一般选用钢筋混凝土结构；对于多层房屋或大跨度结构，选用钢结构明显优于钢筋混凝土结构；对于高层或者超高层结构，框架结构和剪力墙结构比较经济。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1341", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "初步设计达到一定深度，建筑结构尺寸比较明确，能按照初步设计的平面图、立面图、剖面图纸计算出楼地面、墙身、门窗和屋面等扩大分项工程（或扩大结构构件）项目的工程量时，此时比较适用的编制概算的方法是()。", "options": {"A": "概算定额法", "B": "概算指标法", "C": "类似工程预算法", "D": "综合吨位指标法"}, "answer": ["A"], "analysis": "概算定额法又称扩大单价法或扩大结构定额法，是套用概算定额编制建筑工程概算的方法。运用概算定额法，要求初步设计必须达到一定深度，建筑结构尺寸比较明确，能按照初步设计的平面图、立面图、剖面图纸计算出楼地面、墙身、门窗和屋面等扩大分项工程（或扩大结构构件）项目的工程量时，方可采用。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1342", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "常用于设备价格波动较大的非标准设备和引进设备的安装工程概算编制方法是()。", "options": {"A": "预算单价法", "B": "扩大单价法", "C": "设备价值百分比法", "D": "综合吨位指标法"}, "answer": ["D"], "analysis": "各种安装工程概算编制方法的适用对象是一个常考的问题，尤其是设备价值百分比法和综合吨位指标法的区别。设备价值百分比法常用于价格波动不大的定型产品和通用设备产品；综合吨位指标法常用于设备价格波动较大的非标准设备和引进设备的安装工程概算。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1343", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "工业建筑设计评价中，下列不同平面形状的建筑物，其建筑物周长与建筑面积比K周按从小到大顺序排列正确的是( )。", "options": {"A": "正方形→矩形→T形→L形", "B": "矩形→正方形→T形→L形", "C": "T形→L形→正方形→矩形", "D": "L形→T形→矩形→正方形"}, "answer": ["A"], "analysis": "本题考查的是设计阶段影响工程造价的主要因素。圆形、正方形、矩形、T形、L形，建筑周长系数依次增大。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1344", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "在建设项目各阶段的工程造价中，一经批准将作为控制建设项目投资最高限额的是( )。", "options": {"A": "投资估算", "B": "设计概算", "C": "施工图预算", "D": "竣工结算"}, "answer": ["B"], "analysis": "本题考查的是设计概算的概念及其编制内容。设计概算一经批准，将作为控制建设投资的最高限额。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1345", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "在用类似工程预算法编制工程概算时，需用价差公式对类似工程的成本单价进行调整，以下各项中不属于成本单价的是()。", "options": {"A": "人工费", "B": "施工机具使用费", "C": "企业管理费", "D": "规费"}, "answer": ["D"], "analysis": "价差调整公式为： 式中a%、b%、c%、d%、——类似工程预算的人工费、材料费、施工机具使用费、企业管理费占预算成本的比重。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1346", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "下列建筑设计影响工程造价的选项中，属于影响工业建筑但一般不影响民用建筑的因素是( )。", "options": {"A": "建筑物平面形状", "B": "项目利益相关者", "C": "柱网布置", "D": "风险因素"}, "answer": ["C"], "analysis": "本题考查的是设计阶段影响工程造价的主要因素。柱网布置是工业建设项目所独有的，在民用建设项目中，没有该影响因素。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1347", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "工业项目总面积设计中，影响工程造价的主要因素包括()。", "options": {"A": "现场条件、占地面积、功能分区、运输方式", "B": "现场条件、产品方案、运输方式、柱网布置", "C": "占地面积、功能分区、空间组合、建筑材料", "D": "功能分区、空间组合、设备选型、厂址方案"}, "answer": ["A"], "analysis": "总平面设计中影响工程造价的主要因素包括：现场条件、占地面积、功能分区、运输方式的选择。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1348", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "下列不属于影响民用住宅建筑设计中影响工程造价的主要因素的是()。", "options": {"A": "建筑物平面形状和周长系数", "B": "住宅的层高和净高", "C": "建筑物的体积与面积", "D": "住宅建筑结构的选择"}, "answer": ["C"], "analysis": "影响民用住宅建筑设计中影响工程造价的主要因素：建筑物平面形状和周长系数；住宅的层高和净高；住宅的层数；住宅单元组成、户型和住户面积；住宅建筑结构的选择。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1349", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "利用概算指标法编制拟建工程概算，已知概算指标中每100㎡建筑面积中分摊的人工消耗量为500工日。拟建工程与概算指标相比，仅楼地面做法不同，概算指标为瓷砖地面，拟建工程为花岗岩地面。查预算定额得到铺瓷砖和花岗岩地面的人工消耗量分别为37工日/100㎡和24工日/100㎡。拟建工程楼地面面积占建筑面积的65%。则对概算指标修正后的人工消耗量为()工日/100㎡。", "options": {"A": "316.55", "B": "491.55", "C": "508.45", "D": "845.00"}, "answer": ["B"], "analysis": "结构变化修正概算指标的人工量=原概算指标的人工量+换入结构件工程量×相应定额 人工消耗量-换出结构件工程量×相应定额人工消耗量 拟建工程100㎡中楼地面面积=100×65%=65(㎡) 修正后100㎡的人工消耗量=500+24×65/100-37×65/100=491.55（工日）", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1350", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "当初步设计深度不够，不能准确地计算出工程量，但工程设计技术比较成熟而又有类似工程概算指标可以利用时，可采用的方法是()。", "options": {"A": "概算定额法", "B": "概算指标法", "C": "类似工程预算法", "D": "类似工程概算法"}, "answer": ["B"], "analysis": "2.概算指标法概算指标法是用拟建的厂房、住宅的建筑面积（或体积）乘以技术条件相同或基本相同的概算指标而得出人、材、机费，然后按规定计算出企业管理费、利润、增值税等，得出单位工程概算的方法。概算指标法适用的情况包括： 1)在方案设计中，由于设计无详图而只有概念性设计时，或初步设计深度不够，不能准确地计算出工程量.，但工程设计采用的技术比较成熟时可以选定与该工程相似类型的概算指标编制概算； 2)设计方案急需造价概算而又有类似工程概算指标可以利用的情况； 3)图样设计间隔很久后再来实施，概算造价不适用于当前情况而又急需确定造价的情形下，可按当前概算指标来修正原有概算造价； 4)通用设计图设计可组织编制通用图设计概算指标，来确定造价。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1351", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "在建筑工程初步设计文件深度不够、不能准确计算出工程量的情况下，可采用的设计概算编制方法是（）。", "options": {"A": "概算定额法", "B": "概算指标法", "C": "预算单价法", "D": "综合吨位指标法"}, "answer": ["B"], "analysis": "概算指标法适用的情况包括：（1）在方案设计中，由于设计无详图而只有概念性设计时，或初步设计深度不够，不能准确地计算出工程量，但工程设计采用的技术比较成熟时可以选定与该工程相似类型的概算指标编制概算。（2）设计方案急需造价概算而又有类似工程概算指标可以利用的情况。（3）图样设计间隔很久后再来实施，概算造价不适用于当前情况而又急需确定造价的情形下，可按当前概算指标来修正原有概算造价。（4）通用设计图设计可组织编制通用图设计概算指标，来确定造价。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1352", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "已知某引进设备吨重为50t，设备原价3000万元，每吨设备安装费指标为8万元，同类国产设备的安装费率为15%，则该设备安装费为()万元。", "options": {"A": "400", "B": "425", "C": "450", "D": "500"}, "answer": ["A"], "analysis": "综合吨位指标法。当初步设计提供的设备清单有规格和设备重量时，可采用综合吨位指标编制概算，其综合吨位指标由相关主管部门或由设计单位根据已完类似工程的资料确定。该法常用于设备价格波动较大的非标准设备和引进设备的安装工程概算，其计算 (3.2.8) 公:式为设备安装费= 设备吨重X每吨设备安装费指标（元/吨）", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1353", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "拟建工程初步设计与已完工程或在建工程的设计相类似而又没有可用的概算指标时采用，但必须对建筑结构差异和价差进行调整，适用于()方法。", "options": {"A": "概算指标法", "B": "类似工程预算法", "C": "分组计算审查法", "D": "标准预算审查法"}, "answer": ["B"], "analysis": "类似工程预算法在拟建工程初步设计与已完工程或在建工程的设计相类似而又没有可用的概算指标时采用，但必须对建筑结构差异和价差进行调整。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1354", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "某建设项目由各个单项工程构成，应包含在其中某单项工程综合概算中的费用项目是()。", "options": {"A": "工器具及生产家具购置费", "B": "办公和生活用品购置费", "C": "研究试验费", "D": "基本预备费"}, "answer": ["A"], "analysis": "综合概算一般应包括建筑工程费用、安装工程费用、设备及工器具购置费。而B、C属于建设项目总概算中其他费用概算的内容，D属于建设项目总概算中预备费的内容。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1355", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "对于民用建设项目，衡量单元组成、户型设计的结构面积系数是（）之比。", "options": {"A": "住宅结构面积与建筑面积", "B": "建筑面积与住宅结构面积", "C": "住宅结构面积与房屋平均面积", "D": "房屋平均面积与住宅结构面积"}, "answer": ["A"], "analysis": "衡量单元组成、户型设计的指标是结构面积系数（住宅结构面积与建筑面积之比）， 系数越小设计方案越经济。因为，结构面积小，有效面积就增加。结构面积系数除与房屋结构有关 外，还与房屋外形及其长度和宽度有关，同时也与房间平均面积大小和户型组成有关。房屋平均面积 越大，内墙、隔墙在建筑面积所占比重就越小。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1356", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "某拟建工程初步设计已达到必要的深度，能够据此计算出扩大分项工程的工程量，则能较为准确地编制拟建工程概算的方法是( )。", "options": {"A": "概算指标法", "B": "类似工程预算法", "C": "概算定额法", "D": "综合吨位指标法"}, "answer": ["C"], "analysis": "本题考查的是设计概算的编制。概算定额法又称扩大单价法或扩大结构定额法，是套用概算定额编制建筑工程概算的方法，要求初步设计必须达到一定深度，建筑结构尺寸比较明确。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1357", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "下列概算编制方法中，用于设备及安装工程概算编制的方法为( )。", "options": {"A": "概算定额法", "B": "类似工程预算法", "C": "扩大单价法", "D": "概算指标法"}, "answer": ["C"], "analysis": "本题考查的是设计概算的编制。选项ABD均属于建筑工程单位概算的编制方法。设备及安装工程概算的编制方法有预算单价法、扩大单价法、设备价值百分比法和综合吨位指标法等", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1358", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "当初步设计深度较深，有详细的设备清单时，最能精确的编制设备安装工程费概算的方式是（）。", "options": {"A": "预算单价法", "B": "扩大单价法", "C": "设备价值百分比法", "D": "综合吨位指标法"}, "answer": ["A"], "analysis": "本题考查单位设备安装工程概算的编制方法，设备安装工程费概算的编制方法应根据初步设计深度和要求所明确的程度而采用，其主要编制方法有： 1)预算单价法。当初步设计较深，有详细的设备清单时，可直接按安装工程预算定额单价编制安装工程概算，概算编制程序与安装工程施工图预算程序基本相同。该法的优点是计算比较具体，精确性较高。 2)扩大单价法。当初步设计深度不够，设备清单不完备，只有主体设备或仅有成套设备重量时，可采用主体设备、成套设备的综合扩大安装单价来编制概算。上述两种方法的具体编制步骤与建筑工程概算相类似。 3)设备价值百分比法，又称安装设备百分比法。当初步设计深度不够，只有设备出厂价而无详细规格、重量时，安装费可按占设备费的百分比计算。其百分比值(即安装费率)由相关管理部门制定或由设计单位根据已完类似工程确定。该法常用于价格波动不大的定型产品和通用设备产品，其计算公式为：设备安装费=设备原价×安装费率(%)(3.2.16) 4)综合吨位指标法。当初步设计提供的设备清单有规格和设备重量时，可采用综合吨位指标编制概算", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1359", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "关于建筑设计对民用住宅项目工程造价的影响，下列说法中正确的是（）。", "options": {"A": "加大住宅宽度，不利于降低单方造价", "B": "降低住宅层高，有利于降低单方造价", "C": "结构面积系数越大，越有利于降低单方造价", "D": "住宅层数越多，越有利于降低单方造价"}, "answer": ["B"], "analysis": "住宅的层高和净高，直接影响工程造价。根据不同性质的工程综合测算住宅层高每降低10 厘米，可降低造价1.2%~1.5%。层高降低还可提高住宅区的建筑密度，节约土地成本及市政设施费。但是，层高设计中还需考虑采光与通风问题，层高过低不利于采光及通风，因此，民用住宅的层高一般不宜超过2.8 米。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1360", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "在满足住宅功能和质量前提下，()有利于降低造价。", "options": {"A": "适当加大住宅宽度", "B": "增加住宅层数", "C": "适当提高层高", "D": "提高结构面积系数"}, "answer": ["A"], "analysis": "在满足住宅功能和质量前提下，适当加大住宅宽度。这是由于宽度加大，墙体面积系数相减少，有利于降低造价；降低层高有利于造价；随着住宅层数的增加，单方造价系数在逐渐降低，根据《住宅设计规范》(GB50096-2011)的规定，七层及七层以上住宅或住户入口层楼面距室外设计地面的高度超过16m时必须设置电梯，需要较多的交通面积（过道、走廊要加宽）和补充设备（供水设备和供电设备等）。当住宅层数超过一定限度时，要经受较强的风力荷载，需要提高结构强度，改变结构形式，使工程造价大幅度上升。 本题库是以官方教材为依据，知识点所对应的习题综合了二建法规、二建管理、造价员基础、一级造价师考试的题库+真题编辑，基本上做到了每个知识点都有相对应的题目及解析,题库会陆续更新,会有模拟题,预测题及考前更新押题。 《建设工程计量与计价实务》题库编辑中,教材出来后会陆续更新 www.jinkaodian.com 金考典考试软件。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1361", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "关于建设工程预算，符合组合与分解层次关系的是( )。", "options": {"A": "单位工程预算、单项工程综合预算、类似工程预算", "B": "单位工程预算、类似工程预算、建设项目总预算", "C": "单位工程预算、单项工程综合预算、建设项目总预算", "D": "单位工程综合预算、类似工程预算、建设项目总预算"}, "answer": ["C"], "analysis": "施工图预算根据建设项目实际情况可采用三级预算编制或二级预算编制形式。当建设项目有多个单项工程时，应采用三级预算编制形式，三级预算编制形式由建设项目总预算、单项工程综合预算、单位工程预算组成。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1362", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "单位建筑工程预算是建筑工程各专业单位工程施工图预算的总称，下列属于按其工程性质划分的是（ ）", "options": {"A": "煤气工程预算，电气设备安装工程预算、工业管道工程预算", "B": "一般土建工程预算，给排水工程预算，采暖通风工程预算", "C": "电气设备安装工程预算、工业管道工程预算和热力设备安装工程预算", "D": "给排水工程预算，机械设备安装工程预算、电气设备安装工程预算、工业管道工程预算"}, "answer": ["B"], "analysis": "单位建筑工程预算是建筑工程各专业单位工程施工图预算的总称，按其工程性质分为一般土建工程预算，给排水工程预算，采暖通风工程预算，煤气工程预算，电气照明工程预算，弱电工程预算，特殊构筑物如烟窗、水塔等工程预算以及工业管道工程预算等。 安装工程预算是安装工程各专业单位工程预算的总称，安装工程预算按其工程性质分为机械设备安装工程预算、电气设备安装工程预算、工业管道工程预算和热力设备安装工程预算等。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1363", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "未达到固定资产标准的工器具购置费的计算基数一般为（）。", "options": {"A": "工程建设其他费", "B": "建筑安装工程费", "C": "设备购置费", "D": "设备及安装工程费"}, "answer": ["C"], "analysis": "设备购置费由设备原价和设备运杂费构成；未到达固定资产标准的工器具购置费一般以设备购置费为计算基数，按照规定的费率计算。设备及工器具购置费编制方法及内容可参照设计概算相关内容", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1364", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "关于各级施工图预算的构成内容，下列说法中正确的是（）。", "options": {"A": "建设项目总预算反映施工图设计阶段建设项目的预算总投资", "B": "建设项目总预算由组成该项目的各个单项工程综合预算费用相加而成", "C": "单项工程综合预算由单项工程的建筑工程费和设备及工器具购置费组成", "D": "单位工程预算由单位建筑工程预算和单位安装工程预算费用组成"}, "answer": ["A"], "analysis": "按照预算文件的不同，施工图预算的内容有所不同。建设项目总预算是反映施工图设计阶段建设项目投资总额的造价文件，是施工图预算文件的主要组成部分。由组成该建设项目的各个单项工程综合预算和相关费组成。具体包括：建筑安装工程费、设备及工器具购置费、工程建设其他费用、预备费、建设期利息及铺底流动资金。施工图总预算应控制在已批准的设计总概算投资范围以内。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1365", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "工料单价法编制施工图预算的工作有：①计算主材费；②套用工料单价；③计算措施项目人材机费用；④划分工程项目和计算工程量；⑤进行工料分析。下列工作排序正确的是（）。", "options": {"A": "④②⑤①③", "B": "④⑤①②③", "C": "②④⑤①③", "D": "④②③⑤①"}, "answer": ["D"], "analysis": "图3.3.1施工图预算中建筑安装工程费的计算程序", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1367", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "定额单价法和实物量法是编制施工图预算的两种方法，关于这两种方法的编制步骤和特点，下列说法中正确的是（）。", "options": {"A": "定额单价法在计算得到分项工程工程量后，先套用消耗量，在进行工料分析", "B": "实物量法在计算得到分项工程工程量后，先套用消耗量定额，在进行工料分析", "C": "定额单价法反映市场价格水平", "D": "实物量法编制速度快，但调价计算繁琐"}, "answer": ["B"], "analysis": "实物法与预算单价法首尾部分的步骤是相同的，所不同的主要是中间的两个步骤，即：采用实物法计算工程量后，套用相应人工、材料、施工机械台班预算定额消耗量。求出各分项工程人工、材料、施工机械台班消耗数量并汇总成单位工程所需各类人工工日、材料和施工机械台班的消耗量。采用实物法，用当时当地的各类人工工日、材料和施工机械台班的实际单价分别乘以相应的人工工日、材料和施工机械台班总的消耗量，并汇总后得出单位工程的人工费、材料费和机械费。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1368", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "采用实物量法编制施工图预算时，在按人工、材料、机械台班的市场价计算人、材、机费用之后，下一个步骤是（）。", "options": {"A": "进行工料分析", "B": "计算管理费、利润等费用", "C": "计算工程量", "D": "编写编制说明"}, "answer": ["B"], "analysis": "本题考查的是实物量法的编制步骤。计算完成人工费和材料费后进行管理费利润的计算。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1369", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "下列费用项目中，不在单位工程施工图预算编制范围之内的是（）。", "options": {"A": "构筑物建筑工程费", "B": "工业管道安装工程费", "C": "炉窑购置费", "D": "弱电工程安装工程费"}, "answer": ["C"], "analysis": "单位工程预算编制的范围。单位工程预算包括建筑工程预算与设备安装工程预算两类。选项C 属于设备购置费，不属于单位工程施工图预算编制的内容。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1370", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "在编制施工图预算的下列各项工作步骤中，同时适用于预算单价法和实物法的是（）。", "options": {"A": "套人工、材料、机械台班定额消耗量", "B": "汇总各类人工、材料、机械台班消耗量", "C": "套当时当地人工、材料、机械台班单价", "D": "汇总人工、材料、机械台班总费用"}, "answer": ["D"], "analysis": "预算单价法与实物法首尾部分的步骤是相同的，都需要先进行编制前的准备工作，而最后都需要计算其他费用，汇总工程造价。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1371", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "采用定额单价发编制施工图预算时，下列做法正确的是（）。", "options": {"A": "若分项工程主要材料品种与预算单价规定材料不一致，需要按实际使用材料价格换算预算单价", "B": "因施工工艺条件与预算单价的不一致而致工人、机械的数量增加，只调价不调量", "C": "因施工工艺条件与预算单价的不一致而致工人、机械的数量减少，既调价也调量", "D": "对于定额项目计价中未包括的主材费用，应按造价管理机构发布的造价信息价补充进定额"}, "answer": ["A"], "analysis": "套用定额预算单价，计算直接工程费。分项工程的主要材料品种与预算单价或单位估价表中规定材料不一致时，不能够直接套用预算单价，需要按实际使用材料价格换算预算单价。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1372", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "关于施工图预算文件的组成，下列说法中错误的是()。", "options": {"A": "当建设项目有多个单项工程时，应采用三级预算编制形式", "B": "三级预算编制形式有建设项目总预算、单项工程综合预算、单位工程预算组成", "C": "当建设项目仅有一个单项工程时，可采用二级预算编制形式", "D": "二级预算编制形式的施工图预算文件包括综合预算表和单位工程预算表两个主要报表"}, "answer": ["D"], "analysis": "施工图预算根据建设项目实际情况可采用三级预算编制或二级预算编制形式。当建设项目有多个单项工程时，应采用三级预算编制形式，三级预算编制形式南建设项目总预算、单项工程综合预算、单位工程预算组成。当建设项目只有一个单项工程时，应采用二级预算编制形式，二级预算编制形式由建设项目总预算和单位工程预算组成。采用三级预算编制形式的工程预算文件包括：封面、签署页及目录、编制说明、总预算表、综合预算表、单位工程预算表、附件等内容。^采用二级预算编制形式的工程预算文件包括：封面、签署页及目录、编制说明、总预算表、单位工程预算表、附件等内容。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1373", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "(2016年)按照形成资产法编制建设项目投资估算表，下列费用中可计入固定资产其他费用的是()。", "options": {"A": "开办费", "B": "非专利技术使用费", "C": "土地使用权取得费", "D": "生产准备费"}, "answer": ["C"], "analysis": "后者被称为固定资产其他费用， 主要包括建设管理费、可行性研究费、 研究试验费、勘察设计费、专项评价及验收费、场地准备及临时设施费、引进技术和引进设备其他费、工程保险费、联合试运转费、特殊设备安全监督检验费和市政公用设施建设及绿化费等；", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1374", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "(2010年)关于生产技术方案选择的基本原则，下列说法中错误的是()。", "options": {"A": "先进适用", "B": "节约土地", "C": "安全可靠", "D": "经济合理"}, "answer": ["B"], "analysis": "(1)技术方案选择的基本原则： 1)先进适用。2)安全可靠。3)经济合理。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1375", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "(2010年)下列流动资金分项详细估算的计算式中，正确的是()。", "options": {"A": "应收账款=年营业收入／应收账款周转次数", "B": "预收账款=年经营成本／预收账款周转次数", "C": "产成品=（年经营成本-年其他营业费用）／产成品周转次数", "D": "预付账款=存贷／预付账款周转次数"}, "answer": ["C"], "analysis": "流动资金各项内容估算公式如下：(1)应收账款=年经营成本／应收账款周转次数，(2)预收账款=预收的营业收入年金额／预收账款周转次数，(3)产成品=（年经营成本-年其他营业费用）／产成品周转次数，(4)预付账款=外购商品或服务年费用金额／预付账款周转次数", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1376", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "(14年)可行性研究阶段投资估算的精确度的要求为：误差控制在&plusmn;（）%以内。", "options": {"A": "5", "B": "10", "C": "15", "D": "20"}, "answer": ["B"], "analysis": "详细可行性研究阶段的投资估算此时项目的细节已清楚并已进行了建筑材料设备的询价亦已进行了设计和施工的咨询但工程图纸和技术说明尚不完备可根据此时期的投资估算额进行筹款这一阶段称为确定估算或称控制估算其对投资估算精度的要求为误差控制在&plusmn;10%以内", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1377", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "(2016年)建设项目投资决策阶段，在技术方案中选择生产方法时应重点关注()。", "options": {"A": "是否选择了合理的物料消耗定额", "B": "是否符合工艺流程的柔性安排", "C": "是否使工艺流程中的工序合理衔接", "D": "是否符合节能清洁要求"}, "answer": ["D"], "analysis": "生产方法是指产品生产所采用的制作方法，生产方法直接影响生产工艺流程的选择。一般在选择生产方法时，从以下几个方面着手：①研究分析与项目产品相关的国内外生产方法的优缺点，并预测未来发展趋势，积极采用先进适用的生产方法；②研究拟采用的生产方法是否与采用的原材料相适应，避免出现生产方法与供给原材料不匹配的现象；③研究拟采用生产方法的技术来源的可得性，若采用引进技术或专利，应比较所需费用；④研究拟采用生产方法是否符合节能和清洁的要求，应尽量选择节能环保的生产方法。ABC属于工艺流程方案选择的内容。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1378", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "(2016年)某地2016年拟建一年产50万吨产品的工业项目，预计建设期为3年，该地区2013年已建年产40万吨的类似项目投资为2亿元。已知生产能力指数为0.9，该地区2013、2016年同类工程造价指数分别为108、112，预计拟建项目建设期内工程造价年上涨率为5%。用生产能力指数法估算的拟建项目静态投资为()亿元。", "options": {"A": "2.54", "B": "2.74", "C": "2.75", "D": "2.94"}, "answer": ["A"], "analysis": "2*(50/40)^0.9*112/108=2.54", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1379", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "(2016年)下列原因中，不能据以调整设计概算的是()。", "options": {"A": "超出原设计范围的重大变更", "B": "超出承包人预期的货币贬值和汇率变化", "C": "超出基本预备费规定范围的不可抗拒重大自然灾害引起的工程变动和费用增加", "D": "超出价差预备费的国家重大政策性调整"}, "answer": ["B"], "analysis": "政府投资项目的设计概算经批准后，一般不得调整。如果由于下列原因需要调整概算时，应由建设单位调査分析变更原因，报主管部门审批同意后，由原设计单位核实编制调整概算，并按有关审批程序报批。当影响工程概算的主要因素査明且工程量完成了一定量后，方可对其进行调整。一个工程只允许调整一次概算。允许调整概算的原因包括以下几点：①超出原设计范围的重大变更；②超出基本预备费规定范围不可抗拒的重大自然灾害引起的工程变动和费用增加；③超出工程造价调整预备费的国家重大政策性的调整。才用排除法，", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1380", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "(2016年)某地拟建一工程，与其类似的已完工程单方工程造价为4500元/㎡，其中人、材料、施工机具使用费分别占工程造价的15%、55%和10%，拟建工程地区与类似工程地区人工、材料、施工机具使用费差异系数分别为1.05、1.03和0.98。假定以人、材、机费用之和为基数取费，综合费率为25%。用类似工程预算法计算的拟建工程造价指标为()元/㎡。", "options": {"A": "3699.00", "B": "4590.75", "C": "4599.00", "D": "4623.75"}, "answer": ["D"], "analysis": "先使用调差系数计算出拟建工程的工料单价。类似工程的工料单价=4500×(15%+55%+10%)=3600(元/m2)在类似工程的工料单价中，人工、材料、施工机具使用费的比重分别为18.75%、68.75%和12.5%。拟建工程的工料单价=3600×(18.75%×1.05+68.75%×1.03+12.5%×0.98)=3699(元/m2)则：拟建工程适用的综合单价=3699×(1+25%)=4623.75(元/m2)", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1381", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "(2010年)下列关于建筑设计评价的说法中，错误的是()。", "options": {"A": "建筑物周长与建筑面积之比越高越经济", "B": "厂房展开面积主要用于确定多层厂房的经济层数", "C": "厂房有效面积与建筑面积之比主要用于评价柱网布置的合理性", "D": "工程全寿命成本用于评价建筑物功能水平的合理性"}, "answer": ["A"], "analysis": "(1)平面形状。一 般来说，建筑物平面形状越简单，单位面积造价就越低。当一座建筑物的形状不规则时，将导致室外工程、排水工程、砌砖工程及屋面工程等复杂化，增加工程费用。即使在同样的建筑面积下，建筑平面形状不同，建筑周长系数(建筑物周长.与建筑面积比，即单位建筑面积所占外墙长度）便不同。通常情况下建筑周长系数越低，设计越经济。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1382", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "(2015年)设计概算一经批准一般不得进行调整，其总投资反映( )时的价格水平。", "options": {"A": "项目立项", "B": "可行性研究", "C": "概算编制", "D": "项目施工"}, "answer": ["C"], "analysis": "设计概算应按编制时项目所在地的价格水平编制，总投资应完整地反映编制时建设项目实际投资。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1383", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "(2016年)某地拟建一办公楼，当地类似工程的单位工程概算指标为3600元/㎡。概算指标为瓷砖地面，拟建工程为复合木地板，每100㎡该类建筑中铺贴地面面积为50㎡，当地预算定额中瓷砖地面和复合木地板的预算单价分别为128元/㎡、190元/㎡。假定以人、材、机费用之和为基数取费，综合费率为25%。则用概算指标法计算的拟建工程造价指标为()元/㎡。", "options": {"A": "2918.75", "B": "3413.75", "C": "3631.00", "D": "3638.75"}, "answer": ["D"], "analysis": "2.概算指标法 概算指标法是用拟建的厂房、住宅的建筑面积（或体积）乘以技术条件相同或基本相同的概算指标而得出人、材、机费，然后按规定计算出企业管理费、利润、增值税等，得出单位工程概算的方法。3600+(190-128)*0.5*1.25=3638.75", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1384", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "(2015年)单位建筑工程预算的费用项目包括( )。", "options": {"A": "建筑安装工程费用、设备及工器具购置费、建设单位管理费", "B": "人、才、机费用及企业管理费、利润、规费、税金", "C": "人、才、机费用及企业管理费、工程建设其他费用", "D": "分部分项工程费、措施费、规费、税金、工程建设其他费用"}, "answer": ["A"], "analysis": "本题考查的是施工图预算的概念及其编制内容。单位工程施工图预算包括：建筑工程费、安装工程费和设备及工器具购置费。单位工程施工图预算中的建筑安装工程费应根据施工图设计文件、预算定额（或综合单价）以及人工材料及施工机具台班等价格资料进行计算。不论是按照单价法还是全费用综合单价法，都包含：企业管理费、利润、税金和规费。简单点说，单位建筑工程预算的费用项目包括人、材、机费用及企业管理费、利润、规费、税金。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1385", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "(2010年)应用预算单价法编制施工图预算时，在套用定额单价后，紧接的工作是()。", "options": {"A": "计算工程量", "B": "工料分析", "C": "编写编制说明", "D": "计算造价"}, "answer": ["B"], "analysis": "预算中建筑安装工程费的计算程序", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1386", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "(2014年)建设工程预算编制中的总预算由（）组成。", "options": {"A": "综合预算和工程建设其他费、预备费", "B": "预备费、建设期利息及铺底流动资金", "C": "综合预算和工程建设其他费、铺底流动资金", "D": "综合预算和工程建设其他费、预备费、建设期利息及铺底流动资金"}, "answer": ["D"], "analysis": "本题考查的是建设项目总预算的编制。总预算=∑单项工程施工图预算+工程建设其他费+预备费+建设期利息+铺底流动资金。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1387", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "(2016年)某单项工程的单位建筑工程预算为1000万元，单位安装工程预算为500万元，设备购置预算为600万元，未达到固定资产标准的工器具购置预算为60万元，若预备费率费5%，则该单项工程施工图预算为()万元。", "options": {"A": "1500", "B": "2100", "C": "2160", "D": "2268"}, "answer": ["C"], "analysis": "单项工程施工图预算=∑单位建筑工程费用+∑单位设备及安装工程费用。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1425", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "投资估算编制内容中，（ ）单独估算以便对建设项目进行融资前和融资后财务分析。", "options": {"A": "建设投资", "B": "固定资产投资方向调节税", "C": "流动资金", "D": "建设期利息"}, "answer": ["D"], "analysis": "建设期利息单独估算以便对建设项目进行融资前和融资后财务分析。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1426", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "建筑工程费用估算方法中的（ ），占有较为详细的工程资料、建筑材料价格和工程费用指标，投入的时间和工作量大。", "options": {"A": "单位实物工程量投资估算法", "B": "单位功能价格法", "C": "概算指标投资估算法", "D": "单位建筑工程投资估算法"}, "answer": ["C"], "analysis": "概算指标投资估算法，采用此种方法，应占有较为详细的工程资料、建筑材料价格和工程费用指标，投入的时间和工作量较大。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1427", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "建设期贷款利息的估算，根据建设期资金用款计划，可按（ ）考虑。", "options": {"A": "当年借款、上年借款均按半年计息", "B": "当年借款、上年借款均按全年计息", "C": "当年借款按全年计息，上年借款按半年计息", "D": "当年借款按半年计息，上年借款按全年计息"}, "answer": ["D"], "analysis": "建设期利息的估算，根据建设期资金用款计划，可按当年借款在当年年中支用考虑， 即当年借款按半年计息，上年借款按全年计息。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1428", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "某建设项目建安工程费8000万元，设备购置费4500万元，工程建设其他费用3000万元，已知基本预备费率5%，项目建设前期年限为1年，建设期为3年，第一年完成投资30%，则建设期第一年完成投资为（ ）万元。", "options": {"A": "16275", "B": "15500", "C": "4882．5", "D": "4650"}, "answer": ["C"], "analysis": "基本预备费的估算一般是以建设项目的工程费用和工程建设其他费用之和为基础， 乘以基本预备费率进行计算。 基本预备费=(8000+4500+3000)万元×5%=775万元 投资额=(8000+4500+3000+775)万元=16275万元 建设期第一年完成投资=16275万元×30%=4882．5万元", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1429", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "下列投资估算方法中，适合于对估算精确度要求较高的方法是（ ）。", "options": {"A": "系数法", "B": "指标估算法", "C": "生产能力指数法", "D": "类似项目对比法"}, "answer": ["B"], "analysis": "在可行性研究阶段，投资估算精度要求就要比前一阶段高些，需采用相对详细的估算方法，如指标估算法等。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1430", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "建设期贷款利息包括（ ）和为筹集资金而发生的融资费用。", "options": {"A": "支付金融机构的贷款利息", "B": "调整投资结构而征收的投资方向调整税金", "C": "产品销售所需要的周转资金", "D": "工程成本核算"}, "answer": ["A"], "analysis": "建设期利息是为工程建设筹措债务资金而发生的融资费用及在建设期内发生并应计入固定资产原值的利息，包括支付金融机构的贷款利息和为筹集资金而发生的融资费用。建设期利息单独估算以便对建设项目进行融资前和融资后财务分析。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1431", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "价差预备费一般根据国家规定的投资综合价格指数，按估算年份价格水平的投资额为基数，采用（ ）计算。", "options": {"A": "复利方法", "B": "建设项目的工程费用乘以价差预备费率", "C": "工程建设其他费用乘以预备费率", "D": "以建设项目的工程费用和工程建设其他费用之和为基础，乘以预备费率"}, "answer": ["A"], "analysis": "价差预备费的内容包括：人工、设备、材料、施工机械的价差费，建筑安装工程费及工程建设其他费用调整，利率、汇率调整等增加的费用。价差预备费一般根据国家规定的投资综合价格指数，按估算年份价格水平的投资额为基数，采用复利方法计算。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1432", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "在可行性研究阶段，投资估算原则上应采用（ ）进行投资估算的编制。", "options": {"A": "指标估算法", "B": "系数估算法", "C": "生产能力指数法", "D": "混合法"}, "answer": ["A"], "analysis": "建设项目可行性研究阶段技资估算原则上应采用指标估算法。指标估算法是依据投资估算指标，对各单位工程或单项工程费用进行估算，进而估算建设项目总投资，再按相关规定估算工程建设其他费用、基本预备费、建设期利息等，形成拟建项目静态投资 。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1433", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "生产能力指数法又称指数估算法，它是根据（ ）和投资额来粗略估算拟建项目投资额的方法，是对单位生产能力估算法的改进。", "options": {"A": "已建成的类似项目生产能力", "B": "已建类似项目的静态投资额", "C": "拟建项目的主体工程费", "D": "世界银行投资的项目估算"}, "answer": ["A"], "analysis": "生产能力指数法又称指数估算法，它是根据已建成的类似项目生产能力和投资额来粗略估算拟建项目投资额的方法，是对单位生产能力估算法的改进 。生产能力指数法与单位生产能力估算法相比精确度略高些。尽管估价误差仍较大，但有它独特的好处：即这种估价方法不需要详细的工程设计资料，只知道工艺流程及规模就可以，在总承包工程报价时，承包商大都采用这种方法估价 。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1434", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "可行性研究阶段建设项目投资估算原则上应采用（ ）。", "options": {"A": "混合法", "B": "指标估算法", "C": "比例估算法", "D": "系数估算法"}, "answer": ["B"], "analysis": "建设项目可行性研究阶段投资估算原则上应采用指标估算法。对投资有重大影响的主体工程应估算出分部分项工程量，参考相关概算指标或概算定额编制主要单项工程的投资估算。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1435", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "某项目建设期为2年，第一年贷款4000万元，第二年贷款0万元，贷款年利率10%，贷款在年内均衡发放，建设期内只计息不付息。该项目第二年的建设期利息为（ ）万元。", "options": {"A": "200", "B": "500", "C": "520", "D": "600"}, "answer": ["C"], "analysis": "本题考查的是可行性研究阶段的投资估算。第一年利息＝4000/2×10%＝200（万元），第二年利息＝（4000＋200＋2000/2）×10%＝520（万元）。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1436", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "2014年已建成年产10万吨的某钢厂，其投资额为4000万元，2018年拟建生产50万吨的钢厂项目，建设期2年。自2014年至2018年每年平均造价指数递增4%，预计建设期2年平均造价指数递减5%，估算拟建钢厂的静态投资额为（ ）万元（生产能力指数取0.8）。", "options": {"A": "16958", "B": "16815", "C": "14496", "D": "15304"}, "answer": ["A"], "analysis": "本题考查的是投资估算的编制方法。综合调整系数＝（1＋4%）4，拟建钢厂的静态投资额＝4000×（50/10）0.8×（1＋4%）4＝16958万元。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1437", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "2009年在某地兴建一座50万t合成氨的化肥厂，总投资为460000万元，假如2014年在该地开工兴建65万t合成氨的工厂，合成氨的生产能力指数为0．81，则所需静态投资为（ ）万元(假定从2009--2014年每年平均指数为1．05)。", "options": {"A": "698763．68", "B": "726103．35", "C": "681346．65", "D": "735621．21"}, "answer": ["B"], "analysis": "生产能力指数法又称指数估算法，它是根据己建成的类似项目生产能力和投资额来 粗略估算拟建项目投资额的方法，是对单位生产能力估算法的改进 。 其计算公式为:", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1438", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "以拟建项目的主体工程费或主要工艺设备费为基数，以其他辅助或配套工程费占主体工程费的百分比为系数，估算项目总投资的方法叫( )。", "options": {"A": "类似项目对比法", "B": "系数估算法", "C": "生产能力指数法", "D": "比例估算法"}, "answer": ["B"], "analysis": "系数估算法也称为因子估算法，它是以拟建项目的主体工程费或主要设备购置费为基数，以其他工程费与主体工程费或设备购置费的百分比为系数，依此估算拟建项目总投资的方法。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1439", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "某新建项目，建设期为3年，分年均衡进行贷款，第一年贷款500万元，第二年贷款700万元，第三年贷款600万元，年利率为6%，建设期内利息只计息不支付，则建设期利息为（ ）万元。", "options": {"A": "160．91", "B": "161．32", "C": "159．68", "D": "158．65"}, "answer": ["A"], "analysis": "建设期利息的估算，根据建设期资金用款计划，可按当年借款在当年年中支用考虑， 即当年借款按半年计息，上年借款按全年计息。 在建设期，各年利息计算如下：", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1440", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "审查设计概算的方法中，（ ）是对一些关键设备和设施、重要装置、引进工程图样不全、难以核算的较大投资进行多方查询核对，逐项落实的方法。", "options": {"A": "对比分析法", "B": "查询核实法", "C": "设备价值百分率法", "D": "联合会审法"}, "answer": ["B"], "analysis": "查询核实法是对一些关键设备和设施、重要装置、引进工程图纸不全、难以核算的较大投资进行多方查询核对，逐项落实的方法。主要设备的市场价向设备采购部门或招标公司查询核实，重要生产装置、设施向同类企业(工程)查询了解，引进设备价格及有关费税向进出口公司调查落实，复杂的建筑安装工程向同类工程的建设、承包、施工单位征求意见，深度不够或不清楚的问题直接同原概算编制人员、设计者询问清楚。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1441", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "下列方法中，（ ）是利用技术条件相类似工程的预算或结算资料来编制拟建工程概算的方法。", "options": {"A": "综合吨位指标法", "B": "类似工程预算法", "C": "单项工程综合概算", "D": "概算指标法"}, "answer": ["B"], "analysis": "类似工程预算法是利用技术条件相类似工程的预算或结算资料，编制拟建单位工程 概算的方法。类似工程预算法适用于拟建工程设计与已完工程或在建工程的设计相类似而又没有可用的概算指标时采用，但必须对建筑结构差异和价差进行调整。 综合吨位指标法，当设计文件提供的设备清单有规格和设备重量时，可采用综合吨位指标编制概算，综合吨位指标由主管部门或由设计院根据已完类似工程资料确定。 单项工程综合概算(以下简称综合概算)是以初步设计文件为依据，在单位工程概算的基础上汇总单项工程工程费用的成果文件，是设计概算书的组成部分 。 概算指标法是利用概算指标编制单位工程概算的方法，是用拟建的厂房、住宅的建筑面积(或体积)乘以技术条件相同或基本相同工程的概算指标，得出人工费、材料费、施工机具使用费合计，然后按规定计算出企业管理费、利润和增值税等，编制出单位工程概算的方法 。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1442", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "衡量设计方案经济合理性和选择最佳设计方案的依据是（ ）。", "options": {"A": "设计概算", "B": "概算指标", "C": "预算定额", "D": "概算定额"}, "answer": ["A"], "analysis": "设计概算是衡量设计方案技术经济合理性和选择最佳设计方案的依据。设计部门在初步设计阶段要选择最佳设计方案，设计概算是从经济角度衡量设计方案经济合理性的重要依据。因此，设计概算是衡量设计方案技术经济合理性和选择最佳设计方案的依据。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1443", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "概算定额法又称（ ）法，是利用概算定额编制单位工程概算的方法。", "options": {"A": "扩大结构定额", "B": "缩小结构定额", "C": "综合结构定额", "D": "定性结构定额"}, "answer": ["A"], "analysis": "概算定额法又叫扩大单价法或扩大结构定额法，是利用概算定额编制单位工程概算的方法。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1444", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "当设计深度不够，只有设备出厂价而无详细规格、重量时，安装费可按（ ）计算。", "options": {"A": "设备购置费概算法", "B": "预算单价法", "C": "设备价值百分比法", "D": "综合吨位指标法"}, "answer": ["C"], "analysis": "设备价值百分比法，也称安装设备百分比法。当设计深度不够，只有设备出厂价而无详细规格、重量时，安装费可按占设备费的百分比计算 。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1445", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "编制固定资产投资计划、确定和控制建设项目投资的依据是（ ）。", "options": {"A": "修正概算", "B": "施工图预算", "C": "投资估算", "D": "设计概算"}, "answer": ["D"], "analysis": "设计概算是编制固定资产投资计划，确定和控制建设项目投资的依据。国家规定，编制年度固定资产投资计划，确定计划投资总额及其构成数额，要以批准的初步设计概算为依据，没有批准的初步设计文件及其概算，建设工程就不能列入年度固定资产投资计划。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1446", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "设备安装工程费概算的编制方法中，（ ）常用于设备价格波动较大的非标准设备和引进设备的安装工程概算。", "options": {"A": "预算单价法", "B": "设备价值百分率法", "C": "扩大单价法", "D": "综合吨位指标法"}, "answer": ["D"], "analysis": "当设计文件提供的设备清单有规格和设备重量时，可采用综合吨位指标编制概算，综合吨位指标由主管部门或由设计院根据已完类似工程资料确定。该法常用于设备价格波动较大的非标准设备和引进设备的安装工程概算，或者安装方式不确定，没有定额或指标。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1447", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "二级编制形式的设计概算文件的组成中，不包括（ ）。", "options": {"A": "总概算表", "B": "编制说明", "C": "单项工程综合概算表", "D": "封面、签署页及目录"}, "answer": ["C"], "analysis": "对于采用二级编制形式的设计概算文件，一般由封面、签署页及目录、编制说明、总概算表、其他费用计算表、单位工程概算表组成，可将所有概算文件组成一册。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1448", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "对总概算投资超过批准投资估算（ ）以上的，应查明原因，重新上报审批。", "options": {"A": "3%", "B": "5%", "C": "8%", "D": "10%"}, "answer": ["D"], "analysis": "审查建设规模(投资规模、生产能力等)、建设标准(用地指标、建筑标准等)、配套工程、设计定员等是否符合原批准的可行性研究报告或立项批文的标准。对总概算投资超过批准投资估算10%以上的，应查明原因，重新上报审批。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1449", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "审查设计概算时， 对一些关键设备和设施、 重要装置、 引进工程图纸不全、 难以核算的较大投资宜采用的审查方法是（ ）。", "options": {"A": "对比分析法", "B": "筛选审查法", "C": "查询核实法", "D": "标准预算审查法"}, "answer": ["C"], "analysis": "本题考查审查设计概算时的方法选择。审查设计概算时，需要对一些关键设备和设施、重要装置、引进工程图纸不全、难以核算的较大投资进行审查。根据审查的目的和特点，选择合适的审查方法是非常重要的。选项中，对比分析法和标准预算审查法都是比较常见的审查方法，但对于设计概算中的特殊情况，可能不太适用。筛选审查法主要是对设计概算中的各项费用进行筛选，不太适用于对特定设备和装置的审查。因此，正确答案为C，查询核实法。查询核实法是通过查询资料、核实数据等方式，对设计概算中的关键设备和设施、重要装置、引进工程图纸不全、难以核算的较大投资进行审查，是一种比较实用的方法。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1450", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "适应市场经济条件的工程量清单计价模式下的施工图预算编制方法是（ ）。", "options": {"A": "实物量法", "B": "可调单价法", "C": "综合单价法", "D": "工料单价法"}, "answer": ["C"], "analysis": "施工图预算的编制可以采用工料单价法和综合单价法。工料单价法是指分部分项工程的工料机单价，以分部分项工程量乘以对应工料单价汇总后另加企业管理费、利润、税金生成单位工程施工图预算造价。按照分部分项工程单价产生的方法不同，工料单价法又可以分为预算单价法和实物量法。而综合单价法是适应市场经济条件的工程量清单计价模式下的施工图预算编制方法。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1451", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "有关费用项目计取的审查要注意的方面不包括（ ）。", "options": {"A": "措施费的计算是否符合有关的规定标准", "B": "直接费和利润的计取基础是否符合现行规定", "C": "有无巧立名目，乱计费、乱摊费用现象", "D": "预算外调增的材料差价是否计取了企业管理费"}, "answer": ["B"], "analysis": "有关费用项目计取的审查要注意以下几个方面： (1)措施费的计算是否符合有关的规定标准，企业管理费和利润的计取基础是否符合现行规定，有无不能作为计费基础的费用列入计费的基础。 (2)预算外调增的材料差价是否计取了企业管理费。人工费增减后，有关费用是否相应做了调整 。 (3)有无巧立名目，乱计费、乱摊费用现象。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1452", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "对（ ）而言，编制施工图预算可以用来检验工程设计在经济上的合理性。", "options": {"A": "投资单位", "B": "设计单位", "C": "施工单位", "D": "监理单位"}, "answer": ["B"], "analysis": "对设计单位而言，通过施工图预算来检验设计方案的经济合理性。其作用有： (1)根据施工图预算进行控制投资。 (2)根据施工图预算调整、优化设计。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1453", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "审查施工图预算方法较多，其中（ ）的优点是简单易懂，便于掌握，审查速度和发现问题快，但解决差错分析其原因需继续审查。", "options": {"A": "全面审查法", "B": "标准预算审查法", "C": "筛选审查法", "D": "重点抽查法"}, "answer": ["C"], "analysis": "筛选审查法。建筑工程虽然有建筑面积和高度的不同，但是它们的各个分部分项工程的工程量、造价、用工量在每个单位面积上的数值变化不大，把已建工程的这些数据加以分析汇集，归纳为工程量、造价(价值)、用工三个单位面积基本数值分析表，并注明其适用的建筑标准。这些基本数值犹如\"筛子孔”用来筛选各分部分项工程，筛下去的就不审查了，没有筛下去的就意味着此分部分项的单位建筑面积数值不在基本数值范围之内，应对该分部分项工程详细审查。筛选法的优点是简单易懂，便于掌握，审查速度和发现问题快，但解决差错、分析其原因需继续审查。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1454", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "审查施工图预算方法较多，（ ）的优点是时间短、效果好；缺点是只适应按标准图样设计的工程，适用范围小，具有局限性。", "options": {"A": "全面审查法", "B": "分组计算审查法", "C": "标准预算审查法", "D": "对比审查法"}, "answer": ["C"], "analysis": "对于采用标准图纸或通用图纸施工的工程，先集中力量，编制标准预算，以此为标准审查施工图预算。按标准图纸设计或通用图纸施工的工程，预算编制和造价基本相同，可集中力量细审一份预算或编制一份预算，作为这种标准图纸的标准预算，或以这种标准图纸的工程量为标准，对照审查，而对局部不同部分作单独审查即可。这种方法的优点是时间短、效果好；缺点是只适用于按标准图纸设计的工程，适用范围小，具有局限性。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1455", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "对于工程造价管理部门而言，（ ）是监督、检查执行定额标准、合理确定工程造价、测算造价指数及审查招标工程招标控制价的重要依据。", "options": {"A": "设计概算", "B": "预算定额", "C": "综合概算", "D": "施工图预算"}, "answer": ["D"], "analysis": "对于工程造价管理部门而言，施工图预算是监督、检查定额标准执行情况、测算造价指数以及审定工程招标限价(或标底)的重要依据。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1456", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "实物量法编制施工图预算时采用的人工、 材料、 机械的单价应为( )。", "options": {"A": "项目所在地定额基价中的价格", "B": "预测的项目建设期的市场价格", "C": "当时当地的实际价格", "D": "定额编制时的市场价格"}, "answer": ["C"], "analysis": "实物量法编制施工图预算时，需要确定人工、材料、机械的单价。其中，人工、材料、机械的单价应该是当时当地的实际价格，因为预算编制需要考虑实际情况，包括当地的市场价格、供需情况等因素。因此，选项C为正确答案。选项A、B、D都不太准确，因为定额基价中的价格、预测的市场价格、定额编制时的市场价格都不能完全反映当时当地的实际情况。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1457", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "当建设工程条件相同时，用同类已完工程的预算或未完但已经过审查修正的工程预算审查拟建工程的方法是（ ）。", "options": {"A": "标准预算审查法", "B": "对比审查法", "C": "筛选审查法", "D": "全面审查法"}, "answer": ["B"], "analysis": "本题考查的是施工图预算的编制。对比审查法是用已建工程的预算或虽未建成但已通过审查的工程预算，对比审查拟建工程预算的一种方法。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1459", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "某地拟建一幢建筑面积为2500m2办公楼。已知建筑面积为2700m2的类似工程预算成本为216万元，其人、材、机、企业管理费占预算成本的比重分别为20%、50%、10%、15%。拟建工程和类似工程地区的人工费、材料费、施工机具使用费、企业管理费之间的差异系数分别是1.1、1.2、1.3、1.15，综合费率为4%，则利用类似工程预算法编制该拟建工程概算造价为（ ）万元。", "options": {"A": "233.48", "B": "252.2", "C": "287.4", "D": "302.8"}, "answer": ["A"], "analysis": "本题考查的是设计概算的编制。综合调整系数=20%×1.1+50%×1.2+10%×1.3+15%×1.15=1.1225，拟建工程概算造价=216/2700×1.1225×（1+4%）×2500=233.48（万元）。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1831", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "关于《国务院关于投资体制改革的决定》，特别重大的政府投资项目应实行（ ）制度。", "options": {"A": "网上公示", "B": "咨询论证", "C": "专家评议", "D": "民众听证"}, "answer": ["C"], "analysis": "【内容考查】本题考查的是投资决策阶段工作内容【选项分析】根据《国务院关于投资体制改革的决定》，特别重大的政府投资项目应实行专家评议制度。", "tags": [], "source": "二、工程建设程序", "src": "好题库"}, {"id": "ht_mgmt_1832", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "根据《国务院关于投资体系改革的决定》，政府投资项目实行（ ）。", "options": {"A": "备案制", "B": "审批制", "C": "核准制", "D": "报告制"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是投资决策阶段工作内容【选项分析】根据《国务院关于投资体制改革的决定》（国发[2004]20号），政府投资项目实行审批制；非政府投资项目实行核准制或登记备案制。", "tags": [], "source": "二、工程建设程序", "src": "好题库"}, {"id": "ht_mgmt_1834", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "工程设计工作一般划分为两个阶段，即（ ）和施工图设计。", "options": {"A": "规划设计", "B": "技术设计", "C": "初步设计", "D": "工艺设计"}, "answer": ["C"], "analysis": "【内容考查】本题考查的是建设实施阶段工作内容【选项分析】工程设计工作一般划分为两个阶段，即初步设计和施工图设计。重大项目和技术复杂项目，可根据需要增加技术设计阶段。", "tags": [], "source": "二、工程建设程序", "src": "好题库"}, {"id": "ht_mgmt_1840", "date": "2026-07-10", "chapter": "g05", "type": "single", "stem": "住宅建筑的平面形式中，既有利于施工、又能降低造价的是（ ）。", "options": {"A": "矩形", "B": "方形", "C": "圆族", "D": "椭圆形"}, "answer": ["A"], "analysis": "【考点来源】本题考查的是工程设计阶段影响造价的主要因素【选项分析】一般住宅建筑平面多为矩形，既有利于施工，又能降低造价和使用方便。", "tags": [], "source": "三、工程决策和设计阶段影响造价的主要因素", "src": "好题库"}, {"id": "mgmt_hqwx_0255", "date": "2026-07-09", "chapter": "g05", "type": "single", "stem": "关于我国项目前期各阶段投资估算的精度要求，下列说法中正确的是（ ）。", "options": {"A": "项目建议书阶段，允许误差大于±30％", "B": "投资机会研究阶段，要求误差控制在±30％以内", "C": "初步可行性研究阶段，要求误差控制在±20％以内", "D": "详细可行性研究阶段，要求误差控制在±15％以内"}, "answer": ["C"], "analysis": "【内容考查】本题考查的是工程决策和设计阶段造价管理的工作内容 【选项分析】A选项，项目建议书阶段，要求误差控制在±30％以内。D选项，可行性研究阶段，要求误差控制在±10%以内。选项C，初步可行性研究阶段，要求误差控制在20％以内，选项C正确。选项B，投资机会研究阶段，要求误差控制在 ±30％左右。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0257", "date": "2026-07-09", "chapter": "g05", "type": "single", "stem": "项目建议书阶段投资估算额度的偏差率一般控制在（ ）以内。", "options": {"A": "±5%", "B": "±10%", "C": "±20%", "D": "±30%"}, "answer": ["D"], "analysis": "【考点来源】本题考查的是工程决策和设计阶段造价管理的工作内容 【选项分析】", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0258", "date": "2026-07-09", "chapter": "g05", "type": "single", "stem": "关于可行性研究对工程造价的影响，下列说法正确的是（ ）。", "options": {"A": "工程造价的高低、投资多少不会影响可行性研究结论", "B": "项目可行性研究结论的正确性是决定工程造价的基础", "C": "可行性研究的深度是工程造价合理性的前提", "D": "项目可行性研究的内容是决定工程造价的基础"}, "answer": ["D"], "analysis": "从项目可行性研究报告的内容与作用可以看出，项目可行性研究与工程造价有着密不可分的联系：（1）项目可行性研究结论的正确性是工程造价合理性的前提。（2）项目可行性研究的内容是决定工程造价的基础。（3）工程造价髙低、投资多少也影响可行性研究结论。（4）可行性研究的深度影响投资估算的精确度，也影响工程造价的控制效果。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0261", "date": "2026-07-09", "chapter": "g05", "type": "single", "stem": "关于可行性研究对工作造价的影响，下列说法中错误的是（ ）。", "options": {"A": "可行性研究结论的正确性是工程造价合理性的前提", "B": "可行性研究的内容是决定工程造价的基础", "C": "工程造价的数额不影响项目决策的结果", "D": "可行性研究的深度影响投资估算精确度，也影响工程造价的控制效果"}, "answer": ["C"], "analysis": "【内容考查】本题考查的是可行性研究对工程造价的影晌 【选项分项】从项目可行性研究报告的内容与作用可以看出，项目可行性研究与工程造价有着密不可分的联系： （1）项目可行性研究结论的正确性是工程造价合理性的前提。（2）项目可行性研究的内容是决定工程造价的基础。（3）工程造价高低、投资多少也影响可行性研究结论。（4）可行性研究的深度影响投资估算的精确度，也影响工程造价的控制效果。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0263", "date": "2026-07-09", "chapter": "g05", "type": "single", "stem": "下列不属于可行性研究阶段工作内容的是（ ）。", "options": {"A": "市场调研", "B": "工艺技术方案的研究", "C": "论述项目获利的可行性", "D": "财务和经济分析"}, "answer": ["C"], "analysis": "可行性研究应完成以下工作内容：①进行市场研究，以解决项目建设的必要性问题； ②进行工艺技术方案的研究，以解决项目建设的技术可行性问题；③进行财务和经济分析，以解决项目建设的经济合理性问题。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0267", "date": "2026-07-09", "chapter": "g05", "type": "single", "stem": "在详细可行性研究阶段，投资估算的误差率在（ ）。", "options": {"A": "±5％内", "B": "±10％内", "C": "±20％内", "D": "±30％内"}, "answer": ["B"], "analysis": "在详细可行性研究阶段，投资估算的误差率在±10％内。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0268", "date": "2026-07-09", "chapter": "g05", "type": "single", "stem": "以拟建项目的主体工程费为基础，并且以其他工程费与主体工程费的比例系数估算项目静态投资的方法叫（ ）。", "options": {"A": "因子估算法", "B": "比例估算法", "C": "指标估算法", "D": "扩大指标估算法"}, "answer": ["A"], "analysis": "【内容考查】本题考查的是项目建议书阶段的投资估算 【选项分项】系数估算法也称为因子估算法，它是以拟建项目的主体工程费或主要设备购置费为基数，以其他工程费与主体工程费的百分比为系数估算项目的静态投资的方法。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0269", "date": "2026-07-09", "chapter": "g05", "type": "single", "stem": "单项工程投资估算应按建设项目划分的各个单项工程分别计算组成工程费用的建筑工程费、（ ）、安装工程费。", "options": {"A": "企业管理费", "B": "设备购置费", "C": "分部分项费", "D": "措施费用"}, "answer": ["B"], "analysis": "单项工程投资估算应按建设项目划分的各个单项工程分别计算组成工程费用的建筑工程费、设备购置费、安装工程费。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0271", "date": "2026-07-09", "chapter": "g05", "type": "single", "stem": "预计某年度应收账款1800万元，应付账款1300万元，预收账款700万元，预付账款500万元，存货1000万元，现金400万元。则该年度流动资金估算额为（ ）万元。", "options": {"A": "700", "B": "1100", "C": "1700", "D": "2100"}, "answer": ["C"], "analysis": "【内容考查】本题考查的是流动资金的估算 【选项分项】流动资金=流动资产－流动负债=1700 流动资产=应收账款+预付账款+存货+库存现金 =1800+500+1000+400=3700 流动负债=应付账款+预收账款=1300+700=2000。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0273", "date": "2026-07-09", "chapter": "g05", "type": "single", "stem": "应用分项详细估算法估算项目流动资金时，流动资产的正确构成是（ ）。", "options": {"A": "应付账款+预付账款+存货+年其他费用", "B": "应付账款+应收账款+存货+现金", "C": "应收账款+存货+预收账款+现金", "D": "预付账款+现金+应收账款+存货"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是流动资金的估算 【选项分项】流动资产=应收账款+预付账款+存货+库存现金。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0274", "date": "2026-07-09", "chapter": "g05", "type": "single", "stem": "关于联合试运转费，下列说法中正确的是（ ）。", "options": {"A": "包括对整个生产线或装置运行无负荷和有负荷试运转所发生的费用", "B": "包括施工单位参加试运转人员的工资及专家指导费", "C": "包括试运转中暴露的因设备缺陷发生的处理费用", "D": "包括对单台设备进行单机试运转工作的调试费"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是可行性研究阶段的投资估算 【选项分析】是试运转支出大于收入的差额部分费用，其中试运转支出包括试运转所需原材料、燃料及动力消耗、低值易耗品、其他物料消耗、工具用具使用费、机械使用费、保险金、施工单位参加试运转人员工资、以及专家指导费等。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0277", "date": "2026-07-09", "chapter": "g05", "type": "single", "stem": "某新建项目，建设期为2年，分年均衡进行贷款，第一年贷款 2000万元，第二年贷款3000万元。在建设期内贷款利息只计息不支付。年利率为10%的情况下，该项目应计建设期贷款利息为（ ）万元。", "options": {"A": "360.0", "B": "460.0", "C": "520.0", "D": "700.0"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是可行性研究阶段的投资估算 【选项分项】 第一年利息=2000×0.5×10%=100万元；第二年利息= (2000+100+3000×0.5)×10%=360万元；建设期贷款利息=100+360=460万元。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0278", "date": "2026-07-09", "chapter": "g05", "type": "single", "stem": "采用分项详细估算法进行流动资金估算时，应计入流动负债的是（ ）。", "options": {"A": "预收账款", "B": "存货", "C": "库存资金", "D": "应收账款"}, "answer": ["A"], "analysis": "【内容考查】本题考查的是流动资金的估算 【选项分析】流动负债=应付账款+预收账款", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0279", "date": "2026-07-09", "chapter": "g05", "type": "single", "stem": "关于项目投资估算的作用，下列说法中正确的是（ ）。", "options": {"A": "项目建议书阶段的投资估算，是确定建设投资最高限额的依据", "B": "可行性研究阶段的投资估算，是项目投资决策的重要依据，不得突破", "C": "投资估算不能作为制定建设贷款计划的依据", "D": "投资估算是核算建设项目固定资产需要额的重要依据"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是投资估算的作用 【选项分项】A选项，项目建议书阶段的投资估算是编制项目规划、确定建设规模的参考依据，B选项，项目可行性研究阶段的投资估算，是项目投资决策的重要依据，当可行性研究报告被批准后，其投资估算额将作为设计任务书中下达的投资限额，即建设项目投资的最高限额，不能随意突破，C选项，项目投资估算可作为项目资金筹措及制订建设贷款计划的依据。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0280", "date": "2026-07-09", "chapter": "g05", "type": "single", "stem": "某地市政道路工程，已知与其类似已完工作造价指标为600元/m2，人、材、机占工程造价10%，50%，20%，拟建工程与类似工程人、材、机差异系数为1.1，1.05，1.05，假定以人、材、机为基数取费，综合费率为25%，则该工程综合单价为（ ）。", "options": {"A": "507", "B": "608.4", "C": "633.75", "D": "657"}, "answer": ["C"], "analysis": "【内容考查】本题考查的是单位工程概算的编制方法 【选项分项】该工程综合单价=600×（10%×1.1+50%×1.05+20%×1.05）×（1+25%）=633.75元/m2", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0281", "date": "2026-07-09", "chapter": "g05", "type": "single", "stem": "单位建筑工程概算的主要编制方法有（ ）。", "options": {"A": "生产能力指数法、系数法、造价指标法", "B": "概算定额法、设备价值百分比法、类似工程预算法", "C": "概算定额法、概算指标法、类似工程预算法", "D": "预算单价法、概算指标法、设备价值百分比法"}, "answer": ["C"], "analysis": "【内容考查】本题考查的是单位工程概算的编制方法 【选项分析】建筑单位工程概算编制方法：概算定额法；概算指标法；类似工程预算法。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0282", "date": "2026-07-09", "chapter": "g05", "type": "single", "stem": "设计概算审查时，对图纸不全的复杂建筑安装工程投资，通过向同类工程的建设施工企业征求意见判断其合理性。这种审查方法属于（ ）。", "options": {"A": "对比分析法", "B": "专家意见法", "C": "查询核实法", "D": "联合会审法"}, "answer": ["C"], "analysis": "【内容考查】本题考查的是设计概算审查的方法。 【选项分析】查询核实法是对一些关键设备和设施、重要装置、引进工程图纸不全、难以核算的较大投资进行多方查询核对，逐项落实的方法。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0284", "date": "2026-07-09", "chapter": "g05", "type": "single", "stem": "单位工程设计概算按其工程性质分为建筑工程概算和（ ）。", "options": {"A": "设备及安装工程概算", "B": "流动资金概算", "C": "设备购置费概算", "D": "安装工程概算"}, "answer": ["A"], "analysis": "单位工程概算分为建筑工程概算、设备及安装工程概算。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0285", "date": "2026-07-09", "chapter": "g05", "type": "single", "stem": "新建工程与某已建工程仅外墙饰面不同。已建成工程外墙为水泥砂浆抹面，单价为9.75元/㎡,每平方米建筑面积消耗量为0.862㎡；新建工程外墙为贴釉面砖，单价为59.25元/㎡,每平方米建筑面积消耗量为0.856㎡,。若已建成工程概算指标为636元/㎡，则新建工程修正概算指标为（ ）元/㎡。", "options": {"A": "576.50", "B": "585.25", "C": "568.63", "D": "678.31"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是修正概算的相关内容。 【选项分析】结构变化修正概算指标（元／㎡） =J+Q1P1-Q2P2 = 636+59.25 ×0.856-9.75×0.862=636-8.4045+50.718=678.31（元／㎡）。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0286", "date": "2026-07-09", "chapter": "g05", "type": "single", "stem": "关于设计概算的作用，下列说法正确的是（ ）。", "options": {"A": "设计概算是确定建设规模的依据", "B": "设计概算是编制固定资产投资计划的依据", "C": "政府投资项目设计概算经批准后，不得进行调整", "D": "设计概算不应作为签订贷款合同的依据"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是设计概算的作用 【选项分析】设计概算是确定建设项目投资的依据；政府投资项目的设计概算经批准后，一般不得调整；设计概算作为签订贷款合同的依据。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0289", "date": "2026-07-09", "chapter": "g05", "type": "single", "stem": "当采用类似工程预算法编制概算时，必须要调整的因素是( )。", "options": {"A": "质量类似和进度差异", "B": "时间差异和地点差异", "C": "建筑结构差异和价格差异", "D": "质量差异和价格差异"}, "answer": ["C"], "analysis": "【内容考查】本题考查的是单位工程概算的编制方法 【选项分项】类似工程预算法适用于拟建工程设计与已完工程或在建工程的设计相类似而又没有可用的概算指标时采用，但必须对建筑结构差异和价差进行调整。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0290", "date": "2026-07-09", "chapter": "g05", "type": "single", "stem": "当初步设计深度不够，只有设备出厂价而无详细规格、重量时，编制设备安装工程费概算可选用的方法是（ ）。", "options": {"A": "设备价值百分比法", "B": "设备系数法", "C": "综合吨位指标法", "D": "预算单价法"}, "answer": ["A"], "analysis": "【内容考查】本题考查的是单位工程概算的编制方法 【选项分项】设备价值百分比法，又叫安装设备百分比法。当初步设计深度不够，只有设备出厂价而无详细规格、重量时，安装费可按占设备费的百分比计算。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0292", "date": "2026-07-09", "chapter": "g05", "type": "single", "stem": "某单位建筑工程初步设计深度不够，不能准确的计算工程量，但工程采用的技术比较成熟而又有类似指标可以利用时，编制该工程设计概算宜采用的方法是（ ）。", "options": {"A": "扩大单价法", "B": "类似工程换算法", "C": "生产能力指数法", "D": "概算指标法"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是单位工程概算的编制方法 【选项分析】当初步设计深度不够，不能准确地计算工程量，但工程设计采用的技术比较成熟而又有类似工程概算指标可以利用时，可以采用概算指标法编制工程概算。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0293", "date": "2026-07-09", "chapter": "g05", "type": "single", "stem": "某地已建设一栋面积为 3000 ㎡的教学楼，该教学楼建筑工程部分部分项工程费为 950 元/㎡，其中墙涂料费用为 30 元/㎡，今拟建一栋建筑面积为 5500 ㎡的教学楼，外墙采用刷仿石漆，其费用为 120 元/㎡,其他结构相同，则拟建教学楼的建筑工程分部分工程费为（ ）万元。", "options": {"A": "360", "B": "400", "C": "572", "D": "560"}, "answer": ["C"], "analysis": "【考点来源】本题考查的是单位工程概算的编制 【选项分析】调整后的概算指标为：950-30+120=1040元/㎡ 拟建教学楼的建筑工程分部分工程费：1040×5500 =572万元", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0295", "date": "2026-07-09", "chapter": "g05", "type": "single", "stem": "不属于施工图预算审查方法的为（ ）。", "options": {"A": "全面审查法", "B": "对比审查法", "C": "重点抽查法", "D": "查询核实法"}, "answer": ["D"], "analysis": "施工图预算审查方法较多，主要有全面审查法、标准预算审查法、分组计算审查法、对比审查法、筛选审查法、重点抽查法、利用于册审查法和分解对比审查法等多种。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0296", "date": "2026-07-09", "chapter": "g05", "type": "single", "stem": "对于设计方案比较特殊，无同类工程可比，且审查精度要求高的施工图预算，适宜采用的审查方法是（ ）。", "options": {"A": "全面审查法", "B": "标准预算审查法", "C": "对比审查法", "D": "重点审查法"}, "answer": ["A"], "analysis": "【内容考查】本题考查的是施工图预算审査方法 【选项分析】全面审查法又称逐项审查法，即按定额顺序或施工顺序，对各项工程细目逐项全面详细审查的一种方法。其优点是全面、细致，审查质量高、效果好。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0299", "date": "2026-07-09", "chapter": "g05", "type": "single", "stem": "实物量法编制施工图预算所用的材料单价应采用（ ）。", "options": {"A": "网上咨询厂家的报价", "B": "编制预算定额时采用的单价", "C": "当时当地的实际价格", "D": "预算定额中采用的单价加上运杂费"}, "answer": ["C"], "analysis": "【内容考查】本题考查的是施工图预算的编制方法 【选项分析】实物量法编制施工图预算所用人工、材料和机械台班的单价都是当时当地的实际价格，编制出的预算可较准确地反映实际水平，误差较小，适用于市场经济条件波动较大的情况。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0300", "date": "2026-07-09", "chapter": "g05", "type": "single", "stem": "关于施工图预算的作用，下列说法中正确的是（ ）。", "options": {"A": "施工图预算可以作为业主拨付工程进度款的基础", "B": "施工图预算是工程造价管理部门制定招标控制价的依据", "C": "施工图预算是业主方进行施工图预算与施工预算“两算”对比的依据", "D": "施工图预算是建设单位安排调配施工力量、组织材料设备供应的依据"}, "answer": ["A"], "analysis": "【内容考查】本题考查的是施工图预算的作用 【选项分项】施工图预算的作用分为对投资方的作用、对施工企业的作用和对其他方面的作用三个方面。对于投资方来说，施工图预算可以作为确定合同价款、拨付工程进度款及办理工程结算的基础。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0301", "date": "2026-07-09", "chapter": "g05", "type": "single", "stem": "施工图预算编制完成后，需要认真进行全面、系统的审查。施工图预算审查的主要内容不包括（ ）。", "options": {"A": "审查材料代用是否合理", "B": "审查设备、材料的预算价格", "C": "审查工程量", "D": "审查预算单价的套用"}, "answer": ["A"], "analysis": "施工图预算审查的内容包括：工程量的审查、审查设备、材料的预算价格、审査预算单价的套用、审查有关费用项目及其取值。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0304", "date": "2026-07-09", "chapter": "g05", "type": "single", "stem": "施工图预算的二级预算编制形式由（ ）组成。", "options": {"A": "总预算和单位工程预算", "B": "单位工程综合预算和单位工程预算", "C": "总预算和单位工程综合预算", "D": "建筑工程预算和设备安装工程预算"}, "answer": ["A"], "analysis": "施工图预算根据建设项目实际情况可采用三级预算编制或二级预算编制形式。当建设项目有多个单项工程时，应采用三级预算编制形式，三级预算编制形式由建设项目总预算、单项工程综合预算、单位工程预算组成。当建设项目只有一个单项工程时，应采用二级预算编制形式，二级预算编制形式由建设项目总预算和单位工程预算组成。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0307", "date": "2026-07-09", "chapter": "g05", "type": "single", "stem": "采用实物量法与预算单价法编制施工图预算，其工作步骤差异体现在（ ）。", "options": {"A": "工程量的计算", "B": "直接费的计算", "C": "企业管理费的计算", "D": "税金的计算"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是施工图预算的编制方法 【选项分析】用实物量法编制单位工程施工图预算，就是根据施工图计算的各分部分项工程量分别乘以地区定额中人工、材料、施工机械台班的定额消耗量，分类汇总得出该单位工程所需的全部人工、材料、施工机械台班消耗数量，然后再乘以当时当地人工工日单价、各种材料单价、施工机械台班单价，求出相应的人工费、材料费、施工机具使用费。企业管理费、利润及增值税等费用计取方法与预算单价法相同。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0308", "date": "2026-07-09", "chapter": "g05", "type": "single", "stem": "施工图预算审查法所采用的标准预算审查法的特点描述正确的是（ ）。", "options": {"A": "优点是全面、细致，审查的质量高；缺点是工作量大，审查时间较长", "B": "优点是审查时间较短，审查效果好；缺点是应用范围较小", "C": "优点是可加快工程量审查的速度；缺点是审查的精度较差", "D": "优点是便于掌握，审查速度较快；缺点是有局限性"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是施工图预算审査方法 【选项分析】标准预算审查法是指对于利用标准图纸或通用图纸施工的工程，先集中力量编制标准预算，然后以此为标准对施工图预算进行审查。其优点是审查时间较短，审查效果好；缺点是应用范围较小。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0309", "date": "2026-07-09", "chapter": "g05", "type": "single", "stem": "对采用通用图纸的多个工程施工图预算进行审查时，为节省时间，宜采用的审查方法是（ ）。", "options": {"A": "全面审查法", "B": "筛选审查法", "C": "标准预算审查法", "D": "对比审查法"}, "answer": ["C"], "analysis": "标准预算审查法就是对利用标准图纸或通用图纸施工的工程，先集中力量编制标准预算，以此为准来审查工程预算的一种方法。该方法的优点是时间短、效果好；其缺点是适用范围小，仅适用于采用标准图纸的工程。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0310", "date": "2026-07-09", "chapter": "g05", "type": "single", "stem": "施工图预算的三级预算编制形式由（ ）组成。", "options": {"A": "单位工程预算、单项工程综合预算、建设项目总预算", "B": "静态投资、动态投资、流动资金", "C": "建筑安装工程费、设备购置费、工程建设其他费", "D": "单项工程综合预算、建设期利息、建设项目总预算"}, "answer": ["A"], "analysis": "施工图预算根据建设项目实际情况可采用三级预算编制或二级预算编制形式。当建设项目有多个单项工程时，应采用三级预算编制形式，三级预算编制形式由建设项目总预算、单项工程综合预算、单位工程预算组成。当建设项目只有一个单项工程时，应采用二级预算编制形式，二级预算编制形式由建设项目总预算和单位工程预算组成。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "gl-g05-009", "date": "2026-07-08", "chapter": "g05", "type": "multiple", "stem": "在项目决策和设计阶段，影响工程造价的主要因素包括（ ）。", "options": {"A": "项目规模", "B": "建设标准", "C": "工艺方案", "D": "设备选型", "E": "施工单位资质"}, "answer": ["A", "B", "C", "D"], "analysis": "决策设计阶段影响造价的因素包括项目规模、建设标准、工艺方案、设备选型和厂址选择等。施工单位资质属于招标投标阶段考虑的因素。", "tags": ["决策设计阶段", "影响因素"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g05-013", "date": "2026-07-08", "chapter": "g05", "type": "multiple", "stem": "单位设备安装工程概算的编制方法包括（ ）。", "options": {"A": "预算单价法", "B": "扩大单价法", "C": "设备价值百分比法", "D": "概算指标法", "E": "类似工程预算法"}, "answer": ["A", "B", "C"], "analysis": "单位设备安装工程概算的编制方法有：预算单价法、扩大单价法和设备价值百分比法（安装费率法）。概算指标法和类似工程预算法是建筑工程概算方法。", "tags": ["设计概算", "设备安装概算方法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g05-016", "date": "2026-07-08", "chapter": "g05", "type": "multiple", "stem": "设计概算的审查方法主要包括（ ）。", "options": {"A": "对比分析法", "B": "查询核实法", "C": "联合会审法", "D": "逐项审查法", "E": "筛选审查法"}, "answer": ["A", "B", "C"], "analysis": "设计概算审查方法包括对比分析法、查询核实法和联合会审法。逐项审查法和筛选审查法是施工图预算的审查方法。", "tags": ["设计概算", "审查方法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g05-019", "date": "2026-07-08", "chapter": "g05", "type": "multiple", "stem": "施工图预算的审查方法包括（ ）。", "options": {"A": "逐项审查法", "B": "标准预算审查法", "C": "分组计算审查法", "D": "对比审查法", "E": "联合会审法"}, "answer": ["A", "B", "C", "D"], "analysis": "施工图预算审查方法包括：逐项审查法、标准预算审查法、分组计算审查法、对比审查法、筛选审查法等。联合会审法是设计概算的审查方法。", "tags": ["施工图预算", "审查方法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g05-022", "date": "2026-07-08", "chapter": "g05", "type": "multiple", "stem": "价值工程活动中，提高产品价值的途径包括（ ）。", "options": {"A": "功能不变，降低成本", "B": "成本不变，提高功能", "C": "功能提高，成本降低", "D": "成本略有提高，功能大幅提高", "E": "功能略有降低，成本不变"}, "answer": ["A", "B", "C", "D"], "analysis": "根据V=F/C，提高价值的途径：①功能不变降低成本；②成本不变提高功能；③功能提高成本降低（最理想）；④成本略有提高但功能大幅提高。功能降低而成本不变会降低价值。", "tags": ["价值工程", "提高价值途径"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g05-029", "date": "2026-07-08", "chapter": "g05", "type": "multiple", "stem": "在投资估算中，常用的静态投资估算方法包括（ ）。", "options": {"A": "生产能力指数法", "B": "比例估算法", "C": "系数估算法", "D": "指标估算法", "E": "内部收益率法"}, "answer": ["A", "B", "C", "D"], "analysis": "静态投资估算方法包括生产能力指数法、比例估算法、系数估算法和指标估算法。内部收益率法是经济评价方法而非投资估算方法。", "tags": ["投资估算", "估算方法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g05-032", "date": "2026-07-08", "chapter": "g05", "type": "multiple", "stem": "建设项目的厂址选择应考虑的主要因素包括（ ）。", "options": {"A": "土地费用", "B": "交通运输条件", "C": "环境保护要求", "D": "当地建筑材料来源", "E": "施工企业的注册地址"}, "answer": ["A", "B", "C", "D"], "analysis": "厂址选择需考虑土地费用、交通运输条件、环境保护要求、当地建筑材料来源、水电供应条件等。施工企业注册地与厂址选择无关。", "tags": ["决策阶段", "厂址选择"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g05-036", "date": "2026-07-08", "chapter": "g05", "type": "multiple", "stem": "实物量法编制施工图预算与定额单价法相比，其特点包括（ ）。", "options": {"A": "采用当时当地的市场价格", "B": "能较好地反映实际价格水平", "C": "计算过程相对复杂", "D": "不需要计算工程量", "E": "适用于市场价格波动较大的情况"}, "answer": ["A", "B", "C", "E"], "analysis": "实物量法采用当时当地市场单价，能较好反映实际价格水平，但计算复杂。两种方法都需要计算工程量。实物量法更适合市场价格波动较大的情况。", "tags": ["施工图预算", "实物量法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-047", "date": "2026-07-08", "chapter": "g05", "type": "multiple", "stem": "建设工程各阶段对造价的影响程度，以下对应关系正确的有（ ）。", "options": {"A": "初步设计阶段：75%～95%", "B": "技术设计阶段：35%～75%", "C": "施工图设计阶段：5%～35%", "D": "项目建议书阶段：±50%", "E": "可行性研究阶段：±10%"}, "answer": ["A", "B", "C", "E"], "analysis": "A、B、C正确（设计影响度）。D错误：项目建议书精度±30%。E正确：可研精度±10%。", "tags": ["阶段精度", "设计影响度"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-048", "date": "2026-07-08", "chapter": "g05", "type": "multiple", "stem": "投资估算的编制方法包括（ ）。", "options": {"A": "生产能力指数法", "B": "比例估算法", "C": "系数估算法", "D": "指标估算法", "E": "定额单价法"}, "answer": ["A", "B", "C", "D"], "analysis": "投资估算方法包括生产能力指数法、比例估算法、系数估算法（朗格系数法）、指标估算法等。定额单价法是施工图预算编制方法。", "tags": ["投资估算", "方法汇总"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-049", "date": "2026-07-08", "chapter": "g05", "type": "multiple", "stem": "关于生产能力指数法中n值的取值，下列说法正确的有（ ）。", "options": {"A": "Q2/Q1≤0.5时，n≈0.6", "B": "0.5<Q2/Q1≤2时，n=0.7～0.8", "C": "2<Q2/Q1≤50时，n=0.8～0.9", "D": "靠增大设备规格扩大规模时，n=0.8～0.9", "E": "靠增加同规格设备数量时，n=0.6～0.7"}, "answer": ["A", "B", "C"], "analysis": "A、B、C正确（规模比值区间与n值对应）。D错误：增大设备规格n=0.6～0.7。E错误：增加同规格设备数量n=0.8～0.9。D和E恰好说反。", "tags": ["投资估算", "生产能力指数法", "n值"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-050", "date": "2026-07-08", "chapter": "g05", "type": "multiple", "stem": "单位建筑工程设计概算的编制方法包括（ ）。", "options": {"A": "概算定额法", "B": "概算指标法", "C": "类似工程预算法", "D": "预算单价法", "E": "生产能力指数法"}, "answer": ["A", "B", "C"], "analysis": "单位建筑工程概算编制方法：概算定额法、概算指标法、类似工程预算法。D预算单价法属于设备安装工程概算方法。E生产能力指数法属于投资估算方法。", "tags": ["设计概算", "编制方法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-051", "date": "2026-07-08", "chapter": "g05", "type": "multiple", "stem": "设备及安装工程概算的编制方法包括（ ）。", "options": {"A": "预算单价法", "B": "扩大单价法", "C": "设备百分比法", "D": "综合吨位指标法", "E": "概算指标法"}, "answer": ["A", "B", "C", "D"], "analysis": "设备安装工程概算方法：预算单价法（有清单）、扩大单价法（清单不完备）、设备百分比法（只有设备费）、综合吨位指标法。E概算指标法属于建筑工程概算方法。", "tags": ["设计概算", "设备概算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-052", "date": "2026-07-08", "chapter": "g05", "type": "multiple", "stem": "设计概算审查的方法包括（ ）。", "options": {"A": "对比分析法", "B": "查询核实法", "C": "联合会审法", "D": "逐项审查法", "E": "筛选审查法"}, "answer": ["A", "B", "C"], "analysis": "设计概算审查3法：对比分析法、查询核实法、联合会审法。D逐项审查法和E筛选审查法属于施工图预算的审查方法，注意区分。", "tags": ["设计概算", "审查方法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-054", "date": "2026-07-08", "chapter": "g05", "type": "multiple", "stem": "施工图预算编制方法中，定额单价法与实物量法的对比，正确的有（ ）。", "options": {"A": "定额单价法套用预算定额基价，实物量法套用市场单价", "B": "定额单价法简便快捷，实物量法工作量大", "C": "实物量法能更好地反映市场实际价格水平", "D": "定额单价法不需要计算工程量", "E": "实物量法比定额单价法更能适应市场价格波动"}, "answer": ["A", "B", "C", "E"], "analysis": "A、B、C、E均正确。D错误：两种方法都需要先计算分项工程量，只是后续单价取值方式不同。", "tags": ["施工图预算", "定额单价vs实物量"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-055", "date": "2026-07-08", "chapter": "g05", "type": "multiple", "stem": "施工图预算审查的内容包括（ ）。", "options": {"A": "工程量计算是否正确", "B": "定额套用是否合理", "C": "各项取费是否符合规定", "D": "人工、材料、机械价格是否合理", "E": "施工进度计划是否可行"}, "answer": ["A", "B", "C", "D"], "analysis": "施工图预算审查内容：工程量、定额套用、各项取费、人材机价格。施工进度计划属于施工组织设计内容，不属于预算审查范围。", "tags": ["施工图预算", "审查内容"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-056", "date": "2026-07-08", "chapter": "g05", "type": "multiple", "stem": "关于限额设计的原则，下列说法正确的有（ ）。", "options": {"A": "施工图预算不得突破设计概算", "B": "设计概算不得突破经批准的投资估算", "C": "各专业按分配的投资限额进行设计", "D": "限额设计只在施工图设计阶段执行", "E": "设计变更时应严格控制在限额以内"}, "answer": ["A", "B", "C", "E"], "analysis": "A、B、C、E正确。D错误：限额设计贯穿初步设计、技术设计、施工图设计全过程，不是仅在施工图阶段执行。", "tags": ["限额设计", "原则"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-057", "date": "2026-07-08", "chapter": "g05", "type": "multiple", "stem": "根据价值工程原理 V=F/C，提高产品价值的途径有（ ）。", "options": {"A": "F↑, C↓（功能提高，成本降低）", "B": "F→, C↓（功能不变，成本降低）", "C": "F↑, C→（功能提高，成本不变）", "D": "F↓, C↑（功能降低，成本增加）", "E": "F↑↑, C↑（功能大幅提高，成本略有增加）"}, "answer": ["A", "B", "C", "E"], "analysis": "提高V值的5种途径：F↑C↓、F→C↓、F↑C→、F↑↑C↑、F↓C↓↓。D选项F↓C↑会使V值下降，不是提高途径。", "tags": ["价值工程", "V=F/C"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-058", "date": "2026-07-08", "chapter": "g05", "type": "multiple", "stem": "下列关于各类审查方法的适用条件，正确的有（ ）。", "options": {"A": "逐项审查法适用于工程量较小、工艺简单的工程", "B": "标准预算审查法适用于按标准图纸施工的工程", "C": "分组计算审查法适用于住宅工程", "D": "对比审查法适用于有类似已审预算的工程", "E": "筛选审查法适用于不具备全面审查条件、但结构形式基本相同的工程"}, "answer": ["A", "B", "D", "E"], "analysis": "A、B、D、E正确。C错误：分组计算审查法的特点是利用同组数据关联审查，不是特指住宅工程。筛选审查法适用于住宅工程等结构形式基本相同的情况。", "tags": ["施工图预算", "审查方法", "对比"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-059", "date": "2026-07-08", "chapter": "g05", "type": "multiple", "stem": "以下关于概算编制方法的选用条件，正确的有（ ）。", "options": {"A": "设计深度足够→概算定额法", "B": "设计深度不够→概算指标法", "C": "有类似已完工程→类似工程预算法", "D": "有详细设备清单→预算单价法", "E": "设备清单不完备→扩大单价法"}, "answer": ["A", "B", "C", "D", "E"], "analysis": "全部正确。建筑工程概算：深度够用概算定额法，深度不够用概算指标法，有类似工程用类似工程预算法。设备概算：有清单用预算单价法，不完备用扩大单价法，只有设备费用设备百分比法。", "tags": ["设计概算", "编制方法选用"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g05-060", "date": "2026-07-08", "chapter": "g05", "type": "multiple", "stem": "关于投资估算各方法的特点，下列说法正确的有（ ）。", "options": {"A": "生产能力指数法计算快，但需注意n值的正确选取", "B": "比例估算法以设备费为基数，适用于设备投资比重大的项目", "C": "朗格系数法通过单一系数快速估算总投资", "D": "指标估算法适用于设计深度较深时的施工图预算编制", "E": "生产能力指数法的综合调整系数f包含价格、时间等因素"}, "answer": ["A", "B", "C", "E"], "analysis": "A、B、C、E正确。D错误：指标估算法精度较低，主要用于投资估算阶段，不适用于设计深度较深时的施工图预算编制。设计深度深时应用概算定额法或定额单价法。", "tags": ["投资估算", "方法对比"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "ht_mgmt_1388", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "建设项目投资估算可以用混合法，是根据主体专业设计的阶段和深度，采用()相混合估算其相关投资额的方法。", "options": {"A": "生产能力指数法与系数估算法", "B": "系数估算法与比例估算法", "C": "单位生产能力估算法与比例估算法", "D": "系数估算法与单位生产能力估算法", "E": "生产能力指数法与比例估算法"}, "answer": ["B", "E"], "analysis": "混合法是根据主体专业设计的阶段和深度，投资估算编制者所掌握的国家及地区、行业或部门相关投资估算基础资料和数据，以及其他统计和积累的、可靠的相关造价基础资料，对一个拟建建设项目采用生产能力指数法与比例估算法或系数估算法与比例估算法混合估算其相关投资额的方法。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1389", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "建设规模是影响工程造价的主要因素之一，项目决策阶段合理确定建设规模的主要方法有（）。", "options": {"A": "盈亏平衡产量分析法", "B": "平均成本法", "C": "生产能力平衡法", "D": "单位生产能力估算法", "E": "回归分析法"}, "answer": ["A", "B", "C"], "analysis": "不同行业、不同类型项目的在研究确定其建设规模时还应充分考虑其自身特点。项目合理建设规模的确定方法包括：盈亏平衡产量分析法、平均成本法、生产能力平衡法、政府或行业规定。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1390", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "下列关于制约项目建设规模合理化因素的表述中，正确的是()。", "options": {"A": "确定项目生产规模的前提是项目资金供应情况", "B": "先进适用的生产技术及技术装备是项目规模效益实现的保证", "C": "市场价格分析是制定营销策略和影响竞争力的主要因素", "D": "原材料市场、资金市场和劳动力市场对项目规模的选择起到制约作用", "E": "市场风险分析是确定项目建设规模的重要依据"}, "answer": ["C", "D", "E"], "analysis": "选项A错误，确定项目生产规模的前提是市场需求；选项B错误，效益实现的保证并非先进适用的生产技术及技术装备，应当是管理技术水平。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1391", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "在进行工程方案的选择时，应满足的基本要求包括()。", "options": {"A": "满足生产使用功能要求", "B": "适应已选定的场址", "C": "符合工程标准规范要求", "D": "经济合理", "E": "力求环境效益与经济效益相统一"}, "answer": ["A", "B", "C", "D"], "analysis": "工程方案选择应满足的基本要求：①满足生产使用功能要求；②适应已选定的场址；③符合工程标准规范要求；④经济合理。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1392", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "估算建设投资后需编制建设投资估算表，为后期的融资决策提供依据。按概算法分类，建设投资可分为()。", "options": {"A": "工程费用", "B": "工程建设其他费用", "C": "固定资产费用", "D": "无形资产费用", "E": "预备费"}, "answer": ["A", "B", "E"], "analysis": "按照概算法分类，建设投资由工程费用、工程建设其他费用和预备费三部分构成。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1393", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "下列关于建设项目决策阶段设备方案选择的说法，正确的有()。", "options": {"A": "设备选择应符合政府部门的技术标准要求", "B": "尽量选用质量高的进口设备", "C": "在保证设备性能前提下，力求经济合理", "D": "注意进口设备的配套问题", "E": "先确定设备的型号和数量后再确定生产工艺流程"}, "answer": ["A", "C", "D"], "analysis": "在确定生产工艺流程和生产技术后，应根据工厂生产规模和工艺过程的要求，选择设备的型号和数量。设备方案选择应符合的要求包括：主要设备方案应与确定的建设规模、产品方案和技术方案相适应，并满足项目投产后生产或使用的要求；主要设备之间、主要设备与辅助设备之间的生产或使用性能要相互匹配；设备质量应安全可靠、性能成熟，保证生产和产品质量稳定；在保证设备性能前提下，力求经济合理；选择的设备应符合政府部门或专门机构发布的技术标准要求。设备选用应注意处理的问题包括：要尽量选用国产设备；要注意进口设备之间以及国内外设备之间的衔接配套问题；要注意进口设备与原有国产设备、厂房之间的配套问题；要注意进口设备与原材料、备品备件及维修能力之间的配套问题。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1394", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "在编制建设投资估算表时，按形成资产法分类，下列费用属于建设投资组成部分的有()。", "options": {"A": "固定资产费用", "B": "无形资产费用", "C": "其他资产费用", "D": "工程费用", "E": "预备费"}, "answer": ["A", "B", "C", "E"], "analysis": "按概算法分类，建设投资由工程费用、工程建设其他费用和预备费三部分构成。按形成资产法分类，建设投资由形成固定资产的费用、形成无形资产的费用、形成其他资产的费用和预备费四部分组成。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1395", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "项目决策阶段进行设备选用时，应处理好的问题包括()。", "options": {"A": "进口设备与国产设备费用的比例关系问题", "B": "进口设备的备件供应与维修能力问题", "C": "设备间的衔接配套问题", "D": "设备与原有厂房之间的配套问题", "E": "进口设备与原材料之间的配套问题"}, "answer": ["B", "C", "D", "E"], "analysis": "设备选用应注意处理的问题：①要尽量选用国产设备；②要注意进口设备之间以及国内外设备之间的衔接配套问题；③要注意进口设备与原有国产设备、厂房之间的配套问题；④要注意进口设备与原材料、备品备件及维修能力之间的配套问题。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1396", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "下列形成固定资产，但属于固定资产其他费用的是()。", "options": {"A": "工器具购置费", "B": "建设管理费", "C": "勘察设计费", "D": "引进技术和引进设备其他费用", "E": "生产准备及开办费"}, "answer": ["B", "C", "D"], "analysis": "固定资产其他费用，主要包括建设管理费、可行性研究费、研究试验费、勘察设计费、环境影响评价费、场地准备及临时设施费、引进技术和引进设备其他费、工程保险费、联合试运转费、特殊设备安全监督检验费和市政公用设施建设及绿化费等。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1397", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "在建设项目决策阶段，技术方案影响着工程造价，因此，选择技术方案应坚持的基本原则是()。", "options": {"A": "先进适用", "B": "安全可靠", "C": "经济合理", "D": "简明适用", "E": "平均先进"}, "answer": ["A", "B", "C"], "analysis": "生产技术方案指产品生产所采用的工艺流程和生产方法。在建设规模和建设地区及地点确定后，具体的工程技术方案的确定，在很大程度上影响着工程建设成本以及建成后的运营成本。技术方案的选择直接影响项目的工程造价。技术方案选择的基本原则是先进适用、安全可靠、经济合理。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1398", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "对于工业建设项目厂址选择时，需要进行技术经济论证，下列内容中属于建设厂址比较的主要内容的有()。", "options": {"A": "建设费用比较", "B": "经营费用比较", "C": "市场风险比较", "D": "技术水平比较", "E": "环境影响比较"}, "answer": ["A", "B", "E"], "analysis": "市场因素与技术因素属于确定建设规模的影响因素。在项目选址工作中，通过实地调查和基础资料的搜集，拟定项目选址的备选方案，并对各种方案进行技术经济论证，确定最佳厂址方案。建设地点（厂址）比较的主要内容有：建设条件比较、建设费用比较、经营费用比较、运输费用比较、环境影响比较和安全条件比较。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1399", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "采用指标估算法时.影响投资估算精度的因素有()。", "options": {"A": "价格变化", "B": "技术水平的变化", "C": "现场施工条件的变化", "D": "工艺流程的变化", "E": "项目特征的变化"}, "answer": ["A", "C", "E"], "analysis": "影响投资估算精度的因素主要包括价格变化、现场施工条件、项目特征的变化等。因而，在应用指标估算法时，应根据不同地区、建设年代、条件等进行调整。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1400", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "下列费用中，项目投产时将直接形成固定资产的费用有（）。", "options": {"A": "建设单位管理费", "B": "研究试验费", "C": "生产准备费", "D": "工程保险费", "E": "临时设施费"}, "answer": ["A", "B", "D", "E"], "analysis": "建设投资由形成固定资产的费用、形成无形资产的费用、形成其他资产的费用和预备费四部分组成。固定资产费用是指项目投产时将直接形成固定资产的建设投资，包括工程费用和工程建设其他费用中按规定将形成固定资产的费用，后者被称为固定资产其他费用，主要包括建设管理费、可行性研究费、研究试验费、勘察设计费、环境影响评价费、场地准备及临时设施费、引进技术和引进设备其他费、工程保险费、联合试运转费、特殊设备安全监督检验费和市政公用设施建设及绿化费等。生产准备费属于其他资产费用的范畴。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1401", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "在技术改造项目中，可采用生产能力平衡法来确定合理生产规模。下列属于生产能力平衡法的是（）。", "options": {"A": "盈亏平衡产量分析法", "B": "平均成本法", "C": "最小公倍数法", "D": "最大工序生产能力法", "E": "设备系数法"}, "answer": ["C", "D"], "analysis": "3)生产能力平衡法。在技改项目中，可采用生产能力平衡法来确定合理生产规模。最大土序生产能力法是以现有最大生产能力的工序为标准，逐步填平补齐，成龙配套，使之满足最大生产能力的设备要求。最小公倍数法是以项目各工序生产能力或现有标准设备的生产能力为基础，并以各工序生产能力的最小公倍数为准，通过填平补齐，成龙配套，形成最佳的生产规模。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1402", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "应用朗格系数进行工程项目或装置估价的精度应不是很高,主要原因在于（）。", "options": {"A": "装置规模大小发生变化的影响", "B": "主要设备材质发生变化时,设备费用变化较大而安装费变化不大所产生的影响", "C": "不同地区经济制度不同的影响", "D": "不同地区气候条件的影响", "E": "不同地区自然地理条件的影响"}, "answer": ["A", "B", "D", "E"], "analysis": "朗格系数法进行工程项目或装置估价的精度仍不是很高，主要原因为:①装置规模大小发生变化;②不同地区自然地理条件的差异;③不同地区经济地理条件的差异；不同地区气候条件的差异;⑤主要设备材质发生变化时，设备费用变化较大而安装费变化不大。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1403", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "静态投资估算中的混合法是利用（）混合估算其相关投资额度的方法。", "options": {"A": "生产能力指数法与比例估算法", "B": "系数估算法与比例估算法", "C": "系数估算法与生产能力指数法", "D": "生产能力指数法与朗格系数法", "E": "朗格系数法与单位生产能力估算法"}, "answer": ["A", "B"], "analysis": "混合法是根据主体专业设计的阶段和深度,投资估算编制者所掌握的国家及地区、行业或部门相关投资估算基础资料和数据，以及其他统计和积累的可靠的相关造价基础资料,对一个拟建建设项目采用生产能力指数法与比例估算法或系数估算法与比例估算法混合估算其相关投资额的方法。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1404", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "下列选项中，在选择工程方案时需要在选定项目（）的基础上进行论证。", "options": {"A": "建设规模", "B": "技术方案", "C": "设备方案", "D": "环境保护措施", "E": "建设地点"}, "answer": ["A", "B", "C"], "analysis": "工程方案:1.选定项目建设规模、技术方案和设备方案的基础上进行论证。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1405", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "直接套用概算指标编制单位建筑工程设计概算时，拟建工程应符合的条件包括（）。", "options": {"A": "建设地点与概算指标中的工程建设地点相同", "B": "工程特征与概算指标中的工程特征基本相同", "C": "建筑面积与概算指标中的工程建筑面积相差不大", "D": "建造时间与概算指标中工程建造时间相近", "E": "物价水平与概算指标中工程的物价水平基本相同"}, "answer": ["A", "B", "C"], "analysis": "在直接套用概算指标时，拟建工程应符合以下条件：（1）拟建工程的建设地点与概算指标中的工程建设地点相同。（2）拟建工程的工程特征和结构特征与概算指标中的工程特征、结构特征基本相同。（3）拟建工程的建筑面积与概算指标中工程的建筑面积相差不大。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1406", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "下列关于工业项目建筑设计影响工程造价的阐述，正确的是()。", "options": {"A": "在满足建筑物一定要求前提下，将流通空间减小到最小", "B": "建筑物周长与建筑面积比越低，设计越经济", "C": "对于多跨厂房，当跨度不变时，中跨数目越多越经济", "D": "建筑物的室内外高差过小，工程造价将有所提高", "E": "对于工业建筑，采用大跨度、大柱距的平面设计形式，可提高平面利用系数，从而降低工程造价"}, "answer": ["A", "B", "C", "E"], "analysis": "选项D错误，室内外高差过大，则建筑物的工程造价提高。通常情况下建筑周长系数越低，设计越经济。 建筑物的体积与面积。建筑物尺寸的增加，一般会引起单位面积造价的降低。对于同一项目，固定费用不一定会随着建筑体积和面积的扩大而有明显的变化，一般情况下，单位面积固定费用会相应减少。对于工业建筑，厂房、设备布置紧凑合理，可提高生产能力，采用大跨度、大柱距的平面设计形式，可提高平面利用系数，从而降低工程造价。对于多跨厂房，当跨度不变时，中跨数目越多越经济，这是因为柱子和基础分摊在单位面积上的造价减少。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1407", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "民用住宅建筑设计中影响工程造价的主要因素包括()。", "options": {"A": "建筑物平面形状和周长系数", "B": "占地面积", "C": "住宅的层高和净高", "D": "住宅的层数", "E": "建筑群体的布置形式"}, "answer": ["A", "C", "D"], "analysis": "民用住宅建筑设计中影响工程造价的主要因素包括：(1)建筑物平面形状和周长系数；(2)住宅的层高和净高；(3)住宅的层数；(4)住宅的单元组成、户型和住户面积；(5)住宅建筑结构的选择。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1408", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "采用概算指标法编制建筑工程设计概算，直接套用概算指标时，拟建工程符合的条件是()。", "options": {"A": "拟建工程和概算指标中工程建设地区相同", "B": "拟建工程和概算指标中工程建设地点相同", "C": "拟建工程和概算指标中工程的工程特征、结构特征基本相同", "D": "拟建工程和概算指标中工程的建造工艺相差不大", "E": "拟建工程和概算指标中工程的建筑面积相差不大"}, "answer": ["B", "C", "E"], "analysis": "在直接套用概算指标时，拟建工程应符合以下条件：(1)拟建工程的建设地点与概算指标中的工程建设地点相同；(2)拟建工程的工程特征和结构特征与概算指标中的工程特征、结构特征基本相同；(3)拟建工程的建筑面积与概算指标中工程的建筑面积相差不大。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1409", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "关于工业建设项目的设备选用，其选用的重点因设计形式的不同而不同，应选择能满足()要求的最适用的设备和机械。", "options": {"A": "建设规模", "B": "建筑结构", "C": "生产工艺", "D": "生产能力", "E": "环保措施"}, "answer": ["C", "D"], "analysis": "关于工业建设项目的设备选用，其选用的重点因设计形式的不同而不同，应选择能满足生产工艺和生产能力要求的最适用的设备和机械。建设规模、环保措施属于工艺设计阶段影响工程造价的因素。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1410", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "某建设项目由厂房、办公楼、宿舍等单项工程组成，则单项工程综合概算中的内容有()。", "options": {"A": "机械设备及安装工程概算", "B": "电气设备及安装工程概算", "C": "工程建设其他费用概算", "D": "特殊构筑物工程概算", "E": "流动资金概算"}, "answer": ["A", "B", "D"], "analysis": "单项工程综合概算的内容如图3-3所示：", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1411", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "设计概算编制方法中，照明工程概算的编制方法包括()。", "options": {"A": "概算定额法", "B": "设备价值百分比法", "C": "概算指标法", "D": "综合吨位指标法", "E": "类似工程预算法"}, "answer": ["A", "C", "E"], "analysis": "照明工程的概算属于建筑单位工程概算，其常用的方法有概算定额法、概算指标法、类似工程预算法。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1412", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "住宅建筑是民用建筑中最大量、最主要的建筑形式。下列内容中，属于民用住宅建筑设计中影响工程造价的主要因素的有()。", "options": {"A": "占地面积", "B": "平面形状", "C": "层高", "D": "建筑结构", "E": "建筑群体的布置形式"}, "answer": ["B", "C", "D"], "analysis": "民用住宅建筑设计中影响工程造价的主要因素包括建筑物平面形状和周长系数、住宅的层高和净高、住宅的层数、住宅的单元组成、户型和住户面积、住宅建筑结构。占地面积和建筑群体的布置形式是建设规划中影响工程造价的主要因素。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1413", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "下列关于总平面设计中影响工程造价的主要因素描述，正确的是()。", "options": {"A": "地质、水文、气象条件影响基础形式及埋深", "B": "地形地貌影响平面布置和建筑层数", "C": "场地大小、邻近建筑物地上附着物平面布置、建筑层数、基础形式及埋深", "D": "占地面积大小影响征地费用的高低及项目运输成本", "E": "合理的功能分区有利于降低工程造价和运营成本"}, "answer": ["A", "C", "D", "E"], "analysis": "总平面设计中影响工程造价的主要因素包括：现场条件（场地大小、邻近建筑物地上附着物等影响平面布置、建筑层数、基础形式及埋深）、占地面积、功能分区、运输方式。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1414", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "下列关于民用住宅建筑设计中影响工程造价的主要因素的表述中，正确的是()。", "options": {"A": "在矩形民用住宅建筑中长宽比以4:3最佳", "B": "住宅层高降低，可降低工程造价和提高建筑密度’", "C": "在满足住宅功能和质量的前提下，适当加大住宅宽度，有利于降低工程造价", "D": "随着住宅层数的增加，单方造价系数逐渐降低，而边际造价系数逐渐增加", "E": "衡量单元组合、户型设计的指标是结构面积系数"}, "answer": ["B", "C", "E"], "analysis": "选项A错误，在矩型住宅建筑中，以长﹕宽=2:1为佳；选项D错误，随着住宅层数的增加，单方造价系数在逐渐降低，但是边际造价系数也在逐渐减小。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1415", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "在使用概算指标法编制设计概算时，若想直接套用概算指标编制概算，则拟建工程应在（）等方面与概算指标相同或相近。", "options": {"A": "消耗定额", "B": "结构特征", "C": "地质及自然条件", "D": "投资主体", "E": "建筑面积"}, "answer": ["B", "C", "E"], "analysis": "拟建工程结构特征与概算指标相同时的计算。在使用概算指标法时，如果拟建工程在建设地点、结构特征、地质及自然条件、建筑面积等方面与概算指标相同或相近，就可直接套用概算指标编制概算。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1416", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "下列关于施工图预算对施工企业的作用，表述正确的是()。", "options": {"A": "施工图预算是进行“两算”对比的依据", "B": "施工图预算是建筑工程预算包干的依据", "C": "施工图是控制造价及资金合理使用的依据", "D": "施工图预算是确定工程招标控制价的依据", "E": "施工图预算是施工图设计不突破设计概算的重要措施"}, "answer": ["A", "B"], "analysis": "施工图预算对施工企业的作用：(1)施工图预算是建筑施工企业投标报价的基础；(2)施工图预算是建筑工程预算包干的依据和签订施工合同的主要内容；(3)施工图预算是施工企业安排调配施工力量、组织材料供应的依据；(4)施工图预算是施工企业控制工程成本的依据；(5)施工图预算是进行“两算”对比的依据。选项CDE属于施工图预算对投资方的作用。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1417", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "采用全费用综合单价法编制施工图预算，下列说法中正确的是（）。", "options": {"A": "计算直接费后应编制工料分析表", "B": "全费用综合单价中应包括增值税", "C": "综合计取的措施项目费以分部分项工程费和可计量的措施项目费之和为基数计算", "D": "编制综合单价分析表时，工料机消耗量与单价均应来预算定额", "E": "分部分项工程量与措施项目费之和即为建筑安装工程施工图预算费用"}, "answer": ["B", "C"], "analysis": "2)综合单价的计算。各子目综合单价的计算可通过预算定额及其配套的费用定额确定。其中人工费、材料费、机具费应根据相应的预算定额子目的人材机要素消耗量，以及报告编制期人材机的市场价格（不含增值税进项税额）等因素确卑；管理费、利润、增值税等应依据预算定额配套的费用定额或取费标准，并依据报告编制期拟建项目的实际情况、市场水平等因素确定，同时编制建筑安装工程预算时应同时编制综合单价分析表", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1418", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "下列内容中，属于建筑安装工程施工图预算编制依据的是()。", "options": {"A": "国家、行业和地方有关规定", "B": "相应工程造价管理机构发布的预算定额", "C": "施工图设计文件及相关标准图集和规范", "D": "工程建设其他费定额", "E": "工程分析表"}, "answer": ["A", "B", "C"], "analysis": "施工图预算的编制依据施工图预算的编制必须遵循以下依据：(1) 国家、行业和地方有关规定；(2) 相应工程造价管理机构发布的预算定额；(3) 施工图设计文件及相关标准图集和规范；(4) 项目相关文件、合同、协议等；(5) 工程所在地的人工、材料、设备、施工机具预算价格；(6) 施工组织设计和施工方案；(7) 项目的管理模式、发包模式及施工条件；(8) 其他应提供的资料。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1419", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "施工图预算是建设程序中一个重要的技术经济文件，下列各项中属于施工图预算对投资方的作用的是( )。", "options": {"A": "调配施工力量、组织材料供应的依据", "B": "控制造价及资金合理使用的依据", "C": "确定合同价款、拨付工程进度款的依据", "D": "建筑工程预算包干的依据", "E": "确定工程招标控制价的依据"}, "answer": ["B", "C", "E"], "analysis": "施工图预算对投资方的作用包括：(1)施工图预算是设计阶段控制工程造价的重要环节，是控制施工图设计不突破设计概算的重要措施；(2)施工图预算是控制造价及资金合理使用的依据；(3)施工图预算是确定工程招标控制价的依据；(4)施工图预算可以作为确定合同价款、拨付工程进度款及办理工程结算的基础。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1420", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "编制施工图预算的过程中，包括在预算单价法中、但不包括在实物法中的工作内容有（）。", "options": {"A": "套用预算定额", "B": "汇总人材机费用", "C": "计算未计价材料费", "D": "计算材料价差", "E": "计算其他费用"}, "answer": ["C", "D"], "analysis": "本题考核预算单价法和实物法编制程序差异。二者前4 步骤和后2 步骤都一致，但中间不同。预算单价法计算工程量后套定额单价、进行工料分析（计算材料价差）、计算主材费（未计价材料费）；而实物法计算工程量后是套定额消耗量，计算汇总人、材、机费用。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1421", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "下列表格中，属于单位设备及安装工程预算书构成内容的有（）。", "options": {"A": "工器具及生产家具购置费计算表", "B": "设备及安装工程预算表", "C": "设备及安装工程取费表", "D": "综合预算表", "E": "总预算表"}, "answer": ["B", "C"], "analysis": "单位设备及安装工程预算书由设备及安装工程预算表和设备及安装工程取费表构成。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1422", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "(2014年)在选择建设地点（厂址）时，应尽量满足下列需求（）", "options": {"A": "节约土地，尽量少占耕地，降低土地补偿费用", "B": "建设地点（厂址）的地下水位应与地下建筑物的基准面持平", "C": "尽量选择人口相对稀疏的地区，减少拆迁移民数量", "D": "尽量选择在工程地质、水文地质较好的地段", "E": "厂区地形求平坦，避免山地"}, "answer": ["A", "C", "D"], "analysis": "本题考查的是建设选址的要求。选择建设地点（厂址）的要求： ①节约土地，尽量少占耕地，降低土地补偿费用；②减少拆迁移民数量；③尽量选择在工程地质，水文地质较好的地段；④要有利于厂区合理布置和安全运行；⑤应尽量靠近交通运输条件和水电供应等条件好的地方；⑥应尽量减少对环境的污染。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1423", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "(2016年)关于投资决策阶段流动资金的估算，下列说法中正确的有()。", "options": {"A": "流动资金周转额的大小与生产规模及周转速度直接相关", "B": "分项详细估算时，需要计算各类流动资产和流动负债的年周转次数", "C": "当年发生的流动资金借款应按半年计息", "D": "流动资金借贷利息应计入建设期贷款利息", "E": "不同生产负荷下的流动资金按100%生产负荷下的流动资金乘以生产负荷百分比计算"}, "answer": ["A", "B"], "analysis": "流动资金的显著特点是在生产过程中不断周转，其周转额的大小与生产规模及周转速度直接相关。 进行流动资金估算时，首先计算各类流动资产和流动负债的年周转次数，然后再分项估算占用资金额。 其借款部分按全年计算利息，流动资金利息应计人生产期间财务费用，项目计算期末收回全部流动资金（不含利息）。 4)在不同生产负荷下的流动资金，应按不同生产负荷所需的各项费用金额，根据上述公式分别估算，而不能直接按照100%生产负荷下的流动资金乘以生产负荷百分比求得。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1424", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "(2015年)关于施工图预算对投资方的作用，下列说法中正确的有( )。", "options": {"A": "是控制施工图设计不突破设计概算的重要措施", "B": "是控制造价及资金合理使用的依据", "C": "是投标报价的基础", "D": "是与施工预算进行“两算”对比的依据", "E": "是调配施工力量、组织材料供应的依据"}, "answer": ["A", "B"], "analysis": "该题主要考察的是：施工图预算对投资方的作用。(1)施工图预算对投资方的作用。1)施工预算图式设计阶段控制工程造价的重要环节，是控制施工图设计不突破设计概算的重要措施。2)施工图预算是控制造价及资金合理使用的依据。3)施工图预算是确定工程招标控制价的依据。“选项CDE均指的是施工图预算对施工企业的作用。”", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1460", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "建筑工程费用是指为建造永久性建筑物和构筑物所需要的费用，一般采用（ ）等进行估算。", "options": {"A": "概算指标投资估算法", "B": "安装工程费估算", "C": "单位建筑工程投资估算法", "D": "单位实物工程量投资估算法", "E": "工程建设其他费用估算"}, "answer": ["A", "C", "D"], "analysis": "建筑工程费用是指为建造永久性建筑物和构筑物所需要的费用，一般采用单位建筑工程投资估算法、单位实物工程量投资估算法、概算指标投资估算法等进行估算 。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1461", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "除建筑安装工程费用、工程建设其他费用以外，在编制建设项目投资估算、设计总概算时，应计算（ ）。", "options": {"A": "工程定额测定费", "B": "预备费", "C": "社会保障费", "D": "建设期利息", "E": "流动资金"}, "answer": ["B", "D", "E"], "analysis": "建设项目投资估算包括建设投资、建设期利息和流动资金的估算。建设投资估算的内容按照费用的性质划分，包括工程费用、工程建设其他费用和预备费用三部分。其中，工程费用包括建筑工程费、设备及工器具购置费、安装工程费；工程建设其他费用包括建设用地费、与建设有关的其他费用、与生产经营有关的费用；预备费用包括基本预备费和价差预备费 。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1462", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "实务操作中，设备安装工程费概算的编制方法应根据初步设计深度和要求所明确的程度而采用，主要编制方法有（ ）。", "options": {"A": "预算单价法", "B": "扩大单价法", "C": "综合单价法", "D": "综合吨位指标法", "E": "设备价值百分比法"}, "answer": ["A", "B", "D", "E"], "analysis": "设备安装工程费概算的编制方法应根据初步设计深度和要求所明确的程度而采用，主要编制方法有：1.预算单价法。2.扩大单价法。3.设备价值百分比法，也称安装设备百分比法。4.综合吨位指标法。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1463", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "设计概算批准后，一般不得调整，但由于（ ）原因引起的设计和投资变化可以调整概算，但要严格按照调整概算的有关程序执行。", "options": {"A": "超出原设计范围的重大变更", "B": "施工图发生重大改变", "C": "工程施工场所调整", "D": "超出工程造价调整预备费", "E": "超出基本预备费规定范围"}, "answer": ["A", "D", "E"], "analysis": "批准后的设计概算一般不得调整。由于以下原因引起的设计和投资变化可以调整概算，但要严格按照调整概算的有关程序执行。 (1)超出原设计范围的重大变更。凡涉及建设规模、产品方案、总平面布置、主要工艺流程、主要设备型号规格、建筑面积、设计定员等方面的修改，必须由原批准立项单位认可，原设计审批单位复审，经复核批准后方可变更。 (2)超出基本预备费规定范围，不可抗拒的重大自然灾害引起的工程变动或费用增加。 (3)超出工程造价调整预备费，属国家重大政策性变动因素引起的调整。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1464", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "加强施工图预算的审查，对于提高预算的准确性，降低工程造价都具有重要的现实意义，其中包括（ ）等。", "options": {"A": "有利于合理确定和有效控制工程造价，克服和防止预算超概算现象发生", "B": "有利于加强固定资产投资管理，合理使用建设资金", "C": "通过审查工程概算，核实了概算价值", "D": "有利于施工承包合同价的合理确定和控制", "E": "有利于积累和分析各项技术经济指标"}, "answer": ["A", "B", "D", "E"], "analysis": "施工图预算审查的意义如下： (1)有利于合理确定和有效控制工程造价，克服和防止预算超概算现象发生。 (2)有利于加强固定资产投资管理，合理使用建设资金 。 (3)有利于施工承包合同价的合理确定和控制。因为施工图预算对于招标工程， 它是编制招标限价、投标报价、签订工程承包合同价、结算合同价款的基础。 (4)有利于积累和分析各项技术经济指标，不断提高设计水平。通过审查工程预算，核实了预算价值，为积累和分析技术经济指标提供了准确数据，进而通过有关指标的比较，找出设计中的薄弱环节，以便及时改进，不断提高设计水平。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1465", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "下列科目中，属于资产负债表中的流动资产的有（ ）。", "options": {"A": "货币资金", "B": "应收账款", "C": "预付账款", "D": "存货", "E": "预收账款"}, "answer": ["A", "B", "C", "D"], "analysis": "本题考查的是流动资金的估算。流动资产＝应收账款＋预付账款＋存货＋库存现金，流动负债＝应付账款＋预收账款。", "tags": [], "source": "第五章  工程决策和设计阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1841", "date": "2026-07-10", "chapter": "g05", "type": "multiple", "stem": "建设项目流动资金的分项估算法中，流动负债的构成要素一般包括（ ）。", "options": {"A": "应收账款", "B": "预付账款", "C": "存货", "D": "应付账款", "E": "预收账款"}, "answer": ["D", "E"], "analysis": "【考点来源】本题考查的是流动资金的估算【选项分析】流动负债的构成要素一般包括应付账款和预收账款。", "tags": [], "source": "三、投资估算的编制方法", "src": "好题库"}, {"id": "mgmt_hqwx_0184", "date": "2026-07-09", "chapter": "g05", "type": "multiple", "stem": "下列工作内容中，属于可行性研究应完成的工作内容的是（ ）。", "options": {"A": "项目提出的必要性和依据", "B": "产品方案、拟建规模和建设地点的初步设想", "C": "项目进度安排", "D": "进行市场研究，以解决项目建设的必要性问题", "E": "进行财务和经济分析，以解决项目建设的经济合理性问题"}, "answer": ["D", "E"], "analysis": "【内容考查】本题考查的是投资决策阶段工作内容 【选项分析】可行性研究应完成以下工作内容: ( 1)进行市场研究，以解决项目建设的必要性问题，(2)进行工艺技术方案的研究，以解决项目建设的技术可行性问题;(3)进行财务和经济分析，以解决项目建设的经济合理性问题。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0252", "date": "2026-07-09", "chapter": "g05", "type": "multiple", "stem": "决策阶段影响工程造价的主要因素包括（ ）。", "options": {"A": "项目建设规模", "B": "技术方案", "C": "设备方案", "D": "外部协作条件", "E": "环境保护措施"}, "answer": ["A", "B", "C", "E"], "analysis": "【内容考查】本题考查的是 工程决策阶段影响造价的主要因素 【选项分析】工程决策阶段影响造价的主要因素有：项目建设规模、建设地区及地点（厂址）、技术方案、设备方案、工程方案和环境保护措施等。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0260", "date": "2026-07-09", "chapter": "g05", "type": "multiple", "stem": "可行性研究的工作内容包括（ ）。", "options": {"A": "市场研究", "B": "工艺技术方案研究", "C": "财务分析", "D": "项目建议书"}, "answer": ["A", "B", "C"], "analysis": "可行性研究应完成以下工作内容：①进行市场研究，以解决项目建设的必要性问题；②进行工艺技术方案的研究，以解决项目建设的技术可行性问题；③进行财务和经济分析，以解决项目建设的经济合理性问题。可行性研究工作完成后，需要编写反映其全部工作成果的“可行性研究报告”。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0272", "date": "2026-07-09", "chapter": "g05", "type": "multiple", "stem": "投资机会研究和初步可行性研究阶段，建设投资估算编制方法有（ ）。【陕西】", "options": {"A": "生产能力指数法", "B": "比例估算法", "C": "系数估算法", "D": "指标估算法", "E": "单位生产能力估算法"}, "answer": ["A", "B", "C", "D"], "analysis": "投资机会研究和项目建议书阶段的投资估算精度要求较低，可采取简单的匡算法，如单位生产能力法、生产能力指数法、系数估算法、比例估算法、指标估算法等。可行性研究阶段的投资估算精度要求就要比前阶段高些，需采用相对详细的估算方法， 如指标(定额)估算法等。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0283", "date": "2026-07-09", "chapter": "g05", "type": "multiple", "stem": "某单位建筑工程的初步设计采用的技术比较成熟，但由于设计深度不够，不能准确计算出工程量,若急需该单位建筑工程概算时，可采用的概算编制方法有（ ）。", "options": {"A": "预算单价法", "B": "概算定额法", "C": "概算指标法", "D": "类似工程预算法", "E": "扩大单价法"}, "answer": ["C", "D"], "analysis": "【内容考查】本题考查的是单位工程概算的编制方法 【选项分析】在方案设计中，由于设计无详图而只有概念性设计时，或初步设计深度不够，不能准确地计算出工程量，但工程设计采用的技术比较成熟时可以选定与该工程相似类型的概算指标编制概算。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0287", "date": "2026-07-09", "chapter": "g05", "type": "multiple", "stem": "设计概算的主要作用有（ ）。", "options": {"A": "是确定和控制建设投资的依据", "B": "是签订建设工程承发包合同的依据", "C": "是考核建设项目投资效果的依据", "D": "是工程竣工结算的依据", "E": "是控制施工图预算和施工图设计的依据"}, "answer": ["A", "B", "C", "E"], "analysis": "【内容考查】本题考查的是设计概算的作用 【选项分项】设计概算的作用：设计概算是编制固定资产投资计划，确定和控制建设项目投资的依据；设计概算是控制施工图设计和施工图预算的依据；设计概算是衡量设计方案技术经济合理性和选择最佳设计方案的依据；设计概算是编制招标限价（招标标底）和投标报价的依据；设计概算是签订建设工程施工合同和贷款合同的依据；设计概算是考核建设项目投资效果的依据。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0288", "date": "2026-07-09", "chapter": "g05", "type": "multiple", "stem": "设计概算的审查内容包括（ ）。", "options": {"A": "编制依据", "B": "编制方法", "C": "编制内容", "D": "编制深度", "E": "编制程序"}, "answer": ["A", "C", "D"], "analysis": "设计概算的审查内容：1． 审查设计概算的编制依据2． 审查概算编制深度3． 审查概算编制内容。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0294", "date": "2026-07-09", "chapter": "g05", "type": "multiple", "stem": "设计概算是控制（ ）的依据。", "options": {"A": "施工图设计", "B": "方案投资估算", "C": "可行性研究估算", "D": "施工图预算"}, "answer": ["A", "D"], "analysis": "设计概算是控制施工图设计和施工图预算的依据。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0297", "date": "2026-07-09", "chapter": "g05", "type": "multiple", "stem": "施工图预算对投资方、施工企业都具有十分重要的作用。下列选项中仅属于施工企业作用的有（ ）。", "options": {"A": "确定合同价款的依据", "B": "控制资金合理使用的依据", "C": "控制工程施工成本的依据", "D": "调配施工力量的依据", "E": "办理工程结算的依据"}, "answer": ["C", "D"], "analysis": "【内容考查】本题考查的是施工图预算的作用 【选项分析】施工图预算对施工企业的作用：1）施工图预算是建筑施工企业投标报价的基础。2）施工图预算是建筑工程预算包干的依据和签订施工合同的主要内容。3）施工图预算是施工企业安排调配施工力量、组织材料供应的依据。4）施工图预算是施工企业控制工程成本的依据。5）施工图预算是进行“两算”对比的依据。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0298", "date": "2026-07-09", "chapter": "g05", "type": "multiple", "stem": "施工图预算审查的重点包括（ ）。", "options": {"A": "审查工程量计算是否准确", "B": "审查相关的技术规范是否有错误", "C": "审查施工图设计方案是否合理", "D": "审查施工图预算编制中定额套用是否恰当", "E": "审查有关费用项目及其取值"}, "answer": ["A", "D", "E"], "analysis": "施工图预算审查的内容包括：1.工程量的审查2.审查设备、材料的预算价格3.审查预算单价的套用4.审查有关费用项目及其取值。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0305", "date": "2026-07-09", "chapter": "g05", "type": "multiple", "stem": "单位工程施工图预算一般包括（ ）。", "options": {"A": "建筑工程预算", "B": "流动资金预算", "C": "建设用地费预算", "D": "设备安装工程预算", "E": "工程建设其他费预算"}, "answer": ["A", "D"], "analysis": "单位工程预算包括建筑工程预算和设备安装工程预算。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0306", "date": "2026-07-09", "chapter": "g05", "type": "multiple", "stem": "用筛选法审查施工图预算时，一般选用的筛选标准是( )等单方基本值。", "options": {"A": "用工", "B": "材料用量", "C": "机械台班用量", "D": "工程量", "E": "造价"}, "answer": ["A", "D", "E"], "analysis": "【内容考查】本题考查的是施工图预算审査方法 【选项分项】建筑工程虽然有建筑面积和高度的不同，但是它们的各个分部分项工程的工程量、造价、用工量在每个单位面积上的数值变化不大，把已建工程的这些数据加以分析汇集，归纳为工程量、造价（价值）、用工三个单位面积基本数值分析表，并注明其适用的建筑标准。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "gl-g06-001", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "根据现行规定，施工单项合同估算价在（ ）万元人民币以上的必须进行招标。", "options": {"A": "200", "B": "300", "C": "400", "D": "500"}, "answer": ["C"], "analysis": "必须招标的规模标准：施工单项合同估算价≥400万元，重要设备材料采购≥200万元，勘察设计监理服务≥100万元。", "tags": ["招标方式", "必须招标规模"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-002", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "重要设备、材料等货物的采购，单项合同估算价在（ ）万元人民币以上的必须进行招标。", "options": {"A": "100", "B": "200", "C": "300", "D": "400"}, "answer": ["B"], "analysis": "重要设备、材料等货物采购单项合同估算价≥200万元必须招标。施工≥400万，勘察设计监理≥100万。", "tags": ["招标方式", "必须招标规模"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-003", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "勘察、设计、监理等服务的采购，单项合同估算价在（ ）万元人民币以上的必须进行招标。", "options": {"A": "50", "B": "100", "C": "150", "D": "200"}, "answer": ["B"], "analysis": "勘察、设计、监理等服务采购单项合同估算价≥100万元必须招标。施工≥400万，设备材料≥200万。", "tags": ["招标方式", "必须招标规模"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-005", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "清标是指（ ）。", "options": {"A": "对中标人的业绩进行审查", "B": "对投标文件进行基础性分析和清理", "C": "对招标文件的澄清和修改", "D": "清理施工现场的工作"}, "answer": ["B"], "analysis": "清标是指在评标委员会评标之前，招标人或招标代理机构对投标文件进行基础性分析、清理和整理工作，为评标提供基础资料。", "tags": ["招标程序", "清标"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-008", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "固定总价合同中，价格风险主要由（ ）承担。", "options": {"A": "发包方", "B": "承包方", "C": "双方平均分担", "D": "监理方"}, "answer": ["B"], "analysis": "固定总价合同中，除发包方增减工程量和设计变更外，合同总价固定不变，承包方承担合同履行过程中的主要价格风险。", "tags": ["合同类型", "固定总价合同"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-009", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "可调总价合同与固定总价合同相比，可调总价合同中发包方需要承担（ ）。", "options": {"A": "全部价格风险", "B": "通货膨胀等部分价格风险", "C": "不承担任何价格风险", "D": "工程量变化风险"}, "answer": ["B"], "analysis": "可调总价合同中，当出现通货膨胀等特定风险因素导致工料成本增加时，合同总价可按约定调整，发包方需承担这部分价格风险。", "tags": ["合同类型", "可调总价合同"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-010", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "成本加酬金合同中，成本风险主要由（ ）承担。", "options": {"A": "承包方", "B": "发包方", "C": "双方按比例分担", "D": "监理方"}, "answer": ["B"], "analysis": "成本加酬金合同中，承包方按实际成本获得补偿并收取酬金，发包方承担全部成本风险。这种合同适用于紧急工程或新型工程。", "tags": ["合同类型", "成本加酬金合同"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-011", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "固定单价合同中，工程量按（ ）结算。", "options": {"A": "招标文件工程量", "B": "投标报价工程量", "C": "实际完成工程量", "D": "概算工程量"}, "answer": ["C"], "analysis": "固定单价合同的特点是单价固定不变，工程量按实际完成工程量据实结算，这是单价合同的本质特征。", "tags": ["合同类型", "固定单价合同"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-012", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "根据GB/T 50500-2024，分部分项工程量清单的项目编码共有（ ）位。", "options": {"A": "9", "B": "10", "C": "12", "D": "15"}, "answer": ["C"], "analysis": "根据GB/T 50500-2024《建设工程工程量清单计价规范》，分部分项工程量清单项目编码为12位阿拉伯数字，前9位为统一编码，后3位为清单项目名称顺序码。", "tags": ["工程量清单", "编码"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-015", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "关于最高投标限价，下列说法正确的是（ ）。", "options": {"A": "所有工程都必须编制最高投标限价", "B": "国有资金投资的工程建设项目必须编制", "C": "最高投标限价可以适当上浮", "D": "最高投标限价根据投标报价确定"}, "answer": ["B"], "analysis": "国有资金投资的建设工程招标，招标人必须编制最高投标限价（招标控制价）。最高投标限价不得上浮或下调，依据GB/T50500-2024、定额、信息价等编制。", "tags": ["最高投标限价"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-016", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "投标报价不得低于（ ）。", "options": {"A": "最高投标限价", "B": "企业个别成本", "C": "社会平均成本", "D": "预算定额水平"}, "answer": ["B"], "analysis": "投标报价由投标人自主确定，但不得低于企业个别成本（即企业自身的成本水平）。低于成本的报价属于不正当竞争。", "tags": ["投标报价"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-017", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "投标人采用不平衡报价法时，通常的做法是（ ）。", "options": {"A": "将前期施工项目的单价报低，后期项目报高", "B": "将前期施工项目的单价报高，后期项目报低", "C": "所有项目报价保持一致", "D": "将利润均摊到每个项目"}, "answer": ["B"], "analysis": "不平衡报价法的策略是将早期施工项目（如土方、基础）单价报高，后期项目单价报低，以便尽早回收资金，减少资金占用。", "tags": ["投标报价", "不平衡报价法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-018", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "突然降价法属于（ ）。", "options": {"A": "招标策略", "B": "评标方法", "C": "投标报价策略", "D": "合同类型"}, "answer": ["C"], "analysis": "突然降价法是在投标截止前突然降低报价以迷惑竞争对手的投标报价策略，属于投标报价策略之一。其他策略还包括不平衡报价法、多方案报价法等。", "tags": ["投标报价", "突然降价法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-019", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "EPC总承包模式的含义是（ ）。", "options": {"A": "设计-施工总承包", "B": "采购-施工总承包", "C": "设计-采购-施工一体化总承包", "D": "项目管理总承包"}, "answer": ["C"], "analysis": "EPC（Engineering-Procurement-Construction）即设计-采购-施工一体化总承包模式，由总承包商对工程的设计、采购、施工全过程负责。", "tags": ["合同类型", "EPC"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-021", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "投标人对招标文件中的工程量清单进行复核时，若发现工程量有误，正确的做法是（ ）。", "options": {"A": "自行修改工程量清单", "B": "按招标文件要求进行报价", "C": "以书面形式向招标人提出疑问", "D": "忽略工程量差异"}, "answer": ["C"], "analysis": "投标人发现工程量清单有误时，应通过书面形式向招标人提出澄清要求（质疑），不能自行修改工程量清单。招标人确认后以书面形式回复。", "tags": ["投标报价", "工程量复核"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-022", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "最高投标限价的编制依据不包括（ ）。", "options": {"A": "GB/T 50500-2024", "B": "国家或省级建设主管部门颁发的计价定额", "C": "投标人的企业定额", "D": "工程造价管理机构发布的信息价"}, "answer": ["C"], "analysis": "最高投标限价依据GB/T50500-2024、计价定额、信息价、设计文件等编制，不依据投标人的企业定额。企业定额是投标人自主报价的依据。", "tags": ["最高投标限价", "编制依据"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-023", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "关于暂列金额，下列说法正确的是（ ）。", "options": {"A": "由投标人自主确定金额", "B": "用于必然发生但暂时不能确定价格的项目", "C": "由招标人在工程量清单中暂定并包括在合同价款中", "D": "结算时不予调整"}, "answer": ["C"], "analysis": "暂列金额是招标人在工程量清单中暂定并包含在合同价款中的一笔款项，用于施工中可能发生的工程变更、合同约定调整因素出现时的工程价款调整。暂估价用于必然发生但暂时不能确定价格的项目。", "tags": ["工程量清单", "暂列金额"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-024", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "自行招标的条件是招标人具有编制招标文件和（ ）。", "options": {"A": "一定数量的注册造价工程师", "B": "组织评标的能力", "C": "与项目规模相匹配的注册资本", "D": "足够的施工资质"}, "answer": ["B"], "analysis": "招标人自行办理招标的，应具有编制招标文件和组织评标的能力。如不具备，应委托招标代理机构办理。", "tags": ["招标方式", "自行招标"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-025", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "多方案报价法的适用情况是（ ）。", "options": {"A": "招标文件中合同条款明确且无争议", "B": "招标文件中工程范围不明确或条款苛刻", "C": "投标人拥有独家技术优势", "D": "工程量清单准确无误"}, "answer": ["B"], "analysis": "多方案报价法适用于招标文件中工程范围不明确、条款不清楚或不公正、技术规范要求过于苛刻的情况，投标人可提出多个报价方案供招标人选择。", "tags": ["投标报价", "多方案报价法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-026", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "邀请招标的特点不包括（ ）。", "options": {"A": "无需发布招标公告", "B": "邀请对象一般不少于3家", "C": "适用于技术复杂或有特殊要求的项目", "D": "竞争范围比公开招标更广"}, "answer": ["D"], "analysis": "邀请招标以投标邀请书方式邀请特定法人或组织投标，邀请对象不少于3家，适用于技术复杂或有特殊要求的项目。其竞争范围比公开招标窄，不是更广。", "tags": ["招标方式", "邀请招标"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-028", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "根据现行工程量清单计价规范，安全文明施工费属于（ ）。", "options": {"A": "分部分项工程费", "B": "措施项目费", "C": "其他项目费", "D": "规费"}, "answer": ["B"], "analysis": "安全文明施工费属于措施项目费中的安全施工费、文明施工费、环境保护费和临时设施费，是不可竞争费用。", "tags": ["工程量清单", "措施项目费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-029", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "投标人在进行询价时，主要询价对象不包括（ ）。", "options": {"A": "材料设备供应商", "B": "分包商", "C": "招标人的银行账户", "D": "劳务市场"}, "answer": ["C"], "analysis": "投标人询价对象包括材料设备供应商、分包商、劳务市场等，以获取准确的市场价格信息。招标人的银行账户不属于询价范围。", "tags": ["投标报价", "询价"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-030", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "EPC总承包模式中，总承包单位对工程的质量、安全、工期和造价（ ）。", "options": {"A": "仅对施工阶段负责", "B": "仅对设计和采购阶段负责", "C": "全面负责", "D": "仅对采购阶段负责"}, "answer": ["C"], "analysis": "EPC模式下总承包单位对工程的设计、采购、施工全过程负责，对工程质量、安全、工期和造价全面负责。", "tags": ["合同类型", "EPC"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-032", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "计日工适用于（ ）。", "options": {"A": "工程量清单中的主要工程项目", "B": "合同约定范围内的常规工作", "C": "合同约定范围以外的零星工作或临时工作", "D": "措施项目的计价"}, "answer": ["C"], "analysis": "计日工适用于完成合同约定范围以外、工程量清单中没有相应项目的零星工作或临时工作，按合同约定的计日工单价计价。", "tags": ["工程量清单", "计日工"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-034", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "总承包服务费是指（ ）。", "options": {"A": "总承包单位自行施工的费用", "B": "总承包单位配合协调发包人专业工程发包和材料设备供应的费用", "C": "总承包单位的管理人员工资", "D": "总承包单位的利润"}, "answer": ["B"], "analysis": "总承包服务费是总承包人为配合协调发包人进行的专业工程分包、自行采购材料设备等进行现场管理、服务所需的费用。", "tags": ["工程量清单", "总承包服务费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-035", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "关于固定总价合同，下列说法错误的是（ ）。", "options": {"A": "合同总价在约定风险范围内不变", "B": "承包方承担价格风险", "C": "适用于工程量小、工期短的工程", "D": "工程量按实际完成量据实结算"}, "answer": ["D"], "analysis": "固定总价合同按合同总价结算，而非据实结算。工程量据实结算是固定单价合同的特征。", "tags": ["合同类型", "固定总价合同"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-037", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "根据现行规定，施工招标中招标人不得（ ）。", "options": {"A": "编制最高投标限价", "B": "设定最低投标限价", "C": "设定暂列金额", "D": "采用工程量清单招标"}, "answer": ["B"], "analysis": "招标人不得规定最低投标限价。最高投标限价（招标控制价）在国有资金投资项目中必须编制。禁止低于成本报价是投标人的义务，而非招标人设定最低限价。", "tags": ["最高投标限价"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-039", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "在进行不平衡报价时，对于预计工程量将来可能减少的分项工程，投标人应（ ）。", "options": {"A": "提高单价", "B": "降低单价", "C": "维持正常单价", "D": "按最高投标限价填报"}, "answer": ["B"], "analysis": "不平衡报价法中，对预计工程量减少的项目应报低单价，因为实际结算时工程量减少会少结算，报低价可减少损失；对预计工程量增加的项目应报高单价。", "tags": ["投标报价", "不平衡报价法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-040", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "措施项目中的总价措施项目与实体工程的关联关系是（ ）。", "options": {"A": "与实体工程有直接对应关系", "B": "与实体工程没有直接对应关系", "C": "仅与主体结构工程对应", "D": "仅与装饰装修工程对应"}, "answer": ["B"], "analysis": "措施项目中能计算工程量的为单价措施项目，与实体工程有对应关系；以\"项\"计价的为总价措施项目，与实体工程没有直接对应关系，服务于整个工程。", "tags": ["工程量清单", "措施项目"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-042", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "施工招标中，中标人的投标报价应符合的条件是（ ）。", "options": {"A": "不高于最高投标限价", "B": "不低于最低投标限价", "C": "等于所有投标报价平均值", "D": "与标底完全一致"}, "answer": ["A"], "analysis": "中标人投标报价应不高于最高投标限价（招标控制价），否则应作废标处理。不得设定最低投标限价，投标报价不低于企业个别成本即可。", "tags": ["投标报价"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-043", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "招标人在发布招标公告前，工程应具备的条件不包括（ ）。", "options": {"A": "已履行项目审批手续", "B": "招标方式已核准", "C": "相应资金已落实", "D": "施工许可证已取得"}, "answer": ["D"], "analysis": "招标前应具备：已履行审批手续、招标方式已核准、资金已落实等。施工许可证是在确定中标人、签订施工合同后办理的，不是招标前必须具备的条件。", "tags": ["招标程序"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-045", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "最高投标限价编制中，综合单价中应包含的风险费用一般不超过（ ）。", "options": {"A": "不计入", "B": "人工费的一定比例", "C": "材料费的2%-5%", "D": "分部分项工程费的3%-5%"}, "answer": ["D"], "analysis": "编制最高投标限价时，综合单价中应考虑一定范围内的风险因素，一般不超过分部分项工程费的3%-5%，具体比例根据工程特点和发承包双方约定确定。", "tags": ["最高投标限价", "风险费用"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-046", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "工程量清单编制的现行国家标准是（ ）。", "options": {"A": "GB 50500-2013", "B": "GB/T 50500-2024", "C": "GB 50500-2020", "D": "GB/T 50500-2018"}, "answer": ["B"], "analysis": "现行工程量清单计价规范为GB/T 50500-2024《建设工程工程量清单计价规范》，是2025年二造考试需要关注的新标准。", "tags": ["工程量清单", "GB/T 50500-2024"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-047", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "采用突然降价法时，投标人应在（ ）提交降价文件。", "options": {"A": "开标后", "B": "投标截止时间前", "C": "评标过程中", "D": "中标通知书发出后"}, "answer": ["B"], "analysis": "突然降价法必须在投标截止时间前提交最终报价（降价文件），超过投标截止时间的报价无效。因此投标人需精心安排降价函的送交时间。", "tags": ["投标报价", "突然降价法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-049", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "投标报价中，管理费和利润的计算基础是（ ）。", "options": {"A": "分部分项工程量清单", "B": "人工费+材料费+施工机具使用费", "C": "直接费", "D": "合同总价"}, "answer": ["B"], "analysis": "在工程量清单计价中，综合单价=人工费+材料费+施工机具使用费+管理费+利润（+风险）。管理费和利润的计算基础是人工费加材料费加施工机具使用费。", "tags": ["投标报价", "综合单价"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-050", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "关于招标代理机构，下列说法正确的是（ ）。", "options": {"A": "只能由国家机关设立", "B": "与行政机关不得存在隶属关系", "C": "必须是事业单位", "D": "无需具备专业力量"}, "answer": ["B"], "analysis": "招标代理机构是依法设立的社会中介组织，与行政机关不得存在隶属关系或其他利益关系，应具备编制招标文件和组织评标的专业力量。", "tags": ["招标方式", "委托代理"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-052", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "措施项目清单中的安全文明施工费，投标人应（ ）。", "options": {"A": "自主确定费率", "B": "按照招标人规定的金额填报", "C": "可以优惠报价", "D": "按国家和省级主管部门规定的标准计取"}, "answer": ["D"], "analysis": "安全文明施工费是不可竞争费用，投标人必须按照国家或省级建设主管部门规定的标准计取，不得作为竞争性费用自主报价或优惠。", "tags": ["投标报价", "不可竞争费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-001", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "关于招标方式，下列说法正确的是？", "options": {"A": "国有资金占控股或主导地位的项目一律应当公开招标", "B": "公开招标的缺点是招标时间短、费用低", "C": "邀请招标适用于技术复杂、有特殊要求或受自然环境限制，只有少量潜在投标人可供选择的情形", "D": "邀请招标不需要向投标人发出投标邀请书"}, "answer": ["C"], "analysis": "邀请招标适用于三种情形：①技术复杂、有特殊要求或受自然环境限制，只有少量潜在投标人可供选择；②采用公开招标方式的费用占项目合同金额的比例过大；③涉及国家安全、国家秘密。A选项：国有资金占控股或主导地位的依法必须进行招标的项目，应当公开招标，但有下列情形之一的可以邀请招标。B选项：公开招标的缺点是招标时间长、费用高。D选项：邀请招标应当向三个以上具备能力的特定法人或组织发出投标邀请书。", "tags": ["招标方式", "邀请招标"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-002", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "下列哪项不属于邀请招标的适用情形？", "options": {"A": "技术复杂、有特殊要求，只有少量潜在投标人可供选择", "B": "涉及国家安全、国家秘密，不宜公开招标", "C": "采用公开招标方式的费用占项目合同金额的比例过小", "D": "受自然环境限制，只有少量潜在投标人可供选择"}, "answer": ["C"], "analysis": "邀请招标的适用情形中包括【采用公开招标方式的费用占项目合同金额的比例过大】，而非【过小】。费用占比过小说明公开招标的成本不高，更适合公开招标。", "tags": ["招标方式", "邀请招标"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-004", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "招标人自行办理招标事宜，应当具有的能力是？", "options": {"A": "具有编制工程量清单和确定标底的能力", "B": "具有编制招标文件和组织评标的能力", "C": "具有组织资格预审和发布公告的能力", "D": "具有组织投标人踏勘现场和答疑的能力"}, "answer": ["B"], "analysis": "招标人具有编制招标文件和组织评标能力的，可以自行办理招标事宜。任何单位和个人不得强制其委托招标代理机构办理招标事宜。依法必须进行招标的项目，招标人自行办理招标事宜的，应当向有关行政监督部门备案。", "tags": ["招标方式", "自行招标"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-005", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "关于公开招标与邀请招标的比较，下列说法错误的是？", "options": {"A": "公开招标竞争性强，有利于降低造价", "B": "邀请招标适用于不宜公开招标的特殊项目", "C": "公开招标的投标人数量不受限制", "D": "公开招标比邀请招标的时间更短"}, "answer": ["D"], "analysis": "公开招标需要发布招标公告、资格预审等程序，招标时间通常比邀请招标更长，而非更短。公开招标的优点在于竞争更充分，缺点是程序复杂、时间长、费用高。", "tags": ["招标方式", "公开招标", "邀请招标"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-006", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "根据《必须招标的工程项目规定》，施工单项合同估算价在多少万元以上的，必须进行招标？", "options": {"A": "100万元", "B": "200万元", "C": "400万元", "D": "500万元"}, "answer": ["C"], "analysis": "施工单项合同估算价在400万元人民币以上的，必须进行招标。这是《必须招标的工程项目规定》明确的规模标准。", "tags": ["必须招标", "规模标准"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-007", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "根据《必须招标的工程项目规定》，重要设备、材料等货物的采购，单项合同估算价在多少万元以上的，必须进行招标？", "options": {"A": "100万元", "B": "200万元", "C": "300万元", "D": "400万元"}, "answer": ["B"], "analysis": "重要设备、材料等货物的采购，单项合同估算价在200万元人民币以上，必须进行招标。", "tags": ["必须招标", "规模标准"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-008", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "根据《必须招标的工程项目规定》，勘察、设计、监理等服务的采购，单项合同估算价在多少万元以上的，必须进行招标？", "options": {"A": "50万元", "B": "100万元", "C": "200万元", "D": "400万元"}, "answer": ["B"], "analysis": "勘察、设计、监理等服务的采购，单项合同估算价在100万元人民币以上，必须进行招标。", "tags": ["必须招标", "规模标准"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-009", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "某项目中，施工合同估算价350万元，设备采购合同估算价150万元，勘察合同估算价80万元。关于是否必须招标，下列说法正确的是？", "options": {"A": "施工合同因未达400万，不必招标", "B": "设备采购因未达200万，不必招标", "C": "上述合同均未达到规模标准，均不必招标", "D": "施工和设备采购为同一项目中可以合并采购的，合并后合同估算价达到500万元，必须招标"}, "answer": ["D"], "analysis": "同一项目中可以合并进行的勘察、设计、施工、监理以及与工程建设有关的重要设备、材料等的采购，合同估算价合计达到规定标准的（即合并后达到施工400万或货物200万或服务100万），必须招标。施工350万+设备150万=500万，超过400万标准。", "tags": ["必须招标", "规模标准", "合并采购"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-011", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "某国有资金投资项目的施工合同估算价为380万元，设备采购估算价250万元，监理服务估算价90万元。下列必须招标的是？", "options": {"A": "仅施工合同", "B": "仅设备采购", "C": "设备采购和监理服务", "D": "施工合同和设备采购"}, "answer": ["B"], "analysis": "施工380万<400万，未达标准；设备250万≥200万，必须招标；监理90万<100万，未达标准。各合同独立判断，不合并。本题中仅设备采购须招标。", "tags": ["必须招标", "规模标准"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-012", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "关于必须招标的规模标准，下列说法正确的是？", "options": {"A": "勘察合同估算价150万元不必招标", "B": "施工合同估算价500万元必须招标", "C": "设备采购合同估算价180万元必须招标", "D": "设计合同估算价80万元必须招标"}, "answer": ["B"], "analysis": "施工合同500万≥400万标准，必须招标，B正确。勘察150万≥100万应当招标，A错误。设备采购180万<200万标准不必招标，C错误。设计80万<100万标准不必招标，D错误。", "tags": ["必须招标", "规模标准"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-013", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "招标人采用资格预审办法对潜在投标人进行资格审查的，资格预审文件发售期不得少于几日？", "options": {"A": "3日", "B": "5日", "C": "7日", "D": "10日"}, "answer": ["B"], "analysis": "资格预审文件或者招标文件的发售期不得少于5日。", "tags": ["招标程序", "资格预审"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-014", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "从招标文件开始发出之日起至投标人提交投标文件截止之日止，最短不得少于多少日？", "options": {"A": "10日", "B": "15日", "C": "20日", "D": "30日"}, "answer": ["C"], "analysis": "依法必须进行招标的项目，自招标文件开始发出之日起至投标人提交投标文件截止之日止，最短不得少于20日。", "tags": ["招标程序", "时间节点"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-015", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "招标人对已发出的招标文件进行必要的澄清或修改的，应当在招标文件要求提交投标文件截止时间至少多少日前，以书面形式通知所有获取招标文件的潜在投标人？", "options": {"A": "5日", "B": "10日", "C": "15日", "D": "20日"}, "answer": ["C"], "analysis": "招标人对已发出的招标文件进行必要的澄清或者修改的，应当在招标文件要求提交投标文件截止时间至少15日前，以书面形式通知所有获取招标文件的潜在投标人。不足15日的，应当顺延投标截止时间。", "tags": ["招标程序", "澄清修改"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-016", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "投标保证金不得超过招标项目估算价的多少？并且最高不得超过多少万元？", "options": {"A": "1%，60万元", "B": "2%，80万元", "C": "3%，100万元", "D": "5%，80万元"}, "answer": ["B"], "analysis": "投标保证金不得超过招标项目估算价的2%，且勘察、设计、施工、监理投标保证金最高不得超过80万元。这是两个限制条件，取较小值。", "tags": ["招标程序", "投标保证金"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-017", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "某施工招标项目估算价为3000万元，根据规定投标保证金最高不得超过多少万元？", "options": {"A": "60万元", "B": "80万元", "C": "100万元", "D": "120万元"}, "answer": ["A"], "analysis": "投标保证金不得超过招标项目估算价的2%，即3000×2%=60万元。同时最高不得超过80万元。取两者中的较小值60万元。", "tags": ["招标程序", "投标保证金"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-019", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "投标保证金的退还，下列说法正确的是？", "options": {"A": "招标人最迟应当在书面合同签订后5日内向中标人和未中标的投标人退还投标保证金及银行同期存款利息", "B": "招标人应当在书面合同签订后3日内向所有投标人退还投标保证金", "C": "招标人仅需向未中标的投标人退还投标保证金", "D": "投标保证金只需退还本金，无需支付利息"}, "answer": ["A"], "analysis": "招标人最迟应当在书面合同签订后5日内向中标人和未中标的投标人退还投标保证金及银行同期存款利息。中标人也应退还保证金。D错误，需要退还银行同期存款利息。", "tags": ["招标程序", "投标保证金"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-021", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "关于开标，下列说法正确的是？", "options": {"A": "开标可以在投标截止时间之后的合理时间内进行", "B": "开标由行政监督部门主持", "C": "开标应当在招标文件确定的提交投标文件截止时间的同一时间公开进行", "D": "投标人无需参加开标，不得检查投标文件的密封情况"}, "answer": ["C"], "analysis": "开标应当在招标文件确定的提交投标文件截止时间的同一时间公开进行。A错误，必须在同一时间。B错误，开标由招标人主持。D错误，投标人或其代表有权检查投标文件的密封情况。", "tags": ["开标"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-022", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "开标时，由谁检查投标文件的密封情况？", "options": {"A": "招标人", "B": "评标委员会", "C": "行政监督部门", "D": "投标人或者其推选的代表"}, "answer": ["D"], "analysis": "开标时，由投标人或者其推选的代表检查投标文件的密封情况，也可以由招标人委托的公证机构检查并公证。经确认无误后，由工作人员当众拆封。", "tags": ["开标"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-023", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "评标委员会可以要求投标人对投标文件中含义不明确的内容作必要的澄清或者说明，但澄清或者说明不得？", "options": {"A": "涉及投标报价", "B": "超出投标文件的范围或者改变投标文件的实质性内容", "C": "以书面形式进行", "D": "由投标人法定代表人或其授权代表签字"}, "answer": ["B"], "analysis": "评标委员会可以要求投标人对投标文件中含义不明确的内容作必要的澄清或者说明，但是澄清或者说明不得超出投标文件的范围或者改变投标文件的实质性内容。", "tags": ["评标", "澄清"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-024", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "下列哪项属于评标委员会否决投标的情形？", "options": {"A": "投标报价大写金额与小写金额不一致", "B": "投标文件中总价金额与单价金额计算结果不一致", "C": "投标文件未经投标单位盖章和单位负责人签字", "D": "投标文件中有个别页码序数错误"}, "answer": ["C"], "analysis": "投标文件未经投标单位盖章和单位负责人签字属于实质性不响应，应当否决投标。A、B、D属于细微偏差，可以进行澄清修正，不应直接否决。", "tags": ["评标", "否决投标"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-025", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "依法必须进行招标的项目，提交投标文件的投标人少于多少个的，招标人应当重新招标？", "options": {"A": "2个", "B": "3个", "C": "5个", "D": "7个"}, "answer": ["B"], "analysis": "投标人少于3个的，招标人应当依法重新招标。重新招标后投标人仍少于3个的，属于必须审批、核准的工程建设项目，报经原审批、核准部门批准后可以不再进行招标。", "tags": ["重新招标"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-027", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "评标委员会由招标人依法组建，成员人数为几人以上单数？", "options": {"A": "3人", "B": "5人", "C": "7人", "D": "9人"}, "answer": ["B"], "analysis": "评标委员会由招标人依法组建，成员人数为5人以上单数，其中技术、经济等方面的专家不得少于成员总数的2/3。", "tags": ["评标", "评标委员会"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-029", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "招标人和中标人应当自中标通知书发出之日起多少日内，按照招标文件和中标人的投标文件订立书面合同？", "options": {"A": "15日", "B": "20日", "C": "28日", "D": "30日"}, "answer": ["D"], "analysis": "招标人和中标人应当自中标通知书发出之日起30日内，按照招标文件和中标人的投标文件订立书面合同。合同的标的、价款、质量、履行期限等主要条款应当与招标文件和中标人的投标文件的内容一致。", "tags": ["合同签订"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-030", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "招标人与中标人签订合同后多少日内，应当向有关行政监督部门提交招标投标情况的书面报告？", "options": {"A": "5日", "B": "10日", "C": "15日", "D": "30日"}, "answer": ["C"], "analysis": "依法必须进行招标的项目，招标人应当自确定中标人之日起15日内，向有关行政监督部门提交招标投标情况的书面报告。", "tags": ["招标程序", "书面报告"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-031", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "关于固定总价合同，下列说法正确的是？", "options": {"A": "发包方承担价格风险为主", "B": "适用于工期长、技术复杂的项目", "C": "承包方承担价格风险为主，适用于工期短、技术简单的项目", "D": "工程量据实结算"}, "answer": ["C"], "analysis": "固定总价合同中承包方承担价格风险为主。在固定总价范围内，无论实际成本和工程量如何变化，合同总价不变。适用于工期短（一般不超过1年）、技术简单、设计详细明确的项目。", "tags": ["合同类型", "总价合同"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-032", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "可调总价合同与固定总价合同的主要区别在于？", "options": {"A": "可调总价合同适用于工期短的项目", "B": "可调总价合同中发包方承担一部分价格风险", "C": "可调总价合同中工程量按实结算", "D": "可调总价合同不适用于工期长的项目"}, "answer": ["B"], "analysis": "可调总价合同适用于工期较长（如一年以上）的项目，发包方承担了一部分价格风险（如通货膨胀、材料价格上涨等），合同条款约定在特定条件下合同总价可以调整。固定总价合同中承包方承担全部价格风险。", "tags": ["合同类型", "可调总价合同"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-034", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "单价合同适用于下列哪种情况？", "options": {"A": "施工图设计详细完整，工程量明确的项目", "B": "工程量不确定或预计有较大变化的项目", "C": "工期短、技术简单的项目", "D": "紧急抢险项目"}, "answer": ["B"], "analysis": "单价合同适用于工程量不确定或预计在施工中会有较大变化的项目。在单价合同中，工程量按实际完成量结算，单价固定不变。A适合总价合同，D适合成本加酬金合同。", "tags": ["合同类型", "单价合同"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-035", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "关于成本加酬金合同，下列说法正确的是？", "options": {"A": "承包方承担全部成本风险", "B": "发包方承担全部成本风险", "C": "双方平摊成本风险", "D": "成本风险由第三方机构承担"}, "answer": ["B"], "analysis": "成本加酬金合同中，发包方承担全部成本风险。工程的实际成本全部由发包方承担，承包方只获得约定的酬金。这种合同适用于紧急抢险项目、新型项目或风险大的项目。", "tags": ["合同类型", "成本加酬金合同"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-037", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "成本加酬金合同中，发包方对承包方的激励最大、承包方降低成本积极性最高的形式是？", "options": {"A": "成本加固定酬金", "B": "成本加百分比酬金", "C": "成本加浮动酬金", "D": "成本加固定费率酬金"}, "answer": ["C"], "analysis": "成本加浮动酬金合同中，酬金与实际成本挂钩，成本降低承包方可获得更多酬金，因此对承包方降低成本有较强激励。成本加固定酬金和百分比酬金都不具备降低成本的激励效果。", "tags": ["合同类型", "成本加酬金合同"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-038", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "关于成本加百分比酬金合同，下列说法错误的是？", "options": {"A": "酬金按实际成本的百分比计算", "B": "承包方有降低成本的积极性", "C": "发包方承担全部成本风险", "D": "适用于紧急工程项目"}, "answer": ["B"], "analysis": "成本加百分比酬金合同中，酬金=实际成本×百分比，成本越高酬金越多，因此承包方不仅没有降低成本的积极性，反而可能倾向于提高成本以获取更多酬金。这是该合同形式的缺点。", "tags": ["合同类型", "成本加酬金合同"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-039", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "关于EPC（设计采购施工总承包）合同，下列说法正确的是？", "options": {"A": "EPC合同通常采用单价合同形式", "B": "EPC合同中承包商承担的风险较小", "C": "EPC合同中承包商承担绝大部分风险，通常采用固定总价形式", "D": "EPC合同适用于工程量不确定的项目"}, "answer": ["C"], "analysis": "EPC合同（2025年新增考点）通常采用固定总价合同形式，由承包商承担设计、采购、施工全过程中的绝大部分风险，包括设计风险、价格风险和工期风险。发包方的主要任务是对承包商进行监督和验收。", "tags": ["合同类型", "EPC合同"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-040", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "EPC合同中，承包商通常不承担下列哪项风险？", "options": {"A": "设计风险", "B": "价格风险", "C": "工期风险", "D": "发包方已提供资料错误的风险"}, "answer": ["D"], "analysis": "EPC合同中承包商承担设计、采购、施工全过程的绝大部分风险。但发包方应对其提供的现场资料（如地质资料、水文资料等）的真实性、准确性负责，因此发包方提供的资料错误导致的风险由发包方承担。", "tags": ["合同类型", "EPC合同"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-042", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "下列合同类型中，最适合设计深度不足、工程量难以准确确定的项目的是？", "options": {"A": "固定总价合同", "B": "可调总价合同", "C": "单价合同", "D": "成本加酬金合同"}, "answer": ["C"], "analysis": "单价合同最适合设计深度不足、工程量不确定的项目。采用单价合同，工程量据实结算，可以避免因工程量不确定导致的争议。", "tags": ["合同类型", "单价合同"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-044", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "根据GB/T 50500-2024《建设工程工程量清单计价标准》，分部分项工程量清单应包括多少项要件？", "options": {"A": "3项", "B": "4项", "C": "5项", "D": "6项"}, "answer": ["C"], "analysis": "分部分项工程量清单的5项要件为：项目编码（12位）、项目名称、项目特征、计量单位、工程量。这五项缺一不可。", "tags": ["工程量清单", "分部分项清单"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-046", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "分部分项工程量清单的项目编码由多少位数字组成？", "options": {"A": "10位", "B": "12位", "C": "9位", "D": "15位"}, "answer": ["B"], "analysis": "根据GB/T 50500-2024，分部分项工程量清单的项目编码应采用12位阿拉伯数字表示。前9位应按标准附录的规定设置，10-12位应根据拟建工程的工程量清单项目名称设置。", "tags": ["工程量清单", "项目编码"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-047", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "下列属于不可竞争费用的是？", "options": {"A": "脚手架工程费", "B": "模板工程费", "C": "安全文明施工费", "D": "大型机械设备进出场费"}, "answer": ["C"], "analysis": "安全文明施工费（包括环境保护费、文明施工费、安全施工费、临时设施费）属于不可竞争费用，投标报价时不得低于规定标准。A、B、D属于可竞争的措施项目费。", "tags": ["工程量清单", "措施项目", "不可竞争费"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-050", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "暂列金额一般按照分部分项工程费的多少比例估算？", "options": {"A": "5%-8%", "B": "10%-15%", "C": "15%-20%", "D": "20%-25%"}, "answer": ["B"], "analysis": "暂列金额一般按照分部分项工程费的10%-15%估算。暂列金额是招标人在工程量清单中暂定的一笔款项，用于施工合同签订时尚未确定或者不可预见的所需材料、工程设备、服务的采购，以及施工中可能发生的工程变更、合同约定调整因素出现时的合同价款调整。", "tags": ["工程量清单", "暂列金额"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-051", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "关于暂估价与暂列金额的区别，下列说法正确的是？", "options": {"A": "暂列金额一定发生，暂估价不一定发生", "B": "暂列金额不一定发生，暂估价一定发生", "C": "两者都一定发生", "D": "两者都不一定发生"}, "answer": ["B"], "analysis": "暂列金额是预留的一笔可能发生也可能不发生的费用，用于不可预见的情况。暂估价中的材料暂估价和专业工程暂估价是必然发生但暂不确定价格的费用，因此暂估价是一定发生的。", "tags": ["工程量清单", "暂列金额", "暂估价"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-052", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "工程量清单中的【计日工】是指在施工过程中，完成谁提出的施工图纸以外的零星项目或工作所需的费用？", "options": {"A": "承包人提出，发包人确认", "B": "发包人提出，承包人报价", "C": "监理人提出，发包人确认", "D": "设计单位提出，承包人确认"}, "answer": ["A"], "analysis": "计日工是指在施工过程中完成发包人（或监理人）提出的施工图纸以外的零星项目或工作所需的费用（按合同约定计日工单价和相关数量进行结算）。在清单编制阶段由招标人估算数量，投标人自主报价。", "tags": ["工程量清单", "计日工"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-053", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "关于最高投标限价（招标控制价），下列说法正确的是？", "options": {"A": "所有招标项目都必须编制最高投标限价", "B": "最高投标限价可以根据市场情况下调10%以内", "C": "国有资金投资的建设工程招标，必须编制最高投标限价", "D": "最高投标限价只需编制人签字即可，不需复核"}, "answer": ["C"], "analysis": "国有资金投资的建设工程招标，招标人必须编制最高投标限价（招标控制价）。非国有资金可自主决定是否编制。最高投标限价不得上浮或下调。", "tags": ["最高投标限价", "招标控制价"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-054", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "最高投标限价（招标控制价）编制完成后，下列说法正确的是？", "options": {"A": "可根据市场行情适当上浮", "B": "可根据市场行情适当下调", "C": "不得上浮或下调", "D": "可以在投标报价的±5%范围内浮动"}, "answer": ["C"], "analysis": "最高投标限价（招标控制价）编制完成后不得上浮或下调。投标人的投标报价高于最高投标限价的，其投标应予拒绝。", "tags": ["最高投标限价"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-055", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "当最高投标限价超过批准的概算时，招标人应当如何处理？", "options": {"A": "直接按最高投标限价执行", "B": "适当下浮后使用", "C": "应将其报原概算审批部门审核", "D": "重新编制最高投标限价"}, "answer": ["C"], "analysis": "最高投标限价超过批准的概算时，招标人应将其报原概算审批部门审核。这是为了防止国有资金超概算投资。", "tags": ["最高投标限价"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-057", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "投标人投标报价时，下列说法正确的是？", "options": {"A": "投标报价可以低于成本竞标", "B": "投标人可自主报价，但不得低于成本", "C": "投标报价必须等于最高投标限价", "D": "投标人可以高于最高投标限价报价"}, "answer": ["B"], "analysis": "投标人自主报价，但不得低于成本竞标。低于成本报价属于不正当竞争行为，评标委员会应否决其投标。投标报价不得高于最高投标限价，否则应被否决。", "tags": ["投标报价"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-059", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "投标人在总价不变的前提下，调高先期施工项目的单价、调低后期施工项目的单价，这种投标报价策略称为？", "options": {"A": "多方案报价法", "B": "突然降价法", "C": "不平衡报价法", "D": "先亏后盈法"}, "answer": ["C"], "analysis": "不平衡报价法是在工程总价基本确定后，通过调整内部各个项目的报价，以期既不提高总价，又能在结算时获得更理想的经济效益。通常提高先施工项目的单价（早收钱），降低后施工项目的单价。", "tags": ["投标报价", "不平衡报价法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-060", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "投标人为了迷惑竞争对手，在投标截止前突然降低报价，这种报价策略称为？", "options": {"A": "不平衡报价法", "B": "多方案报价法", "C": "突然降价法", "D": "逐步升级法"}, "answer": ["C"], "analysis": "突然降价法是指在投标截止时间前突然降低报价，使竞争对手来不及调整报价，从而获得中标机会的策略。这是一种迷惑竞争对手的报价技巧。", "tags": ["投标报价", "突然降价法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-061", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "投标人为了提高中标几率，同时提供满足招标文件要求的方案和一个备选方案，这种策略称为？", "options": {"A": "不平衡报价法", "B": "多方案报价法", "C": "突然降价法", "D": "低价夺标法"}, "answer": ["B"], "analysis": "多方案报价法是指投标人在投标文件中提出两个或多个方案及相应的报价，以提高中标几率或为发包方提供更多选择。通常包括一个完全响应招标文件的方案和一个备选优化方案。", "tags": ["投标报价", "多方案报价法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-062", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "投标人在投标前对招标工程量清单进行复核，发现工程量有较大误差时应如何处理？", "options": {"A": "自行调整后按调整的工程量报价", "B": "忽略差异按原有清单报价", "C": "在投标答疑时向招标人提出澄清请求", "D": "在报价中隐藏此项调整"}, "answer": ["C"], "analysis": "投标人对招标工程量清单复核后发现误差时，应在投标截止前通过规定的澄清程序向招标人提出，由招标人统一澄清或修改。投标人不得自行修改工程量清单中的工程量。", "tags": ["投标报价", "工程量复核"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-064", "date": "2026-07-08", "chapter": "g06", "type": "single", "stem": "不适用于不平衡报价法的情形是？", "options": {"A": "能够早日结算的项目适当提高报价", "B": "预计今后工程量会增加的项目适当提高报价", "C": "图纸不明确、估计修改后工程量要增加的提高报价", "D": "工程量明确且不会有变化的项目提高报价"}, "answer": ["D"], "analysis": "不平衡报价法适用于工程量可能发生变化或时间价值差异较大的项目。工程量明确且不会变化的项目提高报价没有意义，因为总价固定，调高某项目单价必然需要调低其他项目单价，反而不利于竞争。", "tags": ["投标报价", "不平衡报价法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "ht_mgmt_1466", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "招标人和中标人在签订合同的谈判中， 为了防范货币贬值或者通货膨胀的风险， 一般通过( )约定风险承担方式", "options": {"A": "调整投标价格", "B": "价格调整条款", "C": "调整中标价格", "D": "调整工作范围"}, "answer": ["B"], "analysis": "本题考查的是建设工程施工承包合同谈判的价格调整条款。对于工期较长的建设工程，容易遭受货币贬值或通货膨胀等因素的影响，可能给承包人造成较大损失，价格调整条款可以比较公正地解决这一承包人无法控制的风险损失。无论是单价合同还是总价合同，都可以确定价格调整条款，即是否调整以及如何调整等。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1467", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "关于工程建设项目是否必须招标的说法， 正确的是（ ）。", "options": {"A": "使用国有企业事业单位自有资金的工程建设项目必须进行招标", "B": "施工单项合同估算价为人民币 100 万， 但项目总投资额为人民币 2000 万元的工程建设项目必须进行招标", "C": "利用扶贫资金实行以工代赈、 需要使用农民工的建设工程项目可以不进行招标", "D": "需要采用专利或者专有技术的建设工程项目可以不进行招标"}, "answer": ["C"], "analysis": "必须招标的项目需要同时条件和规模两类。A选项缺少规模；B选项确实条件，同时规模达不到必须招标的规模；D需要采用不可替代的专利技术，才可以不进行招标。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1468", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "某市政工程施工招标项目估算价为 5000 万元， 其投标保证金不得超过（ ） 万元", "options": {"A": "80", "B": "100", "C": "150", "D": "200"}, "answer": ["A"], "analysis": "根据《招标投标办法》规定，房建、市政等建筑工程是够招标项目的投标保证金不得超过项目估算价的2%。施工招标的投标保证金不得项目估算价的2%，且不得超过80万。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1469", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "根据《招标投标法实施条例》， 国有资金占控股地位的依法必须进行招标的项目， 关于如何确定中标人的说法， 正确的是（ ）。", "options": {"A": "招标人可以确定任何一名中标候选人为中标人", "B": "招标人可以授权评标委员会直接确定中标人", "C": "排名第一的中标候选人放弃中标， 必须重新招标", "D": "排名第一的中标候选人被查实不符合条件的， 应当重新评标"}, "answer": ["B"], "analysis": "国有资金为主的项目招标，招标人应当按照评标委员会选出的中标候选人顺序选定中标人。如果排名第一的中标候选人放弃中标或不符合条件，招标人可以选择排名第二的中标候选人，或者选择重新招标。招标人可以授权评标委员会直接确定中标人。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1470", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "某投标人对招标项目的评标结果有异议，应当依法先向规定的受理人提出异议。该受理人应当是（ ）。", "options": {"A": "评标委员会", "B": "招标人", "C": "行政监督部门", "D": "招标代理机构"}, "answer": ["B"], "analysis": "《招标投标法实施条例》规定，投标人或者其他利害关系人认为招标投标活动不符合法律、行政法规规定的，可以自知道或者应当知道之日起10日内向有关行政监督部门投诉。但是，对资格预审文件、招标文件、开标以及对依法必须进行招标项目的评标结果有异议的，应当依法先向招标人提出异议。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1471", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "对于应当招标的工程建设项目，经批准可以不采用招标发包的情形是（ ）。", "options": {"A": "拟公开招标的费用与项目价值相比，不值得", "B": "当地投标企业较少", "C": "采购人依法能够自行建设、生产或者提供", "D": "受自然地域限制的"}, "answer": ["C"], "analysis": "《招标投标法实施条例》还规定，除《招标投标法》规定可以不进行招标的特殊情况外，有下列情形之一的，可以不进行招标：（1）需要采用不可替代的专利或者专有技术；（2）采购人依法能够自行建设、生产或者提供；（3）已通过招标方式选定的特许经营项目投资人依法能够自行建设、生产或者提供；（4）需要向原中标人采购工程、货物或者服务，否则将影响施工或者功能配套要求；（5）国家规定的其他特殊情形。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1472", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "根据《政府采购法实施条例》， 政府采购工程依法不进行招标的， 可以采用的采购方式是（ ）", "options": {"A": "询价", "B": "单一来源采购", "C": "直接确定", "D": "框架协议"}, "answer": ["B"], "analysis": "《中华人民共和国政府采购法实施条例》进一步规定，政府采购工程依法不进行招标的，应当依照政府采购法和本条例规定的竞争性谈判或者单一来源采购方式采购。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1473", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "国有资金占控股或主导地位依法必须招标的项目有（ ）情形的可邀请招标。", "options": {"A": "项目技术比较复杂", "B": "拟进行公开招标的费用占项目合同金额比例过大", "C": "受自然地域限制的", "D": "工程项目工期紧"}, "answer": ["B"], "analysis": "国务院发展计划部门确定的国家重点项目和省、自治区、直辖市人民政府确定的地方重点项目不适宜公开招标经批准可邀请招标；国有资金占控股或主导地位依法必须招标的项目有下列情形之一的可邀请招标：（1）技术复杂、有特殊要求或受自然环境限制，只有少量潜在投标人可供选择的；（2）采用公开招标方式费用占项目合同金额比例过大。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1474", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "依法必须招标的建设项目， 招标人应当自确定中标人之日起（ ） 日内， 向有关行政监督部门提交招标投标情况的书面报告", "options": {"A": "15", "B": "20", "C": "30", "D": "60"}, "answer": ["A"], "analysis": "依法必须进行招标的项目，招标人应当自确定中标人之日起15日内，向有关行政监督部门提交招标投标情况的书面报告。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1475", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "下列建设工程项目招投标活动中， 属于合同要约行为的是( )。", "options": {"A": "提交投标文件", "B": "订立承包合同", "C": "发出中标通知书", "D": "发布招标公告"}, "answer": ["A"], "analysis": "本题考核的是合同订立的程序。建设工程合同的订立也要采取要约和承诺方式。根据《招标投标法》对招标、投标的规定，招标、投标、中标的过程实质就是要约、承诺的一种具体方式。招标人通过媒体发布招标公告，或向符合条件的投标人发出招标文件，为要约邀请；投标人根据招标文件内容在约定的期限内向招标人提交投标文件，为要约；招标人通过评标确定中标人，发出中标通知书，为承诺；招标人和中标人按照中标通知书、招标文件和中标人的投标文件等订立书面合同时，合同成立并生效。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1476", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "乙施工单位通过招投标程序中标了甲开发公司的一个施工项目。签约前，甲要求让利5%，否则不签施工合同。后双方按中标价签订了设备合同，同时签订了让利5%的补充协议。竣工结算时，甲按让利协议扣减结算总价5%，乙以自己亏损为由不同意让利并向法院提起诉讼，要求按中标价结算。下列说法正确的是（ ）。", "options": {"A": "该补充协议属于可撤销合同", "B": "应以备案合同作为结算工程价款依据", "C": "应以补充协议作为结算工程价款依据", "D": "乙方行为构成合同违约"}, "answer": ["B"], "analysis": "建设工程纠纷中，应以备案合同作为结算工程价款的依据。当事人就同二建设工程另行订立的建设工程施工合同与经过备案的中标合同实质性内容不一致的，应当以备案的中标合同作为结算工程价款的根据。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1477", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "据我国有关法规规定， 下列关于招标文件出售的说法中， 正确的是( )。", "options": {"A": "自招标文件出售之日起至停止出售之日止， 最短不得少于 20 日", "B": "对招标文件的收费应合理， 遵循微利的原则", "C": "招标人在售出招标文件后， 可随时终止招标", "D": "招标文件售出后， 不予退还"}, "answer": ["D"], "analysis": "自招标文件或者资格预审文件出售之日起至停止出售之日止，最短不得少于5日。 投标人必须自费购买相关招标或资格预审文件。招标人发售资格预审文件、招标文件，不得以营利为目的。对于所附的设计文件，招标人可以向投标人酌收押金。招标文件或者资格预审文件售出后，不予退还。招标人在发布招标公告、发出投标邀请书后或者售出招标文件或资格预审文件后不得擅自终止招标。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1478", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "某按工程量清单计价的招标工程， 投标人在复核工程量清单时发现工程数量与设计文件和现场实际有较大的差异， 则投标人的正确处理方式是( )", "options": {"A": "自行调整清单数量， 在附录中加以说明， 并按调整后的数量投标", "B": "根据清单数量和投标人复核的数量分别报价， 供业主选择", "C": "以适当的方式要求业主澄清， 视结果进行投标", "D": "不予理会， 按照招标文件提供的清单数量进行投标"}, "answer": ["C"], "analysis": "本题考核的是工程量的复核。有的招标文件中提供了工程量清单，尽管如此，投标者还是需要进行复核，因为这直接影响到投标报价以及中标的机会。对于单价合同，尽管是以实测工程量结算工程款，但投标人仍应根据图纸仔细核算工程量，当发现相差较大时，投标人应向招标人要求澄清。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1479", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "发售招标文件收取的费用应当限于补偿（ ） 的成本支出。", "options": {"A": "编制招标文件", "B": "印刷、 邮寄招标文件", "C": "招标人办公", "D": "招标活动"}, "answer": ["B"], "analysis": "招标人发售资格预审文件、招标文件收取的费用应当限于补偿印刷、邮寄的成本支出，不得以营利为目的。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1480", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "如果修改招标文件的时间距投标截止时间不足( )天，相应推后投标截止时间。", "options": {"A": "7", "B": "14", "C": "15", "D": "20"}, "answer": ["C"], "analysis": "本题考查的是招标文件的组成内容及其编制要求。如果修改招标文件的时间距投标截止时间不足15天，相应推后投标截止时间。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1481", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "根据《标准施工招标文件》（2007年版），进行了资格预审的施工招标文件应包括（）。", "options": {"A": "招标公告", "B": "投标资格条件", "C": "投标邀请书", "D": "评标委员会名单"}, "answer": ["C"], "analysis": "当进行资格预审时，招标文件中应包括投标邀请书，该邀请书可代替资格预审通过通知书，以明确投标人已具备了在某具体项目某具体标段的投标资格，其他内容包括招标文件的获取、投标文件的递交等。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1482", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "招标人对已发出的招标文件进行的必要修改，应当在投标截止时间（）天前发出。", "options": {"A": "7", "B": "10", "C": "14", "D": "15"}, "answer": ["D"], "analysis": "招标文件的澄清将在规定的投标截止时间15天前以书面形式发给所有购买招标文件的投标人，但不指明澄清问题的来源。如果澄清发出的时间距投标截止时间不足15天，相应推迟投标截止时间。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1484", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "施工投标报价的主要工作有：①复核工程量；②研究招标文件；③确定基础标价；④编制投标文件，其正确的工作流程是( )。", "options": {"A": "①②③④", "B": "②③①④", "C": "①②④③", "D": "②①③④"}, "answer": ["D"], "analysis": "整个投标过程需遵循一定的程序进行表格投标报价编制流程图", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1485", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "施工项目投标报价的工作包括：①收集投标信息；②选择报价策略；③组建投标班子；④确定基础标价；⑤确定投标报价；⑥研究招标文件。以下工作正确的先后顺序是()。", "options": {"A": "⑥①③②④⑤", "B": "③⑥①④②⑤", "C": "③①⑥②④⑤", "D": "⑥③①④②⑤"}, "answer": ["B"], "analysis": "本题考查的是建设项目施工投标与投标文件的编制。根据教材图4.2.1，施工投标报价编制流程图可知，题干中工作的正确顺序是：组建投标班子、研究招标文件、收集投标信息、确定基础标价、选择报价策略、确定投标报价。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1486", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "某投标人在递交投标文件的同时，按规定递交了投标保证金，其投标总价为00 万元，则其投标保证金数额最高为（）万元。", "options": {"A": "50", "B": "80", "C": "100", "D": "160"}, "answer": ["B"], "analysis": "投标保证金的数额不得超过投标总价的2%，且不超过80 万元。5000×2%=100，所以最高保证金80万元。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1487", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "关于招标文件的澄清和修改，下列说法中错误的是()。", "options": {"A": "投标人应以信函、电报等可以有形地表现所载内容的形式向招标人提出疑问", "B": "招标文件的澄清无须发给所有投标人澄清问题的来源", "C": "澄清发出的时间距投标截止日不足10天的应推迟投标截止时间", "D": "投标人收到澄清的确认时间可以是相对时间，也可以是绝对时间"}, "answer": ["C"], "analysis": "本题考查的是招标文件的组成内容及其编制要求。选项C错误，如果修改招标文件的时间距投标截止时间不足15天，相应推后投标截止时间。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1488", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "其他项目清单中，无须由招标人根据拟建工程实际情况提出估算额度的费用项目是()。", "options": {"A": "暂列金额", "B": "材料暂估价", "C": "专业工程暂估价", "D": "计日工费用"}, "answer": ["D"], "analysis": "其他项目清单由暂列金额、暂估价、计日工和总承包服务费组成，其中暂列金额和暂估价均由招标人填写，投标人直接计入投标总价即可。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1489", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "关于招标工程量清单中分部分项工程量清单的编制，下列说法中错误的是（）。", "options": {"A": "招标人只负责项目编码、项目名称、计量单位和工程量四项内容的填写", "B": "同一招标工程的项目编码不得有重码", "C": "清单所列项目应是在单位工程施工过程中以其本身构成该工程实体的分项工程", "D": "当清单计价规范附录中有两个计量单位时，应结合实际情况选择其中一个"}, "answer": ["A"], "analysis": "分部分项工程量清单所反映的是拟建工程分部分项工程项目名称和相应数量的明细清单，招标人负责包括项目编码、项目名称、项目特征、计量单位和工程量在内的五项内容。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1490", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "关于工程量清单编制总说明的内容，下列说法中正确的是()。", "options": {"A": "建设规模是指工程投资总额", "B": "工程特征是指结构类型及主要施工方案", "C": "环境保护要求包括避免材料运输影响周边环境的防护要求", "D": "施工现场实际情况是指自然地理条件"}, "answer": ["C"], "analysis": "工程概况中要对建设规模、工程特征、计划工期、施工现场实际情况、自然地理条件、环境保护要求等做出描述。其中建设规模是指建筑面积；选项A错误；工程特征应说明基础及结构类型、建筑层数、高度、门窗类型及各部位装饰、装修做法； 选项B错误； 施工现场实际情况是指施工场地的地表状况；选项D错误；环境保护要求，是针对施工噪声及材料运输可能对周围环境造成的影响和污染所提出的防护要求。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1491", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "下列关于发承包阶段合同价款约定的说法，正确的是()。", "options": {"A": "对于直接发包的项目，如按初步设计总概算投资包干时，应以中标时确定的金额为签约合同价", "B": "对于直接发包的项目，如按施工图预算包干，则应以审查后的施工图总预算或综合预算为准", "C": "招标人发布的招标文件提出了各项要求，主要对承包方有约束力", "D": "招标文件包括招标文件的构成以及澄清，但并不含对其修改的内容"}, "answer": ["B"], "analysis": "本题考查的是招标文件的组成内容及其编制要求。选项A错误，对于招标发包的项目，即以招标投标方式签订的合同中，应以中标时确定的金额为准；对于直接发包的项目，如按初步设计总概算投资包干时，应以经审批的概算投资中与承包内容相应部分的投资（包括相应的不可预见费）为签约合同价；如按施工图预算包干，则应以审查后的施工图总预算或综合预算为准。选项C错误，招标文件中提出的各项要求，对整个招标工作乃至发承包双方都具有约束力。选项D错误，招标文件主要包括招标文件的构成以及澄清和修改的规定。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1492", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "编制钢筋工程量清单时，适宜采用暂估量加签证处理的钢筋是()。", "options": {"A": "支撑双层钢筋用的“铁马”", "B": "伸出构件的锚固钢筋", "C": "设计注明的搭接钢筋", "D": "规范规定的搭接钢筋"}, "answer": ["A"], "analysis": "本题考查的是招标工程量清单的编制。 ①现浇构件中伸出构件的锚固钢筋应并入钢筋工程量内。除设计（包括规范规定）标明的搭接外，其他施工搭接不计算工程量，在综合单价中综合考虑。②现浇构件中固定位置的支撑钢筋、双层钢筋用的‘铁马’在编制工程量清单时，如果设计未明确，其工程数量可为暂估量，结算时按现场签证数量计算。”", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1493", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "关于依法必须招标的工程，下列说法中正确的是()。", "options": {"A": "国有资金投资的建筑工程招标可不设招标控制价", "B": "招标人可以自行决定是否编制标底，标底必须保密", "C": "招标人设有最高投标限价的，应当在开标时公布", "D": "招标人也可以根据需要，规定最低投标限价"}, "answer": ["B"], "analysis": "本题考查的是招标控制价的编制。选项A错误，国有资金投资的建筑工程招标的，应当设有最高投标限价；选项C错误，招标人设有最髙投标限价的，应当在 标文件中明确最高投标限价或者最高投标限价的计算方法；选项D错误，招标人不得规定最低投标限价。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1494", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "为编制招标工程量清单，在拟定常规的施工组织设计时，正确的做法是（）。", "options": {"A": "根据概算指标和类似工程估算整体工程量时，仅对主要项目加以估算", "B": "拟定施工总方案时需要考虑施工步骤", "C": "在满足工期要求的前提下，施工进度计划应尽量推后以降低风险", "D": "在计算工、料、机资源需要量时，不必考虑节假日、气候的影响"}, "answer": ["A"], "analysis": "在拟定常规的施工组织设计时需注意以下问题：1)估算整体工程量。根据概算指标或类似工程进行估算，且仅对主要项目加以估算即可，如土石方、混凝土等。2)拟定施工总方案。施工总方案只需对重大问题和关键工艺作原则性的规定，不需考虑施工步骤，4)编制施工进度计划。施工进度计划要满足合同对工期的要求，在不增加资源的前提下尽量提前。编制施工进度计划时要处理好工程中各分部、分项、单位工程之间的关系，避免出现施工顺序的颠倒或工种相互冲突。5)计算人、材、机资源需要量。人工工日数量根据估算的工程量、选用的定额、拟定的施工总方案、施工方法及要求的工期来确定，并考虑节假日、气候等的影响。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1495", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "关于招标工程量清单中其他项目清单的编制，下列说法中正确的是（）", "options": {"A": "投标人情况、发包人对工程管理要求对其内容会有直接影响", "B": "暂列金额可以只列总额，但不同专业预留的暂列金额应分别列项", "C": "专业工程暂估价应包括利润、增值税", "D": "计日工的暂定数量可以由投标人填写"}, "answer": ["B"], "analysis": "(1)暂列金额是指招标人暂定并包括在合同中的一笔款项。用于工程合同签订时尚未确定或者不可预见的所需材料、工程设备、服务的采购，施工中可能发生的工程变更、合同约定调整因素出现时的合同价款调整以及发生的索赔、现场签证确认等的费用。此项费用由招标人填写其项目名称、计量单位、暂定金额等，若不能详列，也可只列暂定金额总额", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1496", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "招标工程量清单应根据常规施工方案编制，拟定常规施工方案时（）。", "options": {"A": "应对主要项目进行估算，如土石方、混凝土", "B": "需对施工总方案中的重大问题及关键工艺作明确具体的规定", "C": "不需计算人、材、机资源消耗量", "D": "不需考虑节假日与气候对工期的影响"}, "answer": ["A"], "analysis": "在拟定常规的施工组织设计时需注意以下问题：1）估算整体工程量，根据概算指标或类似工程进行估算，且仅对主要项目加以估算即可，如土石方、混凝土等；2）拟定施工总方案，施工总方案只需对重大问题和关键工艺作原则性的规定，不需考虑施工步骤。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1497", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "拟定施工总方案是编制招标工程量清单的一项准备工作，下列选项中属于拟定施工总方案范畴的是()。", "options": {"A": "对关键工艺的原则性规定", "B": "拟定施工步骤和施工顺序", "C": "估算整体工程量", "D": "编制施工进度计划"}, "answer": ["A"], "analysis": "拟定施工总方案。 施工总方案只需对重大问题和关键工艺作原则性 的规定，不需 考虑施工步骤。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1498", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "招标人要求总承包人对专业工程进行统一管理和协调的，总承包人可计取总承包服务费，其取费基数为()。", "options": {"A": "专业工程估算造价", "B": "投标报价总额", "C": "分部分项工程费用", "D": "分部分项工程费与措施费之和"}, "answer": ["A"], "analysis": "本题考查的是招标控制价的编制。总承包服务费应按照省级或行业建设主管部门的规定计算，在计算时可参考以下标准：(1)招标人仅要求对分包的专业工程进行总承包管理和协调时，按分包的专业工程估算造价的1.5%计算；(2)招标人要求对分包的专业工程进行总承包管理和协调，并同时要求提供配合服务时，根据招标文件中列出的配合服务内容和提出的要求，按分包的专业工程估算造价的3%~5%计算；(3)招标人自行供应材料的，按招标人供应材料价值的1%计算。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1499", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "在编制脚手架工程量清单时，其工作内容不包括()。", "options": {"A": "场内、场外材料搬运", "B": "安全网的铺设", "C": "选择附墙点与主体连接", "D": "测试手动装置、安全锁等"}, "answer": ["D"], "analysis": "本题考查的是招标工程量清单的编制。计算脚手架工程量时，其工作内容包括：(1)场内、场外材料搬运；(2)搭、拆脚手架、斜道、上料平台；(3)安全网的铺设；(4)选择附墙点与主体连接；(5)测试电动装置、安全锁等；(6)拆除脚手架后材料的堆放。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1500", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "编制招标工程量清单中分部分项工程量清单时，项目特征可以不描述的是（）。", "options": {"A": "梁的标高", "B": "混凝土的强度等级", "C": "门(窗)框外围尺寸或洞口尺寸", "D": "油漆(涂料)的品种"}, "answer": ["A"], "analysis": "可不描述的内容：(1)对计量计价没有实质影响的(混凝土柱高度、断面大小)；(2)应由投标人根据施工方案确定的(石方爆破单孔深度及装药量特征)；(3)应由投标人根据当地材料和施下要求确定的(混凝土拌料中砂子、石子种类、特征)；(4)应由施工措施解决的(现浇混凝土板、梁的标高)。 本题库是以官方教材为依据，知识点所对应的习题综合了二建法规、二建管理、造价员基础、一级造价师考试的题库+真题编辑，基本上做到了每个知识点都有相对应的题目及解析,题库会陆续更新,会有模拟题,预测题及考前更新押题。 《建设工程计量与计价实务》题库编辑中,教材出来后会陆续更新 www.jinkaodian.com 金考典考试软件。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1501", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "施工招标工程量清单中，应由投标人自主报价的其他项目是（）。", "options": {"A": "专业工程暂估价", "B": "暂列金额", "C": "工程设备暂估价", "D": "计日工单价"}, "answer": ["D"], "analysis": "表4.1.2建设单位工程招标控制价计价程序（施工企业投标报价计价程序）表 本题库是以官方教材为依据，知识点所对应的习题综合了二建法规、二建管理、造价员基础、一级造价师考试的题库+真题编辑，基本上做到了每个知识点都有相对应的题目及解析,题库会陆续更新,会有模拟题,预测题及考前更新押题。 《建设工程计量与计价实务》题库编辑中,教材出来后会陆续更新 www.jinkaodian.com 金考典考试软件。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1502", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "关于标底与招标控制价的编制，下列说法中正确的是()。", "options": {"A": "招标人不得自行决定是否编制标底", "B": "招标人不得规定最低投标限价", "C": "编制标底时必须同时设有最高投标限价", "D": "招标人不编制标底时应规定最低投标限价"}, "answer": ["B"], "analysis": "《招标投标法实施条例》规定，招标人可以自行决定是否编制标底，一个招标项目只能有一个标底，标底必须保密。同时规定，招标人设有最高投标限价的，应当在招标文件中明确最高投标限价或者最高投标限价的计算方法，招标人不得规定最低投标限价。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1503", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "招标控制价中暂列金额一般按分部分项工程费的一定比率参考计算，这一比率的范围是（）。", "options": {"A": "3%~5%", "B": "5%~10%", "C": "10%~15%", "D": "15%~20%"}, "answer": ["C"], "analysis": "招标控制价编制时，暂列金额由招标人根据工程特点、工期长短，按有关计价规定进行估算，一般可以分部分项工程费的10%~15%为参考。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1504", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "关于招标控制价的相关规定，下列说法中正确的是()。", "options": {"A": "国有资金投资的工程建设项目，应编制招标控制价", "B": "招标控制价应在招标文件中公布，仅需公布总价", "C": "招标控制价超过批准概算3%以内时，招标人不必将其报原概算审批部门审核", "D": "当招标控制价复查结论超过原公布的招标控制价3%以内时，应责成招标人改正"}, "answer": ["A"], "analysis": "本题考查的是招标控制价的编制。选项B，招标控制价应在招标文件中公布，对所编制的招标控制价不得进行上浮或下调。在公布招标控制价时，除公布招标控制价的总价外，还应公布各单位工程的分部分项工程费、措施项自费、其他项目费、增值税。选项C，招标控制价超过批准的概算时，招标人应将其报原概算审批部门审核。选项D，当招标控制价复查结论与原公布的招标控制价误差大于±3%时，应责成招标人改正。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1505", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "关于依法必须招标工程的标底和招标控制价，下列说法中正确的是()。", "options": {"A": "招标人有权白行决定是否采用设标底招标、无标底招标以及招标控制价招标", "B": "采用设标底招标的，招标人有权决定标底是否在招标文件中公开", "C": "采用招标控制价招标的，招标人应在招标文件中明确最高投标限价，也可以规定最低投标限价", "D": "公布招标控制价时，还应公布各单位工程的分部分项工程费、措施项目费、其他项目费、增值税"}, "answer": ["D"], "analysis": "选项A，国有资金投资的建筑工程招标的，应当设有最高投标限价；非国有资金投资的建筑工程招标的，可以设有最高投标限价或者招标标底；选项B，招标人可以自行决定是否编制标底，一个招标项目只能有一个标底，标底必须保密；选项C，招标设有最髙投标限价的，应当在招标文件中明确最高投标限价或者最高投标限价的计算方法，招标人不得规定最低投标限价。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1506", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "招标控制价综合单价的组价包括如下工作：①根据政策规定或造价信息确定工料机单价；②根据工程所在地的定额规定计算工程量；③将定额项目的合价除以清单项目的工程量；④根据费率和利率计算出组价定额项目的合价口则正确的工作顺序是（）", "options": {"A": "①④②③", "B": "①③②④", "C": "②①③④", "D": "②①④③"}, "answer": ["D"], "analysis": "综合单价的组价：(1)首先，确定所组价的定额项目名称，并计算出相应的工程量；(2)其次，依据工程造价政策规定或工程造价信息确定其人工、材料、机械台班单价；(3)在考虑风险因素确定管理费率和利润率的基础上，计算定额项目合价；(4)计算工程量清单综合单价，未计价材料费(包括暂估单价的材料费)应计入综合单价。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1507", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "某工程投标总价为5000万元，则投标保证金最高不得超过()。", "options": {"A": "20万元", "B": "50万元", "C": "80万元", "D": "100万元"}, "answer": ["C"], "analysis": "本题考查的是招标投标法实施条例。投标保证金一般不得超过投标总价的2%，且最高不超过80万元。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1508", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "关于工程量清单方式招标工程合同价格风险及风险分担，下列说法中正确的是( )。", "options": {"A": "当出现的风险内容及幅度在招标文件规定的范围内时，综合单价不变", "B": "市场价格波动导致施工机具使用费发生变化时，承包人只承担5%以内的价格风险", "C": "人工费变化发生的风险全部由发包人承担", "D": "承包人管理费的风险一般由发承包双方共同承担"}, "answer": ["A"], "analysis": "招标文件中要求投标人承担的风险费用，投标人应考虑进入综合单价。在施工过程中，当出现的风险内容及其范围（幅度）在招标文件规定的范围（幅度）内时，综合单价不得变动，合同价款不作调整。对于主要由市场价格波动导致价格风险......根据工程特点和工期要求，一般采取的方式是承包人承担5%以内的材料、工程设备价格风险，10%以内的施工机具使用费风险。D是由承包人全部承担。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1509", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "投标人为使报价具有竞争力，下列有关生产要素询价的做法中，正确的是()。", "options": {"A": "在通过资格预审前进行询价", "B": "尽量向咨询公司进行询价", "C": "不论何时何地尽量使用自有机械", "D": "劳务市场招募零散工有利于管理"}, "answer": ["B"], "analysis": "本题考查的是询价与工程量复核。选项A错误，在报价前必须通过各种渠道，采用各种方式对所需人工、材料、施工 机具等要素进行系统 的调査，掌握各要素的价格、质量、供应时间、供应数量等数据，这个过程称为询价。选项B正确，通过咨询公司所得到的询价资料比较可靠，但需要支付一定的咨询费用，也可向同行了解。选项C错误，在外地施工需用的施工机具， 有时在当地租赁或采购可能更为有利。选项D错误，劳务询价主要有两种情况：一是成建制的劳务公司，相当于劳务分包，一般费用较高，但素质较可靠，工效较高，承包商的管理工作较轻；另一种是劳务市场招募零散劳动力，根据需要进行选择，这种方式虽然劳务价格低廉，但有时素质达不到要求或工效较低，且承包商的管理工作较繁重。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1510", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "投标人在投标报价时，应优先被采用为综合单价编制依据的是()。", "options": {"A": "企业定额", "B": "地区定额", "C": "行业定额", "D": "国家定额"}, "answer": ["A"], "analysis": "本题考查的是投标报价的编制方法和内容。综合单价计算基础主要包括消耗量指标和生产要素单价。应根据本企业的企业实际消耗量水平，并结合拟定的施工方案确定完成清单项目要消耗的各种人工、材料、机械台班的数量。计算时应采用企业定额，在没有企业定额或企业定额缺项时，可参照与本企业实际水平相近的国家、地区、行业定额，并通过调整来确定清单项目的人、材、机单位用量。各种人工、材料、机械台班的单价，则应根据询价的结果和市场行情综合确定。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1512", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "关于投标报价时综合单价的确定，下列做法中正确的是()。", "options": {"A": "以项目特征描述为依据确定综合单价", "B": "招标工程量清单特征描述与设计图纸不符时，应以设计图纸为准", "C": "应考虑招标文件规定范围（幅度）外的风险费用", "D": "消耗量指标的计算应以地区或行业定额为依据"}, "answer": ["A"], "analysis": "本题考查的是投标报价的编制方法和内容。确定综合单价时的注意事项：（1）以项目特征描述为依据。 项目特征是确定综合单价的重要依据之一，投标人投标 报价时应依据招标文件中清单项目的特征描述确定综合单价。在招标投标过程中，当出现 招标工程量清单特征描 与设计图纸不符时，投标人应 以招标工程量清单的项目特征描述 为准，确定投标报价的综合单价。选项A正确，选项B错误。选项C错误，招标文件中要求投标人承担的风险费用，投标人应考虑进入综合单价。选项D错误，计算基础主要包括消耗量指标和生产要素单价。应根据本企业的 实际消耗量水平，并结合拟定的施工方案确定完成清单项目需要消耗的各种人工、材料、机具台班的数量。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1513", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "对于其他项目中的计日工，投标人正确的报价方式是( )。", "options": {"A": "按政策规定标准估算报价", "B": "按招标文件提供的金额报价", "C": "自主报价", "D": "待签证时报价"}, "answer": ["C"], "analysis": "计日工应按照招标人提供的其他项目清单列出的项目和估算的数量，自主确定各项综合单价并计算费用。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1514", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "编制投标报价，下列关于分部分项工程综合单价确定的描述中，正确的是()。", "options": {"A": "招投标过程中，当出现招标文件中分部分项工程量清单特征描述与设计图纸不符时，投标人应以设计图纸为准，结合规范确定投标报价的综合单价", "B": "施工中施工图纸或设计变更与工程量清单特征描述不一致时，应按工程量清单特征，确定综合单价", "C": "综合单价应包括承包人承担的5%以内的材料、工程设备的价格风险，10%以内的施工机具使用费风险", "D": "承包人应承担法律、法规、规章或有关政策出台导致工程税金、规费的变化"}, "answer": ["C"], "analysis": "本题考查的是投标报价的编制方法和内容。选项A错误，再招标投标过程中，当出现招标文件中分部分项工程量清单特征描述与设计图纸不符时，投标人应以招标工程量清单的项目特征描述为准，确定投标报价的综合单价；选项B错误，当施工中施工图纸或设计变更与招标工程量清单项目特征描述不一致时，发承包双方应按实际施工的项目特征，依据合同约定重新确定综合单价；选项D错误，法律、法规、规章或有关政策出台导致工程税金、规费的变化，承包人不应承担此类风险，应按照有关调整规定执行。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1516", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "某施工企业投标一城市基础设施项目，投标总价为00万元，则投标保证金最高数额为()万元。", "options": {"A": "50", "B": "80", "C": "76", "D": "100"}, "answer": ["B"], "analysis": "投标保证金除现金外，可以是银行出具的银行保函、保兑支票、银行汇票或现金支票。投标保证金的数额不得超过项目估算价的2％，且最高不超过80万元。D", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1517", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "关于联合体投标需要遵循的规定，下列说法中正确的是（）。", "options": {"A": "联合体各方签订共同投标协议后，可再以自己名义单独投标", "B": "资格预审后联合体增减、更换成员的，其投标有效性待定", "C": "由同一专业的单位组成的联合体，按其中较高资质确定联合体资质等级", "D": "联合体投标的，可以联合体牵头人的名义提交投标保证金"}, "answer": ["D"], "analysis": "1.联合体投标两个以上法人或者其他组织可以组成一个联合体，以一个投标人的身份共同投标。联合体投标需遵循以下规定：? (1)联合体各方应按招标文件提供的格式签订联合体协议书，联合体各方应当指定牵头人，授权其代表所有联合体成员负责投标和合同实施阶段的主办、协调工作，并应当向招标人提交由所有联合体成员法定代表人签署的授权书。 (2)联合体各方签订共同投标协议后，不得再以自己名义单独投标，也不得组成新的联合体或参加其他联合体在同一项目中投标。联合体各方在同一招标项目中以自己名义单独投标或者参加其他联合体投标的，相关投标均无效。 (3)招标人接受联合体投标并进行资格预审的，联合体应当在提交资格预审申请文件前组成。资格预审后联合体增减、更换成员的 ， 其投标无效。 (4)由同一专业的单位组成的联合体，按照资质等级较低的单位确定资质等级。 (5)联合体投标的，.应当以联合体各方或者联合体中牵头人的名义提交投标保证金，以联合体中牵头人名义提交的投标保证金，对联合体各成员具有约束力。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1518", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "下列内容中，属于招标工程量清单编制依据的是（）。", "options": {"A": "分部分项工程清单", "B": "拟定的招标文件", "C": "招标控制价", "D": "潜在投标人的潜质及能力"}, "answer": ["B"], "analysis": "本题考查清单编制依据，很简单，工程量清单编制依据。包括建设工程工程量清单计价规范、设计文件、招标文件、施工现场情况、工程特点及常规施工方案等。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1519", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "投标人针对工程量清单中工程量的遗漏或错误，可以采取的正确做法是（）。", "options": {"A": "即向招标人提出异议，要求招标人修改", "B": "不向招标人提出异议，风险自留", "C": "是否向招标人提出修改意见取决于投标策略", "D": "等中标后，要求招标人按实调整"}, "answer": ["C"], "analysis": "投标人进行复核工程量的目的不是修改工程量清单对工程量清单。对工程量清单存在的错误，可以向招标人提出，由招标人统一修改，并把修改情况通知所有投标人；针对工程量清单中工程量的遗漏或错误，是否向招标人提出修改意见取决于投标策略：投标人可以运用一些报价的技巧提高报价的质量，争取在中标后能获得更大的收益。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1521", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "在签订合同的谈判中，为了防范货币贬值或者通货膨胀的风险，招标人和中标人一般通过()约定风险分担方式（2013）", "options": {"A": "确定价格调整条款", "B": "确定合同价格条款", "C": "调整工程范围", "D": "确定合同款支付方式"}, "answer": ["A"], "analysis": "对于工期较长的建设工程，容易遭受货币贬值或通货膨胀等因素的影响，可能给承包人造成较大损失。价格调整条款可以比较公正地解决这一承包人无法控制的风险损失。 【教材】P274", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1522", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "投标人根据招标文件在约定期限内向招标人提交投标文件的行为，称为（ ）。 （2014）", "options": {"A": "要约", "B": "承诺", "C": "要约邀请", "D": "合同生效"}, "answer": ["A"], "analysis": "招标、投标、中标的过程实质就是要约、承诺的一种具体方式。 招标人通过媒体发布招标公告，或向符合条件的投标人发出招标邀请，为要约邀请； 投标人根据招标文件内容在约定的期限内向招标人提交投标文件，为要约； 招标人通过评标确定中标人，发出中标通知书，为承诺; 招标人和中标人按照中标通知书、招标文件和中标人的投标文件等订立书面合同时，合同成立并生效。 【教材】P274", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1523", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "【2018年真题】关于招标价格的说法，正确的是（ ）。", "options": {"A": "招标时可以设定最低投标限价", "B": "招标时应当编制标底", "C": "招标的项目应当采用工程量清单计价", "D": "招标时可以设定最高投标限价"}, "answer": ["D"], "analysis": "本题考查招标文件、标底及工程量清单计价的规定。选项A错误，招标人不得规定最低投标限价。选项B错误，招标人可以自行决定是否编制标底。选项C错误，全部使用国有资金投资或者以国有资金投资为主的建筑工程，应当采用工程量清单计价；非国有资金投资的建筑工程，鼓励采用工程量清单计价。选项D正确，招标人可以设最高投标限价，且应当在招标文件中明确最高投标限价或者最高投标限价的计算方法。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1524", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "【2016年真题】下列招标人的行为中合法的是（ ）。", "options": {"A": "招标人可以根据需要组织部分潜在投标人踏勘项目现场", "B": "招标人可以限定或者指定特定的专利、品牌、原产地或供应商", "C": "依法必须进行招标的项目以非特定行业的奖项作为加分条件", "D": "依法必须进行招标的项目招标人限定投标人必须为国有企业"}, "answer": ["C"], "analysis": "A招标人可以组织也可以不组织现场踏勘，但如果组织应该组织所有潜在投标人参加，不是部分。BD歧视待遇。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1525", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "【2018年真题】根据《招标投标法》，可以确定中标人的主体是（ ）。", "options": {"A": "经招标人授权的招标代理机构", "B": "建设行政主管部门", "C": "经招标人授权的评标委员会", "D": "招标投标有形市场"}, "answer": ["C"], "analysis": "本题考查确定中标人的主体。招标人根据评标委员会提出的书面评标报告和推荐的中标候选人确定中标人。招标人也可以授权评标委员会直接确定中标人。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1526", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "【2018年真题】根据《招标投标法》，中标通知书自（ ）发生法律效力。", "options": {"A": "发出之日", "B": "作出之日", "C": "盖章之日", "D": "收到之日"}, "answer": ["A"], "analysis": "本题考查中标通知书的规定。中标通知书发出后，招标人改变中标结果的，或者中标人放弃中标项目的，应当依法承担法律责任，故是从发出之日生效。4.履约保证金?招标文件要求中标人提交履约保证金的，中标人应当提交?履约保证金不得超过中标合同金额的10%（投标保证金不超过合同价的2%）", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1527", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "【2018年真题】根据《招标投标法实施条例》，履约保证金的上限是中标合同金额的（ ）。", "options": {"A": "2%", "B": "5%", "C": "10%", "D": "20%"}, "answer": ["C"], "analysis": "本题考查履约保证金的规定。履约保证金不得超过中标合同金额的10%。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1528", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "【2017年真题】关于招标文件澄清或者修改的说法，正确的是（ ）", "options": {"A": "招标文件的效力高于其澄清或修改文件", "B": "澄清或者修改的内容可能影响投标文件编制的，招标人应在投标截止时间至少15日前澄清或者修改", "C": "澄清或者修改可以以口头形式通知所有获取招标文件的潜在投标人", "D": "澄清或者修改通知至投标截止时间不足15日的，在征得全部投标人同意后，可按原投标截止时间开标"}, "answer": ["B"], "analysis": "本题考查招标文件的澄清或修改的规定。如不足15日，应顺延投标截止时间。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1529", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "【2017年真题】关于投标文件撤回和撤销的说法，正确的是（ ）", "options": {"A": "投标人可以选择电话或书面方式通知招标人撤回投标文件", "B": "招标人收取的投标保证金，应当自收到投标人撤回通知之日起10日内退还", "C": "投标截止时间后投标人撤销投标文件的，招标人应当退还投标保证金", "D": "投标人撤回已提交的投标文件，应当在投标截止时间前通知招标人"}, "answer": ["D"], "analysis": "本题考查投标文件的撤回与撤销。投标人撤回已提交的投标文件，应当在投标截止时间前书面通知招标人。投标人撤销投标文件，是在投标截止时间之后，后果是被扣留投标保证金。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1530", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "【2017年真题】关于投标文件的送达与签收的说法，正确的是（ ）。", "options": {"A": "投标人应当在投标截止时间前，将投标文件送达投标地点", "B": "招标人签收投标文件后，可以开启投标文件", "C": "投标截止时间后送达的投标文件，招标人不得拒收", "D": "未按招标文件要求密封的投标文件，招标人不得拒收"}, "answer": ["A"], "analysis": "本题考查投标文件的送达与签收。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1531", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "(2013年)关于招标文件的编制，下列说法中错误的是()。", "options": {"A": "当未进行资格预审时招标文件应包括招标公告", "B": "应规定重新招标和不再招标的条件", "C": "招标控制价应在招标时(或在招标文件中)一并公布", "D": "投标人须知前附表与投标人须知正文内容有抵触的以投标人须知前附表为准"}, "answer": ["D"], "analysis": "标人须知前附表不得与投标人须知正文内容有抵触。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1532", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "(2014年)在招标投标过程中，载明获取方式的应是（）。", "options": {"A": "招标公告", "B": "资格预审公告", "C": "招标文件", "D": "投标文件"}, "answer": ["A"], "analysis": "本题考查的是招标文件的编制内容。(1)招标公告或投标邀请书）。当未进行资格预审时，招标文件中应包括招标公告。当进行资格预审时，招标文件中应包括投标邀请书，该邀请书可代替资格预审通过通知书，以明确投标人已具备了在某具体项目某具体标段的投标资格，其他内容包括招标文件的获取、投标文件的递交等。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1533", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "(2016年)关于暂列金额，下列说法中正确的是（ ）。", "options": {"A": "用于必须要发生但暂时不能确定价格的项目", "B": "由承包人支配，按签证价格结算", "C": "不能用于因工程变更而发生的索赔支付", "D": "不同专业预留的暂列金额应分别列项"}, "answer": ["D"], "analysis": "暂列金额是指招标人暂定并包括在合同中的一笔款项。用于工程合同签订时尚未确定或者不可预见的所需材料、工程设备、服务的采购，施工中可能发生的工程变更、合同约定调整因素出现时的合同价款调整以及发生的索赔、现场签证确认等的费用。 暂估价是招标人在招标文件中提供的用于支付必然要发生但暂时不能确定价格的材料、工程设备的单价以及专业工程的金额。 由于暂列金额由招标人支配，实际发生后才得以支付。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1534", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "(2010年)关于工程招标的性质，下列说法中正确的是()。", "options": {"A": "招标是要约", "B": "投标是承诺", "C": "招标公告是要约", "D": "中标通知书是承诺"}, "answer": ["D"], "analysis": "招标人首先提供招标文件，是一个要约邀请的活动，在招标件中招标人要对投标人的投标报价进行约束，这一约束就是招标控制价。招标人在招标时，把合同条款的主要内容纳入招标文件中，对投标报价的编制办法和“ 要求及合同价款的约定、调整和支付方式已做了详细说明，如采用“单价计价”方式、 “总价计价”方式或“成本加酬金计价”的方式发包，在招标文件内均已明确。投标人递交投标文件是个要约的活动，投标文件要包括投标报价这一实质内容，投标人在获得招标文件后按其中的规定和要求、根据自己的实力和市场因素等确定投标报价，报价应满足业主的要求并且不髙于招标控制价。招标人组织评标委员会对合格的投标文件进行评标，确定中标人，经过评标修正后的中标人的投标报价即为中标价，发出中标通知书的行为是一 个承诺的活动。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1535", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "(2010年)下列关于招标控制价的说法中，正确的是()。", "options": {"A": "招标控制价必须由招标人编制", "B": "招标控制价只需公布总价", "C": "招标人不得对招标控制价提出异议", "D": "招标控制价不应上调或下浮"}, "answer": ["D"], "analysis": "(3)招标控制价应当依据工程量清单、工程计价有关规定和市场价格信息等编制。招标控制价应在招标文件中公布，对所编制的招标控制价不得进行上浮或下调。招标人应当在招标时公布招标控制价的总价，以及各单位工程的分部分项工程费、措施项目费、其他项目 费增值税。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1536", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "(2014年)关于招标控制价及其编制，下列说法中正确的是（）", "options": {"A": "招标人不得拒绝高于招标控制价的投标报价", "B": "当重新公布招标控制价时，原投标截止期不变", "C": "经复核认为招标控制价误差大于±3%时，投标人应责成招标人改正", "D": "投标人经复核认为招标控制价未按规定编制的，应在招标控制价公布后5日内提出投诉"}, "answer": ["D"], "analysis": "题考查的是招标控制价的编制。A选项招标人应否决高于招标控制价的投标价，B选项重新公布控制价时，若重新公布之日起至原投标截止期不足15天的应延长投标截止期。C选项，不应由投标人责成改正。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1537", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "(2016年)根据《标准施工招标文件》（2007年版），关于“分包和偏差问题处理”的内容应包括于（ ）之中。", "options": {"A": "招标公告", "B": "投标人须知", "C": "评标办法", "D": "合同条款与格式"}, "answer": ["B"], "analysis": "(2)投标人须知。投标人须知包括10个内容：1)总则。主要包括项目概况、资金来源和落实情况、招标范围、计划工期和质量要求的描述，对投标人资格要求的规定，对费用承担、保密、语言文字、计量单位等内容的约定，对踏勘现场、投标预备会的要求，以及对分包和偏离问题的处理。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1538", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "(2010年)某施工企业参加一市政道路工程投标，该企业的投标报价为00万元，则其应交的投标保证金为()万元。", "options": {"A": "30", "B": "60", "C": "80", "D": "120"}, "answer": ["C"], "analysis": "投标保证金的数额不得超过项目估算价的2%，且最髙不超过80万元。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1539", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "(2010年)工程量清单计价模式下，确定分部分项工程单价的工作包括：①分析各清单项目的工程内容，②确定计算基础，③计算人工、材料、机械费用，④计算工程内容的工程量与清单单位含量，⑤计算综合单价。对上述工作先后顺序的排列，正确的是()。", "options": {"A": "①②④⑤③", "B": "②①④③⑤", "C": "①②④⑧⑤", "D": "②①④⑤③"}, "answer": ["B"], "analysis": "分部分项工程单价确定的步骤为：①确定计算基础；②分析每一清单项目的工程内容；③计算工程内容的工程数量与清单单位的含量；④分部分项工程人工、材料、机械费用的计算；⑤计算综合单价。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1540", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "(2013年)下列情形中，属于投标人相互串通投标的是()。", "options": {"A": "不同投标人的投标报价呈现规律性差异", "B": "不同投标人的投标文件由同一单位或个人编制", "C": "不同投标人委托了同一单位或个人办理某项投标事宜", "D": "投标人之间约定中标人"}, "answer": ["D"], "analysis": "有下列情形之一的，属于投标人相互串通投标：①投标人之间协商投标报价等投标文件的实质性内容；②投标人之间约定中标人；③投标人之间约定部分投标人放弃投标或者中标；④属于同一集团、协会、商会等组织成员的投标人按照该组织要求协同投标；⑤投标人之间为谋取中标或者排斥特定投标人而采取的其他联合行动。 其他的是视为。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1569", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "建设项目招标投标是国际上广泛采用的（ ）择优选择工程的主要交易方式。", "options": {"A": "业主", "B": "承包商", "C": "单位", "D": "个人"}, "answer": ["A"], "analysis": "招标投标是商品经济中的一种竞争性市场交易方式，通常适用于大宗交易。它的特点是由唯一的买主(或卖主)设定标的，招请若干个卖主(或买主)通过报价进行竞争，从中选择优胜者与之达成交易协议，随后按协议实现标的。工程建设项目招标投标是国际上广泛采用的建设项目业主择优选择工程承包商或材料设备供应商的主要交易方式 。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1570", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "下列建设项目中，属于依法应当进行公开招标范围的是（ ）。", "options": {"A": "涉及国家安全、国家秘密的项目", "B": "使用国有企业事业单位资金，并且该资金占控股或者主导地位的项目", "C": "使用企业事业单位自有资金的项目", "D": "使用上市公司资金的项目"}, "answer": ["B"], "analysis": "《招标投标法》规定，涉及国家安全、国家秘密、抢险救灾或者属于利用扶贫资金实行以工代赈、需要使用农民工等特殊情况，不适宜进行招标的项目，按照国家有关规定可以不进行招标。A选项不属于公开招标。 《招标投标法实施条例》明确规定，国有资金占控股或者主导地位的依法必须进行招标的项目，应当公开招标。B选项正确，C选项不完整。 D选项不符合必须进行公开招标的项目。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1571", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "根据《工程建设项目施工招标投标办法》，关于投标保证金说法正确的是（ ）。", "options": {"A": "投标保证金最高不得超过50万元", "B": "招标人发了中标通知书，投标保证金的有效期自动终止", "C": "投标保证金只能以现金的方式提交", "D": "招标人不得挪用投标保证金"}, "answer": ["D"], "analysis": "招标人要求递交投标保证金的，应在招标文件中明确。投标保证金不得超过招标项目估算价的2%，且最高不得超过八十万元人民币。投标保证金有效期应当与投标有效期一致。依法必须进行招标的项目的境内投标单位，以现金或者支票形式提交的投标保证金应当从其基本账户转出。招标人不得挪用投标保证金。投标人不按要求提交投标保证金的，其投标文件作废标处理。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1572", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "根据我国《建设工程质量保证金管理暂行办法》有关规定，下列表述中错误的是（ ）。", "options": {"A": "缺陷责任期从工程通过竣(交)工验收之日起计算", "B": "由于发包人原因导致工程无法按规定期限进行竣(交)工验收的，在承包人提交竣(交)工验收报告90天后，工程自动进入缺陷责任期", "C": "全部或部分使用政府投资的建设项目，保证金按工程价款结算总额的3%预留", "D": "缺陷责任期内，承包人维修并承担相应费用后，不免除对工程的一般损失赔偿责任"}, "answer": ["C"], "analysis": "缺陷责任期从工程通过竣工验收之日起计算，合同当事人应在专用合同条款约定缺陷责任期的具体期限，但该期限最长不超过24个月。发包人累计扣留的质量保证金不得超过工程价款结算总额的3%。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1573", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "承包人的预付款保函的担保金额根据预付款扣回的数额（ ）。", "options": {"A": "相应减少", "B": "相应递增", "C": "逐渐失效", "D": "保持不变"}, "answer": ["A"], "analysis": "发包人在工程款中逐期扣回预付款后，预付款担保额度应相应减少，但剩余的预付款担保金额不得低于未被扣回的预付款金额 。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1574", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "在建设工程施工合同文件的组成中，（ ）是就工程建设的实施及相关事项，对合同当事人的权利义务做出的原则性约定。", "options": {"A": "专用条款", "B": "通用条款", "C": "协议书", "D": "附件"}, "answer": ["B"], "analysis": "通用合同条款是合同当事人根据《中华人民共和国建筑法》、《中华人民共和国合同法》等法律法规的规定，就工程建设的实施及相关事项，对合同当事人的权利义务做出的原则性约定。通用合同条款共计20条，具体条款分别为：一般约定、发包人、承包人、监理人、工程质量、安全文明施工与环境保护、工期和进度、材料与设备、试验与检验、变更、价格调整、合同价格、计量与支付、验收和工程试车、竣工结算、缺陷责任与保修、违约、不可抗力、保险、索赔和争议解决。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1575", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "根据《建设工程价款结算暂行办法》，在具备施工条件的前提下，发包人支付预付款的期限应是（ ）", "options": {"A": "不迟于约定的开工日期前的7天内", "B": "不迟于约定的开工日期后的7天内", "C": "不迟于约定的开工日期前的14天内", "D": "不迟于约定的开工日期后的14天内"}, "answer": ["A"], "analysis": "预付款的支付按照专用合同条款约定执行，但至迟应在开工通知载明的开工日期7天前支付。预付款应当用于材料、工程设备、施工设备的采购及修建临时工程、组织施工队伍进场等。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1576", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "关于保证(保修)金使用及返还的叙述不正确的是（ ）。", "options": {"A": "缺陷责任期内，承包人应认真履行合同约定的责任", "B": "承包人维修并承担相应费用后，免除对工程的一般损失赔偿责任", "C": "承包人已经提供履约担保的，发包人不得同时预留工程质量保证金", "D": "经查明属他人原因造成的缺陷，发包人负责组织维修，承包人不承担费用"}, "answer": ["B"], "analysis": "缺陷责任期内，由承包人原因造成的缺陷，承包人应负责维修，并承担鉴定及维修费用。如承包人不维修也不承担费用，发包人可按合同约定从保证金或银行保函中扣除，费用超出保证金额的，发包人可按合同约定向承包人进行索赔。承包人维修并承担相应费用后，不免除对工程的损失赔偿责任。发包人有权要求承包人延长缺陷责任期， 并应在原缺陷责任期届满前发出延长通知。但缺陷责任期(含延长部分)最长不能超过24个月。由他人原因造成的缺陷，发包人负责组织维修，承包人不承担费用，且发包人不得从保证金中扣除费用。缺陷责任期内，承包人认真履行合同约定的责任，到期后，承包人可向发包人申请返还保证金。在工程项目竣工前，承包人已经提供履约担保的，发包人不得同时预留工程质量保证金。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1577", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "《建筑工程施工合同(示范文本)》合同文件执行的优先顺序是（ ）。", "options": {"A": "合同协议书→合同通用条款→合同专用条款→技术标准和要求→已标价工程量清单或预算书", "B": "合同协议书→合同专用条款→合同通用条款→技术标准和要求→已标价工程量清单或预算书", "C": "技术标准和要求→合同协议书→合同专用条款→合同通用条款→已标价工程量清单或预算书", "D": "技术标准和要求→合同协议书→已标价工程量清单或预算书→合同通用条款→合同专用条款"}, "answer": ["B"], "analysis": "通用合同条款规定，组成合同的各项文件应互相解释，互为说明。除专用合同条款另有约定外，解释合同文件的优先顺序如下： ①合同协议书； ②中标通知书（如果有）； ③投标函及投标函附录（如果有）； ④专用合同条款及其附件； ⑤通用合同条款； ⑥技术标准和要求； ⑦图纸； ⑧已标价工程量清单或预算书； ⑨其他合同文件。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1578", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "承包人应在知道或应当知道索赔事件发生后（ ）天内，向监理人递交索赔意向通知书。", "options": {"A": "7", "B": "14", "C": "21", "D": "28"}, "answer": ["D"], "analysis": "承包人应在知道或应当知道索赔事件发生后28天内，向监理人递交索赔意向通知书，并说明发生索赔事件的事由；承包人未在前述28天内发出索赔意向通知书的，丧失要求追加付款和(或)延长工期的权利。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1579", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "在具备施工条件的前提下，发包人应在双方签订合同后一个月内或不迟于约定开工日期前（ ）内预付工程备料款。", "options": {"A": "10天", "B": "7天", "C": "15天", "D": "20天"}, "answer": ["B"], "analysis": "工程价款结算是指承包商在工程施工过程中，依据承包合同中关于付款的规定和已经完成的工程量，以预付备料款和工程进度款的形式，按照规定的程序向业主收取工程价款的一项经济活动。价款结算办法规定：在具备施工条件的前提下，业主应在双方签订合同后的一个月内或不迟于约定的开工日期前的7天内预付工程款。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1580", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "由于发包人原因导致工程无法按规定期限竣(交)工验收的，在承包人提交竣(交)工验收报告（ ）天后，工程自动进入缺陷责任期。", "options": {"A": "30", "B": "60", "C": "90", "D": "120"}, "answer": ["C"], "analysis": "因发包人原因导致工程无法按合同约定期限进行竣工验收的，在承包人提交竣工验收报告90天后，工程自动进入缺陷责任期；发包人未经竣工验收擅自使用工程的，缺陷责任期自工程转移占有之日起开始计算。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1581", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "由于承包人原因造成某项缺陷或损坏，使某项工程或工程设备不能按原定目标使用而需要再次检查、检验和修复的，发包人有权要求承包人相应延长缺陷责任期，但缺陷责任期最长不超过（ ）年。", "options": {"A": "2", "B": "3", "C": "5", "D": "6"}, "answer": ["A"], "analysis": "缺陷责任期内，由承包人原因造成的缺陷，承包人应负责维修，并承担鉴定及维修费用。如承包人不维修也不承担费用，发包人可按合同约定从保证金或银行保函中扣除，费用超出保证金额的，发包人可按合同约定向承包人进行索赔。承包人维修并承担相应费用后，不免除对工程的损失赔偿责任。发包人有权要求承包人延长缺陷责任期，并应在原缺陷责任期届满前发出延长通知。但缺陷责任期(含延长部分)最长不能超过24个月。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1582", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "某建筑工程钢筋综合用量1000t。施工合同中约定，结算时对钢筋综合价格涨幅±5%以上部分依据造价处发布的基准价调整价格差额。承包人投标报价2400元/t，投标期、施工期造价管理机构发布的钢筋综合基准价格分别为2500元/t、2800元/t，则需调增钢筋材料费用为（ ）万元。", "options": {"A": "17.5", "B": "28.0", "C": "30.0", "D": "40.0"}, "answer": ["A"], "analysis": "本题考查的是价格调整。需调增钢筋材料费用＝（2800－2500×1.05）×1000＝175000元＝17.5万元。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1584", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "根据《建设工程施工合同（示范文本）》，关于安全文明施工费，下列说法错误的是（ ）。", "options": {"A": "发包人应在开工后28天内预付安全文明施工费总额的50%，其余部分与进度款同期支", "B": "承包人对安全文明施工费应专款专用，不得挪作他用", "C": "发包人逾期支付安全文明施工费超过14天的，承包人有权向发包人发出要求预付的催告通知", "D": "安全文明施工费由发包人承担，发包人不得以任何形式扣减该部分费用"}, "answer": ["C"], "analysis": "本题考查的是施工合同示范文本。发包人逾期支付安全文明施工费超过7天的，承包人有权向发包人发出要求预付的催告通知。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1585", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "根据合同通用条款规定的文件解释优先顺序，下列文件中具有最优先解释权的是（ ）。", "options": {"A": "规范标准", "B": "中标通知书", "C": "合同协议书", "D": "设计文件"}, "answer": ["C"], "analysis": "本题考查的是施工合同示范文本。合同协议书优先解释合同文件。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1586", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "由于承包人原因导致工期延误的，对于计划进度日期后续施工的工程，在使用价格调整公式时，现行价格指数应采用（ ）。", "options": {"A": "计划进度日期的价格指数", "B": "实际进度日期的价格指数", "C": "A和B中较低者", "D": "A和B中较高者"}, "answer": ["C"], "analysis": "本题考查的是价格调整。因承包人原因未按期竣工的，对合同约定的竣工日期后继续施工的工程，在使用价格调整公式时，应采用计划竣工日期与实际竣工日期的两个价格指数中较低的一个作为现行价格指数。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1587", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "关于施工承包合同中缺陷责任与保修的说法，正确的是（ ）。", "options": {"A": "缺陷责任期自实际竣工日期起计算，最长不超过12个月", "B": "由他人原因造成的缺陷，发包人负责组织维修，承包人不承担费用，且发包人不得从保证金中扣除费用", "C": "因发包人原因导致工程无法按合同约定期限进行竣工验收的，缺陷责任期自竣工验收合格之日开始计算", "D": "发包人未经竣工验收擅自使用工程的，缺陷责任期自承包人提交竣工验收申请报告之日开始计算"}, "answer": ["B"], "analysis": "本题考查的是施工合同示范文本。缺陷责任期自通过竣工验收之日起计算，最长不超过24个月。因发包人原因导致工程无法按合同约定期限进行竣工验收的，承包人提交竣工验收报告90天后，工程自动进行缺陷责任期。发包人未经竣工验收擅自使用工程的，缺陷责任期自转移占有之日开始计算。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1588", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "按照索赔程序，承包人首先要完成的工作应当是（ ）。", "options": {"A": "向发包人递交索赔报告", "B": "建立赔偿档案", "C": "确定判定索赔成立的原则", "D": "向发包人发出书面索赔意向通知"}, "answer": ["D"], "analysis": "本题考查的是施工合同示范文本。按照索赔程序，承包人首先要完成的工作应当是向发包人发出书面索赔意向通知。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1589", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "下列在施工合同履行期间由不可抗力造成的损失中，应由承包人承担的是（ ）", "options": {"A": "因工程损害导致的第三方人员伤亡", "B": "因工程损害导致的承包人人员伤亡", "C": "工程设备的损害", "D": "应监理人要求承包人照管工程的费用"}, "answer": ["B"], "analysis": "本题考查的是施工合同示范文本。因工程损害导致的第三方人员伤亡由发包人承担。工程设备的损害由发包人承担。应监理人要求承包人照管工程的费用由发包人承担。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1590", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "某工程合同价为 300 万元， 本期完成合同价款 100 万元， 合同约定： 采用调值公式进行动态结算， 其中固定要素比重为 0.2， 调价要素分为 A、 B、 C 三类， 分别占合同价的比重为 0.15、 0.35、 0.3， 结算时价格指数分别增长了 20%、 15%、 25%， 则该工程需要调整的价款差额为（ ） 万元", "options": {"A": "115.75", "B": "19.75", "C": "15.75", "D": "120.75"}, "answer": ["C"], "analysis": "100×[0.2+（0.15×1.2+0.35×1.15+0.3×1.25） -1]=15.75 万元", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1591", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "关于建设项目竣工结清阶段承包人索赔的权利和期限，下列说法中正确的是（ ）。", "options": {"A": "承包人接受竣工结算支付证书后再无权提出任何索赔", "B": "承包人只能提出工程接收证书颁发前的索赔", "C": "承包人提出索赔的期限自缺陷责任期满时终止", "D": "承包人提出索赔的期限自接受最终支付证书时终止"}, "answer": ["D"], "analysis": "本题考查的是施工合同示范文本。承包人提出索赔的期限自接受最终支付证书时终止。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1592", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "下列措施项目中宜采用分部(分项)工程量清单的方式编制的是（ ）。", "options": {"A": "非夜间施工照明", "B": "施工排水、降水", "C": "已完工程及设备保护", "D": "二次搬运"}, "answer": ["B"], "analysis": "有些措施项目是可以计算工程量的，如脚手架工程，混凝土模板及支架(撑) ，垂直运输、超高施工增加，大型机械设备进出场及安拆，施工排水、降水等，这类措施项目按照分部分项工程量清单的方式采用综合单价计价，更有利于措施费的确定和调整。措施项目中可以计算工程量的项目(单价措施项目)宜采用分部分项工程项目清单的方式编制，列出项目编码、项目名称、项目特征、计量单位和工程量；不能计算工程量的项目(总价措施项目)，以\"项\"为计量单位进行编制。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1593", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "工程量清单是招标文件的组成部分，工程量清单的组成不包括（ ）。", "options": {"A": "分部分项工程工程量清单", "B": "措施项目清单", "C": "其他项目清单", "D": "直接工程费用清单"}, "answer": ["D"], "analysis": "工程量清单作为招标文件的组成部分，主要由分部分项工程量清单、措施项目清 单、其他项目清单、规费和增值税项目清单组成。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1594", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "项目编码是分部(分项)工程量清单项目名称的数字标识，应采用（ ）位阿拉伯数字表示。", "options": {"A": "13", "B": "12", "C": "11", "D": "10"}, "answer": ["B"], "analysis": "项目编码是分部分项工程项目和措施项目清单名称的阿拉伯数字标识。分部分项工程量清单项目编码以五级编码设置，用十二位阿拉伯数字表示。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1597", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "在分部(分项)工程项目清单中，表示专业工程分类编码的是（ ）。", "options": {"A": "第一级编码", "B": "第二级编码", "C": "第三级编码", "D": "第四级编码"}, "answer": ["A"], "analysis": "分部分项工程量清单项目编码以五级编码设置，用十二位阿拉伯数字表示。最新题库，考前【黑钻押题】，金考典软件考前更新，下载链接 www.jinkaodian.com 一、二、三、四级编码为全国统一，即一至九位按计算规范附录的规定设置；第五级即十至十二位应根据拟建工程的工程量清单项目名称设置，不得有重码，这三位清单项目编码由招标人针对招标工程项目具体编制，并应自001其顺序编制。各级编码代表的含义如下: (1) 第一级表示专业工程代码(分二位)； (2) 第二级表示附录分类顺序码(分二位) ; (3) 第三级表示分部工程顺序码(分二位) ; (4) 第四级表示分项工程项目名称顺序码(分三位) ; (5) 第五级表示工程量清单项目名称顺序码(分三位)。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1599", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "编制工程量清单时，招标人自行供应材料、工程设备的，总承包服务费按招标人供应材料、工程设备价值的（ ）计算。", "options": {"A": "1%", "B": "1．5%", "C": "3%", "D": "5%"}, "answer": ["A"], "analysis": "编制最高投标限价时，总承包服务费应按照省级或行业建设主管部门的规定计算，或者根据行业经验标准计算。针对一般情况，可参考的常用标准如下： 1)招标人仅要求对分包的专业工程进行总承包管理和协调时，按分包的专业工程估算造价的1.5%计算。 2)招标人要求对分包的专业工程进行总承包管理和协调，并同时要求提供配合服务时，根据招标文件中列出的配合服务内容和提出的要求，按分包的专业工程估算造价的3%~5%计算。 3)招标人自行供应材料、工程设备的，按招标人供应材料、工程设备价值的1%计算。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1601", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "建设工程施工投标报价程序中，确定基础标价的紧后工作是（ ）。", "options": {"A": "标书编制", "B": "选择报价策略调整标价", "C": "招标文件研究", "D": "计算投标报价"}, "answer": ["B"], "analysis": "建设工程施工投标报价程序中，确定基础标价的紧后工作是选择报价策略调整标价。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1602", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "（ ）报价技巧，可以迷惑对手，提高中标概率。但对投标单位的分析判断和决策能力要求较高。", "options": {"A": "不平衡报价法", "B": "多方案报价法", "C": "突然降价法", "D": "无利润报价法"}, "answer": ["C"], "analysis": "本题考查的是投标报价编制。突然降价法，先按照一般情况报价或表现出自己对该工程兴趣不大，等到投标截止时，再突然降价。采用此本报价技巧，可以迷惑对手，提高中标概率。但对投标单位的分析判断和决策能力要求较高。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1603", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "关于缺陷责任期内的工程维修及费用承担，下列说法中正确的是（ ）。", "options": {"A": "不可抗力造成的缺陷，发包人负责维修，从质量保证金中扣除费用", "B": "承包人造成的缺陷，承包人负责维修并承担费用后，可免除其对工程的一般损失赔偿责任", "C": "发承包双方对缺陷责任有争议的，按质量鉴定机构的鉴定结论，由责任方承担维修费，另一方承担鉴定费", "D": "承包人造成工程无法使用而需再次检验、修复的，发包人有权要求承包人延长缺陷责任期"}, "answer": ["D"], "analysis": "本题考查的是质量保证金的使用及返还。由他人及不可抗力原因造成的缺陷，发包人负责组织维修，承包人不承担费用，且发包人不得从保证金中扣除费用。如发包人委托承包人维修的，发包人应该支付相应的维修费用。有争议，可进行鉴定，责任方承担费用。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1604", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "根据《标准施工合同》，当中标通知书、图纸和专用合同条款出现含义或内容矛盾时，合同文件优先解释的顺序是（ ）。", "options": {"A": "图纸→专用合同条款→中标通知书", "B": "图纸→中标通知书→专用合同条款", "C": "中标通知书→图纸→专用合同条款", "D": "中标通知书→专用合同条款→图纸"}, "answer": ["D"], "analysis": "解释合同文件的优先顺序如下: (1)合同协议书; (2)中标通知书(如果有) ; (3)投标函及其附录(如果有) ; (4)专用合同条款及其附件; (5)通用合同条款; (6)技术标准和要求; (7)图纸; (8)己标价工程量清单或预算书; (9)其他合同文件。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1605", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "根据《标准施工合同》，就图纸、通用合同条款和已标价的工程量清单而言，优先解释的顺序是（ ）。", "options": {"A": "已标价的工程量清单—通用合同条款—图纸", "B": "已标价的工程量清单—图纸—通用合同条款", "C": "通用合同条款—已标价的工程量清单—图纸", "D": "通用合同条款—图纸—已标价的工程量清单"}, "answer": ["D"], "analysis": "解释合同文件的优先顺序如下: (1)合同协议书; (2)中标通知书(如果有) ; (3)投标函及其附录(如果有) ; (4)专用合同条款及其附件; (5)通用合同条款; (6)技术标准和要求; (7)图纸; (8)己标价工程量清单或预算书; (9)其他合同文件。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1606", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "建设工程在缺陷责任期内，由第三方原因造成的缺陷（ ）。", "options": {"A": "应由承包人负责维修，费用从质量保证金中扣除", "B": "应由承包人负责维修，费用由发包人承担", "C": "发包人委托承包人维修的，费用由第三方支付", "D": "发包人委托承包人维修的，费用由发包人支付"}, "answer": ["D"], "analysis": "本题考查的是质量保证金的使用及返还。由他人及不可抗力原因造成的缺陷，发包人负责组织维修，承包人不承担费用，且发包人不得从保证金中扣除费用。如发包人委托承包人维修的，发包人应该支付相应的维修费用。有争议，可进行鉴定，责任方承担费用。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1607", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "关于缺陷责任期与保修期，下列说法中正确的是（ ）。", "options": {"A": "缺陷责任期就是保修期", "B": "屋面防水工程的保修期为5年", "C": "结构工程的保修期为10年", "D": "给排水管道的保修期为5年"}, "answer": ["B"], "analysis": "本题考查的是缺陷责任期的概念和期限。基础、主体合理使用年限；与“水”有关的5年；供热、供冷系统，为2个周期；管线、管道、安装、装修，2年。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1845", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "根据《建设工程施工合同（示范文本），（GF-2017-0201）》，除专有合同条款另有规定外，预付款扣回的方式是（ ）。", "options": {"A": "在进度付款中按比例扣回", "B": "在进度付款中等额扣回", "C": "在第一次进度款中全额扣回", "D": "在最后一次进度款中全额扣回"}, "answer": ["A"], "analysis": "【考点来源】本题考查的是建设工程施工合同（示范文本）【选项分析】根据《建设工程施工合同（示范文本）》的相关规定，除专业合同条款另有约定外，预付款在进度付款中同比例扣回。", "tags": [], "source": "二、《建设工程施工合同（示范文本）》的主要内容", "src": "好题库"}, {"id": "mgmt_hqwx_0198", "date": "2026-07-09", "chapter": "g06", "type": "single", "stem": "有关联合体承包模式和合作体承包模式的说法，正确的是（ ）。", "options": {"A": "采用联合体承包模式，建设单位承担风险较大", "B": "采用联合体承包模式，不利于工程造价控制", "C": "采用合作体承包模式，建设单位需签订工程承包意向合同、工程承包合同", "D": "采用合作体承包模式，建设单位组织协调工作量大"}, "answer": ["C"], "analysis": "联合体承包模式和合作体承包模式的特点是： （1）采用联合体承包模式，建设单位承担风险较小；采用合作体承包模式，建设单位承担风险较大。 （2）采用联合体承包模式，有利于工程造价控制。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0202", "date": "2026-07-09", "chapter": "g06", "type": "single", "stem": "工程项目实现有条件的“边设计、边施工”的承包模式是（ ）。", "options": {"A": "总分包模式", "B": "CM承包模式", "C": "Partnering模式", "D": "合作体承包模式"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是CM模式与Partnering模式 【选项分析】CM ( Construction Management)模式是指由建设单位委托一家CM单位承担项目管理工作，该CM单位以承包商身份进行施工管理，并在一定程度上影响工程设计活动，组织快速路径(Fast-Track)的生产方式，使工程项目实现有条件的“边设计、边施工”。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0205", "date": "2026-07-09", "chapter": "g06", "type": "single", "stem": "CM承包模式的特点是（ ）。", "options": {"A": "CM单位是以发包人的身份进行施工管理", "B": "采用流水施工法施工", "C": "CM单位不会影响工程设计活动", "D": "采用快速路径法施工"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是CM模式与Partnering模式 【选项分析】CM承包模式是指由建设单位委托一家CM单位承担项目管理工作，该CM单位以承包单位的身份进行施工管理，并在一定程度上影响工程设计活动，组织快速路径(Fast-Track)的生产方式，使工程项目实现有条件的“边设计、边施工”。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0312", "date": "2026-07-09", "chapter": "g06", "type": "single", "stem": "公开招标方式的缺点是（ ）。", "options": {"A": "投标竞争的激烈程度较差", "B": "对投标申请者进行资格预审和评标的工作量大", "C": "可能排除某些在技术上或报价上有竞争力的承包商参与投标", "D": "可能会提高中标合同价"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是工程施工招标方式 【选项分项】公开招标方式的缺点是，准备招标、对投标申请者进行资格预审和评标的工作量大，招标时间长、费用高。同时，参加竞争的投标者越多，中标的机会就越小；投标风险越大，损失的费用也就越多，而这种费用的损失必然会反映在标价中，最终会由招标人承担，故这种方式在一些国家较少采用。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0314", "date": "2026-07-09", "chapter": "g06", "type": "single", "stem": "下列选项中，关于《建设工程施工合同（示范文本）》的说法，正确的是（ ）。", "options": {"A": "《建设工程施工合同（示范文本）》由通用合同条款和专用合同条款组成", "B": "《建设工程施工合同（示范文本）》是强制性文本", "C": "合同协议书的内容集中约定了合同当事人基本的合同权利义务", "D": "通用合同条款的是对专用合同条款原则性约定的细化、完善、补偿、修改或另行约定的条款"}, "answer": ["C"], "analysis": "【内容考查】本题考查的是《建设工程施工合同（示范文本）》概述 【选项分项】A.《建设工程施工合同（示范文本）》GF-2017-0201由合同协议书、通用合同条款和专用合同条款三部分组成；B.《建设工程施工合同（示范文本）》是非强制性文本；D.专用合同条款的是对通用合同条款原则性约定的细化、完善、补偿、修改或另行约定的条款。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0316", "date": "2026-07-09", "chapter": "g06", "type": "single", "stem": "根据《建设工程施工合同示范文本》中的合同条款，签约合同价包含的内容有（ ）。", "options": {"A": "变更价款", "B": "暂列金额", "C": "索赔费用", "D": "结算价款"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是《建设工程施工合同（示范文本）》的主要内容 【选项分析】签约合同价：是发包人和承包人在合同协议书中确定的总金额，包括安全文明施工费、暂估价及暂列金额等。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0317", "date": "2026-07-09", "chapter": "g06", "type": "single", "stem": "某项目施工合同约定，承包人承租的水泥价格风险幅度为±5%，超出部分采用造价信息法调差，已知投标人投标价格、基准期发布价格为440元/t、450元/t，2018年3月的造价信息发布价为430元/t，则该月水泥的实际结算价格为（ ）元/t。", "options": {"A": "418", "B": "427.5", "C": "430", "D": "440"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是《建设工程施工合同（示范文本）》的主要内容 【选项分项】此题中，投标报价为440元/t，3月份的价格下降，应以较低的投标报价为基准价基础计算合同月的风险幅度。440×（1-5%）=418元/t，未超过投标报价5%的风险幅度范围因此不作调整。因此，正确选项为D。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0320", "date": "2026-07-09", "chapter": "g06", "type": "single", "stem": "根据《建设项目工程施工合同（示范文本）》，合同约定由承包人向发包人提交履约保函时，发包人应向承包人提交（ ）担保。", "options": {"A": "支付", "B": "预付款", "C": "履约", "D": "变更"}, "answer": ["A"], "analysis": "【内容考查】本题考查的是《建设工程施工合同（示范文本）》的主要内容 【选项分项】除专用合同条款另有约定外，发包人要求承包人提供履约担保的，发包人应当向承包人提供支付担保。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0321", "date": "2026-07-09", "chapter": "g06", "type": "single", "stem": "根据《标准施工招标文件》，下列合同文件的内容不一致时，除专用合同条款另有约定外，应以（ ）为准。", "options": {"A": "投标函", "B": "中标通知书", "C": "专用合同条款", "D": "通用合同条款"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是《建设工程施工合同（示范文本）》概述 【选项分析】除专用合同条款另有约定外，解释合同文件的优先顺序如下： 1）合同协议书； 2）中标通知书（如有时）； 3）分包人的投标函或报价书； 4）除总包合同价款之外的总包合同文件； 5）合同专用条款； 6）合同通用条款； 7）合同工程建设标准、图纸； 8）合同履行过程中承包人、分包人协商一致的其他书面文件。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0322", "date": "2026-07-09", "chapter": "g06", "type": "single", "stem": "根据《建设工程施工合同（示范文本）》，下列选项中说法错误的是（ ）。", "options": {"A": "发包人逾期支付安全文明施工费超过7天的，承包人有权暂停施工", "B": "除专用合同条款另有约定外，发包人应在开工后28天内支付安全文明施工费总额的50%", "C": "承包人对安全文明施工费应专款专用，不得挪作他用", "D": "安全文明施工费由发包人承担，发包人不得以任何方式扣减部分费用"}, "answer": ["A"], "analysis": "【内容考查】本题考查的是《建设工程施工合同（示范文本）》的主要内容 【选项分项】发包人逾期支付安全文明施工费超过7天的，承包人有权向发包人发出要求预付的催告通知，发包人收到通知后7天内仍未支付的，承包人有权暂停施工，并按合同中“发包人违约的情形”执行。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0323", "date": "2026-07-09", "chapter": "g06", "type": "single", "stem": "【陕西】根据《建设工程施工合同（示范文本）》，因发包人原因造成监理人未能在计划开工日期之日起（ ）日内发出开工通知的，承包人有权解除合同。", "options": {"A": "30", "B": "60", "C": "45", "D": "90"}, "answer": ["D"], "analysis": "【考点来源】本题考查的是建设工程施工合同（示范文本） 【选项分析】除专用合同条款另有约定外，因发包人原因造成监理人未能在计划开工日期之日起90天内发出开工通知的，承包人有权提出价格调整要求，或者解除合同。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0330", "date": "2026-07-09", "chapter": "g06", "type": "single", "stem": "根据《陕西省建设工程工程量清单计价规则》，规费的内容包括社会保障保险、住房公积金和（ ）。", "options": {"A": "教育费附加", "B": "地方教育附加", "C": "危险作业意外伤害保险", "D": "城市维护建设税"}, "answer": ["C"], "analysis": "【考点来源】本题考查的是规费、税金（增值税）项目清单 【选项分析】根据《陕西省建设工程工程量清单计价规则》，规费的内容包括社会保障保险、住房公积金和危险作业意外伤害保险。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0331", "date": "2026-07-09", "chapter": "g06", "type": "single", "stem": "对于不能计算工程量的措施项目，当按施工方案计算措施费时，若无“计算基础”和“费率”数值，则（ ）。", "options": {"A": "以定额计价为计算基础，以国家、行业、地区定额中相应的费率计算金额", "B": "以“定额人工费+定额机械费”为计算基础，以国家、行业、地区定额中相应费率计算金额", "C": "只填写“金额”数值，在备注中说明施工方案出处或计算方法", "D": "备注中说明中计算方法，补充填写“计算基础”和“费率”"}, "answer": ["C"], "analysis": "【内容考查】本题考查的是措施项目清单的标准袼式 【选项分项】按施工方案计算的措施费，若无“计算基础”和“费率”的数值，也可只填“金额”数值，但应在备注栏说明施工方案出处或计算方法。因此，正确选项为C。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0332", "date": "2026-07-09", "chapter": "g06", "type": "single", "stem": "在工程量清单的其他项目清单中，包含了为解决现场发生的零星工作的计价而设立的（ ）。", "options": {"A": "暂列金额", "B": "暂估价", "C": "计日工", "D": "总承包服务费"}, "answer": ["C"], "analysis": "【内容考查】本题考查的是计日工 【选项分析】计日工是为了解决现场发生的零星工作的计价而设立的。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0333", "date": "2026-07-09", "chapter": "g06", "type": "single", "stem": "在工程量清单中，最能体现分部分项工程项目自身价值的本质是（ ）。", "options": {"A": "项目特征", "B": "项目编码", "C": "项目名称", "D": "项目计量单位"}, "answer": ["A"], "analysis": "【内容考查】本题考查的是项目特征 【选项分析】项目特征是构成分部分项工程项目，措施项目自身价值的本质特征。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0334", "date": "2026-07-09", "chapter": "g06", "type": "single", "stem": "发包人仅要求对分包的专业工程进行总承包管理和协调时，总包单位可按分包的专业工程造价的（ ）向发包方计取总承包管理和协调费。", "options": {"A": "1.5%", "B": "1-3%", "C": "2-3%", "D": "2-4%"}, "answer": ["A"], "analysis": "【内容考查】本题考查的是最高投标限价的编制内容 【选项分析】招标人仅要求对分包的专业工程进行总承包管理和协调时，按分包的专业工程估算造价的1.5%计算。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0336", "date": "2026-07-09", "chapter": "g06", "type": "single", "stem": "编制招标工程量清单时，根据工程的复杂程度、设计深度、工程环境条件（包括地质、水文、气候条件等）进行估算的清单项目是（ ）。", "options": {"A": "措施项目清单", "B": "暂列金额", "C": "专业工程暂估价", "D": "计日工"}, "answer": ["B"], "analysis": "暂列金额可根据工程的复杂程度、设计深度、工程环境条件（包括地质、水文、气候条件等）进行估算。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0338", "date": "2026-07-09", "chapter": "g06", "type": "single", "stem": "投标报价时，发承包双方对于主要由市场价格波动导致的价格风险，应（ ）。", "options": {"A": "由承包人全部承担", "B": "由发包人全部承担", "C": "发承包双方各承担50%", "D": "在招标文件或合同中约定范围和幅度，合理分摊"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是分部分项工程和措施项目清单与计价表的编制 【选项分析】对于主要由市场价格波动导致的价格风险，如工程造价中的建筑材料、燃料等价格风险，发承包双方应当在招标文件中或在合同中对此类风险的范围和幅度予以明确约定，进行合理分摊。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0339", "date": "2026-07-09", "chapter": "g06", "type": "single", "stem": "投标人在投标前期研究招标文件时，对合同形式进行分析的主要内容为（ ）。", "options": {"A": "承包商任务", "B": "计价方式", "C": "付款办法", "D": "合同价款调整"}, "answer": ["B"], "analysis": "【选项分析】合同形式分析内容是主要分析承包方式（如分项承包、施工承包、设计与施工总承包和管理承包等）；计价方式（如固定合同价格、可调合同价格和成本加酬金确定的合同价格等）。A、C、D均属于合同条款分析的内容。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0340", "date": "2026-07-09", "chapter": "g06", "type": "single", "stem": "招标工程量清单是招标文件的组成部分，其准确性由（ ）负责。", "options": {"A": "招标代理机构", "B": "招标人", "C": "编制工程量清单的造价咨询机构", "D": "招标工程量清单的编制人"}, "answer": ["B"], "analysis": "采用工程量清单方式招标，招标工程量清单必须作为招标文件的组成部分，其准确性和完整性由招标人负责。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0341", "date": "2026-07-09", "chapter": "g06", "type": "single", "stem": "关于工程施工投标报价过程中的工程量的复核，下列说法正确的是（ ）。", "options": {"A": "复核的准确程度不会影响施工方法的选用", "B": "复核的目的在于修改工程量清单中的工程量", "C": "复核有助于防止由于物资少购带来的停工待料", "D": "复核中发现的遗漏和错误须向招标人提出"}, "answer": ["C"], "analysis": "【内容考查】本题考查的是复核工程量 【选项分析】复核的准确程度会影响施工方法的选用；复核的目的不是在于修改工程量清单中的工程量；针对工程量清单中工程量的遗漏或错误，是否向招标人提出修改意见取决于投标策略。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0342", "date": "2026-07-09", "chapter": "g06", "type": "single", "stem": "投标人复核招标工程量清单时发现了遗漏，是否向招标人提出修改意见取决于（ ） 。", "options": {"A": "招标文件规定是否允许提出增补", "B": "遗漏工程量的大小", "C": "投标人的投标策略", "D": "遗漏项目是否在工程量计算规范附录中有列项"}, "answer": ["C"], "analysis": "【内容考查】本题考查的是复核工程量 【选项分析】针对招标工程量清单中工程量的遗漏或错误，是否向招标人提出修改意见取决于投标策略。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0344", "date": "2026-07-09", "chapter": "g06", "type": "single", "stem": "在不影响工程总报价的前提下，通过调整内部各个项目的报价，以达到既不提高总报价、不影响中标，又能在结算时得到更理想的经济效益的报价方法是（ ）。", "options": {"A": "突然降价法", "B": "不平衡报价法", "C": "多方案报价法", "D": "无利润报价法"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是投标报价的策略 【选项分析】不平衡报价法。指在不影响工程总报价的前提下，通过调整内部各个项目的报价，以达到既不提高总报价、不影响中标，又能在结算时得到更理想的经济效益的报价方法。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0355", "date": "2026-07-09", "chapter": "g06", "type": "single", "stem": "由于异常恶劣的天气条件影响而引起的停工，承包人（ ）。", "options": {"A": "可索赔工期", "B": "可索赔费用", "C": "可索赔工期和费用", "D": "得不到索赔"}, "answer": ["A"], "analysis": "【内容考查】本题考查的是工期索赔的计算 【选项分析】可原谅延期，可细分为可原谅并给予费用补偿的延期和可原谅延期但不给予补偿费用的延期，不给予补偿费用的延期大多是指由于发包人承担的风险责任而引起的责任的影响，比如异常恶劣的天气条件影响而引起的停工等。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0368", "date": "2026-07-09", "chapter": "g06", "type": "single", "stem": "由于不可抗力解除合同的，承包人可获得的金额支付下列说法不正确的是（ ）。", "options": {"A": "合同解除之日前已完成工程但尚未支付的合同价款", "B": "承包人为合同工程合理订购且已支付的材料和工程设备货款，该材料和工程设备视为承包人的财产", "C": "承包人撤离现场所需的合理费用", "D": "已实施或部分实施的措施项目应付价款"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是合同解除的价款结算与支付 【选项分析】由于不可抗力解除合同的，发包人除应向承包人支付合同解除之日前已完成工程但尚未支付的合同价款，还应支付下列金额：（1）合同中约定应由发包人承担的费用。（2）已实施或部分实施的措施项目应付价款。（3）承包人为合同工程合理订购且已交付的材料和工程设备货款。发包人一经支付此项货款，该材料和工程设备即成为发包人的财产。（4）承包人撤离现场所需的合理费用，包括员工遣送费和临时工程拆除、施工设备运离现场的费用。（5）承包人为完成合同工程而预期开支的任何合理费用，且该项费用未包括在本款其他各项支付之内。 发承包双方办理结算合同价款时，应扣除合同解除之日前发包人应向承包人收回的价款。当发包人应扣除的金额超过了应支付的金额，则承包人应在合同解除后的约定期限内将其差额退还给发包人。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0370", "date": "2026-07-09", "chapter": "g06", "type": "single", "stem": "根据《建设工程质量保证金管理办法》，由于发包人原因导致工程无法按规定期限进行竣工验收的，在承包人提交竣工验收报告（ ）天后，工程自动进入缺陷责任期。", "options": {"A": "30", "B": "45", "C": "60", "D": "90"}, "answer": ["D"], "analysis": "由于发包人原因导致工程无法按规定期限进行竣工验收的，在承包人提交竣工验收报告90 天后，工程自动进入缺陷责任期。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "gl-g06-004", "date": "2026-07-08", "chapter": "g06", "type": "multiple", "stem": "公开招标与邀请招标相比，公开招标的特点包括（ ）。", "options": {"A": "招标公告公开发布", "B": "竞争范围更广", "C": "招标时间较短", "D": "可选择范围大", "E": "有利于降低造价"}, "answer": ["A", "B", "D", "E"], "analysis": "公开招标通过公告公开发布，竞争范围广、选择范围大，有利于降低造价。但招标时间较长（需等公告期），邀请招标时间较短。", "tags": ["招标方式", "公开招标"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-006", "date": "2026-07-08", "chapter": "g06", "type": "multiple", "stem": "招标文件通常包括的内容有（ ）。", "options": {"A": "招标公告（投标邀请书）", "B": "投标人须知", "C": "评标办法", "D": "合同条款及格式", "E": "投标保证金银行账户信息"}, "answer": ["A", "B", "C", "D"], "analysis": "招标文件包括：招标公告（或投标邀请书）、投标人须知、评标办法、合同条款及格式、工程量清单、图纸、技术标准和要求等。投标保证金信息通常在投标人须知中规定。", "tags": ["招标投标文件", "招标文件"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-007", "date": "2026-07-08", "chapter": "g06", "type": "multiple", "stem": "投标文件通常包括的内容有（ ）。", "options": {"A": "投标函及投标函附录", "B": "已标价工程量清单（投标报价）", "C": "施工组织设计", "D": "资格审查资料", "E": "评标办法"}, "answer": ["A", "B", "C", "D"], "analysis": "投标文件包括：投标函及附录、投标报价（已标价工程量清单）、施工组织设计、资格审查资料（资格证明）、项目管理机构等。评标办法属于招标文件内容。", "tags": ["招标投标文件", "投标文件"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-013", "date": "2026-07-08", "chapter": "g06", "type": "multiple", "stem": "分部分项工程量清单应包括的要素有（ ）。", "options": {"A": "项目编码", "B": "项目名称", "C": "项目特征描述", "D": "计量单位", "E": "综合单价"}, "answer": ["A", "B", "C", "D"], "analysis": "分部分项工程量清单的五大要素为：项目编码（12位）、项目名称、项目特征描述、计量单位和工程量。综合单价在投标人填写报价时确定，不是招标人编制清单的内容。", "tags": ["工程量清单", "分部分项清单"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-014", "date": "2026-07-08", "chapter": "g06", "type": "multiple", "stem": "其他项目清单通常包括的内容有（ ）。", "options": {"A": "暂列金额", "B": "暂估价", "C": "计日工", "D": "总承包服务费", "E": "安全文明施工费"}, "answer": ["A", "B", "C", "D"], "analysis": "其他项目清单包括：暂列金额、暂估价（材料暂估价和专业工程暂估价）、计日工和总承包服务费。安全文明施工费属于措施项目费。", "tags": ["工程量清单", "其他项目清单"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-020", "date": "2026-07-08", "chapter": "g06", "type": "multiple", "stem": "关于工程量清单的作用，下列说法正确的有（ ）。", "options": {"A": "是编制最高投标限价的依据", "B": "是投标人报价的依据", "C": "是工程索赔的依据之一", "D": "是工程价款调整的依据之一", "E": "取代施工图纸的作用"}, "answer": ["A", "B", "C", "D"], "analysis": "工程量清单是编制最高投标限价、投标报价、计算工程量、支付工程款、调整合同价款、办理竣工结算以及工程索赔等的依据之一，但不能取代施工图纸。", "tags": ["工程量清单", "作用"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-027", "date": "2026-07-08", "chapter": "g06", "type": "multiple", "stem": "当出现下列（ ）情形时，成本加酬金合同更为适用。", "options": {"A": "工程内容明确，设计图纸详细", "B": "紧急抢险救灾工程", "C": "新型工程，无法准确确定造价", "D": "工期较短的小型工程", "E": "风险很大的项目"}, "answer": ["B", "C", "E"], "analysis": "成本加酬金合同适用于：紧急工程（如抢险救灾）、新型工程（无法准确确定造价）、风险较大的项目。工程内容明确应优先使用总价或单价合同。", "tags": ["合同类型", "成本加酬金合同"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-031", "date": "2026-07-08", "chapter": "g06", "type": "multiple", "stem": "关于工程量清单计价，下列说法正确的有（ ）。", "options": {"A": "采用综合单价计价", "B": "工程量由招标人提供", "C": "投标人不能修改工程量清单", "D": "综合单价包含人工费、材料费、机具费、管理费和利润", "E": "综合单价已包含全部税金"}, "answer": ["A", "B", "C", "D"], "analysis": "工程量清单计价采用综合单价，招标人提供工程量清单且投标人不得修改。综合单价包含人材机费用、管理费和利润及一定风险，但不包含增值税（增值税单独计取）。", "tags": ["工程量清单", "综合单价"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-033", "date": "2026-07-08", "chapter": "g06", "type": "multiple", "stem": "工程量清单中措施项目清单列项需考虑的因素包括（ ）。", "options": {"A": "拟建工程的实际情况", "B": "常规施工方案", "C": "水文气象条件", "D": "环境保护要求", "E": "投标人的管理水平"}, "answer": ["A", "B", "C", "D"], "analysis": "措施项目清单根据拟建工程实际情况、常规施工方案、水文气象条件、环境保护要求等列项。投标人管理水平不同会导致措施费报价差异，但清单列项由招标人确定。", "tags": ["工程量清单", "措施项目清单"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-036", "date": "2026-07-08", "chapter": "g06", "type": "multiple", "stem": "投标报价的编制依据包括（ ）。", "options": {"A": "GB/T 50500-2024", "B": "企业定额", "C": "招标文件及工程量清单", "D": "市场价格信息", "E": "可行性研究报告"}, "answer": ["A", "B", "C", "D"], "analysis": "投标报价依据包括：GB/T50500-2024、企业定额、招标文件及工程量清单、市场价格信息、施工现场情况等。可行性研究报告是决策阶段的文件，不作为投标报价的直接依据。", "tags": ["投标报价", "编制依据"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-038", "date": "2026-07-08", "chapter": "g06", "type": "multiple", "stem": "施工合同计价方式的选择应考虑的因素包括（ ）。", "options": {"A": "项目的复杂程度", "B": "工程设计深度", "C": "施工技术的先进程度", "D": "施工工期的紧迫程度", "E": "施工企业的注册资本"}, "answer": ["A", "B", "C", "D"], "analysis": "合同类型选择考虑：项目复杂程度、设计深度、技术先进性、工期紧迫度等。设计深度不足时应避免固定总价合同；紧急工程可考虑成本加酬金合同。注册资本不是关键因素。", "tags": ["合同类型", "选择因素"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-041", "date": "2026-07-08", "chapter": "g06", "type": "multiple", "stem": "EPC总承包合同的特点包括（ ）。", "options": {"A": "设计、采购、施工一体化", "B": "总价合同为主", "C": "总承包单位承担较大风险", "D": "业主管理相对简单", "E": "适用于设计深度充分的项目"}, "answer": ["A", "B", "C", "D"], "analysis": "EPC合同特点：设计采购施工一体化、以总价合同为主、承包方承担较大风险、业主管理简单。EPC适用于大型复杂项目，通常在初步设计完成后即可发包，不要求设计深度充分。", "tags": ["合同类型", "EPC"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-044", "date": "2026-07-08", "chapter": "g06", "type": "multiple", "stem": "关于暂估价，下列说法正确的有（ ）。", "options": {"A": "包括材料暂估价和专业工程暂估价", "B": "用于必然发生但暂时不能确定价格的项目", "C": "由招标人在清单中给定", "D": "暂估价项目必须招标", "E": "结算时按实际价格调整"}, "answer": ["A", "B", "C", "E"], "analysis": "暂估价包括材料暂估价和专业工程暂估价，用于必然发生但暂不能确定价格的项目，由招标人给定，结算时按实际价格调整。达到招标规模的暂估价项目才需要招标，不是所有暂估价都必须招标。", "tags": ["工程量清单", "暂估价"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-048", "date": "2026-07-08", "chapter": "g06", "type": "multiple", "stem": "施工合同中，一般在下列（ ）情况下宜采用固定总价合同。", "options": {"A": "工程设计详细，图纸完整清楚", "B": "工程量小、工期短", "C": "工程结构和技术简单", "D": "工程紧急，无法准确估计造价", "E": "投标期相对宽裕"}, "answer": ["A", "B", "C", "E"], "analysis": "固定总价合同适用于：设计详细、图纸完整、工程量小工期短、技术简单、投标期充裕的情况。工程紧急且无法准确估计造价时宜采用成本加酬金合同。", "tags": ["合同类型", "固定总价合同"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g06-051", "date": "2026-07-08", "chapter": "g06", "type": "multiple", "stem": "不平衡报价法的常用策略包括（ ）。", "options": {"A": "对早期施工项目报高价", "B": "对预计工程量增加的项目报高价", "C": "对图纸不明确的项目报高价", "D": "对计日工项目报高价", "E": "对暂定项目报高价"}, "answer": ["A", "B", "C", "D"], "analysis": "不平衡报价策略：早期施工项目报高、预计工程量增加报高、图纸不明确项目报高、计日工报高。暂定项目是否报高需判断：自己承包可能性大时报高，不承包时报低。", "tags": ["投标报价", "不平衡报价法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-003", "date": "2026-07-08", "chapter": "g06", "type": "multiple", "stem": "下列属于邀请招标适用情形的是？", "options": {"A": "技术复杂、有特殊要求或受自然环境限制，只有少量潜在投标人可供选择", "B": "采用公开招标方式的费用占项目合同金额的比例过大", "C": "涉及国家安全、国家秘密，不宜公开招标", "D": "施工单项合同估算价在400万元以上的"}, "answer": ["A", "B", "C"], "analysis": "邀请招标适用三种情形：技术复杂少数投标人、费用比例过大、国家安全或秘密。D选项是必须招标的规模标准，不属于邀请招标的适用情形。", "tags": ["招标方式", "邀请招标"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-010", "date": "2026-07-08", "chapter": "g06", "type": "multiple", "stem": "根据《必须招标的工程项目规定》，下列关于必须招标规模标准的说法正确的有？", "options": {"A": "施工单项合同估算价在400万元人民币以上", "B": "重要设备、材料等货物采购单项合同估算价在200万元人民币以上", "C": "勘察、设计、监理等服务采购单项合同估算价在100万元人民币以上", "D": "同一项目中可以合并采购的，合并估算价未达到上述标准也须招标"}, "answer": ["A", "B", "C"], "analysis": "A、B、C均为正确的规模标准。D选项表述错误：同一项目中可以合并采购的，合并后合同估算价合计达到上述标准（400万/200万/100万）的才必须招标，未达到则不必。", "tags": ["必须招标", "规模标准"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-018", "date": "2026-07-08", "chapter": "g06", "type": "multiple", "stem": "关于招标投标的时间节点，下列说法正确的有？", "options": {"A": "资格预审文件发售期不得少于5日", "B": "招标文件发出至投标截止最短不得少于15日", "C": "招标文件澄清或修改应在投标截止至少15日前通知", "D": "投标保证金不得超过估算价的2%且不超过80万元"}, "answer": ["A", "C", "D"], "analysis": "A选项正确，资格预审文件发售期≥5日。B选项错误，应为≥20日而非15日。C选项正确，澄清修改应在截止前≥15日。D选项正确，投标保证金≤估算价2%且≤80万。", "tags": ["招标程序", "时间节点"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-020", "date": "2026-07-08", "chapter": "g06", "type": "multiple", "stem": "关于投标保证金，下列说法正确的有？", "options": {"A": "投标保证金不得超过招标项目估算价的2%", "B": "投标保证金最高不得超过80万元", "C": "投标保证金有效期应当与投标有效期一致", "D": "招标人不得挪用投标保证金"}, "answer": ["A", "B", "C", "D"], "analysis": "四个选项均为关于投标保证金的正确规定：不得超过估算价的2%，最高不超过80万元，有效期与投标有效期一致，招标人不得挪用。", "tags": ["招标程序", "投标保证金"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-026", "date": "2026-07-08", "chapter": "g06", "type": "multiple", "stem": "下列情形中，招标人应当依法重新招标的有？", "options": {"A": "提交投标文件的投标人少于3个", "B": "所有投标均被评标委员会否决", "C": "招标文件售价过高导致投标人不足", "D": "中标候选人放弃中标"}, "answer": ["A", "B"], "analysis": "投标人少于3个或所有投标均被否决的，应当重新招标。C选项：如果招标人自身原因（如售价不合理）导致投标人不足，也应重新招标，但这不是法定的直接重新招标情形。D选项：中标候选人放弃中标，招标人可以依序确定其他中标候选人，不一定重新招标。 A和B是法定的重新招标情形。", "tags": ["重新招标"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-028", "date": "2026-07-08", "chapter": "g06", "type": "multiple", "stem": "关于开标和评标，下列说法正确的有？", "options": {"A": "开标应邀请所有投标人参加", "B": "投标人可检查投标文件密封情况", "C": "评标委员会可要求投标人澄清，但不得改变实质性内容", "D": "投标人少于3个的，招标人应当重新招标"}, "answer": ["A", "B", "C", "D"], "analysis": "四个选项均为正确表述：A开标应邀请所有投标人参加；B投标人有权检查密封；C澄清不得改变实质性内容；D少于3个投标人应重新招标。", "tags": ["开标", "评标"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-033", "date": "2026-07-08", "chapter": "g06", "type": "multiple", "stem": "下列关于总价合同的说法，正确的有？", "options": {"A": "固定总价合同中承包方承担价格风险为主", "B": "固定总价合同适用于工期短、技术简单的项目", "C": "可调总价合同中发包方承担部分价格风险", "D": "可调总价合同适用于工期较长的项目"}, "answer": ["A", "B", "C", "D"], "analysis": "四个选项均为关于总价合同的正确描述：固定总价合同承包方担风险、适用短工期简单项目；可调总价合同发包方承担部分风险、适用长工期项目。", "tags": ["合同类型", "总价合同"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-036", "date": "2026-07-08", "chapter": "g06", "type": "multiple", "stem": "成本加酬金合同的适用情形包括？", "options": {"A": "紧急抢险救灾项目", "B": "新型或技术不成熟的项目", "C": "风险较大的项目", "D": "设计详细完整、工期短的项目"}, "answer": ["A", "B", "C"], "analysis": "成本加酬金合同适用于开工前无法确定工程范围或风险的紧急项目（如抢险救灾）、新型或技术不成熟的项目、风险大的项目。D选项是固定总价合同的适用情形。", "tags": ["合同类型", "成本加酬金合同"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-041", "date": "2026-07-08", "chapter": "g06", "type": "multiple", "stem": "下列关于各类合同风险承担的说法，正确的有？", "options": {"A": "固定总价合同中承包方承担价格风险为主", "B": "单价合同中发包方承担工程量变化的风险", "C": "成本加酬金合同中发包方承担全部成本风险", "D": "EPC合同中承包商承担绝大部分风险"}, "answer": ["A", "B", "C", "D"], "analysis": "四个选项均正确：A固定总价合同承包方担价格风险；B单价合同工程量按实结算，发包方承担风险；C成本加酬金发包方承担全部成本风险；D EPC合同承包商承担绝大部分风险。", "tags": ["合同类型", "风险承担"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-043", "date": "2026-07-08", "chapter": "g06", "type": "multiple", "stem": "成本加酬金合同的形式包括？", "options": {"A": "成本加固定酬金", "B": "成本加百分比酬金", "C": "成本加浮动酬金", "D": "成本加目标酬金（含奖惩）"}, "answer": ["A", "B", "C", "D"], "analysis": "成本加酬金合同的主要形式包括：成本加固定酬金、成本加百分比酬金、成本加浮动酬金、成本加目标酬金等。不同形式的激励效果不同。", "tags": ["合同类型", "成本加酬金合同"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-045", "date": "2026-07-08", "chapter": "g06", "type": "multiple", "stem": "根据GB/T 50500-2024，分部分项工程量清单应包括的要件有？", "options": {"A": "项目编码", "B": "项目名称和项目特征", "C": "计量单位和工程量", "D": "综合单价"}, "answer": ["A", "B", "C"], "analysis": "分部分项工程量清单的5项要件为：编码、名称、特征、单位、工程量。综合单价是投标人填报的内容，不是清单要件。", "tags": ["工程量清单", "分部分项清单"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-048", "date": "2026-07-08", "chapter": "g06", "type": "multiple", "stem": "下列属于措施项目清单内容的有？", "options": {"A": "安全文明施工费", "B": "脚手架工程费", "C": "模板工程费", "D": "大型机械设备进出场及安拆费"}, "answer": ["A", "B", "C", "D"], "analysis": "措施项目清单包括安全文明施工费、脚手架工程费、模板工程费、大型机械设备进出场及安拆费、垂直运输费、超高施工增加费等。四个选项均为措施项目。", "tags": ["工程量清单", "措施项目"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-049", "date": "2026-07-08", "chapter": "g06", "type": "multiple", "stem": "根据《建设工程工程量清单计价规范》，其他项目清单包括？", "options": {"A": "暂列金额", "B": "暂估价（材料暂估价和专业工程暂估价）", "C": "计日工", "D": "总承包服务费"}, "answer": ["A", "B", "C", "D"], "analysis": "其他项目清单包括4项：暂列金额、暂估价（含材料暂估价和工程设备暂估价、专业工程暂估价）、计日工、总承包服务费。答案为ABCD。", "tags": ["工程量清单", "其他项目清单"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-058", "date": "2026-07-08", "chapter": "g06", "type": "multiple", "stem": "综合单价的组成内容包括？", "options": {"A": "人工费、材料费、施工机具使用费", "B": "企业管理费和利润", "C": "一定范围内的风险费用", "D": "增值税"}, "answer": ["A", "B", "C"], "analysis": "综合单价由人工费、材料费、施工机具使用费、企业管理费、利润以及一定范围内的风险费用组成。增值税不包含在综合单价中，而是单独列项计算。", "tags": ["投标报价", "综合单价"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g06-063", "date": "2026-07-08", "chapter": "g06", "type": "multiple", "stem": "下列属于投标报价策略的有？", "options": {"A": "不平衡报价法", "B": "多方案报价法", "C": "突然降价法", "D": "扩大标价法"}, "answer": ["A", "B", "C"], "analysis": "常见投标报价策略包括不平衡报价法、多方案报价法、突然降价法、先亏后盈法等。【扩大标价法】不是标准的投标报价策略名称。", "tags": ["投标报价", "报价策略"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "ht_mgmt_1541", "date": "2026-07-10", "chapter": "g06", "type": "multiple", "stem": "根据《招标投标法》 ， 工程施工项目招标信息发布的说法， 正确的有( )。", "options": {"A": "指定媒介可以酌情收取额外费用", "B": "招标文件售出后不予退还", "C": "招标人应至少在两家指定的媒介发布招标公告", "D": "招标人可以对招标文件所附的设计文件向投标人收取一定的费用", "E": "自招标文件出售之日起至停止出售之日止， 最短不得少于 5 日"}, "answer": ["B", "E"], "analysis": "招标人应当按招标公告或者投标邀请书规定的时间、地点出售招标文件或资格预审文件。自招标文件或者资格预审文件出售之日起至停止出售之日止，最短不得少于5个工作日。投标人必须自费购买相关招标或资格预审文件。招标人发售资格预审文件、招标文件收取的费用应当限于补偿印刷、邮寄的成本支出，不得以营利为目的。对于所附的设计文件，招标人可以向投标人酌收押金；对于开标后投标人退还设计文件的，招标人应当向投标人退还押金。招标文件或者资格预审文件售出后，不予退还。招标人在发布招标公告、发出投标邀请书后或者售出招标文件或资格预审文件后不得擅自终止招标。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1542", "date": "2026-07-10", "chapter": "g06", "type": "multiple", "stem": "关于建设工程施工招标标前会议的说法， 正确的有（ ） 。", "options": {"A": "标签会议是招标人按投标须知在规定的时间、 地点召开的会议", "B": "标前会议纪要与招标文件不一致时， 应以招标文件为准", "C": "标前会议结束后， 招标人应将会议纪要用书面形式发给每个投标人", "D": "招标人可以根据实际情况在标前会议上确定延长投标截止时间", "E": "招标人的答复函件对问题的答复须注明问题来源"}, "answer": ["A", "C", "D"], "analysis": "A选项正确，标前会议是招标人按投标须知规定的时间和地点召开的会议。 B选项错误，当补充文件与招标文件内容不一致时，应以补充文件为准。 C选项正确，会议结束后，招标人应将会议纪要用书面通知的形式发给每一个投标人。 D选项正确，为了使投标单位在编写投标文件时有充分的时间考虑招标人对招标文件的补充或修改内容，招标人可以根据实际情况在标前会议上确定延长投标截止时间。E选项错误，无论是会议纪要还是对个别投标人的问题的解答，都应以书面形式发给每一个获得投标文件的投标人，以保证招标的公平和公正。但对问题的答复不需要说明问题来源。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1543", "date": "2026-07-10", "chapter": "g06", "type": "multiple", "stem": "根据《中华人民共和国招标投标法实施条例》（中华人民共和国国务院令第613号）第八条，可以采用邀请招标的有（ ）。", "options": {"A": "国有资金占控股地位", "B": "技术复杂、有特殊要求或者受自然环境限制，只有少量潜在投标人可供选择", "C": "国有资金占主导地位", "D": "采用公开招标方式的费用占项目合同金额的比例过大", "E": "公开招标程序过于繁琐的"}, "answer": ["B", "D"], "analysis": "对于有些特殊项目，采用邀请招标方式确实更加有利。根据《中华人民共和国招标投标法实施条例》（中华人民共和国国务院令第613号）第八条，国有资金占控股或者主导地位的依法必须进行招标的项目，应当公开招标；但有下列情形之一的，可以邀请招标：（一）技术复杂、有特殊要求或者受自然环境限制，只有少量潜在投标人可供选择；（二）采用公开招标方式的费用占项目合同金额的比例过大。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1544", "date": "2026-07-10", "chapter": "g06", "type": "multiple", "stem": "根据我国有关法规规定， 建设工程施工招标应具备的条件包括( )。", "options": {"A": "招标人已经委托了招标代理单位", "B": "施工图设计已经全部完成", "C": "有相应资金或资金来源已经落实", "D": "应当履行审批手续的初步设计及概算已获批准", "E": "应当履行核准手续的招标范围和招标方式等已获核准"}, "answer": ["C", "D", "E"], "analysis": "建设工程施工招标应该具备的条件包括以下几项：招标人已经依法成立；初步设计及概算应当履行审批手续的，已经批准；招标范围、招标方式和招标组织形式等应当履行核准手续的，已经核准；有相应资金或资金来源已经落实；有招标所需的设计图纸及技术资料。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1545", "date": "2026-07-10", "chapter": "g06", "type": "multiple", "stem": "根据《招标投标法》 和相关法律法规， 下列评标委员会的做法中。 正确的是（ ）。", "options": {"A": "招标人代表不可以作为评标委员会成员", "B": "评标委员会成员中， 经济技术专家的人数不得少于总数的 1/2", "C": "评标委员会的人数必须为 5 人以上单数", "D": "与投标人有利害关系的人不得进入相关项目的评标委员会", "E": "评标委员会成员的名单在开标时应当公布"}, "answer": ["C", "D"], "analysis": "A评标委员会由招标人的代表和有关技术、经济方面的专家组成；B经济技术专家的数量不得少于评标委员会成员总数的2/3。E评标委员会成员名单在汇总表结果确定前必须保密。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1546", "date": "2026-07-10", "chapter": "g06", "type": "multiple", "stem": "下列属于招标人不合理限制、 排斥投标人的行为的有（ ）", "options": {"A": "就同一个招标项目， 向潜在投标人提供有差别的信息", "B": "对非特定行业的业绩、 奖项作为加分条件", "C": "组织部分潜在投标人踏勘项目现场", "D": "对潜在投标人采取不同的资格审查或评标标准", "E": "限定或指定特定的专利或者品牌"}, "answer": ["A", "C", "D", "E"], "analysis": "招标人有下列行为之一的，属于以不合理条件限制、排斥潜在投标人或者投标人：（1）就同一招标项目向潜在投标人或者投标人提供有差别的项目信息；（2）设定的资格、技术、商务条件与招标项目的具体特点和实际需要不相适应或者与合同履行无关；（3）依法必须进行招标的项目以特定行政区域或者特定行业的业绩、奖项作为加分条件或者中标条件；（4）对潜在投标人或者投标人采取不同的资格审査或者评标标准；（5）限定或者指定特定的专利、商标、品牌、原产地或者供应商（6）依法必须进行招标的项目非法限定潜在投标人或者投标人的所有制形式或者组织形式；（7）以其他不合理条件限制、排斥潜在投标人或者投标人。招标人不得组织单个或者部分潜在投标人踏勘项目现场。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1547", "date": "2026-07-10", "chapter": "g06", "type": "multiple", "stem": "根据2015年《政府采购法实施条例》和2013年《电子招标投标办法》的规定，下列说法错误的是（ ）。", "options": {"A": "政府采购工程依法不进行招标的，应当只能依照竞争性谈判方式进行采购", "B": "政府采购工程依法不进行招标的，可以依照单一来源采购方式进行采购", "C": "招标投标交易场所可以以营利为目的", "D": "数据电文形式与纸质形式的招标投标活动的法律效力不同", "E": "投标截止时间后送达的投标文件，电子招标投标交易平台可以拒收"}, "answer": ["A", "C", "D", "E"], "analysis": "政府采购工程依法不进行招标的，应当依照政府采购法和本条例规定的竞争性谈判或者单一来源采购方式采购。招标投标交易场所不得与行政监督部门存在隶属关系，不得以营利为目的。数据电文形式与纸质形式的招标投标活动具有同等法律效力。投标截止时间后送达的投标文件，电子招标投标交易平台应当拒收。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1548", "date": "2026-07-10", "chapter": "g06", "type": "multiple", "stem": "关于招标投标活动中， 投标人提出异议的说法， 正确的是（ ）。", "options": {"A": "对招标文件有异议的， 必须在投标截止日前提出", "B": "对资格预审文件有异议的， 必须在资格预审申请截止前 2 日提出", "C": "投标人认为招标活动不符合相关法律规定的， 可以在知道或者应当知道之日起 15 日向有关部门投诉", "D": "收到对招标文件异议后， 招标人应当在 3 日内进行答复； 答复前， 招标活动应当暂停。", "E": "对资格预审文件、 招标文件、 开标及对依法必须进行招标项目的评标结果有异议的， 应当先向招标人提出异议， 再向有关部门投诉。"}, "answer": ["B", "D", "E"], "analysis": "A对招标文件有异议的，应当在投标截止时间10日前提出；C投标人认为招标活动不符合相关法律规定的，可以在知道或者应当知道之日起10日内向有关行政监督部门投诉。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1549", "date": "2026-07-10", "chapter": "g06", "type": "multiple", "stem": "投标人须知是招标人向投标人传递基础信息的文件， 投标人应特别注意其中的( )。", "options": {"A": "招标工程的范围和详细内容", "B": "招标人的职责权利", "C": "施工技术说明", "D": "投标文件的组成", "E": "重要的时间安排"}, "answer": ["A", "D", "E"], "analysis": "首先，投标人需要注意招标工程的详细内容和范围，避免遗漏或多报。 其次，还要特别注意投标文件的组成，避免因提供的资料不全而被作为废标处理。例如，曾经有一资信良好的著名企业在投标时因为遗漏资产负债表而失去了本来非常有希望的中标机会。在工程实践中，这方面的先例不在少数。还要注意招标答疑时间、投标截止时间等重要时间安排，避免因遗忘或迟到等原因而失去竞争机会。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1550", "date": "2026-07-10", "chapter": "g06", "type": "multiple", "stem": "某港口建设项目向社会公开招标，招标文件中明确规定提交投标文件的截止时间为2014年6月2日上午9点，则下列说法正确的有（ ）。", "options": {"A": "开标时间为2014年6月2日上午9点至2014年6月3日上午9点之间", "B": "开标由该市建设行政主管部门主持", "C": "开标邀请所有投标人参加", "D": "开标时，可由投标人检查投标文件的密封情况", "E": "招标人对2014年6月2日上午9点15分送达的投标文件不予受理"}, "answer": ["C", "D", "E"], "analysis": "本题考点是开标。根据《招标投标法》，开标应当在招标文件确定的提交投标文件截止时间的同一时间公开进行；地点：应当为招标文件中预先确定的地点。开标由招标人主持。邀请所有投标人参加。开标时，由投标人或者其推选的代表检查投标文件的密封情况，也可以由招标人委托的公证机构检查并公证；经确认无误后，由工作人员当众拆封，宣读投标人名称、投标价格和投标文件的其他主要内容。开标过程应当记录，并存档备查。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1551", "date": "2026-07-10", "chapter": "g06", "type": "multiple", "stem": "关于投标文件的编制与递交，下列说法中正确的有()。", "options": {"A": "投标函附录在满足招标文件实质性要求的基础上，提出比招标文中要求更能吸引招标人的承诺", "B": "当投标文件的正本与副本不一致时以正本为准", "C": "允许递交备选投标方案时，所有投标人的备选方案应同等对待", "D": "在要求提交投标文件的截止时间后送达的投票文件为无效的投标文件", "E": "境内投标人以现金形式提交的投标保证金应当出自投标人的基本账户"}, "answer": ["A", "B", "D", "E"], "analysis": "投标文件编制和递交时应遵循如下规定：,投标文件应按“投标文件格式”进行编写，如有必要，可以增加附页，作为投标文件的组成部分。其中，投标函附录在满足招标文件实质性要求的基础上，可以提出比招标文件要求更能吸引招标人的承诺；投标文件正本一份，副本份数按招标文件有关规定。投标文件的正本与副本应分别装订成册，并编制目录。当副本和正本不一致时，以正本为准；投标人应当在招标文件规定的提交投标文件的截止时间前，将投标文件密封送达投标地点。在招标文件要求提交投标文件的截止时间后送达或未送达指定地点的投标文件，为无效的投标文件，招标人不予受理；依法必须进行招标的项目的境内投标单位，以现金或者支票形式提交的投标保证金应当从其基本账户转出。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1552", "date": "2026-07-10", "chapter": "g06", "type": "multiple", "stem": "投标文件应当对招标文件作出实质性响应的内容有()。", "options": {"A": "报价", "B": "工期", "C": "投标有效期", "D": "质量要求", "E": "招标范围"}, "answer": ["B", "C", "D", "E"], "analysis": "本题考查的是编制投标文件。投标文件应当对招标文件有关工期、投标有效期、质量要求、技术标准和要求、招标范围等实质性内容作出响应。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1553", "date": "2026-07-10", "chapter": "g06", "type": "multiple", "stem": "关于工程量清单中的项目特征描述，下列表述正确的是( )。", "options": {"A": "应符合工程量计算规范附录的规定", "B": "应能满足确定综合单价的需要", "C": "不能直接采用详见××图集的方式", "D": "可以采用文字描述和详见××图号的方式", "E": "应结合拟建工程实际"}, "answer": ["A", "B", "D", "E"], "analysis": "在描述工程量清单项目特征时应按以下原则进行：(l)项目特征描述的内 容应按附录中的规定，结合拟建工程的实际，满足确定综合单价的需要；(2)若采用标 准图集或施工图纸能够全部或部分满足项目特征描述的要求，项目特征描述可直接采用 详见××图集或××图号的方式。对不能满足项目特征描述要求的部分，仍应用文字 描述。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1554", "date": "2026-07-10", "chapter": "g06", "type": "multiple", "stem": "关于招标分部分项工程量清单的项目特征描述，应遵循的编制原则有()。", "options": {"A": "按专业工程量计算规范附录的规定，结合拟建工程实际描述", "B": "其他独有特征，由清单编制人视项目具体情况确定", "C": "要满足确定综合单价的需要", "D": "应详细描述分部分项工程的施工工艺和方法", "E": "对于采用标准图集的项目，可直接描述为“详见××图集”"}, "answer": ["A", "B", "C"], "analysis": "本题考查的是招标工程量清单的编制。选项D，在编制分部分项工程量清单时，工作内容通常无须描述；选项E，若采用标准图集或施工图纸能够全部或部分满足项目特征描述的要求，项目特征描述可直接采用“详见××图集”或“××图号”的方式。对不能满足项目特征描述要求的部分，仍应用文字描述。E选项是不正确的，采用图集，分二种情况，图集能满足特征描述的要求的，就是E选项。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1555", "date": "2026-07-10", "chapter": "g06", "type": "multiple", "stem": "下列关于招标工程量清单的描述，说法正确的有()。", "options": {"A": "招标工程量清单是招标文件的组成部分，可以由招标人委托的工程造价咨询人编制", "B": "招标人对工程量清单中各分部分项工程工程量的准确性和完整性负责", "C": "由于措施项目投标人可自行选择，因此招标人无须对措施项目工程量的准确性和完整性负责", "D": "招标工程量清单编制前也要进行现场踏勘", "E": "招标工程量清单编制时需进行先进施工组织设计方案的编制，以提高施工水平"}, "answer": ["A", "B", "D"], "analysis": "本题考查的是招标工程量清单的编制。选项C错误，招标人对工程量清单中各分部分项工程或适合以分部分项工程项目清单设置的措施项目的工程量的准确性和完整性负责；选项E错误，招标工程量清单编制的准备工作(1) 初步研究(2) 现场踏勘（3）拟定常规施工组织设计。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1556", "date": "2026-07-10", "chapter": "g06", "type": "multiple", "stem": "在分部分项工程量清单编制计算工程量时，应依据的计算原则包括()。", "options": {"A": "计算口径一致", "B": "按工程量计算规则计算", "C": "按图纸计算", "D": "按一定顺序计算", "E": "根据工程内容和定额项目计算"}, "answer": ["A", "B", "C", "D"], "analysis": "本题考查的是招标工程量清单的编制。分部分项工程量清单编制中，必须依据的一定的计算原则及方法：(1)计算口径一致；(2)按工程量计算规则计算；(3)按图纸计算；(4)按一定顺序计算。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1558", "date": "2026-07-10", "chapter": "g06", "type": "multiple", "stem": "复核工程量是投标人编制投标报价前的一项重要工作。通过复核工程量，便于投标人（）。", "options": {"A": "决定报价尺度", "B": "采取合适的施工方法", "C": "选用合适的施工机具", "D": "决定投入劳动力数量", "E": "选用合适的承包方法"}, "answer": ["A", "B", "C", "D"], "analysis": "复核工程量的准确程度，将影响承包商的经营行为：一是根据复核后的工程量与招标文件提供的工程量之间的差距，从而考虑相应的投标策略，决定报价尺度；二是根据工程量的大小采取合适的施工方法，选择适用、经济的施工机具设备、投入使用相应的劳动力数量等。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1559", "date": "2026-07-10", "chapter": "g06", "type": "multiple", "stem": "关于发承包双方在工程施工阶段的风险分摊原则，下列说法正确的有()。", "options": {"A": "发承包双方应当在合同中对市场价格波动导致风险的范围和幅度予以约定", "B": "承包人承担5%以内的材料价格风险和10%以内的工程设备、施工机具使用费风险", "C": "对于政府定价或政府指导价管理的原材料价格发生变动的风险，承包人应适当承担", "D": "对于承包人根据自身技术水平、管理、经营状况能够自主控制的风险，发包人不予承担", "E": "承包人的管理费、利润的风险应由承包人自己承担"}, "answer": ["A", "D", "E"], "analysis": "本题考查的是投标报价的编制方法和内容。选项B错误，根据工程特点和工期要求，一般采取的方式是承包人承担5%以内的材料、工程设备价格风险，10%以内的施工机具使用费风险；选项C错误，对于法律、法规、规章或有关政策出台导致工程税金、规费、人工费发生变化，并由省级、行业建设行政主管部门或其授权的工程造价管理机构根据上述变化发布的政策性调整，以及由政府定价或政府指导价管理的原材料等价格进行了调整，承包人不应承担此类风险，应按照有关调整规定执行。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1560", "date": "2026-07-10", "chapter": "g06", "type": "multiple", "stem": "根据我国现行施工招标投标管理规定，投标有效期的确定一般应考虑的因素有（）。", "options": {"A": "投标报价需要的时间", "B": "组织评标需要的时间", "C": "确定中标人需要的时间", "D": "签订合同需要的时间", "E": "提交履约保证金需要的时间"}, "answer": ["B", "C", "D"], "analysis": "2)投标有效期。投标有期从投标截止时间起开始计算，主要用作组织评标委员会评标、招标人定标、发出中标通知书，以及签订合同等工作，一般考虑以下因素：1)组织评标委员会完成评标需要的时间；2)确定中标人需要的时间；3)签订合同需要的时间。一 般项目投标有效期为60-90天，大型项目120天左右。投标保证金的有效期应与投标有效期保持一致。出现特殊情况需要延长投标有效期的，招标人以书面形式通知所有投标人延长投标有效期。投标人同意延长的，应相应延长其投标保证金的有效期，但不得要求或被允许修改或撤销其投标文件；投标人拒绝延长的，其投标失效，但投标人有权收回其投标保证金。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1561", "date": "2026-07-10", "chapter": "g06", "type": "multiple", "stem": "根据《工程建设项目施工招标投标法》，工程施工项目招标信息发布时，正确的有（）。（2014）", "options": {"A": "指定媒介可以酌情收取额费用", "B": "招标文件售出后不予退还", "C": "招标人应至少在两家指定的媒介发布招标公告", "D": "招标人可以对招标文件所附的设计文件向投标人收取一定费用", "E": "自招标文件出售之日起至停止出售之日止，最短不得少于5个工作日"}, "answer": ["B", "E"], "analysis": "指定媒介发布依法必须进行招标的项目的境内资格预审公告、招标公告，不得收取费用。 招标人或其委托的招标代理机构应至少在一家指定的媒介发布招标公告。 自招标文件或者资格预审文件出售之日起至停止出售之日止，最短不得少于5 个工作日。 投标人必须自费购买相关招标或资格预审文件。招标人发售资格预审文件、招标文件收取的费用应当限于补偿印刷、邮寄的成本支出，不得以营利为目的。对于所附的设计文件 ，招标人可以向投标人酌收押金 招标文件或者资格预审文件售出后，不予退还。 【教材】P268", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1562", "date": "2026-07-10", "chapter": "g06", "type": "multiple", "stem": "依据《中华人民共和国招标投标法实施条例》，招标人以不合理条件限制、排斥投标人的行为有（ ）。2017", "options": {"A": "就同一招标项目向投标人提供有差别的项目信息", "B": "就同一招标项目对投标人采取不同的资格审查标准", "C": "招标项目以获得鲁班奖工程业绩作为加分条件", "D": "招标项目指定特定的专利作为中标条件", "E": "依照招标项目的总体特点设定专门的技术条件"}, "answer": ["A", "B", "C", "D"], "analysis": "本题考查的是资格预审。属于以不合理条件限制、排斥潜在投标人或者投标人的行为有：（1）就同一招标项目向潜在投标人或者投标人提供有差别的项目信息；（2）设定的资格、技术、商务条件与招标项目的具体特点和实际需要不相适应或者与合同履行无关；（3）依法必须进行招标的项目以特定行政区域或者特定行业的业绩、奖项作为加分条件或者中标条件；（4）对潜在投标人或者投标人采取不同的资格审查或者评标标准；（5）限定或者指定特定的专利、商标、品牌、原产地或者供应商；（6）依法必须进行招标的项目非法限定潜在投标人或者投标人的所有制形式或者组织形式；（7）以其他不合理条件限制、排斥潜在投标人或者投标人。参见教材P269～P270。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1563", "date": "2026-07-10", "chapter": "g06", "type": "multiple", "stem": "【2018年真题】下列情形中，依法可以不招标的项目有（ ）。", "options": {"A": "需要使用不可替代的施工专有技术的项目", "B": "采购人的全资子公司能够自行建设的", "C": "需要向原中标人采购工程，否则将影响施工或者功能配套要求的", "D": "只有少量潜在投标人可供选择的项目", "E": "已通过招标方式选定的特许经营项目投资人依法能够自行建设的"}, "answer": ["A", "C", "E"], "analysis": "本题考查可以不进行招标的建设工程项目。选项B，子公司为独立法人，不视为自行建设。选项D，可以邀请招标，不是可以不招标。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1564", "date": "2026-07-10", "chapter": "g06", "type": "multiple", "stem": "【2017年真题】下列招标情形中，属于不合理条件限制、排斥潜在投标人或者投标人的有（ ）。", "options": {"A": "就同一招标项目向潜在投标人或者投标人提供有差别的项目信息", "B": "设定的资格、技术、商务条件与招标项目的具体特点和实际需要不相适应", "C": "先订或者指定特定的专利、商标、品牌、原产地或者供应商", "D": "对不同的潜在投标人或者投标人采取相同的资格审查或者评标标准", "E": "依法必须进行招标的项目以特定行业的业绩、奖项作为加分条件或者中标条件"}, "answer": ["A", "B", "C", "E"], "analysis": "本题考查招标中不合理条件限制。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1565", "date": "2026-07-10", "chapter": "g06", "type": "multiple", "stem": "【2016年真题】根据《和暂行规定》，下列文件属于投标文件内容的有（ ）。", "options": {"A": "投标函及其附录", "B": "施工组织设计", "C": "项目管理机构", "D": "法定代表人身份证明", "E": "投标邀请书"}, "answer": ["A", "B", "C", "D"], "analysis": "投标文件为投标人向招标人提交的资料，而投标邀请函是招标人发给投标人的。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1566", "date": "2026-07-10", "chapter": "g06", "type": "multiple", "stem": "【2018年真题】下列情形中，招标人应当拒收的投标文件有（ ）。", "options": {"A": "逾期送送达的", "B": "投标人未提交投标保证金的", "C": "投标人的法定代表人未到场的", "D": "未按招标文件要求密封的", "E": "投标人对招标文件有异议的"}, "answer": ["A", "D"], "analysis": "本题考查投标文件的送达与签收。未通过资格预审的申请人提交的投标文件，以及逾期送达或者不按照招标文件要求密封的投标文件，招标人应当拒收。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1567", "date": "2026-07-10", "chapter": "g06", "type": "multiple", "stem": "(2013年)关于施工招标文件，下列说法中正确的有()。", "options": {"A": "招标文件应包括拟签合同的主要条款", "B": "当进行资格预审时，招标文件中应包括投标邀请书", "C": "自招标文件开始发出之日起至投标截止之日最短不得少于5天", "D": "招标文件不得说明评标委员会的组建方法", "E": "招标文件应明确评标方法"}, "answer": ["A", "B", "E"], "analysis": "自招标文件开始发出之日起至投标截止日最短不得少于20天。 招标文件应当包括招标项目的技术要求，对投标人资格审査的标准、投标报价要求和评标标准等所有实质性要求和条件以及拟签合同的主要条款。所以A正确。 当进行资格预审时，招标文件中应包括投标邀请书，所以B正确。 投标准备时间，是指自招标文件开始发出之日起至投标人提交投标文件截止之日止的期限，最短不得少于 20 天。所以C错误。6) 评标。说明评标委员会的组建方法，评标原则和采取的评标办法。所以D错误。 (2) 评标。按招标文件所明确规定的标准和评标方法，评定各标书的评标价，所以E正确。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1568", "date": "2026-07-10", "chapter": "g06", "type": "multiple", "stem": "(2015年)投标报价的调查询价阶段，总承包商对分包人询价时应注意的事项包括（）。", "options": {"A": "分包标函的完整性", "B": "分包人的质量保证措施", "C": "分包人的成本和利润", "D": "分包工程单价所含内容", "E": "分包工程施工进度计划"}, "answer": ["A", "B", "D"], "analysis": "该题主要考察的是：分包询价的内容“对分包人询价应注意以下几点：分包标函是否完整，分包工程单价所包含的内容，分包人的工程质量信誉及可信赖程度，质量保证措施，分包报价。”", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1609", "date": "2026-07-10", "chapter": "g06", "type": "multiple", "stem": "在招标方式中，邀请招标与公开招标比较，其缺点主要有（ ）等。", "options": {"A": "选择面窄，有可能排除某些在技术上或报价上有竞争力的承包商参与投标", "B": "投标竞争的激烈程度较差", "C": "招标时间长", "D": "对投标申请者进行评标的工作量大", "E": "招标费用高"}, "answer": ["A", "B"], "analysis": "与公开招标方式相比，邀请招标的优点是不发布招标公告， 不进行资格预审，简化了招标程序，因而节约了招标费用、缩短了招标时间。而且由于招标人比较了解投标人，从而减少了合同履约过程中承包商违约的风险。邀请招标的缺点主要体现在邀请招标的投标竞争激烈程度较差，有可能会提高中标合同价格，也有可能排除某些在技术上或报价上有竞争力的承包商参与投标。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1610", "date": "2026-07-10", "chapter": "g06", "type": "multiple", "stem": "根据《工程建设项目招标范围和规模标准规定》，必须招标范围内的各类工程建设项目，达到下列标准之一必须进行招标的有（ ）。", "options": {"A": "材料采购的单项合同估算价为人民币180万", "B": "施工单项合同估算价为人民币500万", "C": "重要设备采购的单项合同估算价为人民币250万", "D": "监理服务采购的单项合同估算价为人民币160万", "E": "项目总投资额为人民币2500万"}, "answer": ["B", "C", "D"], "analysis": "本题考查的是施工招标方式和程序。材料采购的单项合同估算价为人民币200万以上时才必须进行招标.最新题库，考前【黑钻押题】，金考典软件考前更新，下载链接 www.jinkaodian.com", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1611", "date": "2026-07-10", "chapter": "g06", "type": "multiple", "stem": "关于工程质量保证金的使用及返还，叙述正确的有（ ）。", "options": {"A": "如果承包人没有认真履行合同约定的保修责任，则发包人可以按照合同约定扣除保证金，并要求承包人赔偿相应的损失", "B": "发包人在接到承包人返还保证金申请后，应于28天内会同承包人按照合同约定的内容进行核实", "C": "发包人在接到承包人返还保证金申请后14天内不予答复，经催告后14天内仍不予答复，视同认可承包商的返还保证金申请", "D": "发包人和承包人对保证金预留、返还以及工程维修质量、费用有争议，按照合同约定的争议和纠纷解决程序处理", "E": "缺陷责任期内，承包人认真履行合同约定的责任，到期后，承包人向发包人申请返还保证金"}, "answer": ["A", "C", "D", "E"], "analysis": "工程质量保证(保修)金的使用及返还的要求包括：缺陷责任期内，承包人认真履行合同约定的责任，到期后，承包人向发包人申请返还保证金。发包人在接到承包人返还保证金申请后，应于14天内会同承包人按照合同约定的内容进行核实。如无异议，发包人应当在核实后14天内将保证金返还承包人，逾期支付的，依法承担违约责任。发包人在接到承包人返还保证金申请后14天内不予答复，经催告后14天内仍不予答复，视同认可承包商的返还保证金申请。发包人和承包人对保证金预留、返还以及工程维修质量、费用有争议，按照合同约定的争议和纠纷解决程序处理。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1612", "date": "2026-07-10", "chapter": "g06", "type": "multiple", "stem": "关于工程质量保证(保修)金的预留、使用及管理，下列说法正确的有（ ）。", "options": {"A": "发包人应按照合同约定方式预留保证金，保证金总预留比例不得高于工程价款结算总额的3%", "B": "质量保证金的计算额度包括预付款的支付、扣回以及价格调整的金额", "C": "建设工程竣工结算后，发包人应及时向承包人支付工程结算价款并预留保证金", "D": "监理人应从第一个付款周期开始，在发包人的进度付款中，按专用合同条款的约定扣留质量保证金", "E": "他人原因造成的缺陷，发包人负责组织维修，承包人不承担费用，且发包人不得从保证金中扣除费用"}, "answer": ["A", "C", "D", "E"], "analysis": "选项B错误，正确的说法是质量保证金的计算基数不包括预付款的支付、扣回以及价格调整的金额。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1613", "date": "2026-07-10", "chapter": "g06", "type": "multiple", "stem": "根据《建设工程施工合同（示范文本）》（GF-2017-0201），合同示范文本由（ ）组成。", "options": {"A": "通用合同条款", "B": "合同协议书", "C": "标准和技术规范", "D": "专用合同条款", "E": "中标通知书"}, "answer": ["A", "B", "D"], "analysis": "本题考查的是施工合同示范文本。施工合同示范文本包括：（1）协议书；（2）通用条款；（3）专用条款。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1615", "date": "2026-07-10", "chapter": "g06", "type": "multiple", "stem": "关于分部分项工程量清单的编制，下列说法中正确的有（ ）。", "options": {"A": "以清单计算规范附录中的名称为基础，结合具体工作内容补充细化项目名称", "B": "清单项目的工作内容在招标工程量清单的项目特征中加以描述", "C": "有两个或以上计量单位时，选择最适宜表现项目特征并方便计量的单位", "D": "除另有说明外，清单项目的工程量应以实体工程量为准，各种施工总的损耗和需要增加的工程量应在单价中考虑", "E": "在工程量清单中应附补充项目的项目名称、项目特征、计量单位和工程量"}, "answer": ["A", "C", "D"], "analysis": "本题考查的是分部分项工程项目清单。选项B，，在编制分部分项工程项目清单时，工程内容通常无须描述；选项E，在工程量清单中应附补充项目的项目名称、项目特征、计量单位、工程量计算规则和工作内容。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1616", "date": "2026-07-10", "chapter": "g06", "type": "multiple", "stem": "关于工程量清单及其编制，下列说法中正确的有（ ）。", "options": {"A": "招标工程量清单必须作为投标文件的组成部分", "B": "安全文明施工费应列入以“项”为单位计价的措施项目清单中", "C": "招标工程量清单的准确性和完整性由其编制人负责", "D": "暂列金中包括用于施工中必然发生但暂不能确定价格的材料、设备的费用", "E": "计价规范中未列的规费项目，应根据省级政府或省级有关权力部门的规定列项"}, "answer": ["B", "E"], "analysis": "本题考查的是规费、税金项目清单。选项A，招标工程量清单必须作为招标文件的组成部分；选项C，招标工程量清单的准确性和完整性由其招标人负责；选项D，暂估价是指招标人在工程量清单中提供的用于支付必然发生但暂时不能确定价格的材料、工程设备的单价以及专业工程的金额。", "tags": [], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库"}, {"id": "mgmt_hqwx_0200", "date": "2026-07-09", "chapter": "g06", "type": "multiple", "stem": "建设工程施工联合体承包模式的特点有（ ）。", "options": {"A": "业主的合同结构简单，组织协调工作量小", "B": "通过联合体内部合同约束，增加了工程质量监控环节", "C": "施工合同总价可以较早确定，业主可承担较少风险", "D": "施工合同总价风险大，要求各承包商有较高的综合管理水平", "E": "能够集中联合成员单位优势，增强抗风险能力"}, "answer": ["A", "C", "E"], "analysis": "采用联合体承包模式的特点： （1）对业主而言，与总分包模式相同，合同结构简单，组织协调工作量小，而且有利于工程造价和建设工期的控制。 （2）对联合体而言，可以集中各成员单位在资金、技术和管理等方面的优势，克服单一公司力不能及的困难，不仅增强了竞争能力，同时也增强了抗风险能力。 采用联合体承包模式与施工总承包模式共同特点是施工合同总价可以较早确定，业主可承担较少风险。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0241", "date": "2026-07-09", "chapter": "g06", "type": "multiple", "stem": "工程量清单计价的作用是（ ）。", "options": {"A": "为投标者提供了一个平等的竞争条件", "B": "满足市场经济条件下竞争的需要", "C": "有利于国家对建设工程造价的宏观调控", "D": "有利于减少业主与施工单位之间的纠纷", "E": "有利于业主对投资的控制"}, "answer": ["A", "B", "D", "E"], "analysis": "【内容考查】本题考查的是 工程量清单的原理和作用 【选项分析】工程量清单计价的作用：1.提供一个平等的竞争条件。2.满足市场经济条件下竞争的需要。3.有利于工程款的拨付和工程造价的最终结算。中标后，中标价就是双方确定合同价的基础，技标清单上的单价就成了拨付工程款的依据。招标人根据施工企业完成的工程量，可以很容易地确定进度款的拨付额。工程 竣工后，根据设计变更、工程量增减等，招标人也很容易确定工程的最终造价，可在某种程度上减少招标人与施工单位之间的纠纷。 4.有利于招标人对投资的控制。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0311", "date": "2026-07-09", "chapter": "g06", "type": "multiple", "stem": "根据分部分项工程单价产生的方法不同，工料单价可以分为（ ）。", "options": {"A": "预算单价法", "B": "实物量法", "C": "分析法", "D": "综合单价法", "E": "工程量计算法"}, "answer": ["A", "B"], "analysis": "【考点来源】本题考查的是施工图预算的编制方法 【选项分析】按照分部分项工程单价产生的方法不同，工料单价法又可以分为单价法和实物量法。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0324", "date": "2026-07-09", "chapter": "g06", "type": "multiple", "stem": "下列工程项目中，必须采用工程量清单计价的有（ ）。", "options": {"A": "使用各级财政预算资金的项目", "B": "使用国家发行债券所筹资金的项目", "C": "国有资金投资总额占50%以上的项目", "D": "使用国家政策性贷款的项目", "E": "使用国际金融机构货款的项目"}, "answer": ["A", "B", "C", "D"], "analysis": "【内容考查】本题考查的是工程量清单计价的适用范围 【选项分析】使用国有资金投资的建设工程发承包，必须采用工程量清单计价。国有资金投资的项目包括全部使用国有资金（含国家融资资金）投资或国有资金投资为主的工程建设项目。国有资金（含国家融资资金）为主的工程建设项目是指国有资金占投资总额50%以上，或虽不足50%但国有投资者实质上拥有控股权的工程建设项目。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0325", "date": "2026-07-09", "chapter": "g06", "type": "multiple", "stem": "关于暂估价的计算和填写，下列说法中正确的有（ ）。", "options": {"A": "暂估价数量和拟用项目应结合工程量清单中的“暂估价表”予以补充说明", "B": "材料暂估价应由招标人填写暂估单价，无须指出拟用于哪些清单项目", "C": "工程设备暂估价不应纳入分部分项工程综合单价", "D": "专业工程暂估价应分不同专业，列出明细表", "E": "专业工程暂估价必须按照招标人提供的其他项目清单中列出的金额填写"}, "answer": ["A", "D", "E"], "analysis": "【内容考查】本题考查的是暂估价 【选项分析】材料（工程设备）暂估价由招标人填写“暂估单价”，并在备注栏说明暂估价的材料、工程设备拟用在哪些清单项目上，故B错误；工程设备暂估价计入工程量清单综合单价报价中，故C错误。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0326", "date": "2026-07-09", "chapter": "g06", "type": "multiple", "stem": "下列选项中，应以“项”为计量单位的措施项目费是（）。", "options": {"A": "脚手架工程", "B": "安全文明施工费", "C": "二次搬运费", "D": "夜间施工增加费", "E": "大型机械设备进出场及安拆费"}, "answer": ["B", "C", "D"], "analysis": "【内容考查】本题考查的是措施项目清单的标准格式 【选项分析】措施项目费用的发生与使用时间、施工方法或者两个以上的工序相关，如安全文明施工费，夜间施工，非夜间施工照明，二次搬运，冬雨季施工，地上、地下设施和建筑物的临时保护设施，已完工程及设备保护等。但是有些措施项目是可以计算工程量的，如脚手架工程，混凝土模板及支架（撑），垂直运输、超髙施工增加，大型机械设备进出场及安拆，施工排水、降水等，这类措施项目按照分部分项工程量清单的方式采用综合单价计价，更有利于措施费的确定和调整。措施项目中可以计算工程量的项目（单价措施项目）宜采用分部分项工程项目清单的方式编制，列出项目编码、项目名称、项目特征、计量单位和工程量;不能计算工程量的项目（总价措施项目），以“项” 为计量单位进行编制。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0327", "date": "2026-07-09", "chapter": "g06", "type": "multiple", "stem": "工程量清单是载明建设工程分部分项工程项目、措施项目和其他项目的名称和相应数量以及（ ）项目等内容的明细清单。", "options": {"A": "规费", "B": "企业管理费", "C": "利润", "D": "税金", "E": "风险费"}, "answer": ["A", "D"], "analysis": "【内容考查】本题考查的是工程量清单编制概述 【选项分析】工程量清单是载明建设工程分部分项工程项目、措施项目和其他项目的名称和相应数量以及规费和税金项目等内容的明细清单。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0329", "date": "2026-07-09", "chapter": "g06", "type": "multiple", "stem": "编写工程清单中的项目特征时，下列内容属于必须描述的有（ ）。【陕西】", "options": {"A": "外运土的具体运距", "B": "混凝土的种类和强度等级", "C": "金属构件的材质", "D": "抹灰面油漆的基层类型", "E": "混凝土拌合料使用的石子粒径"}, "answer": ["B", "C", "D"], "analysis": "考点来源】本题考查的是项目特征 【选项分析】属于项目特征必须描述的内容有： 1）涉及正确计量计价的必须描述:如混凝土灌注柱“虚桩”的长度；楼地面下各种垫层材料的种类、厚度；屋面找坡层、屋面保温层、墙面保温、管道保温的厚度；墙柱面抹灰砂浆的种类、厚度、配合比等。 2）涉及结构要求的必须描述:如混凝土的种类和强度等级，种类是指现场搅拌混凝土(砾石、碎石)还是商品混凝土或其他特种混凝士，混凝土强度等级如C25、C30、C30P8。如砌筑砂浆的种类和强度等级，砂浆种类是指水泥砂浆、混合砂浆、预拌砂浆(湿拌砂浆或干混砂浆)，砂浆等级如M5或M10等 3）涉及施工难易程度的必须描述:如墙面一般抹灰、装饰抹灰、镶點块料的墙体类型(砖墙或凝土墙、轻质墙;内墙或外墙等)；天棚抹灰的基层类型(现浇天棚或预制天棚等)；抹灰面油漆的基层类型(如一般抹灰面)等。 4）涉及材质要求的必须描述:如各种金属构件的材质、装饰材料的材质、玻璃品种、油漆品种、管材的材质(如碳钢管、无缝钢管、不锈钢管)等。 5）涉及材料品种、规格要求的必须描述:如块状装饰材料石材、地砖、面砖、瓷砖的规格；防水材料、保温材料的品种，厚度或涂刷遍数等。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0337", "date": "2026-07-09", "chapter": "g06", "type": "multiple", "stem": "当计算清单单位含量时，所需要的基础数据包括（ ）。", "options": {"A": "清单工程量", "B": "某工程内容的定额工程量", "C": "人工定额单位用量", "D": "材料定额单位用量", "E": "机械定额单位用量"}, "answer": ["A", "B"], "analysis": "【内容考查】本题考查的是分部分项工程和措施项目清单与计价表的编制 【选项分析】 当采用清单单位含量计算人工费、材料费、施工机具使用费时，还需要计算每一计量单位的清单项目所分摊的工程内容的工程数量，即清单单位含量。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0343", "date": "2026-07-09", "chapter": "g06", "type": "multiple", "stem": "投标报价的分包询价，投标人应注意的问题有（ ）。", "options": {"A": "分包标函是否完整", "B": "分包单价所包含的内容", "C": "分包人是否自备专用施工机具", "D": "分包人可信赖程度", "E": "分包人的质量保证措施"}, "answer": ["A", "B", "D", "E"], "analysis": "【内容考查】本题考查的是询价 【选项分析】对分包人询价应注意以下几点:分包标函是否完整；分包工程单价所包含的内容；分包人的工程质量、信誉及可信赖程度；质量保证措施；分包报价。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0346", "date": "2026-07-09", "chapter": "g06", "type": "multiple", "stem": "下列方法中，可用于编制工程项目成本计划的是（ ）。", "options": {"A": "挣值分析法", "B": "目标利润法", "C": "工期-成本同步分析法", "D": "成本分析表法", "E": "技术进步法"}, "answer": ["B", "E"], "analysis": "【内容考查】本题考查的是施工成本管理内容。 【选项分析】成本计划的编制方法。目标利润法。2）技术进步法。3）按实计算法。4）定率估算法（历史资料法）。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0348", "date": "2026-07-09", "chapter": "g06", "type": "multiple", "stem": "下列指标中，属于承包企业层面项目成本考核指标的有（ ）。", "options": {"A": "施工计划成本实际降低额", "B": "项目施工成本降低额", "C": "目标总成本降低额", "D": "项目施工成本降低率", "E": "施工责任目标成本实际降低率"}, "answer": ["B", "D"], "analysis": "【内容考查】本题考核的是项目成本考核指标。 【选项分析】1）企业的项目成本考核指标： 项目施工成本降低额和降低率： 2）项目经理部可控责任成本考核指标： ①项目经理责任目标总成本降低额和降低率： ②施工责任目标成本实际降低额和降低率： ③施工计划成本实际降低额和降低率：", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0353", "date": "2026-07-09", "chapter": "g06", "type": "multiple", "stem": "根据相关规定，承包人工程索赔成立的基本条件有（ ）。", "options": {"A": "合同履行过程中承包人没有违约行为", "B": "索赔事件已造成承包人直接经济损失或工期延误", "C": "索赔事件是因非承包人的原因引起的", "D": "承包人已按合同规定提交了索赔意向通知、索赔报告及相关证明材料", "E": "发包人已按合同规定给予了承包人答复"}, "answer": ["B", "C", "D"], "analysis": "【内容考查】本题考查的是 工程索赔的依据和前提条件 【选项分析】承包人工程索赔成立的基本条件包括：1）索赔事件已造成了承包人直接经济损失或工期延误2）造成费用增加或工期延误的索赔事件是因非承包人的原因发生的。3）承包人已经按照工程施工合同规定的期限和程序提交了索赔意向通知、索赔报告及相关证明材料。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0361", "date": "2026-07-09", "chapter": "g06", "type": "multiple", "stem": "在承包人提交的进度款支付申请中，本周期合计完成的合同价款中包括（ ）。", "options": {"A": "本周期已完成单价项目的金额", "B": "本周期应支付的总价项目金额", "C": "本周期应支付的安全文明施工费", "D": "本周期应扣回的预付款", "E": "本周期应增加的金额"}, "answer": ["A", "B", "C", "E"], "analysis": "【内容考查】本题考查的是期中支付。 【选项分析】本周期合计完成的合同价款，其中包括：①本周期已完成单价项目的金额；②本周期应支付的总价项目的金额；③本周期已完成的计日工价款；④本周期应支付的安全文明施工费；⑤本周期应增加的金额。因此选择ABCE。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "gl-g07-001", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "施工成本管理的六个环节正确的顺序是（ ）。", "options": {"A": "计划→预测→控制→核算→分析→考核", "B": "预测→计划→控制→核算→分析→考核", "C": "预测→计划→核算→控制→分析→考核", "D": "计划→预测→核算→控制→考核→分析"}, "answer": ["B"], "analysis": "成本管理6环节的正确顺序为：预测→计划→控制→核算→分析→考核。先预测成本、制定计划，再实施控制，然后核算实际成本，进行分析，最后考核评价。", "tags": ["成本管理", "基础知识"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-002", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "在挣值法中，BCWP的含义是（ ）。", "options": {"A": "计划工作预算费用", "B": "已完工作实际费用", "C": "已完工作预算费用", "D": "计划工作实际费用"}, "answer": ["C"], "analysis": "BCWP(Budgeted Cost for Work Performed)即已完工作预算费用，也称挣值(Earned Value)，计算公式为：已完工作量×预算单价。", "tags": ["挣值法", "BCWP"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-003", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "某工程计划完成工程量1000m³，预算单价200元/m³；实际完成工程量900m³，实际单价210元/m³。则BCWS为（ ）元。", "options": {"A": "180000", "B": "189000", "C": "200000", "D": "210000"}, "answer": ["C"], "analysis": "BCWS(计划工作预算费用)=计划量×预算单价=1000×200=200000元。注意BCWS只看计划和预算，不看实际完成情况。", "tags": ["挣值法", "BCWS", "计算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-004", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "接上题，该工程的BCWP为（ ）元。", "options": {"A": "180000", "B": "189000", "C": "200000", "D": "210000"}, "answer": ["A"], "analysis": "BCWP(挣值)=已完工作量×预算单价=900×200=180000元。注意BCWP用已完量乘以预算单价，不用实际单价。", "tags": ["挣值法", "BCWP", "计算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-005", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "某工程BCWP=180000元，BCWS=200000元，ACWP=189000元，则费用偏差CV为（ ）元。", "options": {"A": "-9000", "B": "-20000", "C": "9000", "D": "-11000"}, "answer": ["A"], "analysis": "CV(费用偏差)=BCWP-ACWP=180000-189000=-9000元。CV为负值表示费用超支9000元。", "tags": ["挣值法", "费用偏差", "计算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-006", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "某工程BCWP=180000元，BCWS=200000元，则进度偏差SV为（ ）元。", "options": {"A": "20000", "B": "-20000", "C": "180000", "D": "-180000"}, "answer": ["B"], "analysis": "SV(进度偏差)=BCWP-BCWS=180000-200000=-20000元。SV为负值表示进度延误，实际完成工作量落后于计划。", "tags": ["挣值法", "进度偏差", "计算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-007", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "关于挣值法指标的说法，正确的是（ ）。", "options": {"A": "CV＞0表示费用超支", "B": "SV＞0表示进度延误", "C": "CPI＞1表示费用节约", "D": "SPI＜1表示进度提前"}, "answer": ["C"], "analysis": "CPI(费用绩效指数)=BCWP/ACWP，当CPI＞1时表示实际费用低于预算费用，即费用节约。CV＞0表示节约(非超支)，SV＞0表示提前(非延误)，SPI＜1表示延误(非提前)。", "tags": ["挣值法", "绩效指数"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-008", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "某工程BCWP=150万元，ACWP=120万元，则费用绩效指数CPI为（ ）。", "options": {"A": "0.8", "B": "1.25", "C": "0.75", "D": "1.33"}, "answer": ["B"], "analysis": "CPI=BCWP/ACWP=150/120=1.25。CPI＞1说明每投入1元成本完成1.25元的工作量，费用处于节约状态。", "tags": ["挣值法", "CPI", "计算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-009", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "某工程某月计划完成工程量500m³，预算单价300元/m³；实际完成400m³，实际单价320元/m³。则费用偏差CV为（ ）元。", "options": {"A": "-8000", "B": "-6000", "C": "8000", "D": "6000"}, "answer": ["A"], "analysis": "BCWP=400×300=120000元，ACWP=400×320=128000元。CV=120000-128000=-8000元，费用超支8000元。", "tags": ["挣值法", "费用偏差", "计算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-010", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "挣值法中，ACWP的计算公式是（ ）。", "options": {"A": "计划量×预算单价", "B": "已完成量×预算单价", "C": "已完成量×实际单价", "D": "计划量×实际单价"}, "answer": ["C"], "analysis": "ACWP(Actual Cost for Work Performed)即已完工作实际费用，=已完成工作量×实际单价，反映实际发生的成本。", "tags": ["挣值法", "ACWP"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-011", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "某土方工程计划开挖5000m³，预算单价20元/m³。截至检查日实际开挖4000m³，实际支出90000元。则进度绩效指数SPI为（ ）。", "options": {"A": "0.8", "B": "0.9", "C": "1.1", "D": "1.25"}, "answer": ["A"], "analysis": "BCWP=4000×20=80000元，BCWS=5000×20=100000元。SPI=BCWP/BCWS=80000/100000=0.8。SPI＜1表示进度滞后。", "tags": ["挣值法", "SPI", "计算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-012", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "工程变更的正确程序是（ ）。", "options": {"A": "批准→提出→审查→实施→调整合同价款", "B": "提出→审查→批准→实施→调整合同价款", "C": "提出→批准→审查→调整合同价款→实施", "D": "审查→提出→批准→实施→调整合同价款"}, "answer": ["B"], "analysis": "工程变更程序为：提出变更→审查→批准→实施变更→调整合同价款。必须先审查再批准，实施后根据实际完成情况调整合同价款。", "tags": ["工程变更", "程序"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-013", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "关于工程变更价款确定原则，说法错误的是（ ）。", "options": {"A": "合同中已有适用价格的，按合同已有价格执行", "B": "合同中有类似价格的，可以参照类似价格", "C": "合同中没有适用或类似价格的，由承包人提出经发包人确认", "D": "合同中没有适用价格的，直接按市场价确定"}, "answer": ["D"], "analysis": "变更价款确定原则：①合同中已有适用价格→按合同价格；②有类似价格→参照类似价格；③无适用或类似价格→由承包人提出，经发包人确认后执行。不能直接按市场价确定。", "tags": ["工程变更", "价款确定"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-015", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "根据规定，承包人应在索赔事件发生后（ ）天内向发包人提出索赔意向通知。", "options": {"A": "7", "B": "14", "C": "28", "D": "42"}, "answer": ["C"], "analysis": "索赔程序：事件发生后28天内，承包人应向发包人提出索赔意向通知书。若未在28天内提出，视为放弃索赔权利。", "tags": ["索赔", "时限"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-016", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "承包人应在索赔事件发生后（ ）天内提交详细的索赔报告。", "options": {"A": "7", "B": "14", "C": "28", "D": "42"}, "answer": ["D"], "analysis": "索赔意向通知后，承包人应在事件发生后42天内(或合同约定时间)提交详细索赔报告，包含索赔依据、费用计算和工期影响分析等。", "tags": ["索赔", "时限"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-017", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "关于不可抗力事件损失承担的说法，正确的是（ ）。", "options": {"A": "全部损失由承包人承担", "B": "全部损失由发包人承担", "C": "各自人员机械损失各自承担，工程实体由发包人承担", "D": "各自人员和机械损失由发包人承担，工程实体各自承担"}, "answer": ["C"], "analysis": "不可抗力损失分担原则：各自的人员伤亡和施工机械设备损坏由各自承担；工程实体(已完工程、材料等)的损坏由发包人承担。", "tags": ["索赔", "不可抗力"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-018", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "因发包人原因导致工程延误，承包人可索赔的内容是（ ）。", "options": {"A": "仅工期", "B": "仅费用", "C": "工期和费用", "D": "仅利润"}, "answer": ["C"], "analysis": "发包人原因造成的延误，属于发包人违约，承包人可以同时索赔工期和费用(含合理利润)。", "tags": ["索赔", "发包人原因"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-019", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "遭遇异常恶劣天气条件导致施工中断，承包人可索赔的内容是（ ）。", "options": {"A": "工期和费用", "B": "仅工期", "C": "仅费用", "D": "不可索赔"}, "answer": ["B"], "analysis": "异常恶劣天气属于不可预见的外部条件，承包人可索赔工期，但不能索赔费用，因为这不是发包人原因造成的。", "tags": ["索赔", "恶劣天气"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-020", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "不可抗力事件发生时，承包人可索赔的内容是（ ）。", "options": {"A": "工期和费用", "B": "仅工期", "C": "仅费用", "D": "工期和利润"}, "answer": ["B"], "analysis": "不可抗力事件发生后，承包人可以索赔工期延长，但各自承担自身的人员和机械损失。工程实体损失由发包人承担，但这属于发包人的直接损失，不属于承包人的费用索赔。", "tags": ["索赔", "不可抗力"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-023", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "工程预付款一般不应低于合同价（暂列金额除外）的（ ）。", "options": {"A": "5%", "B": "10%", "C": "15%", "D": "20%"}, "answer": ["B"], "analysis": "预付款额度一般不低于合同价(扣除暂列金额)的10%，不高于30%。这是保证承包人前期资金周转的基本保障。", "tags": ["价款结算", "预付款"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-024", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "工程预付款的最高限额一般不高于合同价（暂列金额除外）的（ ）。", "options": {"A": "20%", "B": "25%", "C": "30%", "D": "40%"}, "answer": ["C"], "analysis": "预付款一般不低于10%且不高于30%合同价(暂列金额除外)。预付款过高会增加发包人资金压力，过低则影响承包人资金周转。", "tags": ["价款结算", "预付款"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-025", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "预付款起扣点计算公式T=P-M/N中，N表示（ ）。", "options": {"A": "合同总价款", "B": "预付款总额", "C": "主要材料占合同价比重", "D": "已完工程量"}, "answer": ["C"], "analysis": "T=P-M/N中：P=合同价，M=预付款额度，N=主要材料及构件所占合同价比重。起扣点表示当累计完成工程款达到T时开始按比例扣回预付款。", "tags": ["价款结算", "预付款扣回", "计算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-026", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "某工程合同价1000万元，预付款200万元，主要材料占合同价比重为50%，则预付款起扣点T为（ ）万元。", "options": {"A": "400", "B": "500", "C": "600", "D": "800"}, "answer": ["C"], "analysis": "T=P-M/N=1000-200/0.5=1000-400=600万元。即当累计完成工程款达到600万元时，开始按比例扣回预付款。", "tags": ["价款结算", "预付款扣回", "计算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-027", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "进度款的支付比例一般为已完成工程价款的（ ）。", "options": {"A": "50%-80%", "B": "60%-90%", "C": "70%-95%", "D": "80%-100%"}, "answer": ["B"], "analysis": "进度款支付比例一般为已完成工程价款的60%-90%。通常在合同中约定具体比例，发包人按该比例支付进度款，剩余部分在结算时统一处理。", "tags": ["价款结算", "进度款"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-028", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "承包人提交竣工结算文件后，发包人应在（ ）天内完成审查。", "options": {"A": "14", "B": "28", "C": "42", "D": "56"}, "answer": ["B"], "analysis": "竣工结算中，承包人提交竣工结算文件后，发包人应在28天内完成审查并支付。这是保障承包人结算权益的重要时限规定。", "tags": ["价款结算", "竣工结算", "时限"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-029", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "工程结算发生争议时，正确的解决顺序是（ ）。", "options": {"A": "协商→仲裁→调解→诉讼", "B": "协商→调解→仲裁→诉讼", "C": "调解→协商→仲裁→诉讼", "D": "仲裁→协商→调解→诉讼"}, "answer": ["B"], "analysis": "结算争议解决顺序：首先协商解决，协商不成进行调解，调解不成可申请仲裁或提起诉讼。仲裁和诉讼通常只能择一进行(或裁或审)。", "tags": ["价款结算", "争议解决"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-031", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "竣工决算反映的是建设项目（ ）的实际费用。", "options": {"A": "施工阶段", "B": "设计阶段到施工阶段", "C": "招标阶段到竣工阶段", "D": "从筹建到竣工交付使用"}, "answer": ["D"], "analysis": "竣工决算是反映建设项目从筹建开始到竣工交付使用为止的全部实际建设费用的文件，是核定新增固定资产价值的主要依据。", "tags": ["竣工决算", "概念"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-034", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "工程质量保证金预留比例不得超过工程价款结算总额的（ ）。", "options": {"A": "1%", "B": "3%", "C": "5%", "D": "10%"}, "answer": ["B"], "analysis": "质量保证金总预留比例不得高于工程价款结算总额的3%。目前已推行以银行保函方式替代工程质量保证金，减轻承包人的资金压力。", "tags": ["竣工决算", "质量保证金"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-035", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "屋面防水工程的最低保修期限为（ ）。", "options": {"A": "2年", "B": "3年", "C": "5年", "D": "设计使用年限"}, "answer": ["C"], "analysis": "屋面防水工程的最低保修期限为5年。有防水要求的卫生间、房间和外墙面的防渗漏也是5年。", "tags": ["竣工决算", "保修期限"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-036", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "供热与供冷系统的最低保修期限为（ ）。", "options": {"A": "1年", "B": "2个采暖期、供冷期", "C": "3个采暖期、供冷期", "D": "5年"}, "answer": ["B"], "analysis": "供热与供冷系统的保修期限为2个采暖期、供冷期。注意是按供暖/供冷周期计算，不是按自然年计算。", "tags": ["竣工决算", "保修期限"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-037", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "电气管线、给排水管道、设备安装和装修工程的最低保修期限为（ ）。", "options": {"A": "1年", "B": "2年", "C": "3年", "D": "5年"}, "answer": ["B"], "analysis": "电气管线、给排水管道、设备安装和装修工程的最低保修期为2年。这类工程属于常规安装装修工程，保修期相对较短。", "tags": ["竣工决算", "保修期限"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-038", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "基础设施工程、房屋建筑的地基基础工程和主体结构工程的最低保修期限为（ ）。", "options": {"A": "5年", "B": "10年", "C": "50年", "D": "设计文件规定的该工程的合理使用年限"}, "answer": ["D"], "analysis": "基础设施工程、地基基础和主体结构工程的最低保修期为设计文件规定的合理使用年限。这类工程关系到结构安全，保修期最长。", "tags": ["竣工决算", "保修期限"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-042", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "成本考核是成本管理的（ ）环节。", "options": {"A": "第一个", "B": "第三个", "C": "第五个", "D": "最后一个"}, "answer": ["D"], "analysis": "成本管理六环节顺序为：预测→计划→控制→核算→分析→考核。考核是最后一个环节，通过对成本管理结果的评价，落实奖惩措施。", "tags": ["成本管理", "环节"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-043", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "在挣值法分析中，当CV＜0且SV＜0时，表明项目处于（ ）状态。", "options": {"A": "费用节约、进度提前", "B": "费用超支、进度延误", "C": "费用节约、进度延误", "D": "费用超支、进度提前"}, "answer": ["B"], "analysis": "CV＜0表示BCWP＜ACWP，即已完工作的实际费用超出预算，费用超支。SV＜0表示BCWP＜BCWS，即实际完成工作量少于计划，进度延误。", "tags": ["挣值法", "综合分析"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-044", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "某工程截至某时点，BCWP=500万元，ACWP=480万元，BCWS=520万元，则项目状态为（ ）。", "options": {"A": "费用节约、进度提前", "B": "费用超支、进度延误", "C": "费用节约、进度延误", "D": "费用超支、进度提前"}, "answer": ["C"], "analysis": "CV=500-480=20＞0，费用节约；SV=500-520=-20＜0，进度延误。即虽然花钱比预算少，但完成的工作量没达到计划要求。", "tags": ["挣值法", "综合分析"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-045", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "工程变更批准后，承包人在实施变更过程中，变更价款应（ ）。", "options": {"A": "在变更实施前一次性支付", "B": "纳入当期或下期进度款中支付", "C": "在竣工结算时一次性支付", "D": "变更价款不单独支付"}, "answer": ["B"], "analysis": "变更价款确定后，通常纳入当期或下期工程进度款中一并支付，不需要等到竣工结算才支付。这样有利于承包人资金周转。", "tags": ["工程变更", "价款支付"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-046", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "某招标工程的合同价为800万元，预付款为160万元，主要材料占合同价比重为40%。起扣点T的值为（ ）万元。", "options": {"A": "360", "B": "400", "C": "440", "D": "480"}, "answer": ["B"], "analysis": "T=P-M/N=800-160/0.4=800-400=400万元。累计完成工程款达400万元时开始扣回预付款。", "tags": ["价款结算", "预付款扣回", "计算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-048", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "发包人收到承包人提交的竣工结算文件后，若在28天内未提出异议的，则（ ）。", "options": {"A": "视为发包人认可结算文件", "B": "承包人可以单方面确认结算", "C": "需要重新提交结算文件", "D": "自动进入仲裁程序"}, "answer": ["A"], "analysis": "根据规定，发包人应在收到竣工结算文件后28天内完成审查。逾期未提出异议的，视为认可承包人提交的竣工结算文件。", "tags": ["价款结算", "竣工结算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-049", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "挣值法中，反映挣得价值的参数是（ ）。", "options": {"A": "BCWS", "B": "ACWP", "C": "BCWP", "D": "EAC"}, "answer": ["C"], "analysis": "BCWP(Budgeted Cost for Work Performed)也称为挣值(Earned Value)，代表已完成工作量按预算单价计算的挣得价值，是挣值法的核心参数。", "tags": ["挣值法", "基本概念"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-050", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "发包人原因导致工程暂停施工，停工期间承包人的人员窝工费和机械闲置费，应由（ ）承担。", "options": {"A": "承包人自行承担", "B": "发包人承担", "C": "双方各承担一半", "D": "由监理单位承担"}, "answer": ["B"], "analysis": "发包人原因导致停工，属于发包人违约或过错，由此产生的承包人窝工费、机械闲置费等损失应由发包人承担，承包人可以据此提出费用索赔。", "tags": ["索赔", "费用承担"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-051", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "工程变更指令发出前，承包人（ ）实施变更工作。", "options": {"A": "可以先行", "B": "不得擅自", "C": "经监理口头同意可以", "D": "经设计单位同意可以"}, "answer": ["B"], "analysis": "工程变更必须按程序执行：提出→审查→批准→实施。在变更指令正式发出前，承包人不得擅自实施变更工作，否则费用和工期后果自负。", "tags": ["工程变更", "程序"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-053", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "挣值分析中，竣工偏差VAC的计算公式为（ ）。", "options": {"A": "VAC=BAC-EAC", "B": "VAC=EAC-BAC", "C": "VAC=BCWP-ACWP", "D": "VAC=BCWP-BCWS"}, "answer": ["A"], "analysis": "VAC(Variance at Completion)即竣工偏差=BAC(竣工预算)-EAC(竣工估算)。VAC＞0表示预计竣工时费用有结余，VAC＜0表示预计超支。", "tags": ["挣值法", "竣工偏差"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-054", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "表格法进行投资偏差分析的优点是（ ）。", "options": {"A": "形象直观", "B": "信息量大，适用性强", "C": "可以直接显示偏差曲线", "D": "计算简单"}, "answer": ["B"], "analysis": "表格法是投资偏差分析最常用的方法，优点是信息量大、适用性强，可以反映各费用项目的偏差情况。横道图法形象直观，曲线法可直接显示偏差曲线和趋势。", "tags": ["投资偏差分析", "表格法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-055", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "质量保证金推行以（ ）方式替代预留现金。", "options": {"A": "履约保证金", "B": "投标保证金", "C": "银行保函", "D": "工程保险"}, "answer": ["C"], "analysis": "目前已推行以银行保函方式替代工程质量保证金预留现金，目的是为了减轻建筑企业的资金占用压力。", "tags": ["竣工决算", "质量保证金"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-057", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "承包人递交索赔意向通知时，应说明的内容不包括（ ）。", "options": {"A": "索赔事件发生的时间", "B": "索赔事件的简要情况", "C": "索赔的详细费用计算", "D": "索赔依据的合同条款"}, "answer": ["C"], "analysis": "索赔意向通知是初步通知，只需说明索赔事件的基本情况(时间、概况、依据)即可。详细的费用计算和工期影响分析应在后续的详细索赔报告中提供。", "tags": ["索赔", "意向通知"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-058", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "某工程计划砌筑500m³，预算单价400元/m³。月末检查：实际砌筑450m³，实际单价420元/m³。则进度偏差SV为（ ）元。", "options": {"A": "-20000", "B": "-21000", "C": "20000", "D": "-10000"}, "answer": ["A"], "analysis": "BCWP=450×400=180000元，BCWS=500×400=200000元。SV=BCWP-BCWS=180000-200000=-20000元，进度延误。", "tags": ["挣值法", "进度偏差", "计算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-059", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "关于新增固定资产的确定，正确的是（ ）。", "options": {"A": "仅包括建筑安装工程费用", "B": "包括达到固定资产标准的设备工器具购置费", "C": "不包括待摊投资分摊部分", "D": "不包括工程建设其他费用"}, "answer": ["B"], "analysis": "新增固定资产包括建筑安装工程费、达到固定资产标准的设备工器具购置费、待摊投资分摊及其他费用中形成固定资产的部分。", "tags": ["竣工决算", "新增固定资产"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-061", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "费用绩效指数CPI=0.9说明（ ）。", "options": {"A": "每投入1元获得0.9元的工作量，费用超支", "B": "每投入1元获得1.1元的工作量，费用节约", "C": "进度完成90%", "D": "费用节约10%"}, "answer": ["A"], "analysis": "CPI=0.9＜1，表示每投入1元只完成0.9元预算工作量，费用超支10%。这不是进度指标(SPI才是进度指标)，而是费用效率指标。", "tags": ["挣值法", "CPI"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-062", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "工程进度款支付时，发包人应按照不低于（ ）的比例支付。", "options": {"A": "50%", "B": "60%", "C": "70%", "D": "80%"}, "answer": ["B"], "analysis": "进度款支付比例一般为已完成工程价款的60%-90%。故最低比例不应低于60%。", "tags": ["价款结算", "进度款"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-063", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "成本分析的主要目的是（ ）。", "options": {"A": "编制成本计划", "B": "确定成本目标", "C": "找出成本偏差原因并提出改进措施", "D": "对成本管理成果进行奖惩"}, "answer": ["C"], "analysis": "成本分析是在成本核算基础上，分析成本偏差原因，总结经验教训，提出改进措施。编制计划和确定目标是预测/计划环节的任务，奖惩是考核环节的任务。", "tags": ["成本管理", "成本分析"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-064", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "新增无形资产通常不包括（ ）。", "options": {"A": "专利权", "B": "土地使用权", "C": "办公家具", "D": "非专利技术"}, "answer": ["C"], "analysis": "新增无形资产包括专利权、商标权、土地使用权、非专利技术等。办公家具属于固定资产范畴，不属于无形资产。", "tags": ["竣工决算", "新增无形资产"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-001", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "施工成本管理的正确环节顺序是？", "options": {"A": "计划→预测→控制→核算→分析→考核", "B": "预测→计划→控制→核算→分析→考核", "C": "预测→控制→计划→核算→考核→分析", "D": "计划→控制→预测→分析→核算→考核"}, "answer": ["B"], "analysis": "施工成本管理6环节的正确顺序：预测→计划→控制→核算→分析→考核。预测是起点，考核是终点。", "tags": ["成本管理", "管理环节"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-006", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "费用偏差CV的计算公式是？", "options": {"A": "CV = BCWS - ACWP", "B": "CV = BCWP - BCWS", "C": "CV = BCWP - ACWP", "D": "CV = BCWS - BCWP"}, "answer": ["C"], "analysis": "CV（Cost Variance）= BCWP - ACWP = 已完工作预算费用 - 已完工作实际费用。CV>0表示费用节约，CV<0表示费用超支。", "tags": ["挣值法", "CV"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-007", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "进度偏差SV的计算公式是？", "options": {"A": "SV = BCWP - ACWP", "B": "SV = BCWP - BCWS", "C": "SV = BCWS - ACWP", "D": "SV = ACWP - BCWS"}, "answer": ["B"], "analysis": "SV（Schedule Variance）= BCWP - BCWS = 已完工作预算费用 - 计划工作预算费用。SV>0表示进度提前，SV<0表示进度延误。", "tags": ["挣值法", "SV"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-008", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "费用绩效指数CPI的计算公式是？", "options": {"A": "CPI = BCWP / BCWS", "B": "CPI = BCWS / BCWP", "C": "CPI = BCWP / ACWP", "D": "CPI = ACWP / BCWP"}, "answer": ["C"], "analysis": "CPI（Cost Performance Index）= BCWP / ACWP = 已完工作预算费用 / 已完工作实际费用。CPI>1表示费用节约，CPI<1表示费用超支。", "tags": ["挣值法", "CPI"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-009", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "进度绩效指数SPI的计算公式是？", "options": {"A": "SPI = BCWP / BCWS", "B": "SPI = BCWS / BCWP", "C": "SPI = BCWP / ACWP", "D": "SPI = ACWP / BCWP"}, "answer": ["A"], "analysis": "SPI（Schedule Performance Index）= BCWP / BCWS = 已完工作预算费用 / 计划工作预算费用。SPI>1表示进度提前，SPI<1表示进度延误。", "tags": ["挣值法", "SPI"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-010", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "某工程某月计划完成工程量100m³，预算单价200元/m³；实际完成工程量120m³，实际单价180元/m³。该月的费用偏差CV为多少？", "options": {"A": "-2400元（超支）", "B": "+2400元（节约）", "C": "+4000元（节约）", "D": "-4000元（超支）"}, "answer": ["B"], "analysis": "BCWP=120×200=24000元，ACWP=120×180=21600元，CV=24000-21600=+2400元（正数为节约）。", "tags": ["挣值法", "CV", "计算题"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-013", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "某工程某月计划完成工作量预算金额为50000元，实际完成工作量预算金额为55000元，实际完成工作量实际费用为52000元。该月的CPI为多少？", "options": {"A": "0.945（费用超支）", "B": "1.058（费用节约）", "C": "1.100（费用节约）", "D": "0.909（费用超支）"}, "answer": ["B"], "analysis": "BCWP=55000元，ACWP=52000元，CPI=55000/52000=1.058（>1表示费用节约）。", "tags": ["挣值法", "CPI", "计算题"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-014", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "某工程某月BCWP=30000元，BCWS=40000元，ACWP=35000元。该月的SPI为多少？", "options": {"A": "0.75（进度延误）", "B": "1.33（进度提前）", "C": "0.857（进度延误）", "D": "1.167（进度提前）"}, "answer": ["A"], "analysis": "SPI=BCWP/BCWS=30000/40000=0.75（<1表示进度延误）。", "tags": ["挣值法", "SPI", "计算题"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-015", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "某工程某月末，BCWP=120万元，BCWS=100万元，ACWP=130万元。下列说法正确的是？", "options": {"A": "费用节约，进度提前", "B": "费用超支，进度提前", "C": "费用节约，进度延误", "D": "费用超支，进度延误"}, "answer": ["B"], "analysis": "CV=BCWP-ACWP=120-130=-10万元<0（费用超支）。SV=BCWP-BCWS=120-100=+20万元>0（进度提前）。", "tags": ["挣值法", "偏差判断"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-018", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "某项目前3个月累计数据：BCWP=200万元，BCWS=240万元，ACWP=220万元。该项目的执行情况是？", "options": {"A": "CV=-20万元超支，SV=-40万元延误", "B": "CV=+20万元节约，SV=-40万元延误", "C": "CV=-20万元超支，SV=+40万元提前", "D": "CV=+20万元节约，SV=+40万元提前"}, "answer": ["A"], "analysis": "CV=200-220=-20万元（超支），SV=200-240=-40万元（延误）。", "tags": ["挣值法", "偏差判断", "累计"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-019", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "某工程施工至某月底，BCWP=360万元，BCWS=300万元，ACWP=400万元。该工程的CPI和SPI分别为？", "options": {"A": "CPI=0.9，SPI=1.2", "B": "CPI=1.2，SPI=0.9", "C": "CPI=0.9，SPI=0.9", "D": "CPI=1.2，SPI=1.2"}, "answer": ["A"], "analysis": "CPI=BCWP/ACWP=360/400=0.9（<1费用超支），SPI=BCWP/BCWS=360/300=1.2（>1进度提前）。", "tags": ["挣值法", "CPI", "SPI"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-021", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "某工程计划完成工程量200m³，预算单价400元/m³；实际完成工程量180m³，实际单价420元/m³。该工程的费用偏差CV为？", "options": {"A": "-3600元", "B": "+3600元", "C": "-8000元", "D": "+8000元"}, "answer": ["A"], "analysis": "BCWP=180×400=72000元，ACWP=180×420=75600元，CV=72000-75600=-3600元（超支）。", "tags": ["挣值法", "CV", "计算题"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-022", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "根据上题数据，该工程的进度偏差SV为？", "options": {"A": "-3600元", "B": "+3600元", "C": "-8000元", "D": "+8000元"}, "answer": ["C"], "analysis": "BCWP=180×400=72000元，BCWS=200×400=80000元，SV=72000-80000=-8000元（延误）。", "tags": ["挣值法", "SV", "计算题"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-023", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "某分部工程，预算单价为500元/m³，计划3个月完成，每月计划完成量均为200m³。第1个月实际完成150m³，实际单价520元/m³。第1个月的CPI为？", "options": {"A": "0.962", "B": "1.040", "C": "0.750", "D": "1.333"}, "answer": ["A"], "analysis": "BCWP=150×500=75000元，ACWP=150×520=78000元，CPI=75000/78000=0.962（<1费用超支）。", "tags": ["挣值法", "CPI", "计算题"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-024", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "根据上题数据，第1个月的SPI为？", "options": {"A": "0.962", "B": "1.040", "C": "0.750", "D": "1.333"}, "answer": ["C"], "analysis": "BCWP=150×500=75000元，BCWS=200×500=100000元，SPI=75000/100000=0.75（<1进度延误）。", "tags": ["挣值法", "SPI", "计算题"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-025", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "某工程计划一个月完成1000m²路面施工，预算综合单价80元/m²。月底实际完成1100m²，实际综合单价75元/m²。该月挣值BCWP为？", "options": {"A": "80000元", "B": "82500元", "C": "88000元", "D": "75000元"}, "answer": ["C"], "analysis": "BCWP=已完成量×预算单价=1100×80=88000元。注意：挣值使用预算单价而非实际单价。", "tags": ["挣值法", "BCWP", "计算题"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-028", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "关于工程变更价款的确定原则，下列说法正确的是？", "options": {"A": "已有适用价格的，仍需重新组价", "B": "有类似价格的，可以直接套用不调整", "C": "已有适用价格的，按已有价格执行", "D": "无类似价格的，由发包人单方确定"}, "answer": ["C"], "analysis": "变更价款确定原则：①已标价工程量清单中有适用于变更项目的，采用该项目的单价（C正确）；②有类似项目的，参照类似项目单价调整（B错误需调整）；③无适用也无类似项目的，由承包人提出变更单价，经发包人确认后执行（D错误非发包人单方确定）。", "tags": ["工程变更", "价款确定"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-030", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "因工程变更引起措施项目发生变化的，下列说法正确的是？", "options": {"A": "措施费一律不调整", "B": "措施费由发包人自行决定是否调整", "C": "承包人事先应将拟实施的方案提交发包人确认后调整", "D": "措施费自动按比例调整"}, "answer": ["C"], "analysis": "工程变更引起措施项目发生变化的，承包人应事先将拟实施的方案提交发包人确认。经确认后，措施项目费应按规定进行调整。", "tags": ["工程变更", "措施费调整"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-031", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "工程变更引起施工方案改变的，承包人的正确做法是？", "options": {"A": "先实施变更再提出方案", "B": "擅自按照新方案施工", "C": "事先将拟实施的方案提交发包人确认", "D": "在结算时一次性提出变更要求"}, "answer": ["C"], "analysis": "工程变更引起施工方案改变并使措施项目发生变化时，承包人提出调整措施项目费的，应事先将拟实施的方案提交发包人确认，并详细说明变化情况。", "tags": ["工程变更", "方案变更"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-032", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "承包人在索赔事件发生后多少天内，应向发包人提交索赔意向通知书？", "options": {"A": "14天", "B": "28天", "C": "42天", "D": "56天"}, "answer": ["B"], "analysis": "承包人应在知道或应当知道索赔事件发生后28天内，向监理人递交索赔意向通知书，并说明发生索赔事件的事由。逾期未提出，视为放弃索赔权利。", "tags": ["索赔", "程序时限"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-033", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "承包人应在发出索赔意向通知书后多少天内，向监理人正式递交索赔报告？", "options": {"A": "28天", "B": "35天", "C": "42天", "D": "56天"}, "answer": ["C"], "analysis": "承包人应在发出索赔意向通知书后42天内，向监理人正式递交索赔报告。索赔报告应详细说明索赔理由以及要求追加的金额和（或）延长的工期，并附必要的记录和证明材料。", "tags": ["索赔", "程序时限"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-034", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "发包人在收到承包人索赔报告后，应在多少天内做出答复？", "options": {"A": "14天", "B": "28天", "C": "42天", "D": "60天"}, "answer": ["B"], "analysis": "发包人（通过监理人）收到承包人提交的索赔报告和有关资料后，应在28天内做出答复，或要求承包人进一步补充索赔理由和证据。逾期未答复视为认可索赔要求。", "tags": ["索赔", "程序时限"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-036", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "因发包人原因造成工程延误，承包人可以索赔的内容是？", "options": {"A": "仅工期", "B": "仅费用", "C": "工期和费用均可", "D": "均不可索赔"}, "answer": ["C"], "analysis": "因发包人原因造成工程延误，承包人可同时索赔工期和费用。发包人应承担因其原因导致的工期延长和费用增加。", "tags": ["索赔", "发包人原因"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-037", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "因不可抗力导致的损失，承包人可以索赔的内容是？", "options": {"A": "工期和全部费用", "B": "工期，但人员机械损失各自承担", "C": "仅费用", "D": "均不可索赔"}, "answer": ["B"], "analysis": "不可抗力发生后，承包人可索赔工期。工程本身的损害和运至现场的发包人材料设备损害由发包人承担；承包人的施工机械设备损坏及停工损失由承包人承担；各自人员伤亡由各自承担。", "tags": ["索赔", "不可抗力"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-038", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "出现异常恶劣的气候条件，承包人可以索赔？", "options": {"A": "工期和费用", "B": "仅工期", "C": "仅费用", "D": "均不可索赔"}, "answer": ["B"], "analysis": "异常恶劣的气候条件属于可索赔工期但不索赔费用的情形。工期的延误可以得到补偿，但由此增加的费用由承包人自行承担（除非合同另有特别约定）。", "tags": ["索赔", "异常恶劣天气"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-039", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "发包人提供的材料和设备不符合合同要求，导致承包人停工，承包人可以索赔？", "options": {"A": "仅工期", "B": "仅费用", "C": "工期和费用", "D": "均不可索赔"}, "answer": ["C"], "analysis": "发包人提供的材料和设备不符合合同要求，属于发包人原因导致的延误和损失，承包人可同时索赔工期和费用。", "tags": ["索赔", "发包人供材不合格"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-040", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "发包人未按合同约定提供设计图纸，导致工期延误，承包人可以索赔？", "options": {"A": "仅工期", "B": "仅费用", "C": "工期和费用", "D": "均不可索赔"}, "answer": ["C"], "analysis": "发包人未按合同约定提供图纸属于发包人违约行为，导致承包人无法按时施工，承包人可以索赔工期和相应的费用损失。", "tags": ["索赔", "图纸延误"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-041", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "由承包人自身原因（施工组织不当、施工质量不合格等）造成的工期延误，承包人？", "options": {"A": "可索赔工期", "B": "可索赔费用", "C": "可索赔工期和费用", "D": "不可索赔，且应承担违约责任"}, "answer": ["D"], "analysis": "承包人自身原因造成的工期延误，承包人不可索赔工期或费用，且应承担由此造成的损失和违约责任，包括可能向发包人支付误期损害赔偿金。", "tags": ["索赔", "承包人原因"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-042", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "发生共同延误时，责任由谁承担？", "options": {"A": "双方平均分摊", "B": "发包人承担全部责任", "C": "由初始责任方（先发生延误的一方）承担", "D": "承包人承担全部责任"}, "answer": ["C"], "analysis": "共同延误（并发延误）的处理原则：由初始责任方承担延误责任。即先发生延误的一方对被延误方的后续影响负有责任。不能简单划分时，按各自责任分担。", "tags": ["索赔", "共同延误"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-045", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "承包人索赔成立必须具备的条件不包括？", "options": {"A": "与合同相比较，已经造成了实际的额外费用或工期损失", "B": "造成费用增加或工期损失的原因不属于承包人的行为责任", "C": "承包人提交了索赔意向通知书和索赔报告", "D": "发包人已确认同意赔偿"}, "answer": ["D"], "analysis": "承包人索赔成立的条件包括：①造成了实际的额外费用或工期损失；②损失原因不属于承包人行为责任；③按规定程序和时间提交了索赔通知和报告。发包人的确认不是索赔成立的先决条件，索赔是否成立应以事实和合同为依据。", "tags": ["索赔", "成立条件"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-047", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "工程预付款的支付比例一般是多少？", "options": {"A": "5%-10%", "B": "10%-30%", "C": "30%-50%", "D": "50%-70%"}, "answer": ["B"], "analysis": "工程预付款一般不低于合同价（扣除暂列金额）的10%，不高于30%。具体比例由双方在合同中约定。", "tags": ["预付款", "支付比例"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-048", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "预付款起扣点的计算公式 T=P-M/N 中，N代表？", "options": {"A": "预付款额度", "B": "合同总价", "C": "主要材料和构件占合同价的比例", "D": "预付款占合同价比例"}, "answer": ["C"], "analysis": "起扣点公式T=P-M/N中：T=起扣点（累计完成工程款累计额），P=合同价（扣除暂列金额），M=预付款额度，N=主要材料及构件所占合同价比重。", "tags": ["预付款", "起扣点"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-049", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "某工程合同价（扣除暂列金额）为5000万元，预付款额度为1000万元，主要材料占合同价比重为60%。预付款起扣点T为多少万元？", "options": {"A": "3000万元", "B": "3333.33万元", "C": "4000万元", "D": "2500万元"}, "answer": ["B"], "analysis": "T=P-M/N=5000-1000/60%=5000-1666.67=3333.33万元。当累计完成工程款达到3333.33万元时开始起扣预付款。", "tags": ["预付款", "起扣点", "计算题"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-050", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "某工程合同价（扣除暂列金额）为3000万元，预付款为750万元，主要材料占比50%。起扣点为？", "options": {"A": "1000万元", "B": "1200万元", "C": "1500万元", "D": "1800万元"}, "answer": ["C"], "analysis": "T=P-M/N=3000-750/50%=3000-1500=1500万元。", "tags": ["预付款", "起扣点", "计算题"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-053", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "进度款支付比例一般为？", "options": {"A": "30%-60%", "B": "50%-80%", "C": "60%-90%", "D": "70%-100%"}, "answer": ["C"], "analysis": "进度款支付比例一般不低于60%，不高于90%。具体比例由发包人和承包人在合同中约定。", "tags": ["进度款", "支付比例"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-055", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "关于预付款的扣回，下列说法正确的是？", "options": {"A": "预付款在开工后即开始扣回", "B": "预付款扣回方式只有等额扣回一种", "C": "预付款应在累计完成工程款达到起扣点后开始扣回", "D": "预付款应在合同中约定不扣回"}, "answer": ["C"], "analysis": "预付款扣回的基本原则：在累计完成工程款达到起扣点后开始扣回。扣回方式可以是等额扣回或等比率扣回，由合同约定。A错误：非开工即扣；B错误：有多种扣回方式。", "tags": ["预付款", "扣回"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-056", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "承包人应在竣工验收合格后多少天内，向发包人提交竣工结算文件？", "options": {"A": "14天", "B": "21天", "C": "28天", "D": "42天"}, "answer": ["C"], "analysis": "承包人应在工程竣工验收合格后28天内，向发包人（或监理人）提交竣工结算文件。未在规定时间内提交且未说明理由的，发包人有权根据已有资料进行审查。", "tags": ["竣工结算", "提交时限"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-057", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "发包人收到竣工结算文件后，应在多少天内完成审查？", "options": {"A": "14天", "B": "21天", "C": "28天", "D": "56天"}, "answer": ["C"], "analysis": "发包人应在收到承包人提交的竣工结算文件后的28天内完成审查。工程规模大、技术复杂的可适当延长审查期限，但应在合同专用条款中约定。", "tags": ["竣工结算", "审查时限"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-058", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "质量保证金预留比例不得超过工程价款结算总额的多少？", "options": {"A": "2%", "B": "3%", "C": "5%", "D": "10%"}, "answer": ["B"], "analysis": "发包人应按照合同约定的质量保证金比例从结算款中预留质量保证金，但质量保证金总预留比例不得高于工程价款结算总额的3%。", "tags": ["竣工结算", "质保金"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-059", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "关于质量保证金，下列说法正确的是？", "options": {"A": "只能用现金形式预留", "B": "可用质量保函代替", "C": "预留比例不设上限", "D": "在工程开工时预留"}, "answer": ["B"], "analysis": "质量保证金可以用银行保函、担保保函等形式代替现金预留。A错误：可用保函代替；C错误：上限为结算总额的3%；D错误：在竣工结算时预留，非开工时。", "tags": ["竣工结算", "质保金"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-060", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "竣工结算发生争议时，正确的处理顺序是？", "options": {"A": "仲裁→诉讼→调解→协商", "B": "诉讼→仲裁→协商→调解", "C": "协商→调解→仲裁→诉讼", "D": "调解→协商→诉讼→仲裁"}, "answer": ["C"], "analysis": "竣工结算争议的正确解决顺序：协商→调解→仲裁→诉讼。即先双方友好协商，协商不成可调解，仍不能解决则依合同约定仲裁或诉讼。", "tags": ["竣工结算", "争议解决"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-062", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "竣工决算的内容不包括？", "options": {"A": "竣工财务决算报表", "B": "竣工财务决算说明书", "C": "施工组织设计", "D": "竣工图及造价对比分析"}, "answer": ["C"], "analysis": "竣工决算的内容包括：竣工财务决算报表、竣工财务决算说明书、竣工图、工程造价对比分析。施工组织设计属于施工前期文件，不属于竣工决算内容。", "tags": ["竣工决算", "决算内容"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-065", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "下列属于无形资产的是？", "options": {"A": "施工机械设备", "B": "土地使用权", "C": "临时设施", "D": "低值易耗品"}, "answer": ["B"], "analysis": "土地使用权属于无形资产。A施工机械设备属于固定资产；C临时设施属于固定资产；D低值易耗品属于流动资产。", "tags": ["竣工决算", "无形资产"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-067", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "关于【待核销基建支出】，下列说法正确的是？", "options": {"A": "属于新增固定资产", "B": "可以计入新增无形资产", "C": "不计入新增资产价值，直接核销", "D": "属于流动资产"}, "answer": ["C"], "analysis": "待核销基建支出是指非经营性项目发生的不能形成资产的支出（如江河清障、航道清淤、水土保持等），不计入新增资产价值，直接予以核销。", "tags": ["竣工决算", "待核销基建支出"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-068", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "关于【转出投资】，下列说法正确的是？", "options": {"A": "计入固定资产价值", "B": "属于本项目的资产", "C": "本项目发生但不属于本项目的投资支出，转出给其他单位", "D": "属于无形资产"}, "answer": ["C"], "analysis": "转出投资是指非经营性项目为本项目配套建设的、产权不属于本单位的专用设施的投资支出（如专用铁路、专用道路等），这些投资需转出给接收单位，不计入本项目的资产价值。", "tags": ["竣工决算", "转出投资"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-069", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "建设工程保修期从何时起算？", "options": {"A": "签订合同之日", "B": "开工之日", "C": "竣工验收合格之日", "D": "竣工结算完成之日"}, "answer": ["C"], "analysis": "建设工程的保修期自竣工验收合格之日起计算。这是《建设工程质量管理条例》的明确规定。", "tags": ["保修", "保修期起算"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-071", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "屋面防水工程和有防水要求的卫生间的保修期最低为？", "options": {"A": "2年", "B": "3年", "C": "5年", "D": "10年"}, "answer": ["C"], "analysis": "屋面防水工程、有防水要求的卫生间、房间和外墙面的防渗漏，最低保修期限为5年。", "tags": ["保修", "保修期", "防水"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-072", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "供热与供冷系统的保修期最低为？", "options": {"A": "1个采暖期/供冷期", "B": "2个采暖期/供冷期", "C": "3个采暖期/供冷期", "D": "5年"}, "answer": ["B"], "analysis": "供热与供冷系统，保修期最低为2个采暖期、供冷期。注意是2个周期而非固定的年数。", "tags": ["保修", "保修期", "供热供冷"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-075", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "保修期内因施工方原因造成的质量缺陷，保修责任如何承担？", "options": {"A": "发包方自行承担维修费用", "B": "施工方负责免费维修", "C": "由保修基金承担", "D": "施工方和发包方各承担一半"}, "answer": ["B"], "analysis": "保修期内，因施工方原因造成的质量缺陷，施工方应当负责免费维修并承担由此造成的损失。这是施工方的法定义务。", "tags": ["保修", "保修责任"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-076", "date": "2026-07-08", "chapter": "g07", "type": "single", "stem": "保修期内因使用不当或第三方原因造成的质量缺陷，责任如何承担？", "options": {"A": "施工方免费维修", "B": "发包方与施工方协商解决，使用方承担费用", "C": "由保修基金承担", "D": "无需维修"}, "answer": ["B"], "analysis": "因使用不当或第三方原因造成的质量缺陷，不属于施工方的保修责任范围。应由责任方承担维修费用，施工方可协助维修，但费用由使用方或第三方承担。双方协商解决。", "tags": ["保修", "保修责任"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "ht_mgmt_1617", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "在施工成本管理的各类措施中，一般不需增加费用，而且是其他各类措施的前提和保障的是（）。", "options": {"A": "过程控制措施", "B": "经济措施", "C": "技术措施", "D": "组织措施"}, "answer": ["D"], "analysis": "组织措施是从施工成本管理的组织方面采取的措施。组织措施是其他各类措施的前提和保障，而且一般不需要增加什么费用，运用得当可以收到良好的效果。所", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1618", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "施工成本分析是在（）的基础上，对成本的形成过程和影响因素进行分析。", "options": {"A": "施工成本计划", "B": "施工成本预测", "C": "施工成本核算", "D": "施工成本考核"}, "answer": ["C"], "analysis": "成本分析是在成本核算的基础上，对成本的形成过程和影响成本升降的因素进行分析，以寻求进一步降低成本的途径，包括有利偏差的挖掘和不利偏差的纠正。成本分析贯穿于成本管理的全过程，主要利用项目的成本核算资料（成本信息），与目标成本、预算成本以及类似项目的实际成本等进行比较，了解成本的变动情况。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1619", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "为了取得成本管理的理想效果，项目经理可采取的组织措施是（）。", "options": {"A": "加强施工调度，避免窝工损失", "B": "进行技术经济分析，确定最佳施工方案", "C": "对各种变更及时落实业主签证", "D": "研究合同条款，寻找索赔机会"}, "answer": ["A"], "analysis": "组织措施是从施工成本管理的组织方面采取的措施。施工成本控制是全员的活动，如实行项目经理责任制，落实施工成本管理的组织机构和人员，明确各级施工成本管理人员的任务和职能分工、权利和责任。施工成本管理不仅是专业成本管理人员的工作，各级项目管理人员都负有成本控制责任。B属于技术措施;C属于经济措施;D属于合同措施。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1620", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "根据建设工程项目施工成本的组成，属于直接成本的是（）", "options": {"A": "工具用具使用费", "B": "职工教育经费", "C": "机械折旧费", "D": "管理人员工资"}, "answer": ["C"], "analysis": "直接成本是指施工过程中耗费的构成工程实体或有助于工程实体形成的各项费用支出，是可以直接计入工程对象的费用，包括人工费、材料费和施工机具使用费等。C属于施工机具使用费;ABD属于间接成本。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1621", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "作为施工企业全面成本管理的重要环节，施工项目成本控制应贯穿于（）的全过程。", "options": {"A": "从项目策划开始到项目开始运营", "B": "从项目设计开始到项目开始运营", "C": "从项目投标开始到项目保证金返还", "D": "从项目施工开始到项目竣工验收"}, "answer": ["C"], "analysis": "建设工程项目施工成本控制应贯穿于项目从投标阶段开始直至保证金返还的全过程。成本控制可分为事先控制、事中控制（过程控制）和事后控制。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1622", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "建筑施工企业编制实施性成本计划时，宜以（）为依据。", "options": {"A": "施工图预算成本", "B": "工程概算成本", "C": "施工预算成本", "D": "施工结算成本"}, "answer": ["C"], "analysis": "施工成本计划按其作用可分为三类，即竞争性成本计划、指导性成本计划与实施性成本计划。竞争性成本计划是估算成本计划，以招标文件中的合同条件、投标者须知、技术规程、设计图纸或工程量清单等为依据；指导性成本计划是预算成本计划，以合同标书为依据；实施性成本计划是施工预算成本计划，以项目实施方案为依据。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1623", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "某施工企业经过投标获得了某工程的施工任务，合同签订后，公司有关部门开始选派项目经理并编制成本计划。该阶段所编制的成本计划属于（）。", "options": {"A": "竞争性成本计划", "B": "指导性成本计划", "C": "实施性成本计划", "D": "战略性成本计划"}, "answer": ["B"], "analysis": "指导性成本计划即选派项目经理阶段的预算成本计划，是项目经理的责任成本目标。它是以合同价为依据，按照企业的预算定额标准制定的设计预算成本计划，且一般情况下以此确定责任总成本指标。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1626", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "建设工程项目施工准备阶段的施工预算成本计划以项目实施方案为依据，采用（）编制。", "options": {"A": "人工定额", "B": "概算定额", "C": "预算定额", "D": "施工定额"}, "answer": ["D"], "analysis": "实施性计划成本即项目施工准备阶段的施工预算成本计划，采用企业的施工定额，通过施工预算的编制而形成的实施性施工成本计划。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1627", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "在编制施工成本计划时，通常需要进行“两算”对比分析，“两算”指的是（）。", "options": {"A": "施工图预算、成本核算", "B": "施工图预算、施工预算", "C": "施工预算、成本核算", "D": "施工预算、施工决算"}, "answer": ["B"], "analysis": "在编制实施性成本计划时要进行施工预算和施工图预算的对比分析，通过“两算”对比，分析节约和超支的原因，以便制定解决问题的措施，防止工程亏损，为降低工程成本提供依据。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1628", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "施工成本控制需要进行实际成本情况与施工成本计划的比较，其中实际成本情况是通过（）反映的。", "options": {"A": "工程变更文件", "B": "进度报告", "C": "施工组织设计", "D": "分包合同"}, "answer": ["B"], "analysis": "进度报告提供了对应时间节点的工程实际完成量，工程成本实际支出情况等重要信息。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1629", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "施工企业组织生产、编制施工计划。签发任务书的依据是（）。", "options": {"A": "施工预算", "B": "施工图预算", "C": "投标报价", "D": "项目经理的责任成本"}, "answer": ["A"], "analysis": "施工预算是施工企业组织生产、编制施工计划、准备现场材料、签发任务书、考核功效、进行紧急核算的依据，也是施工企业改善经营管理、降低生产成本和推行内部经营承包责任制的重要手段。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1630", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "若按项目组成编制施工成本计划，项目应按（）的顺序依次进行分解。", "options": {"A": "单项工程-单位工程-分部工程-分项工程", "B": "单项工程-分部工程-单位工程-分项工程", "C": "单位工程-单项工程-分部工程-分项工程", "D": "单位工程-单项工程-分项工程-分部工程"}, "answer": ["A"], "analysis": "大中型工程项目通常是由若干单项工程构成的，而每个单项工程包括了多个单位工程，每个单位工程又是由若干个分部分项工程所构成。因此，首先要把项目，总施工成本分解到单项工程和单位工程中，再进一步分解为分部工程和分项工程。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1631", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "编制大中型建设工程项目施工成本支出计划时，要在项目总的方面考虑总的预备费，也要在（）中考虑不可预见费。", "options": {"A": "前期工作", "B": "主要分项工程", "C": "企业管理费", "D": "所有的分项工程"}, "answer": ["B"], "analysis": "在编制成本支出计划时，要在项目总的方面考虑总的预备费，也要在主要的分项工程中安排适当的不可预见费。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1632", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "采用时间一成本累积曲线编制建设工程项目进度计划时，从节约资金贷款利息的角度出发，适宜采取的做法是（）。", "options": {"A": "所有工作均按最早时间开始", "B": "关键工作均按最迟开始时间开始", "C": "所有工作均按最迟开始时间开始", "D": "关键工作均按最早开始时间开始"}, "answer": ["C"], "analysis": "一般而言，所有工作都按最迟开始时间开始，对节约资金贷款利息是有利的。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1633", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "某土方工程，计划总工程量为4800m3预算单价为580 元/m3，计划 个月内均衡完成，开工后，实际单价为600 元/m3，施工至第3 个月底，累计实际完成工程量3000m3，若运用赢得值法分析，则至第3 个月底的费用偏差为（）万元。", "options": {"A": "-34.8", "B": "-6", "C": "6", "D": "34.8"}, "answer": ["B"], "analysis": "计算过程如下： 已完工作预算费用（BCWP）=已完成工作量×预算单价=3000×580=174（万元） 已完工作实际费用（ACWP）=已完成工作量×实际单价=3000×600=180（万元） 费用偏差（CV）=BCWP-ACWP=174-180=-6（万元）。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1634", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "业务核算是施工成本分析的依据之一，其目的是（）。", "options": {"A": "预测成本变化发展的趋势", "B": "迅速取得资料，及时采取措施调整经济活动", "C": "计算当前的实际成本水平", "D": "记录企业的一切生产经营活动"}, "answer": ["B"], "analysis": "业务核算的范围比会计、统计核算要广。会计和统计核算一般是对已经发生的经济活动进行核算，而业务核算不但可以核算已经完成的项目是否达到原定的目的、取得预期的效果，而且可以对尚未发生或正在发生的经济活动进行核算，以确定该项经济活动是否有经济效果，是否有执行的必要。业务核算的目的在于迅速取得资料，以便在经济活动中及时采取措施进行调整。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1635", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "分部分项工程成本分析采用的\"三算\"对比分析法，其\"三算\"对比指的是（）的比较。", "options": {"A": "概算成本、预算成本、决算成本", "B": "预算成本、目标成本、实际成本", "C": "月度成本、季度成本、年度成本", "D": "预算成本、计划成本、目标成本"}, "answer": ["B"], "analysis": "分部分项工程成本分析是施工项目成本分析的基础。分部分项工程成本分析的对象为已完成分部分项工程。分析的方法是：进行预算成本、目标成本和实际成本的“三算”对比。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1636", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "在建设工程项目施工成本分析中，成本盈亏异常分析属于（）方法。", "options": {"A": "因素分析", "B": "综合成本分析", "C": "专项成本分析", "D": "成本项目分析"}, "answer": ["C"], "analysis": "针对与成本有关的特定事项的分析，包括成本盈亏异常分析、工期成本分析和资金成本分析等内容。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1637", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "某项目在进行资金成本分析时，其计算期实际工程款收入为220 万元，计算期实际成本支出为119万元，计划工期成本为150 万元，则该项目成本支出率为（）。", "options": {"A": "30.69%", "B": "54.09%", "C": "68.18%", "D": "79.33%"}, "answer": ["B"], "analysis": "进行资金成本分析通常应用“成本支出率”指标，即成本支出占工程款收入的比例，计算公式如下：成本支出率= 计算期实际成本支出/计算期实际工程款收入×100%，即119/220=54.09%。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1638", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "成本核算要求的归集“三同步”是指（）的取值范围应当一致。", "options": {"A": "形象进度、产值统计、实际成本", "B": "成本预测、成本计划、成本分析", "C": "目标成本、预算成本、实际成本", "D": "人工成本、材料成本、机械成本"}, "answer": ["A"], "analysis": "项目成本核算应坚持形象进度、产值统计、成本归集同步的原则。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1640", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "在FIDIC合同条件下，当变更的工程量与对该项工作规定的具体费率的乘积超过了接受合同额的一定比例时，其费率或单价可以调整，该比例为()。", "options": {"A": "10％", "B": "1％", "C": "0.1％", "D": "0.01％"}, "answer": ["D"], "analysis": "因工程量变更可以调整合同规定费率或价格的条件包括：(1)该部分工程实际测量的工程量比工程量表或其他报表中规定的工程量的变动大于10％；(2)该项部分工程工程量的变更与相对应费率的乘积超过了中标金额的0.01％；(3)由于工程量的变更直接造成该部分工程每单位工程量费用的变动超过1％；(4)该部分工程不是合同中规定的“固定费率项目”。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1641", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "根据《建设项目工程总承包合同示范文本》(GF2011-0126)，下列属于施工变更的是( )。", "options": {"A": "对区域内标准标高的调整", "B": "对备品备件采购数量的调整", "C": "发包人对竣工检验合格的项目重新进行竣工试验", "D": "因发包人原因暂停工程超过45天，调减受影响的部分工程"}, "answer": ["C"], "analysis": "施工变更的范围包括：(1)因设计变更，造成施工方法改变、设备、材料、部件和工程量的增减；(2)发包人要求增加的附加试验、改变试验地点；(3)在发包人提供的项目基础资料和现场障碍资料之外，新增加的施工障碍处理；(4)发包人对竣工试验经验收或视为验收合格的项目，通知重新进行竣工试验；(5)因执行基准日期之后新颁布的法律、标准、规范引起的变更；(6)上述变更所需的附加工作。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1642", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "根据《建设项目工程总承包合同示范文本》(GF-2011-0216)，下列关于变更程序的说法中正确的是()。", "options": {"A": "发包人要求的变更，应事先以书面或口头形式通知承包人", "B": "承包人接到发包人变更通知后，有义务在规定时间内向发包人提交书面建议报告", "C": "承包人有义务接受发包人要求的变更，无须通过建议报告表达不支持的观点", "D": "承包人在提交变更建议报告后，在等待发包人回复的时间内，可停止相关工作"}, "answer": ["B"], "analysis": "本题考查的是工程总承包合同价款的结算。选项A，发包人要求的变更以及采纳了承包人提交的变更建议书后决定的变更，应事先以书面形式通知承包人。选项B正确，承包人接到发包人的变更通知后，有义务在 10 天内向发包人提交书面建议报告选项C，如承包人不接受发包人变更通知中的此项变更时，建议报告中包括不支持此项变更的理由。选项D，承包人在等待发包人回复的时间内，不能停止或延误任何工作。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1643", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "根据FIDIC合同条件的规定，下列有关工程量变更引起的价格调整的情形，错误的是()。", "options": {"A": "该部分工程不是合同中规定的“固定费率项目”", "B": "该部分工程实际测量的工程量比工程量表规定的工程量的变动大于10%", "C": "该部分工程工程量的变更与相对应费率的乘积超过了中标金额的0.01%", "D": "由于工程量的变更直接造成该部分工程每单位工程量费用的变动超过0.1%"}, "answer": ["D"], "analysis": "本题考查的是国际工程合同价款的结算。“国际工程工程量变更引起的价格调整：(1)该部分工程实际测量的工程量比工程量表规定的工程量的变动大于10%；(2)该项部分工程工程量的变更与相对应费率的乘积超过了中标金额的0.01%；(3)由于工程量的变更直接造成该部分工程每单位工程量费用的变动超过1%；(4)该部分工程不是合同中规定的“固定费率项目”。”", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1647", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "某建设工程由于业主临时设计变更导致停工，承包商的工人窝工8 个工日，窝工费为300 元/工日；承包商租赁的挖土机窝工2 个台班，挖土机租赁费为1000 元/台班，动力费160 元/台班，承包商自有的自卸汽车窝工2 个台班，该汽车折旧费用400 元/台班，动力费为200 元/台班，则承包商可以向业主索赔的费用为（）元。", "options": {"A": "5200", "B": "4800", "C": "5400", "D": "5800"}, "answer": ["A"], "analysis": "可索赔的费用：人工费=300×8=2400元;租赁机械费=1000×2=2000元;自有机械费=400×2=800元。2400+2000+800=5200元。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1656", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "工程计量过程中，对于钻孔桩的桩长一般采用（）进行计量。", "options": {"A": "均摊法", "B": "图纸法", "C": "断面法", "D": "分解计量法"}, "answer": ["B"], "analysis": "在工程量清单中，许多项目都采取按照设计图纸所示的尺寸进行计量，如混凝土构筑物的体积、钻孔桩的桩长等。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1658", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "按照我国现行规定，合同价款采用造价信息差额调整法调整时，当承包人中材料单价低于，施工期间材料单价涨幅以（）为基础超过合同约定的风险幅度值时，其超过部分按实调整。", "options": {"A": "基准单价", "B": "投标报价", "C": "市场价格", "D": "投标价和基准价的平均值"}, "answer": ["A"], "analysis": "承包人投标报价中材料单价高于基准单价：施工期间材料单价跌幅以基准单价为基础超过合同约定的风险幅度值，或材料单价涨幅以投标报价为基础超过合同约定的风险幅度值时，其超过部分按实调整。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1659", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "实际费用法是工程费用索赔中最常用的一种计算方法，该方法的计算原则是（）。", "options": {"A": "以承包商为某项索赔工作所支付的实际开支为根据", "B": "以承包商为某项索赔工作所支付的含税工程造价为根据", "C": "以承包商为某项索赔工作所支付的直接工程费为根据", "D": "以承包商为某项索赔工作所支付的直接费为根据"}, "answer": ["A"], "analysis": "实际费用法是计算工程索赔时最常用的一种方法。这种方法的计算原则是以承包商为某项索赔工作所支付的实际开支为根据，向业主要求费用补偿。用实际费用法计算时，在直接费的额外费用部分的基础上，再加上应得的间接费和利润，即是承包商应得的索赔金额。由于实际费用法所依据的是实际发生的成本记录或单据，所以，在施工过程中，系统而准确地积累记录资料是非常重要的。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1660", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "根据《建设工程工程量计价规范》，关于暂列金额的说法，正确的是（）。", "options": {"A": "已签约合同中的暂列金额应由发包人掌握使用", "B": "已签约合同中的暂列金额应由承包人掌握使用", "C": "发包人按照合同规定将暂列金额作出支付后，剩余金额归承包人所有", "D": "发包人按照合同规定将暂列金额作出支付后，剩余金额由发包人和承包人共同所有"}, "answer": ["A"], "analysis": "已签约合同价中的暂列金额由发包人掌握使用。发包人按照合同的规定支付后，如有剩余，则暂列金额余额归发包人所有。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1661", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "在用起扣点计算法扣回预付款时，起扣点计算公式为T=P-(M/N)则式中N是指()。", "options": {"A": "工程预付款总额", "B": "工程合同总额", "C": "主要材料及构件所占比重", "D": "累计完成工程金额"}, "answer": ["C"], "analysis": "起扣点的计算公式如下： T=P-(M/N) 式中：T—起扣点（即工程预付款开始扣回时）的累计完成工程金额； P—承包工程合同总额。 M—工程预付款总额； N—主要材料及构件所占比重；", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1662", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "某承包工程总价为500万元，其中材料费占45％，该工程计划工期为500天，材料储备定额天数为天，则应支付预付款()万元。", "options": {"A": "36.99", "B": "225", "C": "27", "D": "60"}, "answer": ["C"], "analysis": "公式5.2.1中是年度工程总价不是工程总价， 应为：工程预付款数额=[（年度工程总价×材料比例）/年度施工天数]×材料储备定额天数=[（500/500*365*45%）/365]×60=27（万元） 年度施工天数按365天日历天计算", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1663", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "发包人应当开始支付不低于当年施工进度计划的安全文明施工费总额60％的期限是工程开工后的()天内。", "options": {"A": "7", "B": "14", "C": "21", "D": "28"}, "answer": ["D"], "analysis": "发包人应在工程开工后的28天内预付不低于当年施工进度计划的安全文明施工费总额的60％，其余部分按照提前安排的原则进行分解，与进度款同期支付。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1665", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "在进行竣工结算价款支付的过程中，以下做法错误的是()。", "options": {"A": "发包人应在收到承包人提交竣工结算款支付申请后规定时间内予以核实，向承包人签发竣工结算支付证书", "B": "发包人签发竣工结算支付证书后的规定时间内，按照竣工结算支付证书列明的金额向承包人支付结算款", "C": "发包人未按照规定的程序支付竣工结算款的，承包人可催告发包人支付，并有权获得延迟支付的利息", "D": "发包人逾期未支付竣工结算款时，除法律另有规定外，承包人可与发包人协商将该工程折价，也可直接向人民法院申请将该工程依法拍卖，发包人就该工程折价或拍卖的价款优先受偿"}, "answer": ["D"], "analysis": "承包人在竣工结算支付证书签发后或者在收到承包人提交的竣工结算款支付申请规定时间内仍未支付的，除法律另有规定外，承包人可与发包人协商将该工程折价，也可直接向人民法院申请将该工程依法拍卖。承包人就该工程折价或拍卖的价款优先受偿。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1666", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "最终结清是指合同约定的缺陷责任期终止后，承包人已按合同规定完成全部剩余工作且质量合格的，发包人与承包人结清全部剩余款项的活动，以下说法错误的是()。", "options": {"A": "缺陷责任期终止后，承包人已按合同规定完成全部剩余工作且质量合格的，发包人签发缺陷责任期终止证书", "B": "缺陷责任期终止后，承包人在合同内享有的索赔权利也自行终止", "C": "发包人收到承包人提交的最终结清申请单后的14天内予以核实，向承包人签发最终支付证书", "D": "发包人应在签发最终结清支付证书后的14天内，按照最终结清支付证书列明的金额向承包人支付最终结清款"}, "answer": ["B"], "analysis": "最终结清付款后，承包人在合同内享有的索赔权利也自行终止。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1667", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "关于施工合同履行期间的期中支付，下列说法中正确的是（ ）。", "options": {"A": "双方对工程计量结果的争议，不影响发包人对已完工工程的期中支付", "B": "对已签发支付证书中的计算错误，发包人不得再予修正", "C": "进度款支付申请中应包括累计已完成的合同价款", "D": "本周期实际支付的合同额为本期完成的合同价款合计"}, "answer": ["C"], "analysis": "进度款支付申请的内容包括：(1)累计已完成的合同价款；(2)累计已实际支付的合同价款；(3)本周期合计完成的合同价款；(4)本周期合计应扣减的金额；(5)本周期实际应支付的合同价款。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1668", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "关于垫资施工合同价款纠纷处理，下列说法正确的是( )。", "options": {"A": "合同约定垫资利率高于中国人民银行发布的同期同类贷款利率的，按合同约定返还垫资利息", "B": "当事人对垫资没有约定的，按照工程欠款处理", "C": "当事人对垫资利息没有约定的，按中国人民银行发布的同期同类贷款利率计算利息", "D": "垫资达到合同总和一定比例以上时为无效合同"}, "answer": ["B"], "analysis": "对于发包人要求承包人垫资施工的项目，对于垫资施工部分的工程价款结算，最高人民法院《关于审理建设工程施工合同纠纷案件适用法律问题的解释》提出了处理意见：(1)当事人对垫资和垫资利息有约定，承包人请求按照约定返还垫资及其利息的，应予支持，但是约定的利息计算标准高于中国人民银行发布的同期同类贷款利率的部分除外；(2)当事人对垫资没有约定的，按照工程欠款处理；(3)当事人对垫资利", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1670", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "关于建设工程竣工结算审核，下列说法中正确的是（）。", "options": {"A": "非国有企业投资的建设工程，不应委托工程造价咨询机构审核", "B": "国有资金投资的建设工程，应当委托工程造价咨询机构审核", "C": "承包人不同意造价咨询机构的结算审核结论时，造价咨询机构不得出具审核报告", "D": "工程造价咨询机构的核对结论与承包人竣工结算文件不一致的，以造价机构核对结论为准"}, "answer": ["B"], "analysis": "国有资金投资建设工程的发包人，应当委托具有相应资质的工程造价咨询企业对竣工结算文件进行审核，并在收到竣工结算文件后的约定期限内向承包人提出由工程造价咨询企业出具的竣工结算文件审核意见；逾期未答复的，按照合同约定处理，合同没有约定的，竣工结算文件视为已被认可。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1671", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "已知某建筑工程施工合同总额为8000万元，工程预付款按合同金额的20%计取，主要材料及构件造价占合同额50%。预付款起扣点为()万元。", "options": {"A": "1600", "B": "4000", "C": "4800", "D": "6400"}, "answer": ["C"], "analysis": "本题考查的是预付款及期中支付。起扣点的累计完成工程金额=承包工程合同总额一工程预付款总额／主要材料及构件所占比重=8000-8000×20%/50%=4800（万元）。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1672", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "关于工程量清单计价方式下竣工结算的编制原则，下列说法中正确的是()。", "options": {"A": "措施项目费按双方确认的工程量乘以已标价工程量清单的综合单价计算", "B": "总承包服务费按已标价工程量清单的金额计算，不应调整", "C": "暂列金额应减去工程价款调整的金额，余额归承包人", "D": "工程实施过程中发承包双方已经确认的工程计量结果和合同价款，应直接进入结算"}, "answer": ["D"], "analysis": "本题考查的是竣工结算。选项A错误，分部分项工程和措施项目中的单价项目应依据双方确认的工程量与已标价工程量清单的综合单价计算； 措施项目中的总价项目应依据合同约定的项目和金额计算；选项B错误，总承包服务费应依据合同约定金额计算，如发生调整的，以发承包双方确认调整的金额计算；选项C错误，暂列金额应减去工程价款调整 （包括索赔、现场签证）金额计算，如有余额归发包人。选项D正确，发承包双方在合同工程实施过程中已经确认的工程计量结果和合同价款，在竣工结算办理中应直接进入结算。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1673", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "建设工程最终结清的工作事项和时间节点包括：①提交最终结清申请单；②签发最终结清支付证书；③签发缺陷责任期终止证书；④最终结清付款；⑤缺陷责任期终止。按时间先后顺序排列正确的是()。", "options": {"A": "⑤③①②④", "B": "①②④⑤③", "C": "③①②④⑤", "D": "①③②⑤④"}, "answer": ["A"], "analysis": "本题考查的是最终结清。所谓最终结清，是指合同约定的缺陷责任期终止后，承包人已按合同规定完成全部剩余工作且质量合格的，发包人与承包人结清全部剩余款项的活动。最终结清顺序：最终结清申请单、最终支付证书、最终结清付款。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1674", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "施工合同价款纠纷处理中，一方当事人拒不履行，另一方当事人可以请求人民法院执行的文书是()。", "options": {"A": "和解协议书", "B": "造价认定书", "C": "行政调解书", "D": "仲裁调解书"}, "answer": ["D"], "analysis": "本题考查的是合同价款纠纷的处理。当事人应当履行发生法律效力的法院判决或裁定、仲裁裁决、法院或仲裁调解书；拒不履行的，对方当事人可以请求人民法院执行。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1675", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "下列承包商发生的行为中，发包人可以请求解除施工合同，应予支持的是()。", "options": {"A": "明确表示或者以行为表明不履行合同主要义务的", "B": "合同约定的期限内没有完工", "C": "已经完成的建设工程质量不合格", "D": "将承包的建设工程分包的"}, "answer": ["A"], "analysis": "本题考查的是合同价款纠纷的处理。承包人具有下列情形之一，发包人请求解除建设工程施工合同的，应予支持：(1)明确表示或者以行为表明不履行合同主要义务的；(2)合同约定的期限内没有完工，且在发包人催告的合理期限内仍未完工的；(3)已经完成的建设工程质量不合格，并拒绝修复的；(4)将承包的建设工程非法转包、违法分包的。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1676", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "关于合同履行过程中因不可抗力解除合同的价款结算与支付的说法，不正确的是()。", "options": {"A": "由于不可抗力解除合同的，承包人应自行支付撤离现场所需的费用", "B": "发包人应向承包人支付已实施或部分实施的措施项目应付价款", "C": "发包人一经支付材料和工程设备货款，则该材料和工程设备成为发包人的财产", "D": "发包人应向承包人支付承包人为完成合同工程而预期开支的任何合理费用"}, "answer": ["A"], "analysis": "本题考查的是竣工结算。由于不可抗力解除合同的，发包人除应向承包人支付合同解除之日前已完成工程但尚未支付的合同价款，还应支付下列金额：(1) 合同中约定应由发包人承担的费用。(2) 已实施或部分实施的措施项目应付价款。(3) 承包人为合同工程合理订购且已 交付的材料和工程设备货款。发包人一经支付此项货款，该材料和工程设备即成为发包人的财产。(4)承包人撤离现场所需的合理费用，包括员工遣送费和临时工程拆除、施工设备运离现场的费用。(5)承包人为完成合同工程而预期开支的任何合理费用，且该项费用未包括在本款其他各项支付之内。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1678", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "关于工程造价咨询人从事工程造价鉴定工作，下列做法中正确的是()。", "options": {"A": "不需收集施工过程中的施工组织、质量、工期等资料", "B": "可以安排经验丰富的造价员独立承担鉴定工作", "C": "应收集鉴定项目同时期、同类型工程的技术经济指标", "D": "工程造价鉴定书中可不对鉴定过程中使用的技术手段进行描述"}, "answer": ["C"], "analysis": "本题考查的是合同价款纠纷的处理。工程造价咨询人进行工程造价鉴定工作时，应收集鉴定项目同时期同类型工程的技术经济指标及其各类要素价格等。选项A错误，工程造价咨询人收集鉴定项目的鉴定依据时，内容包括施工过程中施工组织、质量、工期和造价等工程资料。选项B错误，工程造价咨询人进行工程造价司法鉴定，应指派专业对口、经验丰富的注册造价工程师承担鉴定工作。选项D错误，工程造价鉴定书中应鉴定过程中使用的技术手段进行描述。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1679", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "关于施工合同工程价款的期中支付，下列说法中正确的是（）。", "options": {"A": "期中进度款的支付比例，一般不低于期中价款总额的60%", "B": "期中进度款的支付比例，一般不高于期中价款总额的80%", "C": "综合单价发生调整的项目，其增减费在竣工结算时一并结算", "D": "发承包双方如对部分计量结果存在争议，等待争议解决后再支付全部进度款"}, "answer": ["A"], "analysis": "(3)进度款的支付比例。进度款的支付比例按照合同约定，按期中结算价款总额计，不低于60%，不高于90%", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1680", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "发包人未按照规定的程序支付竣工结算款的，承包人正确的做法是（）。", "options": {"A": "将该工程自主拍卖", "B": "将该工程折价出售", "C": "将该工程抵押贷款", "D": "催告发包人支付，并索要延迟付"}, "answer": ["D"], "analysis": "发包人未按照规定的程序支付竣工结算款的，承包人可催告发包人支付，并有权获得延迟支付的利息。发包人在竣工结算支付证书签发后或者在收到承包人提交的竣工结算款支付申请规定时间内仍未支付的，除法律另有规定外，承包人可与发包人协商将该工程折价，也可直接向人民法院申请将该工程依法拍卖。承包人就该工程折价或拍卖的价款优先受偿", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1682", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "预付款担保保证承包人能够按合同规定的目的使用并及时偿还发包人已支付的全部预付金额。下列有关预付款担保的说法错误的是()。", "options": {"A": "预付款担保的担保金额通常与发包人的预付款是等值的", "B": "承包人的预付款保函的担保金额根据预付款扣回的数额相应递减，但在预付款全部扣回之前一直保持有效", "C": "发包人应在预付款扣完后的14天内将预付款保函退还给承包人", "D": "预付款担保只能采用银行保函一种形式"}, "answer": ["D"], "analysis": "预付款担保也可以采用发承包双方约定的其他形式，如由担保公司提供担保，或采取抵押等担保形式。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1683", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "某进度款支付申请报告包含了下列内容：①累计已完成的合同价款；②累计已实际支付的合同价款；③本周期已完成的计日工价款；④本周期应扣回预付款。据此，发包人本周期应支付的合同价款是()。", "options": {"A": "①+②-③-④", "B": "①-②+③-④", "C": "②-①+③-④", "D": "①+②+③-④"}, "answer": ["B"], "analysis": "进度款支付申请应包括下列内容：(1)累计已完成的合同价款。(2)累计已实际支付的合同价款。(3)本周期合计完成的合同价款：1）本周期已完成单价项目的金额；2）本周期应支付的总价项目的金额；3）本周期已完成的计日工价款；4）本周期应支付的安全文明施工费；5）本周期应增加的金额。(4)本周期合计应扣减的金额： 1)本周期应扣减的预付款；2）本周期应扣减的金额。(5)本周期实际应支付的合同价款。 发包人本期应支付的工程价款=本周期合计完成的合同价款+本期以前累计尚未支付的价款-本周期合计应扣减的金额 本期以前累计尚未支付的价款＝累计已完成的工程价款-累计已支付的工程价款", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1684", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "按照规定，发包人委托工程造价咨询机构核对竣工结算的，工程造价咨询机构应核对完毕后，结论与承包人不一致时，下列说法中正确的是()。", "options": {"A": "以工程造价咨询机构的结论为准", "B": "以承包人竣工结算文件为准", "C": "提交承包人复核", "D": "按照合同约定的争议解决方式处理"}, "answer": ["C"], "analysis": "工程造价咨询机构核对结论与承包人竣工结算文件不一致时，应提交给承包人复核，承包人应在14天内将同意核对结论或不同意见的说明提交工程造价咨询机构。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1685", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "某工程合同总价为0万元，合同工期180天，材料费占合同总价的60%，材料储备定额天数为25天。材料供应在途天数为5天。用公式计算法来求得该工程的预付款为( )万元。", "options": {"A": "417", "B": "500", "C": "694", "D": "833"}, "answer": ["A"], "analysis": "工程预付款数额=5000×60%/180×25=417（万元）", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1686", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "关于办理有质量争议工程的竣工结算，下列说法中错误的是( )。", "options": {"A": "已实际投入使用工程的质量争议按工程保修合同执行，竣工结算按合同约定办理", "B": "已竣工未投入使用工程的质量争议按工程保修合同执行，竣工结算按合同约定办理", "C": "停工、停建工程的质量争议可在执行工程质量监督机构处理决定后办理竣工结算", "D": "已竣工未验收并且未实际投入使用，其无质量争议部分的工程，竣工结算按合同约定办理"}, "answer": ["B"], "analysis": "发包人以对工程质量有异议，拒绝办理工程竣工结算的：(1)已经竣工验收或已竣工未验收但实际投入使用的工程，其质量争议按该工程保修合同执行，竣工结算按合同约定办理；(2)已竣工未验收且未实际投入使用的工程以及停工、停建工程的质量争议，双方应就有争议的部分委托有资质的检测鉴定机构进行检测，根据检测结果确定解决方案，或按工程质量监督机构的处理决定执行后办理竣工结算，无争议部分的竣工结算按合同约定办理。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1687", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "国际工程中的预付款扣回，一般为工程进度累计金额超过合同价格的()时开始起扣，每月从进度款中按一定比例扣回。", "options": {"A": "5%-10%", "B": "10%-20%", "C": "10%-30%", "D": "30%-40%"}, "answer": ["B"], "analysis": "本题考查的是预付款及期中支付。 国际工程中的扣款方法一般为：当工程进度款累计金额超过合同价格的10%~20%时开始起扣，每月从进度款中按一定比例扣回。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1688", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "承包人可根据确定的工程计量结果向发包人提出支付工程进度款申请，发包人应在14天内支付最高限额为()的工程价款作为工程进度款，", "options": {"A": "70%", "B": "80%", "C": "90%", "D": "100%"}, "answer": ["C"], "analysis": "本题考查的是预付款及期中支付。进度款的支付比例按照合同约定，按期中结算价款总额计，不低于60%， 不高于90%。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1689", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "最终结清时，如果被扣留的质量保证金不足以抵减工程缺陷修复费用的，()应承担不足部分的补偿责任。", "options": {"A": "承包人", "B": "发包人", "C": "监理人", "D": "建设主管部门"}, "answer": ["A"], "analysis": "本题考查的是最终结清。最终结清时，如果承包人被扣留的质量保证金不足以抵减发包人工程缺陷修复费用的，承包人应承担不足部分的补偿责任。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1690", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "当承发包双方的合同价款纠纷提交仲裁时，如果仲裁是在仲裁机构要求停止施工的情况下进行，应对合同工程采取保护措施，由此增加的费用由()承担。", "options": {"A": "发包人", "B": "承包人", "C": "发包人和承包人", "D": "败诉方"}, "answer": ["D"], "analysis": "本题考查的是合同价款纠纷的处理。“当仲裁是在仲裁机构要求停止施工的情况下进行时，承包人应对合同工程采取保护措施，由此增加的费用由败诉方承担。”", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1691", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "调解是解决工程合同价款纠纷的一种途径，下列关于调解的说法中正确是（）。", "options": {"A": "承包人对调解书有异议时，可以停止施工", "B": "发承包双方签字认可的调解书不能作为合同的补充文件", "C": "发承包双方可在合同履行期间协议调换或终止合同约定的调解人", "D": "调解人的任期在竣工结算经发承包双方确认时终止"}, "answer": ["C"], "analysis": "1)约定调解人。发承包双方应在合同中约定或在合同签订后共同约定争议调解人，负责双方在合同履行过程中发生争议的调解。合同履行期间，发承包双方可以协议调换或终止任何调解人，但发包人或承包人都不能单独采取行动。除非双方另有协议，在最终结清支付证书生效后，调解人的任期即终止。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1692", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "根据《建设工程价款结算暂行办法》，发包人应在一定时间内预付工程款，否则，承包人应在预付时间到期后的一定时间内发出要求预付工程款的通知，若发包人仍不预付，则承包人可在发出通知的（）天后停止施工。", "options": {"A": "7", "B": "10", "C": "14", "D": "28"}, "answer": ["C"], "analysis": "根据《建设工程价款结算暂行办法》规定，在具备施工条件的前提下，发包人应在双方签订合同后的一个月或不迟于约定的开工日期前7 天预付工程款，否则，承包人应在预付时间到期后的10 天内向发包人发出要求预付工程款的通知，若发包人仍不预付，则承包人可在发出通知的14 天后停止施工。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1693", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "关于竣工结算的编制与审查的说法中，错误的是（）。", "options": {"A": "单位工程竣工结算由承包人编制", "B": "建设项目竣工总结算经发、承包人签字盖章后有效。", "C": "竣工结算的编制依据包括经批准的开、竣工报告或停、复工报告", "D": "结算中的暂列金额应减去工程价款调整与索赔、现场签证金额，若有余款归承包人"}, "answer": ["D"], "analysis": "结算中的暂列金额应减去工程价款调整与索赔、现场签证金额，若有余额归发包人。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1694", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "根据我国现行的关于工程预付款的规定，下列说法中正确的是（）。", "options": {"A": "发包人应在合同签订后一个月内或开工前10 天内支付", "B": "当约定需提交预付款保函时则保函的担保金额必须大于预付款金额", "C": "发包人不按约定预付且经催促仍不按要求预付的，承包人可停止施工", "D": "预付款是发包人为解决承包人在施工过程中的资金周转问题而提供的协助"}, "answer": ["C"], "analysis": "预付款是发包人为解决承包人在施工准备阶段资金周转问题提供的协助。按照《建设工程价款结算暂行办法》的规定，在具备施工条件的前提下，发包人应在双方签订合同后的一个月内或不迟于约定的开工日期前的7 天内预付工程款，发包人不按约定预付，承包人应在预付时间到期后10 天内向发包人发出要求预付的通知，发包人收到通知后仍不按要求预付，承包人可在发出通知14 天后停止施工。除专用合同条款另有约定外，承包人应在收到预付款的同时向发包人提交预付款保函，预付款保函的担保金额与预付款金额相同，在发包人全部扣回预付款之前，该银行保函将一直有效。 本题库是以官方教材为依据，知识点所对应的习题综合了二建法规、二建管理、造价员基础、一级造价师考试的题库+真题编辑，基本上做到了每个知识点都有相对应的题目及解析,题库会陆续更新,会有模拟题,预测题及考前更新押题。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1695", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "在工程合同履行过程中出现施工合同无效导致价款纠纷的处理原则，以下说法正确的是()。", "options": {"A": "建设工程施工合同无效，则无论竣工验收是否合格，承包人请求支付工程价款的，均不予支持", "B": "建设工程施工合同无效，且建设工程经竣工验收不合格，修复后的建设工程经竣工验收合格，发包人承担修复费用", "C": "建设工程施工合同无效，且建设工程经竣工验收不合格，修复后的建设工程经竣工验收不合格，发包人应向承包人支付由此造成的损失费", "D": "没有资质的实际施工人借用有资质的建筑施工企业名义与他人签订建设工程施工合同的行为无效"}, "answer": ["D"], "analysis": "建设工程施工合同无效，但建设工程经竣工验收合格，承包人请求参照合同约定支付工程价款的，应予支持。建设工程经竣工验收不合格，修复后的建设工程经竣工验收合格，发包人请求承包人承担修复费用的，应予支持。^修复后的建设工程经竣工验收不合格，承包人请求支付工程价款的，不予支持。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1696", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "发包人发出赶工指令，若因承包人原因造成实际进度明显落后于发包人批准的项目进度计划时，以下说法正确的是()。", "options": {"A": "承包人应采取措施，赶上项目进度计划，费用由双方协商支付", "B": "承包人应自费采取措施，赶上项目进度计划", "C": "竣工日期延误时，承包人无须承担误期赔偿", "D": "竣工日期延误时，承包人可请求发包人顺延工期，发包人应予批准"}, "answer": ["B"], "analysis": "因承包人原因造成实际进度明显落后于发包人批准的项目进度计划时，承包人应自费采取措施，赶上项目进度计划；竣工日期延误时，承包人承担误期赔偿。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1697", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "在工程进度款支付时，因各种原因导致付款时间延误的处理正确的是()。", "options": {"A": "因发包人的原因未能按合同约定的时间向承包人支付工程进度款的，应从发包人收到付款申请报告后的第15日开始，向承包人支付延期付款的利息", "B": "发包人延误付款26天以上，承包人有权向发包人发出要求付款的通知，发包人收到通知后仍不能付款的，承包人可暂停部分工作", "C": "双方未能达成延期付款协议，导致工程无法实施，承包人可停止部分或全部工程，发包人承担违约责任，导致工程关键路径延误时，竣工日期顺延", "D": "发包人的延误付款达60天以上，并影响到整个工程实施的，承包人有权向发包人发出要求付款的通知，发包人收到通知后仍不能付款的，根据合同的约定向发包人发出解除合同的通知，并有权就因此增加的相关费用向发包人提出索赔"}, "answer": ["C"], "analysis": "因发包人的原因未能按合同约定的时间向承包人支付工程进度款的，应从发包人收到付款申请报告后的第26日开始，以中国人民银行颁布的同期同类贷款利率向承包人支付延期付款的利息，作为延期付款的违约金额。发包人延误付款15天以上，承包人有权向发包人发出要求付款的通知，发包人收到通知后仍不能付款的，承包人可暂停部分工作，视为发包人导致的暂停，并按合同中关于发包人暂停的约定执行。发包人的延误付款达60天以上，并影响到整个工程实施的，承包人有权根据合同的约定向发包人发出解除合同的通知，并有权就因此增加的相关费用向发包人提出索赔。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1698", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "关于建设工程总承包合同价款的支付，下列说法正确的是（）。", "options": {"A": "预付款扣完后，由于工程尚未竣工，发包人可以不退还预付款保函", "B": "未约定预付款保函的，发包人在合同生效后规定时间内向承包人支付预付款金额", "C": "发包人延误付款，应自延误之日起按同期存款利率向承包人支付延期付款利息", "D": "发包人延误付款的，承包人有权直接暂停施工"}, "answer": ["B"], "analysis": "发包人按合同价格的一定比例支付预付款金额，具体金额由双方在合同专用条款中约定。合同约定了预付款保函的，在合同生效后，发包人收到承包人提交的预付款保函后10日内向承包人支付预付款金额；未约定预付款保函的，发包人在合同生效后10日内向承包人支付预付款金额。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1699", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "根据FIDIC《施工合同条件》（1999版），关于合同价款调整的规定，下列说法正确的是（）。", "options": {"A": "工程量的变更与对应费率的乘积超过了中标总金额的1%时才予调整", "B": "实际测量工程量比工程量表中工程量变动大于10%时，可调整相应单价", "C": "工程师要求改变施工顺序的，不应调整合同价款", "D": "承包人配合工程检验所发生的剥露和覆盖，不应调整合同价款"}, "answer": ["B"], "analysis": "因工程量变更可以调整合同规定费率或价格的条件包括：⑴该部分工程实际测量的工程量比工程量表或其他报表中规定的工程量的变动大于10%。⑵该部分工程工程量的变更与相对应费率的乘积超过了中标金额的0.01%。⑶由于工程量的变更直接造成该部分工程每单位工程量费用的变动超过1%。⑷该部分工程不是合同中规定的“固定费率项目”。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1700", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "FIDIC施工合同条件规定，如果承包商不能按时收到业主的付款，承包商有权就未付款额收取延误支付期间的融资费。融资费计息方式是()。", "options": {"A": "按星期计算单利", "B": "按星期计算复利", "C": "按月计算单利", "D": "按月计算复利"}, "answer": ["D"], "analysis": "本题考查的是国际工程合同价款的结算。如果承包商不能按时收到业主的付款，承包商有权就未付款额从业主应当支付之日起，按月计算复利，收取延误支付期间的融资费。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1701", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "在FIDIC合同条件中，工程师确认用于永久工程的材料和设备符合预支条件，在确定其实际费用后，期中支付证书中应增加该费用的()作为工程材料和设备预支款。", "options": {"A": "50%", "B": "60%", "C": "70%", "D": "80%"}, "answer": ["D"], "analysis": "本题考查的是国际工程合同价款的结算。“工程师确认用于永久工程的材料和设备符合预支条件后，应当根据审查承包商提交的相关文件确定此类材料和设备的实际费用（包括运至现场的费用），期中支付证书中应增加的款额为该费用的80%。”", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1702", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "根据FIDIC《施工合同文件》（1999年版）通用合同条件，关于发包人对保留金的保留和返还，下列说法中正确的是（）。", "options": {"A": "每次期中支付时扣留2.5%~5%作为保留金", "B": "签发整个工程的接收证书后，返还40%的保留金", "C": "工程最后一个缺陷通知期满后，返还剩余的保留金", "D": "如承包人有尚未完成的工作，不用返还剩余的保证金"}, "answer": ["C"], "analysis": "2)在工程的最后一个缺陷通知期期满后，保留金的余额应立即支付给承包商。如果颁发的接收证书只限于一个区段或部分工程，则在该区段或部分工程的缺陷通知期期满后，再返还相应区段或部分工程的保留金的40%，计算方法与公式相同。但是，如果在返还保留金时，承包商尚有任何工作仍需完成，工程师有权在此类工作完成之前扣发与完成工作所需费用相应的保留金余额。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1703", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "物价波动引起的价款调整，在承包商未能在竣工时间内完成工程的，应选择下列哪个指数或价格进行价格调整()。", "options": {"A": "工程竣工时间期满前第49天当天适用的每项指数或价格", "B": "现行指数或价格", "C": "以上两种指数或价格中对业主有利的指数或价格进行价格调整", "D": "以上两种指数或价格中对承包商有利的指数或价格进行价格调整"}, "answer": ["C"], "analysis": "如果承包商未能在竣工时间内完成工程，则应选择适用下列两种指数或价格中对业主有利的指数或价格进行价格调整：(1)工程竣工时间期满前第49天当天适用的每项指数或价格；(2)现行指数或价格。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1704", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "根据《建设项目工程总承包合同示范文本》（GF-2011-0126），发包人按付款 计划表付款时，如承包人的实际进度比约定的目标进度落后30日及以上，发包人有权 ( )。", "options": {"A": "停止当期结算", "B": "自行调整付款计划表", "C": "与承包人商定减少当期付款额", "D": "与承包人协商抵减合同总额"}, "answer": ["C"], "analysis": "发包人按付款计划表付款时，承包人的实际工作和（或）实际进度比付款 计划表约定的关键路径的目标任务落后30日及以上时，发包人有权与承包人商定减少 当期付款金额，并有权与承包人共同调整付款计划表。承包人以后各期的付款申请及发 包人的付款，以调整后的付款计划表为依据。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1705", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "关于建设工程施工合同索赔，下列说法中正确的是()。", "options": {"A": "发包人可以在索赔事件发生后暂不通知承包人，待工程结算时一并处理", "B": "发包人向承包人提出索赔，承包人无权要求发包人补充提供索赔理由和证据", "C": "承包人在收到发包人的索赔资料后，未在规定时间内作出答复，视为该项索赔事件已成立", "D": "承包人未在索赔事件发生后的规定时间内发出索赔通知的，应免除发包人的一切责任"}, "answer": ["C"], "analysis": "本题考查的是工程总承包合同价款的结算。承包人在收到发包人送交的索赔资料后30天内未与发包人协商或未予答复或未向发包人提出进一步要求的，视为该项索赔已被承包人认可。选项A错误，发包人应在索赔事件发生后的 30 天内，向承包人送交索赔通知。未能在索赔事件发生后的30天内发出索赔通知，承包人不再承担任何责任，法律另有规定的除外；选项B错误，承包人在收到发包人送交的索赔资料后 30 天内，与发包人协商解决，或给予答复， 或要求发包人进一步补充提供索赔理由和证据；选项D错误，承包商应在索赔事件发生后30天内，向发包人发出索赔通知。未在索赔事件发生后的 30 天内发出索赔通知，发包人不再承担任何责任，法律另有规定除外；", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1706", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "国际工程中，当承包商提交书面结清单后的一定期限内，由工程师向业主发出的证书是（）。", "options": {"A": "期中支付证书", "B": "最终支付证书", "C": "履约证书", "D": "工程接收证书"}, "answer": ["B"], "analysis": "在收到最终报表及书面结清单后28 天内，工程师应向业主发出一份最终支付证书。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1707", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "建设项目竣工财务决算应编制基本建设项目概况表，下列选项中应计入基本建设项目概况表“非经营性项目转出投资”的是（）。", "options": {"A": "水土保持、城市绿化费用", "B": "产权不归属本单位的专用道路建设费", "C": "报废工程建设费", "D": "产权归本单位的地下管道建设费"}, "answer": ["B"], "analysis": "本题考查的是竣工财务决算表。非经营性项目转出投资支出是指非经营项目为项目配套的专用设施投资，包括专用道路、专用通信设施、送变电站、地下管道等，其产权不属于本单位的投资支出，对于产权归属本单位的，应计入交付使用资产价值。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1708", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "编制大中型建设项目竣工财务决算报表时，下列属于资金占用的项目是（）。", "options": {"A": "待冲基建支出", "B": "应付款", "C": "预付及应收款", "D": "来交款"}, "answer": ["C"], "analysis": "预付及应收款属于资金占用，其他三项属于资金来源。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1709", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "下列不属于建设项目竣工财务决算说明书内容的是()。", "options": {"A": "基本建设项目概况", "B": "基建结余资金等分配情况", "C": "主要技术经济指标的分析、计算情况", "D": "主要实物工程量分析"}, "answer": ["D"], "analysis": "竣工财务决算说明书主要反映竣工工程建设成果和经验，是对竣工决算报表进行分析和补充说明的文件，是全面考核分析工程投资与造价的书面总结，是竣工决算报告的重要组成部分，其内容主要包括：(1)基本建设项目概况；(2)会计账务的处理、财产物资清理及债权债务的清偿情况；(3)基建结余资金等分配情况；(4)主要技术经济指标的分析、计算情况；(5)基本建设项目管理及决算中存在的问题、建议；(6)决算与概算的差异和原因分析；(7)需说明的其他事项。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1710", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "关于建设项目竣工运营后的新增资产，下列说法正确的是（）。", "options": {"A": "新增资产按资产性质分为固定资产、流动资产和无形资产三大类", "B": "分期分批交付生产或使用的工程，待工程全部交付使用后，一次性计算新增固定资产增值", "C": "凡购置的达到固定资产标准不需安装的工器具，应在交付使用后计入新增固定资产", "D": "企业库存现金、存货及建设单位管理费中未计入固定资产的各项费用等，应在交付使用后计入新增流动资产价值"}, "answer": ["C"], "analysis": "在计算新增固定资产价值时，应注意以下几种情况：⑴对于为了提高产品质量、改善劳动条件、节约材料消耗、保护环境而建设的附属辅助工程，只要全部建成，正式验收交付使用后就要计入新增固定资产价值；⑵对于单项工程中不构成生产系统，但能独立发挥效益的非生产性项目，如住宅、食堂、医务室、托儿所、生活服务网点等，在建成并交付使用后，也要计算新增固定资产价值；⑶凡购置达到固定资产标准不需安装的设备、工器具，应在交付使用后计入新增固定资产价值；⑷属于新增固定资产价值的其他投资，应随同受益工程交付使用的同时一并计入。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1711", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "建设周期长、建设内容多的项目，单项工程竣工，具备交付使用条件的，可编制()。", "options": {"A": "单项工程竣工财务决算", "B": "单项工程竣工财务决算书", "C": "单项工程竣工财务决算报表", "D": "单项工程竣工图"}, "answer": ["A"], "analysis": "项目竣工时，应编制建设项目竣工财务决算。建设周期长、建设内容多的项目，单项工程竣工，具备交付使用条件的，可编制单项工程竣工财务决算。建设项目全部竣工后应编制竣工财务总决算。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1712", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "()用来反映建设项目的全部资金来源和资金占用情况，是考核和分析投资效果的依据。", "options": {"A": "基本建设项目竣工财务决算表", "B": "基本建设项目概况表", "C": "基本建设项目交付使用资产明细表", "D": "基本建设项目交付使用资产总表"}, "answer": ["A"], "analysis": "(2)基本建设项目竣工财务决算表（见表6.2.2)。竣工财务决算表是竣工财务决算报表的一种，建设项目竣工财务决算表是用来反映建设项目的全部资金来源和资金占用情况，是考核和分析投资效果的依据。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1713", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "本身具有使用价值，且其价值在于它的使用能产生超额获利能力，一般不作为无形资产入账，自创过程中发生的费用按当期费用处理，按此确定价值的资产是()。", "options": {"A": "专利权", "B": "专有技术", "C": "商标权", "D": "存货"}, "answer": ["B"], "analysis": "(2)专有技术（又称非专利技术）的计价。专有技术具有使用价值和价值，使用价值.是专有技术本身应具有的，专有技术的价值在于专有技术的使用所能产生的超额获利能力，应在研究分析其直接和间接的获利能力的基础上，准确计算出其价值。如果专有技术是自创的，一般不作为无形资产入账，自创过程中发生的费用，按当期费用处理。对于外购专有技术，应由法定评估机构确认后再进行估价，其方法往往通过能产生的收益采用收益法进行估价。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1714", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "竣工决算文件中，真实记录各种地上、地下建筑物、构筑物、特别是基础、地下管线以及设备安装等隐蔽部分的技术文件是()。", "options": {"A": "总平面图", "B": "竣工图", "C": "施工图", "D": "交付使用资产明细表"}, "answer": ["B"], "analysis": "本题考查竣工图的编制内容，建设工程竣工图是真实地记录各种地上、地下建筑物、构筑物等情况的技术文件，是工程进行交工验收、维护、改建和扩建的依据，是国家的重要技术档案。国家规定：各项新建、扩建、改建的基本建设工程，特别是基础、地下建筑、管线、结构、井巷、桥梁、隧道、港口、水坝以及设备安装等隐蔽部位，都要编制竣工图。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1715", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "()是以实物数量和货币标准为计量单位，综合反映竣工项目从筹建开始到项目竣工交付使用为止的全部建设费用、建设成果和财务情况的总结性文件，是正确核定新增固定资产价值的依据。", "options": {"A": "竣工图", "B": "竣工结算", "C": "竣工决算", "D": "竣工验收签证书"}, "answer": ["C"], "analysis": "项目竣工决算是指所有项目竣工后，项目单位按照国家有关规定在项目竣工验收阶段编制的竣工决算报告。竣工决算是以实物数量和货币指标为计量单位，综合反映竣工建设项目全部建设费用、建设成果和财务状况的总结性文件，是竣工验收报告的重要组成部分，竣工决算是正确核定新增固定资产价值，考核分析投资效果，建立健全经济责任制的侬据，是反映建设项目实际造价和投资效果的文件。竣工决算是建设工程经济效益的全面反映，是项目法人核定各类新增资产价值、办理其交付使用的依据。竣工决算是工程造价管理的重要组成部分，做好竣工决算是全面完成工程造价管理目标的关键性因素之一。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1716", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "( )反映建设项目建成后新增固定资产、流动资产、无形资产和其他资产价值的情况和价值，作为财产交接、检查投资计划完成情况和分析投资效果的依据。", "options": {"A": "基本建设项目概况表", "B": "基本建设项目竣工财务决算表", "C": "基本建设项目交付使用资产总表", "D": "建设项目交付使用资产明细表"}, "answer": ["C"], "analysis": "(3)基本建设项目交付使用资产总表（见表6.2.3)。该表反映建项目建成后新增固定资产、流动资产、无形资产价值的情况和价值，作为财产交接、检查投资计划完成情况和分析投资效果的据。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1717", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "对共同费用进行分摊时，土地征用费按照()比例分摊。", "options": {"A": "工程费用", "B": "建筑工程造价", "C": "建筑安装工程费用", "D": "工程费用+基本预备费"}, "answer": ["B"], "analysis": "新增固定资产的其他费用，如果是属于整个建设项目或两个以上单项工程的，在计算新增固定资产价值时，应在各单项工程中按比例分摊。一般情况下，建设单位管理费按建筑工程、安装工程、需安装设备价值总额等按比例分摊，而土地征用费、地质勘察和建筑工程设计费等费用则按建筑工程造价比例分摊，生产工艺流程系统设计费按安装工程造价比例分摊。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1718", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "下列有关新增固定资产价值的确定，描述错误的是()。", "options": {"A": "医务所、托儿所等单项工程建成并交付使用后，也要计算新增固定资产价值", "B": "凡购置达到固定资产标准不需要安装的设备、工器具，应在交付使用后计人新增固定资产价值", "C": "-次交付生产或使用、分期分批交付生产或使用的单项工程，均应最终一次性计算新增固定资产价值", "D": "一般情况下，建设单位管理费按建安工程、需安装设备价值总额等按比例分摊"}, "answer": ["C"], "analysis": "一 次交付生产或使用的工程一次计算新增固定资产价值，分期分批交付生产或使 用的工程，应分期分批计算新增固定资产价值。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1719", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "施工企业建立施工项目成本管理责任制、开展成本控制和核算的基础是（ ）。", "options": {"A": "施工成本预测", "B": "施工成本分析", "C": "施工成本考核", "D": "施工成本计划"}, "answer": ["D"], "analysis": "施工项目成本管理责任制、开展成本控制和核算的基础。另外根据动态控制的原理，控制的前提必须有计划，所以成本计划是成本控制的基础。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1720", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "通过加强施工定额管理和施工任务单管理，控制活劳动和物化劳动的消耗。这属于施工成本管理措施的（ ）。", "options": {"A": "技术措施", "B": "组织措施", "C": "经济措施", "D": "合同措施"}, "answer": ["B"], "analysis": "本题考查的是施工成本管理的任务与措施。组织措施是从施工成本管理的组织方面采取的措施。加强施工定额管理和施工任务单管理，控制活劳动和物化劳动的损耗，加强施工调度，避免因施工计划不周和盲目调度造成窝工损失、机械利用率降低、物料积压等而使施工成本增加。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1721", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "施工成本的过程控制中，对于人工费和材料费都可以采用的控制方法是（ ）。", "options": {"A": "量价分离", "B": "包干控制", "C": "预算控制", "D": "跟踪检查"}, "answer": ["A"], "analysis": "本题考查的是施工成本的过程控制方法。人工费的控制实行“量价分离”的方法；材料费控制同样按照“量价分离”原则，控制材料用量和材料价格。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1722", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "施工项目经理部在对施工机械使用费支出的控制过程中，采取合理受安排施工生产、加强机械调度工作等的成本控制措施，主要作用是控制机械的（ ）。", "options": {"A": "台班单价", "B": "台班数量", "C": "台班保养费", "D": "台班质量"}, "answer": ["B"], "analysis": "施工生产的合理安排、加强机械调度等工作主要涉及台班数量，与机械台班单价、台班保养费和台班质量无直接关系，所以选B。选项A、C、D 均不合适。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1723", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "某建筑工程施工至某月月末，出现了工程的费用偏差小于0、进度偏差大于0 的状况，则该工程的已完工作实际费用（ACWP）、计划工作预算费用（BCWS）和已完工作预算费用（BCWP）的关系可表示为（ ）。", "options": {"A": "BCWP>ACWP>BCWS", "B": "BCWS>BCWP>ACWP", "C": "ACWP>BCWP>BCWS", "D": "BCWS>ACWP>BCWP"}, "answer": ["C"], "analysis": "按赢得值法，费用偏差CV=BCWP-ACWP；进度偏差SV=BCWP-BCWS。若CV 小于0，则ACWP 大于BCWP;SV大于0，则BCWP 大于BCWS。故有ACWP>BCWP>BCWS。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1724", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "某打桩工程合同约定，第一个月计划完成工程桩120 根；单价为1.2 万元／根。时值月底，经确认的承包商实际完成的工程桩为110 根；实际单价为1.3 万元／根。在第一个月度内，该打桩工程的已完工作预算费用（BCWP）为（ ）万元。", "options": {"A": "132", "B": "143", "C": "144", "D": "156"}, "answer": ["A"], "analysis": "BCWP 是赢得值法中的参数之一，它是按已完工作量乘以预算价格而得，故为110×1.2=132 万元。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1725", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "某地下工程施工合同约定，计划1 月份开挖土方80000m3，合同单价均为 元／m3。至1 月底，经确认实际开挖土方90000m3，实际单价为72 元/m3，则该工程的费用偏差（CV）为（ ）万元。", "options": {"A": "117", "B": "-117", "C": "85", "D": "-85"}, "answer": ["A"], "analysis": "费用偏差CV=BCWP-ACWP=90000×（85-72）=117 万元。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1726", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "某地下工程施工合同约定，计划4 月份完成混凝土工程量450m3，合同单价均为600 元/m3。该工程4 月份实际完成的混凝土工程量为400m3，实际单价700 元／m3。至4 月底，该工程的进度绩效指数（SPI）为（ ）。", "options": {"A": "0.857", "B": "0.889", "C": "1.12 5", "D": "1.167"}, "answer": ["B"], "analysis": "进度绩效指数SPI=BCWP/BCWS=400×600/450×600=0.889", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1727", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "应用相关比率法进行施工成本分析、考察管理成果的好坏，通常所采用的对比指标具有的特点是（ ）。", "options": {"A": "性质不同但相关", "B": "性质不同又不相关", "C": "概念相关时期相同", "D": "概念相关时期不同"}, "answer": ["A"], "analysis": "比率法通常是将两个以上指标的比例作分析。相关比率法一般是将两个性质不同但又相关的指标进行对比，计算出比率进行分析。这是因为项目的各个方面往往是相互联系、相互依存、相互影响的，所以选择A。选项B、C、D 均不合适。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1728", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "项目经理部通过在混凝土拌和物中加入添加剂以降低水泥消耗量，属于成本管理措施中（ ）。", "options": {"A": "经济措施", "B": "组织措施", "C": "合同措施", "D": "技术措施"}, "answer": ["D"], "analysis": "本题考查的是施工成本管理的措施。成本管理的技术措施包括：结合施工方法，进行材料使用的比选，在满足功能要求的前提下，通过代用、改变配合比、使用添加剂等方法降低材料消耗的费用等。参见教材P108。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1729", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "关于用时间—成本累计曲线编制成本计划的说法，正确的是（ ）。", "options": {"A": "可调整非关键工作的开工时间以控制实际成本支出", "B": "全部工作必须按照最早开始时间安排", "C": "全部工作必须按照最迟开始时间安排", "D": "可缩短关键工作的持续时间以降低成本"}, "answer": ["A"], "analysis": "考点:施工成本计划的编制方法。项目经理可根据编制的成本支出计划来合理安排资金，同时项目经理也可以根据筹措的资金来调整S形曲线，即通过调整非关键路线上的工序项目的最早或最迟开工时间，力争将实际的成本支出控制在计划的范围内。参见教材P112。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1730", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "对某综合楼项目实施阶段的总进度目标进行控制的主体是（ ）。", "options": {"A": "设计单位", "B": "施工单位", "C": "监理单位", "D": "建设单位"}, "answer": ["D"], "analysis": "考点:建设工程项目的总进度目标的内涵。建设工程项目总进度目标的控制是业主方项目管理的任务。参见教材P126。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1731", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "关于建设工程项目总进度目标的说法，正确的是（ ）。", "options": {"A": "建设工程项目总进度目标的控制是施工总承包方项目管理的任务", "B": "项目实施阶段的总进度指的就是施工进度", "C": "在进行项目总进度目标控制前，应分析和论证目标实现的可能性", "D": "项目总进度目标论证就是要编制项目的总进度计划"}, "answer": ["C"], "analysis": "考点:建设工程项目的总进度目标的内涵。在进行建设工程项目总进度目标控制前，首先应分析和论证目标实现的可能性。参见教材P126。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1732", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "某工程基坑开挖恰逢雨季，造成承包商雨季施工增加费用超支，产生此费用偏差的原因是（ ）。", "options": {"A": "业主原因", "B": "设计原因", "C": "客观原因", "D": "施工原因"}, "answer": ["C"], "analysis": "考点:赢得值（挣值）法。参见教材P120。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1733", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "作为施工成本控制的重要依据，工程实际完成量和成本实际支出等信息主要是从（ ）中获取的。", "options": {"A": "业务核算报告", "B": "施工组织设计", "C": "工程进度报告", "D": "工程变更报告"}, "answer": ["C"], "analysis": "因为工程实际完成量、成本实际支出等信息，反映的是工程进展的实际状况，由进度报告反映，所以选C。业务核算报告、施工组织设计和工程变更报告分别反映综合性经济指标、施工的计划信息和工程变更情况等，故选项A、B、D 均不合适。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1734", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "某混凝土工程招标清单工程量为200m3，综合单价为300 元/m3。在施工过程中，由于工程变更导致实际完成工程量为250m3。合同约定当实际工程量增加超过15%时可调整单价，调价系数为0.9。该混凝土工程的实际工程费用为（ ）万元。", "options": {"A": "6.00", "B": "7.44", "C": "7.50", "D": "8.25"}, "answer": ["B"], "analysis": "由于混凝土工程实际工程量超过了工程量清单的工程数量15%，其超出部分的工程量为250-200×（1 十15%）=20m3，该部分的综合单价需要调整，故该混凝土工程的价款为200×（1+15%)×300+20×300×0.9=7.44 万元。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1735", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "某住宅小区在施工过程中，突然要求取消建设一处配套设备用房，施工承包单位在规定期限内向开发商提交了索赔报告，开发商未及时支付变更工程款也末提供替代工程，造成施工承包单位费用及利润损失，则费用及利润损失由（ ）承担。", "options": {"A": "开发商", "B": "施工承包单位", "C": "双方共同承担", "D": "其他方式"}, "answer": ["A"], "analysis": "因非承包人原因删减了合同中的某项原定工作或工程，致使承包人发生的费用或（和）得到的利益不能被包括在其他已支付或应支付的项目中，也未被包含在任何替代的工作或工程中，则承包人有权提出并得到合理的费用及利润补偿。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1736", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "(2014年)关于最终结清，下列说法中正确的是（）。", "options": {"A": "最终结清是在工程保修期满后对剩余质量保证金的最终结清", "B": "最终结清支付证书一经签发，承包人对合同内享有的索赔权利即自行终止", "C": "质量保证金不足以抵减发包人工程缺陷修复费用的，应按合同约定的争议解决方式处理", "D": "最终结清付款涉及政府投资的，应按国家集中支付相关规定和专用合同条款约定办理"}, "answer": ["D"], "analysis": "本题考查的是最终结算。最终结清付款涉及政府投资资金的，按照国库集中支付等国家相关规定和专用合同条款的约定办理。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1737", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "(2016年)由发包人提供的工程材料、工程设备的金额，应在合同价款的期中支付和结算中予以扣出。具体的扣出标准是()。", "options": {"A": "按签约单价和签约数量", "B": "按实际采购单价和实际数量", "C": "按签约单价和实际数量", "D": "按实际采购单价和签约数量"}, "answer": ["A"], "analysis": "由发包人提供的材料、工程设备金额，应按照发包人签约提供的单价和数量从进度款支付中扣出，列入本周期应扣减的金额中。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1738", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "某工程合同工期约定为6 个月，签订的合同价为95 万元，则该工程适宜采用（ ）方式结算工程款。", "options": {"A": "按月结算", "B": "其他方式结算", "C": "分段结算", "D": "竣工后一次结算"}, "answer": ["D"], "analysis": "建设项目或单项工程全部建筑安装工程建设期12 个月以内，或者工程承包合同价值在100 万元 以下的，可以实行开工前预付一定的预付款或加上工程款每月预支，竣工后一次结算的方式。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1739", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "某基础工程包含土方和混凝土两个子项工程，工程量清单中的土方工程量为4400m3，混凝土工程量为2000m3，合同约定土石方工程综合单价为75 元/m3，混凝土工程综合单价为420 元／m3；工程预付款额度为合同价的15%，主要材料和构配件所占比重为60%。则该工程预付款的额度及起扣点分别为（ ）万元。", "options": {"A": "17.55,87.75", "B": "17.10,99.45", "C": "17.10,87.75", "D": "17.55,99.45"}, "answer": ["A"], "analysis": "合同总额P=4400×75＋2000×420=117 万元工程预付款额度=117×15%=17.55 万元起扣点T=P-M／N=117-117×15%÷60%＝87.75 万元。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1740", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "某单价合同履行中，承包人提交了已完工程量报告，发包人认为需要到现场计量，并在计量前24小时通知了承包人，但承包人收到通知后没有派人参加。则关于发包人现场计量结果的说法，正确的是（ ）。", "options": {"A": "以发包人的计量核实结果为准", "B": "以承包人的计量核实结果为准", "C": "由监理工程师根据具体情况确定", "D": "双方的计量核实结果均无效"}, "answer": ["A"], "analysis": "考点:单价合同的计量。发包人认为需要进行现场计量核实时，应在计量前24小时通知承包人，承包人应为计量提供便利条件并派人参加。双方均同意核实结果时，则双方应在上述记录上签字确认。承包人收到通知后不派人参加计量，视为认可发包人的计量核实结果。参见教材P82。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1741", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "某工程项目施工合同约定竣工时间为2016年12月30日，承包人施工质量不合格返工导致总工期延误了2个月；2017年1月项目所在地政府出台了新政策，直接导致承包人计入总造价的税金增加20万元。关于增加的20万元税金责任承担的说法，正确的是（ ）。", "options": {"A": "由承包人和发包人共同承担，理由是国家政策变化，非承包人的责任", "B": "由发包人承担，理由是国家政策变化，承包人没有义务承担", "C": "由承包人承担，理由是承包人责任导致延期，进而导致税金增加", "D": "由发包人承担，理由是承包人承担质量问题责任，发包人承担政策变化的风险"}, "answer": ["C"], "analysis": "考点:法律法规变化。因承包人原因导致工期延误，且上述规定的调整时间在合同工程原定竣工时间之后，合同价款调增的不予调整，合同价款调减的予以调整。参见教材P84。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1742", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "根据九部委《标准施工招标文件》，监理人对隐蔽工程重新检查，经经验证明工程质量符合合同要求的，发包人应补偿承包人（ ）。", "options": {"A": "工期和费用", "B": "工期、费用和利润", "C": "费用和利润", "D": "工期和利润"}, "answer": ["B"], "analysis": "本题考查的是索赔费用的计算。监理人对隐蔽工程重新检查，经检验证明工程质量符合合同要求的，发包人应补偿承包人工期、费用和利润。参见教材P93。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1744", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "(2015年)关于建设项目竣工验收，下列说法正确的是( )。", "options": {"A": "单位工程的验收由施工单位组织", "B": "大型项目单位工程的验收由国家发改委组织", "C": "小型项目的整体验收由项目主管部门组织", "D": "工程保修书不属于竣工验收的条件"}, "answer": ["C"], "analysis": "小型和限额以下项目地整体验收由项目主管部门组织。选项A，单位工程的验收由监理单位组织。选项B，大型项目的整体验收由国家发改委组织。选项D，工程保修书属于竣工验收的条件之一。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1745", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "(2013年)下列资料中，不属于竣工验收报告附有文件的是()。", "options": {"A": "工程竣工验收备案表", "B": "施工许可证", "C": "施工图设计文件审查意见", "D": "施工单位签署的工程质量保修书"}, "answer": ["A"], "analysis": "工程竣工验收报告还应附有下列文件：①施工许可证；②施工图设计文件审查意见；③验收组人员签署的工程竣工验收意见；④市政基础设施工程应附有质量检测和功能性试验资料；⑤施工单位签署的工程质量保修书；⑥法规、规章规定的其他有关文件。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1746", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "(2014年)大中型和限额以上建设项目及技术改造项目，工程整体验收的组织单位可以是（）", "options": {"A": "监理单位", "B": "业主单位", "C": "使用单位", "D": "国家发改委"}, "answer": ["D"], "analysis": "大中型和限额以上建设项目及技术改造项目，由国家发改委或国家发改委委托项目主管部门、地方政府部门组织验收；小型和限额以下建设项目及技术改造项目，由项目主管部门或地方政府部门组织验收。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1747", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "(2016年)竣工财务决算的基本建设项目概况表中，应列入非经营性项目转出投资支出的项目是()。", "options": {"A": "产权属于本单位的城市绿化", "B": "不能形成资产的城市绿化", "C": "产权属于本单位的专用道路", "D": "产权不属于本单位的专用道路"}, "answer": ["D"], "analysis": "经营性项目转出投资支出是指非经营项目为项目配套的专用设施投资，包括专用道路、专用通信设施、送变电站、地下管道等，且其产权不属于本单位的投资支出。对于产权归属本单位的，应计入交付使用资产价值。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1783", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "下列项目成本分析方法中，（ ）具有通俗易懂、简单易行、便于掌握的特点，因而得到了广泛的应用，但在应用时必须注意各技术经济指标的可比性。", "options": {"A": "比较法", "B": "因素分析法", "C": "差额计算法", "D": "比率法"}, "answer": ["A"], "analysis": "1)比较法。又称指标对比分析法，是通过技术经济指标的对比检查目标的完成情况，分析产生差异的原因，进而挖掘内部潜力的方法。其特点是通俗易懂、简单易行、便于掌握。 2)因素分析法。又称连环置换法。这种方法可用来分析各种因素对成本的影响程度。 3)差额计算法。差额计算法是因素分析法的一种简化形式，它利用各个因素的目标值与实际值的差额来计算其对成本的影响程度。 4)比率法。比率法是指用两个以上的指标的比例进行分析的方法。其基本特点是，先把对比分析的数值变成相对数，再观察其相互之间的关系。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1784", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "成本控制方法中，（ ）是对工程项目成本/进度进行综合控制的一种分析方法。", "options": {"A": "工期一成本同步分析法", "B": "挣值法", "C": "项目成本分析表法", "D": "比率法"}, "answer": ["B"], "analysis": "赢得值法也叫挣值法。赢得值法是对工程项目成本/进度进行综合控制的一种分析方法。通过比较已完工程预算成本与已完工程实际成本之间的差值，可以分析由于实际价格的变化而引起的累计成本偏差；通过比较已完工程预算成本与拟完工程预算成本之间的差值，可以分析由于进度偏差而引起的累计成本偏差。并通过计算后续未完工程的计划成本余额，预测其尚需的成本数额，从而为后续工程施工的成本、进度控制及寻求降低成本途径指明方向。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1785", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "下列选项中，（ ）是指在项目实施过程中，对影响项目成本的各项要素，即施工生产所耗费的人力、物力和各项费用开支，采取一定措施进行监督、调节和控制，及时预防、发现和纠正偏差，保证项目成本目标的实现。", "options": {"A": "成本核算", "B": "成本控制", "C": "成本分析", "D": "成本测算"}, "answer": ["B"], "analysis": "成本控制是指在工程项目实施过程中，对影响工程项目成本的各项要素，即施工生产所耗费的人力、物力和各项费用开支，采取一定措施进行监督、调节和控制，及时预防、发现和纠正偏差，保证工程项目成本目标的实现。 成本核算是施工承包单位利用会计核算体系，对工程项目施工过程中所发生的各项费用进行归集，统计其实际发生额，并计算工程项目总成本和单位工程成本的管理工作。 成本分析是揭示工程项目成本变化情况及其变化原因的过程。成本分析为成本考核提供依据，也为未来的成本预测与成本计划编制指明方向。 成本测算是指施工承包单位凭借历史数据和工程经验，运用一定方法对工程项目未来的成本水平及其可能的发展趋势做出科学估计。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1786", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "建设工程成本管理内容中，（ ）是目标成本的一种表达形式，是建立项目成本管理责任制、开展和核算的基础，是进行成本费用控制的主要依据。", "options": {"A": "成本分析", "B": "成本计划", "C": "成本控制", "D": "成本核算"}, "answer": ["B"], "analysis": "成本计划是在成本预测的基础上，施工承包单位及其项目经理部对计划期内工程项目成本水平所做的筹划。施工成本计划是以货币形式表达的项目在计划期内的生产费用、成本水平及为降低成本采取的主要措施和规划的具体方案。成本计划是目标成本的一种表达形式，是建立项目成本管理责任制、开展成本控制和核算的基础，是进行成本费用控制的主要依据。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1787", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "项目成本计划的编制方法中，当项目非常庞大和复杂而需要分为几个部分时，可采用（ ）。", "options": {"A": "定率估算法", "B": "技术进步法", "C": "按实计算法", "D": "目标利润法"}, "answer": ["A"], "analysis": "定率估算法(历史资料法) 。当工程项目非常庞大和复杂而需要分为几个部分时采用的方法。首先将工程项目分为若干子项目，参照同类工程项目的历史数据，采用算术平均法计算子项目目标成本降低率和降低额，然后再汇总整个工程项目的目标成本降低率、降低额。在确定子项目成本降低率时，可采用加权平均法或三点估算法。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1788", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "项目（ ）是以货币形式编制的项目在计划期内的生产费用、成本水平及为降低成本采取的主要措施和规划的具体方案。", "options": {"A": "成本计划", "B": "成本预测", "C": "成本控制", "D": "成本核算"}, "answer": ["A"], "analysis": "成本计划是在成本预测的基础上，施工承包单位及其项目经理部对计划期内工程项目成本水平所做的筹划。施工成本计划是以货币形式表达的项目在计划期内的生产费用、成本水平及为降低成本采取的主要措施和规划的具体方案。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1789", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "先将对比分析的数值变成相对数，再观察其相互之间关系的项目成本分析方法是（ ）。", "options": {"A": "比较法", "B": "差额计算法", "C": "比率法", "D": "因素分析法"}, "answer": ["C"], "analysis": "比率法是指用两个以上的指标的比例进行分析的方法。其基本特点是，先把对比分析的数值变成相对数，再观察其相互之间的关系。常用的比率法有以下几种：①相关比率法。②构成比率法。③动态比率法。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1790", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "根据《建设工程施工合同示范文本》中的合同条款，关于合理补偿承包人索赔的说法，正确的是（ ）。", "options": {"A": "承包人遇到不利物质条件可进行利润索赔", "B": "发生不可抗力只能进行工期索赔", "C": "异常恶劣天气导致的停工通常可以进行费用索赔", "D": "发包人原因引起的暂停施工只能进行工期索赔"}, "answer": ["B"], "analysis": "", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1791", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "如果初始延误者是客观原因，则在客观因素发生影响的延误期内，承包人（ ）。", "options": {"A": "不可以得到工期延长，也很难得到费用补偿", "B": "不可以得到工期延长，可以得到费用补偿", "C": "可以得到工期延长，也可以得到费用补偿", "D": "可以得到工期延长，但很难得到费用补偿"}, "answer": ["D"], "analysis": "在实际施工过程中，工期拖期很少是只由一方造成的，往往是两、三种原因同时发生(或相互作用)而形成的，故称为\"共同延误\"。在这种情况下，要具体分析哪一种情况延误是有效的，应依据以下原则： (1)首先判断造成拖期的哪一种原因是最先发生的，即确定\"初始延误\"者，它应对工程拖期负责。在初始延误发生作用期间，其他并发的延误者不承担拖期责任。 (2)如果初始延误者是发包人原因，则在发包人原因造成的延误期内，承包人既可得到工期延长，又可得到经济补偿。 (3)如果初始延误者是客观原因，则在客观因素发生影响的延误期内，承包人可以得到工期延长，但很难得到费用补偿。 (4)如果初始延误者是承包人原因，则在承包人原因造成的延误期内，承包人既不能得到工期补偿，也不能得到费用补偿 。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1792", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "施工单位在施工中发生如下事项：完成业主要求的合同外用工花费万元；由于设计图纸延误造成工人窝工损失1万元；施工电梯机械故障造成工人窝工损失2万元。施工单位可向业主索赔的人工费为（ ）万元。", "options": {"A": "3", "B": "5", "C": "4", "D": "6"}, "answer": ["C"], "analysis": "施工单位可向业主索赔的人工费为(3+1)万元=4万元。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1793", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "某工程合同价格为5000万元，计划工期是200天，施工期间因非承包人原因导致工期延误天，若同期该公司承揽的所有工程合同总价为2．5亿元，计划总部管理费为1250万元，则承包人可以索赔的总部管理费为（ ）万元。", "options": {"A": "7．5", "B": "10", "C": "12．5", "D": "15"}, "answer": ["C"], "analysis": "该工程的总部管理费=1250×5000／25000=250万元 日平均总部管理费=250／200=1．25万元 索赔的总部管理费=1．25×10=12．5万元 考前黑钻押题，金考典软件考前更新，下载链接 www.jinkaodian.com", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1794", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "根据《建设工程价款结算暂行办法》，原则上预付比例不低于合同金额的（ ）。", "options": {"A": "5%", "B": "10%", "C": "15%", "D": "20%"}, "answer": ["B"], "analysis": "根据《建设工程价款结算暂行办法》的规定，预付款的比例原则上不低于合同金额的10% ，不高于合同金额的30%。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1795", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "已知某工程承包合同价款总额是3000万元，其主要材料及构件所占比重为60%，预付款总金额为工程价款总额的20%，则预付款起扣点是（ ）万元。", "options": {"A": "1000", "B": "1400", "C": "1500", "D": "2000"}, "answer": ["D"], "analysis": "起扣点的计算公式如下：T=P-M/N 式中T一一起扣点(即工程预付款开始扣回时)的累计完成工程金额；P一一承包工程合同总额；M一一工程预付款总额； N一一主要材料及构件所占比重。 预付款起扣点=3000-(3000×20%)÷60%=2000万元。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1796", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "由于不可抗力解除合同的，发包人应向承包人支付（ ）。", "options": {"A": "合同解除之日前已完成工程但尚未支付的合同价款", "B": "合同解除之后完成工程但尚未支付的合同价款", "C": "合同解除之后完成工程的合同价款", "D": "合同解除之日前未完成工程但尚未支付的合同价款"}, "answer": ["A"], "analysis": "由于不可抗力解除合同的，发包人除应向承包人支付合同解除之日前已完成工程但尚未支付的合同价款，还应支付下列金额： (1)合同中约定应由发包人承担的费用。 (2)已实施或部分实施的措施项目应付价款。 (3)承包人为合同工程合理订购且已交付的材料和工程设备货款。发包人一经支付此项货款，该材料和工程设备即成为发包人的财产。 (4)承包人撤离现场所需的合理费用，包括员工遣送费和临时工程拆除、施工设备运离现场的费用。 (5)承包人为完成合同工程而预期开支的任何合理费用，且该项费用未包括在本款其他各项支付之内。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1797", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "承包人在合同内享有的索赔权利也自行终止是在（ ）。", "options": {"A": "最终结清付款后", "B": "缺陷责任期终止后", "C": "最终结清申请单进行审核后", "D": "签发最终支付证书后"}, "answer": ["A"], "analysis": "发包人应在签发最终结清支付证书后的规定时间内，按照最终结清支付证书列明的金额向承包人支付最终结清款。最终结清付款后，承包人在合同内享有的索赔权利也自行终止。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1798", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "根据《建设工程价款结算暂行办法》的规定，在竣工结算编审过程中，单位工程竣工结算的编制人是（ ）。", "options": {"A": "业主", "B": "承包商", "C": "总承包商", "D": "监理咨询机构"}, "answer": ["B"], "analysis": "单位工程竣工结算由承包人编制，发包人审查;实行总承包的工程，由具体承包人编制，在总包人审查的基础上，发包人审查。单项工程竣工结算或建设项目竣工总结算由总(承)包人编制，发包人可直接进行审查，也可以委托具有相应资质的工程造价咨询机构进行审查。政府投资项目由同级财政部门审查。单项工程竣工结算或建设项目竣工总结算经发包人、承包人签字盖章后有效。承包人应在合同约定期限内完成项目竣工结算编制工作，未在规定期限内完成的，并且提不出正当理由延期的，责任自负。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1799", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "由建设单位编制，反映建设项目实际造价和投资效果的文件是（ ）。", "options": {"A": "竣工决算", "B": "竣工验收", "C": "竣工整理", "D": "竣工核实"}, "answer": ["A"], "analysis": "竣工决算是以实物数量和货币指标为计量单位，综合反映竣工建设项目全部建设费用、建设成果和财务状况的总结性文件，是竣工验收报告的重要组成部分，竣工决算是正确核定新增固定资产价值，考核分析投资效果，建立健全经济责任制的依据，是反映建设项目实际造价和投资效果的文件 。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1800", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "股票和债券根据是否可以上市流通分别采用（ ）确定其价值。", "options": {"A": "市场法和收益法", "B": "政府定价法和市场法", "C": "市场法和政府定价法", "D": "收益法和计划法"}, "answer": ["A"], "analysis": "短期投资包括股票、债券、基金。股票和债券根据是否可以上市流通分别采用市场法和收益法确定其价值。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1801", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "关于建设工程项目竣工决算，下列说法不正确的是（ ）。", "options": {"A": "竣工决算是以工程量和技术指标为计量单位的", "B": "竣工决算是竣工验收报告的重要组成部分", "C": "竣工决算是反映建设项目实际造价和投资效果的文件", "D": "竣工决算是综合反映竣工建设项目全部建设费用、建设成果和财务情况的总结性文件"}, "answer": ["A"], "analysis": "竣工决算是以实物数量和货币指标为计量单位，综合反映竣工建设项目全部建设费用、建设成果和财务状况的总结性文件，是竣工验收报告的重要组成部分，竣工决算是正确核定新增固定资产价值，考核分析投资效果，建立健全经济责任制的依据，是反映建设项目实际造价和投资效果的文件 。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1802", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "竣工财务决算报表中，（ ）是办理资产交接和接收单位登记资产账目的依据，是使用单位建立资产明细账和登记新增资产价值的依据。", "options": {"A": "建设项目竣工财务决算审批表", "B": "建设项目交付使用资产明细表", "C": "建设项目概况表", "D": "建设项目交付使用资产总表"}, "answer": ["B"], "analysis": "基本建设项目交付使用资产明细表。该表反映交付使用的固定资产、流动资产、无形资产和其他资产及其价值的明细情况，是办理资产交接和接收单位登记资产账目的依据，是使用单位建立资产明细账和登记新增资产价值的依据。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1803", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "新增固定资产是建设项目竣工投产后所增加的固定资产的价值，它是以（ ）形态表示的固定资产投资最终成果的综合性指标。", "options": {"A": "时间", "B": "期货", "C": "货币", "D": "价值"}, "answer": ["D"], "analysis": "新增固定资产价值是建设项目竣工投产后所增加的固定资产的价值，它是以价值形态表示的固定资产投资最终成果的综合性指标。新增固定资产价值是投资项目竣工投产后所增加的固定资产价值，即交付使用的固定资产价值，是以价值形态表示建设项目的固定资产最终成果的指标。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1804", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "建设工程竣工决算的文件，由（ ）负责组织人员编写。", "options": {"A": "施工单位", "B": "建设单位", "C": "设计单位", "D": "监理单位"}, "answer": ["B"], "analysis": "建设项目竣工决算是指项目建设单位根据国家有关规定在项目竣工验收阶段为确定建设项目从筹建到竣工验收实际发生的全部建设费用(包括建筑工程费、安装工程费、设备及工器具购置费用、预备费等费用)而编制的财务文件。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1805", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "间接成本是指与研制开发有关的费用，其中不包括（ ）。", "options": {"A": "非专用设备折旧费", "B": "管理费", "C": "应分摊的公共费用及能源费用", "D": "咨询鉴定费"}, "answer": ["D"], "analysis": "研制成本包括直接成本和间接成本：直接成本是指研制过程中直接投入发生的费用(主要包括材料费用、工资费用、专用设备费、资料费、咨询鉴定费、协作费、培训费和差旅费等)，间接成本是指与研制开发有关的费用(主要包括管理费、非专用设备折旧费、应分摊的公共费用及能源费用)。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1806", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "某企业固定资产原价为10000元，预计净残值500元，预计可使用5年。采用平均年限法和双倍余额递减法计算第4年的折旧额分别为（ ）元。", "options": {"A": "1900和830", "B": "2000和864", "C": "1900和864", "D": "2000和830"}, "answer": ["A"], "analysis": "平均年限法：折旧额=（10000-500）÷5=1900元；双倍余额递减法：年折旧率=2÷5×100%=40%；第一年折旧额：10000×40%=4000（元）；第二年折旧额：（10000-4000）×40%=2400（元）；第三年折旧额：（10000-4000-2400）×40%=1440（元）；第四年、第五年折旧额：（10000-4000-2400-1440-500）÷2=830（元）。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1839", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "施工合同履行期间，下列不属于工程计量范围的是（ ）", "options": {"A": "工程变更修改的工程量清单内容", "B": "合同文件中规定的各种费用支付项目", "C": "暂列金额中的专业工程", "D": "擅自超比施工图纸施工的工程"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是工程计量【选项分析】工程计量的范围包括：工程量清单及工程变更所修订的工程量清单的内容；合同文件中规定的各种费用支付项目，如费用索赔、各种预付款、价格调整、违约金等。", "tags": [], "source": "四、信息技术在工程造价计价与计量中的应用", "src": "好题库"}, {"id": "ht_mgmt_1846", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "根据《建设工程施工合同（示范文本）》（GF-2017-0201），工程缺陷责任期最长不超过（ ）个月。", "options": {"A": "6", "B": "12", "C": "24", "D": "36"}, "answer": ["C"], "analysis": "【考点来源】本题考查的是建设工程施工合同（示范文本）【选项分析】缺陷责任期从工程通过竣工验收之日起计算，合同当事人应在专用合同条款约定缺陷责任期的具体期限，但该期限最长不超过24个月。", "tags": [], "source": "二、《建设工程施工合同（示范文本）》的主要内容", "src": "好题库"}, {"id": "ht_mgmt_1852", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "竣工决算文件中，主要反映竣工工程建设成果和经验，全面考核分析工程投资与造价的书面总结文件是（ ）。", "options": {"A": "竣工财务决算说明书", "B": "竣工财务决算报表", "C": "工程竣工造价对比分析", "D": "工程竣工验收报告"}, "answer": ["A"], "analysis": "【内容考查】本题考查的是竣工财务决算说明书【选项分析】竣工财务决算说明书主要反映竣工工程建设成果和经验，是对竣工决算报表进行分析和补充说明的文件，是全面考核分析工程投资与造价的书面总结。", "tags": [], "source": "二、竣工决算的内容", "src": "好题库"}, {"id": "mgmt_hqwx_0249", "date": "2026-07-09", "chapter": "g07", "type": "single", "stem": "关于工程计量的方法，下列说法正确的是（ ）。", "options": {"A": "按照合同文件中规定的工程量予以计量", "B": "不符合合同文件要求的工程不予计量", "C": "单价合同工程量必须按现行定额规定的工程量计算规则计量", "D": "总价合同项目的工程量是予以计量的最终工程量"}, "answer": ["B"], "analysis": "【选项分析】本题考查的是 【内容考查】工程计量的原则包括下列三个方面：1）不符合合同文件要求的工程不予计量。2）按合同文件所规定的方法、范围、内容和单位计量3）因承包人原因造成的超出合同工程范围施工或返工的工程量，发包人不予计量。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0319", "date": "2026-07-09", "chapter": "g07", "type": "single", "stem": "根据《建设工程施工合同（示范文本）》(GF-2017-0201)，工程预付款支付应按照专用合同的约定执行，但最迟支付的时间是（ ）。", "options": {"A": "签订施工合同后30天内", "B": "开工通知载明的开工日期7天前", "C": "收到中标通知书并确认后30天内", "D": "实际开工前14天"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是《建设工程施工合同（示范文本）》的主要内容 【选项分项】预付款的支付按照专用合同条款约定执行，但至迟应在开工通知载明的开工日期7天前支付。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0347", "date": "2026-07-09", "chapter": "g07", "type": "single", "stem": "成本分析、成本考核、成本核算是建设工程项目施工成本管理的重要环节，仅就此三项工作而言，其正确的工作流程是（ ）。", "options": {"A": "成本核算-成本分析-成本考核", "B": "成本分析-成本考核-成本核算", "C": "成本考核-成本核算-成本分析", "D": "成本分析-成本核算-成本考核"}, "answer": ["A"], "analysis": "施工成本管理是一个有机联系与相互制约的系统过程，施工成本管理流程应遵循下列程序：（1）掌握成本测算数据（生产要素的价格信息及中标的施工合同价）；（2）编制成本计划，确定成本实施目标；（3）进行成本控制；（4）进行施工过程成本核算；（5）进行施工过程成本分析；（6）进行施工过程成本考核；（7）编制施工成本报告；（8）施工成本管理资料归档。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0351", "date": "2026-07-09", "chapter": "g07", "type": "single", "stem": "关于工程变更权的说法，正确的是（ ）。", "options": {"A": "发包人与工程师均可以提出变更", "B": "发包人与承包人均可以提出变更", "C": "承包人与工程师均可以提出变更", "D": "仅工程师可以提出变更"}, "answer": ["A"], "analysis": "发包人和工程师（指监理人、咨询人等业主授权的第三方，下同）均可以提出变更。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0352", "date": "2026-07-09", "chapter": "g07", "type": "single", "stem": "根据《建设工程施工合同（示范文本）》(GF-2017-0201)，除专用合同条款另有约定的外，下列情形不属于工程变更的是（ ）。", "options": {"A": "追加额外的工作", "B": "基础工程的标高略有改变", "C": "改变基础的尺寸", "D": "合同中的某项工作转由他人实施"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是工程变更的范围 【选项分析】工程变更包括以下五个方面： （1）增加或减少合同中任何工作，或追加额外的工作; （2）取消合同中任何工作，但转由他人实施的工作除外; （3）改变合同中任何工作的质量标准或其他特性; （4）改变工程的基线、标高、位置和尺寸; （5）改变工程的时间安排或实施顺序。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0354", "date": "2026-07-09", "chapter": "g07", "type": "single", "stem": "关于工程索赔的相关论述，下列说法正确的是（ ）。", "options": {"A": "工程索赔是指承包人向发包人提出工期和(或)费用补偿要求的行为", "B": "由于发包人原因导致分包人遭受经济损失，分包人可直接向发包人提出索赔", "C": "承包人提出的工期补偿索赔经发包人批准后，可先免除承包人非自身原因拖期违约责任", "D": "由于不可抗力事件造成合同非正常终止，承包人不能向发包人提出索赔"}, "answer": ["C"], "analysis": "选项A错误，工程索赔是指在工程合同履行过程中，当事人一方因非己方的原因而遭受经济损失或工期延误，按照合同约定或法律规定，应由对方承担责任，而向对方提出工期和(或)费用补偿要求的行为。选项B错误，由于发包人原因导致分包人遭受经济损失，分包人不可直接向发包人提出索赔，选项D错误，由于不可抗力事件造成合同非正常终止，承包人可以向发包从提出索赔。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0357", "date": "2026-07-09", "chapter": "g07", "type": "single", "stem": "工程在施工合同履行期间发生共同延误时间，正确的处理方式是（ ）。", "options": {"A": "按照延误时间的长短，由责任方共同分担延误带来的损失", "B": "发包人是初始延误者，承包人可得到工期和费用补偿，但得不到利润补偿", "C": "承包人是初始延误者，承包人只能得到工期的补偿，但得不到费用补偿", "D": "客观原因造成的初始延误，承包人可得到工期补偿，但很难到费用补偿"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是工期索赔的计算 【选项分析】（1）首先判断造成拖期的哪一种原因是最先发生的，即确定“初始延误” 者，它应对工程拖期负责。在初始延误发生作用期间，其他并发的延误者不承担拖期责任。（2）如果初始延误者是发包人原因，则在发包人原因造成的延误期内，承包人既可得到工期延长，又可得到经济补偿。（3）如果初始延误者是客观原因，则在客观因素发生影响的延误期内，承包人可以得到工期延长，但很难得到费用补偿。（4）如果初始延误者是承包人原因，则在承包人原因造成的延误期内，承包人既不能得到工期补偿，也不能得到费用补偿。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0360", "date": "2026-07-09", "chapter": "g07", "type": "single", "stem": "根据《建设工程价款结算暂行办法》的规定，预付款的比例原则上不低于合同金额的（ ），不高于合同金额的（ ）。", "options": {"A": "10%，20%", "B": "10%，30%", "C": "20%，30%", "D": "20%，40%"}, "answer": ["B"], "analysis": "【内容考查】本题考查的是预付款 【选项分析】 根据《建设工程价款结算暂行办法》的规定，预付款的比例原则上不低于合同金额的10%，不高于合同金额的30%。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0363", "date": "2026-07-09", "chapter": "g07", "type": "single", "stem": "下列文件和资料中，可作为建设工程工程量计量依据的是（ ）。", "options": {"A": "造价管理机构发布的调价文件", "B": "造价管理机构发布的价格信息", "C": "质量合格证书", "D": "各种预付款支付凭证"}, "answer": ["C"], "analysis": "【内容考查】本题考查的是工程计量的原则与范围 【选项分析】工程计量的依据包括：工程量清单及说明；合同图纸；工程变更令及其修订的工程量清单；合同条件；技术规范；有关计量的补充协议；质量合格证书等。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0364", "date": "2026-07-09", "chapter": "g07", "type": "single", "stem": "关于施工合同工程预付款，下列说法中正确的是（ ）。", "options": {"A": "承包人预付款的担保金额通常高于发包人的预付款", "B": "采用起扣点计算法抵扣预付款对承包人比较不利", "C": "预付款的担保金额不会随着预付款的扣回而减少", "D": "预付款的额度通常与主要材料和构件费用占建安费的比例相关"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是预付款 【选项分析】关于A预付款担保的担保金额通常与发包人的预付款是等值的。关于B起扣点计算法对承包人比较有利，最大限度地占用了发包人的流动资金，但是，显然不利于发包人资金使用。关于C预付款一般逐月从工程进度款中扣除，预付款担保的担保金额也相应逐月减少。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0365", "date": "2026-07-09", "chapter": "g07", "type": "single", "stem": "根据《建设工程质量保证金管理办法》（建质〔2017〕138 号），工程质量保证金总预留比例不得高于工程价款结算总额的（ ）。", "options": {"A": "3%", "B": "5%", "C": "8%", "D": "10%"}, "answer": ["A"], "analysis": "【考点来源】本题考查的是工程质量保证金的预留 【选项分析】根据《建设工程质量保证金管理暂行办法》（建质〔2017〕138号）中规定：发包人应按照合同约定方式预留保证金，保证金总预留比例不得高于工程价款结算总额的3%。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0366", "date": "2026-07-09", "chapter": "g07", "type": "single", "stem": "关于政府投资项目竣工结算的审核，下列说法正确的是（ ）。", "options": {"A": "单位工程竣工结算由承包人审核", "B": "单项工程竣工结算由承包人审核", "C": "建设项目竣工总结算由发包人委托造价工程师审核", "D": "竣工结算文件由发包人委托具有相应资质的工程造价咨询机构审核"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是工程竣工结算的编制和审核 【选项分析】国有资金投资建设工程的发包人，应当委托具有相应资质的工程造价咨询企业对竣工结算文件进行审核。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0367", "date": "2026-07-09", "chapter": "g07", "type": "single", "stem": "关于建筑安装工程结算的编制，下列说法中正确的是（ ）。", "options": {"A": "采用固定总价合同的，暂列金额不得调整", "B": "采用固定总价合同的，税率可不按政府部门新公布的税率调整", "C": "规费应按县级建设主管部门规定的费率计算", "D": "现场签证费用应依据发承包双方签证资料确认的金额计算"}, "answer": ["D"], "analysis": "【内容考查】本题考查的是工程结算的编制和审核 【选项分析】在工程竣工结算时，其他项目应按下列规定计价：1）计日工应按发包人实际签证确认的事项计算2）暂估价应按发承包双方按照《建设工程工程量清单计价规范》的相关规定计算3）总承包服务费应依据合同约定金额计算，如发生调整的，以发承包双方确认调整的金额计算4）施工索赔费用应依据发承包双方确认的索赔事项和金额计算5）现场签证费用应依据发承包双方签证资料确认的金额计算6）暂列金额应减去工程价款调整（包括索赔、现场签证）金额计算，如有余额归发包人。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0369", "date": "2026-07-09", "chapter": "g07", "type": "single", "stem": "某工程合同约定以银行保函替代预留工程质量保证金，签约合同价为800万元。工程价款结算总额为780万元，依据《建设工程质量保证金管理办法》，该保函金额最大为（ ）万元 。", "options": {"A": "15.6", "B": "16.0", "C": "23.4", "D": "24.0"}, "answer": ["C"], "analysis": "保函金额不得高于工程价款结算总额的3% 。780*3%=23.4", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0371", "date": "2026-07-09", "chapter": "g07", "type": "single", "stem": "竣工决算编制程序的内容有:①收集、整理有关项目竣工决算依据:②编写项目竣工决算说明书③清理项目账务、债务和结算物资④报上级审查⑤填写项目竣工决算报告。其正确的顺序是（ ）。", "options": {"A": "②-①-③-⑤-④", "B": "②-①-④-③-⑤", "C": "①-③-⑤-②-④", "D": "①-④-②-③-⑤"}, "answer": ["C"], "analysis": "竣工决算编制程序：（1）收集、整理有关项目竣工决算依据（2）清理项目账务、债务和结算物资（3）填写项目竣工决算报告（4）编写项目竣工决算说明书（5）报上级审查。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0372", "date": "2026-07-09", "chapter": "g07", "type": "single", "stem": "在工程竣工结算的编制和审核过程中，单位工程竣工结算的审查人是（ ）。", "options": {"A": "监理人", "B": "发包人", "C": "工程师", "D": "工程造价咨询机构"}, "answer": ["B"], "analysis": "单位工程竣工结算由承包人编制，发包人审查；实行总承包的工程，由具体承包人编制，在总包人审查的基础上，发包人审查。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0373", "date": "2026-07-09", "chapter": "g07", "type": "single", "stem": "竣工决算的编制程序分为前期准备、实施、完成和（ ）四个阶段。", "options": {"A": "对比分析", "B": "资料归档", "C": "分类整理", "D": "后评价"}, "answer": ["B"], "analysis": "竣工决算的编制程序分为前期准备、实施、完成和资料归档四个阶段。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0374", "date": "2026-07-09", "chapter": "g07", "type": "single", "stem": "竣工决算的内容由四部分组成，其核心内容为（ ）。", "options": {"A": "竣工财务决算说明书和工程竣工造价对比分析", "B": "竣工财务决算说明书和工程竣工图", "C": "竣工财务决算说明书和竣工财务决算报表", "D": "工程竣工图和工程竣工造价对比分析"}, "answer": ["C"], "analysis": "【内容考查】本题考查的是竣工决算的内容 【选项分析】竣工决算由竣工财务决算说明书、竣工财务决算报表、工程竣工图和工程竣工造价对比分析四部分组成。其中竣工财务决算说明书和竣工财务决算报表两部分又称建设项目竣工财务决算，是竣工决算的核心内容。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0379", "date": "2026-07-09", "chapter": "g07", "type": "single", "stem": "下列选项中，不属于竣工决算的组成部分的有（ ）。", "options": {"A": "竣工财务决算说明书", "B": "竣工财务决算报表", "C": "工程施工图纸", "D": "工程造价对比分析"}, "answer": ["C"], "analysis": "本题考查的是竣工决算。根据财政部、国家发改委和住房城乡建设部的有关文件规定，竣工决算是由竣工财务决算说明书、竣工财务决算报表、工程竣工图和工程竣工造价对比分析四部分组成。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0382", "date": "2026-07-09", "chapter": "g07", "type": "single", "stem": "根据建设项目规模的大小，竣工决算分为（ ）。", "options": {"A": "大型建设项目竣工决算和中、小型建设项目竣工决算两大类", "B": "大、中型建设项目竣工决算和小型建设项目竣工决算两大类", "C": "重点建设项目竣工决算和一般建设项目竣工决算两大类", "D": "大型建设项目竣工决算、中型建设项目竣工决算和小型建设项目竣工决算三大类"}, "answer": ["B"], "analysis": "【考点来源】本题考查的是竣工决算概述 【选项分析】根据建设项目规模的大小，竣工决算分为大、中型建设项目竣工决算和小型建设项目竣工决算两大类。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0385", "date": "2026-07-09", "chapter": "g07", "type": "single", "stem": "对于国有资金投资的建设工程，受发包人委托对竣工结算文件进行审核的单位是（ ）。", "options": {"A": "工程造价咨询机构", "B": "工程设计单位", "C": "工程造价管理机构", "D": "工程监理单位"}, "answer": ["A"], "analysis": "竣工结算文件审核的委托。国有资金投资建设工程的发包人，应当委托具有相应资质的工程造价咨询机构对竣工结算文件进行审核。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "gl-g07-014", "date": "2026-07-08", "chapter": "g07", "type": "multiple", "stem": "工程变更价款确定的原则包括（ ）。", "options": {"A": "合同中已有适用价格的，按合同价格执行", "B": "合同中有类似价格的，参照类似价格", "C": "合同中没有适用或类似价格的，由发包人直接定价", "D": "合同中没有适用或类似价格的，由承包人提出经发包人确认", "E": "变更价款一律由造价咨询机构确定"}, "answer": ["A", "B", "D"], "analysis": "三种情况：已有适用价格→按合同价格(A)；有类似价格→参照类似价格(B)；无适用或类似价格→承包人提出经发包人确认(D)。C错误(不能发包人单方定价)，E错误(并非一律由咨询机构确定)。", "tags": ["工程变更", "价款确定"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-021", "date": "2026-07-08", "chapter": "g07", "type": "multiple", "stem": "下列属于费用索赔组成内容的有（ ）。", "options": {"A": "人工费", "B": "材料费", "C": "管理费", "D": "利润", "E": "违约金"}, "answer": ["A", "B", "C", "D"], "analysis": "费用索赔组成包括：人工费、材料费、施工机具使用费、管理费、利润以及增值税。违约金不属于索赔费用组成，属于违约责任的范畴。", "tags": ["索赔", "费用组成"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-022", "date": "2026-07-08", "chapter": "g07", "type": "multiple", "stem": "根据索赔分类，工程索赔可分为（ ）。", "options": {"A": "工期索赔", "B": "费用索赔", "C": "质量索赔", "D": "安全索赔", "E": "违约索赔"}, "answer": ["A", "B"], "analysis": "工程索赔主要分为工期索赔(要求延长工期)和费用索赔(要求经济补偿)两大类。质量索赔、安全索赔、违约索赔属于其他法律范畴。", "tags": ["索赔", "分类"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-030", "date": "2026-07-08", "chapter": "g07", "type": "multiple", "stem": "进度款结算的方式包括（ ）。", "options": {"A": "按月结算", "B": "分段结算", "C": "竣工后一次结算", "D": "按日结算", "E": "即时结算"}, "answer": ["A", "B"], "analysis": "进度款结算主要有两种方式：按月结算(每月按实际完成量支付)和分段结算(按工程形象进度分段支付)。竣工后一次结算适用于工期短的小型工程，按日结算和即时结算不常用。", "tags": ["价款结算", "结算方式"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-032", "date": "2026-07-08", "chapter": "g07", "type": "multiple", "stem": "竣工决算的内容包括（ ）。", "options": {"A": "竣工财务决算报表", "B": "竣工财务决算说明书", "C": "竣工图", "D": "造价对比分析", "E": "施工组织设计"}, "answer": ["A", "B", "C", "D"], "analysis": "竣工决算内容包括：竣工财务决算报表+竣工财务决算说明书+竣工图+工程造价对比分析。施工组织设计属于施工准备阶段文件，不在竣工决算范围内。", "tags": ["竣工决算", "内容"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-033", "date": "2026-07-08", "chapter": "g07", "type": "multiple", "stem": "新增资产按性质可分为（ ）。", "options": {"A": "固定资产", "B": "流动资产", "C": "无形资产", "D": "其他资产", "E": "递延资产"}, "answer": ["A", "B", "C", "D"], "analysis": "新增资产分为四类：固定资产、流动资产、无形资产、其他资产。递延资产已并入其他资产或长期待摊费用的概念中，不单独列为一类。", "tags": ["竣工决算", "新增资产"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-039", "date": "2026-07-08", "chapter": "g07", "type": "multiple", "stem": "下列关于工程保修期限的说法，正确的有（ ）。", "options": {"A": "屋面防水工程最低保修期为5年", "B": "供热供冷系统为2个采暖期、供冷期", "C": "电气管线最低保修期为2年", "D": "主体结构工程最低保修期为50年", "E": "装修工程最低保修期为2年"}, "answer": ["A", "B", "C", "E"], "analysis": "屋面防水=5年(A)，供热供冷=2个采暖供冷期(B)，电气给排水装修=2年(C、E)。主体结构=设计使用年限，不是50年(D错误)。", "tags": ["竣工决算", "保修期限"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-040", "date": "2026-07-08", "chapter": "g07", "type": "multiple", "stem": "投资偏差分析的方法包括（ ）。", "options": {"A": "横道图法", "B": "表格法", "C": "曲线法", "D": "网络图法", "E": "排列图法"}, "answer": ["A", "B", "C"], "analysis": "投资偏差分析方法主要有三种：横道图法(直观但信息量有限)、表格法(常用、信息量大)和曲线法(可绘制投资曲线进行对比)。网络图法用于进度管理，排列图法用于质量管理。", "tags": ["投资偏差分析", "方法"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-041", "date": "2026-07-08", "chapter": "g07", "type": "multiple", "stem": "导致投资偏差的主要原因包括（ ）。", "options": {"A": "物价上涨", "B": "设计变更", "C": "施工原因", "D": "业主原因"}, "answer": ["A", "B", "C", "D"], "analysis": "投资偏差原因主要包括：物价上涨(材料人工涨价)、设计变更、施工原因(管理不善、技术问题等)、业主原因(要求变更等)以及客观原因(自然灾害等)。E为干扰项不符合多选格式要求。", "tags": ["投资偏差分析", "偏差原因"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-047", "date": "2026-07-08", "chapter": "g07", "type": "multiple", "stem": "成本管理的环节包括（ ）。", "options": {"A": "成本预测", "B": "成本计划", "C": "成本控制", "D": "成本核算", "E": "成本融资"}, "answer": ["A", "B", "C", "D"], "analysis": "成本管理六环节为预测、计划、控制、核算、分析、考核，选项中ABCD均正确。E成本融资不属于成本管理的常规环节。", "tags": ["成本管理", "环节"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-052", "date": "2026-07-08", "chapter": "g07", "type": "multiple", "stem": "在工程索赔中，以下哪些情况承包人可同时索赔工期和费用（ ）。", "options": {"A": "发包人未按约定提供施工图纸", "B": "发包人提供材料不合格导致返工", "C": "不可抗力事件", "D": "异常恶劣天气条件", "E": "发包人要求暂停施工"}, "answer": ["A", "B", "E"], "analysis": "发包人原因导致的问题可索赔工期+费用：A、B、E均为发包人责任。C不可抗力和D异常恶劣天气只能索赔工期，费用各自承担。", "tags": ["索赔", "可索赔情形"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-056", "date": "2026-07-08", "chapter": "g07", "type": "multiple", "stem": "关于费用偏差CV与费用绩效指数CPI，下列说法正确的有（ ）。", "options": {"A": "CV是绝对偏差指标", "B": "CPI是相对偏差指标", "C": "CV＞0时必然CPI＞1", "D": "CV=BCWP-ACWP", "E": "CPI=BCWP/BCWS"}, "answer": ["A", "B", "C", "D"], "analysis": "CV=BCWP-ACWP，是绝对偏差(A、D正确)；CPI=BCWP/ACWP(不是BCWS,E错误)，是相对偏差(B正确)；CV＞0即BCWP＞ACWP，则CPI=BCWP/ACWP＞1(C正确)。", "tags": ["挣值法", "偏差分析"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl-g07-060", "date": "2026-07-08", "chapter": "g07", "type": "multiple", "stem": "下列属于挣值法三个基本参数的有（ ）。", "options": {"A": "BCWS", "B": "BCWP", "C": "ACWP", "D": "CV", "E": "SV"}, "answer": ["A", "B", "C"], "analysis": "挣值法三个基本参数：BCWS(计划工作预算费用)、BCWP(已完工作预算费用/挣值)、ACWP(已完工作实际费用)。CV和SV是由这三个参数派生的偏差分析指标，不属于基本参数。", "tags": ["挣值法", "基本参数"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-005", "date": "2026-07-08", "chapter": "g07", "type": "multiple", "stem": "在挣值法中，三个基本参数包括？", "options": {"A": "BCWP（已完工作预算费用）", "B": "BCWS（计划工作预算费用）", "C": "ACWP（已完工作实际费用）", "D": "CV（费用偏差）"}, "answer": ["A", "B", "C"], "analysis": "挣值法的三个基本参数是BCWP（挣值）、BCWS（计划值）、ACWP（实际值）。CV是由这三个参数计算出来的派生指标（评价指标），不是基本参数。", "tags": ["挣值法", "基本参数"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-020", "date": "2026-07-08", "chapter": "g07", "type": "multiple", "stem": "关于挣值法偏差指标的说法，正确的有？", "options": {"A": "CV>0表示费用节约", "B": "SV>0表示进度提前", "C": "CPI>1表示费用超支", "D": "SPI<1表示进度延误"}, "answer": ["A", "B", "D"], "analysis": "C选项错误：CPI>1表示费用节约（预算>实际），CPI<1才表示费用超支。A、B、D均为正确表述。", "tags": ["挣值法", "偏差判断"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-026", "date": "2026-07-08", "chapter": "g07", "type": "multiple", "stem": "在挣值分析中，当CV<0且SV<0时，说明？", "options": {"A": "费用超支", "B": "费用节约", "C": "进度延误", "D": "进度提前"}, "answer": ["A", "C"], "analysis": "CV<0表示BCWP<ACWP，实际费用超过预算，即费用超支。SV<0表示BCWP<BCWS，实际进度落后于计划，即进度延误。", "tags": ["挣值法", "偏差判断"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-029", "date": "2026-07-08", "chapter": "g07", "type": "multiple", "stem": "工程变更价款确定的原则有？", "options": {"A": "已标价工程量清单中有适用于变更项目的，采用该项目的单价", "B": "已标价工程量清单中有类似于变更项目的，参照类似项目的单价调整", "C": "已标价工程量清单中无适用也无类似项目的，由承包人提出变更单价经发包人确认", "D": "任何情况下均由发包人单方确定变更价款"}, "answer": ["A", "B", "C"], "analysis": "A、B、C为正确的三条变更价款确定原则。D错误：发包人不能单方确定，需承包人提出并经发包人确认。", "tags": ["工程变更", "价款确定"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-035", "date": "2026-07-08", "chapter": "g07", "type": "multiple", "stem": "关于索赔程序时限，下列说法正确的有？", "options": {"A": "索赔事件发生后28天内提交索赔意向通知书", "B": "发出索赔意向通知后42天内提交详细索赔报告", "C": "发包人收到索赔报告后28天内答复", "D": "承包人逾期未提出索赔意向通知视为放弃索赔"}, "answer": ["A", "B", "C", "D"], "analysis": "索赔程序时限：28天意向通知→42天详细报告→28天发包人答复。逾期未提出意向通知视为放弃。四个选项均正确。", "tags": ["索赔", "程序时限"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-043", "date": "2026-07-08", "chapter": "g07", "type": "multiple", "stem": "下列情形中，承包人可以同时索赔工期和费用的有？", "options": {"A": "发包人原因造成工程延误", "B": "发包人提供材料和设备不符合要求", "C": "发包人未按约定提供设计图纸", "D": "异常恶劣的气候条件"}, "answer": ["A", "B", "C"], "analysis": "A、B、C均为发包人原因导致的延误，可同时索赔工期和费用。D选项异常恶劣天气只能索赔工期，不能索赔费用。", "tags": ["索赔", "索赔情形"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-044", "date": "2026-07-08", "chapter": "g07", "type": "multiple", "stem": "下列关于索赔分类的说法，正确的有？", "options": {"A": "工期索赔是指承包人向发包人要求延长工期的索赔", "B": "费用索赔是指承包人向发包人要求补偿额外费用支出的索赔", "C": "费用索赔包括人工费、材料费、机械使用费等", "D": "工期索赔和费用索赔不能同时提出"}, "answer": ["A", "B", "C"], "analysis": "A、B、C均为关于索赔分类的正确表述。D选项错误：工期索赔和费用索赔可以同时提出，也可以单独提出，取决于具体索赔事件的性质。", "tags": ["索赔", "索赔分类"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-046", "date": "2026-07-08", "chapter": "g07", "type": "multiple", "stem": "下列属于发包人原因可索赔工期和费用的有？", "options": {"A": "发包人未按合同约定提供施工场地", "B": "发包人提供的基准资料错误", "C": "发包人要求提前竣工", "D": "发包人指令暂停施工"}, "answer": ["A", "B", "D"], "analysis": "A、B、D均为发包人原因导致的延误和损失，可同时索赔工期和费用。C选项发包人要求提前竣工，一般只涉及赶工费用（费用索赔），不一定有工期索赔（实际工期反而缩短）。", "tags": ["索赔", "索赔情形"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-054", "date": "2026-07-08", "chapter": "g07", "type": "multiple", "stem": "进度款申请文件包括的内容有？", "options": {"A": "已完工程价款", "B": "变更工程价款和索赔价款", "C": "应扣回的预付款", "D": "应扣留的质量保证金"}, "answer": ["A", "B", "C", "D"], "analysis": "进度款申请内容包括：累计已完工程价款+变更工程价款+索赔价款+应支付的预付款+应扣回的预付款+应扣留的质量保证金。四个选项均为进度款申请的组成部分。", "tags": ["进度款", "申请内容"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-061", "date": "2026-07-08", "chapter": "g07", "type": "multiple", "stem": "竣工结算文件应包括的内容有？", "options": {"A": "竣工结算总价", "B": "已完工程量及价款计算书", "C": "变更和签证费用", "D": "索赔费用"}, "answer": ["A", "B", "C", "D"], "analysis": "竣工结算文件应包括竣工结算总价、已完工程量及计算过程、变更及签证费用、索赔费用、工期提前或延误的补偿费用等。四个选项均正确。", "tags": ["竣工结算", "结算内容"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-066", "date": "2026-07-08", "chapter": "g07", "type": "multiple", "stem": "下列属于无形资产的有？", "options": {"A": "土地使用权", "B": "专利权", "C": "非专利技术", "D": "商标权"}, "answer": ["A", "B", "C", "D"], "analysis": "无形资产包括：土地使用权、专利权、非专利技术、商标权、著作权等不具有实物形态的可辨认非货币性资产。四个选项均属于无形资产。", "tags": ["竣工决算", "无形资产"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-074", "date": "2026-07-08", "chapter": "g07", "type": "multiple", "stem": "下列关于建设工程各项目保修期的说法，正确的有？", "options": {"A": "基础设施工程和地基基础为设计使用年限", "B": "屋面防水工程最低为5年", "C": "供热供冷系统最低为2个采暖期/供冷期", "D": "装修工程最低为2年"}, "answer": ["A", "B", "C", "D"], "analysis": "四个选项均为各项目保修期的正确表述。基础设施/地基基础=设计使用年限；防水=5年；供热供冷=2个采暖期/供冷期；装修/电气/给排水=2年。", "tags": ["保修", "保修期"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "gl2-g07-077", "date": "2026-07-08", "chapter": "g07", "type": "multiple", "stem": "关于建设工程保修责任，下列说法正确的有？", "options": {"A": "保修期内施工方原因造成的缺陷，施工方免费维修", "B": "保修期内因使用不当造成的缺陷，由责任方承担费用", "C": "保修期自竣工验收合格之日起算", "D": "主体结构保修期最低为设计使用年限"}, "answer": ["A", "B", "C", "D"], "analysis": "四个选项均为关于保修责任的正确表述。保修期起算、保修责任划分、主体结构保修期均为教材重点考点。", "tags": ["保修", "保修责任"], "source": "管理教材精读笔记", "src": "原始"}, {"id": "ht_mgmt_1749", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "施工成本分析是在成本形成过程中，将施工项目的成本核算资料与（）进行比较，以了解成本变动情况。", "options": {"A": "类似施工项目的预算成本", "B": "本施工项目的实际成本", "C": "本施工项目的目标成本", "D": "本施工项目的预算成本", "E": "类似施工项目的实际成本"}, "answer": ["C", "D", "E"], "analysis": "成本分析是在成本核算的基础上，对成本的形成过程和影响成本升降的因素进行分析，以寻求进一步降低成本的途径，包括有利偏差的挖掘和不利偏差的纠正。成本分析贯穿于成本管理的全过程，主要利用项目的成本核算资料（成本信息），与目标成本、预算成本以及类似项目的实际成本等进行比较，了解成本的变动情况。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1750", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "关于赢得值法及相关评价指标的说法，正确的有（）。", "options": {"A": "赢得值法可定量判断进度、费用的执行效果", "B": "理想状态是已完工作实际费用、计划工作预算费用和已完工作预算费用三条曲线靠的很近并平稳上升", "C": "进度偏差为负值时，表示实际进度快于计划进度", "D": "费用（进度）偏差适用于在同一项目和不同项目比较中采用", "E": "采用赢得值法可以克服进度、费用分开控制的缺点"}, "answer": ["A", "B", "E"], "analysis": "选项C，当进度偏差为负值，说明进度滞后，实际进度慢于计划进度；选项D，费用和进度偏差只能使用与同一个项目的比较。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1751", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "某工程主要工作是混凝土浇筑，中标的综合单价是400 元/m2，计划工程量是8000m3。施工过程中因原材料价格提高使实际单位为500 元/m3，实际完成并经监理工程师确认的工程师是9000m3。若采用赢得值法进行综合分析，正确的结论有（）。", "options": {"A": "已完工作预算费用为360 万元", "B": "费用偏差为90 万元，费用节省", "C": "已完工作实际费用为450 万元", "D": "进度偏差为40 万元，进度拖延", "E": "计划工作预算费用为320 万元"}, "answer": ["A", "C", "E"], "analysis": "已完工作实际费用=500×9000=450万元，已完工作预算费用=400×9000=360万元，计划工作预算费用=400×8000=320万元。费用偏差=已完工作预算费用-已完工作实际费用=-90万元，费用超支;进度偏差=已完工作预算费用-计划工作预算费用=40万元，进度超前。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1753", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "专项成本分析中，工期成本分析一般采取的方法有（）。", "options": {"A": "构成比率法", "B": "成本盈亏异常分析", "C": "比较法", "D": "因素分析法", "E": "差额计算法"}, "answer": ["C", "D"], "analysis": "工期成本分析一般采用比较法，即将计划工期成本与实际工期成本进行比较，然后应用“因素分析法”分析各种因素的变动对工期成本差异的影响程度。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1754", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "下列关于分部分项工程施工成本分析的说法，正确的有（）。", "options": {"A": "分部分项工程成本分析是施工项目成本分析的基础", "B": "成本分析的对象为已完成分部分项工程", "C": "须对施工项目中的所有分部分项工程进行成本分析", "D": "要进行估算成本与目标成本的比较", "E": "要进行预算成本、目标成本和实际成本的\"三算\"对比，分别计算实际偏差和目标偏差"}, "answer": ["A", "B", "E"], "analysis": "分部分项工程成本分析是施工项目成本分析的基础。分部分项工程成本分析的对象为已完成分部分项工程。分析的方法是：进行预算成本、目标成本和实际成本的“三算”对比。 分部分项工程成本分析的资料来源是：预算成本来自投标报价成本，目标成本来自施工预算。 由于施工项目包括很多分部分项工程，无法也没有必要对每一个分部分项工程都进行成本分析。但是，对于那些主要分部分项工程必须进行成本分析，而且要做到从开工到竣工进行系统的成本分析。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1755", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "下列指标中，属于对项目管理机构成本考核的有（ ）。", "options": {"A": "项目成本降低额", "B": "项目成本降低率", "C": "施工生产总成本", "D": "劳动力不均衡系数", "E": "生产能力利用率"}, "answer": ["A", "B"], "analysis": "公司应以项目成本降低额、项目成本降低率作为项目管理机构成本考核的主要指标。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1756", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "在国际工程承包中，根据FIDIC《施工合同条件》（1999年版），因工程量变更可以调整合同规定非率或价格的条件包括（）。", "options": {"A": "实际工程量比工程量表中规定的工程量变动大于10%", "B": "该工程量的变更与相对应费率的乘积超过了中标金额的0.01%", "C": "由于工程量的变动直接造成单位工程量费用的变动超过1%", "D": "原工程量全部删减，其替代工程的费用对合同总价无影响", "E": "该部分工程量是合同中规定的“固定费率项目”"}, "answer": ["A", "B", "C"], "analysis": "2.价格调整 (1)工程量变更引起的价格调整。因工程量变更可以调整合同规定费率或价格的条件包括 1)该部分工程实际测量的工程量比工程量表或其他报表中规定的工程量的变动大于 10% 2)该部分工程工程量的变更与相对应费率的乘积超过了中标金额的0.01% 3)由于工程量的变更直接造成该部分工程每单位工程量费用的变动超过1%; 4)该部分工程不是合同中规定的“固定费率项目”。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1757", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "根据《建设工程工程量清单计价规范》，关于计日工的说法正确的有（）", "options": {"A": "发包人通知承包人以计日工方式实施的零星工作，承包人应予执行", "B": "采用计日工计价的任何一项工作，承包人都应每天提交报表和有关凭证报送监理人审查", "C": "计日工由承包人汇总后，列入最近一期进度付款申请单，由监理人审查并经发包人批准后列入进度付款", "D": "计日工是承包人完成合同范围内的零星项目按合同约定的单价计价的一种方式", "E": "已标价工程量清单或预算书中无相应的计日工单价的，按照合理的成本与利润构成的原则，由合同当事人确定计日工的单价"}, "answer": ["A", "B", "C", "E"], "analysis": "《建设工程工程量清单计价规范》(GB50500)规定，计日工是指在施工过程中，承包人完成发包人提出的工程合同范围以外的零星项目或工作，按合同中约定的单价计价的一种方式。发包人通知承包人以计日工方式实施的零星工作，承包人应予执行。采用计日工计价的任何一项变更工作，承包人应在该项变更的实施过程中，按合同约定提交相关报表和有关凭证送发包人复核。发包人在收到承包人提交现场签证报告后的2d内予以确认并将其中一份返还给承包人，作为计日工计价和支付的依据。每个支付期末，承包人应按规定向发包人提交本期间所有计日工记录的签证汇总表，以说明本期间自己认为有权得到的计日工金额，调整合同价款，列入进度款支付。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1758", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "工程量必须按照相关工程现行国家计量规范规定的工程量计算规则计算。以下说法正确的是()。", "options": {"A": "因承包人原因造成的超出合同工程范围施工或返工的工程量，发包人不予计量", "B": "规定单价合同、总价合同、成本加酬金合同适用一样的计量方法", "C": "成本加酬金合同按照单价合同的计量规定进行计量", "D": "单价合同若发现招标工程量清单中出现缺项、工程量偏差，或因工程变更引起工程量的增减，应按承包人在履行合同义务中完成的工程量计算", "E": "总价合同除按照工程变更规定引起的工程量增减外，总价合同各项目的工程量是承包人用于结算的最终工程量"}, "answer": ["A", "C", "D", "E"], "analysis": "单价合同和总价合同规定不同的计量方法。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1759", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "在工程合同价款纠纷案件处理中，需做工程造价司法鉴定的，应委托具有相应资质的工程造价咨询人进行，以下说法正确的是()。", "options": {"A": "工程造价咨询人应在收到工程造价司法鉴定资料后10天内，根据自身专业能力和证据资料，判断能否胜任该项委托，如不能，应辞去该项委托", "B": "工程造价咨询人在鉴定过程中要求鉴定项目当事人对缺陷资料进行补充的，应征得鉴定项目委托人同意，或者协调鉴定项目各方当事人共同签认", "C": "工程造价咨询人在鉴定项目合同有效的情况下应根据合同约定进行鉴定，不得任意改变双方合法的合意", "D": "工程造价咨询人出具正式鉴定意见书之前，可报请鉴定项目委托人向鉴定项目各方当事人发出鉴定意见书征求意见稿，并指明应书面答复的期限及其不答复的相应法律责任", "E": "经鉴定项目委托人同意等待鉴定项目当事人提交、补充证据，质证所用的时间计入鉴定期限"}, "answer": ["A", "B", "C", "D"], "analysis": "经鉴定项目委托人同意等待鉴定项目当事人提交、补充证据，质证所用的时间不应计入鉴定期限。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1760", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "关于建设工程竣工结算的办理，下列说法中正确的有（ ）。", "options": {"A": "竣工结算文件经发承包人双方签字确认的，应当作为工程结算的依据", "B": "竣工结算文件由发包人组织编制，承包人组织核对", "C": "工程造价咨询机构审核结论与承包人竣工结算文件不一致时，以造价咨询机构审核意见为准", "D": "合同双方对复核后的竣工结算有异议时，可以就无异议部分的工程办理不完全竣工结算", "E": "有异议部分由发承包双方协商解决，协商不成的, 按照合同约定的争议解决方式处理"}, "answer": ["A", "D", "E"], "analysis": "发包人委托工程造价咨询机构核对竣工结算的，工程造价咨询机构应在规定期限内核对完毕，核对结论与承包人竣工结算文件不一致的，应提交给承包人复核，承包人应在规定期限内将同意核对结论或不同意见的说明提交工程造价咨询机构。工程造价咨询机构收到承包人提出的异议后，应再次复核，复核无异议的，发承包双方应在规定期限内在竣工结算文件上签字确认，竣工结算办理完毕；复核后仍有异议的，对于无异议部分办理不完全竣工结算；有异议部分由发承包双方协商解决，协商不成的, 按照合同约定的争议解决方式处理。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1761", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "承包人应在每个计量周期到期后，向发包人提交已完成工程进度款支付申请，支付申请包括的内容有()。", "options": {"A": "累计已完成的合同价款", "B": "本期合计完成的合同价款", "C": "本期合计应扣减的金额", "D": "累计已调整的合同金额", "E": "预计下期将完成的合同价款"}, "answer": ["A", "B", "C"], "analysis": "本题考查的是预付款及期中支付。承包人应在每个计量周期到期后向发包人提交已完工程进度款支付申请一式四份，详细说明此周期认为有权得到的款额，包括分包人已完工程的价款。支付申请的内容包括：(1)累计已完成的合同价款；(2)累计已实际支付的合同价款；(3)本周期合计完成的合同价款；(4)本周期合计应扣减的金额；(5)本周期实际应支付的合同价款。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1762", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "下列属于承包人提交的进度款支付申请内容的有()。", "options": {"A": "累计已完成的合同价款", "B": "累计已实际支付的合同价款", "C": "本周期应支付的安全文明施工费", "D": "实际应支付的竣工结算款", "E": "本周期应扣回的预付款"}, "answer": ["A", "B", "C", "E"], "analysis": "本题考查的是预付款及期中支付,原文“支付申请的内容包括：(1)累计已完成的合同价款。(2)累计已实际支付的合同价款。(3)本周期合计完成的合同价款：本周期已完成单价项目的金额；本周期应支付的总价项目的金额；本周期已完成的计日工价款；本周期应支付的安全文明施工费；本周期应增加的金额(4)本周期合计应扣减的金额：本周期应扣回的预付款；本周期应扣减的金额。(5)本周期实际应支付的合同价款。”", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1763", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "下列属于工程造价咨询人员出具的工程造价鉴定书内容的有()。", "options": {"A": "委托鉴定的内容", "B": "鉴定结论", "C": "鉴定过程说明", "D": "鉴定的依据", "E": "鉴定的成本"}, "answer": ["A", "B", "C", "D"], "analysis": "本题考查的是合同价款纠纷的处理，“鉴定意见书应包括鉴定意见书封面、签署页、目录、鉴定人员声明、鉴定意见书正文、有关附件等。其中，鉴定意见书正文应包括如下内容：1.项目名称；2文号；3.基本情况；4.鉴定依据；5.鉴定过程及分析；6.鉴定结论意见；7.特殊说明；8.鉴定机构出具鉴定意见书的签章（字）；9.附件。”", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1764", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "建设工程合同价款纠纷的解决途径主要有四种，即和解、调解、仲裁和诉讼。以下有关说法正确的是()。", "options": {"A": "合同价款争议发生后，发承包双方任何时候都可以进行协商。协商达成一致的，双方应签订书面和解协议，和解协议对发承包双方均有约束力", "B": "合同价款争议发生后，发承包双方可就工程计价依据的争议以书面形式提请工程造价管理机构对争议以书面文件进行解释或认定", "C": "发承包双方或一方在收到工程造价管理机构书面解释或认定后，仍可按照合同约定的争议解决方式提请仲裁或诉讼", "D": "合同履行期间，发承包双方可以协议调换或终止任何调解人，但发包人或承包人都不能单独采取行动。除非双方另有协议，在最终结清支付证书生效后，调解人的任期即终止", "E": "仲裁应在竣工之前进行，但发包人、承包人、调解人各自的义务不得因在工程实施期间进行仲裁而有所改变"}, "answer": ["A", "B", "C", "D"], "analysis": "如果发承包双方的协商和解或调解均未达成一致意见，其中的一方已就此争议事项根据合同约定的仲裁协议申请仲裁，应同时通知另一方。仲裁可在竣工之前或之后进行，但发包人、承包人、调解人各自的义务不得因在工程实施期间进行仲裁而有所改变。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1765", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "工程造价咨询人在进行工程造价鉴定时，应自行收集而非由委托人提供的鉴定资料有（）。", "options": {"A": "适用于鉴定项目的规章、规范性文件和定额", "B": "鉴定项目同期同类型工程的技术经济指标", "C": "鉴定项目施工过程中的施工组织、质量、工期等工程资料", "D": "鉴定项目的施工合同及补充协议", "E": "鉴定项目所涉及实物标的的现场勘验资料"}, "answer": ["A", "B"], "analysis": "工程造价咨询人进行工程造价鉴定工作，应自行收集以下（但不限于）鉴定资料：⑴适用于鉴定项目的法律、法规、规章、规范性文件以及规范、标准、定额。⑵鉴定项目同时期同类型工程的技术经济指标及其各类要素价格等。⑶工程造价咨询人收集鉴定项目的鉴定依据时，应向鉴定项目委托人提出具体书面要求，其内容包括：①与鉴定项目相关的合同、协议及其附件；②相应的施工图纸等技术经济文件；③施工过程中施工组织、质量、工期和造价等工程资料；④存在争议的事实及各方当事人的理由；⑤其他有关资料。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1766", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "我国现行合同条件下，下列关于工程预付款的叙述中，正确的有()。", "options": {"A": "工程预付款主要用于采购建材、招募工人和租赁设备", "B": "建筑工程的预付款额度一般不超过当年建筑工程量的30%", "C": "安装工程的预付款额度一般不超过当年安装工程量的15%", "D": "承发包双方应当在专用条款内约定发包人向承包人预付工程款的时间和额度", "E": "工程预付款的预付时间应不迟于约定的开工日期前7天"}, "answer": ["D", "E"], "analysis": "本题考查的是预付款及期中支付，“工程预付款是由发包人按照合同约定，在正式开工前由发包人预先支付给承包人，用于购买工程施工所需的材料和组织施工机械和人员进场的价款。包工包料工程的预付款的支付比例不得低于签约合同价（扣除暂列金额）的10%，不宜高于签约合同价（扣除暂列金额）的30%。”", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1767", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "采用双方约定争议调解人方式解决合同价款纠纷，其程序正确的有()。", "options": {"A": "发承包双方可以在合同签订后共同约定争议调解人", "B": "发生争议，应由承包人将该争议以书面形式提交调解人，并将副本抄送发包人", "C": "调解人收到调解委托后28天内提出调解书", "D": "发承包双方接受调解书的，经双方签字后作为合同的补充文件", "E": "若发承包任一方对调解有异议，应在收到调解书14天内向另一方发出异议通知"}, "answer": ["A", "C", "D"], "analysis": "本题考查的是合同价款纠纷的处理，“发承包双方应在合同中约定或在合同签订后共同约定争议调解人，负责双方在合同履行过程中发生争议的调解。如果发承包双方发生了争议，任何一方可以将该争议以书面形式提交调解人，并将副本抄送另一方，委托调解人调解。调解人应在收到调解委托后28天内，或由调解人建议并经发承包双方认可的其他期限内，提出调解书，发承包双方接受调解书的，经双方签字后作为合同的补充文件，对发承包双方具有约束力，双方都应立即遵照执行。如果发承包任一方对调解人的调解书有异议，应在收到调解书后28天内向另一方发出异议通知，并说明争议的事宜和理由。”", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1768", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "发包人对工程质量有异议，竣工结算仍应按合同约定办理的情形有（）。", "options": {"A": "工程已竣工验收的", "B": "工程已竣工未验收，但实际投入使用的", "C": "工程已竣工未验收，且未实际投入使用的", "D": "工程停建，对无质量争议的部分", "E": "工程停建，对有质量争议的部分"}, "answer": ["A", "B", "D"], "analysis": "(2)已竣工未验收且未实际投人使用的工程以及停工、停建工程的质量争议，双方应就有争议的部分委托有资质的检测鉴定机构进行检测，根据检测结果确定解决方案，或按工程质量监督机构的处理决定执行后办理竣工结算，无争议部分的竣工结算按合同约定办理。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1769", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "承包商采购的用于永久工程的材料和设备，合同通用条款规定，期中支付证书中应包括一笔用于预支已运至现场用于永久工程的材料和设备款额，下列有关说法正确的是()。", "options": {"A": "装运后付款的材料和设备，要求此类材料和设备已经运至工程所在国，并正在运往现场的途中", "B": "装运后付款的材料和设备，承包商应提交保函金额与应付的预支总额相等的银行保函", "C": "装运后付款的材料和设备，承包商提交的保函有效期持续到此类材料和设备已经运至现场并妥善存放，而且承包商已经采取了防护措施为止", "D": "运至现场后付款的材料和设备，要求此类材料和设备已经运至现场，但可先不安排存放", "E": "工程师确认用于永久工程的材料和设备符合预支条件后，应当根据审查承包商提交的相关文件确定此类材料和设备的实际费用，作为期中支付证书中应增加的款额"}, "answer": ["A", "B", "C"], "analysis": "运至现场后付款的材料和设备，要求此类材料和设备已经运至现场并妥善存放，而且承包商已经采取了防护措施。工程师确认用于永久工程的材料和设备符合预支条件后，应当根据审查承包商提交的相关文件确定此类材料和设备的实际费用（包括运至现场的费用），期中支付证书中应增加的款额为该费用的80％。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1770", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "根据《建设项目工程总承包合同示范文本》(GF-2011-0216)，以下情形中，属于应对合同价款进行调整的有()。", "options": {"A": "合同变更", "B": "法律法规变化影响的合同价格增减", "C": "工程造价管理部门公布的价格调整造成工程成本增减", "D": "一周内停水、停电等造成累计停工超过8小时", "E": "发包人批准的变更估算的增减"}, "answer": ["B", "C", "E"], "analysis": "本题考查的是工程总承包合同价款的结算。合同价格调整的情形包括：(1)合同签订后，因法律、行政法规、国家政策和需遵守的行业规定，影响合同价格增减的；(2)合同执行过程中，工程造价管理部门公布的价格调整，涉及承包人投入成本增减的；(3)一周内非承包人原因的停水、停电、停气、道路中断等，造成工程现场停工累计超过8小时的（承包人须提交报告并提供可证实的证明和估算）；(4)发包人批准的变更估算的增减；(5)本合同约定的其他增减的款项调整。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1771", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "国际工程合同价款结算中，关于预付款下列说法中正确的有()。", "options": {"A": "首次预付款的支付时间以收到预付款保函和颁发中标函之日两者中较早者为准", "B": "预付款应在支付证书中按百分比扣减的方式偿还", "C": "当期中支付证书中累计总额超过中标合同价（含暂定金额）的10％开始扣减", "D": "在预付款完全偿还之前承包商应保证预付款保函一直有效", "E": "如在预付款保函截止日期前28天预付款还未完全偿还，则承包商应相应延长保函期限"}, "answer": ["B", "D", "E"], "analysis": "预付款应在支付证书中按百分比扣减的方式偿还。如果在投标函附录中没有注明预付款扣减的百分比，则按照下面的方法扣减：1）当期中支付证书的累计总额（不包括预付款及保留金的扣减与偿还）超过中标合同价（减去暂定金额）的10％时开始扣减；2）按照预付款的货币的种类及其比例，分期从每份支付证书中的数额（不包括预付款及保留金的扣减与偿还）中扣除25％，直至还清全部预付款。在预付款完全偿还之前，承包商应保证预付款保函一直有效，但该预付款保函的总额应随承包商在期中支付证书中所偿还的数额逐步冲抵而减少。如果在该保函截止日期前28天预付款还未完全偿还，则承包商应该相应地延长预付款保函的期限，直到预付款完全偿还。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1772", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "下列关于共同费用分摊计入新增固定资产价值的表述，正确的是（）。", "options": {"A": "建设单位管理费按建筑、安装工程造价总额作比例分摊", "B": "土地征用费按建筑工程造价比例分摊", "C": "建筑工程设计费按建筑工程造价比例分摊", "D": "生产工艺流程系统设计费按需安装设备价值总额作比例分摊", "E": "地质勘察费按建筑工程造价比例分摊"}, "answer": ["B", "C", "E"], "analysis": "本题考查的是新增资产价值的确定。新增固定资产的其他费用，如果是属于整个建设项目或两个以上单项工程的，在计算新增固定资产价值时，应在各单项工程中按比例分摊。一般情况下，建设单位管理费按建筑工程、安装工程、需安装设备价值总额作比例分摊，而土地征用费、地质勘察和建筑工程设计费等费用则按建筑工程造价比例分摊，生产工艺流程系统设计费按安装工程造价比例分摊。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1773", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "建设项目竣工财务决算表中，属于“资金来源”的有（）。", "options": {"A": "专项建设基金拨款", "B": "项目资本公积金", "C": "有价证券", "D": "待冲基建支出", "E": "未交税金"}, "answer": ["A", "B", "D", "E"], "analysis": "竣工财务决算表是竣工财务决算报表的一种，大、中型建设项目竣工财务决算表是用来反映建设项目的全部资金来源和资金占用情况，是考核和分析投资效果的依据。该表反映竣工的大中型建设项目从开工到竣工为止全部资金来源和资金运用的情况。资金来源包括基建拨款(预算拨款几、基建基金拨款和专项建设基金拨款等)、项目资本金、项目资本公积金、基建借款、上级拨入投资借款、企业债券资金、待冲基建支出、应付款和未交款(未交税金和其他未交款)以及上级拨入资金和企业留成收入等。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1774", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "根据国家现行有关竣工结算的规定，建设项目财务决算报表包括()。", "options": {"A": "建设项目竣工财务决算审批表", "B": "建设项目概况表", "C": "基本建设项目竣工财务决算表", "D": "建设项目交付使用资产明细表", "E": "建设项目交付使用资产总表"}, "answer": ["B", "C", "D", "E"], "analysis": "建设项目竣工决算报表包括：基本建设项目概况表；基本建设项目竣工财务决算表；基本建设项目交付使用资产总表；基本建设项目交付使用资产明细表等。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1775", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "按照财政部、国家发展改革委和住房城乡建设部的有关文件规定，竣工决算是由()组成。", "options": {"A": "竣工财务决算说明书", "B": "竣工财务决算报表", "C": "工程竣工图", "D": "工程竣工造价对比分析", "E": "工程结算文件"}, "answer": ["A", "B", "C", "D"], "analysis": "竣工决算是由竣工财务决算说明书、竣工财务决算报表、工程竣工图和工程竣工造价对比分析四部分组成。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1776", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "下列资金项目中，属于“基本建设项目竣工财务决算表”中资金来源的有()。", "options": {"A": "预算拨款", "B": "项目资本金", "C": "应收生产单位投资借款", "D": "基建借款", "E": "待核销基建支出"}, "answer": ["A", "B", "D"], "analysis": "1)资金来源包括基建拨款、部门自筹资金非负债性资金）、项目资本金、项目资本公积金、基建借款、待冲基建支出、应付款和未交款等，", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1777", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "土地使用权的取得方式影响竣工结算新增资产的核定，下列土地使用权的作价应作为无形资产核算的有()。", "options": {"A": "通过支付土地出让金取得的土地使用权", "B": "通过行政划拨取得的土地使用权", "C": "通过划拨转让取得的出让土地使用权", "D": "已补交土地出让价款，作价入股的土地使用权", "E": "租借房屋的土地使用权"}, "answer": ["A", "D"], "analysis": "本题考查的是新增资产价值的确定。当建设单位获得土地使用权是通过行政划拨的，这时土地使用权就不能作为无形资产核算；在将土地使用权有偿转让、出租、抵押、作价人股和投资，按规定补交土地出让价款时，才作为无形资产核算。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1778", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "按照财办建[2008]91号文的规定，竣工决算的编制依据有()。", "options": {"A": "经批准的设计文件及设计交底、图纸会审资料", "B": "项目计划任务书及立项批复文件", "C": "项目总概算书和单项工程概算书文件", "D": "项目竣工结算文件", "E": "双方签订的建筑安装工程承包合同终结凭证"}, "answer": ["A", "B", "C", "D"], "analysis": "建设项目竣工决算的编制依据建设项目竣工决算应依据下列资料编制：(1)《基本建设财务规则》（财政部第 81 号令）等法律、法规和规范性文件;288 建设工程计价(2) 项目计划任务书及立项批复文件；(3) 项目总概算书和单项工程概算书文件；(4) 经批准的设计文件及设计交底、图纸会审资料；(5) 招标文件和最高投标限价；(6) 工程合同文件;(7) 项目竣工结算文件；(8) 工程签证、工程索赔等合同价款调整文件；(9) 设备、材料调价文件记录；(10) 会计核算及财务管理资料；(11) 其他有关项目管理的文件。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1779", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "(2013年)关于合同价款纠纷的处理，下列说法中正确的有()。", "options": {"A": "借用有资质的建筑施工企业名义与他人签订建设工程施工合同的行为无效", "B": "当事人对垫资利息有约定且约定的利息高于同期同类贷款利率的应予支持", "C": "当事人对建筑工程的计价标准或计价方法有约定的按约定结算工程价款", "D": "对于阴阳合同，其价款结算应以备案的中标合同作为依据", "E": "建设工程未交付，工程价款也未结算的，则工程欠款的计息日为当事人的起诉之日"}, "answer": ["A", "C", "D", "E"], "analysis": "当事人对垫资和垫资利息有约定，承包人请求按照约定返还垫资及其利息的，应予支持，但是约定的利息计算标准高于中国人民银行发布的同期同类贷款利率的部分除外。承包人非法转包、违法分包建设工程或者没有资质的实际施工人借用有资质的建筑施工企业名义与他人签订建设工程施工合同的行为无效。当事人对建设工程的计价标准或者计价方法有约定的，按照约定结算工程价款。( 1 )阴阳合同的结算依据。当事人就同一建设工程另行订立的建设工程施工合同与经过备案的中标合同实质性内容不一致的，应当以备案的中标合同作为结算工程价款的根据。③建设工程未交付，工程价款也未结算的，为当事人起诉之日。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1780", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "(2016年)工程造价咨询人开展工程造价司法鉴定工作时，正确的做法有()。", "options": {"A": "应按仲裁.诉讼程序和要求进行鉴定", "B": "应依法出庭接受鉴定项目方当事人对鉴定意向书的质询", "C": "应自行收集适用于鉴定项目的工程造价信息", "D": "应自行对现场进行勘验", "E": "是鉴定项目一方当事人、代理人的，应自行回避"}, "answer": ["A", "B", "C", "E"], "analysis": "现场勘验:根据项目鉴定工作需要，鉴定机构可组织当事人对被鉴定的标的物进行现场勘验,所以D错误。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1781", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "(2014年)下列关于预付款担保的说法中，正确的是（）", "options": {"A": "预付款担保应在施工合同签订后预付款支付前提供", "B": "预付款担保必须采用银行保函的形式", "C": "承包人中途毁约，中止工程，发包人有权从预付款担保金额中获得预付款补偿", "D": "发包人应在预付款扣完后将预付款保函退还承包人", "E": "在预付款全部扣回之前，预付款保函应始终保持有效，且担保金额应保持不变"}, "answer": ["A", "C", "D"], "analysis": "1.预付款担保的概念及作用，预付款担保是指承包人与发包人签订合同后领取预付款前，承包人正确、合理使用发包人支付的预付款而提供的担保。其主要作用是保证承包人能够按合同规定的目的使用并及时偿还发包人已支付的全部预付金额。如果承包人中途毁约，中止工程，使发包人不能再规定期限内从应付工程款中扣除全部预付款，则发包人有权该项担保金额中获得补偿。2.预付款担保的形式。预付款担保的主要是为银行保函，预付款担保的担保金额通常与发包人的预付款是等值的。预付款一般逐月从工程预付款中扣除，预付款担保的担保金额也相应逐月减少。承包人在施工期间。应当定期从发包人处取得同意此保函减值的文件，并送交银行确认。承包人还清全部预付款后，发包人应退还预付款担保，承包人将其退还银行注销，解除担保责任。预付款担保也可以采用发承包双方约定的其他形式，如由担保公司提供担保，或采取抵押等担保形式。承包人的预付款全部扣回之前一直保持有效。发包人应在预付款扣完后的14天内将预付款保函退还给承包人。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1782", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "(2011年)关于无形资产价值确定的说法中，正确的有()。", "options": {"A": "无形资产计价入账后，应在其有效使用期内分期摊销", "B": "专利权转让价格必须按成本估价", "C": "自创专利权的价值为开发过程中的实际支出", "D": "自创的非专利技术一般作为无形资产入账", "E": "通过行政划拨的土地，其土地使用权作为无形资产核算"}, "answer": ["A", "C"], "analysis": "无形资产价值确定原则：企业自创并依法申请取得的，按开发过程中的实际支出计价；无形资产计价入账后，应在其有效使用期内分期摊销等。专利权转让价格不按成本估价，而是按照其所能带来的超额收益计价；如果专有技术是自创的，一般不作为无形资产入账，自创过程中发生得费用，按当期费用处理；当建设单位获得土地所有权是通过行政划拨的，这时土地使用权就不能作为无形资产核算。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1807", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "项目成本核算的方法中，表格核算法的特点包括（ ）。", "options": {"A": "易于操作", "B": "核算范围较大", "C": "适时性较好", "D": "逻辑性强", "E": "覆盖范围较窄"}, "answer": ["A", "C", "E"], "analysis": "项目成本核算的方法中的表格核算法的特点：其优点是比较简捷明了，直观易懂，易于操作，适时性较好。缺点是覆盖范围较窄，核算债权债务等比较困难；且较难实现科学严密的审核制度，有可能造成数据失实，精度较差。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1808", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "根据《中华人民共和国标准施工招标文件》的规定，合同条款规定的承包人可以合理补偿工期、费用和利润的事件包括（ ）。", "options": {"A": "施工中发现文物古迹", "B": "工程师对已经覆盖的隐蔽工程要求重新检查且检查结果符合要求", "C": "迟延提供施工场地", "D": "施工中遇到不利的物质条件", "E": "迟延提供图纸"}, "answer": ["B", "C", "E"], "analysis": "", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1809", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "在《标准施工招标文件》中，合同条款规定的可以合理补偿承包人索赔费用的事件有（ ）", "options": {"A": "发包人要求向承包人提前交付材料和设备", "B": "发包人要求承包人提前竣工", "C": "施工过程发现文物、古迹", "D": "异常恶劣的气候条件", "E": "法律变化引起的价格调整"}, "answer": ["A", "B", "C", "E"], "analysis": "引起承包人索赔的事件以及可能得到的合理补偿内容如表7 -3 所示", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1810", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "下列事件的发生，按照《标准施工招标文件》中相关合同条件，只获得费用补偿的有（ ）。", "options": {"A": "基准日后法律的变化", "B": "工程师对已覆盖的隐蔽工程要求重新检查且检查结果不合格", "C": "工程移交后因发包人原因出现的新的缺陷或损坏的修复", "D": "发包人提供工程设备不合格", "E": "工程移交后因发包人原因出现的缺陷修复后的试验和试运行"}, "answer": ["A", "E"], "analysis": "此题考查索赔的相关知识点", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1811", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "工程预付款额度一般是根据（ ）等因素经测算来确定的。", "options": {"A": "施工规模", "B": "施工工期", "C": "建安工作量", "D": "主要材料和构件费用", "E": "材料储备周期"}, "answer": ["B", "C", "D", "E"], "analysis": "对于工程预付款额度，各地区、各部门的规定不完全相同，主要是保证施工所需材 料和构件的正常储备。工程预付款额度一般是根据施工工期、建筑安装工作量、主要材料和构件费用占建筑安装工程费的比例以及材料储备周期等因素经测算来确定。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1812", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "建设工程进度款支付申请中周期合计完成的合同价款包括（ ）。", "options": {"A": "本周期已完成单价项目的金额", "B": "本周期应支付的总价项目的金额", "C": "本周期应扣回的预付款", "D": "本周期已完成的计日工价款", "E": "本周期应增加的金额"}, "answer": ["A", "B", "D", "E"], "analysis": "进度支付申请的内容包括： 1)累计已完成的合同价款； 2)累计已实际支付的合同价款； 3)本周期合计完成的合同价款，其中包括：①本周期已完成单价项目的金额；②本周期应支付的总价项目的金额；③本周期已完成的计日工价款；④本周期应支付的安全文明施工费；⑤本周期应增加的金额； 4)本周期合计应扣减的金额，其中包括：①本周期应扣回的预付款；②本周期应扣减的金额。 5)本周期实际应支付的合同价款。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1813", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "材料储备定额天数由当地材料供应的（ ）等因素决定。", "options": {"A": "在途天数", "B": "加工天数", "C": "整理天数", "D": "保险天数", "E": "市场行情"}, "answer": ["A", "B", "C", "D"], "analysis": "材料储备定额天数由当地材料供应的在途天数、加工天数、整理天数、供应间隔天数、保险天数等因素决定。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1814", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "百分比法确定工程预付款额度，发包人根据（ ）等因素，招标时在合同条件中约定工程预付款的百分比。", "options": {"A": "工程的特点", "B": "工期长短", "C": "市场行情", "D": "供求规律", "E": "施工规模"}, "answer": ["A", "B", "C", "D"], "analysis": "发包人根据工程的特点、工期长短、市场行情、供求规律等因素，招标时在合同条件中约定工程预付款的百分比。根据《建设工程价款结算暂行办法》 的规定，预付款的比例原则上不低于合同金额的10%，不高于合同金额的30%。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1815", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "专利研制成本中的直接成本是指研制过程中直接投入发生的费用，主要包括（ ）。", "options": {"A": "资料费", "B": "咨询鉴定费", "C": "非专用设备折旧费", "D": "工资费用", "E": "管理费"}, "answer": ["A", "B", "D"], "analysis": "专利权分为自创和外购两类。自创专利权的价值为开发过程中的实际支出，主要包括专利的研制成本和交易成本。研制成本包括直接成本和间接成本：直接成本是指研制过程中直接投入发生的费用(主要包括材料费用、工资费用、专用设备费、资料费、咨询鉴定费、协作费、培训费和差旅费等)。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1816", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "在无形资产的计价原则中，企业接受捐赠的无形资产，按照（ ）作价。", "options": {"A": "开发过程中的实际支出", "B": "发票账单所载金额", "C": "实际支付的价款", "D": "合同协议约定的金额", "E": "同类无形资产市场价"}, "answer": ["B", "E"], "analysis": "无形资产的计价原则： (1)投资者按无形资产作为资本金或者合作条件投入时，按评估确认或合同协议约定的金额计价。 (2)购入的无形资产，按照实际支付的价款计价。 (3)企业自创并依法申请取得的，按开发过程中的实际支出计价。 (4)企业接受捐赠的无形资产，按照发票账单所载金额或者同类无形资产市场价作价。 (5)无形资产计价入账后，应在其有效使用期内分期摊销，即企业为无形资产支出的费用应在无形资产的有效期内得到及时补偿。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1817", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "建设单位与使用单位在办理交付资产的验收交接手续时，通过基本建设项目交付使用资产总表反映了交付使用资产的全部价值，包括（ ）的价值。", "options": {"A": "其他资产", "B": "流动资产", "C": "无形资产", "D": "固定资产", "E": "有形资产"}, "answer": ["A", "B", "C", "D"], "analysis": "基本建设项目交付使用资产总表反映建设项目建成后新增固定资产、流动资产、无形资产和其他资产价值的情况和价值，作为财产交接、检查投资计划完成情况和分析投资效果的依据。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "ht_mgmt_1818", "date": "2026-07-10", "chapter": "g07", "type": "multiple", "stem": "下列关于竣工财务决算说明书的表述，正确的是（ ）。", "options": {"A": "竣工财务决算说明书主要反映竣工工程建设成果和经验", "B": "竣工财务决算说明书是对竣工决算报表进行分析和补充说明的文件", "C": "竣工财务决算说明书是全面考核分析工程投资与造价的书面总结", "D": "竣工财务决算说明书综合反映了大中型项目的基本概况", "E": "竣工财务决算说明书主要用来反映建设项目的全部资金来源和资金占用情况"}, "answer": ["A", "B", "C"], "analysis": "竣工财务决算是正确核定项目资产价值、反映竣工项目建设成果的文件，是办理资产移交和产权登记的依据 。竣工财务决算说明书主要反映竣工工程建设成果和经验，是对竣工决算报表进行分析和补充说明的文件，是全面考核分析工程投资与造价的书面总结。", "tags": [], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库"}, {"id": "mgmt_hqwx_0345", "date": "2026-07-09", "chapter": "g07", "type": "multiple", "stem": "下列施工成本考核指标中，属于施工企业对项目经理部成本考核的是（ ）。", "options": {"A": "项目施工成本降低率", "B": "项目经理责任目标总成本降低率", "C": "施工责任目标成本实际降低率", "D": "施工计划成本实际降低率", "E": "项目经理责任目标总成本降低额"}, "answer": ["B", "C", "D", "E"], "analysis": "【内容考查】本题考查的是施工成本管理内容 【选项分析】 企业的项目成本考核指标：项目施工成本降低额和项目施工成本降低率。 企业对项目经理部成本考核的指标：①项目经理责任目标总成本降低额和降低率； ②施工责任目标成本实际降低额和降低率； ③施工计划成本实际降低额和降低率", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0349", "date": "2026-07-09", "chapter": "g07", "type": "multiple", "stem": "施工合同签订后，工程项目施工成本计划的常用编制方法有（ ）。", "options": {"A": "专家意见法", "B": "功能指数法", "C": "目标利润法", "D": "技术进步法", "E": "定率估算法"}, "answer": ["C", "D", "E"], "analysis": "【内容考查】本题考查的是施工成本管理内容 【选项分析】成本计划的编制方法。1）目标利润法。2）技术进步法。3）按实计算法。4）定率估算法（历史资料法）。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0350", "date": "2026-07-09", "chapter": "g07", "type": "multiple", "stem": "施工成本管理中，企业对项目经理部可控责任成本进行考核的指标有（ ）。", "options": {"A": "直接成本降低率", "B": "预算总成本降低率", "C": "项目经理责任目标总成本降低率", "D": "施工责任目标成本实际降低率", "E": "施工计划成本实际降低率"}, "answer": ["C", "D", "E"], "analysis": "【内容考查】本题考查的是施工成本管理内容 【选项分析】项目经理部可控责任成本考核指标：①项目经理责任目标总成本降低额和降低率；②施工责任目标成本实际降低额和降低率；③施工计划成本实际降低额和降低率。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0356", "date": "2026-07-09", "chapter": "g07", "type": "multiple", "stem": "按索赔目的不同，工程索赔可分为（ ）。", "options": {"A": "合同中明示的索赔", "B": "合同中默示的索赔", "C": "工期索赔", "D": "费用索赔", "E": "工程变更索赔"}, "answer": ["C", "D"], "analysis": "按索赔的目的分类。工程索赔可分为工期索赔和费用索赔。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0358", "date": "2026-07-09", "chapter": "g07", "type": "multiple", "stem": "工程索赔按索赔性质可划分为（ ）。", "options": {"A": "费用索赔", "B": "工期索赔", "C": "工程延误索赔", "D": "工程变更索赔", "E": "意外风险索赔"}, "answer": ["C", "D", "E"], "analysis": "按索赔事件的性质分类。工程索赔可分为工程延期索赔、工程变更索赔、合同被迫终止索赔、工程加速索赔、意外风险和不可预见因素索赔和其他索赔。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0359", "date": "2026-07-09", "chapter": "g07", "type": "multiple", "stem": "下列索赔事件引起的费用索赔中，可以获得利润补偿的有（ ）。", "options": {"A": "施工中发现文物", "B": "延迟提供施工场地", "C": "承包人提前竣工", "D": "延迟提供图纸", "E": "基准日后法律的变化"}, "answer": ["B", "D"], "analysis": "【内容考查】本题考查的是工程索赔的结果 【选项分析】选项A只能索赔工期和费用，选项C只能索赔费用，选项E只能索赔费用。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0362", "date": "2026-07-09", "chapter": "g07", "type": "multiple", "stem": "工程施工中的下列情形，发包人不予计量的有（ ）。", "options": {"A": "监理人抽检不合格返工增加的工程量", "B": "承包人自检不合格返工增加的工程量", "C": "承包人修复因不可抗力损坏工程增加的工程量", "D": "承包人在合同范围之外按发包人要求增建的临时工程工程量", "E": "工程质量验收资料缺项的工程量"}, "answer": ["A", "B", "E"], "analysis": "【内容考查】本题考查的是工程计量的原则与范围 【选项分析】工程计量的原则包括下列三个方面： (1)不符合合同文件要求的工程不予计量。即工程必须满足设计图纸、技术规范等合同文件对其在工程质量上的要求，同时有关的工程质量验收资料齐全、手续完备，满足合同文件对其在工程管理上的要求。 (2) 按合同文件所规定的方法、范围、内容和单位计量。工程计量的方法、范围、内容和单位受合同文件所约束，其中工程量清单(说明)、技术规范、合同条款均会从不同角度、不同侧面涉及这方面的内容。在计量中要严格遵循这些文件的规定，并且一定要结合起来使用。 (3) 因承包人原因造成的超出合同工程范围施工或返工的工程量，发包人不予计量。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0375", "date": "2026-07-09", "chapter": "g07", "type": "multiple", "stem": "建设项目竣工决算的核心内容包括（ ）。", "options": {"A": "竣工财务决算报表", "B": "竣工财务决算说明书", "C": "投标报价书", "D": "工程竣工图", "E": "工程造价比较分析"}, "answer": ["A", "B"], "analysis": "竣工决算主要包括竣工财务决算说明书、竣工财务决算报表、工程竣工图和工程造价比较分析四部分。前两者是核心内容。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0376", "date": "2026-07-09", "chapter": "g07", "type": "multiple", "stem": "大、中型建设项目竣工决算内容有（ ）。", "options": {"A": "竣工验收总表", "B": "竣工财务决算表", "C": "竣工工程概况表", "D": "交付使用财产明细表", "E": "交付使用财产总表"}, "answer": ["B", "C", "D", "E"], "analysis": "按大、中型建设项目竣工决算包括竣工工程概算表、竣工财务决算表、交付使用财产总表以及交付使用财产明细表。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0377", "date": "2026-07-09", "chapter": "g07", "type": "multiple", "stem": "下列属于竣工决算的内容是（ ）。", "options": {"A": "竣工财务决算说明书", "B": "竣工财务决算报表", "C": "工程竣工图", "D": "工程竣工造价对比分析", "E": "竣工验收报告"}, "answer": ["A", "B", "C", "D"], "analysis": "竣工决算由竣工财务决算说明书、竣工财务决算报表、工程竣工图和工程竣工造价对比分析四部分组成。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0378", "date": "2026-07-09", "chapter": "g07", "type": "multiple", "stem": "关于新增固定资产价值的确定，下列说法中正确的有（ ）。", "options": {"A": "以单位工程为对象计算", "B": "以验收合格、正式移交生产或使用为前提", "C": "分期分批将会生产的工程，按最后一批交付时间统一计算", "D": "凡购置达到固定资产标准不需安装的设备、工器具，应在交付使用后计入新增固定资产价值", "E": "是建设项目竣工投产后所增加的固定资产价值"}, "answer": ["B", "D", "E"], "analysis": "【内容考查】本题考查的是新增固定资产价值的确定方法 【选项分析】新增固定资产价值的计算是以独立发挥生产能力的单项工程为对象的，故A错误；分期分批交付生产或使用的工程，应分期分批计算新增固定资产价值，故C错误。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0380", "date": "2026-07-09", "chapter": "g07", "type": "multiple", "stem": "编制建设项目竣工决算必须满足的条件包括（ ）。", "options": {"A": "经批准的初步设计所确定的工程内容已完成", "B": "单项工程或建设项目竣工结算已完成", "C": "收尾工程竣工结算已完成", "D": "预留费用不超过规定比例", "E": "涉及工程质量纠纷事项已处理完毕"}, "answer": ["A", "B", "D", "E"], "analysis": "【内容考查】本题考查的是建设项目竣工决算的编制条件 【选项分项】编制工程竣工决算应具备下列条件： （1）经批准的初步设计所确定的工程内容已完成； （2）单项工程或建设项目竣工结算已完成； （3）收尾工程投资和预留费用不超过规定的比例； （4）涉及法律诉讼、工程质量纠纷的事项已处理完毕； （5）项目建设单位应当完成各项账务处理及财产物资的盘点核实，做到账账、账证、账实、账表相符。 （6）其他影响工程竣工决算编制的重大问题已解决。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0381", "date": "2026-07-09", "chapter": "g07", "type": "multiple", "stem": "根据现行财务制度和企业会计准则，新增固定资产价值的内容包括（ ）。", "options": {"A": "专有技术", "B": "建设单位管理费", "C": "土地征用费", "D": "银行存款", "E": "建筑工程设计费"}, "answer": ["B", "C", "E"], "analysis": "新增固定资产价值的内容包括：已投入生产或交付使用的建筑、安装工程造价；达到固定资产标准的设备、工器具的购置费用；新增固定资产的其他费用包括建设单位管理费、土地征用费、地质勘察和建筑工程设计费和生产工、艺流程系统设计费。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0383", "date": "2026-07-09", "chapter": "g07", "type": "multiple", "stem": "工程竣工决算包括多个内容，其中（ ）是竣工决算的核心。", "options": {"A": "竣工财务决算说明书", "B": "竣工财务决算报表", "C": "竣工财务决算", "D": "工程竣工图", "E": "工程造价对比分析"}, "answer": ["A", "B"], "analysis": "【内容考查】本题考查的是竣工决算的内容 【选项分析】竣工决算的内容包括竣工财务决算说明书、竣工财务决算报表、工程竣工图和工程造价对比分析等四个部分。其中竣工财务决算说明书和竣工财务决算报表又合称为竣工财务决算，它是竣工决算的核心内容。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "mgmt_hqwx_0384", "date": "2026-07-09", "chapter": "g07", "type": "multiple", "stem": "一般不作为无形资产入账，但当涉及转让事项时才做无形资产核算的有（ ）。", "options": {"A": "自创专利权", "B": "自创专有技术", "C": "自创商标权", "D": "出让取得的土地使用权", "E": "划拨取得的土地使用权"}, "answer": ["B", "C", "E"], "analysis": "【内容考查】本题考查的是新增无形资产价值的确定方法 【选项分析】如果专有技术是自创的，一般不作为无形资产入账，自创过程中发生的费用，按当期费用处理。 如果商标权是自创的，一般不作为无形资产入账，而将商标设计、制作、注册、广告宣传等发生的费用直接作为销售费用计人当期损益。转让后可计入无形资产。当建设单位向土地管理部门申请土地使用权并为之支付一笔出让金时，土地使用权作为无形资产核算；当建设单位获得土地使用权是通过行政划拨的，这时土地使用权就不能作为无形资产核算；在将土地使用权有偿转让、出租、抵押、作价入股和投资，按规定补交土地出让价款时，才作为无形资产核算。", "tags": ["环球网校", "26年新题"], "source": "hqwx题库", "src": "hqwx"}, {"id": "ht_mgmt_1024", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "工程量清单计价中，不是编制投标报价和招标控制价时共同依据的资料是()。", "options": {"A": "资料和指数", "B": "国家、地区或行业定额", "C": "工程造价信息", "D": "投标人拟定的施工组织设计方案"}, "answer": ["D"], "analysis": "(二）投标报价的编制依据《建设工程工程量清单计价标准》GB/T 50500-2024 规定，投标报价应根据下列依据编制: (1)《建设工程工程量清单计价标准》GB/T 50500-2024 与专业工程量计算规范。 (2) 国家或省级、行业建设主管部门颁发的计价办法。 (3) 企业定额，国家或省皱、行业建设主管部门颁发的计价定额。 (4) 招标文件、工程量清单及其补充逋知、答疑纪要。 (5) 建设工程设计文件及相关资料。 (6) 施工现场情况、工程特点及投标时拟定的施工组织设计或施工方案。 (7) 与建设项目相关的标准、规范等技术资料。 (8) 市场价格信息或工程造价管理机构发布的工程造价信息。 (9) 其他的相关资料。 招标控制价的编制依据是指在编制招标控制价时需要进行工程量计量、价格确认、工程计价的有关参数、率值的确定等工作时所需的基础性资料，主要包括： (1) 现行国家标准《建设工程工程量清单计价标准》GB/T 50500-2024 与专业工程量计算规范。 (2) 国家或省级、行业建设主管部门颁发的计价定额和计价办法。 (3) 建设工程设计文件及相关资料。 (4) 拟定的招标文件及招标工程量清单。 (5) 与建设项目相关的标准、规范、技术资料。 (6) 施工现场情况、工程特点及常规施工方案。 (7) 工程造价管理机构发布的工程造价信息，但工程造价信息没有发布的，参照市场价。 (8) 其他的相关资料。", "tags": ["好题库"], "source": "第四章  工程计价方法及依据", "src": "好题库", "_review_note": "共同依据: 2024取消定额依赖但AB仍是正确依据,D选项投标人施工方案也是独立依据→答案不变"}, {"id": "ht_mgmt_1035", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "根据《建设工程工程量清单计价标准》GB/T 50500-2024的规定，在合同约定之外的或者因变更而产生的、工程量清单中没有相应的项目的额外工作，尤其是那些难以事先商定价格的额外工作，应计列入()之中。", "options": {"A": "暂列金额", "B": "暂估价", "C": "计日工", "D": "总承包服务费"}, "answer": ["C"], "analysis": "计日工是为了解决现场发生的零星工作的计价而设立的。计日工适用的所谓零星项目或工作一般是指合同约定之外的或者因变更而产生的、工程量清单中没有相应项目的额外工作，尤其是那些难以事先商定价格的额外工作。", "tags": ["好题库"], "source": "第四章  工程计价方法及依据", "src": "好题库", "_review_note": "计日工定义: 基础概念未变,去掉2013编号即可"}, {"id": "ht_mgmt_1041", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "根据《建设工程工程量清单计价标准》GB/T 50500-2024，关于暂估价的说法中，正确的是()。", "options": {"A": "材料、工程设备暂估价表中只填写原材料、燃料、构配件的暂估价", "B": "材料暂估价应纳入分部分项工程量清单项目综合单价", "C": "专业工程暂估价指完成专业工程的建筑安装工程费", "D": "专业工程暂估价由专业工程承包人填写"}, "answer": ["B"], "analysis": "暂估价是指招标人在工程量清单中提供的用于支付必然发生但暂时不能确定价格的材料、工程设备的单价以及专业工程的金额，包括材料暂估单价、工程设备暂估单价和专业工程暂估价，暂估价由招标人确定，投标人应根据招标人列出的金额计入投标总价中。为方便合同管理，需要纳入分部分项工程量清单项目综合单价中的暂估价应只是材料、工程设备暂估单价，以方便投标人组价。根据《建筑安装工程费用项目组成》(建标[2003]206)中规定的材料、工程设备费包括原材料、燃料、构配件以及按规定应计入建筑安装工程造价的设备。专业工程的暂估价一般应是综合暂估价，应当包括除增值税以外的管理费、利润等取费。", "tags": ["好题库"], "source": "第四章  工程计价方法及依据", "src": "好题库", "_review_note": "暂估价: 2024暂估价概念保留,答案B(材料暂估价纳入综合单价)正确"}, {"id": "ht_mgmt_1047", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "《建设工程工程量清单计价标准》（GB/T 50500-2024）规定,招标时用于合同约定调整因素出现时的工程材料价款调整的费用应计人（）中。", "options": {"A": "分部分项综合单价", "B": "暂列金额", "C": "材料暂估价", "D": "总承包服务费"}, "answer": ["B"], "analysis": "本题考核暂列金额包含的项目。清单计价规范中规定暂列金额是用于合同签订时尚未确定或者不可预见的所需材料、设备、服务的采购，施工中可能发生的工程变更、合同约定调整因素出现时工程索赔、现场签证确定等的费用。", "tags": ["好题库"], "source": "第四章  工程计价方法及依据", "src": "好题库", "_review_note": "暂列金额: 2024分两类但基本用途不变,答案B正确"}, {"id": "ht_mgmt_1155", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "(2013年)下列关于工程计价的说法中，正确的是()。", "options": {"A": "工程计价包含计算工程量和套定额两个环节", "B": "建筑安装工程费=∑基本构造单元工程量×相应单价", "C": "工程计价包括工程单价的确定和总价的计算", "D": "工程计价中的工程单价仅指综合单价"}, "answer": ["C"], "analysis": "工程计价包括单价的确定和总价的计算。①工程单价是指完成单位工程基本构造单元的工程量所需要的基本费用。工程单价包括工料单价和综合单价。②工程总价是指经过规定的程序或办法逐级汇总形成的相应工程造价。 分部分项工程费(或措施项目费)=∑[基本构造单元工程量(定额项目或清单项目)×相应单价]", "tags": ["好题库"], "source": "第四章  工程计价方法及依据", "src": "好题库", "_review_note": "工程计价基本概念: 题干只标(2013年)不涉及编号→答案C不变"}, {"id": "ht_mgmt_1160", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "(2016年)根据《建设工程工程量清单计价标准》（GB/T 50500-2024），下列关于计日工的说法中正确的是()。", "options": {"A": "招标工程量清单计日工数量为暂定，计日工费不计入投标总价", "B": "发包人通知承包人以计日工方式实施的零星工作，承包人可以视情况决定是否执行", "C": "计日工表的费用项目包括人工费、材料费、施工机械使用费、企业管理费和利润", "D": "计日工金额不列入期中支付，在竣工结算时一并支付"}, "answer": ["C"], "analysis": "计日工表项目名称这一列包含：人工费、材料费、施工机具使用费、企业管理费、利润。C对。 注：此表项目名称、暂定数量由招标人填写，编制招标控制价时，单价由招标人按有关计价规定确定；投标时，单价由投标人自主报价，按暂定数量计算合价计入投标总价中。A不对。 发包人通知承包人以计日工方式实施的零星工作，承包人应予执行。B不对。 每个支付期末，承包人应与进度款同期向发包人提交本期间所有计日工记录的签证汇总表，以说明本期间自己认为有权得到的计日工金额，调整合同价款，列人进度款支付。D不对。", "tags": ["好题库"], "source": "第四章  工程计价方法及依据", "src": "好题库", "_review_note": "计日工费用组成: 2024取消规费但C选项内容(人工费+材料费+施工机具使用费+企业管理费+利润)为全费用综合单价组成→答案不变"}, {"id": "ht_mgmt_1243", "date": "2026-07-10", "chapter": "g04", "type": "single", "stem": "根据《建设工程工程量清单计价标准》（GB/T 50500-2024），下列费用项目中需纳入分部分项工程项目综合单价的是（ ）。", "options": {"A": "工程设备估价", "B": "专业工程暂估价", "C": "暂列金额", "D": "计日工费"}, "answer": ["A"], "analysis": "本题考查的是工程计价方法。综合单价是指完成一个规定清单项目所需的人工费、材料和工程设备费、施工机具使用费和企业管理费、利润，以及一定范围内的风险费用。考前黑钻押题，金考典软件考前更新，下载链接 www.jinkaodian.com", "tags": ["好题库"], "source": "第四章  工程计价方法及依据", "src": "好题库", "_review_note": "综合单价: 答案A工程设备估价正确,基础概念一致"}, {"id": "ht_mgmt_1194", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "根据《建设工程工程量清单计价标准》（GB/T 50500-2024），在其他项目清单中，应由投标人自主确定价格的有（）。", "options": {"A": "暂列金额", "B": "专业工程暂估价", "C": "材料暂估价单价", "D": "计日工单价", "E": "总承包服务费"}, "answer": ["D", "E"], "analysis": "计日工表的项目名称、暂定数量由招标人填写，编制招标控制时，单价由招标人按有关计价规定确定；投标时，单价由投标人自主报价，按暂定数量计算合价计入投标总价中；总承包服务费计价表中项目名称、服务内容由招标人填写，编制招标控制价时，费率及金额由招标人按有关计价规定确定；投标时，费率及金额由投标人自主报价，计入投标总价中。", "tags": ["好题库"], "source": "第四章  工程计价方法及依据", "src": "好题库", "_review_note": "投标人自主定价: DE(计日工单价+总承包服务费)基础规则一致"}, {"id": "ht_mgmt_1200", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "根据《建设工程工程量清单计价标准》GB/T 50500-2024，关于工程量清单计价的有关要求，下列说法中正确的有（）。", "options": {"A": "事业单位自有资金投资的建设工程发承包，可以不采用工程量清单计价", "B": "使用国有资金投资的建设工程发承包，必须采用工程量清单计价", "C": "招标工程量清单应以单位工程为单位编制", "D": "工程量清单计价方式下，必须采用单价合同", "E": "招标工程量清单的准确性和完整性由清单编制人负责"}, "answer": ["B", "C"], "analysis": "A选项，事业单位自有资金投资的建设工程发承包，必须采用工程量清单计价。D选项，工程量清单计价方式下，鼓励采用单价合同。E选项，招标工程量清单的准确性和完整性由招标人负责。", "tags": ["好题库"], "source": "第四章  工程计价方法及依据", "src": "好题库", "_review_note": "国有资金必须清单计价: 基础原则,答案BC正确"}, {"id": "ht_mgmt_1278", "date": "2026-07-10", "chapter": "g04", "type": "multiple", "stem": "根据《建设工程工程量清单计价标准》的规定，综合单价是指完成一个规定计量单位的分部(分项)工程量清单项目或措施项目所需的（ ），以及一定范围内的风险费用。", "options": {"A": "材料费", "B": "管理费", "C": "税金", "D": "施工机械使用费", "E": "人工费"}, "answer": ["A", "B", "D", "E"], "analysis": "综合单价主要适用于工程量清单计价。我国现行的工程量清单计价的综合单价为非完全综合单价。根据《建筑工程工程量清单计价规范》 GB/T 50500-2024 的规定，综合单价由完成工程量清单中一个规定计量单位项目所需的人工费、材料费、施工机具使用费、管理费和利润，以及一定范围的风险费用组成。而规费和增值税，是在求出单位工程分部分项工程费、措施项目费和其他项目费后再统一计取，最后汇总得出单位工程造价。", "tags": ["好题库"], "source": "第四章  工程计价方法及依据", "src": "好题库", "_review_note": "综合单价组成: 2024取消规费后不包括税金,C选项税金应排除但多选题原答案ABDE→改为ABD或ABDE取决于解读,保留原答案并标记"}, {"id": "ht_mgmt_1483", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "根据《建设工程工程量清单计价标准》GB/T 50500-2024，在招标文件未另有要求的情况下，投标报价的综合单价一般要考虑的风险因素是（）。", "options": {"A": "政策法规的变化", "B": "人工单价的市场变化", "C": "政府定价材料的价格变化", "D": "管理费、利润的风险"}, "answer": ["D"], "analysis": "对于承包人根据自身技术水平、管理、经营状况能够自主控制的风险.， 如承包人的管理费、利润的风险，承包人应结合市场情况，根据企业自身的实际合理确定、自主报价，该部分风险由承包人全部承担", "tags": ["好题库"], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库", "_review_note": "管理费利润风险: 答案D正确,基础规则一致"}, {"id": "ht_mgmt_1511", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "根据《建设工程工程量清单计价标准》GB/T 50500-2024，允许投标人根据具体情况对招标工程量清单进行修正或增加的内容是()。", "options": {"A": "分部分项工程量清单", "B": "措施项目清单", "C": "暂列金额", "D": "计日工"}, "answer": ["B"], "analysis": "本题考查的是投标报价的编制方法和内容。投标人对措施项目中的总价项目投标报价应遵循以下原则：(1)措施项目应依据招标人提供的措施项目清单和投标人投标时拟定的施工组织设计或施工方确定；(2)措施项目费由投标人自主确定，但其中安全文明施工费必须按照国家或省级、行业建设主管部门的规定计价，不得作为竞争性费用。招标人不得要求投标人对该项费用进行优惠，投标人也不得将该项费用参与市场竞争。", "tags": ["好题库"], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库", "_review_note": "措施项目可修改: 2024措施大调整但投标人应依据施工方案自主报价的原则不变"}, {"id": "ht_mgmt_1515", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "根据《建设工程工程量清单计价标准》GB/T 50500-2024，关于施工发承包投标报价的编制，下列做法正确的是（）。", "options": {"A": "设计图纸与招标工程量清单项目特征描述不同的，以设计图纸特征为准", "B": "暂列金额应按照招标工程量清单中列出的金额填写，不得变动", "C": "材料、工程设备暂估价应按暂估单价，乘以所需数量后计入其他项目费", "D": "总承包服务费应按照投标人提出的协调、配合和服务项目自主报价"}, "answer": ["B"], "analysis": "暂估价不得变动和更改。暂估价中的材料、工程设备暂估价必须按照招标人提供的暂估单价计入清单项目的综合单价（如表4.2.6所示专业工程暂估价必须按照招标人提供的其他项目清单中列出的金额填写（如表4.2.7所示）。材料、工程设备暂估单价和专业工程暂估价均由招标人提供，为暂估价格，在工程实施过程中，对于不同类型的材料与专业工程采用不同的计价方法。", "tags": ["好题库"], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库", "_review_note": "暂列金额不得变动: 基础规则,答案B正确"}, {"id": "ht_mgmt_1520", "date": "2026-07-10", "chapter": "g06", "type": "single", "stem": "根据《建设工程工程量清单计价标准》GB/T 50500-2024，关于承发包双方施工阶段风险分摊原则的表述正确的是()。", "options": {"A": "各类原因所致人工费变化的风险由承包人承担", "B": "10％以内的材料价格风险由承包人承担", "C": "10％以内的施工机械使用费风险由承包人承担", "D": "5％以内的人工费风险由承包人承担"}, "answer": ["C"], "analysis": "根据国际惯例并结合我国市场经济条件下工程建设的特点，承发包双方对工程施工阶段的风险宜采用如下分摊原则：(1)对于主要由市场价格波动导致的价格风险，根据工程特点和工期要求，建议可一般采取的方式是承包人承担5％以内的材料价格风险，10％以内的施工机械使用费风险；(2)对于法律、法规、规章或有关政策出台导致工程税金、规费、人工发生变化，并由省级、行业建设行政主管部门或其授权的工程造价管理机构根据上述变化发布的政策性调整，承包人不应承担此类风险，应按照有关调整规定执行；(3)对于承包人根据自身技术水平、管理、经营状况能够自主控制的风险，由承包人全部承担。 本题库是以官方教材为依据，知识点所对应的习题综合了二建法规、二建管理、造价员基础、一级造价师考试的题库+真题编辑，基本上做到了每个知识点都有相对应的题目及解析,题库会陆续更新,会有模拟题,预测题及考前更新押题。 《建设工程计量与计价实务》题库编辑中,教材出来后会陆续更新 www.jinkaodian.com 金考典考试软件。", "tags": ["好题库"], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库", "_review_note": "风险分摊: 2024明确±5%材料±10%人工,原答案C(10%机具费)可能需核实"}, {"id": "ht_mgmt_1557", "date": "2026-07-10", "chapter": "g06", "type": "multiple", "stem": "关于招标工程量清单的编制，下列说法正确的有()。", "options": {"A": "若采用标准图集能够全部满足项目特征描述的要求，项目特征描述可直接采用“详见××图集”的方式", "B": "措施项目清单的编制需考虑工程本身、水文、气象、环境、安全等多种因素", "C": "以“项”为计量单位的专业工程暂估价一般应包括管理费、规费、利润、税金等", "D": "工程量清单总说明应对工程概况、工程招标及分包范围、工程质量要求等进行描述", "E": "T程量清单编制依据包括设计文件、招标文件、施工现场情况、常规施工方案等"}, "answer": ["A", "B", "D", "E"], "analysis": "本题考查的是招标工程量清单的编制。 选项A，若采用标准图集或施工图纸能够全部或部分满足项目特征描述的要求，项目特征 描述可直接采用详见 XX 图集或 XX 图号的方式。选项B，P179措施项目清单的编制需考虑多种 因素， 除工程本身的因素外，还涉及水文、气象、环 境、安全等因素。 选项C，以“项”为计量单位给出的专业工程暂估价一般应是综合暂估价，即应当包括 除规费、税金以外的管理费、利润等。 选项D，工程量清单编制总说明包括以下内容：(1) 工程概况(2) 工程招标及分包范围(3) 工程量清单编制依据(4) 工程质量、材料、施工等的特殊要求(5) 其他需要说明的事项。 选项E，招标工程量清单编制的编制依据：(1) 《建设工程工程量清单计价标准》GB50500— 2013 以及各专业工程量计算规范等(2) 国家或省级、行业建设主管部门颁发的计价定额和办法(3) 建设工程设计文件及相关资料(4) 与建设工程有关的标准、规范、技术资料(5) 拟定 的招标文件(6) 施工现场情况、地勘水文资料、 工程特点及常规施工方案(7) 其他相关资料。", "tags": ["好题库"], "source": "第六章   工程施工招投标阶段造价管理", "src": "好题库", "_review_note": "招标清单编制: 答案ABDE,2024取消规费后C选项含\"规费\"应排除→原答案不变"}, {"id": "ht_mgmt_1645", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "根据《建设工程工程量清单计价规范（GB/T 50500-2024），对于任一招标工程量清单项目，如果因业主方变更的原因导致工程量偏差，则调整原则为（）。", "options": {"A": "当工程量增加超过15%以上时，其增加部分的工程量单价应予调低", "B": "当工程量增加超过15%以上时，其增加部分的工程量单价应予调高", "C": "当工程量减少超过15%以上时，其相应部分的措施费应予调低", "D": "当工程量增加超过15%以上时，其相应部分的措施费应予调高"}, "answer": ["A"], "analysis": "对于任一招标工程量清单项目，如果因本条规定的工程量偏差和工程变更等原因导致工程量偏差超过15%，调整的原则为：当工程量增加15%以上时，其增加部分的工程量的综合单价应予调低;当工程量减少15%以上时，减少后剩余部分的工程量的综合单价应予调高。", "tags": ["好题库"], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库", "_review_note": "已判定"}, {"id": "ht_mgmt_1646", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "根据《建设工程工程量清单计价标准》（GB/T 50500-2024），某工程签订了单价合同，在执行过程中，某分项工程原清单工程量1000m3，综合单价为25 元/m3，后因业主方原因实际工程量变更为1500m3，合同中约定，若实际工程量超过计划工程量15%以上，超过部分综合单价调整为原来的0.9，不考虑其他因素，则该分项工程的结算款应为（）。", "options": {"A": "36625", "B": "35000", "C": "33750", "D": "32875"}, "answer": ["A"], "analysis": "该分项工程的结算款=1000m3×(1+15%)×25元／m3+[1500m3-1000m3×(1+15%)]×25元／m3×0．9=36625元。", "tags": ["好题库"], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库", "_review_note": "结算款计算: 纯计算题,规则一致,答案A正确"}, {"id": "ht_mgmt_1677", "date": "2026-07-10", "chapter": "g07", "type": "single", "stem": "工程竣工结算的计价原则中，下列有关其他项目计价规定描述错误的是()。", "options": {"A": "计日工应按发包人合同确认的事项计算", "B": "暂估价应按发承包双方按照《建设工程工程量清单计价规范》的相关规定计算", "C": "施工索赔费用应依据发承包双方确认的索赔事项和金额计算", "D": "现场签证费用应依据发承包双方签证资料确认的金额计算"}, "answer": ["A"], "analysis": "本题考查的是竣工结算。其他项目应按下列规定计价： 1)计日工应按发包人实际签证确认的事项计算； 2)暂估价应按发、承包双方按照《建设工程工程量清单计价标准》GB/T 50500-2024的相关规定计算； 3)总承包服务费应依据合同约定金额计算，如发生调整的，以发承包双方确认调整的金额计算； 4)施工索赔费用应依据发承包双方确认的索赔事项和金额计算； 5)现场签证费用应依据发承包双方签证资料确认的金额计算； 6)暂列金额应减去工程价款调整（包括索赔、现场签证）金额计算，如有余额归发包人。", "tags": ["好题库"], "source": "第七章  工程施工和竣工阶段造价管理", "src": "好题库", "_review_note": "竣工结算计价: 基础规则,去掉2013编号即可"}];